def _wf_log(message: str) -> None:
    """Operator diagnostics — stderr only; stdio MCP transport owns stdout."""
    print(message, file=sys.stderr, flush=True)


def _mcp_subprocess_run(
    cmd: list[str] | str,
    *,
    cwd: str | Path,
    env: dict[str, str] | None = None,
    timeout: float | None = None,
    shell: bool = False,
    capture_output: bool = True,
    check: bool = False,
):
    """Run a bounded MCP helper subprocess without inheriting JSON-RPC stdio.

    Stdio MCP owns the parent process's stdin/stdout. Helper subprocesses must never inherit
    those streams: stdin is always DEVNULL, and stdout/stderr are either captured for the tool
    response or explicitly discarded.
    """
    import subprocess

    kwargs: dict[str, Any] = {
        "cwd": str(cwd),
        "env": env,
        "stdin": subprocess.DEVNULL,
        "text": True,
        # Wave 1p8gv (review GUARD-3): decode captured child output as UTF-8 (errors=replace) so
        # non-ASCII bytes never mojibake/raise across OSes.
        "encoding": "utf-8",
        "errors": "replace",
        "timeout": timeout,
        "shell": shell,
        "check": check,
    }
    if capture_output:
        kwargs.update({"stdout": subprocess.PIPE, "stderr": subprocess.PIPE})
    else:
        kwargs.update({"stdout": subprocess.DEVNULL, "stderr": subprocess.DEVNULL})
    flags = subprocess_util.no_window_creationflags()
    if flags:
        kwargs["creationflags"] = flags
    return subprocess.run(cmd, **kwargs)


def _windows_no_window_flag() -> int:
    """Windows ``CREATE_NO_WINDOW`` (0 elsewhere) — delegates to the shared helper (wave 1p8gu).

    Retained as a thin alias because three background ``Popen`` sites and ``_pid_is_running`` OR this
    value into a larger ``creationflags`` expression (``DETACHED_PROCESS | CREATE_NEW_PROCESS_GROUP |
    …``), and the source-guard tests assert the call by name. The single source of the value is
    ``subprocess_util.no_window_creationflags``."""
    return subprocess_util.no_window_creationflags()


# ---------------------------------------------------------------------------
# Root discovery (mirrors lifecycle_id.py pattern)
# ---------------------------------------------------------------------------

def _discover_root(override: Optional[str] = None) -> Path:
    """Resolve the repo root, anchored by ``docs/workflow-config.json``, cwd-independently.

    Priority — first candidate carrying the marker wins:
    1. an explicit ``override`` (``--root`` / MCP tool arg);
    2. **this script's own install location** — ``server_impl.py`` always lives at
       ``<root>/.wavefoundry/framework/scripts/``, so ``parents[3]`` IS the served
       repo. Authoritative for the MCP server and independent of the host's cwd, so
       the committed config needs no ``--root .``;
    3. host / generic project-root env vars (``CLAUDE_PROJECT_DIR``, ``PROJECT_ROOT``,
       ``REPO_ROOT``) — used only when they line up with a real Wavefoundry tree
       (the marker), so a stray var can't mis-root us;
    4. CWD and its parents.
    Falls back to the script root (if it looks like a Wavefoundry tree) else CWD.

    Cross-reference: the sibling ``_discover_root`` copies (``indexer``,
    ``lifecycle_id``, ``render_platform_surfaces``, ``docs_gardener``) still anchor on
    CWD only; a future task should unify them onto this script-location logic.
    """
    return repo_root.discover_root(override)


def _tool_venv_base() -> Path:
    """Tool-venv base path — delegates to the single resolver (wave 1p7pl)."""
    return venv_bootstrap.tool_venv_base()


def _preferred_python() -> str:
    """Return the spawn interpreter: tool-venv ``pythonw.exe`` on Windows, else tool-venv Python.

    Builds the venv path via the single resolver (wave 1p7pl). On native Windows, prefers the
    console-free tool-venv ``pythonw.exe`` when present so spawned framework processes never flash a
    console window (wave 1p8pe). Every consumer of this resolver is non-interactive and redirects its
    output. POSIX is unchanged (``windowless_pythonw()`` returns ``None``).
    """
    pythonw = subprocess_util.windowless_pythonw()
    if pythonw is not None:
        return pythonw
    vp = venv_bootstrap.tool_venv_python()
    return str(vp) if vp.exists() else sys.executable


