# context for a code question but must not OUTRANK the implementing source — a gentler
# down-weight than the narrative/historical tiers above (which are weaker evidence).
_DEMOTION_REFDOCS = 0.80  # docs/architecture/, docs/specs/, ADRs
# Post-normalization score boost for symbol-injected code chunks (12q63).
_SYMBOL_INJECTION_BOOST = 0.40
# Definition-file boosting: vocabulary-triggered keyword augmentation for schema languages.
# Each rule fires when any vocabulary term appears in the lowercased query.
# Injected candidates receive score=0.0 so the reranker evaluates them on content merit only.
# Add new rules (GraphQL, protobuf, OpenAPI) by appending to this list — no logic changes required.
DEFINITION_BOOST_RULES: list[dict] = [
    {
        "vocabulary": frozenset({
            "sql", "stored procedure", "proc", "migration", "schema",
            "insert", "query", "database", "db", "routine",
            "table", "column",
        }),
        "extensions": [".sql"],
        "label": "sql",
    },
]
DEFINITION_BOOST_CANDIDATES = 5   # maximum candidates injected per rule per query

# Wave 1p4hj: agent-mode (the default `rerank` value) candidate selection. The host
# agent — code_ask's only consumer, which already synthesizes — fuses labeled,
# deduped, per-index candidates itself, so agent-mode skips BOTH the cross-encoder
# and the RRF cross-source merge. These are tunable; 1p4hj AC-10 calibrates them.
AGENT_TEXT_BUDGET_CHARS = 16000    # PRIMARY ceiling: cumulative full-chunk text (≈ chars÷4 tokens). "Don't over-feed the agent" — count adapts to chunk size (many small chunks fit; few large ones fit). Set from the 1p4hj AC-10 sweep: recall + answer-rank saturate ≤8000c on focused queries (24000 was over-provisioned); 16000 keeps headroom for diffuse/synthesis queries pending cross-project validation.
AGENT_CANDIDATE_MAX = 40           # loose COUNT backstop — guards pathological "hundreds of tiny chunks"; rarely the binding limit (the text budget + drop-off bind first)
AGENT_PER_INDEX_FLOOR_K = 3        # per-index coverage floor — each source contributes ≥K, regardless of cross-source ranking (anti-starvation minimum)
AGENT_RELEVANCE_DROPOFF = 0.85     # quality cutoff: fill stops past the top cluster — keep candidates with weighted score ≥ ratio×top (floor exempt). The "enough to answer, no noise" knob. Calibrated by 1p4hj AC-10.
# Wave 1p4hu: graph-signal source for the dedicated `graph_related` response section. Direction-aware
# 1-hop neighbors (callers / 1p4ls constant `reads` / importers via edges INTO the seed for "what
# calls/reads/uses X"; the seed's mechanism both-ways for "how does X work"), grouped by relationship
# — NOT mixed into citations with a 0.0 score. A match that is also a citation is text-deduped.
AGENT_GRAPH_SIGNAL_CAP = 3         # max structural matches in the graph_related section (bounded — never pulls the subgraph)
AGENT_GRAPH_DEF_WINDOW = 24        # source lines read per graph neighbor to form its candidate text
AGENT_GRAPH_CITATION_CAP = 2       # wave 1p66t: max cross-file graph neighbors merged INTO citations (additive, floor-gated, reranked) so a cross-file chain reaches the answer surface, not only graph_related
AGENT_ENUMERATION_BUDGET_MULT = 2.0  # wave 1p66t: text-budget multiplier for enumeration ("which/all X") queries — lets more of the full set through the selection cutoff instead of a reranked top-k that silently truncates
_GRAPH_SIGNAL_RELATIONS = ("calls", "imports", "reads", "extends", "implements", "writes", "maps_to")  # 1-hop edge types followed for the structural signal (wave 1p9qh review: inheritance edges join it — "what uses X" includes X's implementors/subtypes; wave 1p9qi/1p9qd: `writes` = SQL write-direction table references — "what uses table X" includes its writers; wave 1p9qi/1p9qg: `maps_to` = ORM entity→table mappings — "what uses table X" includes the entities riding it)
_GRAPH_SIGNAL_SEED_KINDS = frozenset({"function", "method", "class", "constant", "module"})
# Kinds a graph NEIGHBOR may be SURFACED as a candidate. Excludes "module" — a whole-file module
# node ("stem > stem") is a poor structural answer (delivery follow-up: it showed up as noise for
# behavioral queries whose seed's importer was a module). Modules can still be seeds.
_GRAPH_SIGNAL_CAND_KINDS = frozenset({"function", "method", "class", "constant"})
# (edge relation, is-incoming-to-the-seed) → the neighbor's RELATIONSHIP to the seed. Incoming
# edges (neighbor → seed) are the "what uses X" answers; outgoing (seed → neighbor) are the
# seed's own dependencies. Drives the response's relationship-grouped `graph_related` section.
_GRAPH_REL_LABEL = {
    ("calls", True): "caller", ("calls", False): "callee",
    ("reads", True): "reader", ("reads", False): "reads",
    ("imports", True): "importer", ("imports", False): "imports",
    # Wave 1p9qh (1p9qa inheritance edges): incoming = the neighbor extends/implements the seed
    # (its subtypes/implementors); outgoing = the seed's own supertypes (both relations).
    ("extends", True): "subtype", ("extends", False): "supertype",
    ("implements", True): "implementor", ("implements", False): "supertype",
    # Wave 1p9qi (1p9qd SQL table references): incoming = the neighbor WRITES the seed
    # (a table's writers — "what modifies table X"); outgoing = the tables the seed writes.
    ("writes", True): "writer", ("writes", False): "writes",
    # Wave 1p9qi (1p9qg ORM entity mapping): incoming = the neighbor is an entity MAPPED
    # onto the seed table; outgoing = the table(s) the seed entity maps to.
    ("maps_to", True): "mapped_entity", ("maps_to", False): "maps_to",
}
# relationship → response bucket key (pluralized).
_GRAPH_REL_BUCKET = {
    "caller": "callers", "callee": "callees", "reader": "readers",
    "reads": "reads", "importer": "importers", "imports": "imports", "related": "related",
    "subtype": "subtypes", "implementor": "implementors", "supertype": "supertypes",
    "writer": "writers", "writes": "writes",
    "mapped_entity": "mapped_entities", "maps_to": "maps_to",
}
# Wave 1p9qi review fix (architecture F1): the code_ask response gate that decides whether the
# assembled graph_related section carries signal is DERIVED from the bucket vocabulary above
# (plus the "related" fallback bucket), not enumerated by hand — a hand-maintained tuple silently
# dropped writers-only / mapped-entities-only signal twice (1p9qh, 1p9qi). "seed" is intentionally
# not a signal key: it is always present in an assembled section, neighbors or not.
_GRAPH_RELATED_SIGNAL_KEYS = frozenset(_GRAPH_REL_BUCKET.values()) | {"related"}
_GRAPH_QUERY_IDENT_RE = re.compile(r"[A-Za-z_][A-Za-z0-9_]{3,}")  # identifier-like query tokens to resolve as seeds
# Wave 1p4hu delivery follow-up — graph-signal seed scoping + direction.
# Generic words that resolve to a coincidental symbol (server.py::main, a `root`/`index` class)
# and pollute the structural seed set — excluded from query-token seed resolution (D3). Checked
# alongside _QUERY_STOPWORDS (defined below) in _graph_signal_candidates._resolve.
_GRAPH_SEED_STOPWORDS = frozenset({
    "main", "root", "index", "name", "names", "data", "type", "types", "item", "items",
    "node", "nodes", "path", "paths", "list", "base", "core", "self", "code", "docs", "file",
    "files", "line", "lines", "text", "call", "calls", "read", "reads", "user", "users",
    "work", "works", "purpose", "build", "handler", "result", "results", "module", "overall",
    "entry", "entries",
    # Generic English nouns that collide with real symbol names and hijack the graph seed
    # (e.g. "what is the value of X" seeded on "value" → unrelated readers). Graph-seed scope only;
    # NOT added to _QUERY_STOPWORDS, which keeps "value" as a content term for DEFAULT_TIMEOUT-style
    # definition matching.
    "value", "values", "flag", "flags", "option", "options",
})
# "what calls/reads/uses X", "where is X used", "callers of X", "is X called" — the user wants the
# things pointing AT X (its callers/readers/importers). Drives direction="in" (vs. the direction-
# blind union that answered a callers question with the seed's callees).
_GRAPH_USER_INTENT_RE = re.compile(
    r"\b(calls?|called|calling|callers?|invoke[sd]?|reads?|readers?|uses?|users?|used|referenc\w*|imports?|importers?|depends?\s+on|where\s+is)\b"
)
# "what does X call", "callees of X", "what X calls/reads", "X calls what" (subject-first) — X is the
# SUBJECT (outgoing); keep both directions rather than forcing "in".
_GRAPH_OUTGOING_INTENT_RE = re.compile(
    r"\b(callees|what\s+does\s+\w+|does\s+\w+\s+(?:call|read|use|import|access)|what\s+\w+\s+(?:calls|reads|imports|uses)|\w+\s+(?:calls|reads|imports|invokes|uses)\s+what)\b"
)
# Wave 1p52p: agent-mode confidence is now calibrated on the CROSS-ENCODER relevance scale
# (``sigmoid(logit)`` ∈ [0,1]), not cosine. The docs/code model split (1p4wx) put arctic-doc and
# bge-code cosines on different scales, so a mixed-source cosine top was never a valid band; the
# cross-encoder scores docs+code on ONE scale. Measured separation: on-topic queries whose answer is
# retrieved top ``sigmoid ≥ ~0.5`` (the model's native relevance boundary), off-topic / no-answer top
# ``sigmoid < ~0.1``. These bands apply ONLY when the cross-encoder actually ran (GPU FP16 or CPU
# INT8). Two reranked=false cases (wave 1seav): healthy-path vector/coverage ordering with
# confidence CAPPED at medium (low with zero citations — mixed-model cosine
# is not trustworthy).
CONF_AGENT_RERANK_HIGH = 0.5       # reranked top sigmoid ≥ this (with ≥2 citations) → "high"
CONF_AGENT_RERANK_LOW = 0.1        # reranked top sigmoid < this → "low" (nothing relevant retrieved)

# Wave 1p4lr: candidate-side constant-definition rank boost. A short constant-declaration
# chunk (the 1p4mf " [const]" marker) whose declared-name tokens ALL appear in the query is
# the answer to a "what value/model/flag is X" question but under-ranks on raw cosine; boost
# its score so it ranks into the returned set. Applied BEFORE the drop-off, but the cutoff is
# computed from UN-boosted scores so the boost never raises the bar for other candidates.
_CONST_SECTION_SUFFIX = " [const]"   # mirrors chunker.py (1p4mf)
DEFINITION_MATCH_BOOST = 1.3         # multiplier for a query-named DEFINITION (const/func/class) chunk; calibrated by the 1p4hj AC-10 recall eval
_QUERY_STOPWORDS = frozenset(
    # function words only — NOT domain words (mode/local/value/default/model stay as content
    # terms, else a constant like DEFAULT_TIMEOUT would never match a "default timeout" query)
    "a an the of to in on at for is are be do does did what which who whom where when how why "
    "this that it its with and or as has have had can could should would will use used uses".split()
)

