# Popen call. We poll the subprocess for up to TIMEOUT seconds in POLL_INTERVAL
# increments. A process that survives the window has acquired its locks and is
# in build_index proper; a process that exits inside the window with non-zero
# code surfaces as build_failed_early in the response. Tests can monkeypatch
# the constants to short-circuit the wait.
_INDEX_BUILD_VERIFY_TIMEOUT_SECONDS = 1.5
_INDEX_BUILD_VERIFY_POLL_INTERVAL_SECONDS = 0.1


def _index_layer_readiness(layer: dict[str, Any]) -> str:
    """Per-layer index state for operators (missing / stale / current / idle)."""
    has_sources = bool(layer.get("has_sources"))
    meta_present = bool(layer.get("meta_present"))
    docs_present = bool(layer.get("docs_present"))
    stale_paths = layer.get("stale_paths") or []
    if has_sources and (not meta_present or not docs_present):
        return "missing"
    if stale_paths:
        return "stale"
    if meta_present and docs_present:
        return "current"
    return "idle"


def _index_readiness_overview(
    missing_layers: list[str],
    stale_layers: list[str],
    compatible_chunks: bool,
    has_any_index: bool,
) -> str:
    """Aggregate readiness: incomplete, needs_update, degraded, absent, or ready."""
    if missing_layers:
        return "incomplete"
    if stale_layers:
        return "needs_update"
    if has_any_index and not compatible_chunks:
        return "degraded"
    if not has_any_index:
        return "absent"
    return "ready"


@contextlib.contextmanager
def _offline_model_env():
    """Module-level context manager: sets HF_HUB_OFFLINE=1 and restores on exit."""
    prior = os.environ.get("HF_HUB_OFFLINE")
    os.environ["HF_HUB_OFFLINE"] = "1"
    try:
        yield
    finally:
        if prior is None:
            os.environ.pop("HF_HUB_OFFLINE", None)
        else:
            os.environ["HF_HUB_OFFLINE"] = prior


def _ensure_model_cached(model_name: str, model_type: str) -> None:
    """Download model files to cache without loading into server working memory.

    The instantiated model object is immediately discarded — this function's
    sole purpose is to populate the on-disk cache so subsequent _get_embedder()
    or _get_reranker() calls succeed offline.
    """
    import os

    if model_type == "reranker":
        # 1p52p: prewarm the cross-encoder reranker (download + compile) so the first live query is
        # fast — FP16 on the GPU or INT8 on the CPU, whichever this machine has. No-op when reranking
        # is disabled (WAVEFOUNDRY_DISABLE_RERANKER) or the model can't be built. The BAAI FP32
        # fastembed reranker is no longer downloaded.
        try:
            import accel_embedder
        except Exception:
            _wf_log(f"[wavefoundry] accel_embedder unavailable; skipping reranker prewarm: {model_name}")
            return
        try:
            reranker = accel_embedder.make_reranker(model_name, [])  # online: downloads + compiles
            if reranker is not None:
                _wf_log(f"[wavefoundry] reranker prewarmed: {model_name} ({reranker.provider})")
            else:
                _wf_log(f"[wavefoundry] reranker not built (disabled or unbuildable): {model_name}")
        except Exception as exc:  # noqa: BLE001
            _wf_log(f"[wavefoundry] reranker prewarm failed for {model_name}: {exc}")

    else:  # embedding
        from fastembed import TextEmbedding

        # Check if already cached (offline probe)
        try:
            with _offline_model_env():
                try:
                    TextEmbedding(model_name=model_name, local_files_only=True)
                except TypeError:
                    TextEmbedding(model_name=model_name)
            _wf_log(f"[wavefoundry] Embedding model already cached: {model_name}")
            return
        except Exception:
            pass

        # Not cached — download (object discarded)
        import setup_index  # wave 1p939: apply the same CA ladder wf setup uses before downloading

        def _download_attempt():
            try:
                TextEmbedding(model_name=model_name, local_files_only=False)
            except TypeError:
                TextEmbedding(model_name=model_name)

        setup_index.ensure_ca_bundle_applied()
        setup_index.retry_with_ca_bundle_ladder(_download_attempt, model_name)
        _wf_log(f"[wavefoundry] Model cached: {model_name}")


class WaveIndex:
    """Loaded in-memory index for semantic search."""

    def __init__(self, root: Path) -> None:
        self.root = root
        self.index_dir = root / ".wavefoundry" / "index"
        self._docs_lance_table = None   # LanceDB Table object for docs, None if not loaded
        self._code_lance_table = None   # LanceDB Table object for code, None if not loaded
        self._reranker = None
        # Wave 1p4wz: serialize the one-time lazy build of the reranker / embedders. FastMCP dispatches
        # tools on a thread pool, so N concurrent first queries could otherwise each pay the CoreML
        # compile + GPU-offload probe (and race the shared offline-env mutation). The locks guard only
        # the build, not steady-state ``.rerank()``/``.embed()`` (ORT sessions are run-thread-safe).
        import threading
        self._reranker_lock = threading.Lock()
        self._embedder_lock = threading.Lock()
        # Wave 1p4wy: cache the embedder per model name so the CoreML/ONNX session
        # (and its ~40s compile) is built once per process, not rebuilt per query.
        self._embedders: dict[str, Any] = {}
        self._model_downloads_started: bool = False
        self._meta: dict = {}
        self._loaded = False
        self._loaded_meta_signature: dict[str, tuple[int, int] | None] = {}
        self._lance_available: set[tuple[str, str]] = set()

    def _open_lance_table(self, layer: str, kind: str):
        """Open a LanceDB table fresh on every call — never returns a stale handle."""
        available = getattr(self, "_lance_available", None)
        if available is not None and (layer, kind) not in available:
            return None
        index_dir = getattr(self, "index_dir", None)
        if index_dir is None:
            return object() if available and (layer, kind) in available else None
        table_path = index_dir / f"{kind}.lance"
        if not table_path.is_dir():
            return object() if available and (layer, kind) in available else None
        try:
            import lancedb
            db = lancedb.connect(str(index_dir))
            return db.open_table(kind)
        except Exception:
            return None

    @staticmethod
    def _fts_query(query: str) -> str:
        stripped = query.strip()
        if len(stripped) >= 2 and stripped[0] == stripped[-1] and stripped[0] in ('"', "'", "`"):
            return stripped[1:-1]
        return query

    def _fts5_lexical_search(
        self,
        table_name: str,
        query: str,
        top_n: int,
        kind: Optional[str] = None,
        tags: Optional[list] = None,
        layer: str = "project",
    ) -> list[dict]:
        """Lexical candidates from the index-state store's FTS5 tables (wave 1rsh9 / 1sauc).

        Replaces the retired Lance/Tantivy ``_lance_fts_search`` as the FTS
        half of ``search_code``'s hybrid merge. Filter parity with the Lance
        ``where`` clause it replaced: exact ``kind`` match and any-of ``tags``
        substring match apply inside the FTS5 query; the ``language``
        post-filter works because rows carry a ``language`` field. Scores are
        ``-bm25`` (higher = better) so the existing best-first sort and RRF
        rank order hold. Every degrade path — absent store, FTS5-less
        interpreter, FTS-hostile query — returns ``[]`` (dense-only hybrid),
        never an error.
        """
        fts_q = self._fts_query(query)
        try:
            iss = _load_script("index_state_store")
            index_dir = Path(self.root) / ".wavefoundry" / "index"
            hits = iss.fts_search(index_dir, table_name, fts_q, limit=top_n,
                                  kind=kind, tags_any=tags)
        except Exception:  # noqa: BLE001 - the lexical half is additive only
            return []
        out = []
        for h in hits:
            out.append({
                "id": h.get("id", ""),
                "path": self._qualify_index_path(h.get("path", ""), layer),
                "kind": h.get("kind", ""),
                "language": h.get("language", ""),
                "tags": h.get("tags", ""),
                "lines": list(h.get("lines") or []),
                "text": h.get("text", ""),
                # sqlite bm25() is smaller-is-better (negative); negate so the
                # existing higher-is-better sort and RRF ordering apply.
                "score": -float(h.get("bm25", 0.0)),
            })
        return out

    def _indexer_module(self):
        return _load_script("indexer")

    def _layer_current_hashes(self, layer: str = "project") -> dict[str, str]:
        idx = self._indexer_module()
        files = idx.walk_repo(self.root, respect_ignore=True)
        files = [path for path in files if not idx._is_relative_to(path, self.index_dir)]
        # Wave 1p31b (1p312 in-session): match the indexer's actual
        # files_for_meta eligibility by reading project_include_prefixes
        # from workflow-config. Without this, the audit's "current
        # eligibility" misses workflow-config opt-ins (e.g. wavefoundry's
        # own self-host opts in `.wavefoundry/framework/scripts` and the
        # 1p4ww folded framework seeds/README) and reports false-positive
        # ``removed_paths`` for paths the indexer correctly indexed.
        # Wave 1p4ww: ``_project_meta_include_prefixes`` is the single source of truth for
        # project file_meta eligibility — the docs+code surface PLUS the folded framework
        # seeds/README. Using it here keeps the health walk aligned with the build walk, so
        # the folded docs don't read as false ``removed_paths`` against the index.
        meta_project_includes = idx._project_meta_include_prefixes(self.root, ())
        files = idx._filter_project_index_excludes(
            files,
            self.root,
            (),
            project_include_prefixes=meta_project_includes,
        )
        return idx._build_file_hashes(files, self.root)

    def _layer_health(self, layer: str = "project") -> dict[str, Any]:
        """Compute health metadata for the project index layer.

        Walks the repo and hashes every indexed file, then compares the result
        against the store's recorded build hashes (1sed6).  Paths where the digest
        differs (or that are present in one set but not the other) are reported
        as ``stale_paths``.  This is an O(total-indexed-bytes) operation — call
        it only via the explicit ``index_health`` MCP tool, never on the
        search hot path.
        """
        layer = "project"
        index_dir = self.index_dir
        docs_lance_path = index_dir / "docs.lance"
        meta = self._meta.get(layer) if self._loaded else {}
        if not isinstance(meta, dict):
            meta = {}
        current_hashes = self._layer_current_hashes(layer)
        # Indexer writes file_meta (hash + mtime + size + inode per file); health checker
        # extracts just the hash for comparison.  Fall back to legacy file_hashes key.
        raw_file_meta = meta.get("file_meta", {})
        if isinstance(raw_file_meta, dict) and raw_file_meta:
            old_hashes = {
                path: entry["hash"]
                for path, entry in raw_file_meta.items()
                if isinstance(entry, dict) and "hash" in entry
            }
        else:
            raw_file_hashes = meta.get("file_hashes", {})
            old_hashes = raw_file_hashes if isinstance(raw_file_hashes, dict) else {}
        modified_paths = sorted(
            path for path, digest in current_hashes.items()
            if path in old_hashes and old_hashes[path] != digest
        )
        added_paths = sorted(
            path for path in current_hashes
            if path not in old_hashes
        )
        removed_paths = sorted(
            path for path in old_hashes
            if path not in current_hashes
        )
        stale_paths = sorted(set(modified_paths) | set(added_paths) | set(removed_paths))
        docs_present = docs_lance_path.is_dir()
        meta_present = _store_has_completed_build(index_dir)  # 1sed6: epoch, not a file
        raw_chunker_versions = meta.get("chunker_versions", {})
        indexed_chunker_versions: dict[str, str] = (
            raw_chunker_versions if isinstance(raw_chunker_versions, dict) else {}
        )
        current_chunker_version: str = _read_chunker_version()
        # 1p7is: detect a silently-absent code layer. Code sources are "in scope" only when code
        # include-prefixes are configured AND at least one indexed-eligible file matches them — so a
        # docs-only repo (no code prefixes) is never flagged for a missing code.lance.
        code_present = (index_dir / "code.lance").is_dir()
        try:
            code_prefixes = self._indexer_module()._workflow_project_include_prefixes(self.root).get("code", ())
        except Exception:
            code_prefixes = ()
        code_sources_in_scope = bool(code_prefixes) and any(
            any(rel.startswith(p) for p in code_prefixes) for rel in current_hashes
        )
        return {
            "layer": layer,
            "index_dir": str(index_dir),
            "meta_present": meta_present,
            "docs_present": docs_present,
            "code_present": code_present,
            "code_sources_in_scope": code_sources_in_scope,
            "has_sources": bool(current_hashes),
            "stale_paths": stale_paths,
            "stale_paths_count": len(stale_paths),
            "modified_paths_count": len(modified_paths),
            "added_paths_count": len(added_paths),
            "removed_paths_count": len(removed_paths),
            "current_hash_count": len(current_hashes),
            "indexed_chunker_versions": indexed_chunker_versions,
            "current_chunker_version": current_chunker_version,
        }

    def docs_health(self) -> dict[str, Any]:
        # Wave 1p4ww: single project docs index — the framework layer is folded in.
        self._ensure_loaded()
        project = self._layer_health("project")
        project["readiness"] = _index_layer_readiness(project)
        compatible_chunks = (
            getattr(self, "_docs_lance_table", None) is not None
            or getattr(self, "_code_lance_table", None) is not None
        )
        has_any_index = project["meta_present"]
        stale_layers = [project["layer"]] if project["stale_paths"] else []
        missing_layers = [
            project["layer"]
        ] if project["has_sources"] and (not project["meta_present"] or not project["docs_present"]) else []
        # 1p7is: a configured-but-absent code layer (e.g. the code embedding pass was OOM-killed)
        # makes the index incomplete, not ready — surface it instead of letting docs.lance mask it.
        code_layer_missing = project["code_sources_in_scope"] and not project["code_present"]
        if code_layer_missing and "code" not in missing_layers:
            missing_layers = [*missing_layers, "code"]
        readiness_overview = _index_readiness_overview(
            missing_layers, stale_layers, compatible_chunks, has_any_index
        )
        # Detect chunker version mismatch: index was built with an older CHUNKER_VERSION.
        # Fires even when file hashes are current (e.g. after a pack upgrade before rebuild).
        chunker_version_mismatch_layers: list[str] = []
        current_cv = project.get("current_chunker_version", "")
        indexed_cvs = project.get("indexed_chunker_versions", {})
        if current_cv and project.get("meta_present") and isinstance(indexed_cvs, dict) and any(
            v != current_cv for v in indexed_cvs.values() if v
        ):
            chunker_version_mismatch_layers.append(project["layer"])
        return {
            "project": project,
            "has_any_index": has_any_index,
            "stale_layers": stale_layers,
            "missing_layers": missing_layers,
            "compatible_chunks": compatible_chunks,
            "readiness_overview": readiness_overview,
            "semantic_ready": has_any_index and not stale_layers and compatible_chunks and not code_layer_missing,
            "code_layer_missing": code_layer_missing,
            "chunker_version_mismatch_layers": chunker_version_mismatch_layers,
        }

    @contextlib.contextmanager
    def _offline_model_env(self):
        with _offline_model_env():
            yield

    def _live_docs_chunks(self) -> list[dict[str, Any]]:
        """Walk the repo and chunk all doc files on the fly (no index required).

        Used as a lexical-fallback data source when the semantic index is
        unavailable or not yet built.  Does a full filesystem walk on every
        call — not suitable for the search hot path in large repos.  Results
        are not cached here; callers should cache if repeated fallback queries
        are expected.
        """
        idx = self._indexer_module()
        files = idx.walk_repo(self.root, respect_ignore=True)
        files = [path for path in files if not idx._is_relative_to(path, self.index_dir)]

        chunks: list[dict[str, Any]] = []
        seen_paths: set[str] = set()
        for path in files:
            rel = str(path.relative_to(self.root)).replace("\\", "/")
            if rel.startswith(".wavefoundry/framework/"):
                if not rel.endswith(".md") and not rel.endswith(".json"):
                    continue
            elif not rel.startswith("docs/"):
                continue
            if rel in seen_paths:
                continue
            seen_paths.add(rel)
            try:
                content = path.read_text(encoding="utf-8", errors="replace")
            except OSError:
                continue
            doc_chunks, _ = idx._chunks_for_file(rel, content)
            chunks.extend(doc_chunks)
        return chunks

    def _lexical_score(self, query: str, chunk: dict[str, Any]) -> float:
        terms = re.findall(r"[a-z0-9]+", query.lower())
        if not terms:
            return 0.0
        haystack = " ".join(
            str(chunk.get(field) or "")
            for field in ("path", "section", "text", "kind")
        ).lower()
        score = 0.0
        unique_terms = set(terms)
        for term in unique_terms:
            count = haystack.count(term)
            if count:
                score += 1.0 + min(count, 5) * 0.25
                if str(chunk.get("path") or "").lower().endswith(f"{term}.md"):
                    score += 0.5
        return score

    def _doc_matches_kind(self, chunk: dict[str, Any], kind: Optional[str]) -> bool:
        if not kind:
            return True
        chunk_kind = str(chunk.get("kind") or "")
        normalized_path = str(chunk.get("path") or "").replace("\\", "/")
        if kind == "seed":
            return chunk_kind == "seed"
        if kind == "prompt":
            return chunk_kind == "prompt"
        if kind == "doc-summary":
            return chunk_kind == "doc-summary"
        if chunk_kind != "doc":
            return False
        if kind == "doc":
            return True
        if kind == "architecture":
            return normalized_path == "docs/ARCHITECTURE.md" or normalized_path.startswith("docs/architecture/")
        return chunk_kind == kind

    def search_docs_lexical(self, query: str, kind: Optional[str] = None, top_n: int = 5, tags: Optional[list] = None) -> list[dict]:
        chunks = self._live_docs_chunks()
        if kind:
            chunks = [chunk for chunk in chunks if self._doc_matches_kind(chunk, kind)]
        if tags:
            # 1seaq review fix: the tag filter survives the live walk —
            # any-of substring semantics, matching the FTS layer's contract.
            tag_list = [str(x) for x in tags if x]
            chunks = [
                chunk for chunk in chunks
                if any(tg in str(chunk.get("tags") or "") for tg in tag_list)
            ]
        ranked = []
        for chunk in chunks:
            score = self._lexical_score(query, chunk)
            if score <= 0:
                continue
            ranked.append({**chunk, "score": score})
        ranked.sort(key=lambda chunk: (-float(chunk["score"]), str(chunk.get("path") or ""), str(chunk.get("section") or "")))
        return ranked[:top_n]

    def _index_meta_signature(self, index_dir: Path) -> "tuple[str, int] | None":
        """1sed6: the reload-invalidation signal is the store's build epoch
        token ``(attempt_id, generation)`` — complete builds only. ``None``
        means not ready / building / interrupted (readers fail closed);
        SQLite file mtime is never consulted (WAL makes it meaningless)."""
        try:
            iss = _load_script("index_state_store")
        except Exception:
            return None
        try:
            return iss.build_epoch_token(index_dir)
        except Exception:
            return None

    def _ensure_loaded(self) -> None:
        if self._loaded:
            # Invalidate if the index has been rebuilt since we last loaded
            # (generation advanced) or the epoch is no longer complete.
            project_signature = self._index_meta_signature(self.index_dir)
            if project_signature is None or project_signature != self._loaded_meta_signature.get("project"):
                self._loaded = False
        if self._loaded:
            return

        _token = self._index_meta_signature(self.index_dir)
        if _token is None:
            # 1sed6 fail-closed contract: no completed build epoch — the
            # store is absent, uninitialized, mid-build, or interrupted.
            raise IndexNotReadyError(
                f"Index state at {self.index_dir} has no completed build epoch "
                "(absent, building, or interrupted). "
                "Run: python3 .wavefoundry/framework/scripts/setup_wavefoundry.py "
                "or index_build(content='all', mode='update')."
            )

        def _load_lance_table(index_dir: Path, table_name: str):
            """Return an open LanceDB Table, or None if the table directory is absent."""
            table_path = index_dir / f"{table_name}.lance"
            if not table_path.is_dir():
                return None
            try:
                import lancedb
                db = lancedb.connect(str(index_dir))
                return db.open_table(table_name)
            except ImportError:
                print(
                    "[wavefoundry] LanceDB index found but lancedb is not installed — "
                    "run: python3 .wavefoundry/framework/scripts/setup_wavefoundry.py",
                    file=sys.stderr,
                )
                return None
            except Exception:
                return None

        proj_docs_table = _load_lance_table(self.index_dir, "docs")
        proj_code_table = _load_lance_table(self.index_dir, "code")

        if not any(t is not None for t in (proj_docs_table, proj_code_table)):
            raise IndexNotReadyError(
                "[wavefoundry] No index found. "
                "Run: python3 .wavefoundry/framework/scripts/setup_wavefoundry.py"
            )

        # 1p4ww: single project layer — the framework index is folded into the project docs index.
        self._docs_lance_table = proj_docs_table
        self._code_lance_table = proj_code_table
        self._proj_docs_lance_table = proj_docs_table
        self._proj_code_lance_table = proj_code_table
        self._lance_available = set()
        for kind in ("docs", "code"):
            if (self.index_dir / f"{kind}.lance").is_dir():
                self._lance_available.add(("project", kind))

        def _load_meta_only(index_dir: Path) -> dict:
            # 1sed6: build-state snapshot from the store (meta.json retired).
            try:
                iss = _load_script("index_state_store")
                return iss.export_meta_snapshot(index_dir) or {}
            except Exception:
                return {}

        self._meta = {
            "project": _load_meta_only(self.index_dir),
        }
        self._loaded_meta_signature = {
            "project": _token,
        }
        self._loaded = True

    # ------------------------------------------------------------------
    # Embedding model
    #
    # Current model: BAAI/bge-base-en-v1.5  (768-d float32)
    # Defined in:    indexer.py  DOCS_MODEL / CODE_MODEL constants
    # Upgrade doc:   docs/architecture/embedding-model.md
    #
    # To upgrade the model:
    #   1. Change DOCS_MODEL / CODE_MODEL in indexer.py
    #   2. Update _EXPECTED_DOCS_MODEL / _EXPECTED_EMBEDDING_DIM in
    #      SemanticEmbeddingRegressionTests (test_server_tools.py)
    #   3. Delete .wavefoundry/index/ and rebuild:
        #        python3 .wavefoundry/framework/scripts/setup_wavefoundry.py --root . --include-code
    #   4. Run tests — all SemanticEmbeddingRegressionTests must pass
    #
    # Skip/fallback contract:
    #   - fastembed not installed          → IndexNotReadyError
    #   - model not locally cached         → SemanticModelUnavailableOfflineError
    #   - Both are caught by docs_search   → lexical fallback, mode="lexical" in response
    #
    # Wave 1p935/1p936: when the index's recorded model_versions class for this layer is "int8",
    # the query embedder is the accel CPU-INT8 StaticShapeEmbedder (not fastembed) — matching the
    # precision the index was actually built at, regardless of the CURRENT machine's own
    # classification. "full" (FP16/FP32/legacy-unrecorded) is unchanged fastembed-resident.
    # ------------------------------------------------------------------
    def _get_embedder(self, model_name: str):
        # Wave 1p4wy: per-process embedder cache (mirrors ``_get_reranker``). On the
        # CoreML path the ONNX session compile is ~40s; without this guard a fresh
        # embedder was built on every query, re-paying the compile each time.
        cached = self._embedders.get(model_name)
        if cached is not None:
            return cached
        lock = getattr(self, "_embedder_lock", None)
        if lock is None:  # bypass-constructed instance (e.g. WaveIndex.__new__ in tests)
            import threading
            lock = self._embedder_lock = threading.Lock()
        with lock:
            # Re-check under the lock so the ~40s CoreML compile (and the shared offline-env mutation)
            # runs once per model even if several queries race the first build.
            cached = self._embedders.get(model_name)
            if cached is not None:
                return cached

            # Wave 1p935/1p936: pick the query embedder's precision from the INDEX's recorded
            # class (model_versions), not the current machine's classification — so query and
            # index precision agree even when they differ (e.g. this query ran on a different
            # host than the one that built the index). Only INT8 diverges from the plain
            # fastembed-resident path below; "full" (FP16/FP32/legacy-unrecorded) is unchanged.
            docs_model = self._indexer_constant("DOCS_MODEL")
            code_model = self._indexer_constant("CODE_MODEL")
            layer = "docs" if model_name == docs_model else "code" if model_name == code_model else None
            recorded_version = None
            if layer is not None:
                # getattr: a bypass-constructed instance (e.g. WaveIndex.__new__ in tests) may
                # not have run __init__, so ``_meta`` might not exist as an attribute at all.
                meta = getattr(self, "_meta", None) or {}
                model_versions = (meta.get("project") or {}).get("model_versions") or {}
                recorded_version = model_versions.get(layer)
            precision_class_from_version = self._indexer_constant("_precision_class_from_version")
            if precision_class_from_version(recorded_version) == "int8":
                try:
                    import accel_embedder
                except Exception:
                    accel_embedder = None
                if accel_embedder is not None:
                    try:
                        # Construct StaticShapeEmbedder directly rather than going through
                        # make_embedder(): the precision decision is already made (from the
                        # index's recorded class, above), so this must force CPU-INT8
                        # unconditionally — make_embedder()'s own GPU-availability fallback
                        # (a deliberate safety net for its indexer.py caller, wave 1p517) would
                        # override an explicit CPU-only request back to GPU on a machine that
                        # also has a GPU, which is exactly the cross-machine mismatch this
                        # precision-from-index-version logic exists to prevent.
                        with self._offline_model_env():
                            accel = accel_embedder.StaticShapeEmbedder(model_name, ["CPUExecutionProvider"])
                    except Exception:
                        accel = None
                    if accel is not None:
                        self._embedders[model_name] = accel
                        return accel
                    # INT8 build unavailable (e.g. not cached, offline) — fall through to the
                    # fastembed full-precision path below rather than raising; a degraded but
                    # usable query beats no query (residual risk noted in change 1p936 Risks).

            try:
                from fastembed import TextEmbedding
            except ImportError:
                raise IndexNotReadyError(
                    "fastembed is not installed. Run: python3 .wavefoundry/framework/scripts/setup_wavefoundry.py"
                )
            try:
                with self._offline_model_env():
                    embedder = TextEmbedding(model_name=model_name, local_files_only=True)
            except TypeError:
                try:
                    with self._offline_model_env():
                        embedder = TextEmbedding(model_name=model_name)
                except Exception as exc:  # pragma: no cover - fallback path
                    raise SemanticModelUnavailableOfflineError(
                        f"Semantic query model '{model_name}' is unavailable offline. "
                        "Run: python3 .wavefoundry/framework/scripts/setup_wavefoundry.py --root ."
                    ) from exc
            except Exception as exc:
                raise SemanticModelUnavailableOfflineError(
                    f"Semantic query model '{model_name}' is unavailable offline. "
                    "Run: python3 .wavefoundry/framework/scripts/setup_wavefoundry.py --root ."
                ) from exc
            self._embedders[model_name] = embedder
            return embedder

    def _embed_query(self, text: str, model_name: str) -> "np.ndarray":
        import numpy as np
        embedder = self._get_embedder(model_name)
        # Wave 1p4wx: asymmetric models (e.g. arctic-embed for docs) require an
        # instruction prefix on the QUERY side. fastembed ``.embed()`` does not
        # apply it, so prepend it explicitly. Empty for symmetric models (bge).
        prefix = self._indexer_module().query_embedding_prefix(model_name)
        query_text = f"{prefix}{text}" if prefix else text
        try:
            with self._offline_model_env():
                return next(iter(embedder.embed([query_text])))
        except Exception as exc:
            raise SemanticModelUnavailableOfflineError(
                f"Semantic query model '{model_name}' is unavailable offline. "
                "Run: python3 .wavefoundry/framework/scripts/setup_wavefoundry.py --root ."
            ) from exc

    def _get_reranker(self):
        """Wave 1p52p: FP16-on-GPU / INT8-on-CPU cross-encoder reranker (`accel_embedder`).

        ``make_reranker`` picks the path for this hardware: a GPU machine gets the FP16 GPU reranker
        (~350 ms/query); a CPU-only machine gets the INT8 CPU reranker (~960 ms/query, no ranking
        loss). It returns ``None`` only when reranking is explicitly disabled
        (``WAVEFOUNDRY_DISABLE_RERANKER``) or the model can't be built — then the search path degrades
        to vector order (the call sites tolerate ``None``), logged once so it's observable.
        """
        if self._reranker is not None:
            return self._reranker
        if getattr(self, "_reranker_disabled", False):
            return None
        lock = getattr(self, "_reranker_lock", None)
        if lock is None:  # bypass-constructed instance (e.g. WaveIndex.__new__ in tests)
            import threading
            lock = self._reranker_lock = threading.Lock()
        with lock:
            # Re-check under the lock: a racing first query may have finished the build (or marked it
            # disabled) while we waited, so the costly compile/probe runs exactly once per process.
            if self._reranker is not None:
                return self._reranker
            if getattr(self, "_reranker_disabled", False):
                return None
            try:
                import accel_embedder
            except Exception:
                accel_embedder = None
            reranker = None
            if accel_embedder is not None:
                try:
                    RERANKER_MODEL = self._indexer_constant("RERANKER_MODEL")
                    # Wave 1p937: pass the SAME resolved provider list the embedder dispatch uses
                    # (indexer._onnx_providers()) instead of an empty list, so the reranker's
                    # GPU-vs-CPU (FP16-vs-INT8) selection keys off the same classification as the
                    # embedder — one machine classification drives the whole pipeline (ADR 1p92d).
                    onnx_providers = self._indexer_constant("_onnx_providers")
                    reranker = accel_embedder.make_reranker(RERANKER_MODEL, onnx_providers())
                except Exception:
                    reranker = None
            if reranker is None:
                self._reranker_disabled = True  # don't re-probe every query
                _wf_log(
                    "[wavefoundry] No reranker (disabled or unbuildable); search uses vector order "
                    "without the cross-encoder rerank stage."
                )
                return None
            self._reranker = reranker
            _wf_log(
                f"[wavefoundry] using cross-encoder reranker: {reranker.model_name} "
                f"({reranker.provider}, static {accel_embedder.STATIC_BATCH}x{accel_embedder.STATIC_SEQ})"
            )
            return self._reranker

    def _start_background_model_downloads(self) -> None:
        import os
        import threading

        if os.environ.get("HF_HUB_OFFLINE") == "1":
            _wf_log("[wavefoundry] HF_HUB_OFFLINE set; skipping background model download")
            return

        if self._model_downloads_started:
            return
        self._model_downloads_started = True

        def _download_worker() -> None:
            try:
                docs_model = self._indexer_constant("DOCS_MODEL")
                code_model = self._indexer_constant("CODE_MODEL")
                reranker_model = self._indexer_constant("RERANKER_MODEL")
            except Exception as exc:
                _wf_log(f"[wavefoundry] Background model download: could not read model constants: {exc}")
                return

            # Deduplicate
            embedding_models = list(dict.fromkeys([docs_model, code_model]))
            all_models = [("embedding", m) for m in embedding_models] + [("reranker", reranker_model)]

            for model_type, model_name in all_models:
                try:
                    _ensure_model_cached(model_name, model_type)
                except Exception as exc:
                    _wf_log(f"[wavefoundry] Background download failed for {model_name}: {exc}")

        thread = threading.Thread(target=_download_worker, daemon=True, name="wavefoundry-model-download")
        thread.start()

    def _start_background_model_downloads_after_startup(self) -> None:
        """Start optional model-cache prewarm outside the MCP startup path.

        MCP clients usually bind tools during process startup. Keep that phase
        limited to imports and tool registration; model/cache work can contend
        for import locks, disk, network, and CPU on slower machines.
        """
        if not hasattr(self, "_model_downloads_started"):
            self._model_downloads_started = False
        self._start_background_model_downloads()

    def _agent_rerank(self, query: str, candidates: list[dict]) -> bool:
        """Wave 1p52p: cross-encoder rerank for agent mode, run BEFORE selection.

        Replaces each candidate's ``score`` with the UNIFIED relevance ``sigmoid(logit)`` ∈ [0,1] so
        the agent selection (per-index floor, relevance drop-off, text budget) and the confidence band
        all key off one scale — the arctic-doc vs bge-code cosines (1p4wx split) are not comparable.
        Mutates ``candidates`` in place; returns True if the cross-encoder ran — it runs on either
        hardware (GPU FP16 or CPU INT8). Returns False only when the reranker is unavailable
        (disabled/unbuildable): scores stay raw cosine and the caller caps confidence at
        "medium" ("low" with zero citations). Never raises.
        """
        reranker = self._get_reranker()
        if not reranker or not candidates:
            return False
        try:
            import math
            logits = list(reranker.rerank(query, [c.get("text", "") for c in candidates]))
            if len(logits) != len(candidates):
                return False
            for logit, c in zip(logits, candidates):
                c["score"] = 1.0 / (1.0 + math.exp(-float(logit)))  # sigmoid → relevance prob
                if c.get("_sym_injected") and c.get("kind") == "code":
                    c["score"] = min(c["score"] + _SYMBOL_INJECTION_BOOST, 1.0)
            return True
        except Exception:
            return False

    def _rerank(self, query: str, candidates: list[dict], top_n: int) -> list[dict]:
        reranker = self._get_reranker()
        if not reranker or not candidates:
            return candidates[:top_n]
        try:
            texts = [c.get("text", "") for c in candidates]
            scores = list(reranker.rerank(query, texts))
            min_s = min(scores)
            max_s = max(scores)
            for s, c in zip(scores, candidates):
                c["score"] = 1.0 if max_s == min_s else float((s - min_s) / (max_s - min_s))
            for c in candidates:
                if c.get("_sym_injected") and c.get("kind") == "code":
                    c["score"] = min(c["score"] + _SYMBOL_INJECTION_BOOST, 1.0)
            return sorted(candidates, key=lambda x: x.get("score", 0.0), reverse=True)[:top_n]
        except Exception:
            return candidates[:top_n]

    def _rrf_merge(self, ranked_lists: list[list[dict]], top_n: int, k: int = 60, weights: Optional[list[float]] = None) -> list[dict]:
        """Reciprocal Rank Fusion across ranked_lists.

        ``weights`` is an optional per-list multiplier applied to each RRF term.
        When omitted all lists are weighted equally (weight=1.0).
        """
        scores: dict[str, float] = {}
        chunks_by_id: dict[str, dict] = {}
        for i, ranked in enumerate(ranked_lists):
            if not ranked:
                continue
            w = weights[i] if weights and i < len(weights) else 1.0
            for rank, chunk in enumerate(ranked):
                chunk_id = str(chunk.get("id") or str(chunk.get("path", "")) + str(chunk.get("lines", "")))
                scores[chunk_id] = scores.get(chunk_id, 0.0) + w / (k + rank)
                chunks_by_id[chunk_id] = chunk
        sorted_ids = sorted(scores, key=lambda cid: scores[cid], reverse=True)
        return [chunks_by_id[cid] for cid in sorted_ids[:top_n]]

    def _node_def_candidate(self, node: dict) -> Optional[dict]:
        """Wave 1p4hu: build an agent candidate from a graph NODE — its definition text read from
        source (a bounded window), tagged kind=code, score 0.0 (it is a structural, not semantic,
        hit). None when the source file is unreadable. Path qualified via the same helper the
        semantic retrieval uses, so cross-source dedup matches."""
        sf = node.get("source_file")
        if not isinstance(sf, str) or not sf:
            return None
        head = str(node.get("source_location") or "").split(":", 1)[0]
        line = int(head) if head.isdigit() else 1
        try:
            text_lines = (self.root / sf).read_text(encoding="utf-8", errors="replace").splitlines()
        except Exception:
            return None
        start = max(0, line - 1)
        window = text_lines[start:start + AGENT_GRAPH_DEF_WINDOW]
        snippet = "\n".join(window).strip()
        if not snippet:
            return None
        label = node.get("label") or sf.rsplit("/", 1)[-1]
        breadcrumb = f"{Path(sf).stem} > {label}"
        return {
            "path": self._qualify_index_path(sf, "project"),
            "text": f"{breadcrumb}\n\n{snippet}",
            "score": 0.0,
            "kind": "code",
            "lines": [line, line + len(window)],
            "_graph_kind": node.get("kind"),
        }

    def _merge_graph_into_citations(self, query: str, graph_src: list[dict], results: list[dict], *, reranked: bool) -> int:
        """Wave 1p66t: append the strongest cross-file graph neighbors to the citation list so a
        cross-file chain reaches the answer surface (not only the ``graph_related`` section).

        The graph rescue fires ONLY for neighbors the semantic pass MISSED (not already cited) — the
        vector-miss/graph-hit case. Each candidate carries a real on-disk ``file:line`` + text window
        (``_node_def_candidate``), so it is reranked on the unified cross-encoder scale, kept only if it
        clears the relevance floor, and appended (additive — never reorders the semantic citations),
        bounded by ``AGENT_GRAPH_CITATION_CAP``. Skipped when the reranker did not run (scores are not
        comparable for the floor gate then). Returns the number merged. Mutates ``results`` in place.
        """
        if not graph_src or not reranked:
            return 0
        cited_keys = {(r.get("path"), (r.get("lines") or [None])[0]) for r in results}
        pool = [c for c in graph_src
                if (c.get("path"), (c.get("lines") or [None])[0]) not in cited_keys]
        if not pool:
            return 0
        self._agent_rerank(query, pool)
        pool.sort(key=lambda c: c.get("score") or 0.0, reverse=True)
        merged = 0
        for c in pool[:AGENT_GRAPH_CITATION_CAP]:
            if (c.get("score") or 0.0) >= CONF_AGENT_RERANK_LOW:
                c["from_graph"] = True
                results.append(c)
                merged += 1
        return merged

    def _graph_signal_candidates(self, query: str, semantic_results: list[dict], *, cap: int) -> list[dict]:
        """Wave 1p4hu: structural graph-signal candidates that feed the dedicated ``graph_related``
        response section (via ``_build_graph_related``), each carrying its ``_relationship`` to the
        seed (caller/reader/importer/…) — NOT injected into the textual citations. Bounded by ``cap``
        (AC-3); returns [] when the graph is absent/empty or no symbol resolves — graceful fallback (AC-4).

        Seed + direction strategy (delivery follow-up — a live 17-query sweep showed the original
        union-of-both-directions, both-seed-channels approach was mostly noise):
        - **TARGETED** (the query NAMES a resolvable identifier, e.g. "what reads RERANKER_MODEL"):
          expand ONLY that symbol — NOT the top semantic hits, whose neighbors are co-location
          noise. Direction follows phrasing: "what calls/reads/uses/references X" / "where is X
          used" wants edges INTO X (its callers / readers / importers — ``direction="in"``), so it
          stops answering a *callers* question with the seed's *callees*; "how does X work" / "what
          is X" keeps both directions (the mechanism).
        - **BEHAVIORAL / NL** (no named identifier, e.g. "how does the chunker split markdown"):
          expand the top semantic hits' symbols, both directions — this is where the wins are (the
          referenced split constants / decision helpers the semantic ranker missed).
        Test-file structural neighbors are suppressed (a user rarely wants a fixture as the answer),
        common generic words are excluded from seed resolution (D3), and candidates are deduped
        against semantic hits by start line (D2)."""
        if cap <= 0:
            return []
        try:
            gq = _load_graph_query()
            index = gq.get_query_index(self.root, layer="project")
            if not getattr(index, "present", False):
                return []
        except Exception:
            return []

        def _resolve(name: str) -> Optional[str]:
            name = (name or "").strip()
            if len(name) < 4 or name.lower() in _GRAPH_SEED_STOPWORDS or name.lower() in _QUERY_STOPWORDS:
                return None
            try:
                return index.resolve_symbol(name)
            except Exception:
                return None

        # Seed channel 2 (PRIMARY when present): identifiers the query NAMES — the user's targets.
        seed_ids: list[str] = []
        seed_set: set[str] = set()
        for tok in _GRAPH_QUERY_IDENT_RE.findall(query or "")[:8]:
            nid = _resolve(tok)
            if nid and nid not in seed_set:
                seed_set.add(nid)
                seed_ids.append(nid)

        ql = (query or "").lower()
        incoming_intent = bool(_GRAPH_USER_INTENT_RE.search(ql)) and not bool(_GRAPH_OUTGOING_INTENT_RE.search(ql))
        if seed_ids and incoming_intent:
            # TARGETED — "what calls/reads/uses X": expand ONLY the named symbol(s), edges INTO them
            # (callers/readers/importers). This is the precision case where the old both-directions
            # union answered a callers question with the seed's callees.
            direction = "in"
        else:
            # BEHAVIORAL / mechanism ("how does X work", or no user-finding verb): expand the named
            # symbol(s) (if any) AND the top semantic hits' symbols, both directions — this is where
            # the wins are (a correctly-ranked seed's referenced split constants / decision helpers
            # the semantic ranker missed). Seeding the named symbol here too means "how does X work"
            # still surfaces X's mechanism without the co-location noise that targeting-only caused.
            for c in semantic_results[:4]:
                section = str(c.get("section") or "")
                if " > " in section:
                    nid = _resolve(section.rsplit(" > ", 1)[-1])
                    if nid and nid not in seed_set:
                        seed_set.add(nid)
                        seed_ids.append(nid)
            direction = "both"
        if not seed_ids:
            return []

        try:
            nb = index.one_hop_neighbors(seed_ids, relations=list(_GRAPH_SIGNAL_RELATIONS), max_neighbors=cap * 6, direction=direction)
        except Exception:
            return []
        nodes = nb.get("nodes", [])
        node_label = {n.get("id"): (n.get("label") or "") for n in nodes}
        # Map each neighbor node → (relationship to the seed, seed label, edge confidence) from the
        # traversed edges, so the response can group structural matches by RELATIONSHIP (caller /
        # reader / importer) — the actual answer to "what calls/reads X" — instead of an
        # undifferentiated source="graph" tag. First edge per neighbor wins.
        rel_by_node: dict[str, tuple[str, str, Optional[str]]] = {}
        for e in nb.get("edges", []):
            src, tgt, rel = e.get("source"), e.get("target"), e.get("relation")
            if src in seed_set and tgt not in seed_set:
                neighbor, incoming, seed = tgt, False, src
            elif tgt in seed_set and src not in seed_set:
                neighbor, incoming, seed = src, True, tgt
            else:
                continue
            if neighbor not in rel_by_node:
                rel_by_node[neighbor] = (_GRAPH_REL_LABEL.get((rel, incoming), "related"),
                                         node_label.get(seed, ""), e.get("confidence"))
        seen: set[tuple] = set()
        out: list[dict] = []
        for node in nodes:
            if len(out) >= cap:
                break
            nid = node.get("id")
            if not isinstance(nid, str) or nid.startswith("external::") or nid in seed_set:
                continue
            if node.get("kind") not in _GRAPH_SIGNAL_CAND_KINDS:
                continue
            # Suppress test-file structural neighbors — a "what calls/reads X" or "how does X work"
            # question rarely wants a test fixture as a structural answer (the sweep showed mis-
            # resolved seeds dragging in _fake_*/CHUNKER_PATH test helpers).
            if _is_test_path(str(node.get("source_file") or "")):
                continue
            cand = self._node_def_candidate(node)
            if cand is None:
                continue
            key = (cand["path"], (cand.get("lines") or [None])[0])
            if key in seen:
                continue
            seen.add(key)
            rel, seed_label, conf = rel_by_node.get(nid, ("related", "", None))
            cand["_relationship"] = rel
            cand["_seed"] = seed_label
            cand["_confidence"] = conf
            cand["_symbol"] = node.get("label") or ""
            out.append(cand)
        return out

    def _build_graph_related(self, cands: list[dict], citations: Optional[list[dict]] = None) -> dict[str, Any]:
        """Wave 1p4hu: assemble the response's ``graph_related`` section — structural matches grouped
        by their RELATIONSHIP to the query's symbol (``callers``/``readers``/``importers`` for a
        "what calls/reads/uses X" question; ``related`` for behavioral both-direction neighbors).
        This replaces mixing 0.0-scored graph rows into the textual ``citations``: the relationship
        (the actual answer) is preserved, and the structural evidence is its own block.

        Semantic dedup: a structural match that is ALSO a semantic citation keeps its relationship
        entry (so the structural answer stays complete + labeled) but DROPS the duplicate ``excerpt``
        and is flagged ``also_cited`` — the agent reads the full text from the citation, so the same
        chunk text is never sent twice. Matched on (path, start line), the cross-source identity.
        Dedup SCOPE (re-review B1/B2): ``citations`` here is the SEMANTIC selection (the keyword
        fallback runs only when <2 citations, which never co-occurs with a resolved graph symbol), and
        the match is exact-start-line (a graph def nested strictly inside a larger citation chunk's
        range escapes) — both bound the observed text duplication to negligible, not a correctness gap.
        The (path, start-line) identity is collision-free among real code symbols (0 distinct-symbol
        start-line collisions in non-test function/method/class/constant nodes on the live graph)."""
        cited = {(str(c.get("path", "")), (c.get("lines") or [None])[0]) for c in (citations or [])}
        seeds: list[str] = []
        buckets: dict[str, list[dict]] = {}
        for c in cands:
            seed = c.get("_seed") or ""
            if seed and seed not in seeds:
                seeds.append(seed)
            lines = c.get("lines") or []
            entry: dict[str, Any] = {
                "symbol": c.get("_symbol") or "",
                "path": c.get("path"),
                "lines": c.get("lines"),
                "kind": c.get("_graph_kind") or c.get("kind"),
            }
            if c.get("_confidence"):
                entry["confidence"] = c.get("_confidence")
            if (str(c.get("path", "")), (lines[0] if lines else None)) in cited:
                entry["also_cited"] = True   # full text already in citations — don't duplicate it
            else:
                entry["excerpt"] = c.get("text") or ""
            bucket = _GRAPH_REL_BUCKET.get(c.get("_relationship") or "related", "related")
            buckets.setdefault(bucket, []).append(entry)
        out: dict[str, Any] = {"seed": seeds}
        out.update(buckets)
        return out

    def _agent_candidate_select(self, source_lists: dict[str, list[dict]], top_n: int, floor_k: int, weights: Optional[dict[str, float]] = None, text_budget: Optional[int] = None) -> list[dict]:
        """Wave 1p4hj agent-mode: labeled, deduped, per-index candidate selection.

        NO cross-encoder, NO RRF cross-source merge — the host agent fuses+ranks.
        Each source contributes its top ``floor_k`` (the per-index coverage floor,
        so a single modality can never be starved); the remaining space is then
        filled by **relevance across all sources** (best-of-rest by score) — NOT a
        forced per-source balance, which would be no better than concatenating
        ``code_search`` + ``docs_search``.

        The returned **count is variable**, governed by three limits (none a fixed N):
        (1) the **relevance drop-off** (``AGENT_RELEVANCE_DROPOFF``×top) — stop once a
        candidate is no longer in the top cluster (*enough to answer, no noise*);
        (2) the **text budget** (``text_budget`` chars of full-chunk text, ≈ tokens×4)
        — the *don't-over-feed-the-agent* ceiling, so the count adapts to chunk SIZE
        (many small chunks fit; few large ones fit — packed greedily by relevance);
        (3) a loose **count backstop** (``top_n``) for pathological tiny-chunk cases.
        Cross-source
        duplicates collapse to one representative but **preserve the multi-source
        signal** — the candidate keeps the set of ``sources`` it appeared in and its
        best per-source rank — so the agent can weigh cross-source agreement the way
        RRF's fusion rewarded it. Returns candidates tagged with ``source`` (primary)
        and ``sources`` (the set); ordering is advisory only (the agent re-ranks).
        """
        def _key(c: dict):
            return (c.get("path", ""), tuple(c.get("lines") or []))

        def _wscore_base(c: dict) -> float:
            # Un-boosted weighted relevance. Post-rerank (1p4wz) docs + code share ONE cross-encoder
            # sigmoid scale → comparable across sources; only when the reranker is unavailable are they
            # mixed arctic/bge cosines. Apply the per-source weight (RRF's navigational tilt).
            return (c.get("score") or 0.0) * ((weights or {}).get(c.get("source"), 1.0))

        def _wscore(c: dict) -> float:
            # Fill-order / final-sort score: un-boosted weighted cosine × the 1p4lr
            # constant-definition boost (1.0 when absent). The drop-off CUTOFF is computed
            # from _wscore_base (un-boosted) so a boosted declaration ranks high WITHOUT
            # raising the relevance bar for any other candidate.
            return _wscore_base(c) * (c.get("_boost") or 1.0)

        # Merge: per-key representative + the set of sources it appeared in + best rank.
        merged: dict[tuple, dict] = {}
        for src, lst in source_lists.items():
            for rank, c in enumerate(lst):
                if not c.get("path"):
                    continue
                k = _key(c)
                rec = merged.get(k)
                if rec is None:
                    rep = dict(c)
                    rep["source"] = src
                    rep["sources"] = [src]
                    rep["_best_rank"] = rank
                    merged[k] = rep
                else:
                    if src not in rec["sources"]:
                        rec["sources"].append(src)
                    if rank < rec.get("_best_rank", rank):
                        rec["_best_rank"] = rank
                    if (c.get("score") or 0.0) > (rec.get("score") or 0.0):
                        rec["score"] = c.get("score")
                        if c.get("text"):
                            rec["text"] = c.get("text")

        # Citation selection is SEMANTIC-only (docs + code). Wave 1p4hu's graph signal is no longer a
        # candidate source here — structural matches go to the response's dedicated ``graph_related``
        # section (relationship-labeled), not mixed into the textual citations with a fake 0.0 score.
        selected: list[tuple] = []
        seen: set[tuple] = set()
        # Per-index floor — guarantee each source's top floor_k, regardless of cross-source rank.
        for src, lst in source_lists.items():
            cnt = 0
            for c in lst:
                if cnt >= floor_k:
                    break
                if not c.get("path"):
                    continue
                k = _key(c)
                if k in seen:
                    continue
                seen.add(k)
                selected.append(k)
                cnt += 1
        # Fill the remaining budget by RELEVANCE across ALL sources (best-of-rest) —
        # NOT a forced per-source balance. The floor already prevents starvation, so the
        # rest are simply the highest-scoring candidates regardless of source: a code-heavy
        # question returns mostly code (docs floor preserved), a docs-heavy one mostly docs.
        # (A forced balance would be no better than concatenating code_search + docs_search.)
        #
        # Fill governed by relevance drop-off + text budget + a loose count backstop — the
        # count is an OUTCOME of relevance and chunk size, never a fixed N:
        #   - drop-off: stop once a candidate falls below AGENT_RELEVANCE_DROPOFF×top (real
        #     distributions are a strong cluster + flat tail — past the gap is noise + tokens).
        #   - text budget: skip a candidate that won't fit the remaining char budget and keep
        #     trying smaller relevant ones (greedy pack by relevance) — so many small chunks
        #     fit while few large chunks do, both measured by context size not count.
        #   - count backstop: top_n only guards pathological "hundreds of tiny chunks".
        # The floor is already selected (and counted against the budget) — anti-starvation wins
        # even if the floor alone is near/over budget.
        def _chars(c: dict) -> int:
            return len(c.get("text") or "")
        used = sum(_chars(merged[k]) for k in selected if k in merged)
        # 1p4lr: cutoff from the UN-boosted top, so a boosted constant declaration ranks into
        # the set without raising the drop-off bar for (and re-trimming) other candidates.
        top_w = max((_wscore_base(rec) for rec in merged.values()), default=0.0)
        cutoff = AGENT_RELEVANCE_DROPOFF * top_w
        rest = sorted(
            (rec for k, rec in merged.items() if k not in seen),
            key=_wscore,
            reverse=True,
        )
        for rec in rest:
            if len(selected) >= top_n:
                break
            if _wscore(rec) < cutoff:
                break
            if text_budget is not None and used + _chars(rec) > text_budget:
                continue
            k = _key(rec)
            seen.add(k)
            selected.append(k)
            used += _chars(rec)
        # Return best-first (advisory — the agent re-ranks; the budget is enforced in the fill above).
        # The floor is guaranteed present by the selection.
        out = [merged[k] for k in selected if k in merged]
        out.sort(key=_wscore, reverse=True)
        return out

    def _lexical_candidates(self, query: str) -> list[dict]:
        """Wave 1rsh9 (1rrr0): BM25 candidates from the index-state store's FTS5 tables.

        Returns candidate dicts shaped like ``_lance_search`` output (path,
        kind, lines, text, score=0.0 — the rerank scores them) ordered
        best-first by BM25 across both tables. Every degrade path — store
        absent, FTS unavailable, FTS-hostile query, any sqlite error — returns
        ``[]`` so retrieval stays vector-only with no error.
        """
        try:
            iss = _load_script("index_state_store")
        except Exception:
            return []
        index_dir = Path(self.root) / ".wavefoundry" / "index"
        hits: list[dict] = []
        for table_name in ("docs", "code"):
            try:
                rows = iss.fts_search(index_dir, table_name, query, limit=LEXICAL_TOP_K)
            except Exception:  # noqa: BLE001 - lexical is additive only
                rows = []
            hits.extend(rows)
        # sqlite bm25() is smaller-is-better (negative); best-first ascending.
        hits.sort(key=lambda h: h.get("bm25", 0.0))
        out: list[dict] = []
        for h in hits:
            out.append({
                "id": h.get("id", ""),
                "path": self._qualify_index_path(h.get("path", "")),
                "kind": h.get("kind") or "",
                "lines": list(h.get("lines") or []),
                "text": h.get("text", ""),
                "score": 0.0,
            })
        return out

    def _indexer_constant(self, name: str) -> str:
        mod = _load_script("indexer")
        return getattr(mod, name)

    def _qualify_index_path(self, path: str, layer: str = "project") -> str:
        # Wave 1p4ww: single project layer — folded framework seeds/README are already
        # stored under their real ``.wavefoundry/framework/...`` path, so no requalification.
        return str(path or "").replace("\\", "/")

    def _lance_search(self, table, query_vec: "np.ndarray", top_n: int, where: Optional[str] = None, layer: str = "project") -> list[dict]:
        """Search a LanceDB table with cosine metric.

        Returns a list of chunk dicts with a ``score`` field (1 - distance, higher = more similar).
        """
        try:
            q = table.search(query_vec.tolist()).metric("cosine").limit(top_n)
            if where:
                q = q.where(where, prefilter=True)
            results = q.to_list()
        except Exception:
            return []
        out = []
        for r in results:
            d = dict(r)
            score = d.pop("_distance", None)
            d.pop("vector", None)
            d["path"] = self._qualify_index_path(d.get("path", ""), layer)
            if score is not None:
                # LanceDB cosine distance = 1 - cosine_similarity; convert to similarity
                d["score"] = float(1.0 - score)
            else:
                d["score"] = 0.0
            out.append(d)
        return out

    def search_docs(self, query: str, kind: Optional[str] = None, top_n: int = 7, tags: Optional[list] = None) -> tuple[list[dict], bool]:
        self._start_background_model_downloads_after_startup()
        self._ensure_loaded()
        DOCS_MODEL = self._indexer_constant("DOCS_MODEL")
        qvec = self._embed_query(query, DOCS_MODEL)

        where_parts = []
        if kind:
            safe_kind = kind.replace("'", "''")
            where_parts.append(f"kind = '{safe_kind}'")
        if tags:
            tag_clauses = [f"tags LIKE '%{t.replace(chr(39), chr(39)*2)}%'" for t in tags]
            where_parts.append(f"({' OR '.join(tag_clauses)})")
        where = " AND ".join(where_parts) if where_parts else None
        tables = [t for t in [getattr(self, "_proj_docs_lance_table", None)] if t is not None]
        if not tables:
            return [], False
        fetch_n = max(top_n, VECTOR_TOP_K)
        all_candidates: list[dict] = []
        if getattr(self, "_proj_docs_lance_table", None) is not None:
            all_candidates.extend(self._lance_search(self._proj_docs_lance_table, qvec, fetch_n, where=where, layer="project"))
        all_candidates.sort(key=lambda x: x.get("score", 0.0), reverse=True)
        candidates = all_candidates[:fetch_n]
        reranker = self._get_reranker()
        if reranker is not None:
            results = self._rerank(query, candidates, top_n)
            return results, True
        return candidates[:top_n], False

    def search_code(self, query: str, language: Optional[str] = None, top_n: int = 7, kind: Optional[str] = None, max_per_file: Optional[int] = None, tags: Optional[list] = None) -> tuple[list[dict], bool]:
        self._start_background_model_downloads_after_startup()
        self._ensure_loaded()
        CODE_MODEL = self._indexer_constant("CODE_MODEL")
        qvec = self._embed_query(query, CODE_MODEL)

        where_parts = []
        if kind:
            safe_kind = kind.replace("'", "''")
            where_parts.append(f"kind = '{safe_kind}'")
        if tags:
            tag_clauses = [f"tags LIKE '%{t.replace(chr(39), chr(39)*2)}%'" for t in tags]
            where_parts.append(f"({' OR '.join(tag_clauses)})")
        where = " AND ".join(where_parts) if where_parts else None
        fetch_n_base = top_n * 4 if language or max_per_file is not None else top_n
        fetch_n = max(fetch_n_base, VECTOR_TOP_K)

        def _code_dense(layer: str) -> list[dict]:
            table = self._open_lance_table(layer, "code")
            if table is None:
                return []
            return self._lance_search(table, qvec, fetch_n, where=where, layer=layer)

        def _code_fts(layer: str) -> list[dict]:
            # Wave 1rsh9 (1sauc): the lexical half of the hybrid merge comes
            # from the index-state store's FTS5 tables (the Lance/Tantivy FTS
            # is retired). kind/tags filter inside the FTS5 query; the
            # language post-filter below applies because rows carry language.
            return self._fts5_lexical_search(
                "code", query, fetch_n, kind=kind, tags=tags, layer=layer
            )

        if getattr(self, "_lance_available", None):
            dense_lists: list[list[dict]] = []
            fts_lists: list[list[dict]] = []
            for layer in ("project",):
                if (layer, "code") in self._lance_available:
                    dense = sorted(_code_dense(layer), key=lambda x: x.get("score", 0.0), reverse=True)
                    fts = sorted(_code_fts(layer), key=lambda x: x.get("score", 0.0), reverse=True)
                    if dense:
                        dense_lists.append(dense)
                    if fts:
                        fts_lists.append(fts)
            if not dense_lists and not fts_lists:
                return [], False
            dense_merged = self._rrf_merge(dense_lists, fetch_n) if dense_lists else []
            fts_merged = self._rrf_merge(fts_lists, fetch_n) if fts_lists else []
            results = self._rrf_merge([dense_merged, fts_merged], fetch_n)
        else:
            tables = [t for t in [getattr(self, "_proj_code_lance_table", None)] if t is not None]
            if not tables:
                return [], False
            all_candidates: list[dict] = []
            if getattr(self, "_proj_code_lance_table", None) is not None:
                all_candidates.extend(self._lance_search(self._proj_code_lance_table, qvec, fetch_n, where=where, layer="project"))
            all_candidates.sort(key=lambda x: x.get("score", 0.0), reverse=True)
            results = all_candidates[:fetch_n]
        if language:
            results = [r for r in results if r.get("language") == language]
        if max_per_file is not None:
            seen: dict[str, int] = {}
            filtered = []
            for r in results:
                p = str(r.get("path") or "")
                count = seen.get(p, 0)
                if count < max_per_file:
                    seen[p] = count + 1
                    filtered.append(r)
            results = filtered
        reranker = self._get_reranker()
        if reranker is not None:
            results = self._rerank(query, results, top_n)
            return results, True
        return results[:top_n], False

    def search_combined(self, query: str, top_n: int = 7, question_type: str = "", rerank: str = "agent") -> tuple[list[dict], bool, int, int, list[str], list[str], str, Optional[dict]]:
        """Combined semantic search across docs and code indexes.

        Returns ``(results, reranked, vector_ms, rerank_ms, definition_boosted, second_hop_symbols, symbol_extraction_method, graph_related)``.

        - ``question_type`` influences retrieval weighting and post-rerank ordering:
          - ``"navigational"``: code-index candidates receive a ``RRF_NAVIGATIONAL_CODE_WEIGHT``
            multiplier in RRF scoring; docs-index receives ``RRF_NAVIGATIONAL_DOCS_WEIGHT``.
          - ``"explanatory"``: after reranking, citations from ``INFRASTRUCTURE_PATH_SEGMENTS``
            (scaffolding/wiring layers) are stable-partitioned to the end of the result list.
            A second retrieval hop extracts symbol names from the top reranked citations and
            injects their definition files as additional candidates before a second rerank.
          - All other values (including ``""``) leave weighting and ordering unchanged.
        - ``vector_ms``: wall time for the vector fetch phase (both indexes), in milliseconds.
        - ``rerank_ms``: wall time for reranker inference or RRF merge, in milliseconds.
        - ``definition_boosted``: list of rule labels that fired (e.g. ``["sql"]``); empty when no rule fired.
        - ``second_hop_symbols``: list of symbol names that triggered second-hop retrieval; empty when
          the second hop was skipped or produced no candidates. In agent mode (wave 1p4hu) this holds
          the breadcrumbs of the graph-signal candidates surfaced via graph-edge traversal.
        - ``symbol_extraction_method``: extraction method used for the second-hop symbol pass —
          ``"ast"`` (Python stdlib AST or tree-sitter produced symbols), ``"regex"`` (AST unavailable
          or produced no symbols), ``"graph"`` (wave 1p4hu — agent mode followed graph EDGES from the
          resolved symbol(s) rather than keyword re-retrieval), or ``"none"`` (no second hop / all
          citations infra-filtered).

        **Wave 1p4hu — graph signal (agent mode default):** alongside the semantic docs/code
        citations, agent mode returns a dedicated ``graph_related`` section (the 8th tuple element):
        structural matches from the code graph, grouped by their RELATIONSHIP to the query's symbol
        (``callers``/``readers``/``importers`` — NOT mixed into citations with a 0.0 score). Seed +
        direction follow query intent: a "what calls/reads/uses X" / "where is X used" question
        expands ONLY the named symbol with edges INTO it (callers / readers via the 1p4ls ``reads``
        edge / importers — ``direction="in"``); a behavioral "how does X work" query expands the
        named symbol AND the top semantic hits both directions (its mechanism, bucketed ``related``).
        Generic-word seeds, test-file neighbors, and whole-file module nodes are suppressed. Bounded
        by ``AGENT_GRAPH_SIGNAL_CAP``; ``None`` when the graph is absent/empty or no symbol resolves.
        No ``GRAPH_BUILDER_VERSION`` bump — it consumes the existing graph.
        """
        self._start_background_model_downloads_after_startup()
        self._ensure_loaded()
        DOCS_MODEL = self._indexer_constant("DOCS_MODEL")
        CODE_MODEL = self._indexer_constant("CODE_MODEL")

        # --- Artifact-anchored exact-first pass ---
        # For questions classified as artifact_anchored, try a keyword lookup on the
        # concrete artifact token before the broad semantic pass. If the exact pass
        # returns at least one code result, rerank and return immediately. If it finds
        # nothing, fall through to the broad semantic pass as explanatory.
        if question_type == "artifact_anchored":
            artifact_token = _extract_artifact_cue(query)
            if artifact_token:
                try:
                    kw_resp = code_keyword_response(self.root, artifact_token)
                    if kw_resp.get("status") == "ok":
                        kw_candidates = [
                            {
                                "path": r.get("path", ""),
                                "text": r.get("snippet", ""),
                                "score": 0.0,
                                "kind": "code",
                                "lines": [r.get("line", 1), r.get("line", 1)],
                            }
                            for r in kw_resp["data"]["results"]
                            if r.get("path")
                        ]
                        if kw_candidates:
                            # Wave 1p52p: agent-mode exact-first artifact pass, rerank-FIRST. Label by
                            # source, then score the keyword candidates (was score=0.0) with the
                            # cross-encoder for a unified relevance order. If the reranker is explicitly
                            # disabled or unbuildable, keep keyword order.
                            for _c in kw_candidates:
                                _p = _c.get("path", "")
                                _c["source"] = "docs" if (_p.startswith("docs/") or "/docs/" in _p or _p.endswith(".md")) else "code"
                                _c["sources"] = [_c["source"]]
                            t_exact = time.monotonic()
                            anchored_reranked = self._agent_rerank(query, kw_candidates)
                            if anchored_reranked:
                                kw_candidates.sort(key=lambda c: c.get("score", 0.0), reverse=True)
                            results = _partition_tests(kw_candidates[:max(top_n, AGENT_CANDIDATE_MAX)])
                            return results, anchored_reranked, 0, round((time.monotonic() - t_exact) * 1000), ["artifact_anchored"], [], "none", None
                except Exception:
                    pass
            # Exact pass found no code results — treat remainder as explanatory
            question_type = "explanatory"

        # --- Vector fetch phase (timed) ---
        t_vector = time.monotonic()
        top_k = VECTOR_TOP_K_EXPLANATORY if question_type == "explanatory" else VECTOR_TOP_K
        docs_qvec = self._embed_query(query, DOCS_MODEL)
        code_qvec = self._embed_query(query, CODE_MODEL)
        docs_candidates = []
        if getattr(self, "_proj_docs_lance_table", None) is not None:
            docs_candidates.extend(self._lance_search(self._proj_docs_lance_table, docs_qvec, top_k, layer="project"))
        docs_candidates.sort(key=lambda x: x.get("score", 0.0), reverse=True)
        code_candidates = []
        if getattr(self, "_proj_code_lance_table", None) is not None:
            code_candidates.extend(self._lance_search(self._proj_code_lance_table, code_qvec, top_k, layer="project"))
        code_candidates.sort(key=lambda x: x.get("score", 0.0), reverse=True)
        vector_ms = round((time.monotonic() - t_vector) * 1000)

        all_candidates = docs_candidates + code_candidates

        # --- Hybrid lexical fusion (wave 1rsh9 / 1rrr0) ---
        # BM25 candidates from the index-state store's FTS5 tables join the
        # pool BEFORE the rerank (the cross-encoder arbitrates); candidates
        # already retrieved by the vector pass are tagged instead of
        # duplicated, preserving the multi-source agreement signal. The kill
        # switch removes all lexical participation.
        _lex_src: list[dict] = []
        if not os.environ.get(LEXICAL_FUSION_DISABLE_ENV):
            try:
                _lex_hits = self._lexical_candidates(query)
            except Exception:  # noqa: BLE001 - lexical is additive only
                _lex_hits = []
            if _lex_hits:
                _by_key = {
                    (c.get("path", ""), tuple(c.get("lines") or [])): c
                    for c in all_candidates
                }
                for _rank, _h in enumerate(_lex_hits):
                    _k = (_h.get("path", ""), tuple(_h.get("lines") or []))
                    _existing = _by_key.get(_k)
                    if _existing is not None:
                        _existing.setdefault("_lex_rank", _rank)
                        _lex_src.append(_existing)
                    else:
                        _h["_lex_rank"] = _rank
                        _lex_src.append(_h)
                        all_candidates.append(_h)
                        _by_key[_k] = _h

        # --- Definition-file boosting: vocabulary-triggered keyword augmentation ---
        q_lower = query.lower()
        definition_boosted: list[str] = []
        for rule in DEFINITION_BOOST_RULES:
            if not any(term in q_lower for term in rule["vocabulary"]):
                continue
            # Most specific matching term: longest vocabulary term > 3 chars present in query
            matching_terms = [t for t in rule["vocabulary"] if len(t) > 3 and t in q_lower]
            search_term = max(matching_terms, key=len) if matching_terms else query
            injected = 0
            for ext in rule["extensions"]:
                if injected >= DEFINITION_BOOST_CANDIDATES:
                    break
                try:
                    kw_resp = code_keyword_response(self.root, search_term, glob=f"*{ext}")
                    if kw_resp.get("status") == "ok":
                        for r in kw_resp["data"]["results"]:
                            if injected >= DEFINITION_BOOST_CANDIDATES:
                                break
                            all_candidates.append({
                                "path": r.get("path", ""),
                                "text": r.get("snippet", ""),
                                "score": 0.0,
                                "kind": "code",
                                "lines": [r.get("line", 1), r.get("line", 1)],
                            })
                            injected += 1
                except Exception:
                    pass
            if injected > 0:
                definition_boosted.append(rule["label"])

        # --- Symbol-first injection (explanatory + navigational, 12q63; widened) ---
        # Value/where-is questions ("what is the value of X and where is it used?") classify as
        # navigational but still NAME a symbol. The injection is the only safety net that forces a
        # query-named declaration into the candidate pool regardless of vector top-K, so the
        # _definition_match_boost leaf branch can lift it; gating it to explanatory left navigational
        # value-questions dependent on raw cosine, which ranks usage chunks over a 1-line declaration.
        if question_type in ("explanatory", "navigational"):
            sym = _extract_question_symbol(query)
            if sym:
                existing_keys = {
                    (r.get("path", ""), (r.get("lines") or [0])[0])
                    for r in all_candidates
                }
                try:
                    kw_resp = code_keyword_response(self.root, sym)
                    if kw_resp.get("status") == "ok":
                        sym_injected = 0
                        for r in kw_resp["data"]["results"][:2]:
                            key = (r.get("path", ""), r.get("line", 0))
                            if key not in existing_keys:
                                all_candidates.append({
                                    "path": r.get("path", ""),
                                    "text": r.get("snippet", ""),
                                    "score": 0.0,
                                    "kind": "code",
                                    "lines": [r.get("line", 1), r.get("line", 1)],
                                    "_sym_injected": True,
                                })
                                existing_keys.add(key)
                                sym_injected += 1
                        if sym_injected > 0:
                            definition_boosted.append(f"symbol:{sym}")
                except Exception:
                    pass

        # --- Rerank / RRF phase (timed) ---
        t_rerank = time.monotonic()
        second_hop_symbols: list[str] = []
        symbol_extraction_method: str = "none"
        graph_related: Optional[dict] = None  # Wave 1p4hu: relationship-grouped structural section (agent mode)
        # Wave 1p4hj: agent-mode (the default) — skip the cross-encoder AND the RRF
        # cross-source merge; return labeled, deduped per-index candidates (per-index
        # floor + balanced cross-index allocation, multi-source agreement preserved).
        # The host agent fuses+ranks. Two-hop expansion stays a "local"-mode feature
        # here (AC-9); `1p4hu` generalizes it to graph edges for agent-mode.
        # Wave 1p52p: code_ask has a SINGLE ranking path — agent selection with a rerank-FIRST
        # cross-encoder stage. The cross-encoder scores the full retrieved pool on ONE unified
        # relevance scale (sigmoid of the logit) BEFORE selection, so the per-index floor / relevance
        # drop-off / text budget AND the confidence band no longer compare incomparable arctic-doc vs
        # bge-code cosines (the 1p4wx model split). The reranker runs on either hardware (GPU FP16 /
        # CPU INT8); only when it is unavailable (disabled/unbuildable) does `_agent_rerank` no-op
        # (scores stay cosine; confidence is capped at medium). The former `rerank="local"`
        # cross-encoder path and the `rrf_fallback` path were REMOVED here — `docs_search`/`code_search`
        # keep their own independent rerank. (`rerank` param retained for API compat; ignored.)
        agent_reranked = self._agent_rerank(query, all_candidates)
        # Lexical fallback scores (1rrr0 Req 3): with the reranker unavailable,
        # lexical-only candidates carry no cosine — give them a rank-derived
        # score with the named weight so they participate in the fallback
        # ordering instead of sinking at 0.0.
        if not agent_reranked and _lex_src:
            for _c in _lex_src:
                if not (_c.get("score") or 0.0):
                    _c["score"] = LEXICAL_RRF_FALLBACK_WEIGHT / (1.0 + float(_c.get("_lex_rank", 0)))
        # Apply the doc-type relevance prior BEFORE selection — a validated signal (code >
        # reference/narrative docs for code-implementation questions); applied up front so the floor +
        # drop-off operate on the adjusted relevance and the demoted prose tail falls below the cutoff.
        # Wave 1p66s: extended from explanatory-only to navigational ("where is X implemented") and to
        # architecture/spec/ADR paths, so a spec no longer outranks the implementing source.
        if question_type in _DOC_DEMOTION_INTENTS:
            all_candidates, _ = _demote_doc_results(all_candidates, question_type)
        # Wave 1p4lr: candidate-side definition-match boost. A DEFINITION chunk whose declared-name
        # tokens ALL appear in the query gets a bounded multiplier on the fill ORDER (cutoff uses
        # un-boosted scores so it never re-trims others).
        _q_terms = _query_content_terms(query)
        for _c in all_candidates:
            _b = _definition_match_boost(_q_terms, _c)
            if _b != 1.0:
                _c["_boost"] = _b
        _docs_src = [c for c in all_candidates if str(c.get("kind", "")) in ("doc", "doc-summary", "seed")]
        _code_src = [c for c in all_candidates if str(c.get("kind", "")) not in ("doc", "doc-summary", "seed")]
        # Wave 1p4wz: rerank-FIRST means the per-index floor must pick each source's top-K on the
        # UNIFIED post-rerank scale — but these lists still carry the pre-rerank cosine order from the
        # vector fetch (1527/1531). Explanatory already re-sorted via _demote_doc_results; navigational/
        # instructional did not, so without this the floor would pick top-K by stale cosine, defeating
        # rerank-first. Sort each source by its current score (sigmoid post-rerank, or same-model cosine
        # when the reranker is unavailable — valid within one source either way). _boost stays a
        # fill-order-only nudge.
        _docs_src.sort(key=lambda c: c.get("score") or 0.0, reverse=True)
        _code_src.sort(key=lambda c: c.get("score") or 0.0, reverse=True)
        # Navigational tilt — boost code over docs for navigational questions. This cross-source weight
        # is only meaningful on the UNIFIED post-rerank sigmoid scale, so apply it only when the
        # cross-encoder actually ran (GPU FP16 or CPU INT8). When the reranker is unavailable
        # (disabled/unbuildable) the per-source scores are incomparable cross-model cosines (arctic docs
        # vs bge code) and a cross-source multiplier would be meaningless — skip it; the per-index floor
        # (each source sorted within itself) still gives a sound result.
        _agent_weights = (
            {"code": RRF_NAVIGATIONAL_CODE_WEIGHT, "docs": RRF_NAVIGATIONAL_DOCS_WEIGHT}
            if (question_type == "navigational" and agent_reranked) else None
        )
        # Citations are SEMANTIC-only (docs + code). The structural graph signal (1p4hu) goes to the
        # dedicated relationship-grouped ``graph_related`` section, bounded by AGENT_GRAPH_SIGNAL_CAP.
        # Wave 1rsh9 (1rrr0): the lexical hits form a third source list — the
        # selection's key-merge unions ``sources``, so a chunk found by both
        # the vector and BM25 passes carries e.g. ["code", "lexical"] (the
        # existing source-marker convention, extended).
        _agent_sources = {"docs": _docs_src, "code": _code_src}
        if _lex_src:
            _lex_src.sort(key=lambda c: c.get("score") or 0.0, reverse=True)
            _agent_sources["lexical"] = _lex_src
        _graph_src = self._graph_signal_candidates(query, all_candidates, cap=AGENT_GRAPH_SIGNAL_CAP)
        # Wave 1p66t: enumeration queries ("which/all X") need the full set, not a reranked top-k —
        # widen the text budget so more of the set clears the selection cutoff (bounded by the mult).
        _enum_query = _is_enumeration_query(query)
        _text_budget = int(AGENT_TEXT_BUDGET_CHARS * AGENT_ENUMERATION_BUDGET_MULT) if _enum_query else AGENT_TEXT_BUDGET_CHARS
        results = self._agent_candidate_select(
            _agent_sources,
            max(top_n, AGENT_CANDIDATE_MAX),
            AGENT_PER_INDEX_FLOOR_K,
            weights=_agent_weights,
            text_budget=_text_budget,
        )
        # Wave 1p66t: surface the strongest cross-file graph neighbors INTO citations (not only the
        # graph_related section), so an agent reading citations sees the load-bearing cross-file files
        # for a cross-file chain. Extracted to _merge_graph_into_citations for direct testability.
        self._merge_graph_into_citations(query, _graph_src, results, reranked=agent_reranked)
        if _graph_src:
            # Build the structural section AFTER citation selection (+ the graph→citation merge above)
            # so a structural match that is also a citation is text-deduped (flagged also_cited, excerpt
            # dropped) — never sent twice.
            graph_related = self._build_graph_related(_graph_src, results)
            second_hop_symbols = [c.get("_symbol") or str(c.get("text", "")).split("\n", 1)[0].strip()
                                  for c in _graph_src]
            symbol_extraction_method = "graph"
        if question_type == "explanatory":
            results = _partition_infra(results)
        for r in results:
            r.pop("_sym_injected", None)
            r.pop("_graph_kind", None)
            r.pop("_lex_rank", None)
        rerank_ms = round((time.monotonic() - t_rerank) * 1000)
        return results, agent_reranked, vector_ms, rerank_ms, definition_boosted, second_hop_symbols, symbol_extraction_method, graph_related

    def get_seed(self, name: str) -> Optional[dict]:
        self._ensure_loaded()
        name_lower = name.lower().strip()
        # First: query the project Lance docs table for seed chunks (1p4ww: folded layer).
        for table in filter(None, [
            getattr(self, "_proj_docs_lance_table", None),
        ]):
            try:
                rows = table.search().where("kind = 'seed'", prefilter=True).to_list()
            except Exception:
                rows = []
            for row in rows:
                chunk = {k: v for k, v in row.items() if k != "vector"}
                path = chunk.get("path", "")
                section = chunk.get("section") or ""
                if name_lower in path.lower() or name_lower in section.lower():
                    chunk["path"] = self._qualify_index_path(path)
                    return chunk

        # Wave 1p35d (1p35j): disk fallback. The index can be incomplete (some
        # seed files exist in file_meta but never produce chunks — root cause
        # in the chunker is out of scope for this change; this fallback makes
        # seed_get robust regardless). Scan the seeds directory directly for a
        # filename match. Match precedence: exact-number-prefix > substring.
        seed_dirs: list[Path] = []
        fw_dir = Path(self.root) / ".wavefoundry" / "framework" / "seeds"
        if fw_dir.is_dir():
            seed_dirs.append(fw_dir)
        for seed_dir in seed_dirs:
            try:
                candidates = sorted(seed_dir.glob("*.prompt.md")) + sorted(seed_dir.glob("*.md"))
            except OSError:
                continue
            # Dedupe by absolute path while preserving order.
            seen: set[Path] = set()
            ordered: list[Path] = []
            for p in candidates:
                if p in seen:
                    continue
                seen.add(p)
                ordered.append(p)
            # Pass 1: exact-number-prefix match (e.g., name='216' matches '216-reality-checker.prompt.md').
            if name_lower and name_lower[0].isdigit():
                for p in ordered:
                    stem = p.name
                    if stem.lower().startswith(name_lower + "-") or stem.lower().startswith(name_lower + "."):
                        return _seed_chunk_from_disk(p, self.root)
            # Pass 2: substring match on filename.
            for p in ordered:
                if name_lower in p.name.lower():
                    return _seed_chunk_from_disk(p, self.root)
        return None

    def closest_seed_names(self, name: str, limit: int = 3) -> list[str]:
        """Return the closest filename matches for a missing seed name.

        Used by ``seed_get_response`` to surface a recovery hint when a seed
        isn't found. Matches against ``<repo>/.wavefoundry/framework/seeds/``
        directly so the suggestion works even when the index is empty/stale.
        """
        import difflib
        fw_dir = Path(self.root) / ".wavefoundry" / "framework" / "seeds"
        if not fw_dir.is_dir():
            return []
        try:
            stems = [p.name for p in fw_dir.glob("*.md")]
        except OSError:
            return []
        return difflib.get_close_matches(name, stems, n=limit, cutoff=0.4)

    def is_stale(self) -> bool:
        """Return True if the index may be out of date (no completed build epoch)."""
        return not _store_has_completed_build(self.index_dir)


# ---------------------------------------------------------------------------
# Wave inspection helpers
# ---------------------------------------------------------------------------

def _read_workflow_config(root: Path) -> dict:
    cfg = root / "docs" / "workflow-config.json"
    if cfg.is_file():
        try:
            return json.loads(cfg.read_text(encoding="utf-8"))
        except (json.JSONDecodeError, OSError):
            pass
    return {}


# Wave 1p9iu: generous default timeout (seconds) for the server-side FULL-corpus docs-lint subprocess
# in run_validate — well above the old hardcoded 30s that was too short on a large field repo, and at
# minimum matching the post-edit hook's 120s floor (indexer.DOCS_LINT_HOOK_TIMEOUT_DEFAULT). The full
# scan (no --changed) is heavier than the incremental hook, so it carries a higher generous-but-bounded
# default.
DOCS_LINT_FULL_SCAN_TIMEOUT_DEFAULT = 300.0


def docs_lint_full_scan_timeout_seconds(root: Path) -> float:
    """Timeout (seconds) for the server-side full-corpus docs-lint subprocess run by ``run_validate``
    (wave 1p9iu). Reads ``docs/workflow-config.json`` ``docs_lint.full_scan_timeout_seconds``; defaults
    to ``DOCS_LINT_FULL_SCAN_TIMEOUT_DEFAULT``. Mirrors the fail-safe contract of
    ``indexer.docs_lint_hook_timeout_seconds``: any error / missing key / non-positive value falls back
    to the default and never raises. A distinct knob (co-located with the hook's under the ``docs_lint``
    namespace) lets an operator raise the heavy full-scan path on a large repo without loosening the
    light incremental hook path."""
    try:
        cfg = _read_workflow_config(root)
        val = (cfg.get("docs_lint") or {}).get("full_scan_timeout_seconds")
        if isinstance(val, (int, float)) and not isinstance(val, bool) and val > 0:
            return float(val)
    except Exception:
        pass
    return DOCS_LINT_FULL_SCAN_TIMEOUT_DEFAULT


# Wave 1p9pe: defensive mirror of indexer.DOCS_LINT_HOOK_TIMEOUT_DEFAULT (120s), used only when the
# indexer module itself cannot be loaded. The canonical default and config reader live in indexer.py;
# this constant exists so the incremental post-write lint path never raises on a broken sibling import.
DOCS_LINT_HOOK_TIMEOUT_FALLBACK = 120.0


def _docs_lint_hook_timeout_default() -> float:
    """The CANONICAL hook-timeout default (``indexer.DOCS_LINT_HOOK_TIMEOUT_DEFAULT``), for
    operator-facing messages. Review-fix (1p9pe follow-up hardening): messages must cite the
    canonical default, not the defensive mirror above — the mirror is only the fail-safe when
    the sibling import is broken."""
    try:
        return float(_load_script("indexer").DOCS_LINT_HOOK_TIMEOUT_DEFAULT)
    except Exception:
        return DOCS_LINT_HOOK_TIMEOUT_FALLBACK


# Review-fix (1p9pe follow-up hardening): defensive mirror of
# wave_lint_lib.cli.INCREMENTAL_FULL_FALLBACK_FILES, used only when the sibling package cannot
# be imported. The canonical trigger list lives in wave_lint_lib/cli.py next to the fallback
# logic it drives.
_INCREMENTAL_FULL_FALLBACK_FILES_MIRROR = (
    "docs/workflow-config.json",
    "docs/prompts/prompt-surface-manifest.json",
    "docs/repo-profile.json",
)


def _incremental_full_fallback_trigger_files() -> tuple[str, ...]:
    """Files whose change makes ``docs_lint --changed`` silently fall back to the FULL lint."""
    try:
        from wave_lint_lib.cli import INCREMENTAL_FULL_FALLBACK_FILES

        return tuple(INCREMENTAL_FULL_FALLBACK_FILES)
    except Exception:
        return _INCREMENTAL_FULL_FALLBACK_FILES_MIRROR


def _predict_incremental_full_fallback(root: Path) -> bool:
    """Predict whether ``docs_lint --changed`` will fall back to the full lint.

    Review-fix (1p9pe follow-up hardening): the CLI's fallback (a changed config/manifest/
    repo-profile file in the git changed set) runs a FULL-corpus scan inside the ``--changed``
    invocation — so ``run_validate_changed`` must bound it with the full-scan timeout knob,
    not the 120s hook knob. Mirrors ``_get_changed_files`` semantics (tracked changes vs HEAD
    plus untracked non-ignored files) in a single cheap ``git status --porcelain`` subprocess.
    Fail-safe: any git failure (non-git checkout, missing binary) predicts False — the CLI
    no-ops on a missing changed set there, so the light hook bound is correct.

    Uses ``subprocess_util.isolated_run`` directly (NOT ``_mcp_subprocess_run``) — this is a
    cheap pre-check, not the docs_lint spawn, and the argv/count assertions on the post-write
    tests patch ``_mcp_subprocess_run`` expecting exactly one docs_lint invocation.
    """
    import subprocess_util

    triggers = set(_incremental_full_fallback_trigger_files())
    try:
        result = subprocess_util.isolated_run(
            ["git", "status", "--porcelain"],
            cwd=str(root),
            capture_output=True,
            text=True,
            timeout=15,
        )
    except Exception:
        return False
    if result.returncode != 0:
        return False
    for line in result.stdout.splitlines():
        if len(line) < 4:
            continue
        path = line[3:].strip()
        # Rename entries read "old -> new"; the new path is the live one.
        if " -> " in path:
            path = path.rsplit(" -> ", 1)[1]
        path = path.strip().strip('"')
        if path in triggers:
            return True
    return False


def docs_lint_hook_timeout_seconds(root: Path) -> float:
    """Timeout (seconds) for the INCREMENTAL post-write docs-lint subprocess run by
    ``run_validate_changed`` (wave 1p9pe). Delegates to ``indexer.docs_lint_hook_timeout_seconds``
    — the same ``docs_lint.hook_timeout_seconds`` knob (default 120s) that bounds the post-edit
    hook's incremental scan, because both incremental paths share one cost profile and should be
    governed by one knob. Fail-safe: any error falls back to the mirrored default and never raises."""
    try:
        return float(_load_script("indexer").docs_lint_hook_timeout_seconds(root))
    except Exception:
        return DOCS_LINT_HOOK_TIMEOUT_FALLBACK


def _read_project_required_review_lanes(root: Path) -> list[str]:
    """Return project-declared required review lanes from workflow-config.json."""
    cfg = _read_workflow_config(root)
    raw = cfg.get("required_review_lanes", [])
    if not isinstance(raw, list):
        return []
    return [str(lane).strip() for lane in raw if isinstance(lane, str) and str(lane).strip()]


def _read_wave_council_policy(root: Path) -> dict[str, Any]:
    """Return normalized Wave Council policy from workflow-config.json.

    Reads the canonical ``wave_review`` key. (Wave 1p5b4: the legacy
    ``wave_council_policy`` reader-fallback was removed along with the canonical-names
    rename mechanism — the one-shot upgrade convergence rewrites legacy configs to
    canonical, so the runtime only ever sees ``wave_review``.)
    """
    cfg = _read_workflow_config(root)
    raw = cfg.get("wave_review")
    if not isinstance(raw, dict) or not bool(raw.get("enabled")):
        return {}

    phases_raw = raw.get("phases", {})
    if not isinstance(phases_raw, dict):
        phases_raw = {}

    phase_defaults = {
        "prepare": "wave-council-readiness",
        "review": "wave-council-delivery",
    }
    phases: dict[str, dict[str, str]] = {}
    for phase, default_key in phase_defaults.items():
        phase_raw = phases_raw.get(phase, {})
        if not isinstance(phase_raw, dict):
            phase_raw = {}
        signoff_key = str(phase_raw.get("signoff_key", default_key)).strip()
        moderator_role = str(phase_raw.get("moderator_role", "wave-council")).strip()
        if signoff_key:
            phases[phase] = {
                "signoff_key": signoff_key,
                "moderator_role": moderator_role or "wave-council",
            }

    return {
        "enabled": True,
        "required_for_all_waves": bool(raw.get("required_for_all_waves", True)),
        "evidence_section": str(raw.get("evidence_section", "## Review Evidence")).strip() or "## Review Evidence",
        "transition_policy": str(raw.get("transition_policy", "")).strip(),
        "phases": phases,
    }


def _required_wave_council_signoffs(root: Path, lifecycle_phase: str, wave_text: Optional[str] = None) -> list[str]:
    policy = _read_wave_council_policy(root)
    if not policy:
        return []
    phase_map = {
        "prepare": ["prepare"],
        "review": ["review"],
        "close": ["prepare", "review"],
    }
    required: list[str] = []
    for phase in phase_map.get(lifecycle_phase, []):
        signoff_key = policy.get("phases", {}).get(phase, {}).get("signoff_key")
        if signoff_key and signoff_key not in required:
            required.append(signoff_key)
    if not required:
        return required

    transition_policy = str(policy.get("transition_policy", "")).strip().lower()
    if transition_policy != "applies-from-next-prepare" or lifecycle_phase == "prepare" or not wave_text:
        return required

    prepare_key = policy.get("phases", {}).get("prepare", {}).get("signoff_key")
    review_key = policy.get("phases", {}).get("review", {}).get("signoff_key")
    has_prepare_signoff = bool(prepare_key and _lane_has_signoff(wave_text, prepare_key))
    has_review_signoff = bool(review_key and _lane_has_signoff(wave_text, review_key))

    if lifecycle_phase == "review":
        return required
    if lifecycle_phase == "close":
        if has_prepare_signoff:
            return required
        if has_review_signoff and review_key:
            return [review_key]
        return [key for key in required if key != prepare_key]
    return required


def _read_project_sensors(root: Path) -> list[dict]:
    """Return registered sensor definitions from workflow-config.json."""
    cfg = _read_workflow_config(root)
    raw = cfg.get("sensors", [])
    if not isinstance(raw, list):
        return []
    out = []
    for item in raw:
        if not isinstance(item, dict):
            continue
        name = str(item.get("name", "")).strip()
        command = item.get("command")
        if not name or not command:
            continue
        out.append({
            "name": name,
            "command": command if isinstance(command, list) else str(command),
            "dimension": str(item.get("dimension", "maintainability")),
            "description": str(item.get("description", "")),
        })
    return out


_WAVE_ID_PATTERN = re.compile(r"^wave-id:\s+`([^`]+)`", re.MULTILINE)
_STATUS_PATTERN = re.compile(r"^Status:\s+(\S+)", re.MULTILINE)
_CHANGE_ID_PATTERN = re.compile(r"^Change ID:\s+`([^`]+)`", re.MULTILINE)
_CHANGE_STATUS_PATTERN = re.compile(r"^(?:Change|Item) Status:\s+`([^`]+)`", re.MULTILINE)

# Wave 1p31b (1p32k): close-time hard gate — every AC and task across the wave's admitted
# changes must be `[x]` (done) or `[~]` (intentionally deferred). Silent `[ ]` items block
# close. `not-this-scope` priority ACs are exempt (the priority encodes the exclusion).
_CLOSE_GATE_CHECKBOX_LINE_RE = re.compile(r"^\s*-\s+\[(?P<mark>[ xX~])\]\s+(?P<text>.+?)\s*$", re.MULTILINE)
_CLOSE_GATE_AC_ID_RE = re.compile(r"(AC-[\w\-]+)")


def _extract_close_gate_section(text: str, heading: str) -> str:
    """Extract H2 section content by heading name (without `## ` prefix)."""
    pattern = re.compile(rf"^## {re.escape(heading)}\s*\n(.*?)(?=^## |\Z)", re.MULTILINE | re.DOTALL)
    match = pattern.search(text)
    return match.group(1) if match else ""


def _close_gate_parse_ac_priority(priority_section: str) -> dict[str, str]:
    """Return `AC-id -> priority` map from a markdown AC priority table (normalized lowercase)."""
    result: dict[str, str] = {}
    for raw in priority_section.splitlines():
        line = raw.strip()
        if not line.startswith("|") or line.count("|") < 2:
            continue
        # Skip the markdown separator row.
        if set(line.replace("|", "").replace("-", "").replace(":", "").strip()) == set():
            continue
        cells = [cell.strip() for cell in line.strip("|").split("|")]
        if len(cells) < 2:
            continue
        id_match = _CLOSE_GATE_AC_ID_RE.search(cells[0])
        if not id_match:
            continue
        result[id_match.group(1)] = cells[1].lower().replace(" ", "-")
    return result


def _collect_silent_unchecked_items_for_close(wave_md: Path, wave_text: str) -> list[dict[str, str]]:
    """Walk admitted change docs; return silent ``[ ]`` items that block close.

    Wave 1p31b (1p32k): the close-time hard gate. Every AC and task must be ``[x]`` or
    ``[~]`` at close. AC items at ``not-this-scope`` priority are exempt. Returns a list of
    ``{'change_id', 'item_type' ('AC' or 'task'), 'item_id', 'item_text'}`` dicts.
    """
    findings: list[dict[str, str]] = []
    for change_id in _CHANGE_ID_PATTERN.findall(wave_text):
        change_path = wave_md.parent / f"{change_id}.md"
        if not change_path.exists():
            continue
        try:
            change_text = change_path.read_text(encoding="utf-8")
        except OSError:
            continue

        ac_section = _extract_close_gate_section(change_text, "Acceptance Criteria")
        priority_section = _extract_close_gate_section(change_text, "AC Priority")
        priorities = _close_gate_parse_ac_priority(priority_section)

        # Walk AC items — silent `[ ]` at non-exempt priority blocks close.
        for match in _CLOSE_GATE_CHECKBOX_LINE_RE.finditer(ac_section):
            if match.group("mark") != " ":
                continue
            text_part = match.group("text").strip()
            id_match = _CLOSE_GATE_AC_ID_RE.search(text_part)
            ac_id = id_match.group(1) if id_match else "<unidentified>"
            priority = priorities.get(ac_id, "unknown")
            if priority == "not-this-scope":
                continue
            findings.append({
                "change_id": change_id,
                "item_type": "AC",
                "item_id": ac_id,
                "item_text": text_part[:120],
            })

        # Walk task items — every silent `[ ]` blocks close (no priority exemption for tasks).
        task_section = _extract_close_gate_section(change_text, "Tasks")
        for match in _CLOSE_GATE_CHECKBOX_LINE_RE.finditer(task_section):
            if match.group("mark") != " ":
                continue
            text_part = match.group("text").strip()
            findings.append({
                "change_id": change_id,
                "item_type": "task",
                "item_id": "",
                "item_text": text_part[:120],
            })
    return findings
_TITLE_PATTERN = re.compile(r"^#\s+(.+)$", re.MULTILINE)


def _parse_wave_record(wave_md: Path) -> dict:
    text = wave_md.read_text(encoding="utf-8")
    wave_id_m = _WAVE_ID_PATTERN.search(text)
    status_m = _STATUS_PATTERN.search(text)
    change_ids = _CHANGE_ID_PATTERN.findall(text)
    change_statuses = _CHANGE_STATUS_PATTERN.findall(text)
    return {
        "wave_id": wave_id_m.group(1) if wave_id_m else wave_md.parent.name,
        "status": status_m.group(1) if status_m else "unknown",
        "changes": [
            {"id": cid, "status": cst}
            for cid, cst in zip(change_ids, change_statuses)
        ],
        "path": str(wave_md),
    }


# Listing order must be TIME order, which means decoded lifecycle-prefix value
# order — NOT filename-string order: at the graceful 6-char overflow a string
# sort inverts ("100000" < "zzzzz" lexically while decoding far greater).
_LIFECYCLE_SORT_PREFIX_RE = re.compile(r"^([0-9a-z]{5,6})[-\s]")


def _lifecycle_sort_key(name: str) -> tuple[int, int, str]:
    """Sort key: decoded lifecycle-prefix value, then name; unprefixed names last."""
    m = _LIFECYCLE_SORT_PREFIX_RE.match(name)
    if m:
        return (0, int(m.group(1), 36), name)
    return (1, 0, name)


def list_waves(root: Path) -> list[dict]:
    waves_root = root / "docs" / "waves"
    if not waves_root.exists():
        return []
    result = []
    for wave_dir in sorted(waves_root.iterdir(), key=lambda p: _lifecycle_sort_key(p.name)):
        if not wave_dir.is_dir():
            continue
        wave_md = wave_dir / "wave.md"
        if wave_md.exists():
            result.append(_parse_wave_record(wave_md))
    return result


def _parse_plan_record(root: Path, plan_md: Path) -> dict:
    text = plan_md.read_text(encoding="utf-8")
    change_id_m = _CHANGE_ID_PATTERN.search(text)
    change_status_m = _CHANGE_STATUS_PATTERN.search(text)
    status_m = _STATUS_PATTERN.search(text)
    title_m = _TITLE_PATTERN.search(text)
    return {
        "id": change_id_m.group(1) if change_id_m else plan_md.stem,
        "status": (
            change_status_m.group(1)
            if change_status_m
            else status_m.group(1) if status_m else "unknown"
        ),
        "title": title_m.group(1).strip() if title_m else plan_md.stem,
        "path": str(plan_md.relative_to(root)).replace("\\", "/"),
    }


def list_plans(root: Path) -> list[dict]:
    plans_root = root / "docs" / "plans"
    if not plans_root.exists():
        return []
    result = []
    for plan_md in sorted(plans_root.glob("*.md"), key=lambda p: _lifecycle_sort_key(p.name)):
        if plan_md.name == "plan-template.md":
            continue
        result.append(_parse_plan_record(root, plan_md))
    return result


def _dir_fingerprint(
    directory: Path,
    glob: str,
    *,
    skip: Optional[set[str]] = None,
    recursive: bool = False,
) -> tuple[int, int]:
    """Return a ``(file_count, max_mtime_ns)`` fingerprint for a directory.

    Used to detect whether a watched directory has changed since the last cache
    population. Returns ``(0, 0)`` when the directory does not exist.

    Args:
        directory: The directory to scan.
        glob: Glob pattern passed to ``Path.rglob`` (recursive) or ``Path.glob``.
        skip: Optional set of filenames to exclude from the scan.
        recursive: When True, uses ``rglob``; otherwise uses ``glob``.
    """
    if not directory.exists():
        return (0, 0)
    best_ns = 0
    count = 0
    scanner = directory.rglob(glob) if recursive else directory.glob(glob)
    for p in scanner:
        if skip and p.name in skip:
            continue
        try:
            st = p.stat()
        except OSError:
            continue
        count += 1
        best_ns = max(best_ns, int(st.st_mtime_ns))
    return (count, best_ns)


class McpRepoCache:
    """Per-process cache for wave/plan summaries and prompt lookups.

    Invalidated automatically when the underlying directory fingerprint
    (file count + max mtime) changes. Call ``invalidate()`` explicitly after
    any mutating operation to force an immediate refresh on the next access.
    """

    def __init__(self, root: Path, *, index: Optional[WaveIndex] = None) -> None:
        self.root = root.resolve()
        self._index = index
        self._waves: Optional[list[dict]] = None
        self._waves_key: Optional[tuple[int, int]] = None
        self._plans: Optional[list[dict]] = None
        self._plans_key: Optional[tuple[int, int]] = None
        self._prompt_cache: dict[str, Any] = {}
        self._prompt_key: Optional[tuple[int, int]] = None

    def invalidate(self) -> None:
        """Clear all cached data and mark the semantic index for reload."""
        self._waves = None
        self._waves_key = None
        self._plans = None
        self._plans_key = None
        self._prompt_cache = {}
        self._prompt_key = None
        if self._index is not None:
            self._index._loaded = False

    def _wave_fingerprint(self) -> tuple[int, int]:
        return _dir_fingerprint(
            self.root / "docs" / "waves", "wave.md", recursive=True
        )

    def _plans_fingerprint(self) -> tuple[int, int]:
        return _dir_fingerprint(
            self.root / "docs" / "plans", "*.md", skip={"plan-template.md"}
        )

    def _prompts_fingerprint(self) -> tuple[int, int]:
        return _dir_fingerprint(self.root / "docs" / "prompts", "*.md")

    def get_prompt_text_cached(self, shortcut: str) -> Optional[str]:
        """Return prompt body like ``get_prompt``, using an mtime-keyed per-process cache."""
        key = self._prompts_fingerprint()
        if self._prompt_key != key:
            self._prompt_cache = {}
            self._prompt_key = key
        norm = shortcut.strip().lower()
        if norm in self._prompt_cache:
            hit = self._prompt_cache[norm]
            return None if hit is _PROMPT_MISS else str(hit)
        text = get_prompt(self.root, shortcut)
        self._prompt_cache[norm] = _PROMPT_MISS if text is None else text
        return text

    def list_waves_cached(self) -> list[dict]:
        key = self._wave_fingerprint()
        if self._waves is not None and self._waves_key == key:
            return self._waves
        waves = list_waves(self.root)
        self._waves = waves
        self._waves_key = key
        return waves

    def list_plans_cached(self) -> list[dict]:
        key = self._plans_fingerprint()
        if self._plans is not None and self._plans_key == key:
            return self._plans
        plans = list_plans(self.root)
        self._plans = plans
        self._plans_key = key
        return plans


def first_party_tool_names_violating_prefix(tool_names: Iterable[str]) -> list[str]:
    """Return tool names that do not start with an approved MCP surface prefix."""
    violations: list[str] = []
    for name in sorted(tool_names):
        if not any(name.startswith(prefix) for prefix in MCP_TOOL_PREFIXES):
            violations.append(name)
    return violations


def resolve_path_under_root(repo_root: Path, user_path: str) -> tuple[Optional[Path], Optional[dict[str, Any]]]:
    """Resolve a user-supplied path to an absolute path confined under repo_root.

    Intended for future file navigation tools. Returns ``(path, None)`` on success or
    ``(None, diagnostic)`` when the path escapes allowed roots or cannot be resolved.
    """
    root = repo_root.resolve()
    raw = Path(user_path.strip()).expanduser()
    try:
        candidate = raw.resolve() if raw.is_absolute() else (root / raw).resolve()
    except (OSError, RuntimeError) as exc:
        return None, _diagnostic(
            "path_resolution_failed",
            str(exc),
            recovery_tools=["wf_validate_docs", "wf_current_wave"],
            recovery_usage="wf_validate_docs()",
        )
    try:
        candidate.relative_to(root)
    except ValueError:
        return None, _diagnostic(
            "path_outside_allowed_roots",
            f"Path {user_path!r} resolves outside the configured repository root.",
            recovery_tools=["wf_current_wave", "wf_validate_docs"],
            recovery_usage="wf_current_wave()",
        )
    return candidate, None


def current_wave(root: Path, cache: Optional[McpRepoCache] = None) -> Optional[dict]:
    waves = cache.list_waves_cached() if cache else list_waves(root)
    for allowed in (("active", "implementing"), ("planned",)):
        for wave in waves:
            if wave["status"] in allowed:
                return wave
    return None


def _find_other_active_wave(
    root: Path,
    target_wave_path: Path,
    cache: Optional[McpRepoCache] = None,
) -> Optional[dict]:
    """Return the first active wave whose path is not ``target_wave_path``.

    Used by the single-active-wave guard in ``wf_prepare_wave``. Returns ``None``
    when no other wave is active (the target may itself be active and still
    allow self-prepare).
    """
    waves = cache.list_waves_cached() if cache else list_waves(root)
    target_resolved = target_wave_path.resolve()
    for wave in waves:
        if wave["status"] not in ("active", "implementing"):
            continue
        wave_md_path = Path(wave["path"])
        if not wave_md_path.is_absolute():
            wave_md_path = root / wave_md_path
        if wave_md_path.resolve() == target_resolved:
            continue
        return wave
    return None


def get_change(root: Path, change_id_prefix: str) -> Optional[str]:
    matches = _resolve_change_doc_matches(root, change_id_prefix)
    if len(matches) != 1:
        return None
    return str(matches[0].get("content") or "")
    return None


def get_prompt(root: Path, shortcut: str) -> Optional[str]:
    shortcut_lower = shortcut.lower().strip()
    prompts_dir = root / "docs" / "prompts"
    if not prompts_dir.exists():
        return None
    # Slug-match the shortcut against prompt filenames and content
    slug = re.sub(r"[^\w]+", "-", shortcut_lower).strip("-")
    for p in prompts_dir.glob("*.md"):
        if slug in p.stem.lower():
            return p.read_text(encoding="utf-8")
    # Fallback: search file content for shortcut phrase
    for p in prompts_dir.glob("*.md"):
        text = p.read_text(encoding="utf-8")
        if shortcut_lower in text.lower():
            return text
    return None


def _diagnostic(
    code: str,
    message: str,
    *,
    recovery_tools: list[str] | None = None,
    recovery_usage: str = "",
) -> dict[str, Any]:
    payload: dict[str, Any] = {"code": code, "message": message}
    if recovery_tools:
        payload["recovery_tools"] = recovery_tools
    if recovery_usage:
        payload["recovery_usage"] = recovery_usage
    return payload


def _graph_auto_rebuild_diagnostic(index: Any) -> list[dict[str, Any]]:
    """Wave 131bt (131e2): surface the GraphQueryIndex auto-rebuild diagnostic.

    Returns a single-element list when ``graph_query.load_graph()`` fired a
    synchronous rebuild for a stale GRAPH_BUILDER_VERSION; an empty list
    otherwise. Call sites can splat this unconditionally.
    """
    diag = getattr(index, "auto_rebuild_diagnostic", None)
    if not isinstance(diag, dict):
        return []
    return [diag]


def _attach_auto_rebuild_diag(envelope: dict[str, Any], index: Any) -> dict[str, Any]:
    """Wave 131bt (131e2): prepend the auto-rebuild diagnostic to an existing
    MCP response envelope. Mutates and returns the envelope so call sites
    can write ``return _attach_auto_rebuild_diag(_response("ok", data, ...), index)``.

    No-op when the index has no diagnostic (the common case post-rebuild
    when the cache has already verified). Idempotent — duplicate calls
    don't insert the diagnostic twice.
    """
    if envelope is None or not isinstance(envelope, dict):
        return envelope
    extras = _graph_auto_rebuild_diagnostic(index)
    if not extras:
        return envelope
    existing = envelope.get("diagnostics")
    if not isinstance(existing, list):
        existing = []
    # Idempotency: if the same diagnostic already at the head, skip.
    diag = extras[0]
    if existing and isinstance(existing[0], dict) and existing[0].get("code") == diag.get("code"):
        return envelope
    envelope["diagnostics"] = [diag, *existing]
    return envelope


def _response(
    status: str,
    data: dict[str, Any] | None = None,
    *,
    diagnostics: list[dict[str, Any]] | None = None,
    next_tools: list[str] | None = None,
    usage: str = "",
) -> dict[str, Any]:
    """Build the standard MCP response envelope.

    Accepted ``status`` values:
    - ``"ok"``       — operation succeeded.
    - ``"error"``    — operation failed; ``isError: True`` is also set so that
                       MCP protocol-level clients see the correct error signal.
    - ``"dry_run"``  — mutating tool was called with ``mode='dry_run'``; no
                       writes were performed.  Callers should treat this like
                       ``"ok"`` but not assume side effects occurred.
    """
    envelope: dict[str, Any] = {
        "status": status,
        "data": data or {},
        "diagnostics": diagnostics or [],
        "next_tools": next_tools or [],
        "usage": usage,
    }
    if status == "error":
        envelope["isError"] = True
    return envelope


def _registered_mcp_tool_names(mcp: Any) -> set[str]:
    """Return registered first-party tool names from FastMCP (API varies by version)."""
    tm = getattr(mcp, "_tool_manager", None)
    tools = getattr(tm, "_tools", None) if tm is not None else None
    if tools:
        return set(tools.keys())
    legacy = getattr(mcp, "_tools", None)
    if legacy:
        return set(legacy.keys())
    return set()


def _registered_mcp_tool_descriptions(mcp: Any) -> dict[str, str]:
    """Return {tool_name: description} for first-party tools from FastMCP's registry.

    Used by wf_reload_mcp to snapshot descriptions before/after the re-register
    pass so the response can honestly report when description strings changed.
    Server-side change detection — does not imply the MCP host's tool-list display
    has refreshed (the MCP protocol's notifications/tools/list_changed propagation
    is host-implementation-dependent).
    """
    tm = getattr(mcp, "_tool_manager", None)
    tools = getattr(tm, "_tools", None) if tm is not None else None
    if not tools:
        tools = getattr(mcp, "_tools", None) or {}
    out: dict[str, str] = {}
    for name, tool in tools.items():
        desc = getattr(tool, "description", None) or ""
        out[name] = str(desc)
    return out


def _ensure_no_extra_args(tool_name: str, kwargs: dict[str, Any]) -> Optional[dict[str, Any]]:
    """If MCP passed unsupported keyword arguments, return a structured error envelope.

    FastMCP generates a schema entry named ``kwargs`` from ``**kwargs`` in the function
    signature and may forward it back to the handler as a named argument.  Strip that
    self-referential key before checking for genuine extras.
    """
    real_extras = {k: v for k, v in kwargs.items() if k != "kwargs"}
    if not real_extras:
        return None
    kwargs = real_extras
    response = _response(
        "error",
        {"tool": tool_name, "rejected_arguments": sorted(kwargs.keys())},
        diagnostics=[
            _diagnostic(
                "unknown_arguments",
                f"{tool_name} received unsupported arguments: {', '.join(sorted(kwargs.keys()))}.",
                recovery_tools=["wf_help"],
                recovery_usage="wf_help()",
            )
        ],
        next_tools=["wf_help"],
        usage=f"wf_help()  # see supported parameters for {tool_name}",
    )
    return _attach_retrieval_failure_context(tool_name, response)


def _slug_fragment(text: str) -> str:
    return re.sub(r"[^\w]+", "-", text.strip().lower()).strip("-")


def _codex_slug_fragment(text: str) -> str:
    return re.sub(r"[^0-9a-z]+", "-", text.strip().lower()).strip("-")


def _project_slug(root: Path) -> str:
    slug = _codex_slug_fragment(root.name)
    return slug or "project"


def server_identity(root: Path, *, server_runner_version: str | None = None) -> dict[str, Any]:
    resolved_root = root.resolve()
    data: dict[str, Any] = {
        "repo_root": str(resolved_root),
        "repo_name": resolved_root.name,
        "project_slug": _project_slug(resolved_root),
    }
    rv = server_runner_version if server_runner_version is not None else _runner_version
    if rv:
        data.update(version_payload(root, server_runner_version=rv))
    return data


def _trust_label(path: str, *, kind: str = "") -> str:
    normalized = path.replace("\\", "/")
    if kind == "seed" or normalized.startswith(".wavefoundry/framework/"):
        return TRUSTED_FRAMEWORK
    if (
        normalized == "docs/workflow-config.json"
        or normalized.startswith("docs/waves/")
        or normalized.startswith("docs/plans/")
    ):
        return TRUSTED_PROJECT_METADATA
    return UNTRUSTED_PROJECT_CONTENT


def _result_id(prefix: str, chunk: dict[str, Any]) -> str:
    raw_id = str(chunk.get("id") or "").strip()
    if raw_id:
        return raw_id if raw_id.startswith(f"{prefix}:") else f"{prefix}:{raw_id}"
    path = str(chunk.get("path") or "").replace("\\", "/")
    section = str(chunk.get("section") or "").strip()
    if section:
        return f"{prefix}:{path}#{_slug_fragment(section)}"
    lines = chunk.get("lines")
    if isinstance(lines, list) and len(lines) >= 2:
        return f"{prefix}:{path}:L{lines[0]}-L{lines[1]}"
    return f"{prefix}:{path}"


def _search_result(prefix: str, chunk: dict[str, Any]) -> dict[str, Any]:
    payload = {
        "result_id": _result_id(prefix, chunk),
        "path": chunk.get("path"),
        "kind": chunk.get("kind"),
        "section": chunk.get("section"),
        "lines": chunk.get("lines"),
        "excerpt": str(chunk.get("text") or "")[:600],
        "trust_label": _trust_label(str(chunk.get("path") or ""), kind=str(chunk.get("kind") or "")),
    }
    if "language" in chunk:
        payload["language"] = chunk.get("language")
    if "score" in chunk:
        payload["score"] = float(chunk["score"])
    return payload


