@functools.lru_cache(maxsize=1)
def _cached_help_catalog_json() -> str:
    return json.dumps(_help_catalog(), sort_keys=True)


def _snapshot_help_catalog() -> dict[str, Any]:
    """Return a deep copy of the discovery catalogue (cached per process)."""
    return json.loads(_cached_help_catalog_json())


def wf_help_response(goal: str = "") -> dict[str, Any]:
    catalog = _snapshot_help_catalog()
    normalized = _slug_fragment(goal).replace("-", "_")
    if not normalized:
        return _response(
            "ok",
            catalog,
            next_tools=["wf_current_wave"],
            usage="wf_help(goal='plan_feature')",
        )
    workflow = catalog["workflows"].get(normalized)
    if workflow is None:
        return _response(
            "ok",
            catalog,
            diagnostics=[
                _diagnostic(
                    "unknown_goal",
                    f"Unsupported workflow goal '{goal}'.",
                    recovery_tools=["wf_help"],
                    recovery_usage="wf_help()",
                )
            ],
            next_tools=["wf_help"],
            usage="wf_help()",
        )
    return _response(
        "ok",
        {"goal": normalized, **workflow},
        next_tools=list(workflow["recommended_chain"]),
        usage=str(workflow["usage"]),
    )




# ---------------------------------------------------------------------------
# Framework operation helpers (direct import)
# ---------------------------------------------------------------------------

_chunker_version_cache: str = ""


def _read_chunker_version() -> str:
    """Read CHUNKER_VERSION from chunker.py without importing the full module.

    Importing chunker.py requires tree-sitter and fastembed which are not
    always available (e.g. during unit tests). Reading the constant directly
    from source avoids that dependency.
    """
    global _chunker_version_cache
    if _chunker_version_cache:
        return _chunker_version_cache
    chunker_path = Path(__file__).resolve().parent / "chunker.py"
    try:
        source = chunker_path.read_text(encoding="utf-8")
        m = re.search(r'^CHUNKER_VERSION\s*=\s*["\']([^"\']+)["\']', source, re.MULTILINE)
        if m:
            _chunker_version_cache = m.group(1)
    except OSError:
        pass
    return _chunker_version_cache


def _background_build_status(root: Path) -> str:
    """Return 'running', 'completed', or 'none' for the background code build.

    Uses a PID file written by _spawn_background_code_build to detect whether
    the process is still alive. 'completed' means the PID file exists but the
    process has already exited (build finished or crashed).
    """
    pid_path = root / ".wavefoundry" / "index" / "background-build.pid"
    if not pid_path.exists():
        return "none"
    try:
        pid = int(pid_path.read_text(encoding="utf-8").strip())
    except (ValueError, OSError):
        return "completed"
    # Wave 1p6d6: route through the guarded _pid_is_running (Windows-correct via tasklist)
    # instead of an inline os.kill that misjudges liveness on native Windows.
    return "running" if _pid_is_running(pid) else "completed"


def _background_build_progress(root: Path) -> str:
    """Return the latest non-empty line from the background build log, if any."""
    log_path = _project_background_build_log_path(root)
    if not log_path.exists():
        return ""
    try:
        log_text = log_path.read_text(encoding="utf-8", errors="replace")
    except OSError:
        return ""
    for line in reversed(log_text.splitlines()):
        text = line.strip()
        if text:
            return text
    return ""


def _infer_tags(path: str) -> list[str]:
    """Return classification tags for a file path. Delegates to _tag_utils — single source of truth."""
    return _load_script("_tag_utils").infer_tags(path)


_script_cache: dict[str, Any] = {}
"""Module-level cache for scripts loaded via _load_script.

Keyed by a namespaced string (e.g. ``_wavefoundry_indexer``) so the cache
entries do not collide with public ``sys.modules`` names. Each module is
executed at most once per process — subsequent calls return the cached object.
If hot-reload is needed during development, call ``_script_cache.clear()``.
"""


def _load_script(name: str) -> Any:
    """Load a sibling script as a module, executing it at most once per process.

    Uses a private ``_script_cache`` dict keyed by a namespaced name. The
    module is registered in ``sys.modules`` under the SAME namespaced key
    (not the public ``<name>``) so dataclass type resolution + relative
    imports work without polluting the public module namespace.
    """
    import importlib.util
    import sys as _sys

    cache_key = f"_wavefoundry_{name}"
    if cache_key in _script_cache:
        return _script_cache[cache_key]
    spec = importlib.util.spec_from_file_location(
        cache_key, Path(__file__).resolve().parent / f"{name}.py"
    )
    mod = importlib.util.module_from_spec(spec)
    # Register before exec so dataclass / typing machinery can resolve types
    # against the module's own namespace mid-construction.
    _sys.modules[cache_key] = mod
    try:
        spec.loader.exec_module(mod)
    except Exception:
        _sys.modules.pop(cache_key, None)
        raise
    _script_cache[cache_key] = mod
    return mod


def _regenerate_codebase_map_safe(root: Path) -> bool:
    """Fail-safe codebase-map regen for lifecycle checkpoints (wave 1p601).

    Map regen is decoupled from the index build; instead it fires at the
    prepare-wave / close-wave lifecycle checkpoints so the committed artifact
    stays fresh. ``generate_safe`` is change-only/idempotent (an unchanged
    codebase is a no-op). All exceptions are swallowed — regenerating the map
    must NEVER fail prepare or close.
    """
    try:
        gen = _load_script("gen_codebase_map")
        return bool(gen.generate_safe(root))
    except Exception:  # noqa: BLE001 — fail-safe: never break prepare/close
        return False


def _run_post_write_lint(root: Path) -> dict[str, Any]:
    """Run the incremental docs-lint and return a bounded summary for write-tool responses.

    Wave 1p3dk / 1p3dq: every write-side wave MCP tool calls this after its
    mutations so the response carries the post-write lint state. Agents no
    longer have to remember to manually invoke ``wf_validate_docs`` between
    gates. Lint state and tool status are deliberately decoupled — a tool
    can succeed structurally while the docs gate has issues, and the agent
    sees both signals at once.

    Wave 1p9pe: this ADVISORY attachment runs the cheap incremental scan
    (``run_validate_changed`` — git-changed-set only, hook timeout bound) so a
    write tool's response reflects only what it just wrote and returns quickly.
    The authoritative FULL-corpus gate stays at the six lifecycle callers of
    ``run_validate`` (wf_audit, wf_validate_docs, wf_audit_install,
    wf_prepare_wave, wf_review_wave, wf_close_wave).

    Returns ``{clean, error_count, warning_count, first_errors, mode}``. The
    ``mode`` key (additive, review-fix) is ``"incremental"`` | ``"full-fallback"``
    | ``"skipped"`` — ``skipped`` means no git changed-set was available (non-git
    checkout), so ``clean: True`` reflects a checked-nothing no-op rather than a
    checked-and-clean scan. The ``first_errors`` list is capped at 5 messages to
    keep responses bounded; full output is available via ``wf_validate_docs`` for
    deep dives. On unexpected failure (e.g., lint subprocess crashes), returns
    ``clean: None`` and an error notice in ``first_errors`` — the integration
    never breaks the tool.
    """
    try:
        result = run_validate_changed(root)
        errors = result.get("errors", [])
        warnings = result.get("warnings", [])
        return {
            "clean": bool(result.get("passed")),
            "error_count": len(errors),
            "warning_count": len(warnings),
            "first_errors": errors[:5],
            "mode": result.get("mode", "incremental"),
        }
    except Exception as exc:  # pragma: no cover — defensive isolation
        return {
            "clean": None,
            "error_count": -1,
            "warning_count": -1,
            "first_errors": [f"lint integration error: {type(exc).__name__}: {exc}"],
        }


def _attach_lint_to_response(envelope: dict[str, Any], root: Path, mode_s: str) -> dict[str, Any]:
    """Add the post-write lint state to a tool response envelope.

    Skip on dry_run (no writes occurred so lint state is unchanged from
    pre-call). Skip on error envelopes (the tool didn't perform writes
    successfully so reporting lint state would be misleading). The lint
    state lands under ``data.lint`` and does NOT change the envelope status.
    """
    if mode_s == "dry_run":
        return envelope
    if envelope.get("status") == "error":
        return envelope
    data = envelope.setdefault("data", {})
    data["lint"] = _run_post_write_lint(root)
    return envelope


def run_validate(root: Path) -> dict:
    """Run docs_lint and return structured pass/fail.

    ``PROJECT_ROOT`` is forwarded explicitly so the subprocess lints the
    correct tree even when the caller's environment already has ``PROJECT_ROOT``
    set to a different path (e.g. in multi-project MCP setups).
    """
    import subprocess

    script = Path(__file__).resolve().parent / "docs_lint.py"
    # Wave 1p9iu makes the timeout configurable via docs/workflow-config.json ``docs_lint.full_scan_
    # timeout_seconds`` (default DOCS_LINT_FULL_SCAN_TIMEOUT_DEFAULT) because the old hardcoded 30s was
    # too short for a large field repo's full-corpus scan. This is a FULL scan (no --changed flag) —
    # only the timeout is tunable, not the scan scope. On timeout we return a structured passed:False
    # result naming the config key instead of propagating TimeoutExpired: the six lifecycle callers
    # (wf_audit, wf_validate_docs, wf_prepare_wave, wf_review_wave, wf_close_wave, wf_audit_install) render
    # ``errors`` via docs_lint_error, so one catch here surfaces an actionable diagnostic through all
    # of them. Wave 1p9pe: the ADVISORY post-write attachment no longer calls this full scan — it uses
    # the incremental sibling run_validate_changed below; these six gate callers stay full-corpus.
    timeout_s = docs_lint_full_scan_timeout_seconds(root)
    try:
        result = _mcp_subprocess_run(
            [_preferred_python(), str(script)],
            cwd=str(root),
            env={**os.environ, "PROJECT_ROOT": str(root)},
            timeout=timeout_s,
        )
    except subprocess.TimeoutExpired as exc:
        elapsed = exc.timeout if getattr(exc, "timeout", None) else timeout_s
        message = (
            f"ERROR: docs-lint full-corpus scan timed out after {elapsed:g}s. Raise "
            f"`docs_lint.full_scan_timeout_seconds` in docs/workflow-config.json (default "
            f"{DOCS_LINT_FULL_SCAN_TIMEOUT_DEFAULT:g}s) if this repo's docs corpus legitimately needs "
            f"longer, or investigate a stalled docs_lint.py."
        )
        return {
            "passed": False,
            "errors": [message],
            "warnings": [],
            "output": message,
        }
    lines = (result.stdout + result.stderr).strip().splitlines()
    errors = [l for l in lines if l.startswith("ERROR:")]
    warnings = [l for l in lines if l.startswith("WARNING:")]
    passed = result.returncode == 0
    return {
        "passed": passed,
        "errors": errors,
        "warnings": warnings,
        "output": result.stdout + result.stderr,
    }


def run_validate_changed(root: Path) -> dict:
    """Run the INCREMENTAL docs_lint (changed-set scan) and return structured pass/fail.

    Wave 1p9pe: the advisory post-write lint attachment path. Spawns ``docs_lint.py``
    with the incremental flag, which self-detects the git working-tree changed set,
    runs only the per-file validators on changed ``docs/`` markdown, no-ops clean on
    an empty or non-git changed set, and falls back to the full lint inside the CLI
    when a config/corpus file changed. Bounded by the hook timeout knob
    (``docs_lint.hook_timeout_seconds``, default 120s — the same knob that bounds the
    post-edit hook's incremental scan), NOT the heavier full-scan knob — EXCEPT when
    the CLI's full-lint fallback is predicted (a trigger config/manifest/repo-profile
    file is in the git changed set): that invocation runs the full corpus, so it is
    bounded by ``docs_lint.full_scan_timeout_seconds`` and any timeout message names
    that knob (review-fix: the two knobs must not cross over). Returns the same
    ``{passed, errors, warnings, output}`` shape as ``run_validate``, including the
    structured timeout return, plus an additive ``mode`` key —
    ``"incremental"`` | ``"full-fallback"`` | ``"skipped"`` (no git changed-set
    available, per the CLI's summary line) — so callers can tell a checked-and-clean
    result from a checked-nothing no-op. The six full-corpus lifecycle gates keep
    calling ``run_validate`` — this helper is only for the post-write attachment.

    ``PROJECT_ROOT`` is forwarded explicitly so the subprocess lints the correct tree
    even when the caller's environment already has ``PROJECT_ROOT`` set to a
    different path (e.g. in multi-project MCP setups).
    """
    import subprocess

    script = Path(__file__).resolve().parent / "docs_lint.py"
    fallback_predicted = _predict_incremental_full_fallback(root)
    if fallback_predicted:
        timeout_s = docs_lint_full_scan_timeout_seconds(root)
    else:
        timeout_s = docs_lint_hook_timeout_seconds(root)
    try:
        result = _mcp_subprocess_run(
            [_preferred_python(), str(script), "--changed"],
            cwd=str(root),
            env={**os.environ, "PROJECT_ROOT": str(root)},
            timeout=timeout_s,
        )
    except subprocess.TimeoutExpired as exc:
        elapsed = exc.timeout if getattr(exc, "timeout", None) else timeout_s
        if fallback_predicted:
            message = (
                f"ERROR: docs-lint changed-set scan (full-lint fallback: a changed config/corpus "
                f"file forces the full corpus) timed out after {elapsed:g}s. Raise "
                f"`docs_lint.full_scan_timeout_seconds` in docs/workflow-config.json (default "
                f"{DOCS_LINT_FULL_SCAN_TIMEOUT_DEFAULT:g}s) if this repo's docs corpus "
                f"legitimately needs longer, or investigate a stalled docs_lint.py."
            )
        else:
            message = (
                f"ERROR: docs-lint incremental (changed-set) scan timed out after {elapsed:g}s. Raise "
                f"`docs_lint.hook_timeout_seconds` in docs/workflow-config.json (default "
                f"{_docs_lint_hook_timeout_default():g}s) if the changed-set scan legitimately needs "
                f"longer, or investigate a stalled docs_lint.py."
            )
        return {
            "passed": False,
            "errors": [message],
            "warnings": [],
            "output": message,
            "mode": "full-fallback" if fallback_predicted else "incremental",
        }
    lines = (result.stdout + result.stderr).strip().splitlines()
    errors = [l for l in lines if l.startswith("ERROR:")]
    warnings = [l for l in lines if l.startswith("WARNING:")]
    if fallback_predicted:
        mode = "full-fallback"
    elif any(l.startswith("docs-lint: skipped") for l in lines):
        mode = "skipped"
    else:
        mode = "incremental"
    return {
        "passed": result.returncode == 0,
        "errors": errors,
        "warnings": warnings,
        "output": result.stdout + result.stderr,
        "mode": mode,
    }


def run_garden(root: Path) -> dict:
    """Run docs_gardener and return structured summary."""
    script = Path(__file__).resolve().parent / "docs_gardener.py"
    result = _mcp_subprocess_run(
        [_preferred_python(), str(script)],
        cwd=str(root),
        env={**os.environ, "PROJECT_ROOT": str(root)},
    )
    output = result.stdout + result.stderr
    updated = [l for l in output.splitlines() if "wrote" in l.lower()]
    return {
        "passed": result.returncode == 0,
        "files_updated": len(updated),
        "updated": updated,
        "output": output,
    }


def run_sync_surfaces(root: Path) -> dict:
    """Run render_platform_surfaces and return structured summary."""
    script = Path(__file__).resolve().parent / "render_platform_surfaces.py"
    result = _mcp_subprocess_run(
        [_preferred_python(), str(script)],
        cwd=str(root),
        env={**os.environ, "PROJECT_ROOT": str(root)},
    )
    output = result.stdout + result.stderr
    written = [l for l in output.splitlines() if "wrote" in l.lower() or "rendered" in l.lower()]
    return {
        "passed": result.returncode == 0,
        "files_written": written,
        "output": output,
    }


def _index_dir_for_layer(root: Path, layer: str = "project") -> Path:
    # Wave 1p4ww: single project index — the framework layer is folded in.
    if layer == "project":
        return root / ".wavefoundry" / "index"
    raise ValueError(f"Unsupported layer '{layer}'.")


def _store_build_meta(index_dir: Path) -> dict[str, Any]:
    """1sed6: the build-state snapshot from the index-state store — the only
    build-metadata read path (meta.json retired). Empty dict when the store
    is absent/unreadable (callers treat as no prior state)."""
    try:
        iss = _load_script("index_state_store")
        return iss.export_meta_snapshot(index_dir) or {}
    except Exception:
        return {}


def _epoch_token(root: Path) -> "tuple[str, int] | None":
    """The reader epoch token (1sed6): ``(attempt_id, generation)`` of the
    COMPLETE build epoch, or None when the index is not servable (absent,
    uninitialized, mid-build, interrupted, unreadable). Cheap: one short
    read-only query, never held across the operation."""
    try:
        iss = _load_script("index_state_store")
        return iss.build_epoch_token(root / ".wavefoundry" / "index")
    except Exception:
        return None


def _epoch_state(root: Path) -> "tuple[str, str, int] | None":
    """The ABA-proof consistency token (1sed6 review fix): the full build-state
    row ``(attempt_id, status, generation)`` in ANY state; None only when the
    store is absent/unreadable. Used for the pre/post seqlock compare at every
    tool — unlike the complete-only ``_epoch_token``, it distinguishes
    ``building A`` from ``building B``, so an operation that straddled a
    finalize + re-fence (both endpoints "not ready") is still discarded."""
    try:
        iss = _load_script("index_state_store")
        return iss.build_epoch_state_token(root / ".wavefoundry" / "index")
    except Exception:
        return None


_FRESHNESS_TTL_SECONDS = 5.0
_FRESHNESS_CACHE: "dict[str, tuple[float, object, dict]]" = {}


def _index_freshness_verdict(root: Path) -> dict[str, Any]:
    """Cheap cached three-state freshness verdict (wave 1seav / 1sbxq).

    ``{"state": "current" | "stale" | "unknown", "reason": str}`` — replaces
    code_ask's per-call ``_layer_health`` O(corpus) hash walk. The cache has
    BOTH invalidation axes (P0 plan repair): a root-scoped seconds-scale TTL
    (the build generation only advances at finalization, so TTL bounds
    edit-detection latency between builds) AND the 1sed7 epoch state token
    (any build transition — publish, fence — refreshes immediately without
    waiting out the TTL). Exceptions and undeterminable states are "unknown",
    never silently "current" (the 1sbfj honesty rule).
    """
    key = str(root)
    now = time.monotonic()
    tok = _epoch_state(root)
    cached = _FRESHNESS_CACHE.get(key)
    if cached is not None and now < cached[0] and cached[1] == tok:
        return cached[2]
    try:
        idx = _load_script("indexer")
        result = idx.project_layer_freshness(root)
        stale = result.get("stale")
        state = "unknown" if stale is None else ("stale" if stale else "current")
        verdict = {"state": state, "reason": str(result.get("reason", ""))}
    except Exception as exc:  # noqa: BLE001 - honesty rule
        verdict = {"state": "unknown", "reason": f"freshness check failed: {exc}"}
    _FRESHNESS_CACHE[key] = (now + _FRESHNESS_TTL_SECONDS, tok, verdict)
    return verdict


def _index_rebuilding_response(tool: str, payload: dict) -> dict[str, Any]:
    """Structured not-ready/rebuilding result (1sed6 AC-4): the index has no
    complete epoch, or it changed while the operation ran — results (if any)
    were discarded rather than served as current."""
    payload = dict(payload)
    # AC-3 (review fix): the search_mode/fallback_reason contract is carried
    # on EVERY response from the gated search tools, including refusals.
    payload.setdefault("search_mode", None)
    payload.setdefault("fallback_reason", "index_not_ready")
    payload.setdefault("results", [])
    response = _response(
        "error", payload,
        diagnostics=[_diagnostic(
            "index_not_ready",
            "The semantic index has no completed build epoch (building, interrupted, "
            "or not yet built) or it changed while this query ran — results were "
            "discarded rather than served from a mixed index state. Check "
            "index_build_status; retry after the build completes.",
            recovery_tools=["index_build_status", "index_build"],
            recovery_usage="index_build_status()",
        )],
        next_tools=["index_build_status"],
        usage="index_build_status()",
    )
    return _attach_retrieval_failure_context(tool, response)


def _store_has_completed_build(index_dir: Path) -> bool:
    """True when the store's build epoch is `complete` (1sed6 readiness)."""
    try:
        iss = _load_script("index_state_store")
        return iss.build_epoch_token(index_dir) is not None
    except Exception:
        return False


def _read_index_rebuild_stats(root: Path, layer: str) -> dict[str, Any]:
    index_dir = _index_dir_for_layer(root, layer)

    meta: dict[str, Any] = {}
    doc_chunks = 0
    code_chunks = 0

    if True:
        try:
            meta = _store_build_meta(index_dir)
        except (OSError, json.JSONDecodeError):
            meta = {}

    # Try Lance tables for chunk counts; fall back to 0 if unavailable.
    try:
        import lancedb
        db = lancedb.connect(str(index_dir))
        if (index_dir / "docs.lance").is_dir():
            doc_chunks = db.open_table("docs").count_rows()
        if (index_dir / "code.lance").is_dir():
            code_chunks = db.open_table("code").count_rows()
    except Exception:
        pass

    return {
        "files_total": len(meta.get("file_meta") or meta.get("file_hashes") or {}),
        "doc_chunks": doc_chunks,
        "code_chunks": code_chunks,
        "available_content": list(meta.get("content", [])),
        "built_at": meta.get("built_at", ""),
    }


def _index_is_up_to_date(root: Path, layer: str, content: str = "docs") -> bool:
    """Return True if the index has no stale or missing files.

    Runs the indexer with --dry-run (hash check only, no embedding/writes) and
    checks whether it reports the index as current. Used by run_index_rebuild
    to short-circuit spawning a background process when there is nothing to do.
    """
    import subprocess
    scripts_dir = Path(__file__).resolve().parent
    index_dir = _index_dir_for_layer(root, layer)
    if not _store_has_completed_build(index_dir):
        return False
    if layer == "project" and content in {"all", "graph"}:
        # setup_index.py (all) and graph-only mode don't support --dry-run; treat as always stale
        return False
    else:
        check_content = content
    cmd = [
        _preferred_python(), str(scripts_dir / "indexer.py"),
        "--root", str(root), "--content", check_content, "--dry-run",
    ]
    # Project layer: indexer.py reads workflow-config include-prefixes itself.
    try:
        result = _mcp_subprocess_run(
            cmd, capture_output=True, cwd=str(root),
            env={**os.environ, "PROJECT_ROOT": str(root)},
            timeout=30,
        )
        return result.returncode == 0 and "build_index: index is up to date" in (result.stdout + result.stderr)
    except Exception:
        return False


def _index_build_state_path(root: Path, layer: str = "project") -> Path:
    return root / ".wavefoundry" / "index" / "index-build.json"


def _clear_index_build_state(root: Path, layer: str) -> None:
    try:
        _index_build_state_path(root, layer).unlink()
    except OSError:
        pass


def _index_build_log_path(root: Path, layer: str = "project") -> Path:
    return root / ".wavefoundry" / "logs" / "project-index-build.log"


def _project_background_build_log_path(root: Path) -> Path:
    return root / ".wavefoundry" / "logs" / "project-background-build.log"


def _index_build_stats_path(root: Path, layer: str = "project") -> Path:
    return root / ".wavefoundry" / "index" / "index-build-stats.json"


def _graph_health_summary(root: Path) -> dict[str, Any]:
    """Wave 13129 (1316n): summary of graph artifact presence + last-built per layer.

    Operators reading index_health get this alongside semantic-layer
    readiness so the "did my rebuild touch graph?" question is answerable
    inline without inspecting timestamps manually.

    Returns dict with shape:
        {
            "project": {"present": bool, "last_built_at": str | None,
                        "node_count": int | None, "edge_count": int | None},
        }

    Wave 1p4ww: single project graph — the framework layer is folded in.
    """
    import datetime as _dt
    summary: dict[str, Any] = {}
    for layer, fname in (("project", "project-graph.json"),):
        graph_path = root / ".wavefoundry" / "index" / "graph" / fname
        if not graph_path.exists():
            summary[layer] = {
                "present": False, "last_built_at": None,
                "node_count": None, "edge_count": None,
            }
            continue
        try:
            mtime = graph_path.stat().st_mtime
            last_built = _dt.datetime.fromtimestamp(mtime, tz=_dt.timezone.utc).isoformat()
        except OSError:
            last_built = None
        node_count = edge_count = None
        try:
            # Wave 1p9q3 (1p9py): graph artifacts are gzip-compressed compact
            # JSON — read through the sniffing reader (legacy plain-JSON safe).
            payload = _load_script("graph_cluster").read_json_artifact(graph_path, {})
            nodes = payload.get("nodes") or []
            edges = payload.get("edges") or []
            node_count = len(nodes) if isinstance(nodes, list) else None
            edge_count = len(edges) if isinstance(edges, list) else None
        except Exception:
            pass
        summary[layer] = {
            "present": True, "last_built_at": last_built,
            "node_count": node_count, "edge_count": edge_count,
        }
    return summary


def _state_store_health_summary(root: Path) -> dict[str, Any]:
    """Wave 1rsh9 (1rq4h): index-state store presence, schema version, integrity.

    Runs the two-layer probe (structural ``quick_check`` + freshness
    source-fingerprint binding). Shape:
        {"present": bool, "schema_version": str | None,
         "integrity": "ok" | "structural-fail" | "stale-fingerprint" | None,
         "size_bytes": int,
         "chunk_index": {table: {"lance_rows": int, "registry_rows": int,
                                 "covered": bool}}}
    Absence of the store (or of the module in an older pack) reports
    ``present: False`` with no diagnostics — a normal not-yet-built state.

    ``chunk_index`` (1sbfj): registry coverage vs Lance per table. The field
    defect left the FTS/registry near-empty (lexical retrieval silently
    blind) while ``integrity`` read ``ok`` — structural soundness says
    nothing about coverage, so coverage is now reported and diagnosed
    explicitly. ``covered`` mirrors the zero-change heal probe: exact match
    against the counts recorded at the last successful reconcile when
    available (Lance ids are not unique, so a raw-vs-registry compare
    misreads duplicate-id rows as under-coverage), else the proportional
    ``max(8, lance_rows // 50)`` gap.
    """
    index_dir = root / ".wavefoundry" / "index"
    summary: dict[str, Any] = {
        "present": False, "schema_version": None, "integrity": None, "size_bytes": 0,
    }
    try:
        iss = _load_script("index_state_store")
    except Exception:
        return summary
    try:
        store_path = iss.state_store_path(index_dir)
        if not store_path.exists():
            return summary
        summary["present"] = True
        summary["size_bytes"] = iss._store_size_bytes(store_path)
        probe = iss.probe_state_store(root, index_dir, deep=False)
        summary["integrity"] = probe.get("status")
        summary["schema_version"] = probe.get("schema_version")
    except Exception:
        pass
    try:
        coverage: dict[str, Any] = {}
        import lancedb  # local import: keep module import cheap and optional
        db = lancedb.connect(str(index_dir))
        for table_name in ("docs", "code"):
            if not (index_dir / f"{table_name}.lance").is_dir():
                continue
            lance_rows = int(db.open_table(table_name).count_rows())
            registry_rows = iss.registry_chunk_count(index_dir, table_name)
            if registry_rows is None:
                continue
            synced_raw, synced_unique = iss.chunk_sync_counts(index_dir, table_name)
            if synced_raw is not None and synced_unique is not None:
                covered = lance_rows == synced_raw and registry_rows == synced_unique
            else:
                covered = abs(lance_rows - registry_rows) <= max(8, lance_rows // 50)
            coverage[table_name] = {
                "lance_rows": lance_rows,
                "registry_rows": int(registry_rows),
                "covered": covered,
            }
        if coverage:
            summary["chunk_index"] = coverage
    except Exception:
        pass
    return summary


def _read_index_build_stats_file(root: Path, layer: str) -> Optional[dict[str, Any]]:
    """Return persisted build stats from a previous completed build, or None."""
    try:
        path = _index_build_stats_path(root, layer)
        if not path.exists():
            return None
        return json.loads(path.read_text(encoding="utf-8"))
    except Exception:
        return None


def _write_index_build_stats_file(root: Path, layer: str, stats: dict[str, Any]) -> None:
    """Persist build stats — never raises."""
    try:
        path = _index_build_stats_path(root, layer)
        path.parent.mkdir(parents=True, exist_ok=True)
        path.write_text(json.dumps(stats), encoding="utf-8")
    except Exception:
        pass


def _parse_finished_build_stats_from_log(
    root: Path,
    layer: str,
    log_path: Path,
    *,
    state_path: Optional[Path] = None,
    fallback_stats: Optional[dict[str, Any]] = None,
) -> Optional[tuple[dict[str, Any], float]]:
    """Return parsed build stats plus the log mtime, or None if the log is not terminal."""
    if not isinstance(root, Path):
        return None
    try:
        active = _index_build_active(root, layer)
    except Exception:
        active = False
    if active or not log_path.exists():
        return None

    try:
        log_text = log_path.read_text(encoding="utf-8", errors="replace")
    except OSError:
        return None
    if not log_text:
        return None
    if not (
        re.search(r"done\s*[—-]+\s*\d+\s+files? indexed,\s*\d+\s+doc chunks?,\s*\d+\s+code chunks?", log_text)
        or re.search(r"index is up to date", log_text)
    ):
        return None

    files_indexed: Optional[int] = None
    doc_chunks: Optional[int] = None
    code_chunks: Optional[int] = None
    m = re.search(r"done\s*[—-]+\s*(\d+)\s+files? indexed,\s*(\d+)\s+doc chunks?,\s*(\d+)\s+code chunks?", log_text)
    if m:
        files_indexed, doc_chunks, code_chunks = int(m.group(1)), int(m.group(2)), int(m.group(3))
    if files_indexed is None:
        return None

    prev_state: dict[str, Any] = {}
    if state_path is not None:
        try:
            if state_path.exists():
                prev_state = json.loads(state_path.read_text(encoding="utf-8"))
        except Exception:
            prev_state = {}
    if not prev_state and isinstance(fallback_stats, dict):
        prev_state = dict(fallback_stats)

    started_at = prev_state.get("started_at")
    try:
        finished_ts = log_path.stat().st_mtime
    except OSError:
        finished_ts = None
    elapsed = (
        int(float(finished_ts) - float(started_at))
        if finished_ts is not None and isinstance(started_at, (int, float))
        else prev_state.get("elapsed_seconds") if isinstance(prev_state.get("elapsed_seconds"), int) else None
    )
    stats = {
        "elapsed_seconds": elapsed,
        "files_indexed": files_indexed,
        "doc_chunks": doc_chunks,
        "code_chunks": code_chunks,
        "built_at": (
            datetime.datetime.utcfromtimestamp(finished_ts).isoformat() + "Z"
            if finished_ts is not None else prev_state.get("built_at")
        ),
        "content": prev_state.get("content"),
        "mode": "rebuild" if prev_state.get("full") else prev_state.get("mode", "update"),
    }
    return stats, float(finished_ts or 0.0)


def _refresh_index_build_stats_from_finished_log(
    root: Path,
    layer: str,
    *,
    log_path: Optional[Path] = None,
    state_path: Optional[Path] = None,
    fallback_stats: Optional[dict[str, Any]] = None,
) -> Optional[dict[str, Any]]:
    """Persist build stats from a finished build log, if available."""
    candidate_log = log_path or _index_build_log_path(root, layer)
    parsed = _parse_finished_build_stats_from_log(
        root,
        layer,
        candidate_log,
        state_path=state_path or _index_build_state_path(root, layer),
        fallback_stats=fallback_stats,
    )
    if parsed is None:
        return None
    stats, _ = parsed
    _write_index_build_stats_file(root, layer, stats)
    return stats


def _refresh_index_build_stats_from_finished_logs(root: Path, layer: str) -> Optional[dict[str, Any]]:
    """Persist build stats from the freshest finished build log for a layer."""
    if not isinstance(root, Path):
        return None
    try:
        active = _index_build_active(root, layer)
    except Exception:
        active = False
    if active:
        return None

    fallback_stats = _read_index_build_stats_file(root, layer) or {}
    candidates: list[tuple[Path, Optional[Path]]] = []
    if layer == "project":
        candidates.append((_project_background_build_log_path(root), None))
    candidates.append((_index_build_log_path(root, layer), _index_build_state_path(root, layer)))

    best_stats: Optional[dict[str, Any]] = None
    best_ts = -1.0
    for candidate_log, candidate_state in candidates:
        parsed = _parse_finished_build_stats_from_log(
            root,
            layer,
            candidate_log,
            state_path=candidate_state,
            fallback_stats=fallback_stats,
        )
        if parsed is None:
            continue
        stats, finished_ts = parsed
        if finished_ts >= best_ts:
            best_ts = finished_ts
            best_stats = stats

    if best_stats is None:
        return None
    _write_index_build_stats_file(root, layer, best_stats)
    return best_stats


def _index_build_active(root: Path, layer: str) -> bool:
    """Return True if a index_build-spawned process is currently running."""
    state_path = _index_build_state_path(root, layer)
    if not state_path.exists():
        return False
    try:
        state = json.loads(state_path.read_text(encoding="utf-8"))
    except (OSError, json.JSONDecodeError):
        return False
    pid = state.get("pid")
    if isinstance(pid, int) and _pid_is_running(pid):
        return True
    # Brief throttle covers the Popen → indexer lock-acquire window (~1-2s cold start).
    # Reuses BACKGROUND_INDEX_REFRESH_THROTTLE_SECONDS (15s) — same race condition.
    started_at = state.get("started_at")
    if isinstance(started_at, (int, float)):
        import time
        if (time.time() - float(started_at)) < BACKGROUND_INDEX_REFRESH_THROTTLE_SECONDS:
            return True
    return False


def run_index_rebuild(
    root: Path,
    *,
    content: str = "docs",
    full: bool = False,
    rechunk: bool = False,
    layer: str = "project",
) -> dict:
    """Spawn indexer.py as a background process and return immediately with pre-build stats.

    The indexer runs detached; stdout/stderr are written to ``index-build.log`` in the
    index directory. Exposed as MCP ``index_build`` with ``mode='update'|'rebuild'``.
    """
    import subprocess
    import time
    if content not in {"docs", "code", "all", "graph", "map", "fts"}:
        raise ValueError(f"Unsupported content '{content}'.")
    # Wave 1p4ww: single project index — the framework layer is folded in.
    if layer != "project":
        raise ValueError(f"Unsupported layer '{layer}'.")

    # Wave 1p601: content="map" is a map-only refresh — run the ~0.09s codebase
    # map generator (change-only/idempotent) WITHOUT a full index rebuild. No
    # subprocess, fail-safe (never raises into the tool).
    if content == "map":
        regenerated = False
        try:
            gen = _load_script("gen_codebase_map")
            regenerated = bool(gen.generate_safe(root, force=True))
        except Exception:
            regenerated = False
        out_rel = "docs/references/codebase-map.md"
        return {
            "passed": True,
            "already_running": False,
            "up_to_date": False,
            "content": "map",
            "full": False,
            "mode": "map-refresh",
            "index_scope": "codebase_map_only",
            "layer": layer,
            "regenerated": regenerated,
            "notice": (
                f"Codebase map refreshed → {out_rel}."
                if regenerated
                else "Codebase map refresh skipped (no artifacts yet or generator unavailable)."
            ),
            "map_path": out_rel,
        }

    # Wave 1sc7c (1sek8): content="fts" — from-scratch rebuild of the DERIVED
    # chunk state (FTS5 lexical tables + chunk registry) from the
    # authoritative Lance tables. Embedding-free and in-process (seconds):
    # the clean recovery for an under-covered/corrupt lexical layer without a
    # semantic build. Runs under the whole-index build lock.
    if content == "fts":
        idx_mod = _load_script("indexer")
        index_dir = root / ".wavefoundry" / "index"
        _fts_busy = {
            "passed": True,
            "already_running": True,
            "content": "fts",
            "mode": "derived-rebuild",
            "index_scope": "derived_chunk_state_only",
            "layer": layer,
            "notice": "Another build holds the index lock — retry when it finishes.",
        }
        if _index_build_active(root, layer):
            return _fts_busy
        _fts_t0 = time.monotonic()
        try:
            with idx_mod._index_build_lock(index_dir):
                tables = idx_mod.rebuild_derived_chunk_state(index_dir)
        except idx_mod.IndexBuildAlreadyRunning:
            return _fts_busy
        _fts_ms = round((time.monotonic() - _fts_t0) * 1000)
        # Independent-review N1: the restore-only refusal is a TOP-LEVEL
        # {"error": str} — it must fail this response, not slip past the
        # dict-only comprehensions as passed=True.
        if isinstance(tables.get("error"), str):
            return {
                "passed": False,
                "already_running": False,
                "content": "fts",
                "mode": "derived-rebuild",
                "index_scope": "derived_chunk_state_only",
                "layer": layer,
                "error": tables["error"],
                "duration_ms": _fts_ms,
                "notice": tables["error"],
            }
        rows = {k: v.get("rows_written") for k, v in tables.items() if isinstance(v, dict)}
        errors = {k: v.get("error") for k, v in tables.items()
                  if isinstance(v, dict) and v.get("error")}
        return {
            "passed": not errors,
            "already_running": False,
            "content": "fts",
            "full": True,
            "mode": "derived-rebuild",
            "index_scope": "derived_chunk_state_only",
            "layer": layer,
            "tables": tables,
            "duration_ms": _fts_ms,
            "notice": (
                "Derived chunk state (FTS5 + registry) rebuilt from Lance: "
                + ", ".join(f"{k}={v}" for k, v in rows.items())
                if rows and not errors else
                "FTS rebuild completed with issues — see tables."
            ),
        }

    if _index_build_active(root, layer):
        log_path = _index_build_log_path(root, layer)
        pre_stats = _read_index_rebuild_stats(root, layer)
        _index_label = {"docs": "docs/seed", "code": "code", "all": "docs/seed + code"}.get(content, content)
        return {
            "passed": True,
            "already_running": True,
            "notice": (
                f"An index build for the {layer} layer is already in progress. "
                f"Watch progress: {log_path}"
            ),
            "content": content,
            "full": full,
            "mode": "rebuild" if full else ("rechunk" if rechunk else "update"),
            "index_scope": "full_rebuild" if full else ("rechunk_reuse" if rechunk else "incremental_update"),
            "layer": layer,
            "stats": pre_stats,
            "log": str(log_path),
        }

    scripts_dir = Path(__file__).resolve().parent
    python_exec = _preferred_python()

    if layer == "project" and content == "all":
        script = scripts_dir / "setup_index.py"
        cmd = [python_exec, str(script), "--root", str(root), "--include-code", "--verbose"]
    elif layer == "project" and content == "graph":
        script = scripts_dir / "setup_index.py"
        cmd = [python_exec, str(script), "--root", str(root), "--graph-only", "--verbose"]
    else:
        script = scripts_dir / "indexer.py"
        cmd = [python_exec, str(script), "--root", str(root), "--content", content, "--verbose"]
    # Project layer (docs/code): indexer.py reads workflow-config include-prefixes itself.
    if full:
        cmd.append("--full")
    # Wave 1p4n4 (mode='rechunk'): re-chunk all files + reuse embeddings by hash, no version change.
    # Meaningful only for chunked content (graph has no embeddings to reuse).
    if rechunk and content in {"docs", "code", "all"}:
        cmd.append("--rechunk")

    pre_stats = _read_index_rebuild_stats(root, layer)
    _index_label = {"docs": "docs/seed", "code": "code", "all": "docs/seed + code"}.get(content, content)
    _file_count = pre_stats.get("files_total", "?")

    # rechunk must NOT short-circuit on an up-to-date index — re-chunking unchanged files is the point.
    if not full and not rechunk and _index_is_up_to_date(root, layer, content):
        # Wave 1p31b (1p312): even when files are up-to-date, LanceDB rows for
        # paths now excluded by workflow-config narrowing must be reaped. The
        # bug is invisible to ``_index_is_up_to_date`` (the build state was already
        # cleaned of the dropped paths) but the LanceDB rows persist until a
        # full rebuild. Run the reaper directly here — no subprocess spawn
        # needed; the reaper is O(LanceDB row count) and finishes in <100ms
        # on tables up to ~5K rows.
        # 1sed6: the former in-process reaper here was a WRITER BYPASS — it
        # mutated Lance without the build lock or epoch. Reaping now lives
        # exclusively in the indexer's zero-change maintenance path (read-only
        # plan → fenced execute), which every real build (including the
        # content=all hook builds) runs; the short-circuit response no longer
        # mutates anything.
        reaped_uptd: dict[str, int] = {"docs": 0, "code": 0, "total": 0}
        return {
            "passed": True,
            "already_running": False,
            "up_to_date": True,
            "notice": f"Index is up to date — no rebuild needed.",
            "content": content,
            "full": False,
            "mode": "update",
            "index_scope": "incremental_update",
            "layer": layer,
            "stats": pre_stats,
            "stranded_rows_reaped": reaped_uptd.get("total", 0),
            "stranded_rows_reaped_by_table": reaped_uptd,
        }

    # Persist stats from the previous completed build before overwriting the log.
    state_path = _index_build_state_path(root, layer)
    log_path = _index_build_log_path(root, layer)
    prev_log_text = ""
    if log_path.exists():
        try:
            prev_log_text = log_path.read_text(encoding="utf-8", errors="replace")
        except OSError:
            pass
    if prev_log_text:
        _m = re.search(
            r"done\s*[—-]+\s*(\d+)\s+files? indexed,\s*(\d+)\s+doc chunks?,\s*(\d+)\s+code chunks?",
            prev_log_text,
        )
        if _m:
            _prev_state: dict[str, Any] = {}
            try:
                _prev_state = json.loads(_index_build_state_path(root, layer).read_text(encoding="utf-8"))
            except Exception:
                pass
            _prev_started = _prev_state.get("started_at")
            _finished_ts: Optional[float] = None
            try:
                _finished_ts = log_path.stat().st_mtime
            except OSError:
                pass
            _elapsed = (
                int(_finished_ts - float(_prev_started))
                if _finished_ts is not None and isinstance(_prev_started, (int, float))
                else None
            )
            _write_index_build_stats_file(root, layer, {
                "elapsed_seconds": _elapsed,
                "files_indexed": int(_m.group(1)),
                "doc_chunks": int(_m.group(2)),
                "code_chunks": int(_m.group(3)),
                "built_at": (
                    datetime.datetime.utcfromtimestamp(_finished_ts).isoformat() + "Z"
                    if _finished_ts is not None else None
                ),
                "content": _prev_state.get("content", content),
                "mode": "rebuild" if _prev_state.get("full") else "update",
            })

    log_path.parent.mkdir(parents=True, exist_ok=True)
    log_file = open(log_path, "w", encoding="utf-8")  # noqa: SIM115
    try:
        kwargs: dict[str, Any] = {
            "stdout": log_file,
            "stderr": log_file,
            "stdin": subprocess.DEVNULL,
            "cwd": str(root),
                "env": {
                    **os.environ,
                    "PROJECT_ROOT": str(root),
                    "WAVEFOUNDRY_INDEX_BUILD_STATE_PATH": str(state_path),
                    "WAVEFOUNDRY_TIMESTAMP_LOGS": "1",
                },
            }
        if os.name == "nt":
            kwargs["creationflags"] = (
                subprocess.DETACHED_PROCESS | subprocess.CREATE_NEW_PROCESS_GROUP | _windows_no_window_flag()
            )
        else:
            kwargs["start_new_session"] = True
        proc = subprocess.Popen(cmd, **kwargs)
    finally:
        log_file.close()
    state_path.write_text(
        json.dumps({"pid": proc.pid, "started_at": time.time(), "content": content, "layer": layer, "full": full}),
        encoding="utf-8",
    )

    _build_stats = _read_index_build_stats_file(root, layer)
    _timing_hint = ""
    if _build_stats and isinstance(_build_stats.get("elapsed_seconds"), int):
        _mins = round(_build_stats["elapsed_seconds"] / 60)
        _prev_files = _build_stats.get("files_indexed", "?")
        _timing_hint = f" Last build took ~{_mins} minute{'s' if _mins != 1 else ''} for {_prev_files} files — expect similar."

    if content == "graph":
        notice = (
            f"Rebuilding graph index ({layer} layer) — extracting nodes/edges and re-clustering communities. "
            f"No semantic embedding — typically completes in ~10 seconds. "
            f"Watch progress: {log_path}"
        )
    elif full:
        notice = (
            f"Rebuilding {_index_label} index ({layer} layer) — {_file_count} source files. "
            f"The index is being built locally and may take 5–10 minutes depending on repository size."
            f"{_timing_hint} "
            f"Watch progress: {log_path}"
        )
    else:
        notice = (
            f"Updating {_index_label} index ({layer} layer) — scanning for changes. "
            f"The index is being built locally and may take 5–10 minutes depending on repository size."
            f"{_timing_hint} "
            f"Watch progress: {log_path}"
        )

    mode_label = "rebuild" if full else ("rechunk" if rechunk else "update")
    # Wave 1p2q3 (1p2w5): synchronous post-Popen verification window. The
    # subprocess can die in its first few hundred ms with "lock file busy"
    # written to the log; the prior code returned `passed: True` immediately
    # after Popen and the caller got no signal that the rebuild silently
    # failed. We poll briefly (≤1.5s, sampled every 100ms): a process that
    # survives the window has acquired its locks and is in `build_index`
    # proper. If the process exited inside the window with a non-zero exit
    # code, surface the failure to the caller.
    import time as _time
    _verify_deadline = _time.monotonic() + _INDEX_BUILD_VERIFY_TIMEOUT_SECONDS
    _early_exit_code: int | None = None
    while _time.monotonic() < _verify_deadline:
        _poll_result = proc.poll()
        # Real `subprocess.Popen.poll()` returns Optional[int]: None means
        # "still running", an int is the exit code. We type-check here both
        # to guard against test mocks that don't configure poll() and to
        # tolerate any future Popen wrapper returning richer objects.
        if isinstance(_poll_result, int):
            _early_exit_code = _poll_result
            break
        _time.sleep(_INDEX_BUILD_VERIFY_POLL_INTERVAL_SECONDS)
    if _early_exit_code is not None and _early_exit_code != 0:
        # Subprocess died inside the verification window. Read the log to
        # surface a useful diagnostic to the caller.
        log_tail = ""
        try:
            log_tail = log_path.read_text(encoding="utf-8", errors="replace")[-2048:]
        except OSError:
            pass
        lock_busy = (
            "Another index build is already running" in log_tail
            or "lock file busy" in log_tail
        )
        diagnostic_code = "build_skipped_lock_busy" if lock_busy else "index_build_subprocess_failed"
        # Look up the lock-holder PID so the caller can decide whether to
        # wait or to clean up after a known-dead holder.
        lock_owner_pid: int | None = None
        try:
            import importlib.util as _importlib_util
            _indexer_spec = _importlib_util.spec_from_file_location(
                "wavefoundry_indexer_for_lock_owner",
                Path(__file__).resolve().parent / "indexer.py",
            )
            if _indexer_spec is not None and _indexer_spec.loader is not None:
                _indexer_mod = _importlib_util.module_from_spec(_indexer_spec)
                _indexer_spec.loader.exec_module(_indexer_mod)
                _lock_path = root / ".wavefoundry" / "index" / "index-build.lock"
                _meta = _indexer_mod.read_index_build_lock_metadata(_lock_path)
                if isinstance(_meta, dict) and isinstance(_meta.get("pid"), int):
                    lock_owner_pid = int(_meta["pid"])
        except Exception:
            pass
        return {
            "passed": False,
            "already_running": False,
            "build_failed_early": True,
            "exit_code": _early_exit_code,
            "lock_owner_pid": lock_owner_pid,
            "diagnostic_code": diagnostic_code,
            "notice": (
                f"Index rebuild subprocess (pid {proc.pid}) exited within {1.5}s with code "
                f"{_early_exit_code}"
                + (f" — lock held by pid {lock_owner_pid}." if lock_busy and lock_owner_pid else ".")
            ),
            "content": content,
            "full": full,
            "mode": mode_label,
            "index_scope": "full_rebuild" if full else ("rechunk_reuse" if rechunk else "incremental_update"),
            "layer": layer,
            "stats": pre_stats,
            "log": str(log_path),
            "log_tail": log_tail,
            "pid": proc.pid,
        }
    return {
        "passed": True,
        "already_running": False,
        "notice": notice,
        "content": content,
        "full": full,
        "mode": mode_label,
        "index_scope": "full_rebuild" if full else ("rechunk_reuse" if rechunk else "incremental_update"),
        "layer": layer,
        "stats": pre_stats,
        "log": str(log_path),
        "pid": proc.pid,
    }


# ---------------------------------------------------------------------------
# Per-citation freshness annotation + drift partition (wave 1ro44 / 1ro43)
# ---------------------------------------------------------------------------
#
# Two distinct freshness vocabularies coexist by design:
# - envelope-level `index_freshness` (1seav): is the INDEX current w.r.t. the
#   working tree ("current" | "stale" | "unknown").
# - per-citation `freshness` (this block): is the CITED CONTENT current w.r.t.
#   the code it describes ({age_days, churn_score} for every path; docs rows
#   add {drifted, commits_since_verified} or {historical, waves_behind}).

# Kill switch + census/eval opt-in for the drift partition. The partition is a
# RANKING change and ships DEFAULT-OFF: flipping the default requires BOTH the
# AC-8 drift-precision census AND a golden-query eval run (or explicit
# operator waiver) per the standing eval-gate policy. Env-var form follows the
# retrieval-toggle convention (WAVEFOUNDRY_DISABLE_RERANKER / _LEXICAL_FUSION).
DRIFT_PARTITION_DISABLE_ENV = "WAVEFOUNDRY_DISABLE_DRIFT_PARTITION"
DRIFT_PARTITION_ENABLE_ENV = "WAVEFOUNDRY_ENABLE_DRIFT_PARTITION"
DRIFT_PARTITION_DEFAULT_ON = False
# Comparable-relevance guard width on the unified cross-encoder sigmoid scale
# (0..1): a drifted docs citation is only partitioned when a NON-drifted
# candidate scores within this band of it (or above) — a nearly-as-relevant
# current alternative exists, so demoting the drifted one cannot bury the only
# good answer. 0.10 is deliberately conservative (one tenth of the scale).
DRIFT_RELEVANCE_BAND = 0.10


def _drift_partition_enabled() -> bool:
    if os.environ.get(DRIFT_PARTITION_DISABLE_ENV):
        return False
    if os.environ.get(DRIFT_PARTITION_ENABLE_ENV):
        return True
    return DRIFT_PARTITION_DEFAULT_ON


def _annotate_freshness(items: list[dict], root: Any, *, search_mode: Optional[str]) -> None:
    """Attach optional per-citation `freshness` via ONE batched store read.

    Silent absence everywhere: metadata-free stores, store read failures, and
    unknown paths simply leave citations unannotated (1ro43 Req 4 back-compat).
    Omitted entirely on `live_fallback` — live-walked content may be newer
    than any stored metadata, so annotating it would be dishonest. Never calls
    `freshness_for_path` per citation (query-path budget) and never spawns git.
    """
    if not items or search_mode == "live_fallback":
        return
    try:
        iss = _load_script("index_state_store")
        annotations = iss.freshness_for_paths(
            Path(root) / ".wavefoundry" / "index",
            [str(it.get("path") or "") for it in items],
        )
    except Exception:
        return
    if not annotations:
        return
    for it in items:
        fresh = annotations.get(str(it.get("path") or ""))
        if fresh:
            it["freshness"] = fresh


def _partition_drift(citations: list[dict]) -> int:
    """Stable partition of drift-flagged docs citations (1ro43 Req 5 / AC-4).

    Pattern: `_partition_infra` — order-preserving, post-rerank, never a score
    perturbation. Reintroduces the per-citation `demoted: true` +
    `partition_reason` fields (removed with the seed/feedback partition in
    change 12q5v) with the new reason `doc_code_drift`. Callers enforce the
    healthy-reranked-path precondition (`reranked` true, semantic/hybrid mode)
    — the relevance band is only meaningful on the unified cross-encoder
    scale, so degraded/exact/unreranked envelopes get annotation only. Code
    chunks are structurally exempt (their annotation never carries `drifted`).
    Mutates `citations` in place; returns the demoted count.
    """
    if not _drift_partition_enabled():
        return 0
    moved_idx: set[int] = set()
    for i, citation in enumerate(citations):
        fresh = citation.get("freshness") or {}
        if not fresh.get("drifted"):
            continue
        score = citation.get("score")
        if score is None:
            continue
        band_floor = float(score) - DRIFT_RELEVANCE_BAND
        has_comparable_current = any(
            j != i
            and not ((citations[j].get("freshness") or {}).get("drifted"))
            and citations[j].get("score") is not None
            and float(citations[j]["score"]) >= band_floor
            for j in range(len(citations))
        )
        if has_comparable_current:
            moved_idx.add(i)
    if not moved_idx:
        return 0
    kept = [c for i, c in enumerate(citations) if i not in moved_idx]
    moved = [citations[i] for i in sorted(moved_idx)]
    for citation in moved:
        citation["demoted"] = True
        citation["partition_reason"] = "doc_code_drift"
    citations[:] = kept + moved
    return len(moved)


def docs_search_response(index: WaveIndex, query: str, kind: str = "", limit: int = 7, tags: Optional[list] = None, epoch_state: Any = "__compute__") -> dict[str, Any]:
    k = (kind or "").strip().lower()
    n = max(1, min(int(limit), 20))  # clamp to [1, 20]
    if k and k not in DOCS_SEARCH_KINDS:
        allowed = ", ".join(sorted(DOCS_SEARCH_KINDS))
        return _response(
            "error",
            {"query": query, "kind": kind, "results": [], "search_mode": None, "fallback_reason": None},
            diagnostics=[
                _diagnostic(
                    "invalid_arguments",
                    f"Unsupported docs_search kind {kind!r}. Allowed: {allowed}, or omit kind.",
                    recovery_tools=["wf_help"],
                    recovery_usage="wf_help(goal='search_docs')",
                )
            ],
            next_tools=["wf_help"],
            usage=f"docs_search(query={query!r}, kind='doc')",
        )
    diagnostics: list[dict[str, Any]] = []
    search_mode = "semantic"
    results: list[dict[str, Any]] = []
    fallback_reason: "str | None" = None
    reranked = False
    coverage: dict[str, Any] = {}
    # 1seaq state discipline: the serve decision is made on the CAPTURED
    # 1sed7 state token (passed in by the tool registration — no second
    # read); a direct caller without one computes it once here.
    if epoch_state == "__compute__":
        epoch_state = _epoch_state(index.root)
    _epoch_complete = epoch_state is not None and epoch_state[1] == "complete"

    def _live_walk(reason: str, exc_msg: str) -> None:
        nonlocal search_mode, fallback_reason, results
        search_mode = "live_fallback"
        fallback_reason = reason
        diagnostics.append(_diagnostic(
            reason if reason in ("index_not_ready",) else "store_absent",
            f"{exc_msg} Serving the live-filesystem walk (per-call re-chunk; "
            "slow on large repos) — the only state with no published FTS to serve.",
            recovery_tools=["index_build", "index_build_status"],
            recovery_usage="index_build(content='all', mode='update')",
        ))
        try:
            # Review fix: the tag filter survives the live walk too (the
            # original 1seaq defect was silent tag loss in this fallback).
            results = index.search_docs_lexical(query, kind=k or None, top_n=n, tags=tags or None)
        except Exception as exc2:  # noqa: BLE001 - typed, never a silent empty
            fallback_reason = "query_failed"
            results = []
            diagnostics.append(_diagnostic(
                "live_fallback_failed",
                f"The live-filesystem walk itself failed ({exc2}) — infrastructure "
                "failure, NOT an empty corpus.",
                recovery_tools=["index_build"],
                recovery_usage="index_build(content='all', mode='update')",
            ))

    def _fts_fallback(reason: str, exc_msg: str) -> None:
        nonlocal search_mode, fallback_reason, results, coverage
        serve = _fts_degraded_serve(index.root, ("docs",), query, n, kind=(k or None), tags=tags)
        coverage = serve.get("coverage") or {}
        if serve["available"]:
            search_mode = "lexical_fallback"
            fallback_reason = reason
            results = serve["results"]
            diagnostics.append(_diagnostic(
                "semantic_model_unavailable_offline" if reason == "model_unavailable" else reason,
                f"{exc_msg} Serving BM25 results from the published FTS layer "
                "(exact-token recall; semantic recall returns when the cause clears).",
                recovery_tools=["wf_help"],
                recovery_usage="python3 .wavefoundry/framework/scripts/setup_wavefoundry.py --root .",
            ))
        else:
            search_mode = "lexical_fallback"
            fallback_reason = serve["failure_reason"]
            results = []
            diagnostics.append(_diagnostic(
                "lexical_fallback_failed",
                f"{exc_msg} The FTS fallback also failed ({serve['failure_reason']}) — "
                "this is an infrastructure failure, NOT an empty corpus.",
                recovery_tools=["index_health", "index_build"],
                recovery_usage="index_health()",
            ))

    try:
        # Attempt semantic search; handlers below route per the 1seaq
        # epoch-state table (FTS only from a captured complete epoch; the
        # live walk only where no published FTS exists).
        results, reranked = index.search_docs(query, kind=k or None, top_n=n, tags=tags or None)
    except SemanticModelUnavailableOfflineError as exc:
        if _epoch_complete:
            _fts_fallback("model_unavailable", str(exc))
        else:
            _live_walk("store_absent" if epoch_state is None else "index_not_ready", str(exc))
    except IndexNotReadyError as exc:
        if _epoch_complete:
            # Published epoch but the semantic tables cannot serve (e.g. a
            # missing Lance table): the FTS layer is still the published one.
            _fts_fallback("index_missing", str(exc))
        else:
            _live_walk("store_absent" if epoch_state is None else "index_not_ready", str(exc))
    except Exception as exc:  # noqa: BLE001 - AC-3: typed end-to-end, never an escaped raw error
        search_mode = "semantic"
        fallback_reason = "query_failed"
        results = []
        diagnostics.append(_diagnostic(
            "query_failed",
            f"Semantic retrieval failed unexpectedly ({exc}) — infrastructure failure, "
            "NOT an empty corpus.",
            recovery_tools=["index_health"],
            recovery_usage="index_health()",
        ))
    _log_degradation_transition(index.root, "docs_search", fallback_reason)
    if not results:
        if fallback_reason == "query_failed":
            # Infrastructure failure already carries its typed diagnostic —
            # a no_results/token-tweak signal would mislabel it as a miss
            # (release-review fix: never both).
            pass
        elif search_mode == "lexical_fallback" and fallback_reason not in ("store_absent",):
            # Zero hits from a WORKING lexical layer: the token-semantics
            # note applies.
            diagnostics.append(_lexical_zero_hit_note())
        else:
            diagnostics.append(
                _diagnostic(
                    "no_results",
                    f"No document results found for query '{query}'"
                    + (" in live-fallback mode." if search_mode == "live_fallback" else "."),
                    recovery_tools=["wf_help"],
                    recovery_usage="wf_help(goal='search_docs')",
                )
            )
        _mode = "lexical" if search_mode != "semantic" else "semantic"
        _zero_data: dict[str, Any] = {"query": query, "kind": k, "mode": _mode, "search_mode": search_mode,
                                      "fallback_reason": fallback_reason, "reranked": reranked, "results": []}
        if fallback_reason is not None or search_mode in ("lexical_fallback", "live_fallback") or coverage:
            _zero_data["coverage"] = coverage
        return _response(
            "ok",
            _zero_data,
            diagnostics=diagnostics,
            next_tools=["wf_help"],
            usage=f"docs_search(query={query!r})",
        )
    _mode = "lexical" if search_mode != "semantic" else "semantic"
    _results_out = [_search_result("doc", result) for result in results]
    # 1ro43: per-citation freshness (batched, silent absence; skipped on
    # live_fallback inside the helper). The drift partition runs only on the
    # healthy reranked path — degraded/exact envelopes are annotation-only.
    _annotate_freshness(_results_out, index.root, search_mode=search_mode)
    _drift_demoted = 0
    if reranked and search_mode in ("semantic", "hybrid"):
        _drift_demoted = _partition_drift(_results_out)
    _data_out: dict[str, Any] = {
        "query": query,
        "kind": k,
        "mode": _mode,
        "search_mode": search_mode,
        "fallback_reason": fallback_reason,
        "reranked": reranked,
        "results": _results_out,
    }
    if _drift_demoted:
        # Distinct from code_ask's `partition_applied` (doc-type SCORE
        # demotion) — never overload that meaning.
        _data_out["drift_partition_applied"] = True
        _data_out["drift_demoted_count"] = _drift_demoted
    if fallback_reason is not None or search_mode in ("lexical_fallback", "live_fallback") or coverage:
        _data_out["coverage"] = coverage  # required on every degraded/failed envelope ({} = unavailable)
    return _response(
        "ok",
        _data_out,
        diagnostics=diagnostics,
        next_tools=["seed_get", "wf_get_prompt"],
        usage=f"seed_get(name={results[0]['path']!r})" if results[0].get("kind") == "seed" else "",
    )


def code_search_response(index: WaveIndex, query: str, language: str = "", limit: int = 7, kind: Optional[str] = None, max_per_file: Optional[int] = None, tags: Optional[list] = None, epoch_state: Any = "__compute__") -> dict[str, Any]:
    n = max(1, min(int(limit), 20))  # clamp to [1, 20]

    # Resolve language input → either a category (set of langs) or a single canonical name.
    category_langs: Optional[frozenset] = None
    if language:
        if language in _LANG_CATEGORIES:
            # Category match — expand to set of canonical language names.
            category_langs = _LANG_CATEGORIES[language]
        else:
            # Try extension normalization (e.g. "tsx" or ".tsx" → "typescript").
            norm = language.lstrip(".")
            as_ext = f".{norm}"
            if as_ext in _EXT_TO_LANG:
                language = _EXT_TO_LANG[as_ext]

    # Build response metadata fields.
    if category_langs is not None:
        lang_resolved: Optional[list[str]] = sorted(category_langs)
        lang_exts: Optional[list[str]] = sorted({
            ext for lang in category_langs for ext in _LANG_TO_EXTS.get(lang, [])
        })
    else:
        lang_resolved = None
        lang_exts = _LANG_TO_EXTS.get(language) if language else None

    def _data(results: list, reranked: bool = False) -> dict:
        d: dict[str, Any] = {"query": query, "language": language or None, "reranked": reranked, "results": results}
        if lang_resolved is not None:
            d["language_resolved"] = lang_resolved
        d["language_extensions"] = lang_exts
        return d

    reranked = False
    search_mode = "hybrid"
    fallback_reason: "str | None" = None
    coverage: dict[str, Any] = {}
    diagnostics: list[dict[str, Any]] = []
    # 1seaq state discipline: serve decisions on the CAPTURED 1sed7 token.
    if epoch_state == "__compute__":
        epoch_state = _epoch_state(index.root)
    _epoch_complete = epoch_state is not None and epoch_state[1] == "complete"

    _fts_attempted = [False]

    def _fts_fallback(reason: str, exc_msg: str) -> "list | None":
        """FTS fallback (complete epoch only). Returns results or None when
        the fallback itself is unavailable (caller emits the typed error)."""
        nonlocal search_mode, fallback_reason, coverage
        _fts_attempted[0] = True
        lang_set = category_langs if category_langs is not None else (
            frozenset({language}) if language else None
        )
        serve = _fts_degraded_serve(
            index.root, ("code",), query, n,
            kind=kind, tags=tags, language_names=lang_set, max_per_file=max_per_file,
        )
        coverage = serve.get("coverage") or {}
        if not serve["available"]:
            fallback_reason = serve["failure_reason"]
            search_mode = "lexical_fallback"  # attempted-and-failed: the mode names the path that failed (cross-tool consistency)
            return None
        search_mode = "lexical_fallback"
        fallback_reason = reason
        diagnostics.append(_diagnostic(
            "semantic_model_unavailable_offline" if reason == "model_unavailable" else reason,
            f"{exc_msg} Serving BM25 results from the published FTS layer with the "
            "requested filters (exact-token recall; semantic recall returns when the cause clears).",
            recovery_tools=["wf_help"],
            recovery_usage="python3 .wavefoundry/framework/scripts/setup_wavefoundry.py --root . --include-code",
        ))
        return serve["results"]

    def _degraded_error(reason: str, code: str, exc_msg: str) -> dict[str, Any]:
        d = _data([])
        d["search_mode"] = search_mode
        d["fallback_reason"] = reason
        d["coverage"] = coverage  # required on every degraded/failed envelope ({} = unavailable)
        diags = [
            _diagnostic(
                code,
                exc_msg,
                recovery_tools=["wf_help"],
                recovery_usage="python3 .wavefoundry/framework/scripts/setup_wavefoundry.py --root . --include-code",
            )
        ]
        if reason == "query_failed" and _fts_attempted[0]:
            # Review fix (cross-tool parity with docs_search): a failed FTS
            # fallback is infrastructure failure, named as such — but ONLY
            # when the fallback actually ran (a generic semantic failure
            # never touched the FTS layer and must not blame it).
            diags.append(_diagnostic(
                "lexical_fallback_failed",
                "The FTS fallback also failed — this is an infrastructure failure, "
                "NOT an empty corpus.",
                recovery_tools=["index_health", "index_build"],
                recovery_usage="index_health()",
            ))
        return _response(
            "error",
            d,
            diagnostics=diags,
            next_tools=["wf_help"],
            usage="wf_help(goal='search_code')",
        )

    try:
        if category_langs is not None:
            # Fetch unfiltered results then post-filter to the category set.
            raw, reranked = index.search_code(query, language=None, top_n=n * len(category_langs), kind=kind, max_per_file=max_per_file, tags=tags or None)
            results = [r for r in raw if r.get("language") in category_langs][:n]
        else:
            results, reranked = index.search_code(query, language=language or None, top_n=n, kind=kind, max_per_file=max_per_file, tags=tags or None)
    except SemanticModelUnavailableOfflineError as exc:
        results = _fts_fallback("model_unavailable", str(exc)) if _epoch_complete else None
        if results is None:
            _log_degradation_transition(index.root, "code_search", fallback_reason or "index_not_ready")
            return _degraded_error(
                fallback_reason or ("index_not_ready" if epoch_state is not None else "store_absent"),
                "semantic_model_unavailable_offline", str(exc),
            )
    except IndexNotReadyError as exc:
        # A complete epoch with unservable semantic tables (e.g. missing
        # code.lance): the published FTS layer is still the honest source.
        results = _fts_fallback("index_missing", str(exc)) if _epoch_complete else None
        if results is None:
            _log_degradation_transition(index.root, "code_search", fallback_reason or "index_not_ready")
            return _degraded_error(
                fallback_reason or ("index_not_ready" if epoch_state is not None else "store_absent"),
                "index_not_ready", str(exc),
            )
    except Exception as exc:  # noqa: BLE001 - AC-3: typed end-to-end
        fallback_reason = "query_failed"
        _log_degradation_transition(index.root, "code_search", fallback_reason)
        return _degraded_error("query_failed", "query_failed",
                               f"Semantic retrieval failed unexpectedly ({exc}) — infrastructure "
                               "failure, NOT an empty corpus.")
    _log_degradation_transition(index.root, "code_search", fallback_reason)
    if not results:
        if search_mode == "lexical_fallback" and fallback_reason not in ("query_failed", "store_absent"):
            diagnostics.append(_lexical_zero_hit_note())
        else:
            diagnostics.append(
                _diagnostic(
                    "no_results",
                    f"No code results found for query '{query}'.",
                    recovery_tools=["wf_help"],
                    recovery_usage="wf_help(goal='search_code')",
                )
            )
        d = _data([], reranked=reranked)
        d["search_mode"] = search_mode
        d["fallback_reason"] = fallback_reason
        if fallback_reason is not None or search_mode == "lexical_fallback" or coverage:
            d["coverage"] = coverage
        return _response(
            "ok",
            d,
            diagnostics=diagnostics,
            next_tools=["wf_help"],
            usage=f"code_search(query={query!r})",
        )
    _results_out = [_search_result("code", result) for result in results]
    # 1ro43: freshness annotation only — code chunks are ground truth for
    # themselves and are never drift-partitioned.
    _annotate_freshness(_results_out, index.root, search_mode=search_mode)
    d = _data(_results_out, reranked=reranked)
    d["search_mode"] = search_mode
    d["fallback_reason"] = fallback_reason
    if fallback_reason is not None or search_mode == "lexical_fallback" or coverage:
        d["coverage"] = coverage
    return _response(
        "ok",
        d,
        diagnostics=diagnostics,
        next_tools=["wf_help"],
        usage=f"code_search(query={query!r}, language={language!r})" if language else "",
    )


def _seed_chunk_from_disk(path: Path, repo_root: Path) -> dict[str, Any]:
    """Build a get_seed-shaped chunk by reading a seed file directly from disk.

    Used as fallback when the index doesn't have the seed (wave 1p35d / 1p35j).
    """
    try:
        text = path.read_text(encoding="utf-8")
    except OSError:
        text = ""
    rel_path = str(path.relative_to(repo_root)) if path.is_absolute() and repo_root else str(path)
    rel_path = rel_path.replace("\\", "/")
    return {
        "path": rel_path,
        "kind": "seed",
        "section": "preamble",
        "text": text,
        "_source": "disk_fallback",
    }


def seed_get_response(index: WaveIndex, name: str) -> dict[str, Any]:
    try:
        chunk = index.get_seed(name)
    except IndexNotReadyError as exc:
        return _response(
            "error",
            {"name": name},
            diagnostics=[
                _diagnostic(
                    "index_not_ready",
                    str(exc),
                    recovery_tools=["wf_help"],
                    recovery_usage="python3 .wavefoundry/framework/scripts/setup_wavefoundry.py --root .",
                )
            ],
            next_tools=["wf_help"],
            usage="wf_help(goal='search_docs')",
        )
    if chunk is None:
        # Wave 1p35d (1p35j): surface closest-name suggestions when a seed isn't found.
        suggestions = index.closest_seed_names(name)
        suggestion_msg = (
            f" Did you mean: {', '.join(suggestions)}?" if suggestions else ""
        )
        return _response(
            "ok",
            {"name": name, "seed": None, "suggestions": suggestions},
            diagnostics=[
                _diagnostic(
                    "seed_not_found",
                    f"No seed found matching '{name}'.{suggestion_msg}",
                    recovery_tools=["docs_search"],
                    recovery_usage=f"docs_search(query={name!r}, kind='seed')",
                )
            ],
            next_tools=["docs_search"],
            usage=f"docs_search(query={name!r}, kind='seed')",
        )
    return _response(
        "ok",
        {
            "name": name,
            "seed": {
                "result_id": _result_id("seed", chunk),
                "path": chunk["path"],
                "trust_label": TRUSTED_FRAMEWORK,
                "content": chunk["text"],
            },
        },
        next_tools=["wf_help"],
        usage=f"docs_search(query={name!r}, kind='seed')",
    )


def _detect_wave_status_drift(root: Path, wave: dict) -> list[dict[str, Any]]:
    """Compare wave.md change statuses against actual change doc files.

    Returns a list of drift entries: ``{"change_id": ..., "wave_md_status": ..., "file_status": ...}``
    for any change whose status differs between wave.md and its change doc file.
    """
    drifts: list[dict[str, Any]] = []
    wave_md_path = Path(wave["path"])
    wave_dir = wave_md_path.parent
    for change in wave.get("changes", []):
        cid = change["id"]
        wave_md_status = change["status"]
        # Search for the change doc in the wave folder
        for p in sorted(wave_dir.rglob("*.md")):
            if p.name == "wave.md":
                continue
            if cid.lower() in p.stem.lower():
                try:
                    text = p.read_text(encoding="utf-8")
                except OSError:
                    continue
                m = _CHANGE_STATUS_PATTERN.search(text)
                if m:
                    file_status = m.group(1)
                    if file_status.strip().lower() != wave_md_status.strip().lower():
                        drifts.append({
                            "change_id": cid,
                            "wave_md_status": wave_md_status,
                            "file_status": file_status,
                        })
                break
    return drifts


_WAVE_CURRENT_NEXT_ACTION = {
    "active": "implement_wave",
    "implementing": "close_wave",
    "planned": "prepare_wave",
    "paused": "resume_wave",
}


def _wf_current_wave_sort_key(wave: dict) -> tuple[int, str]:
    """Sort key: active/implementing (0), planned (1), paused (2), other (3); then by wave_id."""
    priority = {"active": 0, "implementing": 0, "planned": 1, "paused": 2}
    return (priority.get(wave["status"], 3), wave.get("wave_id", ""))


def wf_current_wave_response(root: Path, cache: Optional[McpRepoCache] = None) -> dict[str, Any]:
    all_waves = cache.list_waves_cached() if cache else list_waves(root)
    open_waves = [w for w in all_waves if w["status"] != "closed"]
    open_waves.sort(key=_wf_current_wave_sort_key)
    entries = [
        {**w, "next_action": _WAVE_CURRENT_NEXT_ACTION.get(w["status"], "prepare_wave")}
        for w in open_waves
    ]
    if not entries:
        return _response(
            "ok",
            {"waves": []},
            diagnostics=[
                _diagnostic(
                    "no_active_wave",
                    "No active, planned, or paused wave found.",
                    recovery_tools=["wf_list_waves"],
                    recovery_usage="wf_list_waves()",
                )
            ],
            next_tools=["wf_list_waves", "wf_list_plans"],
            usage="wf_list_waves()",
        )
    # Drift detection only runs against the active wave (if present) — that's the only
    # wave where in-flight Change Status drift is meaningful.
    diagnostics: list[dict[str, Any]] = []
    active_entry = entries[0] if entries[0]["status"] in ("active", "implementing") else None
    if active_entry is not None:
        try:
            drifts = _detect_wave_status_drift(root, active_entry)
            if drifts:
                drift_summary = "; ".join(f"{d['change_id']}: wave.md={d['wave_md_status']!r} vs file={d['file_status']!r}" for d in drifts)
                diagnostics.append(
                    _diagnostic(
                        "change_status_drift",
                        f"Change status drift detected — wave.md and change doc files disagree for: {drift_summary}. Update wave.md Change Status fields to match the actual change docs.",
                        recovery_tools=["wf_get_change", "wf_validate_docs"],
                        recovery_usage=f"wf_get_change(change_id={drifts[0]['change_id']!r})",
                    )
                )
        except Exception:
            pass  # Drift detection is advisory; never let it block the response
    first_entry = entries[0]
    usage = f"wf_get_change(change_id={first_entry['changes'][0]['id']!r})" if first_entry.get("changes") else ""
    data: dict[str, Any] = {"waves": entries}
    # 1svuk: a SEPARATE, labeled estimate for the active wave — never summed into
    # the measured Context Efficiency total, always carrying its causal caveat.
    if active_entry is not None:
        try:
            ea = _load_script("exploration_avoided")
            wid = str(active_entry.get("wave_id") or active_entry.get("id") or "")
            est = ea.read_wave(root, wid) if wid else None
            if est and est.get("estimated_exploration_avoided", 0) > 0:
                data["estimated_exploration_avoided"] = {
                    "wave_id": wid,
                    "tokens": est["estimated_exploration_avoided"],
                    "surfaced_events": est["surfaced_events"],
                    "cited_events": est["cited_events"],
                    "measured": False,
                    "caveat": ea.CAVEAT,
                }
        except Exception:
            pass
    return _response(
        "ok",
        data,
        diagnostics=diagnostics,
        next_tools=["wf_get_change"],
        usage=usage,
    )


def wf_list_waves_response(root: Path, limit: int = 50, cache: Optional[McpRepoCache] = None) -> dict[str, Any]:
    n = max(1, min(int(limit), 200))  # clamp to [1, 200]
    all_waves = cache.list_waves_cached() if cache else list_waves(root)
    has_more = len(all_waves) > n
    waves = all_waves[:n]
    return _response(
        "ok",
        {"waves": waves, "total": len(all_waves), "has_more": has_more},
        diagnostics=[] if waves else [_diagnostic("no_waves", "No waves found.")],
        next_tools=["wf_current_wave"] if waves else ["wf_list_plans"],
        usage="wf_current_wave()" if waves else "wf_list_plans()",
    )


def wf_list_plans_response(root: Path, limit: int = 50, cache: Optional[McpRepoCache] = None) -> dict[str, Any]:
    n = max(1, min(int(limit), 200))  # clamp to [1, 200]
    all_plans = cache.list_plans_cached() if cache else list_plans(root)
    has_more = len(all_plans) > n
    plans = all_plans[:n]
    return _response(
        "ok",
        {"plans": plans, "total": len(all_plans), "has_more": has_more},
        diagnostics=[] if plans else [_diagnostic("no_plans", "No plan docs found.")],
        next_tools=["wf_new_feature", "wf_current_wave"] if plans else ["wf_help"],
        usage="wf_help(goal='plan_feature')",
    )


def wf_get_change_response(root: Path, change_id: str = "", wave_id: str = "") -> dict[str, Any]:
    """Look up a single change doc by ID, or return all changes for a wave.

    When ``wave_id`` is provided and ``change_id`` is omitted (or empty), returns all
    admitted change docs for that wave in ``data.changes``, each with ``id``, ``status``,
    ``path``, and ``content``.  Content per change is capped at 300 lines to avoid
    overly large responses for waves with many large change docs.
    """
    wave_id_s = (wave_id or "").strip()
    change_id_s = (change_id or "").strip()

    # Bulk mode: wave_id provided, no specific change_id
    if wave_id_s and not change_id_s:
        wave_matches = _resolve_wave_md_matches(root, wave_id_s)
        if not wave_matches:
            return _response(
                "ok",
                {"wave_id": wave_id_s, "changes": []},
                diagnostics=[_diagnostic("wave_not_found", f"No wave found matching '{wave_id_s}'.", recovery_tools=["wf_list_waves"], recovery_usage="wf_list_waves()")],
                next_tools=["wf_list_waves"],
                usage="wf_list_waves()",
            )
        if len(wave_matches) > 1:
            candidates = ", ".join(f"{m['wave_id']} ({m['path']})" for m in wave_matches)
            return _response(
                "ok",
                {"wave_id": wave_id_s, "wave": None, "waves": wave_matches, "changes": []},
                diagnostics=[
                    _diagnostic(
                        "ambiguous_wave_id",
                        f"Multiple waves match '{wave_id_s}': {candidates}. Use a more specific wave ID.",
                        recovery_tools=["wf_list_waves"],
                        recovery_usage="wf_list_waves()",
                    )
                ],
                next_tools=["wf_list_waves"],
                usage="wf_list_waves()",
            )
        wave_md = root / str(wave_matches[0]["path"])
        wave_text = wave_md.read_text(encoding="utf-8")
        admitted_ids = _extract_change_ids_from_wave_text(wave_text)
        changes: list[dict[str, Any]] = []
        wave_dir = wave_md.parent
        _MAX_CONTENT_LINES = 300
        for cid in admitted_ids:
            # Prefer wave folder; fall back to docs/plans
            doc_path: Optional[Path] = None
            for p in sorted(wave_dir.rglob("*.md")):
                if p.name != "wave.md" and cid.lower() in p.stem.lower():
                    doc_path = p
                    break
            if doc_path is None:
                doc_path_candidate = root / "docs" / "plans" / f"{cid}.md"
                if doc_path_candidate.exists():
                    doc_path = doc_path_candidate
            if doc_path is not None and doc_path.exists():
                try:
                    content_lines = doc_path.read_text(encoding="utf-8").splitlines()
                except OSError:
                    content_lines = []
                truncated = len(content_lines) > _MAX_CONTENT_LINES
                content = "\n".join(content_lines[:_MAX_CONTENT_LINES])
                if truncated:
                    content += f"\n\n[... truncated at {_MAX_CONTENT_LINES} lines. Use code_read(path=...) for the full file.]"
                # Extract change status from doc
                doc_status_m = _CHANGE_STATUS_PATTERN.search(content)
                doc_status = doc_status_m.group(1) if doc_status_m else "unknown"
                changes.append({
                    "id": cid,
                    "status": doc_status,
                    "path": _repo_rel(root, doc_path),
                    "content": content,
                    "truncated": truncated,
                })
            else:
                changes.append({"id": cid, "status": "unknown", "path": None, "content": None})
        return _response(
            "ok",
            {"wave_id": wave_id_s, "count": len(changes), "changes": changes},
            next_tools=["wf_validate_docs", "wf_current_wave"],
            usage="wf_validate_docs()",
        )

    # Single lookup mode.
    matches = _resolve_change_doc_matches(root, change_id_s)
    if not matches:
        return _response(
            "ok",
            {"change_id": change_id_s, "change": None, "changes": []},
            diagnostics=[
                _diagnostic(
                    "change_not_found",
                    f"No change doc found matching '{change_id_s}'.",
                    recovery_tools=["wf_list_plans", "wf_current_wave"],
                    recovery_usage="wf_list_plans()",
                )
            ],
            next_tools=["wf_list_plans", "wf_current_wave"],
            usage="wf_list_plans()",
        )
    if len(matches) > 1:
        candidates = ", ".join(f"{m['change_id']} ({m['path']})" for m in matches)
        return _response(
            "ok",
            {"change_id": change_id_s, "change": None, "changes": matches},
            diagnostics=[
                _diagnostic(
                    "ambiguous_change_id",
                    f"Multiple change docs match '{change_id_s}': {candidates}. Use a more specific change ID.",
                    recovery_tools=["wf_list_plans", "wf_current_wave"],
                    recovery_usage="wf_list_plans()",
                )
            ],
            next_tools=["wf_list_plans", "wf_current_wave"],
            usage="wf_list_plans()",
        )
    match = matches[0]
    return _response(
        "ok",
        {
            "change_id": change_id_s,
            "changes": [],
            "change": {
                "content": match["content"],
                "path": match["path"],
                "change_id": match["change_id"],
                "trust_label": TRUSTED_PROJECT_METADATA,
            },
        },
        next_tools=["wf_validate_docs"],
        usage="wf_validate_docs()",
    )


def wf_get_prompt_response(root: Path, shortcut: str, cache: Optional[McpRepoCache] = None) -> dict[str, Any]:
    text = cache.get_prompt_text_cached(shortcut) if cache else get_prompt(root, shortcut)
    if text is None:
        return _response(
            "ok",
            {"shortcut": shortcut, "prompt": None},
            diagnostics=[
                _diagnostic(
                    "prompt_not_found",
                    f"No prompt found matching '{shortcut}'.",
                    recovery_tools=["docs_search"],
                    recovery_usage=f"docs_search(query={shortcut!r}, kind='prompt')",
                )
            ],
            next_tools=["docs_search"],
            usage=f"docs_search(query={shortcut!r}, kind='prompt')",
        )
    return _response(
        "ok",
        {
            "shortcut": shortcut,
            "prompt": {
                "content": text,
                "trust_label": UNTRUSTED_PROJECT_CONTENT,
            },
        },
        next_tools=["wf_validate_docs"],
        usage="wf_validate_docs()",
    )


def _parse_wave_address(address: str) -> Optional[dict[str, Any]]:
    """Parse ``doc:``, ``code:``, or ``seed:`` anchor strings from search tools and the spec."""
    s = (address or "").strip()
    if not s:
        return None
    m = re.match(r"^(doc|code|seed):(.+)$", s, flags=re.DOTALL)
    if not m:
        return None
    scheme, rest = m.group(1), m.group(2)
    rest = rest.strip().replace("\\", "/")
    if scheme == "code":
        m2 = re.match(r"^(.+):L(\d+)-L(\d+)$", rest)
        if m2:
            return {
                "scheme": "code",
                "path": m2.group(1).strip().replace("\\", "/"),
                "section": None,
                "line_start": int(m2.group(2)),
                "line_end": int(m2.group(3)),
            }
        return {
            "scheme": "code",
            "path": rest,
            "section": None,
            "line_start": None,
            "line_end": None,
        }
    if "#" in rest:
        path_part, sec = rest.split("#", 1)
        return {
            "scheme": scheme,
            "path": path_part.strip().replace("\\", "/"),
            "section": sec.strip(),
            "line_start": None,
            "line_end": None,
        }
    return {
        "scheme": scheme,
        "path": rest,
        "section": None,
        "line_start": None,
        "line_end": None,
    }


def _read_map_excerpt(
    path: Path,
    line_start: Optional[int],
    line_end: Optional[int],
    max_chars: int = 1600,
) -> str:
    if not path.is_file():
        return ""
    try:
        text = path.read_text(encoding="utf-8", errors="replace")
    except OSError:
        return ""
    if line_start is not None and line_end is not None:
        lines = text.splitlines()
        s_idx = max(1, line_start) - 1
        e_idx = min(len(lines), line_end)
        chunk = "\n".join(lines[s_idx:e_idx])
        return chunk[:max_chars]
    return text[:max_chars]


def _index_chunk_matching_address(index: WaveIndex, address: str, parsed: dict[str, Any]) -> Optional[dict[str, Any]]:
    try:
        index._ensure_loaded()
    except (IndexNotReadyError, OSError, ValueError, Exception):
        return None
    scheme = parsed["scheme"]
    want = address.strip()
    path = (parsed.get("path") or "").replace("\\", "/").replace("'", "''")
    # Determine which Lance table(s) to scan and which prefix(es) to match.
    if scheme == "code":
        table_prefixes = [(getattr(index, "_code_lance_table", None), "code")]
    elif scheme == "seed":
        table_prefixes = [
            (getattr(index, "_docs_lance_table", None), "seed"),
            (getattr(index, "_docs_lance_table", None), "doc"),
        ]
    else:
        table_prefixes = [(getattr(index, "_docs_lance_table", None), "doc")]
    seen_tables: set[int] = set()
    for table, prefix in table_prefixes:
        if table is None:
            continue
        table_id = id(table)
        if table_id in seen_tables:
            continue
        seen_tables.add(table_id)
        try:
            where = f"path = '{path}'" if path else None
            q = table.search()
            if where:
                q = q.where(where, prefilter=True)
            rows = q.to_list()
        except Exception:
            rows = []
        for row in rows:
            ch = {k: v for k, v in row.items() if k != "vector"}
            if _result_id(prefix, ch) == want:
                return ch
    return None


def wf_map_response(root: Path, address: str, index: WaveIndex) -> dict[str, Any]:
    """Resolve a stable anchor string to paths, trust metadata, and optional excerpts."""
    addr = (address or "").strip()
    if not addr:
        return _response(
            "error",
            {"address": address},
            diagnostics=[
                _diagnostic(
                    "invalid_address",
                    "wf_map requires a non-empty anchor (e.g. doc:docs/README.md#intro).",
                    recovery_tools=["docs_search", "wf_help"],
                    recovery_usage="docs_search(query='topic')",
                )
            ],
            next_tools=["docs_search", "wf_help"],
            usage="wf_map(address='doc:docs/README.md')",
        )
    parsed = _parse_wave_address(addr)
    if parsed is None:
        return _response(
            "error",
            {"address": addr},
            diagnostics=[
                _diagnostic(
                    "invalid_address",
                    "Anchor must start with doc:, code:, or seed: and use repo-relative paths.",
                    recovery_tools=["wf_help"],
                    recovery_usage="wf_help(goal='search_docs')",
                )
            ],
            next_tools=["wf_help"],
            usage="wf_map(address='doc:docs/plans/1234-feat x.md')",
        )
    resolved, err = resolve_path_under_root(root, parsed["path"])
    if err is not None:
        return _response(
            "error",
            {"address": addr, "parsed": parsed},
            diagnostics=[err],
            next_tools=["wf_validate_docs", "wf_current_wave"],
            usage="wf_validate_docs()",
        )
    assert resolved is not None
    root_r = root.resolve()
    rel = str(resolved.relative_to(root_r)).replace("\\", "/")
    chunk = _index_chunk_matching_address(index, addr, parsed)
    kind_for_trust = "seed" if parsed["scheme"] == "seed" else (str(chunk.get("kind") or "") if chunk else "")
    trust = _trust_label(rel, kind=kind_for_trust)
    excerpt = ""
    if chunk:
        excerpt = str(chunk.get("text") or "")[:1600]
    if not excerpt:
        excerpt = _read_map_excerpt(resolved, parsed.get("line_start"), parsed.get("line_end"))
    data: dict[str, Any] = {
        "address": addr,
        "scheme": parsed["scheme"],
        "path": rel,
        "section": parsed.get("section"),
        "line_start": parsed.get("line_start"),
        "line_end": parsed.get("line_end"),
        "file_exists": resolved.is_file(),
        "trust_label": trust,
        "index_match": chunk is not None,
        "excerpt": excerpt,
    }
    next_tools = ["wf_validate_docs", "docs_search"]
    if parsed["scheme"] in ("doc", "seed") and chunk and chunk.get("kind") == "seed":
        next_tools = ["seed_get", "wf_validate_docs"]
    return _response(
        "ok",
        data,
        next_tools=next_tools,
        usage="wf_validate_docs()",
    )


def _token_matches_id(candidate: str, query: str) -> bool:
    token = (query or "").strip().lower()
    if not token:
        return False
    return (candidate or "").strip().lower().startswith(token)


def _change_doc_matches_token(path: Path, canonical_change_id: str, token: str) -> bool:
    stem = path.stem
    return _token_matches_id(canonical_change_id, token) or _token_matches_id(stem, token)


def _wave_match_payload(root: Path, wave_md: Path) -> dict[str, Any]:
    try:
        parsed = _parse_wave_record(wave_md)
        text = wave_md.read_text(encoding="utf-8")
    except OSError:
        parsed = {}
        text = ""
    wave_id = str(parsed.get("wave_id") or wave_md.parent.name)
    return {
        "wave_id": wave_id,
        "path": str(wave_md.relative_to(root.resolve())).replace("\\", "/"),
        "changes": _extract_change_ids_from_wave_text(text),
    }


def _resolve_wave_md_matches(root: Path, wave_id_or_prefix: str) -> list[dict[str, Any]]:
    token = (wave_id_or_prefix or "").strip().lower()
    if not token:
        return []
    waves_root = root / "docs" / "waves"
    if not waves_root.exists():
        return []
    matches: list[dict[str, Any]] = []
    for wave_md in waves_root.glob("*/wave.md"):
        try:
            wave_md, _ = _contained_wave_review_paths(root, wave_md)
        except ValueError as exc:
            if _token_matches_id(wave_md.parent.name, token):
                raise ValueError(f"Wave record path is not contained: {exc}") from exc
            continue
        try:
            parsed = _parse_wave_record(wave_md)
            wave_id = str(parsed.get("wave_id") or wave_md.parent.name).lower()
        except OSError:
            continue
        if _token_matches_id(wave_id, token) or _token_matches_id(wave_md.parent.name, token):
            matches.append(_wave_match_payload(root, wave_md))
    return sorted(matches, key=lambda m: str(m.get("path") or ""))


def _find_wave_md(root: Path, wave_id_or_prefix: str) -> Optional[Path]:
    matches = _resolve_wave_md_matches(root, wave_id_or_prefix)
    if not matches:
        return None
    if len(matches) > 1:
        candidates = ", ".join(f"{m['wave_id']} ({m['path']})" for m in matches)
        raise ValueError(f"Multiple wave records match {wave_id_or_prefix!r}: {candidates}")
    return root / str(matches[0]["path"])


def _extract_change_ids_from_wave_text(text: str) -> list[str]:
    return _CHANGE_ID_PATTERN.findall(text)


def _resolve_change_doc_matches(root: Path, change_id_prefix: str) -> list[dict[str, Any]]:
    token = (change_id_prefix or "").strip().lower()
    if not token:
        return []
    matches: list[dict[str, Any]] = []
    search_dirs = [root / "docs" / "plans", root / "docs" / "waves"]
    for base in search_dirs:
        if not base.exists():
            continue
        for p in base.rglob("*.md"):
            if p.name == "wave.md":
                continue
            try:
                text = p.read_text(encoding="utf-8")
            except OSError:
                continue
            change_match = _CHANGE_ID_PATTERN.search(text)
            canonical_change_id = change_match.group(1) if change_match else p.stem
            if not _change_doc_matches_token(p, canonical_change_id, token):
                continue
            matches.append(
                {
                    "path": str(p.relative_to(root)).replace("\\", "/"),
                    "change_id": canonical_change_id,
                    "content": text,
                }
            )
    return sorted(matches, key=lambda m: str(m.get("path") or ""))


_REVIEW_EVIDENCE_MARKERS = ("## Review Evidence", "## Review Signoff Evidence")
_PREPARE_REVIEW_EVIDENCE_MARKER = "## Prepare Review Evidence"
_SIGNOFF_TOKENS = ("sign-off", "signoff", "approved", "passed", "acceptance", "complete")


def _combined_review_evidence(wave_text: str) -> str:
    """Return raw text (preserves case) of all Review Evidence / Signoff sections."""
    parts: list[str] = []
    for marker in _REVIEW_EVIDENCE_MARKERS:
        idx = wave_text.find(marker)
        if idx == -1:
            continue
        start = idx + len(marker)
        nl = wave_text.find("\n", start)
        if nl != -1:
            start = nl + 1
        tail = wave_text[start:]
        m_end = re.search(r"\n(?=## )", tail)
        body = tail[: m_end.start()] if m_end else tail
        parts.append(body)
    return "\n".join(parts)


def _prepare_review_evidence(wave_text: str) -> str:
    """Return raw text of the ## Prepare Review Evidence section (prepare-phase signoffs)."""
    marker = _PREPARE_REVIEW_EVIDENCE_MARKER
    idx = wave_text.find(marker)
    if idx == -1:
        return ""
    start = idx + len(marker)
    nl = wave_text.find("\n", start)
    if nl != -1:
        start = nl + 1
    tail = wave_text[start:]
    m_end = re.search(r"\n(?=## )", tail)
    return tail[: m_end.start()] if m_end else tail


_SIGNOFF_POSITIVE_STATES = ("approved", "passed", "complete")


def _normalize_signoff_line(raw: str) -> str:
    line = raw.strip()
    line = line.lstrip("-*+ ")
    for emphasis in ("**", "__", "`"):
        line = line.replace(emphasis, "")
    return line.strip()


def _signoff_key_matches_lane(key: str, lane_l: str) -> bool:
    """Exact-key matching (release-review round 4 P0): the normalized key must
    BE the lane, or the lane's ``-signoff`` form. Never a prefix match —
    ``qa`` must not match ``qa-reviewer``; ``operator-signoff`` must not
    match ``operator-signoff-notes``."""
    return key == lane_l or key == f"{lane_l}-signoff" or f"{key}-signoff" == lane_l


def _lane_has_signoff_in_evidence(evidence_text: str, lane: str, *, authorization: "bool | None" = None) -> bool:
    """True when the lane's signoff is recorded, current, and explicitly positive.

    Release-review round 4 P0 — FAIL-CLOSED structured parsing:

    - A STATE LINE is one whose text (markdown bullets/emphasis stripped)
      begins with the lane's exact key before the first ``:`` (the lane
      itself or its ``-signoff`` form; never a prefix collision).
    - Parenthesized historical keys (``lane(superseded):``) are bookkeeping
      and never contribute — neither to state nor to prose evidence.
    - Among state lines, ONLY THE LAST governs. Its value must BEGIN with an
      explicit canonical positive state (``approved``/``passed``/``complete``).
      Everything else — ``not approved``, ``pending``, ``blocked``,
      ``rejected``, ``denied``, ``failed``, ``withdrawn``, ``revoked``,
      ``rescinded``, placeholders, unknown wording — is unapproved, and a
      positive word appearing ELSEWHERE in the value never authorizes
      ("blocked because previous checks passed" is blocked).
    - AUTHORIZATION lanes (operator and wave-council signoffs — auto-detected
      unless ``authorization`` is passed explicitly) require a state line:
      prose evidence never authorizes lifecycle closure. Reviewer-seat lanes
      keep prose-line compatibility for their per-seat evidence.
    """
    lane_l = lane.strip().lower()
    if not lane_l or not evidence_text.strip():
        return False
    if authorization is None:
        authorization = (
            lane_l in ("operator", "operator-signoff")
            or lane_l.startswith("wave-council")
        )
    # The bounded current-state projection is authoritative for keys it
    # contains.  It deliberately appears before prose/history parsing so an
    # older approval line cannot override a current withheld/pending row.
    for raw in evidence_text.splitlines():
        stripped = raw.strip()
        if not (stripped.startswith("|") and stripped.endswith("|")):
            continue
        cells = [cell.strip().lower() for cell in stripped.strip("|").split("|")]
        if len(cells) >= 2 and cells[0] == lane_l:
            return cells[1] == "approved"
    state_values: list[str] = []
    any_prose_signoff = False
    for raw in evidence_text.splitlines():
        low = raw.strip().lower()
        if not low or low.startswith("#"):
            continue
        norm = _normalize_signoff_line(low)
        key, sep, value = norm.partition(":")
        if sep:
            key_clean = key.strip()
            # Historical parenthesized variant — the parenthesis abuts the
            # lane key directly ("lane(superseded):"). A SPACED parenthesis
            # ("red-team (delivery):") is a seat descriptor, not bookkeeping.
            paren = key_clean.find("(")
            if paren > 0 and key_clean[paren - 1] != " " and _signoff_key_matches_lane(
                key_clean[:paren].strip(), lane_l
            ):
                continue  # historical variant: never counts
            if _signoff_key_matches_lane(key_clean, lane_l):
                state_values.append(value.strip())
                continue
        # Prose evidence (reviewer seats only): the lane must appear as a
        # WHOLE word — "qa" never matches inside "qa-reviewer" — and
        # placeholders never count.
        if ("<" not in low
                and re.search(rf"(?<![a-z0-9-]){re.escape(lane_l)}(?![a-z0-9-])", low)
                and any(tok in low for tok in _SIGNOFF_TOKENS)):
            any_prose_signoff = True
    if state_values:
        current = state_values[-1]
        if not current or current.startswith("<"):
            return False
        first_word = re.match(r"[a-z][a-z-]*", current)
        return bool(first_word and first_word.group(0) in _SIGNOFF_POSITIVE_STATES)
    if authorization:
        return False  # fail closed: no state line = not authorized
    return any_prose_signoff


def _lanes_missing_signoff(wave_text: str) -> list[str]:
    """Required review roles from Participants that lack a per-line signoff in Review Evidence."""
    evidence = _combined_review_evidence(wave_text)
    missing: list[str] = []
    for lane in _extract_required_review_lanes(wave_text):
        if not _lane_has_signoff_in_evidence(evidence, lane):
            missing.append(lane)
    return missing


def _review_evidence_has_any_signoff_line(wave_text: str) -> bool:
    """When there are no participant review lanes, still require some recorded signoff in evidence."""
    evidence = _combined_review_evidence(wave_text)
    if not evidence.strip():
        return False
    el = evidence.lower()
    for raw in el.splitlines():
        line = raw.strip()
        if not line or line.startswith("#"):
            continue
        if "<" in line:
            continue
        if any(tok in line for tok in _SIGNOFF_TOKENS):
            return True
    return False


def _update_handoff_wave_ref(existing: str, wave_id: Optional[str]) -> str:
    """Surgically update the Active wave reference and Last verified in session-handoff.md.

    Only the ``**Active wave:**`` line and the ``Last verified:`` metadata field are
    updated.  All other content is preserved unchanged.  If the file is empty or the
    ``**Active wave:**`` pattern is absent, a minimal valid scaffold is written instead.

    Args:
        existing: Current file content (empty string when the file does not exist).
        wave_id: Wave ID to mark as active, or None to clear (renders as ``*(none)*``).
    """
    active_ref = f"`{wave_id}`" if wave_id else "*(none)*"
    today = datetime.date.today().isoformat()

    if not existing.strip():
        status = "active" if wave_id else "idle"
        return (
            "# Session Handoff\n\n"
            "Owner: wave-coordinator\n"
            f"Status: {status}\n"
            f"Last verified: {today}\n\n"
            "## Current Session\n\n"
            f"**Active wave:** {active_ref}\n"
        )

    lines = existing.splitlines(keepends=True)
    found_active = False
    out: list[str] = []
    for line in lines:
        stripped = line.strip()
        if stripped.startswith("**Active wave:**"):
            out.append(f"**Active wave:** {active_ref}\n")
            found_active = True
        elif stripped.startswith("Last verified:"):
            out.append(f"Last verified: {today}\n")
        else:
            out.append(line)

    if not found_active:
        # Active wave line absent — insert it under ## Current Session if that section
        # exists, preserving all other content.  Only fall back to a minimal scaffold
        # if the file has no Current Session section at all.
        result = "".join(out)
        if "## Current Session" in result:
            result = re.sub(
                r"(## Current Session\s*\n+)",
                rf"\1**Active wave:** {active_ref}\n",
                result,
                count=1,
            )
            return result
        # No Current Session section — append one.
        if not result.endswith("\n"):
            result += "\n"
        result += f"\n## Current Session\n\n**Active wave:** {active_ref}\n"
        return result

    return "".join(out)


def _resolve_unique_change_doc(root: Path, change_id: str) -> tuple[Optional[dict[str, Any]], Optional[dict[str, Any]]]:
    matches = _resolve_change_doc_matches(root, change_id)
    if not matches:
        return None, _diagnostic("change_not_found", f"No change doc found matching '{change_id}'.", recovery_tools=["wf_list_plans"], recovery_usage="wf_list_plans()")
    if len(matches) > 1:
        candidates = ", ".join(f"{m['change_id']} ({m['path']})" for m in matches)
        return None, _diagnostic("ambiguous_change_id", f"Multiple change docs match '{change_id}': {candidates}. Use a more specific ID.", recovery_tools=["wf_list_plans"], recovery_usage="wf_list_plans()")
    return matches[0], None


def _wave_change_doc_path(root: Path, wave_md: Path, change_id: str) -> Path:
    return wave_md.parent / f"{change_id}.md"


def _plan_change_doc_path(root: Path, change_id: str) -> Path:
    return root / "docs" / "plans" / f"{change_id}.md"


def _repo_rel(root: Path, path: Path) -> str:
    try:
        relative = path.relative_to(root)
    except ValueError:
        relative = path.resolve(strict=False).relative_to(root.resolve())
    return str(relative).replace("\\", "/")


def _background_refresh_state_path(root: Path, layer: str = "project") -> Path:
    return root / ".wavefoundry" / "index" / "background-refresh.json"


def _indexable_refresh_path(rel_path: str) -> bool:
    normalized = rel_path.replace("\\", "/")
    if not normalized:
        return False
    if normalized.startswith(".wavefoundry/index/") or normalized.startswith(".wavefoundry/framework/index/"):
        return False
    skip_suffixes = {
        ".pyc", ".npy", ".png", ".jpg", ".jpeg", ".gif", ".svg",
        ".ico", ".woff", ".woff2", ".ttf", ".eot", ".zip",
    }
    return Path(normalized).suffix.lower() not in skip_suffixes


def _pid_is_running(pid: int) -> bool:
    if pid <= 0:
        return False
    # Wave 1p6d6: os.kill(pid, 0) is unreliable on native Windows; use tasklist there (mirrors
    # the already-guarded copies in indexer.py / upgrade_lib.py). This was the ONLY unguarded
    # liveness check, and it is called from 12+ sites incl. the dashboard 1p654 reconciliation —
    # the bare os.kill misjudged live/dead PIDs on Windows. POSIX branch is unchanged.
    if os.name == "nt":
        import subprocess  # local import — server_impl imports subprocess per-function (convention)
        try:
            # MCP-reachable (12+ liveness call sites incl. dashboard/index status): isolate stdin from
            # the JSON-RPC stream and suppress the console window on Windows (wave 1p88t).
            result = subprocess.run(
                ["tasklist", "/FI", f"PID eq {pid}", "/NH", "/FO", "CSV"],
                capture_output=True, text=True, check=False,
                encoding="utf-8", errors="replace",  # 1p8gv (review F2): deterministic capture decoding
                stdin=subprocess.DEVNULL, creationflags=_windows_no_window_flag(),
            )
            return str(pid) in result.stdout
        except OSError:
            return False
    try:
        os.kill(pid, 0)
    except OSError:
        return False
    return True


def _load_background_refresh_state(state_path: Path) -> dict[str, Any]:
    if not state_path.exists():
        return {}
    try:
        loaded = json.loads(state_path.read_text(encoding="utf-8"))
    except (OSError, json.JSONDecodeError):
        return {}
    return loaded if isinstance(loaded, dict) else {}


def _lock_is_fresh(lock_path: Path) -> bool:
    """Return True if ``lock_path`` exists and its mtime is within the stale threshold."""
    import time as _time

    if not lock_path.exists():
        return False
    try:
        age = _time.time() - lock_path.stat().st_mtime
    except OSError:
        return False
    return age < BACKGROUND_INDEX_LOCK_STALE_SECONDS


def _table_lock_paths(index_dir: Path) -> list[Path]:
    """Return the per-table ``.lock`` file paths for the given index directory."""
    return [index_dir / f"{kind}.lance" / ".lock" for kind in ("docs", "code")]


def _cleanup_stale_table_locks(index_dir: Path, *, remove_stale_running_pid: bool = False) -> list[dict[str, Any]]:
    """Remove dead Lance table lock markers and return cleanup details."""
    import time as _time

    cleaned: list[dict[str, Any]] = []
    for lock_path in _table_lock_paths(index_dir):
        if not lock_path.exists():
            continue
        pid: Optional[int] = None
        try:
            raw_pid = lock_path.read_text(encoding="utf-8").strip()
            pid = int(raw_pid) if raw_pid else None
        except (OSError, ValueError):
            pid = None
        try:
            age = _time.time() - lock_path.stat().st_mtime
        except OSError:
            continue
        pid_dead = pid is None or not _pid_is_running(pid)
        lock_stale = age >= BACKGROUND_INDEX_LOCK_STALE_SECONDS
        if not pid_dead and not (remove_stale_running_pid and lock_stale):
            continue
        try:
            lock_path.unlink()
            removed = True
        except OSError:
            removed = False
        cleaned.append({
            "path": str(lock_path),
            "pid": pid,
            "age_seconds": int(age),
            "reason": "stale" if lock_stale and remove_stale_running_pid else "pid_dead",
            "removed": removed,
        })
    return cleaned


def _background_refresh_active(state_path: Path) -> bool:
    # Primary guard: if any per-table .lock file exists and is fresh, a build is actively
    # running — regardless of what the state file says.
    index_dir = state_path.parent
    _cleanup_stale_table_locks(index_dir, remove_stale_running_pid=True)
    if any(_lock_is_fresh(p) for p in _table_lock_paths(index_dir)):
        return True

    state = _load_background_refresh_state(state_path)
    pid = state.get("pid")
    started_at = state.get("started_at")
    if isinstance(pid, int) and _pid_is_running(pid):
        return True
    # Short throttle covers the brief window between Popen() and the indexer acquiring
    # its build lock (~1-2 seconds on a cold start).
    if isinstance(started_at, (int, float)):
        import time
        if (time.time() - float(started_at)) < BACKGROUND_INDEX_REFRESH_THROTTLE_SECONDS:
            return True
    return False


# Wave 1p98u: the long-lived MCP server spawns detached background index builds (below) with
# start_new_session=True, which detaches them from the controlling terminal/process group but does
# NOT reparent them — so a finished build lingers as a zombie parented to the still-running server
# until reaped. That stale defunct PID then made the index-build lock read as "live" and blocked
# every later build. Track the PIDs we launch and reap the finished ones on the next spawn. POSIX-only:
# Windows detached processes (DETACHED_PROCESS) do not create zombies and os.waitpid is not applicable.
_BACKGROUND_BUILD_PIDS: set[int] = set()


def _register_background_build_pid(pid: int) -> None:
    if os.name == "nt" or not isinstance(pid, int) or pid <= 0:
        return
    _BACKGROUND_BUILD_PIDS.add(pid)


def _reap_background_build_pids() -> None:
    """Reap finished server-launched background builds so they don't linger as zombies.

    POSIX-only. Only ever waits on PIDs this server launched; a PID that is not our child (already
    reaped/reparented) raises ChildProcessError, treated as gone. Never blocks (WNOHANG); a
    still-running child stays registered for a later sweep."""
    if os.name == "nt":
        return
    for pid in list(_BACKGROUND_BUILD_PIDS):
        try:
            ended_pid, _ = os.waitpid(pid, os.WNOHANG)
        except (ChildProcessError, OSError):
            _BACKGROUND_BUILD_PIDS.discard(pid)  # not our child / already reaped / gone
            continue
        if ended_pid == pid:
            _BACKGROUND_BUILD_PIDS.discard(pid)  # reaped — no longer a zombie


# Wave 1rswx: the same non-reparenting spawn problem 1p98u fixed for background builds also applies to
# the dashboard, which the server launches with start_new_session=True (POSIX) and never reaps — so a
# dashboard that crashes/exits mid-session lingers as a <defunct> zombie parented to the server until it
# exits. That zombie also broke wf_stop_dashboard/restart, whose bare os.kill(pid,0) liveness can't
# tell a zombie from a live process. Track the dashboard PIDs we spawn and reap the finished ones with
# the identical WNOHANG sweep pattern. POSIX-only for the same reason (Windows detached processes create
# no zombies; os.waitpid is not applicable). Deliberately NOT a SIGCHLD handler — rejected in 1p98u
# because it breaks the server's synchronous subprocess.run/.wait() with ECHILD.
_DASHBOARD_CHILD_PIDS: set[int] = set()


def _register_dashboard_child_pid(pid: int) -> None:
    if os.name == "nt" or not isinstance(pid, int) or pid <= 0:
        return
    _DASHBOARD_CHILD_PIDS.add(pid)


def _reap_dashboard_child_pids() -> None:
    """Reap finished server-launched dashboard children so they don't linger as zombies.

    POSIX-only, WNOHANG, and scoped to PIDs this server itself spawned (never a bare/recycled PID) —
    mirrors ``_reap_background_build_pids``. A still-running dashboard stays registered for a later
    sweep; a PID that is not (or no longer) our child raises ChildProcessError and is dropped."""
    if os.name == "nt":
        return
    for pid in list(_DASHBOARD_CHILD_PIDS):
        try:
            ended_pid, _ = os.waitpid(pid, os.WNOHANG)
        except (ChildProcessError, OSError):
            _DASHBOARD_CHILD_PIDS.discard(pid)  # not our child / already reaped / gone
            continue
        if ended_pid == pid:
            _DASHBOARD_CHILD_PIDS.discard(pid)  # reaped — no longer a zombie


def _start_background_index_refresh(root: Path, layer: str = "project") -> bool:
    # Wave 1p4ww: single project index — the framework layer is folded in.
    if layer != "project":
        return False
    # Wave 1p98u: reap any prior finished background builds before launching another, so server-owned
    # zombies don't accumulate across a session (each new refresh sweeps the previous ones).
    _reap_background_build_pids()
    # Wave 1rswx: sweep finished dashboard children on this frequently-hit path too, so a dashboard that
    # dies mid-session is reaped during ordinary editing — not left until the next explicit
    # wf_*_dashboard call or server exit (readiness amendment / AC-4).
    _reap_dashboard_child_pids()
    state_path = _background_refresh_state_path(root, layer)
    state_path.parent.mkdir(parents=True, exist_ok=True)
    if _background_refresh_active(state_path):
        return False
    indexer = root / ".wavefoundry" / "framework" / "scripts" / "indexer.py"
    if not indexer.exists():
        return False
    import subprocess
    cmd = [_preferred_python(), str(indexer), "--root", str(root)]
    # Project layer: indexer.py reads workflow-config project include-prefixes
    # itself (docs+code merged for the co-running graph extraction), so the
    # background refresh launches it bare.
    # Wave 1p6d6: detach the background reindex correctly per-OS — on Windows start_new_session
    # is a no-op, so without creationflags the child stays in the server's process group and dies
    # with it. Mirror the three sibling spawns (server_impl.py:3487, :6654, setup_index.py).
    detach_kwargs = {}
    if os.name == "nt":
        detach_kwargs["creationflags"] = (
            subprocess.DETACHED_PROCESS | subprocess.CREATE_NEW_PROCESS_GROUP | _windows_no_window_flag()
        )
    else:
        detach_kwargs["start_new_session"] = True
    proc = subprocess.Popen(
        cmd,
        stdin=subprocess.DEVNULL,  # never inherit the JSON-RPC stdin (sibling-consistent; wave 1p88t)
        stdout=subprocess.DEVNULL,
        stderr=subprocess.DEVNULL,
        cwd=str(root),
        close_fds=os.name != "nt",
        **detach_kwargs,
    )
    import time
    # Wave 1p98u: track this server-launched build so a later spawn reaps it once it exits (POSIX),
    # instead of leaving a defunct PID that makes the index-build lock read as "live".
    _register_background_build_pid(proc.pid)
    state_path.write_text(
        json.dumps({"pid": proc.pid, "started_at": time.time(), "layer": layer}),
        encoding="utf-8",
    )
    return True


def _trigger_background_index_refresh_for_paths(root: Path, paths: Iterable[str | Path]) -> dict[str, bool]:
    normalized_paths: list[str] = []
    for path in paths:
        if isinstance(path, Path):
            normalized = _repo_rel(root, path)
        else:
            normalized = str(path).replace("\\", "/")
            while normalized.startswith("./"):
                normalized = normalized[2:]
        if normalized:
            normalized_paths.append(normalized)
    # Wave 1p4ww: framework seeds + README are folded into the project docs index, so a
    # change to either triggers the single project refresh (no separate framework layer).
    fold_prefixes = (".wavefoundry/framework/seeds/", ".wavefoundry/framework/README.md")
    project_needed = any(
        _indexable_refresh_path(path)
        and (path.startswith("docs/") or path.startswith(fold_prefixes))
        for path in normalized_paths
    )
    return {
        "project": _start_background_index_refresh(root, "project") if project_needed else False,
    }


# ── In-session index-staleness monitor (wave 1p5xu) ─────────────────────────────
#
# A daemon thread owned by ImplHandler periodically checks whether the project
# index inputs are stale and, if so, triggers a refresh via the existing
# single-flight path. This makes continuous freshness independent of the
# dashboard process. All pieces are fail-safe: detection errors degrade to
# "no auto-refresh", never to a broken server.

_MONITOR_MIN_INTERVAL_SECONDS = 5.0
_MONITOR_DEFAULT_INTERVAL_SECONDS = 20.0
# Wave 1p9am: the staleness monitor is a quiet-period SAFETY NET, not a competing trigger. It polls
# every interval (cheap) but only *acts* once editing has settled — no fresh reindex-pending marker
# (the turn-end hook owns that) and no build finished — within this window.
_MONITOR_DEFAULT_QUIET_PERIOD_SECONDS = 300.0


def _index_inputs_stale(root: Path) -> bool:
    """Cheap stat-fast-path staleness check for the project index.

    Delegates to ``indexer.project_index_inputs_stale``. ``None`` (no built
    index / cannot determine) is treated as not stale so the monitor never
    triggers a build on an absent or unreadable index.
    """
    try:
        result = _load_script("indexer").project_index_inputs_stale(root)
    except Exception:  # noqa: BLE001
        return False
    return bool(result) if result is not None else False


def _maybe_refresh_if_stale(root: Path) -> bool:
    """Trigger a single-flight background refresh iff the index is stale, no refresh is already in
    flight, AND the repo has been quiet for the quiet-period. Wave 1p9am: the monitor is a SAFETY NET,
    not a competing trigger — it defers to the turn-end hook. It stays quiet while a `reindex-pending`
    marker is fresh (an agent is mid-turn; the Stop hook owns the next reindex) and for `quiet_period`
    seconds after the last build's `ended_at` (don't pile on a recent build). It fires only for drift
    the turn-end path missed: external edits, a turn that ended without the Stop hook flushing, or a
    non-Stop host. Pure + directly testable. Returns True when a refresh was started, False otherwise.
    """
    if not _index_inputs_stale(root):
        return False
    state_path = _background_refresh_state_path(root, "project")
    if _background_refresh_active(state_path):
        return False
    quiet = _read_monitor_config(root).get("quiet_period_seconds", _MONITOR_DEFAULT_QUIET_PERIOD_SECONDS)
    index_dir = root / ".wavefoundry" / "index"
    try:
        idx = _load_script("indexer")
    except Exception:  # noqa: BLE001
        idx = None
    if idx is not None:
        now = time.time()
        # (a) Defer to the turn-end hook while a reindex-pending marker is FRESH (an agent is editing).
        #     Take over only once it is older than the quiet-period (a turn ended without flushing).
        try:
            pending_age = idx.reindex_pending_age(index_dir)
        except Exception:  # noqa: BLE001
            pending_age = None
        if pending_age is not None and pending_age < quiet:
            return False
        # (b) Don't pile on a recent build: stay quiet for `quiet` seconds after the last build ended.
        try:
            meta = idx.read_index_build_lock_metadata(index_dir / idx.INDEX_BUILD_LOCK_NAME)
            ended_at = meta.get("ended_at") if isinstance(meta, dict) else None
        except Exception:  # noqa: BLE001
            ended_at = None
        if ended_at is not None:
            try:
                if (now - float(ended_at)) < quiet:
                    return False
            except (TypeError, ValueError):
                pass
    return _start_background_index_refresh(root, "project")


def _read_monitor_config(root: Path) -> dict[str, Any]:
    """Read ``indexing.monitor`` from docs/workflow-config.json with
    framework-owned defaults. Never raises; missing/invalid config falls back to
    the defaults (enabled, 20s interval clamped to a 5s minimum).
    """
    enabled = True
    interval = _MONITOR_DEFAULT_INTERVAL_SECONDS
    quiet = _MONITOR_DEFAULT_QUIET_PERIOD_SECONDS
    try:
        cfg = json.loads((root / "docs" / "workflow-config.json").read_text(encoding="utf-8"))
        monitor = (cfg.get("indexing") or {}).get("monitor", {})
        if isinstance(monitor, dict):
            if "enabled" in monitor:
                enabled = bool(monitor.get("enabled"))
            raw_interval = monitor.get("interval_seconds")
            if isinstance(raw_interval, (int, float)):
                interval = float(raw_interval)
            raw_quiet = monitor.get("quiet_period_seconds")
            if isinstance(raw_quiet, (int, float)):
                quiet = float(raw_quiet)
    except Exception:  # noqa: BLE001
        pass
    interval = max(_MONITOR_MIN_INTERVAL_SECONDS, interval)
    quiet = max(interval, quiet)  # a quiet-period shorter than the poll interval is meaningless
    return {"enabled": enabled, "interval_seconds": interval, "quiet_period_seconds": quiet}


def _change_location_state(root: Path, wave_md: Path, change_id: str) -> dict[str, Any]:
    staged = _plan_change_doc_path(root, change_id)
    wave_path = _wave_change_doc_path(root, wave_md, change_id)
    return {
        "staged_path": staged,
        "wave_path": wave_path,
        "staged_exists": staged.exists(),
        "wave_exists": wave_path.exists(),
    }


def _move_change_doc(source: Path, target: Path) -> None:
    target.parent.mkdir(parents=True, exist_ok=True)
    source.rename(target)


_MARKDOWN_LINK_PATTERN = re.compile(r"\[([^\]]*)\]\(([^)]+)\)")


def _broken_relative_links_after_relocation(doc_text: str) -> list[str]:
    """Return relative markdown link targets that used ``../waves/`` anchoring.

    When a change doc is relocated from ``docs/plans/`` to a wave folder the
    relative path depth changes.  Links written as ``../waves/<something>`` were
    valid from ``docs/plans/`` but become invalid from the wave folder (which is
    already *inside* ``docs/waves/``).  This helper returns each such link target
    so callers can surface them to the agent as ``broken_links``.
    """
    broken: list[str] = []
    for _text, href in _MARKDOWN_LINK_PATTERN.findall(doc_text):
        if href.startswith("../waves/"):
            broken.append(href)
    return broken


def _change_block_pattern(change_id: str) -> re.Pattern[str]:
    return re.compile(
        rf"\n?Change ID:\s+`{re.escape(change_id)}`\n(?:Previous Change Status:\s+`[^`]+`\n)?Change Status:\s+`[^`]+`\n?",
        re.MULTILINE,
    )


def _missing_required_change_sections(change_text: str) -> list[str]:
    required_headers = [
        "## Rationale",
        "## Requirements",
        "## Scope",
        "## Acceptance Criteria",
        "## Tasks",
        "## AC Priority",
    ]
    return [hdr for hdr in required_headers if hdr not in change_text]


def _extract_required_review_lanes(wave_text: str) -> list[str]:
    lanes: list[str] = []
    in_participants = False
    for raw in wave_text.splitlines():
        line = raw.strip()
        if line.startswith("## Participants"):
            in_participants = True
            continue
        if in_participants and line.startswith("## "):
            break
        if not in_participants:
            continue
        bullet_match = re.match(
            r"^-\s*Required review lanes\s*:\s*(?P<lanes>.+?)\s*$",
            line,
            re.IGNORECASE,
        )
        if bullet_match:
            for lane in bullet_match.group("lanes").split(","):
                normalized = lane.strip().strip("`").strip()
                if normalized:
                    lanes.append(normalized)
            continue
        if not line.startswith("|") or line.startswith("|------"):
            continue
        cells = [c.strip() for c in line.strip("|").split("|")]
        if len(cells) < 2:
            continue
        role, lane = cells[0], cells[1]
        if role.lower() == "role":
            continue
        if "review" not in lane.lower():
            continue
        lanes.append(role)
    # preserve order, dedupe
    out: list[str] = []
    for lane in lanes:
        if lane not in out:
            out.append(lane)
    return out


def _lane_has_signoff(wave_text: str, lane: str) -> bool:
    """Whether ``lane`` has an explicit signoff on the same line in Review Evidence (not global heuristics)."""
    return _lane_has_signoff_in_evidence(_combined_review_evidence(wave_text), lane)


def _atomic_replace_bytes(path: Path, payload: bytes, purpose: str) -> None:
    """Replace one fixed-path lifecycle artifact from a same-directory temp file."""

    temp = path.with_name(f".{path.name}.{os.getpid()}.{threading.get_ident()}.{purpose}.tmp")
    try:
        temp.write_bytes(payload)
        os.replace(temp, path)
    finally:
        try:
            temp.unlink(missing_ok=True)
        except OSError:
            pass


def _atomic_replace_text(path: Path, text: str, purpose: str) -> None:
    _atomic_replace_bytes(path, text.encode("utf-8"), purpose)


def _contained_wave_review_paths(root: Path, wave_md: Path) -> tuple[Path, Path]:
    """Resolve the fixed wave/event paths and reject any repository escape."""

    root_resolved = root.resolve()
    expected_waves_root = root_resolved / "docs" / "waves"
    waves_root = (root / "docs" / "waves").resolve(strict=False)
    if waves_root != expected_waves_root:
        raise ValueError("docs/waves must resolve to the canonical in-repository directory")
    wave_dir = wave_md.parent.resolve(strict=False)
    if wave_dir.parent != waves_root:
        raise ValueError("wave directory must resolve to one direct child of docs/waves")
    try:
        wave_dir.relative_to(root_resolved)
    except ValueError as exc:
        raise ValueError("wave directory resolves outside the repository") from exc
    expected_wave_md = wave_dir / "wave.md"
    if wave_md.resolve(strict=False) != expected_wave_md:
        raise ValueError("wave.md must not resolve through a file symlink")
    expected_events = wave_dir / "events.jsonl"
    if expected_events.resolve(strict=False) != expected_events:
        raise ValueError("events.jsonl must not resolve through a file symlink")
    return expected_wave_md, expected_events


def create_wave(root: Path, slug: str, mode: str = "dry_run") -> dict[str, Any]:
    slug_s = (slug or "").strip()
    mode_s = "create" if mode == "apply" else mode
    if not slug_s:
        raise ValueError("Wave slug must be a non-empty string.")
    if mode_s not in {"dry_run", "create"}:
        raise ValueError(f"Unsupported mode '{mode}'.")
    # Wave 1p3dk / 1p3ds: dry_run previews the wave_id without burning the
    # lifecycle slot. A subsequent apply call returns the same id.
    wave_id = _lifecycle_module().build_id(
        "wave", slug_s, legacy=False, commit=(mode_s == "create"), repo_root=root,
    )
    wave_dir = root / "docs" / "waves" / wave_id
    wave_md = wave_dir / "wave.md"
    rel_path = str(wave_md.relative_to(root)).replace("\\", "/")
    exists = wave_md.exists()
    # Wave 1p3dk / 1p3do: co-create a journal stub alongside the wave doc so
    # the wave's journal-reference lint check passes immediately and operators
    # don't have to hand-author the 9-section structure.
    journal_filename = f"{wave_id.replace(' ', '-')}.md"
    journal_path = root / "docs" / "agents" / "journals" / journal_filename
    journal_rel_path = str(journal_path.relative_to(root)).replace("\\", "/")
    journal_exists = journal_path.exists()
    if mode_s == "dry_run":
        return {
            "wave_id": wave_id, "path": rel_path, "mode": mode_s,
            "created": False, "exists": exists,
            "journal_path": journal_rel_path,
            "journal_exists": journal_exists,
        }
    wave_md, events_path = _contained_wave_review_paths(root, wave_md)
    today_iso = datetime.date.today().isoformat()
    title = slug_s.replace('-', ' ').title()
    new_wave_text = (
            "# Wave Record\n\n"
            "Owner: Engineering\n"
            "Status: planned\n"
            f"Last verified: {today_iso}\n"
            f"{REVIEW_EVIDENCE_SOURCE_DECLARATION}\n\n"
            f"wave-id: `{wave_id}`\n"
            f"Title: {title}\n\n"
            "## Objective\n\n"
            "<Describe the wave's load-bearing goal in 1–3 sentences — what changes "
            "in the project state when this wave closes, and why now. This text is "
            "displayed in the dashboard wave card.>\n\n"
            "## Changes\n\n"
            "## Wave Summary\n\n"
            "<Describe the purpose and scope of this wave in 1–3 sentences.>\n\n"
            "## Journal Watchpoints\n\n"
            "- <Add watchpoint, follow-up, or blocking notes here — coordination "
            "constraints, sequencing, or guard requirements.>\n\n"
            f"{empty_external_finding_synthesis_section()}\n"
            "## Review Evidence\n\n"
            "- operator-signoff: <approved when operator confirms closure>\n\n"
            "## Dependencies\n\n"
            "- No external wave dependencies.\n"
    )
    # Wave 1t3gt (1t3gu): a scaffold must be lint-valid from creation. Render the
    # projection-owned sections through the SAME renderers the validator compares
    # against (empty record set) so a projection-format change can never drift the
    # scaffold again.
    new_wave_text = render_review_evidence_projection(new_wave_text, ())
    new_wave_text = render_review_status_projection(
        new_wave_text,
        (),
        _review_status_signoff_keys(root, new_wave_text, ()),
    )
    with review_event_write_lock(root):
        if wave_md.exists():
            existing_text = wave_md.read_text(encoding="utf-8")
            source, source_errors = parse_review_evidence_source(existing_text)
            if source != "events.jsonl" or source_errors:
                raise RuntimeError(
                    "Existing wave does not use the external review-event contract; "
                    "runtime creation will not migrate inline history"
                )
            if not events_path.exists():
                state, state_error = adopted_protocol_state(root, wave_id)
                if state_error or state is not None:
                    raise RuntimeError(
                        "Existing adopted wave is missing events.jsonl; refusing to invent authority"
                    )
                _atomic_replace_bytes(events_path, b"", "create-events")
            validation = validate_external_review_evidence(wave_md)
            if validation.errors:
                raise RuntimeError("Existing wave review evidence is invalid: " + "; ".join(validation.errors))
            adoption_error = record_protocol_state_locked(root, wave_id, wave_md)
            if adoption_error:
                raise RuntimeError(
                    f"Existing wave review-evidence adoption could not be reconciled: {adoption_error}"
                )
            return {
                "wave_id": wave_id, "path": rel_path, "mode": mode_s,
                "created": False, "exists": True,
                "events_path": str(events_path.relative_to(root.resolve())).replace("\\", "/"),
                "journal_path": journal_rel_path,
                "journal_exists": journal_exists,
            }
        wave_dir.mkdir(parents=True, exist_ok=True)
        _atomic_replace_bytes(events_path, b"", "create-events")
        _atomic_replace_text(wave_md, new_wave_text, "create-wave")
        adoption_error = record_protocol_state_locked(root, wave_id, wave_md)
        if adoption_error:
            raise RuntimeError(
                f"Wave record and event ledger were created but durable adoption failed: {adoption_error}"
            )
    # Co-create journal stub (1p3do). Idempotent: skip when the file already
    # exists so operator-customized journals are never overwritten.
    journal_created = False
    if not journal_exists:
        journal_path.parent.mkdir(parents=True, exist_ok=True)
        journal_path.write_text(
            _scaffold_wave_journal(wave_id, title, today_iso),
            encoding="utf-8",
        )
        journal_created = True
    return {
        "wave_id": wave_id, "path": rel_path, "mode": mode_s,
        "created": True, "exists": False,
        "events_path": str(events_path.relative_to(root.resolve())).replace("\\", "/"),
        "journal_path": journal_rel_path,
        "journal_created": journal_created,
        "journal_exists": journal_exists,
    }


def _scaffold_wave_journal(wave_id: str, title: str, today_iso: str) -> str:
    """Return a lint-clean journal stub for a newly-created wave (1p3do).

    Every section satisfies the docs-lint content requirements with explicit
    `Pending:` placeholders the operator fills in as the wave progresses.
    The Salience Triggers section uses critical/high/medium/low keywords;
    Operating Identity includes role/responsibility; Promotion Evidence
    references a stable artifact in backticks.
    """
    return (
        f"# Journal - {title}\n\n"
        "Owner: Engineering\n"
        "Status: active\n"
        "Role: wave-coordinator\n"
        f"Last verified: {today_iso}\n\n"
        "Actor: wave-coordinator\n"
        "Schema version: 1.0\n"
        f"Last distilled: {today_iso}\n\n"
        f"wave-id: `{wave_id}`\n\n"
        "## Operating Identity\n\n"
        f"- **Role:** wave-coordinator for wave `{wave_id}`. **Responsibility:** "
        "coordinate the wave's admitted changes through prepare → implement → "
        "review → close per the lifecycle contract.\n\n"
        "## Salience Triggers\n\n"
        "- **critical** — operator directives that change wave scope, admitted "
        "changes, or close authorization\n"
        "- **high** — review-time findings that block close, dependency changes "
        "between admitted changes\n"
        "- **medium** — implementation-time observations about scope drift or "
        "unexpected blockers\n"
        "- **low** — routine coordination notes, status updates, lint pass/fail "
        "signals\n\n"
        "## Default Stance\n\n"
        "Maintain the wave's load-bearing invariants throughout implementation. "
        "Preserve the change-doc contracts admitted at prepare time; surface drift "
        "from operator immediately rather than silently absorbing scope.\n\n"
        "## Memory Responsibilities\n\n"
        "- Track per-change implementation state (gate-open/close pairs, AC "
        "completion, follow-up findings)\n"
        "- Record decisions made during implementation that affected scope, "
        "AC formulation, or test strategy\n\n"
        "## Active Signals\n\n"
        f"- Pending: wave `{wave_id}` opened {today_iso}; populate as admitted "
        "changes move through implementation.\n\n"
        "## Distillation\n\n"
        "- Pending: distilled lessons emerge as the wave delivers; promote durable "
        "findings to `docs/agents/journals/README.md` at close.\n\n"
        "## Promotion Evidence\n\n"
        "- Pending: promotion candidates against `docs/agents/journals/README.md` "
        "emerge as the wave delivers and durable lessons are identified.\n\n"
        "## Retirement And Supersession\n\n"
        "- Pending: retirement happens at wave close per the closure contract in "
        "`docs/agents/journals/README.md`.\n\n"
        "## Governance\n\n"
        "- This journal follows the operating-memory contract in "
        "`docs/agents/journals/README.md`. Critical/high signals may be journaled "
        "during planning, implementation, review, handoff, reindex, or closure — "
        "not only at close. Distillation, promotion, and retirement happen at "
        "close.\n"
    )


def wf_create_wave_response(root: Path, slug: str, mode: str = "dry_run", cache: Optional[McpRepoCache] = None) -> dict[str, Any]:
    try:
        result = create_wave(root, slug, mode)
    except ValueError as exc:
        return _response(
            "error",
            {"slug": slug, "mode": mode},
            diagnostics=[_diagnostic("invalid_arguments", str(exc), recovery_tools=["wf_help"], recovery_usage="wf_help()")],
            next_tools=["wf_help"],
            usage="wf_help()",
        )
    if cache and result.get("created"):
        cache.invalidate()
    if result.get("created"):
        _trigger_background_index_refresh_for_paths(root, [result["path"]])
    diagnostics: list[dict[str, Any]] = []
    if result["exists"] and not result["created"]:
        diagnostics.append(_diagnostic("already_exists", f"Wave already exists at {result['path']}.", recovery_tools=["wf_current_wave"]))
    envelope = _response(
        "dry_run" if result["mode"] == "dry_run" else "ok",
        result,
        diagnostics=diagnostics,
        next_tools=["wf_list_waves", "wf_current_wave"],
        usage="wf_current_wave()",
    )
    return _attach_lint_to_response(envelope, root, result["mode"])


def _insert_change_block_into_changes_section(text: str, change_id: str) -> str:
    """Append a ``Change ID:`` block inside the ``## Changes`` section.

    The block is inserted after any existing change blocks in the section, before
    the next ``## `` heading (or end-of-file). When ``## Changes`` is missing
    (e.g., on operator-edited waves), the section is created just before the
    first existing ``## `` heading, or appended to the end of the file if none
    exist. Admission order is preserved by tail-appending within the section.
    """
    block = f"Change ID: `{change_id}`\nChange Status: `planned`\n"
    changes_match = re.search(r"^## Changes[ \t]*\n", text, re.MULTILINE)
    if changes_match is None:
        next_heading = re.search(r"^## ", text, re.MULTILINE)
        section = "## Changes\n\n" + block + "\n"
        if next_heading is None:
            if text and not text.endswith("\n"):
                text += "\n"
            return text + "\n" + section
        return text[:next_heading.start()] + section + text[next_heading.start():]
    section_start = changes_match.end()
    next_heading = re.search(r"^## ", text[section_start:], re.MULTILINE)
    section_end = section_start + next_heading.start() if next_heading else len(text)
    section_body = text[section_start:section_end]
    body_stripped = section_body.rstrip()
    if body_stripped:
        new_section = body_stripped + "\n\n" + block + "\n"
    else:
        new_section = "\n" + block + "\n"
    return text[:section_start] + new_section + text[section_end:]


def wf_add_change_response(
    root: Path,
    wave_id: str,
    change_id: str,
    mode: str = "dry_run",
    cache: Optional[McpRepoCache] = None,
) -> dict[str, Any]:
    mode_s = "create" if (mode or "").strip().lower() == "apply" else (mode or "").strip().lower()
    if mode_s not in {"dry_run", "create"}:
        return _response("error", {"wave_id": wave_id, "change_id": change_id, "mode": mode}, diagnostics=[_diagnostic("invalid_arguments", f"Unsupported mode '{mode}'.")], next_tools=["wf_help"], usage="wf_help()")
    try:
        wave_md = _find_wave_md(root, wave_id)
    except ValueError as exc:
        return _response(
            "error",
            {"wave_id": wave_id, "change_id": change_id, "mode": mode_s},
            diagnostics=[_diagnostic("review_evidence_path_escape", str(exc))],
        )
    if wave_md is None:
        return _response("error", {"wave_id": wave_id, "change_id": change_id, "mode": mode_s}, diagnostics=[_diagnostic("wave_not_found", f"No wave found matching '{wave_id}'.", recovery_tools=["wf_list_waves"], recovery_usage="wf_list_waves()")], next_tools=["wf_list_waves"], usage="wf_list_waves()")
    change_matches = _resolve_change_doc_matches(root, change_id)
    if not change_matches:
        return _response("error", {"wave_id": wave_id, "change_id": change_id, "mode": mode_s}, diagnostics=[_diagnostic("change_not_found", f"No change doc found matching '{change_id}'.", recovery_tools=["wf_list_plans"], recovery_usage="wf_list_plans()")], next_tools=["wf_list_plans"], usage="wf_list_plans()")
    if len(change_matches) > 1:
        return _response(
            "error",
            {"wave_id": wave_id, "change_id": change_id, "mode": mode_s},
            diagnostics=[
                _diagnostic(
                    "ambiguous_change_id",
                    f"Multiple change docs match '{change_id}'. Use a more specific ID.",
                    recovery_tools=["wf_list_plans"],
                    recovery_usage="wf_list_plans()",
                )
            ],
            next_tools=["wf_list_plans"],
            usage="wf_list_plans()",
        )
    canonical_change_id = str(change_matches[0]["change_id"])
    source_path = root / str(change_matches[0]["path"])
    target_path = _wave_change_doc_path(root, wave_md, canonical_change_id)
    text = wave_md.read_text(encoding="utf-8")
    existing = _extract_change_ids_from_wave_text(text)
    location = _change_location_state(root, wave_md, canonical_change_id)
    if source_path.parent.name != wave_md.parent.name and "docs/waves/" in str(change_matches[0]["path"]).replace("\\", "/") and source_path != target_path:
        return _response(
            "error",
            {"wave_id": wave_id, "change_id": canonical_change_id, "mode": mode_s},
            diagnostics=[
                _diagnostic(
                    "change_already_in_other_wave",
                    f"Change '{canonical_change_id}' already lives in another wave folder at {_repo_rel(root, source_path)}.",
                    recovery_tools=["wf_current_wave", "wf_get_change"],
                    recovery_usage=f"wf_get_change(change_id={canonical_change_id!r})",
                )
            ],
            next_tools=["wf_current_wave", "wf_get_change"],
            usage=f"wf_get_change(change_id={canonical_change_id!r})",
        )
    if canonical_change_id in existing:
        diagnostics = [_diagnostic("already_admitted", f"Change '{canonical_change_id}' is already admitted.")]
        if location["staged_exists"] and location["wave_exists"]:
            diagnostics.append(
                _diagnostic(
                    "duplicate_change_doc_locations",
                    f"Change '{canonical_change_id}' exists in both {_repo_rel(root, location['staged_path'])} and {_repo_rel(root, location['wave_path'])}.",
                    recovery_tools=["wf_prepare_wave", "wf_get_change"],
                    recovery_usage=f"wf_prepare_wave(wave_id={wave_md.parent.name!r}, mode='create')",
                )
            )
            return _response("error", {"wave_id": wave_id, "change_id": canonical_change_id, "mode": mode_s, "updated": False}, diagnostics=diagnostics, next_tools=["wf_prepare_wave", "wf_get_change"], usage=f"wf_prepare_wave(wave_id={wave_md.parent.name!r}, mode='create')")
        return _response(
            "ok",
            {
                "wave_id": wave_id,
                "change_id": canonical_change_id,
                "mode": mode_s,
                "updated": False,
                "relocated": location["wave_exists"],
                "path": _repo_rel(root, location["wave_path"]) if location["wave_exists"] else _repo_rel(root, source_path),
            },
            diagnostics=diagnostics,
            next_tools=["wf_current_wave"],
            usage="wf_current_wave()",
        )
    relocated = source_path == target_path
    if mode_s == "create":
        if target_path.exists() and source_path != target_path:
            return _response(
                "error",
                {"wave_id": wave_id, "change_id": canonical_change_id, "mode": mode_s},
                diagnostics=[
                    _diagnostic(
                        "duplicate_change_doc_locations",
                        f"Target wave doc already exists at {_repo_rel(root, target_path)} while source remains at {_repo_rel(root, source_path)}.",
                        recovery_tools=["wf_prepare_wave", "wf_get_change"],
                        recovery_usage=f"wf_prepare_wave(wave_id={wave_md.parent.name!r}, mode='create')",
                    )
                ],
                next_tools=["wf_prepare_wave", "wf_get_change"],
                usage=f"wf_prepare_wave(wave_id={wave_md.parent.name!r}, mode='create')",
            )
        if source_path != target_path:
            try:
                _move_change_doc(source_path, target_path)
            except OSError as exc:
                return _response(
                    "error",
                    {"wave_id": wave_id, "change_id": canonical_change_id, "mode": mode_s},
                    diagnostics=[
                        _diagnostic(
                            "change_relocation_failed",
                            f"Failed to relocate change doc to {_repo_rel(root, target_path)}: {exc}",
                            recovery_tools=["wf_get_change"],
                            recovery_usage=f"wf_get_change(change_id={canonical_change_id!r})",
                        )
                    ],
                    next_tools=["wf_get_change"],
                    usage=f"wf_get_change(change_id={canonical_change_id!r})",
                )
            relocated = True
        text = _insert_change_block_into_changes_section(text, canonical_change_id)
        wave_md.write_text(text, encoding="utf-8")
        if cache:
            cache.invalidate()
        _trigger_background_index_refresh_for_paths(root, [wave_md, target_path])
    # Detect broken relative links regardless of mode (dry-run reads source, create reads target).
    _doc_check_path = target_path if (mode_s == "create" and target_path.exists()) else source_path
    broken_links: list[str] = []
    if _doc_check_path.exists():
        _doc_text = _doc_check_path.read_text(encoding="utf-8")
        broken_links = _broken_relative_links_after_relocation(_doc_text)
    envelope = _response(
        "dry_run" if mode_s == "dry_run" else "ok",
        {
            "wave_id": wave_id,
            "change_id": canonical_change_id,
            "mode": mode_s,
            "updated": mode_s == "create",
            "relocated": relocated,
            "source_path": _repo_rel(root, source_path),
            "target_path": _repo_rel(root, target_path),
            "broken_links": broken_links,
        },
        next_tools=["wf_current_wave", "wf_add_change", "wf_get_change"],
        usage=f"wf_get_change(change_id={canonical_change_id!r})",
    )
    return _attach_lint_to_response(envelope, root, mode_s)


def wf_remove_change_response(
    root: Path,
    wave_id: str,
    change_id: str,
    mode: str = "dry_run",
    cache: Optional[McpRepoCache] = None,
) -> dict[str, Any]:
    mode_s = "create" if (mode or "").strip().lower() == "apply" else (mode or "").strip().lower()
    if mode_s not in {"dry_run", "create"}:
        return _response("error", {"wave_id": wave_id, "change_id": change_id, "mode": mode}, diagnostics=[_diagnostic("invalid_arguments", f"Unsupported mode '{mode}'.")], next_tools=["wf_help"], usage="wf_help()")
    wave_md = _find_wave_md(root, wave_id)
    if wave_md is None:
        return _response("error", {"wave_id": wave_id, "change_id": change_id, "mode": mode_s}, diagnostics=[_diagnostic("wave_not_found", f"No wave found matching '{wave_id}'.", recovery_tools=["wf_list_waves"], recovery_usage="wf_list_waves()")], next_tools=["wf_list_waves"], usage="wf_list_waves()")
    text = wave_md.read_text(encoding="utf-8")
    target = _change_block_pattern(change_id)
    if not target.search(text):
        return _response("ok", {"wave_id": wave_id, "change_id": change_id, "mode": mode_s, "updated": False}, diagnostics=[_diagnostic("not_admitted", f"Change '{change_id}' is not admitted to wave.")], next_tools=["wf_current_wave"], usage="wf_current_wave()")
    location = _change_location_state(root, wave_md, change_id)
    if location["staged_exists"] and location["wave_exists"]:
        return _response(
            "error",
            {"wave_id": wave_id, "change_id": change_id, "mode": mode_s, "updated": False},
            diagnostics=[
                _diagnostic(
                    "duplicate_change_doc_locations",
                    f"Change '{change_id}' exists in both {_repo_rel(root, location['staged_path'])} and {_repo_rel(root, location['wave_path'])}.",
                    recovery_tools=["wf_prepare_wave", "wf_get_change"],
                    recovery_usage=f"wf_prepare_wave(wave_id={wave_md.parent.name!r}, mode='create')",
                )
            ],
            next_tools=["wf_prepare_wave", "wf_get_change"],
            usage=f"wf_prepare_wave(wave_id={wave_md.parent.name!r}, mode='create')",
        )
    if mode_s == "create":
        text = target.sub("\n", text, count=1)
        if location["wave_exists"]:
            try:
                _move_change_doc(location["wave_path"], location["staged_path"])
            except OSError as exc:
                return _response(
                    "error",
                    {"wave_id": wave_id, "change_id": change_id, "mode": mode_s, "updated": False},
                    diagnostics=[
                        _diagnostic(
                            "change_relocation_failed",
                            f"Failed to move change doc back to {_repo_rel(root, location['staged_path'])}: {exc}",
                            recovery_tools=["wf_get_change"],
                            recovery_usage=f"wf_get_change(change_id={change_id!r})",
                        )
                    ],
                    next_tools=["wf_get_change"],
                    usage=f"wf_get_change(change_id={change_id!r})",
                )
        wave_md.write_text(text, encoding="utf-8")
        if cache:
            cache.invalidate()
        _trigger_background_index_refresh_for_paths(root, [wave_md, location["staged_path"]])
    envelope = _response(
        "dry_run" if mode_s == "dry_run" else "ok",
        {
            "wave_id": wave_id,
            "change_id": change_id,
            "mode": mode_s,
            "updated": mode_s == "create",
            "source_path": _repo_rel(root, location["wave_path"]),
            "target_path": _repo_rel(root, location["staged_path"]),
        },
        next_tools=["wf_current_wave"],
        usage="wf_current_wave()",
    )
    return _attach_lint_to_response(envelope, root, mode_s)

def _lifecycle_module() -> Any:
    """Return the cached ``lifecycle_id`` module.

    Thin wrapper around ``_load_script`` so that tests can mock this single
    call site instead of patching the lower-level loader.
    """
    return _load_script("lifecycle_id")


def new_change(root: Path, kind: str, slug: str, change_id: str | None = None) -> dict:
    """Generate a lifecycle ID and scaffold a change doc. Returns path and ID.

    When ``change_id`` is provided (wave 1p3dk / 1p3ds defect-B fix), reuse it
    instead of calling ``build_id`` a second time. Without this, callers like
    ``change_create`` that already generated an id for the response would
    burn a second lifecycle slot here.
    """
    if change_id is None:
        # Wave 1p45b — pass repo_root so the on-disk dedup scan runs (else a
        # duplicate stem can be minted; observed: 1p44w handed out twice).
        change_id = _lifecycle_module().build_id(kind, slug, legacy=False, repo_root=root)
    plans_dir = root / "docs" / "plans"
    plans_dir.mkdir(parents=True, exist_ok=True)

    template_path = plans_dir / "plan-template.md"
    if template_path.exists():
        template = template_path.read_text(encoding="utf-8")
    else:
        template = _default_template()

    import time
    today = time.strftime("%Y-%m-%d")
    content = template
    content = re.sub(r"`<id-prefix>-<kind> <slug>`.*", f"`{change_id}`", content)
    content = re.sub(r"Change ID:.*", f"Change ID: `{change_id}`", content)
    content = re.sub(r"Last verified:.*", f"Last verified: {today}", content)

    out_path = plans_dir / f"{change_id}.md"
    out_path.write_text(content, encoding="utf-8")
    return {"id": change_id, "path": str(out_path.relative_to(root)).replace("\\", "/")}


def change_create(root: Path, kind: str, slug: str, mode: str = "create") -> dict[str, Any]:
    if kind not in VALID_CHANGE_KINDS:
        raise ValueError(f"Unsupported change kind '{kind}'.")
    norm_mode = "create" if mode == "apply" else mode
    if norm_mode not in {"dry_run", "create"}:
        raise ValueError(f"Unsupported mode '{mode}'.")
    mode = norm_mode

    # Wave 1p3dk / 1p3ds: dry_run previews the id without burning the slot.
    # When mode == "create", reuse the same id when handing off to new_change
    # so a single change-doc creation consumes exactly one lifecycle prefix
    # (closes defect B from the field report).
    change_id = _lifecycle_module().build_id(
        kind, slug, legacy=False, commit=(mode == "create"), repo_root=root,
    )
    plans_dir = root / "docs" / "plans"
    plans_dir.mkdir(parents=True, exist_ok=True)
    rel_path = str((plans_dir / f"{change_id}.md").relative_to(root)).replace("\\", "/")
    out_path = root / rel_path
    exists = out_path.exists()

    if mode == "dry_run":
        return {
            "id": change_id,
            "path": rel_path,
            "mode": mode,
            "created": False,
            "exists": exists,
        }
    if exists:
        return {
            "id": change_id,
            "path": rel_path,
            "mode": mode,
            "created": False,
            "exists": True,
        }
    created = new_change(root, kind, slug, change_id=change_id)
    return {
        **created,
        "mode": mode,
        "created": True,
        "exists": False,
    }


def _change_create_response(
    root: Path,
    kind: str,
    slug: str,
    mode: str = "dry_run",
    cache: Optional[McpRepoCache] = None,
) -> dict[str, Any]:
    kind_s = (kind or "").strip().lower()
    slug_s = (slug or "").strip()
    mode_s = (mode or "").strip().lower()
    if mode_s == "apply":
        mode_s = "create"
    if not slug_s:
        return _response(
            "error",
            {"kind": kind_s, "slug": slug, "mode": mode_s},
            diagnostics=[
                _diagnostic(
                    "invalid_arguments",
                    "Change slug must be a non-empty string.",
                    recovery_tools=["wf_help"],
                    recovery_usage="wf_help(goal='plan_feature')",
                )
            ],
            next_tools=["wf_help"],
            usage="wf_help(goal='plan_feature')",
        )
    try:
        result = change_create(root, kind_s, slug_s, mode=mode_s)
    except ValueError as exc:
        return _response(
            "error",
            {"kind": kind_s, "slug": slug_s, "mode": mode_s},
            diagnostics=[
                _diagnostic(
                    "invalid_arguments",
                    str(exc),
                    recovery_tools=["wf_help"],
                    recovery_usage="wf_help(goal='plan_feature')",
                )
            ],
            next_tools=["wf_help"],
            usage="wf_help(goal='plan_feature')",
        )

    diagnostics: list[dict[str, Any]] = []
    status = "dry_run" if mode_s == "dry_run" else "ok"
    if result["exists"] and not result["created"]:
        diagnostics.append(
            _diagnostic(
                "already_exists",
                f"Change doc already exists at {result['path']}.",
                recovery_tools=["wf_get_change", "wf_validate_docs"],
                recovery_usage=f"wf_get_change(change_id={result['id']!r})",
            )
        )
    if cache and result.get("created"):
        cache.invalidate()
    if result.get("created"):
        _trigger_background_index_refresh_for_paths(root, [result["path"]])
    envelope = _response(
        status,
        {
            "change_id": result["id"],
            "path": result["path"],
            "kind": kind_s,
            "slug": slug_s,
            "mode": mode_s,
            "created": result["created"],
            "exists": result["exists"],
        },
        diagnostics=diagnostics,
        next_tools=["wf_get_change", "wf_validate_docs"],
        usage=f"wf_get_change(change_id={result['id']!r})",
    )
    return _attach_lint_to_response(envelope, root, mode_s)


_VALID_GATES = {"seed_edit_allowed", "framework_edit_allowed", "design_system_edit_allowed"}


def _read_guard_overrides(root: Path) -> dict[str, Any]:
    """Read .wavefoundry/guard-overrides.json; return empty dict on missing/malformed."""
    path = root / ".wavefoundry" / "guard-overrides.json"
    if not path.exists():
        return {}
    try:
        import json as _json
        return _json.loads(path.read_text(encoding="utf-8"))
    except Exception:
        return {}


def _write_guard_overrides(root: Path, data: dict[str, Any]) -> None:
    """Write data to .wavefoundry/guard-overrides.json."""
    import json as _json
    path = root / ".wavefoundry" / "guard-overrides.json"
    path.parent.mkdir(parents=True, exist_ok=True)
    path.write_text(_json.dumps(data, indent=2) + "\n", encoding="utf-8")


def _force_gates_closed(root: Path, mode: str) -> list[dict[str, Any]]:
    """Close all edit gates and return a diagnostic listing which were open.

    In dry-run mode the gate file is not written; the diagnostic is still returned
    so callers can report what would have been closed.

    Args:
        root: Repository root.
        mode: ``"create"`` to write the gate file; any other value is a dry-run.
    """
    overrides = _read_guard_overrides(root)
    open_gates = [g for g in _VALID_GATES if overrides.get(g, {}).get("enabled", False)]
    if not open_gates:
        return []
    if mode == "create":
        for gate in _VALID_GATES:
            overrides.setdefault(gate, {})["enabled"] = False
        _write_guard_overrides(root, overrides)
    return [
        _diagnostic(
            "gates_forced_closed",
            f"The following edit gate(s) were open and have been {'closed' if mode == 'create' else 'detected (dry-run — not closed)' }: {', '.join(sorted(open_gates))}. "
            "Use wf_open_gate / wf_close_gate to manage gates explicitly.",
            recovery_tools=["wf_close_gate"],
            recovery_usage="wf_close_gate(gate='seed_edit_allowed')",
        )
    ]


def wave_open_gate_response(root: Path, gate: str) -> dict[str, Any]:
    """Open an edit gate, enabling the corresponding guard in guard-overrides.json."""
    gate_s = (gate or "").strip()
    if gate_s not in _VALID_GATES:
        return _response(
            "error",
            {"gate": gate_s, "valid_gates": sorted(_VALID_GATES)},
            diagnostics=[_diagnostic("invalid_arguments", f"Unknown gate '{gate_s}'. Valid gates: {sorted(_VALID_GATES)}.")],
            next_tools=["wf_open_gate"],
            usage=f"wf_open_gate(gate='seed_edit_allowed')",
        )
    overrides = _read_guard_overrides(root)
    if overrides.get(gate_s, {}).get("enabled", False):
        return _response(
            "error",
            {"gate": gate_s, "enabled": True},
            diagnostics=[_diagnostic(
                "gate_already_open",
                f"Gate '{gate_s}' is already open. Close it with wf_close_gate before opening again.",
                recovery_tools=["wf_close_gate"],
                recovery_usage=f"wf_close_gate(gate={gate_s!r})",
            )],
            next_tools=["wf_close_gate"],
            usage=f"wf_close_gate(gate={gate_s!r})",
        )
    overrides.setdefault(gate_s, {})["enabled"] = True
    _write_guard_overrides(root, overrides)
    return _response(
        "ok",
        {"gate": gate_s, "enabled": True},
        next_tools=["wf_close_gate"],
        usage=f"wf_close_gate(gate={gate_s!r})",
    )


def wf_close_wave_gate_response(root: Path, gate: str) -> dict[str, Any]:
    """Close an edit gate, disabling the corresponding guard in guard-overrides.json."""
    gate_s = (gate or "").strip()
    if gate_s not in _VALID_GATES:
        return _response(
            "error",
            {"gate": gate_s, "valid_gates": sorted(_VALID_GATES)},
            diagnostics=[_diagnostic("invalid_arguments", f"Unknown gate '{gate_s}'. Valid gates: {sorted(_VALID_GATES)}.")],
            next_tools=["wf_close_gate"],
            usage=f"wf_close_gate(gate='seed_edit_allowed')",
        )
    overrides = _read_guard_overrides(root)
    already_closed = not overrides.get(gate_s, {}).get("enabled", False)
    overrides.setdefault(gate_s, {})["enabled"] = False
    _write_guard_overrides(root, overrides)
    diagnostics: list[dict[str, Any]] = []
    if already_closed:
        diagnostics.append(_diagnostic(
            "gate_already_closed",
            f"Gate '{gate_s}' was already closed — no change made.",
        ))
    return _response(
        "ok",
        {"gate": gate_s, "enabled": False},
        diagnostics=diagnostics if diagnostics else None,
        next_tools=["wf_open_gate"],
        usage=f"wf_open_gate(gate={gate_s!r})",
    )


def wf_gate_status_response(root: Path) -> dict[str, Any]:
    """Return the current enabled/disabled state of all edit gates."""
    overrides = _read_guard_overrides(root)
    gates = {gate: overrides.get(gate, {}).get("enabled", False) for gate in sorted(_VALID_GATES)}
    return _response(
        "ok",
        {"gates": gates},
        next_tools=["wf_open_gate", "wf_close_gate"],
    )


def wf_get_handoff_response(root: Path) -> dict[str, Any]:
    """Read docs/agents/session-handoff.md and return its content and mtime."""
    handoff_path = root / "docs" / "agents" / "session-handoff.md"
    if not handoff_path.exists():
        return _response(
            "ok",
            {"path": "docs/agents/session-handoff.md", "content": None, "mtime": None},
            diagnostics=[
                _diagnostic(
                    "handoff_not_found",
                    "docs/agents/session-handoff.md does not exist. Use wf_set_handoff to create it.",
                    recovery_tools=["wf_current_wave"],
                    recovery_usage="wf_current_wave()",
                )
            ],
            next_tools=["wf_set_handoff", "wf_current_wave"],
            usage="wf_set_handoff(content='# Session Handoff\\n\\n...')",
        )
    try:
        content = handoff_path.read_text(encoding="utf-8")
        mtime = handoff_path.stat().st_mtime
    except OSError as exc:
        return _response("error", {"path": "docs/agents/session-handoff.md"}, diagnostics=[_diagnostic("read_error", str(exc))], next_tools=["wf_current_wave"], usage="wf_current_wave()")
    return _response(
        "ok",
        {"path": "docs/agents/session-handoff.md", "content": content, "mtime": mtime},
        next_tools=["wf_set_handoff", "wf_current_wave"],
        usage="wf_current_wave()",
    )


def wf_set_handoff_response(root: Path, content: str, cache: Optional[McpRepoCache] = None) -> dict[str, Any]:
    """Write content to docs/agents/session-handoff.md, creating the file if absent."""
    handoff_path = root / "docs" / "agents" / "session-handoff.md"
    try:
        handoff_path.parent.mkdir(parents=True, exist_ok=True)
        handoff_path.write_text(content, encoding="utf-8")
    except OSError as exc:
        return _response("error", {"path": "docs/agents/session-handoff.md"}, diagnostics=[_diagnostic("write_error", str(exc))], next_tools=["wf_current_wave"], usage="wf_current_wave()")
    _trigger_background_index_refresh_for_paths(root, ["docs/agents/session-handoff.md"])
    envelope = _response(
        "ok",
        {"path": "docs/agents/session-handoff.md", "written": True, "size": len(content)},
        next_tools=["wf_get_handoff", "wf_current_wave"],
        usage="wf_get_handoff()",
    )
    # wf_set_handoff has no `mode` param — it always writes. Pass "create"
    # so the lint integration fires.
    return _attach_lint_to_response(envelope, root, "create")


def _human_bytes(n: int) -> str:
    units = ("B", "KB", "MB", "GB", "TB", "PB")
    f = float(n)
    i = 0
    while f >= 1024.0 and i < len(units) - 1:
        f /= 1024.0
        i += 1
    return f"{int(f)} {units[i]}" if i == 0 else f"{f:.1f} {units[i]}"


def _path_size_bytes(p: Path) -> int:
    """On-disk byte size of a file or (recursively) a directory — best-effort, never raises."""
    try:
        if p.is_symlink() or p.is_file():
            return p.stat().st_size
    except OSError:
        return 0
    total = 0
    try:
        for dirpath, _dirs, files in os.walk(p):
            for name in files:
                try:
                    total += os.stat(os.path.join(dirpath, name)).st_size
                except OSError:
                    pass
    except OSError:
        pass
    return total


def _index_dir_size(index_dir: Path) -> Optional[dict[str, Any]]:
    """Wave 1p9a9: total + top-level component on-disk size of the index dir. Read-only, best-effort;
    a missing dir or any stat error yields ``None`` (never raises). The per-component breakdown
    (``docs.lance`` / ``code.lance`` / ``graph`` / …) is what makes LanceDB bloat diagnosable."""
    try:
        if not index_dir.exists():
            return None
        components: dict[str, int] = {}
        total = 0
        for entry in sorted(index_dir.iterdir(), key=lambda e: e.name):
            sz = _path_size_bytes(entry)
            components[entry.name] = sz
            total += sz
    except OSError:
        return None
    return {"total_bytes": total, "total_human": _human_bytes(total), "components": components}


# Wave 1rycf: bloat-gated, tier-1-only index optimize run at wave close as an interim reclaim.
# Background: LanceDB's incremental FTS rebuild (`create_fts_index(replace=True)`) leaves un-GC'd
# `_indices/` versions, so `docs.lance` balloons (698 MB observed, 640 MB reclaimable) between the deep
# optimizes that only run at install/upgrade. Until the SQLite FTS5 migration removes the leak at the
# source, reclaim opportunistically at close — but ONLY when the table is genuinely bloated, ONLY tier-1
# in-place (never spawn a synchronous rebuild), and NEVER at the expense of the close itself.
CLOSE_OPTIMIZE_BLOAT_RATIO = 3.0      # on-disk / logical-floor ratio at/above which a table is "bloated"
CLOSE_OPTIMIZE_MIN_ROW_BYTES = 2048   # conservative per-row logical floor (chunk text + vector + FTS)


def _close_optimize_enabled(root: Path) -> bool:
    """Kill-switch for the wave 1rycf close-time optimize. Reads
    ``docs/workflow-config.json`` ``indexing.close_optimize_enabled`` (default ``True``). Fail-safe:
    any read/parse error or missing key yields the default; never raises."""
    try:
        cfg = _read_workflow_config(root)
        indexing = cfg.get("indexing")
        if isinstance(indexing, dict) and "close_optimize_enabled" in indexing:
            return bool(indexing.get("close_optimize_enabled"))
    except Exception:  # noqa: BLE001 — a config read must never gate the close
        pass
    return True


def _index_table_bloat_ratios(root: Path) -> dict[str, float]:
    """Wave 1rycf. Best-effort on-disk-bloat ratio per Lance table (``docs``/``code``): on-disk
    component bytes divided by a conservative logical floor (``rows * CLOSE_OPTIMIZE_MIN_ROW_BYTES``).
    A ratio well above 1.0 means the table's physical footprint far exceeds what its live rows require —
    the FTS-version-leak signature. Read-only, fail-safe: any error (missing dir, unreadable table,
    zero rows) drops that table from the result rather than raising, and returns ``{}`` on total failure."""
    ratios: dict[str, float] = {}
    try:
        index_dir = root / ".wavefoundry" / "index"
        sizes = _index_dir_size(index_dir)
        if not sizes:
            return {}
        components = sizes.get("components") or {}
        import lancedb  # local import: keep module import cheap and optional
        db = lancedb.connect(str(index_dir))
        for table in ("docs", "code"):
            on_disk = int(components.get(f"{table}.lance") or 0)
            if on_disk <= 0:
                continue
            try:
                rows = int(db.open_table(table).count_rows())
            except Exception:  # noqa: BLE001 — missing/unreadable table: skip, don't fail the sweep
                continue
            floor = rows * CLOSE_OPTIMIZE_MIN_ROW_BYTES
            if floor <= 0:
                continue
            ratios[table] = on_disk / floor
    except Exception:  # noqa: BLE001 — the gate is advisory; never let it raise into the close
        return {}
    return ratios


def _maybe_optimize_index_on_close(root: Path) -> Optional[dict[str, Any]]:
    """Wave 1rycf. If the close-time optimize is enabled and a Lance table is genuinely bloated
    (ratio >= ``CLOSE_OPTIMIZE_BLOAT_RATIO``), run a tier-1 in-place ``optimize_index_tables`` over the
    bloated tables to reclaim leaked FTS versions. Contract:

    - **Gated** — no-op (returns ``None``) when disabled or when no table is bloated (the common case).
    - **Lock-aware** — if a build already holds the index lock, ``optimize_index_tables`` raises
      ``IndexBuildAlreadyRunning``; we skip (report ``skipped: index_build_lock_held``) rather than wait.
    - **Tier-1 only** — calls ``optimize_index_tables`` directly, which never spawns a rebuild; any
      ``needs_rebuild`` table is reported and deferred (the tier-3 spawn lives only in the response
      wrapper, not here), so close never blocks on a synchronous re-embed.
    - **Fail-safe** — any error is swallowed; a close must never fail because of opportunistic reclaim.

    Returns a compact summary dict for attachment to the close response, or ``None`` when nothing ran."""
    try:
        if not _close_optimize_enabled(root):
            return None
        ratios = _index_table_bloat_ratios(root)
        bloated = sorted(t for t, r in ratios.items() if r >= CLOSE_OPTIMIZE_BLOAT_RATIO)
        if not bloated:
            return None
        index_dir = root / ".wavefoundry" / "index"
        idx = _load_script("indexer")
        already_running = getattr(idx, "IndexBuildAlreadyRunning", None)
        try:
            results = idx.optimize_index_tables(index_dir, tuple(bloated))
        except Exception as exc:  # noqa: BLE001
            if already_running is not None and isinstance(exc, already_running):
                return {"ran": False, "skipped": "index_build_lock_held",
                        "bloated_tables": bloated,
                        "ratios": {t: round(ratios[t], 2) for t in bloated}}
            return {"ran": False, "skipped": "optimize_error", "error": str(exc),
                    "bloated_tables": bloated}
        if isinstance((results or {}).get("error"), str):
            return {"ran": False, "skipped": "index_not_ready", "error": results["error"],
                    "bloated_tables": bloated}
        reclaimed_total = 0
        deferred_rebuild: list[str] = []
        tables_out: dict[str, Any] = {}
        for t, res in (results or {}).items():
            if not isinstance(res, dict):
                continue
            before = int(res.get("bytes_before") or 0)
            after = int(res.get("bytes_after") or 0)
            reclaimed = max(0, before - after)
            reclaimed_total += reclaimed
            if res.get("needs_rebuild"):
                deferred_rebuild.append(t)
            tables_out[t] = {"tier": res.get("tier"), "reclaimed_bytes": reclaimed,
                             "reclaimed": _human_bytes(reclaimed)}
        return {
            "ran": True,
            "bloated_tables": bloated,
            "ratios": {t: round(ratios[t], 2) for t in bloated},
            "tables": tables_out,
            "reclaimed_bytes": reclaimed_total,
            "reclaimed": _human_bytes(reclaimed_total),
            # Tier-3 rebuild is DEFERRED at close (never spawned inline) — surface it so a follow-up
            # index_optimize / index_build can pick it up.
            "needs_rebuild_deferred": sorted(deferred_rebuild),
        }
    except Exception:  # noqa: BLE001 — the close must never fail because of opportunistic reclaim
        return None


def index_health_response(index: WaveIndex) -> dict[str, Any]:
    """Return structured health status for the project index layer.

    Runs file-hash comparison against the store's recorded build hashes and reports missing, stale, or
    ready state.  Wave 1p4ww folded the framework docs into this single project
    index.  Intended as an explicit diagnostic tool; not on the search hot path.
    """
    try:
        health = index.docs_health()
    except Exception as exc:
        return _response(
            "error",
            {"layers": {}},
            diagnostics=[
                _diagnostic(
                    "index_health_error",
                    f"Could not compute index health: {exc}",
                    recovery_tools=["wf_help"],
                    recovery_usage="python3 .wavefoundry/framework/scripts/setup_wavefoundry.py --root .",
                )
            ],
            next_tools=["wf_help"],
            usage="index_health()",
        )

    diagnostics: list[dict[str, Any]] = []
    for layer in health.get("missing_layers", []):
        diagnostics.append(
            _diagnostic(
                "index_missing",
                f"Index layer missing: {layer}. Run: python3 .wavefoundry/framework/scripts/setup_wavefoundry.py --root .",
                recovery_tools=["wf_help"],
                recovery_usage="python3 .wavefoundry/framework/scripts/setup_wavefoundry.py --root .",
            )
        )
    for layer in health.get("stale_layers", []):
        diagnostics.append(
            _diagnostic(
                "index_stale",
                f"Index layer stale: {layer}. Run: python3 .wavefoundry/framework/scripts/setup_wavefoundry.py --root . --full",
                recovery_tools=["wf_help"],
                recovery_usage="python3 .wavefoundry/framework/scripts/setup_wavefoundry.py --root . --full",
            )
        )
    overview = health.get("readiness_overview")
    if overview == "degraded":
        diagnostics.append(
            _diagnostic(
                "index_degraded",
                "Index metadata is present but merged semantic chunks did not load; search may fall back to lexical retrieval.",
                recovery_tools=["wf_help", "index_build"],
                recovery_usage="python3 .wavefoundry/framework/scripts/setup_wavefoundry.py --root .",
            )
        )
    elif overview == "absent":
        diagnostics.append(
            _diagnostic(
                "index_absent",
                "No index metadata found under the project index dir (nothing to search semantically yet).",
                recovery_tools=["wf_help"],
                recovery_usage="python3 .wavefoundry/framework/scripts/setup_wavefoundry.py --root .",
            )
        )
    if health.get("code_layer_missing"):
        diagnostics.append(
            _diagnostic(
                "code_layer_missing",
                "Code sources are in scope but the code index layer (code.lance) is absent — likely an "
                "interrupted or OOM-killed code embedding pass. code_ask / code_search have no code layer "
                "until it is rebuilt: index_build(content='code').",
                recovery_tools=["index_build"],
                recovery_usage="index_build(content='code')",
            )
        )
    for layer in health.get("chunker_version_mismatch_layers", []):
        diagnostics.append(
            _diagnostic(
                "chunker_version_mismatch",
                f"Index layer '{layer}' was built with an older chunker version. "
                "A full rebuild is required: python3 .wavefoundry/framework/scripts/setup_wavefoundry.py --root . --full",
                recovery_tools=["index_build"],
                recovery_usage="python3 .wavefoundry/framework/scripts/setup_wavefoundry.py --root . --full",
            )
        )
    background_build_status = _background_build_status(index.root)
    if background_build_status == "running":
        diagnostics.append(
            _diagnostic(
                "background_code_build_running",
                "A background code index build is in progress. "
                f"Watch progress: {index.root / '.wavefoundry' / 'logs' / 'project-background-build.log'}",
                recovery_tools=[],
                recovery_usage="index_health()",
            )
        )

    # Wave 1p99o: surface the authoritative index-build lock status so a leftover lock file (present
    # by design, not held) is diagnosable at a glance and agents don't misread its presence as "a build
    # is running."
    health["size"] = _index_dir_size(index.root / ".wavefoundry" / "index")  # wave 1p9a9
    lock_info = _index_build_lock_info(index.root)
    health["lock"] = lock_info
    if (
        lock_info.get("present")
        and not lock_info.get("held")
        and lock_info.get("ended_at") is None
        and lock_info.get("started_at") is not None
    ):
        diagnostics.append(
            _diagnostic(
                "index_build_interrupted",
                "The last index build did NOT finish cleanly (interrupted or killed) — the index may be "
                "partial. Consider a rebuild: index_build(content='all', mode='rebuild'). The lock "
                "file is present but NOT held; do not delete it (it persists by design). Use "
                "index_build_status for the authoritative lock state.",
                recovery_tools=["index_build", "index_build_status"],
                recovery_usage="index_build(content='all', mode='rebuild')",
            )
        )

    _refresh_index_build_stats_from_finished_logs(index.root, "project")
    # Always return "ok" when health data was successfully computed — agents
    # read ``readiness_overview`` and ``diagnostics`` to decide whether to
    # reindex.  Reserve ``status: "error"`` for the except branch above (i.e.
    # when the health check itself crashed, not when the index is merely absent
    # or stale).
    project_stats = _read_index_build_stats_file(index.root, "project")
    if project_stats is not None:
        health["previous_build_stats"] = project_stats

    # Wave 13129 (1316n): graph readiness reported separately from semantic
    # readiness. A consumer caught the silent "rebuild didn't touch graph" misread
    # because there was no breakout. Operators now see graph_present /
    # graph_last_built_at per layer alongside the existing fields.
    health["graph"] = _graph_health_summary(index.root)

    # Wave 1rsh9 (1rq4h): index-state store presence + schema version + two-layer
    # integrity verdict (quick_check + freshness-fingerprint binding). Absence
    # is a normal not-yet-built state, never an error (AC-2/AC-6).
    health["state_store"] = _state_store_health_summary(index.root)
    if health["state_store"].get("integrity") == "structural-fail":
        diagnostics.append(
            _diagnostic(
                "state_store_structural_fail",
                "The index-state store failed its structural integrity check. It is "
                "derived-only: the next index build drops and rebuilds it automatically, "
                "or run index_optimize() to verify and reclaim now.",
                recovery_tools=["index_optimize", "index_build"],
                recovery_usage="index_optimize()",
            )
        )
    # 1sbfj: coverage advisory — a structurally-sound store whose chunk
    # registry/FTS covers materially less than Lance means lexical retrieval
    # is running partially blind (the field defect read as `integrity: ok`).
    # The next index build heals it (the reconcile backfills from Lance,
    # including on zero-change builds).
    _uncovered = [
        f"{t} (registry {c.get('registry_rows')} of {c.get('lance_rows')} Lance rows)"
        for t, c in (health["state_store"].get("chunk_index") or {}).items()
        if c.get("covered") is False
    ]
    if _uncovered:
        diagnostics.append(
            _diagnostic(
                "chunk_index_undercovered",
                "The derived chunk index (FTS/registry) covers materially less than the "
                "Lance tables: " + "; ".join(sorted(_uncovered)) + ". Lexical (BM25) "
                "retrieval is running partially blind until it heals. Rebuild the derived "
                "lexical layer directly (embedding-free, seconds): "
                "index_build(content='fts') — or any ordinary build backfills it.",
                recovery_tools=["index_build", "index_build_status"],
                recovery_usage="index_build(content='fts')",
            )
        )

    semantic_ready = health.get("semantic_ready")
    return _response(
        "ok",
        health,
        diagnostics=diagnostics,
        next_tools=["docs_search"] if semantic_ready else ["index_build"],
        usage="docs_search(query='...')" if semantic_ready else "index_build(content='docs', mode='update')",
    )


# ---------------------------------------------------------------------------
# Agent memory tools (wave 1ro44 / 1p8gy): add / search / brief / reconcile
# ---------------------------------------------------------------------------
#
# The record FILES under docs/agents/memory/ are the source of truth (few,
# small, live); the semantic index is an optional retrieval assist and its
# absence degrades silently. Decay is a ranking view, never a mutation.

# Advisory caps (1p8gy Req 6: named constants, response bloat is a hot-path
# concern). A briefing is a nudge, not a document — five entries is what an
# agent actually reads before acting.
MEMORY_BRIEF_CAP = 5
MEMORY_SEARCH_CAP = 20
MEMORY_PROPOSE_CAP = 20
MEMORY_SUMMARY_EXCERPT_CHARS = 280
MEMORY_BRIEF_CONTEXTS = (
    "session_start", "pre_implementation", "review", "close", "setup", "file_edit",
)


def _memory_mod():
    return _load_script("memory_records")


def _memory_fence(root: Path) -> Optional[str]:
    """Register a WRITER-OWNED fence token BEFORE a record filesystem mutation.
    Returns the token on success; None means the caller must REFUSE the mutation
    (an unfenced write could leave another process serving stale). The token
    must be passed to ``_memory_finalize`` so this writer clears ONLY its own
    fence (a concurrent writer's fence must survive)."""
    try:
        tok = _load_script("index_state_store").memory_fence(
            root / ".wavefoundry" / "index"
        )
        return tok if isinstance(tok, str) and tok else None
    except Exception:
        return None


def _memory_finalize(root: Path, token: Optional[str] = None) -> None:
    """Remove THIS writer's fence token + advance the generation after a
    mutation, and evict the local cache. Best-effort: if the durable finalize
    fails, the token remains so every process keeps bypassing the cache (no
    stale serve) until the next successful mutation or the TTL self-heals it."""
    _MEMORY_RECORDS_CACHE.pop(str(root), None)
    try:
        _load_script("index_state_store").memory_finalize(
            root / ".wavefoundry" / "index", token
        )
    except Exception:
        pass


# Exact lifecycle-id token (v2 scheme): 5-char base36, digit-led, at least one
# letter, bounded by non-alphanumerics so `1abcd` is never found inside
# `1abcde` (delivery-review prefix-collision finding). Mirrors the derivation
# grammar in index_state_store.WAVE_ID_TOKEN.
_LIFECYCLE_ID_TOKEN_RE = re.compile(r"(?<![a-z0-9])(?=[0-9]*[a-z])[0-9][a-z0-9]{4}(?![a-z0-9])")


def _lifecycle_id_tokens(text: str) -> set[str]:
    return set(_LIFECYCLE_ID_TOKEN_RE.findall(str(text).lower()))


# Hot-path caches (delivery-review perf finding): memory advisories fire on
# code_read/code_impact/code_callhierarchy, so re-reading every record file and
# re-decompressing the cluster artifact per call is the wrong cost. Both caches
# are keyed on a cheap on-disk signature and invalidate the instant the backing
# state changes (a memory write bumps the dir signature; a graph rebuild bumps
# the artifact stat). Bounded: one dict entry per repo root.
_MEMORY_RECORDS_CACHE: dict[str, tuple[Any, list[dict[str, Any]]]] = {}
_MEMORY_BETWEENNESS_CACHE: dict[str, tuple[Any, dict[str, float]]] = {}


_MEMORY_KEY_BYPASS = "__bypass__"


def _memory_cache_key(root: Path):
    """Bounded cache key from the durable memory seqlock — NO per-call tree
    walk. One of:
    - ``None`` — the memory root is absent/uncontained (reads → []);
    - ``_MEMORY_KEY_BYPASS`` — the durable state is UNREADABLE or DIRTY (a
      mutation is in flight, or a finalize failed leaving dirty set); the cache
      is bypassed (always reload fresh) so no process serves stale;
    - ``(epoch, generation, dir_mtime_ns)`` — the normal key. The random epoch
      defeats the delete/recreate ABA; the monotonic generation advances on
      every mutation/invalidate across processes; the dir mtime additionally
      catches add/delete/rename.
    """
    mem = _memory_mod()
    mem_dir = mem.canonical_memory_root(root)
    if mem_dir is None or not mem_dir.is_dir():
        return None
    try:
        dir_mtime = int(mem_dir.stat().st_mtime_ns)
    except OSError:
        return None
    state = _load_script("index_state_store").read_memory_state(
        root / ".wavefoundry" / "index"
    )
    if state is None or state.get("dirty"):
        return _MEMORY_KEY_BYPASS
    return (str(state.get("epoch", "")), int(state.get("generation", 0)), dir_mtime)


def _memory_records_cached(root: Path, statuses: Optional[Iterable[str]]) -> list[dict[str, Any]]:
    """All parseable records for ``root``, cached on the bounded key.

    Caches the FULL (all-status) set and filters by status in memory. A key
    change reloads; an unreadable generation BYPASSES the cache (fresh load,
    no store); an absent/uncontained dir → [].
    """
    key_sig = _memory_cache_key(root)
    if key_sig is None:
        return []
    load = _memory_mod().load_memory_records

    def _filter(records):
        if statuses is None:
            return list(records)
        wanted = set(statuses)
        return [r for r in records if r["status"] in wanted]

    if key_sig == _MEMORY_KEY_BYPASS:
        return _filter(load(root))  # durable state unavailable — never cache
    key = str(root)
    cached = _MEMORY_RECORDS_CACHE.get(key)
    if cached and cached[0] == key_sig:
        records = cached[1]
    else:
        records = load(root)  # all statuses
        _MEMORY_RECORDS_CACHE[key] = (key_sig, records)
    return _filter(records)


def _memory_betweenness_by_file(root: Path) -> dict[str, float]:
    """Max persisted betweenness per file from the cluster artifact (top-200).

    Cached on the artifact's (mtime_ns, size) so the gzip decompress runs once
    per graph build, not per advisory call. Graceful absence: {} when the
    artifact is missing/unreadable — ranking falls back to decayed confidence
    alone (AC-12 degrade path).
    """
    path = root / ".wavefoundry" / "index" / "graph" / "project-graph-clusters.json"
    try:
        st = path.stat()
        art_sig = (int(st.st_mtime_ns), int(st.st_size))
    except OSError:
        return {}
    key = str(root)
    cached = _MEMORY_BETWEENNESS_CACHE.get(key)
    if cached and cached[0] == art_sig:
        return cached[1]
    try:
        import gzip
        with gzip.open(path, "rt", encoding="utf-8") as fh:
            data = json.load(fh)
        scores: dict[str, float] = {}
        for entry in (data.get("betweenness") or {}).get("ranking") or []:
            node_id = str(entry.get("node_id") or "")
            file_part = node_id.split("::", 1)[0]
            score = float(entry.get("score") or 0.0)
            if file_part and score > scores.get(file_part, 0.0):
                scores[file_part] = score
        _MEMORY_BETWEENNESS_CACHE[key] = (art_sig, scores)
        return scores
    except Exception:
        return {}


def _memory_view(record: dict[str, Any], decay: dict[str, Any]) -> dict[str, Any]:
    summary = str(record.get("summary") or "")
    view = {
        "memory_id": record["memory_id"],
        "title": record.get("title"),
        "kind": record["kind"],
        "status": record["status"],
        "confidence": record.get("confidence"),
        "effective_confidence": round(float(decay.get("effective_confidence") or 0.0), 3),
        "decay_basis": decay.get("decay_basis"),
        "summary": summary[:MEMORY_SUMMARY_EXCERPT_CHARS],
        "target_refs": record.get("target_refs") or [],
        "evidence_refs": record.get("evidence_refs") or [],
        "path": str(Path(record["path"]).as_posix()) if record.get("path") else None,
        "created_at": record.get("created_at"),
        "updated_at": record.get("updated_at"),
    }
    for key in (
        "source_event", "validation", "validated_by", "action_delta",
        "validation_rationale", "evidence_verified",
        "current_target_verified", "canonical_overlap",
    ):
        if record.get(key) is not None:
            view[key] = record[key]
    if record.get("superseded_by"):
        view["superseded_by"] = record["superseded_by"]
    if decay.get("needs_reverification"):
        view["needs_reverification"] = True
    return view


def _memory_ranked(
    root: Path,
    records: list[dict[str, Any]],
) -> list[tuple[dict[str, Any], dict[str, Any]]]:
    """Decay + centrality-weighted ordering (1p8gy Req 12).

    Primary key: decayed confidence. Tie-band: persisted betweenness of the
    highest-centrality file target (degree/centrality absence degrades to
    flat). Returns [(record, decay)] best-first.

    Freshness is read ONCE for the whole batch (delivery-review perf finding):
    all file targets across the records are collected and their windowed
    commit timestamps fetched in a single store query, then per-record churn
    is computed in memory — no per-target store open, no per-call cluster
    decompress (betweenness is cached).
    """
    mem = _memory_mod()
    index_dir = root / ".wavefoundry" / "index"
    betweenness = _memory_betweenness_by_file(root)

    file_targets = {
        ref for r in records for ref in (r.get("target_refs") or [])
        if not ref.startswith(("symbol:", "community:"))
    }
    commit_times: dict[str, list[int]] = {}
    if file_targets:
        try:
            commit_times = _load_script("index_state_store").file_commit_times(
                index_dir, file_targets
            )
        except Exception:
            commit_times = {}

    def _churn_provider(path: str, since_ts: Optional[int]) -> int:
        times = commit_times.get(path)
        if not times:
            return 0
        if since_ts is None:
            return len(times)
        return sum(1 for t in times if t > since_ts)

    def _centrality(record: dict[str, Any]) -> float:
        best = 0.0
        for ref in record.get("target_refs") or []:
            if ref.startswith(("symbol:", "community:")):
                continue
            best = max(best, betweenness.get(ref, 0.0))
        return best

    scored = []
    for record in records:
        decay = mem.apply_decay(record, index_dir=index_dir, churn_provider=_churn_provider)
        scored.append((record, decay, _centrality(record)))
    scored.sort(
        key=lambda item: (
            -round(float(item[1].get("effective_confidence") or 0.0), 2),
            -item[2],
            item[0]["memory_id"],
        )
    )
    return [(record, decay) for record, decay, _c in scored]


# Per-tool advisory cap on hot read tools (1p8gy Req 6): a nudge in a
# response an agent is reading for OTHER content — three entries max.
MEMORY_ADVISORY_CAP = 3


def _memory_advisories_for_path(root: Path, path: str, symbol: str = "") -> list[dict[str, Any]]:
    """Capped active-memory advisories for a file/symbol (1p8gy AC-5).

    Graceful absence everywhere: no memory directory, no matches, or any
    failure → [] and the host tool's response is unchanged. The empty-match
    short-circuit keeps the hot read tools at directory-scan cost; ranking
    (decay + centrality) runs only when something matched.
    """
    try:
        mem = _memory_mod()
        records = _memory_records_cached(root, mem.DEFAULT_SURFACED_STATUSES)
        if not records:
            return []
        matched = [r for r in records if mem.match_targets(r, path=path, symbol=symbol)]
        if not matched:
            return []
        ranked = _memory_ranked(root, matched)
        surfaced = ranked[:MEMORY_ADVISORY_CAP]
        _credit_exploration_avoided_surface(root, surfaced, [path], mem)
        return [_memory_view(r, d) for r, d in surfaced]
    except Exception:
        return []


def _memory_advisories_for_wave(root: Path, wave: dict[str, Any]) -> list[dict[str, Any]]:
    """Capped advisories relevant to a wave (1p8gy AC-6): records whose
    evidence/target refs mention the wave id or an admitted change id, plus
    any fragile_file advisory flagged needs-reverification. Graceful absence.
    """
    try:
        mem = _memory_mod()
        records = _memory_records_cached(root, mem.DEFAULT_SURFACED_STATUSES)
        if not records:
            return []
        # Exact lifecycle-id token matching (delivery-review finding): collect
        # the wave/change id TOKENS and match refs by whole-token equality, so
        # a memory that references `1abcde` never attaches to wave `1abcd` (the
        # old `ident in ref` substring test did). `_lifecycle_id_tokens` finds
        # 5-char digit-led base36 tokens bounded by non-alphanumerics.
        wave_tokens: set[str] = set()
        wave_id = str(wave.get("wave_id") or wave.get("id") or "")
        if wave_id:
            wave_tokens |= _lifecycle_id_tokens(wave_id)
        for change in wave.get("changes") or []:
            cid = str(change.get("id") or change) if not isinstance(change, str) else change
            if cid:
                wave_tokens |= _lifecycle_id_tokens(cid)
        if not wave_tokens:
            return []

        def _mentions_wave(record: dict[str, Any]) -> bool:
            refs = (record.get("evidence_refs") or []) + (record.get("target_refs") or [])
            return any(_lifecycle_id_tokens(ref) & wave_tokens for ref in refs)

        matched = [r for r in records if _mentions_wave(r)]
        ranked = _memory_ranked(root, matched)
        views = [_memory_view(r, d) for r, d in ranked[:MEMORY_ADVISORY_CAP]]
        # Standing fragile-file warnings that need re-verification surface at
        # lifecycle checkpoints even without a wave-id link.
        if len(views) < MEMORY_ADVISORY_CAP:
            seen = {v["memory_id"] for v in views}
            fragile = [r for r in records
                       if r["kind"] == "fragile_file" and r["memory_id"] not in seen]
            for record, decay in _memory_ranked(root, fragile):
                if decay.get("needs_reverification") and len(views) < MEMORY_ADVISORY_CAP:
                    views.append(_memory_view(record, decay))
        surfaced_matched = [
            pair for pair in ranked[:MEMORY_ADVISORY_CAP]
            if pair[0]["memory_id"] in {view["memory_id"] for view in views}
        ]
        _credit_exploration_avoided_surface(
            root, surfaced_matched, sorted(wave_tokens), mem, evidence_match=True
        )
        return views
    except Exception:
        return []


def _credit_exploration_avoided_surface(
    root: Path,
    surfaced_pairs: list,
    target_list: list,
    mem: Any,
    *,
    evidence_match: bool = False,
) -> None:
    """Fail-isolated 1svuk credit for advisories surfaced by memory_brief.

    Telemetry-only: resolves the current OPEN wave and accrues the SEPARATE,
    labeled estimated-exploration-avoided metric grounded in each surfaced
    record's measured ``source_exploration_cost`` (discounted by a bounded
    attribution). Never raises, never changes the advisory output, and never
    touches the measured Context Efficiency total.
    """
    try:
        # Attribute to the OPEN (active/implementing) wave specifically — not
        # `current_wave`, which returns the first open wave in lifecycle order
        # and can surface a readied (planned) wave that sorts ahead of the
        # implementing one (they coexist under the single-OPEN rule).
        wave = next(
            (w for w in list_waves(root) if w.get("status") in ("active", "implementing")),
            None,
        )
        if not wave:
            return
        wave_id = str(wave.get("wave_id") or wave.get("id") or "").strip()
        if not wave_id:
            return
        ea = _load_script("exploration_avoided")
        items = []
        for record, _decay in surfaced_pairs:
            if evidence_match:
                refs = (
                    list(record.get("evidence_refs") or [])
                    + list(record.get("target_refs") or [])
                )
                matched = bool(target_list) and any(
                    target in _lifecycle_id_tokens(ref)
                    for target in target_list for ref in refs
                )
            else:
                matched = bool(target_list) and any(
                    mem.match_targets(record, path=t) for t in target_list
                )
            if not matched:
                continue
            origin_tokens: set[str] = set()
            for ref in record.get("evidence_refs") or []:
                origin_tokens |= _lifecycle_id_tokens(str(ref))
            items.append({
                "memory_id": record.get("memory_id"),
                "source_origin": (
                    sorted(origin_tokens)[0]
                    if origin_tokens else record.get("memory_id")
                ),
                "source_exploration_cost": record.get("source_exploration_cost"),
                "match_confidence": 1.0,
            })
        context_key = json.dumps(
            sorted({str(target) for target in target_list}),
            ensure_ascii=False,
            separators=(",", ":"),
        )
        ea.credit_surface(
            root, wave_id, items, cited=False, context_key=context_key
        )
    except Exception:
        return


def memory_add_response(
    root: Path,
    kind: str,
    summary: str,
    evidence: list,
    targets: list,
    title: str = "",
    confidence: float = 0.6,
    status: str = "candidate",
    supersedes: str = "",
    memory_id: str = "",
    abort_if_duplicate: bool = False,
) -> dict[str, Any]:
    """Validate without mutation, then serialize duplicate scan + write."""
    return _memory_add_response_locked(
        root, kind, summary, evidence, targets, title=title,
        confidence=confidence, status=status, supersedes=supersedes,
        memory_id=memory_id, abort_if_duplicate=abort_if_duplicate,
    )


def _memory_add_response_locked(
    root: Path,
    kind: str,
    summary: str,
    evidence: list,
    targets: list,
    title: str = "",
    confidence: float = 0.6,
    status: str = "candidate",
    supersedes: str = "",
    memory_id: str = "",
    abort_if_duplicate: bool = False,
    _lock_held: bool = False,
    _source_event: str = "",
    _validation: str = "",
    _validated_by: str = "",
    _action_delta: str = "",
    _validation_rationale: str = "",
    _evidence_verified: Optional[bool] = None,
    _current_target_verified: Optional[bool] = None,
    _canonical_overlap: str = "",
    _defer_index_refresh: bool = False,
) -> dict[str, Any]:
    mem = _memory_mod()
    problems: list[str] = []
    kind = (kind or "").strip()
    status = (status or "candidate").strip()
    evidence = [str(e).strip() for e in (evidence or []) if str(e).strip()]
    targets = [str(t).strip() for t in (targets or []) if str(t).strip()]
    if kind not in mem.MEMORY_KINDS:
        problems.append(f"unknown kind {kind!r}; allowed: {', '.join(mem.MEMORY_KINDS)}")
    if status not in ("candidate", "active"):
        problems.append("new records start as 'candidate' or 'active' — other statuses are reconciliation outcomes")
    if not (summary or "").strip():
        problems.append("summary is required (the lesson, phrased as what changes the next action)")
    if not evidence:
        problems.append("evidence refs are required — memory without evidence is opinion")
    if not targets:
        problems.append("target refs are required — an advisory needs something to attach to")
    try:
        confidence = float(confidence)
        if not 0.0 <= confidence <= 1.0:
            raise ValueError
    except (TypeError, ValueError):
        problems.append("confidence must be a number in [0.0, 1.0]")
    # Security boundary (delivery-review finding 2026-07-13): ids are path
    # components — validate caller-supplied ids and supersedes references
    # against the memory-id grammar BEFORE any filesystem access.
    for label, value in (("memory_id", memory_id), ("supersedes", supersedes)):
        if value:
            try:
                mem.validate_memory_id(value)
            except ValueError as exc:
                problems.append(f"{label}: {exc}")
    # Forbidden-content pre-write scan (1p8gy Req 8). Delivery-review finding:
    # scan EVERY caller-controlled field that gets persisted (title + summary +
    # evidence + targets), and NEVER echo the rejected line — the diagnostic
    # names the offending field only, so a secret is not repeated back into
    # logs/responses.
    try:
        from wave_lint_lib.constants import MEMORY_DISALLOWED_PATTERNS as _FORBIDDEN
    except ImportError:
        _FORBIDDEN = ()
    _scanned_fields = (
        ("title", [title or ""]),
        ("summary", [summary or ""]),
        ("evidence", list(evidence)),
        ("targets", list(targets)),
    )
    _forbidden_fields: list[str] = []
    for field_name, chunks in _scanned_fields:
        hit = False
        for chunk in chunks:
            for line in str(chunk).splitlines():
                if any(p.search(line) for p in _FORBIDDEN):
                    hit = True
                    break
            if hit:
                break
        if hit:
            _forbidden_fields.append(field_name)
    if _forbidden_fields:
        problems.append(
            "content looks like a secret, raw transcript, or personal fact in "
            f"{', '.join(_forbidden_fields)} — forbidden by the memory schema "
            "(the offending text is not echoed back)"
        )
    if problems:
        return _response(
            "error",
            {"written": False, "problems": problems},
            diagnostics=[_diagnostic(
                "invalid_memory_record", "; ".join(problems),
                recovery_tools=["memory_add"],
                recovery_usage="memory_add(kind='fragile_file', summary=..., evidence=[...], targets=[...])",
            )],
            next_tools=["memory_add"],
            usage="",
        )
    if not _lock_held:
        with review_event_write_lock(root):
            return _memory_add_response_locked(
                root, kind, summary, evidence, targets, title=title,
                confidence=confidence, status=status, supersedes=supersedes,
                memory_id=memory_id, abort_if_duplicate=abort_if_duplicate,
                _lock_held=True,
                _source_event=_source_event, _validation=_validation,
                _validated_by=_validated_by, _action_delta=_action_delta,
                _validation_rationale=_validation_rationale,
                _evidence_verified=_evidence_verified,
                _current_target_verified=_current_target_verified,
                _canonical_overlap=_canonical_overlap,
            )
    explicit = bool(memory_id)
    base_id = memory_id or f"mem-{mem.slugify(title or summary)}"

    # Duplicate detection (wave 1stwl) — DETECTION ONLY. Compare a pseudo-record
    # of this add against existing active/candidate records. Non-blocking by
    # default (the record is still written and a possible_duplicate advisory is
    # attached); with abort_if_duplicate the write is refused without mutating
    # anything. Detection never marks superseded/merges/deletes.
    _dup_matches = mem.find_duplicates(
        {"memory_id": memory_id or "", "kind": kind, "summary": summary,
         "evidence_refs": list(evidence), "target_refs": list(targets),
         "status": status},
        mem.load_memory_records(root, statuses=("active", "candidate")),
    )

    def _dup_phrase() -> str:
        return ", ".join(
            f"{m['memory_id']} ({'/'.join(m['signals'])})" for m in _dup_matches
        )

    if _dup_matches and abort_if_duplicate:
        return _response(
            "error", {"written": False, "duplicates": _dup_matches},
            diagnostics=[_diagnostic(
                "possible_duplicate",
                "Refused: possible duplicate of " + _dup_phrase()
                + " (abort_if_duplicate=True; nothing was written or changed).",
                recovery_tools=["memory_search", "memory_add"],
                recovery_usage="memory_add(..., abort_if_duplicate=False) to write anyway")],
            next_tools=["memory_search"], usage="",
        )

    def _render(mid: str) -> str:
        return mem.render_memory_record(
            memory_id=mid, kind=kind, summary=summary, evidence=evidence,
            targets=targets, title=title, confidence=confidence, status=status,
            supersedes=supersedes,
            source_event=_source_event, validation=_validation,
            validated_by=_validated_by, action_delta=_action_delta,
            validation_rationale=_validation_rationale,
            evidence_verified=_evidence_verified,
            current_target_verified=_current_target_verified,
            canonical_overlap=_canonical_overlap,
        )

    # Fence the durable seqlock BEFORE any filesystem write (delivery-review
    # round 4): if the fence cannot be established, refuse the mutation — an
    # unfenced write could leave a second MCP process serving a stale advisory.
    # The token is writer-owned; finalize clears ONLY this token.
    _fence_token = _memory_fence(root)
    if _fence_token is None:
        return _response(
            "error", {"written": False},
            diagnostics=[_diagnostic(
                "memory_state_unwritable",
                "Cannot establish the memory-state fence (memory-state.sqlite is "
                "unwritable). Refusing the write so no process serves a stale advisory.",
                recovery_tools=["memory_add"], recovery_usage="")],
            next_tools=["memory_add"], usage="",
        )
    diagnostics: list[dict[str, Any]] = []
    if _dup_matches:
        diagnostics.append(_diagnostic(
            "possible_duplicate",
            "Written as requested, but this record possibly duplicates "
            + _dup_phrase() + " — detection only; reconcile explicitly if it is "
            "a duplicate (nothing was auto-superseded or merged).",
            recovery_tools=["memory_search", "memory_reconcile"],
            recovery_usage="memory_search(target=...) to compare"))
    try:
        # Atomic creation: exclusive-create, retry only generated-id
        # collisions, surface the conflict for an explicit id. No TOCTOU.
        try:
            path, memory_id = mem.create_memory_record(root, _render, base_id, explicit=explicit)
        except ValueError as exc:
            return _response(
                "error", {"written": False},
                diagnostics=[_diagnostic("invalid_memory_record", str(exc),
                                         recovery_tools=["memory_add"],
                                         recovery_usage="memory_add(memory_id='mem-<kebab-slug>', ...)")],
                next_tools=["memory_add"], usage="",
            )
        except FileExistsError as exc:
            return _response(
                "error", {"written": False},
                diagnostics=[_diagnostic("memory_record_exists", str(exc),
                                         recovery_tools=["memory_reconcile"],
                                         recovery_usage=f"memory_reconcile(memory_id={base_id!r}, status='superseded', superseded_by=<new id>)")],
                next_tools=["memory_search"], usage="",
            )
        if supersedes:
            try:
                mem.reconcile_memory_record(root, supersedes, "superseded", superseded_by=memory_id)
            except (FileNotFoundError, ValueError) as exc:
                diagnostics.append(_diagnostic(
                    "supersedes_target_not_updated",
                    f"The new record was written but {supersedes!r} could not be marked superseded: {exc}",
                    recovery_tools=["memory_reconcile"],
                    recovery_usage=f"memory_reconcile(memory_id={supersedes!r}, status='superseded', superseded_by={memory_id!r})",
                ))
    finally:
        # Clear THIS writer's fence + advance the generation. A concurrent
        # writer's fence survives (only our token is removed).
        _memory_finalize(root, _fence_token)
    if not _defer_index_refresh:
        _trigger_background_index_refresh_for_paths(root, [path])
    record = mem.parse_memory_record(path)
    decay = mem.apply_decay(record, index_dir=root / ".wavefoundry" / "index") if record else {}
    return _response(
        "ok",
        {"written": True, "record": _memory_view(record, decay) if record else {"memory_id": memory_id}},
        diagnostics=diagnostics,
        next_tools=["memory_search", "memory_brief"],
        usage=f"memory_search(target={targets[0]!r})",
    )


def _draft_view(d: dict[str, Any]) -> dict[str, Any]:
    return {
        "kind": d["kind"], "title": d["title"], "summary": d["summary"],
        "evidence": list(d["evidence"]), "targets": list(d["targets"]),
        "source_event": d["source_event"],
        "source_exploration_cost": d["source_exploration_cost"],
    }


def memory_propose_response(
    root: Path,
    wave_id: str = "",
    mode: str = "dry_run",
    limit: int = MEMORY_PROPOSE_CAP,
    *,
    _defer_index_refresh: bool = False,
) -> dict[str, Any]:
    """Serialize create-mode duplicate scan + batch write as one operation."""
    lock = (
        review_event_write_lock(root)
        if (mode or "").strip() == "create"
        else contextlib.nullcontext()
    )
    with lock:
        return _memory_propose_response_locked(
            root,
            wave_id=wave_id,
            mode=mode,
            limit=limit,
            defer_index_refresh=_defer_index_refresh,
        )


def _memory_propose_response_locked(
    root: Path,
    wave_id: str = "",
    mode: str = "dry_run",
    limit: int = MEMORY_PROPOSE_CAP,
    *,
    defer_index_refresh: bool = False,
) -> dict[str, Any]:
    """Draft candidate memory records from a wave's typed review evidence.

    Reads the wave's ``events.jsonl`` heads + admitted change-doc Decision Logs
    and drafts durable-shaped ``candidate`` records (never auto-promoted).
    ``dry_run`` (default) returns the drafts; ``create`` writes them through the
    existing candidate write path, skipping exact/normalized duplicates so
    re-runs are idempotent (1stwl detector). Local-only, read-then-draft.
    """
    mem = _memory_mod()
    supply = _load_script("memory_supply")
    wave_id = (wave_id or "").strip()
    mode = (mode or "dry_run").strip()
    if mode not in ("dry_run", "create"):
        return _response(
            "error", {"valid_modes": ["dry_run", "create"]},
            diagnostics=[_diagnostic(
                "invalid_arguments", f"unknown mode {mode!r}; use 'dry_run' or 'create'",
                recovery_tools=["memory_propose"],
                recovery_usage="memory_propose(wave_id='<id>', mode='dry_run')")],
            next_tools=["memory_propose"], usage="")
    if not wave_id:
        return _response(
            "error", {"proposed": []},
            diagnostics=[_diagnostic(
                "invalid_arguments", "provide a wave_id to draft memory candidates from",
                recovery_tools=["wf_current_wave", "memory_propose"],
                recovery_usage="memory_propose(wave_id='<id>')")],
            next_tools=["wf_current_wave"], usage="")
    try:
        n = max(1, min(int(limit), MEMORY_PROPOSE_CAP))
    except (TypeError, ValueError):
        n = MEMORY_PROPOSE_CAP
    _wave_dir, wave_error = supply.resolve_wave_dir(root, wave_id)
    if wave_error:
        return _response(
            "error",
            {"proposed": [], "records_proposed": 0, "records_promoted": 0,
             "records_written": 0},
            diagnostics=[_diagnostic(
                wave_error,
                "Wave id is ambiguous." if wave_error == "ambiguous_wave_id"
                else "Wave was not found.",
                recovery_tools=["wf_list_waves", "memory_propose"],
                recovery_usage="wf_list_waves()")],
            next_tools=["wf_list_waves"], usage="")
    # Read the complete eligible set, then page AFTER suppressing durable
    # dispositions. Otherwise the first 20 already-validated sources would
    # permanently hide source 21+ on every subsequent run.
    drafts = supply.draft_candidates(root, wave_id, limit=None)

    # Idempotent supply (AC-5): skip a draft whose (kind, targets, normalized
    # summary) already exists (existing corpus + earlier in this run). The
    # shared wave-id evidence ref is deliberately NOT a skip reason — every
    # same-wave draft carries it — so dedup keys on normalized_content only.
    accumulated = list(mem.load_memory_records(root))
    disposition_sources = {
        str(record.get("source_event") or "")
        for record in accumulated
        if record.get("source_event")
    }
    unique: list[dict[str, Any]] = []
    eligible_count = 0
    skipped_duplicates = 0
    skipped_dispositions = 0
    for d in drafts:
        if d["source_event"] in disposition_sources:
            skipped_dispositions += 1
            continue
        pseudo = {"memory_id": "", "kind": d["kind"], "summary": d["summary"],
                  "evidence_refs": list(d["evidence"]), "target_refs": list(d["targets"]),
                  "status": "candidate"}
        matches = mem.find_duplicates(pseudo, accumulated)
        if any("normalized_content" in m["signals"] for m in matches):
            skipped_duplicates += 1
            continue
        eligible_count += 1
        if len(unique) < n:
            unique.append(d)
        # Continue tracking the complete eligible set after the response page
        # fills. This lets the coordinator distinguish an exactly-full final
        # page from a page with additional durable sources without returning
        # those source bodies.
        accumulated.append(pseudo)
        disposition_sources.add(d["source_event"])

    if not drafts:
        return _response(
            "ok",
            {"proposed": [], "records_proposed": 0, "records_promoted": 0,
             "records_written": 0,
             "skipped_duplicates": 0, "skipped_dispositions": 0, "mode": mode},
            diagnostics=[_diagnostic(
                "no_material_evidence",
                "No durable-shaped evidence to draft from this wave (Decision Logs "
                "with a code anchor, or repaired real-defect findings). Sparse by design.",
                recovery_tools=["memory_propose"], recovery_usage="")],
            next_tools=["memory_search"], usage="")

    if mode == "dry_run":
        return _response(
            "ok",
            {"proposed": [_draft_view(d) for d in unique],
             "records_proposed": len(unique), "records_promoted": 0,
             "records_written": 0,
             "records_remaining": max(0, eligible_count - len(unique)),
             "exhausted": eligible_count <= len(unique),
             "skipped_duplicates": skipped_duplicates,
             "skipped_dispositions": skipped_dispositions, "mode": "dry_run"},
            diagnostics=[], next_tools=["memory_propose"],
            usage=f"memory_propose(wave_id={wave_id!r}, mode='create')")

    # create: fence the seqlock, then write each unique draft as a candidate.
    try:
        from wave_lint_lib.constants import MEMORY_DISALLOWED_PATTERNS as _FORBIDDEN
    except ImportError:
        _FORBIDDEN = ()
    _fence_token = _memory_fence(root)
    if _fence_token is None:
        return _response(
            "error", {"written": []},
            diagnostics=[_diagnostic(
                "memory_state_unwritable",
                "Cannot establish the memory-state fence; refusing the batch write.",
                recovery_tools=["memory_propose"], recovery_usage="")],
            next_tools=["memory_propose"], usage="")
    written: list[dict[str, Any]] = []
    diagnostics: list[dict[str, Any]] = []
    try:
        for d in unique:
            fields = [d["summary"], d["title"], *d["evidence"], *d["targets"]]
            if any(p.search(line) for f in fields
                   for line in str(f).splitlines() for p in _FORBIDDEN):
                diagnostics.append(_diagnostic(
                    "memory_draft_skipped_forbidden",
                    f"A draft from {d['source_event']} was skipped: content matched a "
                    "forbidden pattern (not echoed).",
                    recovery_tools=[], recovery_usage=""))
                continue
            base_id = f"mem-{mem.slugify(d['title'] or d['summary'])}"

            def _render(mid: str, _d: dict[str, Any] = d) -> str:
                return mem.render_memory_record(
                    memory_id=mid, kind=_d["kind"], summary=_d["summary"],
                    evidence=list(_d["evidence"]), targets=list(_d["targets"]),
                    title=_d["title"], status="candidate",
                    source_exploration_cost=_d["source_exploration_cost"],
                    source_event=_d["source_event"], validation="pending")

            try:
                path, mid = mem.create_memory_record(root, _render, base_id, explicit=False)
                written.append({
                    "memory_id": mid, "kind": d["kind"],
                    "path": str(path.relative_to(root)).replace("\\", "/"),
                    "source_event": d["source_event"]})
            except (ValueError, FileExistsError, OSError) as exc:
                diagnostics.append(_diagnostic(
                    "memory_draft_write_failed",
                    f"A draft from {d['source_event']} could not be written: {exc}",
                    recovery_tools=[], recovery_usage=""))
    finally:
        _memory_finalize(root, _fence_token)
    if written and not defer_index_refresh:
        _trigger_background_index_refresh_for_paths(root, [root / w["path"] for w in written])
    return _response(
        "ok",
        {"proposed": [_draft_view(d) for d in unique], "written": written,
         "records_proposed": len(unique), "records_promoted": 0,
         "records_written": len(written),
         "records_remaining": max(0, eligible_count - len(unique)),
         "exhausted": eligible_count <= len(unique),
         "skipped_duplicates": skipped_duplicates,
         "skipped_dispositions": skipped_dispositions, "mode": "create"},
        diagnostics=diagnostics,
        next_tools=["memory_validate", "memory_search"],
        usage="memory_validate(memory_id=<id>, verdict='promote', action_delta=..., rationale=..., evidence_verified=True, current_target_verified=True, canonical_overlap='none')")


def memory_backfill_response(
    root: Path,
    mode: str = "dry_run",
    limit: int = 20,
    *,
    entry_path: str = "manual",
) -> dict[str, Any]:
    """Inventory and mechanically draft one bounded historical-memory batch."""

    backfill = _load_script("memory_backfill")
    mode_s = str(mode or "dry_run").strip().lower()
    if mode_s not in {"dry_run", "create"}:
        return _response(
            "error",
            {"mode": mode_s},
            diagnostics=[_diagnostic("invalid_arguments", "mode must be dry_run or create")],
            next_tools=["memory_backfill"],
        )
    entry_path_s = str(entry_path or "manual").strip().lower()
    if entry_path_s not in backfill.ENTRY_PATHS:
        return _response(
            "error",
            {
                "valid_entry_paths": sorted(backfill.ENTRY_PATHS),
            },
            diagnostics=[
                _diagnostic(
                    "invalid_arguments",
                    "entry_path must be manual, setup, or upgrade",
                )
            ],
            next_tools=["memory_backfill"],
        )
    try:
        candidate_budget = max(1, min(int(limit), backfill.MAX_CANDIDATES_PER_CALL))
    except (TypeError, ValueError):
        candidate_budget = backfill.MAX_CANDIDATES_PER_CALL
    try:
        inventory = backfill.inventory_closed_waves(root)
    except OSError as exc:
        return _response(
            "error",
            {"mode": mode_s, "entry_path": entry_path_s},
            diagnostics=[
                _diagnostic(
                    "historical_memory_inventory_failed",
                    f"Historical wave inventory was refused: {exc}",
                    recovery_tools=["memory_backfill"],
                    recovery_usage="repair the local docs/waves path, then retry",
                )
            ],
            next_tools=["memory_backfill"],
        )
    if mode_s == "dry_run":
        return _response(
            "dry_run",
            {
                "mode": mode_s,
                "entry_path": entry_path_s,
                "eligible_waves": sum(
                    1 for item in inventory if item["status"] in backfill._CLOSED_STATES
                ),
                "unsupported_waves": sum(
                    1 for item in inventory if item["status"] == "unsupported"
                ),
                "unreadable_waves": sum(
                    1 for item in inventory if item["status"] == "unreadable"
                ),
                "limits": {
                    "waves": backfill.MAX_WAVES_PER_CALL,
                    "candidates": candidate_budget,
                    "response_bytes": backfill.MAX_RESPONSE_BYTES,
                },
            },
            next_tools=["memory_backfill"],
            usage="memory_backfill(mode='create')",
        )

    processed: list[dict[str, Any]] = []
    with review_event_write_lock(root):
        run_id = backfill.ensure_run(root, entry_path_s)
        backfill.sync_inventory(root, run_id, inventory=inventory)
        for _ in range(backfill.MAX_WAVES_PER_CALL):
            if candidate_budget <= 0:
                break
            claim = backfill.claim_next(root, run_id)
            if claim is None:
                break
            wave_id = claim["wave_id"]
            try:
                proposed = _memory_propose_response_locked(
                    root,
                    wave_id=wave_id,
                    mode="create",
                    limit=candidate_budget,
                    defer_index_refresh=True,
                )
                if proposed.get("status") != "ok":
                    message = "; ".join(
                        str(item.get("message") or item.get("code") or "backfill failed")
                        for item in proposed.get("diagnostics", [])
                    )
                    backfill.fail_claim(
                        root, run_id, wave_id, claim["claim_token"], message
                    )
                    processed.append(
                        {"wave_id": wave_id, "outcome": "failed", "error": message}
                    )
                    continue
                data = proposed.get("data", {})
                count = int(data.get("records_written") or 0)
                unique_count = int(data.get("records_proposed") or 0)
                draft_write_failures = [
                    item
                    for item in proposed.get("diagnostics", [])
                    if item.get("code")
                    in {"memory_draft_skipped_forbidden", "memory_draft_write_failed"}
                ]
                if draft_write_failures:
                    message = "; ".join(
                        str(item.get("message") or item.get("code"))
                        for item in draft_write_failures
                    )
                    backfill.fail_claim(
                        root, run_id, wave_id, claim["claim_token"], message
                    )
                    processed.append(
                        {"wave_id": wave_id, "outcome": "failed", "error": message}
                    )
                    continue
                no_source = any(
                    item.get("code") == "no_material_evidence"
                    for item in proposed.get("diagnostics", [])
                )
                supply = _load_script("memory_supply")
                wave_dir, _wave_error = supply.resolve_wave_dir(root, wave_id)
                ledger_errors: tuple[str, ...] = ()
                if wave_dir is not None:
                    _ledger_rows, ledger_errors = read_review_event_ledger(wave_dir)
                if no_source and ledger_errors:
                    outcome = "unsupported"
                else:
                    outcome = "no_source" if no_source else "extracted"
                exhausted = no_source or bool(data.get("exhausted"))
                source_records = list(data.get("written") or ())
                # Crash recovery: a previous attempt may have committed the
                # candidate file but died before completing the SQLite claim.
                # Recover stable source identities from the current record
                # corpus so the pending-validation census cannot go false-zero.
                if wave_dir is not None:
                    source_events = {
                        str(draft.get("source_event") or "")
                        for draft in supply.draft_candidates(root, wave_id, limit=None)
                    }
                    for record in _memory_mod().load_memory_records(root):
                        if str(record.get("source_event") or "") in source_events:
                            source_records.append(
                                {
                                    "source_event": record.get("source_event"),
                                    "memory_id": record.get("memory_id"),
                                }
                            )
                backfill.complete_claim(
                    root,
                    run_id,
                    wave_id,
                    claim["claim_token"],
                    outcome=outcome,
                    candidate_count=count,
                    source_records=source_records,
                    exhausted=exhausted,
                )
                candidate_budget -= count
                processed.append(
                    {
                        "wave_id": wave_id,
                        "outcome": outcome,
                        "candidates_written": count,
                        "exhausted": exhausted,
                    }
                )
            except Exception as exc:  # noqa: BLE001 — persist exact failed wave
                backfill.fail_claim(
                    root, run_id, wave_id, claim["claim_token"], str(exc)
                )
                processed.append(
                    {"wave_id": wave_id, "outcome": "failed", "error": str(exc)}
                )
        summary = backfill.run_summary(root, run_id)
        worklist = backfill.validation_worklist(
            root, run_id, limit=backfill.MAX_CANDIDATES_PER_CALL
        )
    payload = {
        **summary,
        **worklist,
        "mode": "create",
        "processed": processed,
        "limits": {
            "waves": backfill.MAX_WAVES_PER_CALL,
            "candidates": min(
                int(limit) if isinstance(limit, int) else backfill.MAX_CANDIDATES_PER_CALL,
                backfill.MAX_CANDIDATES_PER_CALL,
            ),
            "response_bytes": backfill.MAX_RESPONSE_BYTES,
        },
    }
    if len(json.dumps(payload, ensure_ascii=False).encode("utf-8")) > backfill.MAX_RESPONSE_BYTES:
        payload["processed"] = [
            {
                key: (
                    str(value)[:2048]
                    if key in {"error", "message"}
                    else value
                )
                for key, value in row.items()
            }
            for row in processed[:1]
        ]
        payload["last_failure"] = str(payload.get("last_failure") or "")[:2048]
        payload["response_truncated"] = True
    if len(json.dumps(payload, ensure_ascii=False).encode("utf-8")) > backfill.MAX_RESPONSE_BYTES:
        # Retain the run-level state/census contract and drop only per-wave
        # presentation detail. Candidate bodies never appear in this response.
        payload["processed"] = []
        payload["last_failure"] = str(payload.get("last_failure") or "")[:256]
    if summary["state"] == "awaiting_validation":
        next_tools = ["memory_validate", "memory_backfill"]
        usage = (
            "validate each data.validation_worklist[].memory_id, then call "
            "memory_backfill(mode='create') for the next exact page"
        )
    elif entry_path_s == "upgrade":
        next_tools = ["wf_upgrade"]
        usage = "wf_upgrade(phase='resume_after_memory')"
    elif entry_path_s == "setup":
        next_tools = []
        usage = "Rerun ordinary `wf setup`; it resumes the durable setup run."
    else:
        next_tools = []
        usage = "Historical memory validation is complete."
    return _response(
        "ok",
        payload,
        diagnostics=[],
        next_tools=next_tools,
        usage=usage,
    )


def _memory_file_target_exists(root: Path, target: str) -> bool:
    """Best-effort current-tree proof for a file target; symbols are agent-verified."""
    target = str(target or "").strip().strip("`")
    if not target or target.startswith(("symbol:", "community:")):
        return True
    direct = root / target
    if direct.is_file():
        return True
    name = Path(target).name
    if not name:
        return False
    try:
        return any(
            path.is_file()
            and str(path.relative_to(root)).replace("\\", "/").endswith(target)
            for path in root.rglob(name)
        )
    except OSError:
        return False


def memory_validate_response(
    root: Path,
    memory_id: str,
    verdict: str,
    action_delta: str,
    rationale: str,
    evidence_verified: bool,
    current_target_verified: bool,
    canonical_overlap: str,
    *,
    rewrite_kind: str = "",
    rewrite_title: str = "",
    rewrite_summary: str = "",
    rewrite_evidence: Optional[list] = None,
    rewrite_targets: Optional[list] = None,
    rewrite_confidence: float = 0.8,
) -> dict[str, Any]:
    """Record a focused agent judgment over one evidence-derived candidate."""
    mem = _memory_mod()
    memory_id = str(memory_id or "").strip()
    verdict = str(verdict or "").strip()
    canonical_overlap = str(canonical_overlap or "").strip()
    problems: list[str] = []
    try:
        mem.validate_memory_id(memory_id)
    except ValueError as exc:
        problems.append(str(exc))
    if verdict not in ("promote", "retain", "reject", "rewrite"):
        problems.append("verdict must be promote, retain, reject, or rewrite")
    if canonical_overlap not in ("none", "supplements", "duplicates"):
        problems.append("canonical_overlap must be none, supplements, or duplicates")
    for label, value in (("action_delta", action_delta), ("rationale", rationale)):
        value = str(value or "")
        if not value.strip() or any(c in value for c in ("\r", "\n")):
            problems.append(f"{label} must be a non-empty single line")
    if verdict in ("promote", "retain", "rewrite"):
        if not evidence_verified:
            problems.append(f"{verdict} requires evidence_verified=True")
        if not current_target_verified:
            problems.append(f"{verdict} requires current_target_verified=True")
        if canonical_overlap == "duplicates":
            problems.append(
                f"{verdict} cannot duplicate a canonical contract; reject the draft"
            )
    rewrite_evidence = [
        str(value).strip() for value in (rewrite_evidence or []) if str(value).strip()
    ]
    rewrite_targets = [
        str(value).strip() for value in (rewrite_targets or []) if str(value).strip()
    ]
    if verdict == "rewrite":
        if rewrite_kind not in mem.MEMORY_KINDS:
            problems.append(f"rewrite_kind must be one of {', '.join(mem.MEMORY_KINDS)}")
        if not str(rewrite_summary or "").strip():
            problems.append("rewrite_summary is required for rewrite")
        if not rewrite_evidence:
            problems.append("rewrite_evidence is required for rewrite")
        if not rewrite_targets:
            problems.append("rewrite_targets is required for rewrite")
        try:
            rewrite_confidence = float(rewrite_confidence)
            if not 0.0 <= rewrite_confidence <= 1.0:
                raise ValueError
        except (TypeError, ValueError):
            problems.append("rewrite_confidence must be a number in [0.0, 1.0]")
    # Every caller-controlled field that can reach the record must pass the
    # same pre-write forbidden-content boundary as memory_add. Report only
    # field names so rejected secrets never echo into responses or logs.
    try:
        from wave_lint_lib.constants import MEMORY_DISALLOWED_PATTERNS as _FORBIDDEN
    except ImportError:
        _FORBIDDEN = ()
    validation_fields = (
        ("action_delta", [action_delta]),
        ("rationale", [rationale]),
        ("rewrite_title", [rewrite_title]),
        ("rewrite_summary", [rewrite_summary]),
        ("rewrite_evidence", rewrite_evidence),
        ("rewrite_targets", rewrite_targets),
    )
    forbidden_fields: list[str] = []
    for field_name, chunks in validation_fields:
        if any(
            pattern.search(line)
            for chunk in chunks
            for line in str(chunk).splitlines()
            for pattern in _FORBIDDEN
        ):
            forbidden_fields.append(field_name)
    if forbidden_fields:
        problems.append(
            "content looks like a secret, raw transcript, or personal fact in "
            f"{', '.join(forbidden_fields)} — forbidden by the memory schema "
            "(the offending text is not echoed back)"
        )
    if problems:
        return _response(
            "error", {"validated": False, "problems": problems},
            diagnostics=[_diagnostic(
                "invalid_memory_validation", "; ".join(problems),
                recovery_tools=["memory_validate"], recovery_usage="")],
            next_tools=["memory_validate"], usage="")

    with review_event_write_lock(root):
        records = {record["memory_id"]: record for record in mem.load_memory_records(root)}
        record = records.get(memory_id)
        if record is None:
            return _response(
                "error", {"validated": False},
                diagnostics=[_diagnostic(
                    "memory_record_not_found", f"Memory record {memory_id!r} was not found.",
                    recovery_tools=["memory_search"], recovery_usage="memory_search()")],
                next_tools=["memory_search"], usage="")
        if not record.get("source_event"):
            return _response(
                "error", {"validated": False},
                diagnostics=[_diagnostic(
                    "memory_not_evidence_derived",
                    "Only evidence-derived records carrying Source event can use agent validation.",
                    recovery_tools=["memory_reconcile"], recovery_usage="")],
                next_tools=["memory_reconcile"], usage="")
        if record.get("validation") != "pending":
            return _response(
                "error", {"validated": False, "record": _memory_view(record, {})},
                diagnostics=[_diagnostic(
                    "memory_validation_not_pending",
                    "Agent validation requires an evidence-derived candidate with "
                    "Validation: pending. Finalized or malformed records are not rewritten "
                    "implicitly.",
                    recovery_tools=["memory_search"],
                    recovery_usage="memory_search(include_history=True)")],
                next_tools=["memory_search"], usage="")
        backfill_run = _load_script("memory_backfill").paused_run_for_source(
            root, str(record.get("source_event") or "")
        )
        missing_targets = [
            target for target in record.get("target_refs") or []
            if not _memory_file_target_exists(root, target)
        ]
        if verdict in ("promote", "retain", "rewrite") and missing_targets:
            return _response(
                "error", {"validated": False, "missing_targets": missing_targets},
                diagnostics=[_diagnostic(
                    "memory_target_not_current",
                    "One or more file targets are not present in the current tree.",
                    recovery_tools=["memory_validate"], recovery_usage="")],
                next_tools=["memory_validate"], usage="")

        rewritten: Optional[dict[str, Any]] = None
        if verdict == "rewrite":
            # A previous attempt may have created the replacement and then
            # failed while superseding the source. Reuse that exact corrected
            # record so retry converges instead of creating suffixed duplicates.
            existing_rewrite = next((
                candidate for candidate in records.values()
                if candidate["memory_id"] != memory_id
                and candidate.get("source_event") == record["source_event"]
                and candidate.get("validation") == "promote"
                and candidate.get("status") == "active"
                and candidate.get("kind") == rewrite_kind
                and candidate.get("summary") == str(rewrite_summary).strip()
                and sorted(candidate.get("evidence_refs") or [])
                == sorted(rewrite_evidence)
                and sorted(candidate.get("target_refs") or [])
                == sorted(rewrite_targets)
                and (not rewrite_title or candidate.get("title") == rewrite_title)
            ), None)
            if existing_rewrite is not None:
                rewritten = _memory_view(existing_rewrite, {})
            else:
                add = _memory_add_response_locked(
                    root, rewrite_kind, rewrite_summary, rewrite_evidence, rewrite_targets,
                    title=rewrite_title, confidence=rewrite_confidence, status="active",
                    abort_if_duplicate=False, _lock_held=True,
                    _source_event=record["source_event"], _validation="promote",
                    _validated_by="agent", _action_delta=str(action_delta).strip(),
                    _validation_rationale=str(rationale).strip(),
                    _evidence_verified=True, _current_target_verified=True,
                    _canonical_overlap=canonical_overlap,
                    _defer_index_refresh=bool(backfill_run),
                )
                if add.get("status") != "ok" or not add.get("data", {}).get("written"):
                    return _response(
                        "error", {"validated": False, "rewrite": add},
                        diagnostics=[_diagnostic(
                            "memory_rewrite_create_failed",
                            "The corrected record was not created; the source candidate is unchanged.",
                            recovery_tools=["memory_validate"], recovery_usage="")],
                        next_tools=["memory_validate"], usage="")
                rewritten = add["data"]["record"]
            replacement_id = rewritten["memory_id"]
        else:
            replacement_id = ""

        fence = _memory_fence(root)
        if fence is None:
            return _response(
                "error", {"validated": False, "rewrite_record": rewritten},
                diagnostics=[_diagnostic(
                    "memory_state_unwritable",
                    "Cannot establish the memory-state fence; validation was not recorded."
                    + (" The corrected record exists and must be reconciled manually."
                       if rewritten else ""),
                    recovery_tools=["memory_reconcile", "memory_validate"],
                    recovery_usage="")],
                next_tools=["memory_search"], usage="")
        try:
            path = mem.record_memory_validation(
                root, memory_id, verdict=verdict,
                action_delta=str(action_delta).strip(),
                rationale=str(rationale).strip(),
                evidence_verified=bool(evidence_verified),
                current_target_verified=bool(current_target_verified),
                canonical_overlap=canonical_overlap,
                superseded_by=replacement_id,
            )
        except (OSError, ValueError, FileNotFoundError) as exc:
            return _response(
                "error", {"validated": False, "rewrite_record": rewritten},
                diagnostics=[_diagnostic(
                    "memory_validation_write_failed",
                    f"Validation could not be recorded: {exc}."
                    + (" The corrected record exists; retry the same validation to "
                       "reuse it, or supersede the source manually."
                       if rewritten else ""),
                    recovery_tools=["memory_reconcile", "memory_validate"],
                    recovery_usage="")],
                next_tools=["memory_search"], usage="")
        finally:
            _memory_finalize(root, fence)
        changed = [path]
        if rewritten and rewritten.get("path"):
            changed.append(root / rewritten["path"])
        if not backfill_run:
            _trigger_background_index_refresh_for_paths(root, changed)
        updated = mem.parse_memory_record(path)
        return _response(
            "ok",
            {"validated": True, "verdict": verdict,
             "record": _memory_view(updated, {}) if updated else {"memory_id": memory_id},
             "rewrite_record": rewritten},
            diagnostics=[],
            next_tools=["memory_search", "memory_brief"],
            usage="memory_search(include_history=True)")


def memory_search_response(
    root: Path,
    query: str = "",
    target: str = "",
    symbol: str = "",
    kind: str = "",
    status: str = "",
    include_history: bool = False,
    limit: int = 10,
    index: Optional[WaveIndex] = None,
) -> dict[str, Any]:
    mem = _memory_mod()
    n = max(1, min(int(limit), MEMORY_SEARCH_CAP))
    if kind and kind not in mem.MEMORY_KINDS:
        return _response(
            "error", {"records": [], "count": 0},
            diagnostics=[_diagnostic("invalid_arguments",
                                     f"unknown kind {kind!r}; allowed: {', '.join(mem.MEMORY_KINDS)}",
                                     recovery_tools=["memory_search"], recovery_usage="memory_search()")],
            next_tools=["memory_search"], usage="",
        )
    statuses = None if include_history else ([status] if status else list(mem.DEFAULT_SURFACED_STATUSES))
    records = mem.load_memory_records(root, statuses=statuses)
    if kind:
        records = [r for r in records if r["kind"] == kind]
    if target or symbol:
        records = [r for r in records if mem.match_targets(r, path=target, symbol=symbol)]
    semantic_hit_order: dict[str, int] = {}
    if query:
        lowered = query.lower()
        # Semantic assist (optional): the docs index already embeds records.
        if index is not None:
            try:
                hits, _reranked = index.search_docs(query, top_n=MEMORY_SEARCH_CAP)
                for rank, hit in enumerate(hits):
                    hit_path = str(hit.get("path") or "")
                    if hit_path.startswith(mem.MEMORY_DIR):
                        stem = Path(hit_path).stem
                        semantic_hit_order.setdefault(stem, rank)
            except Exception:
                pass
        # Token containment keeps search useful with no index at all: every
        # query token must appear somewhere in the record's text surface.
        tokens = [t for t in re.split(r"[^a-z0-9_]+", lowered) if t]

        def _text_match(r: dict[str, Any]) -> bool:
            haystack = " ".join([
                (r.get("summary") or ""), (r.get("title") or ""),
                " ".join(r.get("target_refs") or []),
                " ".join(r.get("evidence_refs") or []),
            ]).lower()
            return bool(tokens) and all(t in haystack for t in tokens)

        records = [
            r for r in records
            if r["memory_id"] in semantic_hit_order or _text_match(r)
        ]
    ranked = _memory_ranked(root, records)
    if query and semantic_hit_order:
        # Semantic rank is a tie-break WITHIN the trust/decay policy, not a
        # wholesale override (1svuj). The policy's primary key is the decayed
        # confidence tier (`round(effective_confidence, 2)`, matching
        # `_memory_ranked`); semantic rank only orders records within the same
        # tier, replacing the arbitrary memory_id tie-break there. So a
        # higher-trust record is never demoted below a lower-trust one by text
        # relevance alone. (No-index path is untouched: `semantic_hit_order` is
        # empty then, so this re-sort never runs.)
        ranked.sort(key=lambda pair: (
            -round(float(pair[1].get("effective_confidence") or 0.0), 2),
            semantic_hit_order.get(pair[0]["memory_id"], MEMORY_SEARCH_CAP),
            pair[0]["memory_id"],
        ))
    views = [_memory_view(record, decay) for record, decay in ranked[:n]]
    diagnostics = []
    if not views:
        diagnostics.append(_diagnostic(
            "no_memory_matches",
            "No memory records matched. Memory is evidence-backed and sparse by design — "
            "absence of a record is not absence of risk.",
            recovery_tools=["memory_add"],
            recovery_usage="memory_add(kind=..., summary=..., evidence=[...], targets=[...])",
        ))
    return _response(
        "ok",
        {"records": views, "count": len(views),
         "statuses_searched": statuses or list(mem.MEMORY_STATUSES),
         "semantic_assist": bool(semantic_hit_order)},
        diagnostics=diagnostics,
        next_tools=["memory_brief", "memory_reconcile"],
        usage="memory_brief(context='pre_implementation')",
    )


def memory_brief_response(
    root: Path,
    context: str = "pre_implementation",
    targets: Optional[list] = None,
    limit: int = MEMORY_BRIEF_CAP,
) -> dict[str, Any]:
    mem = _memory_mod()
    context = (context or "pre_implementation").strip()
    if context not in MEMORY_BRIEF_CONTEXTS:
        return _response(
            "error", {"advisories": [], "count": 0},
            diagnostics=[_diagnostic("invalid_arguments",
                                     f"unknown context {context!r}; allowed: {', '.join(MEMORY_BRIEF_CONTEXTS)}",
                                     recovery_tools=["memory_brief"], recovery_usage="memory_brief()")],
            next_tools=["memory_brief"], usage="",
        )
    n = max(1, min(int(limit), MEMORY_BRIEF_CAP))
    target_list = [str(t).strip() for t in (targets or []) if str(t).strip()]
    records = mem.load_memory_records(root, statuses=mem.DEFAULT_SURFACED_STATUSES)
    ranked = _memory_ranked(root, records)
    ranked = [(r, d) for r, d in ranked if d.get("briefing_included", True)]
    if target_list:
        matched = [(r, d) for r, d in ranked
                   if any(mem.match_targets(r, path=t) for t in target_list)]
        unmatched = [(r, d) for r, d in ranked if (r, d) not in matched]
        ranked = matched + unmatched
    advisories = []
    community_scoped = []
    for record, decay in ranked[:n]:
        view = _memory_view(record, decay)
        if any(ref.startswith("community:") for ref in record.get("target_refs") or []):
            community_scoped.append(view)
        else:
            advisories.append(view)
    data = {
        "context": context,
        "advisories": advisories,
        "count": len(advisories) + len(community_scoped),
        "cap": n,
        "total_surfaceable": len(ranked),
    }
    if community_scoped:
        data["community_scoped"] = community_scoped
    # 1svuk (telemetry-only, fail-isolated): accrue the SEPARATE estimated
    # exploration-avoided metric for the advisories actually surfaced here. This
    # never alters `data`/`advisories` (AC-6 invariance) and never touches the
    # measured Context Efficiency total.
    try:
        _credit_exploration_avoided_surface(root, ranked[:n], target_list, mem)
    except Exception:
        pass
    return _response(
        "ok", data,
        diagnostics=[],
        next_tools=["memory_search", "memory_reconcile"],
        usage="memory_search(query=...)",
    )


def memory_reconcile_response(
    root: Path,
    memory_id: str,
    status: str,
    superseded_by: str = "",
) -> dict[str, Any]:
    mem = _memory_mod()
    # Fence BEFORE the status rewrite (delivery-review round 4): refuse if the
    # durable fence cannot be established. Token is writer-owned.
    _fence_token = _memory_fence(root)
    if _fence_token is None:
        return _response(
            "error", {"updated": False},
            diagnostics=[_diagnostic(
                "memory_state_unwritable",
                "Cannot establish the memory-state fence (memory-state.sqlite is "
                "unwritable). Refusing the reconcile so no process serves a stale advisory.",
                recovery_tools=["memory_reconcile"], recovery_usage="")],
            next_tools=["memory_search"], usage="",
        )
    try:
        try:
            path = mem.reconcile_memory_record(
                root, (memory_id or "").strip(), (status or "").strip(),
                superseded_by=(superseded_by or "").strip(),
            )
        except (FileNotFoundError, ValueError) as exc:
            return _response(
                "error", {"updated": False},
                diagnostics=[_diagnostic("memory_reconcile_failed", str(exc),
                                         recovery_tools=["memory_search"],
                                         recovery_usage="memory_search(include_history=True)")],
                next_tools=["memory_search"], usage="",
            )
    finally:
        _memory_finalize(root, _fence_token)
    _trigger_background_index_refresh_for_paths(root, [path])
    record = mem.parse_memory_record(path)
    decay = mem.apply_decay(record, index_dir=root / ".wavefoundry" / "index") if record else {}
    return _response(
        "ok",
        {"updated": True, "record": _memory_view(record, decay) if record else {"memory_id": memory_id}},
        diagnostics=[],
        next_tools=["memory_search"],
        usage="memory_search(include_history=True)",
    )


def wf_audit_response(
    root: Path,
    wave_id: str = "",
    index: Optional[WaveIndex] = None,
    cache: Optional[McpRepoCache] = None,
) -> dict[str, Any]:
    """Aggregate read-only audit: wave state + docs validation + index health.

    Returns a single ``data`` payload with three sub-objects (``wave``,
    ``validation``, ``index``) and a top-level ``ready`` boolean that is
    ``True`` only when all three sub-checks pass:
    - wave is active or planned
    - docs-lint reports zero failures
    - ``semantic_ready`` is ``True`` in the index health report

    Safe to call at any time; does not trigger writes or reindexes.
    """
    # --- Wave sub-check ---
    wave_data: dict[str, Any] = {}
    wave_ok = False
    if wave_id:
        waves = cache.list_waves_cached() if cache else list_waves(root)
        wid = wave_id.strip().lower()
        matched = next(
            (w for w in waves if w["wave_id"].lower().startswith(wid) or wid in w["wave_id"].lower()),
            None,
        )
        if matched:
            next_action = _WAVE_CURRENT_NEXT_ACTION.get(matched["status"], "prepare_wave")
            wave_data = {**matched, "next_action": next_action}
            wave_ok = matched["status"] in ("active", "implementing", "planned")
        else:
            wave_data = {"id": wave_id, "status": "not_found"}
    else:
        wave = current_wave(root, cache=cache)
        if wave:
            next_action = _WAVE_CURRENT_NEXT_ACTION.get(wave["status"], "prepare_wave")
            wave_data = {**wave, "next_action": next_action}
            wave_ok = True
        # wave_data stays {}; wave_ok stays False when no active wave

    # --- Validation sub-check ---
    try:
        val_result = run_validate(root)
        lint_ok = val_result["passed"]
    except Exception as exc:  # pragma: no cover
        val_result = {"passed": False, "errors": [str(exc)], "warnings": []}
        lint_ok = False

    # --- Index health sub-check ---
    index_data: dict[str, Any] = {}
    index_ok = False
    if index is not None:
        try:
            index_data = index.docs_health()
            index_ok = bool(index_data.get("semantic_ready"))
        except Exception as exc:  # pragma: no cover
            index_data = {"error": str(exc), "semantic_ready": False}
    else:
        index_data = {"semantic_ready": False}

    # --- Doc-code drift summary (wave 1ro44 / 1ro43 Req 7) ---
    # The gardening worklist surface: flagged living docs, worst first,
    # historical (docs/waves/) rows excluded by construction. Never blocks
    # `ready` — drift is a proposal for the verification loop, not a gate.
    # The worklist format below is the STABLE CONSUMER CONTRACT for the
    # future Verify-docs loop: entries ordered by `commits_since` DESC then
    # path; each entry = {path, commits_since, anchor_kind, drift_refs}.
    doc_drift_data: dict[str, Any] = {}
    try:
        _iss_drift = _load_script("index_state_store")
        doc_drift_data = _iss_drift.drift_worklist(
            root / ".wavefoundry" / "index", limit=10
        )
    except Exception:
        doc_drift_data = {"available": False, "flagged_count": 0, "entries": []}

    # --- ready ---
    ready = wave_ok and lint_ok and index_ok

    # --- diagnostics ---
    diagnostics: list[dict[str, Any]] = []
    if not wave_ok:
        diagnostics.append(
            _diagnostic(
                "no_active_wave",
                (
                    f"Wave not found: {wave_id}"
                    if wave_id
                    else "No active or planned wave found."
                ),
                recovery_tools=["wf_list_waves"],
                recovery_usage="wf_list_waves()",
            )
        )
    if not lint_ok:
        for err in val_result.get("errors", []):
            diagnostics.append(_diagnostic("docs_lint_error", err, recovery_tools=["wf_validate_docs"]))
    if not index_ok:
        overview = index_data.get("readiness_overview", "absent")
        diagnostics.append(
            _diagnostic(
                "index_not_ready",
                (
                    f"Semantic index is not ready (readiness_overview: {overview!r}). "
                    "Call index_build to recover."
                ),
                recovery_tools=["index_build"],
                recovery_usage="index_build(content='docs', mode='update')",
            )
        )

    # --- next_tools ---
    next_tools: list[str] = []
    if not lint_ok:
        next_tools.append("wf_validate_docs")
    if not index_ok:
        next_tools.append("index_build")
    if not wave_ok:
        next_tools.append("wf_current_wave")
    if not next_tools:
        next_tools = ["wf_current_wave"]

    # --- Install audit advisory (wave 1p35d / change 1p35h) ---
    # If an install log exists with pending rows, mention wf_audit_install so
    # operators reading wf_audit during install discover the install-time gate.
    # We deliberately do NOT auto-detect install state in wf_audit logic itself
    # (Decision Log MF-2 in 1p35h): install-state and repo-state are
    # fundamentally different checks; conflating them produces ambiguous output.
    try:
        import install_log_lib as _install_log_lib  # local import — module always present in this pack

        _install_log_text = _install_log_lib.read_install_log(root)
        if _install_log_text is not None:
            _install_rows = _install_log_lib.parse_log(_install_log_text)
            if _install_log_lib.is_unparseable(_install_log_text, _install_rows):
                # Wave 1p9bh: a present install log that parsed to ZERO rows is corrupted (typically a
                # non-UTF-8 write mojibake'd the row separators) — surface it explicitly rather than
                # letting it read as vacuously "complete".
                diagnostics.append(_diagnostic(
                    "install_log_unparseable",
                    (
                        "Install log present but NO rows could be parsed — likely an encoding "
                        "corruption (e.g. it was written with a non-UTF-8 tool, so the row "
                        "separators are mojibake). Rewrite it as UTF-8 (the install-log writer / an "
                        "explicit `-Encoding utf8` write) and re-run wf_audit_install; do NOT treat "
                        "the install as complete."
                    ),
                    recovery_tools=["wf_audit_install"],
                    recovery_usage="wf_audit_install()",
                ))
            elif _install_rows and not _install_log_lib.is_complete(_install_rows):
                diagnostics.append(_diagnostic(
                    "install_in_progress",
                    (
                        "Install log present and incomplete. wf_audit reports repo "
                        "health; for install-state checks (lint + checked-row artifacts "
                        "+ next step) call wf_audit_install instead."
                    ),
                    recovery_tools=["wf_audit_install"],
                    recovery_usage="wf_audit_install()",
                ))
    except Exception:  # pragma: no cover — defensive; never block wf_audit on the advisory
        pass

    # --- Agent surface coverage advisory (wave 1p35d / change 1p35l) ---
    # When zero agent role docs are present (post-install), the install never
    # completed seed-050 or every generated doc is missing the `Role:` field
    # (the inclusion gate the dashboard classifies on). Either way, the Agents
    # panel will be empty — surface as a diagnostic with a recovery hint so
    # operators don't have to discover the gap by looking at an empty panel.
    try:
        import dashboard_lib as _dashboard_lib  # local import — module always present
        _agents = _dashboard_lib.collect_agents(root)
        if not _agents:
            diagnostics.append(_diagnostic(
                "no_agent_role_docs",
                (
                    "No agent role docs found under docs/agents/. The dashboard "
                    "Agents panel will be empty. Run seed-050 (Init agent "
                    "surfaces) to generate per-role docs; ensure each generated "
                    "file declares `Role: <role-slug>` in the header (docs-lint "
                    "enforces this)."
                ),
                recovery_tools=["seed_get"],
                recovery_usage='seed_get(name="050")',
            ))
    except Exception:  # pragma: no cover — defensive; never block wf_audit on the advisory
        pass

    # --- Harness sub-checks ---
    commit_governance = _audit_commit_governance(root)
    harnessability = _audit_harnessability(root)
    harness_coverage = _audit_harness_coverage(root)
    harness_coherence = _audit_harness_coherence(root)

    # Advisory diagnostics for harness checks
    if commit_governance.get("available") and commit_governance.get("unassociated_count", 0) > 0:
        n = commit_governance["unassociated_count"]
        diagnostics.append(_diagnostic(
            "unassociated_commits",
            f"{n} recent commit(s) could not be associated with a wave or change ID.",
            recovery_tools=["wf_current_wave"],
            recovery_usage="wf_current_wave()",
        ))
    if harness_coverage.get("covered_count", 3) < 3:
        uncovered = [k for k, v in harness_coverage.get("dimensions", {}).items() if not v["covered"]]
        diagnostics.append(_diagnostic(
            "harness_coverage_gap",
            f"Harness coverage {harness_coverage['coverage_ratio']}: uncovered dimensions: {', '.join(uncovered)}.",
            recovery_tools=["wf_audit"],
            recovery_usage="wf_audit()",
        ))
    if harness_coherence.get("findings_count", 0) > 0:
        diagnostics.append(_diagnostic(
            "harness_coherence_issue",
            f"{harness_coherence['findings_count']} harness coherence finding(s) detected in seed surface.",
            recovery_tools=["wf_audit"],
            recovery_usage="wf_audit()",
        ))
    if doc_drift_data.get("flagged_count", 0) > 0:
        _top = ", ".join(e["path"] for e in doc_drift_data.get("entries", [])[:3])
        diagnostics.append(_diagnostic(
            "doc_code_drift_flagged",
            (
                f"{doc_drift_data['flagged_count']} living doc(s) are drift-flagged — the code "
                f"they reference has churned past their verification anchor (top: {_top}). "
                "Drift is a PROPOSAL, not a verdict: read each doc against the current code and "
                "either update it or record a `Verified against: <hex-sha>` stamp (the stamp "
                "resets the drift clock; docs_gardener never writes it)."
            ),
            recovery_tools=["docs_search", "code_read"],
            recovery_usage="code_read(path=<flagged doc path>)",
        ))

    # 1p8gy AC-6: memory advisories relevant to the audited wave.
    _mem_advisories = _memory_advisories_for_wave(root, wave_data) if wave_data else []

    # 1svuk: the SEPARATE, labeled estimated-exploration-avoided line for the
    # audited wave — never summed into the measured Context Efficiency total.
    _est_avoided: dict[str, Any] = {}
    if wave_data:
        try:
            ea = _load_script("exploration_avoided")
            wid = str(wave_data.get("wave_id") or wave_data.get("id") or "")
            est = ea.read_wave(root, wid) if wid else None
            if est and est.get("estimated_exploration_avoided", 0) > 0:
                _est_avoided = {
                    "tokens": est["estimated_exploration_avoided"],
                    "surfaced_events": est["surfaced_events"],
                    "cited_events": est["cited_events"],
                    "measured": False, "caveat": ea.CAVEAT,
                }
        except Exception:
            _est_avoided = {}

    return _response(
        "ok",
        {
            "ready": ready,
            "wave": wave_data,
            "validation": val_result,
            "index": index_data,
            "doc_drift": doc_drift_data,
            **({"memory_advisories": _mem_advisories} if _mem_advisories else {}),
            **({"estimated_exploration_avoided": _est_avoided} if _est_avoided else {}),
            "commit_governance": commit_governance,
            "harnessability": harnessability,
            "harness_coverage": harness_coverage,
            "harness_coherence": harness_coherence,
        },
        diagnostics=diagnostics,
        next_tools=next_tools,
        usage=next_tools[0] + "()" if next_tools else "wf_current_wave()",
    )


def wf_validate_docs_response(root: Path) -> dict[str, Any]:
    result = run_validate(root)
    status = "ok" if result["passed"] else "error"
    diagnostics = [
        _diagnostic("docs_lint_error", error, recovery_tools=["wf_validate_docs"])
        for error in result["errors"]
    ] + [
        _diagnostic("docs_lint_warning", warning, recovery_tools=["wf_validate_docs"])
        for warning in result["warnings"]
    ]
    return _response(
        status,
        result,
        diagnostics=diagnostics,
        next_tools=["wf_garden_docs"] if result["passed"] else ["wf_help"],
        usage="wf_garden_docs()" if result["passed"] else "wf_help(goal='maintain_framework')",
    )


# --- Wave 1p35d (1p35h): install-time audit tool ---


def wf_audit_install_response(root: Path, phase: Optional[int] = None) -> dict[str, Any]:
    """Run the three-check install audit and return the first failure or the next step.

    Check sequence (stops on first failure):
      1. docs-lint — surface lint errors before advancing.
      2. checked-row artifact validation — for every ``[x]`` row, verify its
         expected artifact exists on disk. Mismatch surfaces the agent-recovery
         path.
      3. first unchecked row — when both checks pass, return the next pending
         row with its seed pointer and the instruction to mark ``[x]`` and
         re-call. When no pending rows remain, return ``status: complete``.

    The ``phase`` argument optionally limits the audit (and the next-step return)
    to a single phase. Missing log file returns an actionable error pointing at
    ``install-wavefoundry.md``.
    """
    # Local import to avoid a hard cycle if install_log_lib later imports
    # from server_impl (it currently doesn't, but defensive).
    import install_log_lib

    log_text = install_log_lib.read_install_log(root)
    if log_text is None:
        return _response(
            "error",
            {
                "status": "missing_log",
                "expected_path": str(root / install_log_lib.INSTALL_LOG_REL_PATH),
            },
            diagnostics=[
                _diagnostic(
                    "install_log_missing",
                    (
                        "No install log at .wavefoundry/install-log.md. "
                        "If this is a fresh install, copy the template at "
                        ".wavefoundry/framework/install/install-log.template.md to "
                        ".wavefoundry/install-log.md (substitute {{generated_at}} with "
                        "today's date), then re-call wf_audit_install. See "
                        "install-wavefoundry.md at the repo root for bootstrap "
                        "instructions."
                    ),
                    recovery_tools=[],
                )
            ],
            next_tools=[],
            usage="wf_audit_install()",
        )

    # CHECK 1 — docs-lint. Block advancement on errors.
    lint_result = run_validate(root)
    if not lint_result.get("passed", False):
        return _response(
            "error",
            {
                "status": "lint_errors",
                "phase": phase,
                "errors": lint_result.get("errors", []),
                "warnings": lint_result.get("warnings", []),
                "next_action": (
                    "Fix the docs-lint errors above before advancing the install log. "
                    "After fixing, re-call wf_audit_install."
                ),
            },
            diagnostics=[
                _diagnostic(
                    "docs_lint_error",
                    error,
                    recovery_tools=["wf_audit_install", "wf_validate_docs"],
                )
                for error in lint_result.get("errors", [])
            ],
            next_tools=["wf_audit_install"],
            usage="wf_audit_install()",
        )

    rows = install_log_lib.parse_log(log_text)

    # Wave 1p9bh: a present log that parsed to ZERO rows is corrupted (typically a non-UTF-8 write
    # mojibake'd the em-dash row separators). Fail loudly here rather than sailing through CHECK 2/3 to a
    # vacuous "complete" (the empty-input vacuous-truth defect).
    if install_log_lib.is_unparseable(log_text, rows):
        return _response(
            "error",
            {
                "status": "unparseable_log",
                "expected_path": str(root / install_log_lib.INSTALL_LOG_REL_PATH),
                "next_action": (
                    "The install log exists but no rows could be parsed — its row separators are "
                    "likely mojibake from a non-UTF-8 write. Rewrite it as UTF-8 (the framework "
                    "install-log writer, or an explicit `-Encoding utf8` write on Windows PowerShell), "
                    "then re-call wf_audit_install. Do NOT treat the install as complete."
                ),
            },
            diagnostics=[
                _diagnostic(
                    "install_log_unparseable",
                    (
                        "Install log present but zero rows parsed — likely an encoding corruption "
                        "(a non-UTF-8 write mojibake'd the em-dash row separators). Rewrite as UTF-8."
                    ),
                    recovery_tools=["wf_audit_install"],
                )
            ],
            next_tools=[],
            usage="wf_audit_install()",
        )

    scope_rows = install_log_lib.filter_phase(rows, phase)

    # CHECK 2 — checked-row artifact validation. Block on missing artifacts.
    missing = install_log_lib.checked_rows_missing_artifact(scope_rows, root)
    if missing:
        first_row, first_path = missing[0]
        return _response(
            "error",
            {
                "status": "checked_but_missing",
                "phase": phase,
                "row": _install_audit_row_brief(first_row),
                "expected_artifact": str(first_path),
                "all_missing": [
                    {
                        "row": _install_audit_row_brief(r),
                        "expected_artifact": str(p),
                    }
                    for r, p in missing
                ],
                "next_action": (
                    f"Row {first_row.number} is marked [x] but its expected artifact "
                    f"({first_row.target}) does not exist at {first_path}. "
                    f"Re-execute the step ({first_row.source}), confirm the artifact, "
                    f"then re-call wf_audit_install."
                ),
            },
            diagnostics=[
                _diagnostic(
                    "install_log_checked_but_missing",
                    (
                        f"Row {r.number} ({r.source}) marked [x] but artifact "
                        f"{r.target!r} does not exist at {p}."
                    ),
                    recovery_tools=["wf_audit_install"],
                )
                for r, p in missing
            ],
            next_tools=["wf_audit_install"],
            usage="wf_audit_install()",
        )

    # CHECK 3 — first unchecked row, or complete.
    next_row = install_log_lib.first_unchecked_row(scope_rows)
    if next_row is None:
        # All rows in scope are terminal.
        complete_overall = install_log_lib.is_complete(rows)
        return _response(
            "ok",
            {
                "status": "complete" if complete_overall else "phase_complete",
                "phase": phase,
                "message": (
                    "Install complete: every row is [x] or [~]."
                    if complete_overall
                    else f"Phase {phase} complete; other phases still have pending rows."
                ),
            },
            diagnostics=[],
            next_tools=[],
            usage="wf_audit_install()",
        )

    return _response(
        "ok",
        {
            "status": "next_step",
            "phase": phase,
            "row": _install_audit_row_brief(next_row),
            "instructions": (
                f"Execute the step indicated by row {next_row.number} "
                f"({next_row.source}: {next_row.slug}). When the expected outcome is "
                f"reached, mark this row [x] in .wavefoundry/install-log.md and call "
                f"wf_audit_install again."
            ),
        },
        diagnostics=[],
        next_tools=["wf_audit_install"],
        usage="wf_audit_install()",
    )


def _install_audit_row_brief(row: Any) -> dict[str, Any]:
    """Return a JSON-friendly summary of an install-log row."""
    return {
        "number": row.number,
        "slug": row.slug,
        "kind": row.kind,
        "source": row.source,
        "target": row.target,
        "phase": row.phase,
        "state": row.state,
        # Wave 1p8gw: expose the parsed field classification so consumers can tell a stat-able artifact
        # PATH apart from a prose verification DESCRIPTION (the description-as-path defect).
        "field": getattr(row, "field", None),
        "artifact_path": getattr(row, "artifact_path", None),
        "description": getattr(row, "description", None),
    }


def wf_garden_docs_response(root: Path, mode: str = "dry_run", cache: Optional[McpRepoCache] = None) -> dict[str, Any]:
    if (mode or "").strip().lower() == "dry_run":
        return _response(
            "ok",
            {"mode": "dry_run", "skipped": True},
            diagnostics=[_diagnostic(
                "dry_run",
                "Pass mode='run' to execute the docs gardener.",
                recovery_tools=[],
                recovery_usage="wf_garden_docs(mode='run')",
            )],
            next_tools=["wf_garden_docs"],
            usage="wf_garden_docs(mode='run')",
        )
    with review_event_write_lock(root):
        result = run_garden(root)
    status = "ok" if result["passed"] else "error"
    diagnostics = [] if result["passed"] else [
        _diagnostic(
            "docs_gardener_failed",
            result["output"].strip() or "docs_gardener failed",
            recovery_tools=["wf_validate_docs"],
            recovery_usage="wf_validate_docs()",
        )
    ]
    # 1ro43 Req 7: gardening has a drift worklist — point at it. The gardener's
    # `Last verified` stamps are mechanical and carry no verification meaning;
    # drift disposal is a deliberate review recorded via `Verified against:`.
    if result["passed"]:
        try:
            _drift = _load_script("index_state_store").drift_worklist(
                root / ".wavefoundry" / "index", limit=3
            )
            if _drift.get("flagged_count", 0) > 0:
                diagnostics.append(_diagnostic(
                    "doc_code_drift_flagged",
                    (
                        f"{_drift['flagged_count']} living doc(s) are drift-flagged (gardener "
                        "stamps do NOT clear drift — only a doc content update or a deliberate "
                        "`Verified against: <hex-sha>` review stamp resets the clock). See "
                        "wf_audit's `doc_drift` worklist for the ordered entries."
                    ),
                    recovery_tools=["wf_audit"],
                    recovery_usage="wf_audit()",
                ))
        except Exception:
            pass
    if cache and result["passed"]:
        cache.invalidate()
    if result["passed"] and result.get("files_updated", 0):
        _trigger_background_index_refresh_for_paths(root, ["docs/"])
    return _response(
        status,
        result,
        diagnostics=diagnostics,
        next_tools=["wf_validate_docs", "wf_sync_surfaces"] if result["passed"] else ["wf_validate_docs"],
        usage="wf_sync_surfaces()" if result["passed"] else "wf_validate_docs()",
    )


def wf_sync_surfaces_response(root: Path, mode: str = "dry_run", cache: Optional[McpRepoCache] = None) -> dict[str, Any]:
    if (mode or "").strip().lower() == "dry_run":
        return _response(
            "ok",
            {"mode": "dry_run", "skipped": True},
            diagnostics=[_diagnostic(
                "dry_run",
                "Pass mode='run' to execute render_platform_surfaces.",
                recovery_tools=[],
                recovery_usage="wf_sync_surfaces(mode='run')",
            )],
            next_tools=["wf_sync_surfaces"],
            usage="wf_sync_surfaces(mode='run')",
        )
    result = run_sync_surfaces(root)
    status = "ok" if result["passed"] else "error"
    diagnostics = [] if result["passed"] else [
        _diagnostic(
            "render_platform_surfaces_failed",
            result["output"].strip() or "render_platform_surfaces failed",
            recovery_tools=["wf_validate_docs"],
            recovery_usage="wf_validate_docs()",
        )
    ]
    if cache and result["passed"]:
        cache.invalidate()
    envelope = _response(
        status,
        result,
        diagnostics=diagnostics,
        next_tools=["wf_validate_docs"],
        usage="wf_validate_docs()",
    )
    # wf_sync_surfaces is a write-side tool (renders host config + native
    # wrappers); attach lint regardless of mode_s for consistency with other
    # gated tools.
    mode_for_lint = "create" if status != "dry_run" else "dry_run"
    return _attach_lint_to_response(envelope, root, mode_for_lint)


def _index_optimize_response(
    root: Path,
    content: str = "all",
    rebuild_if_needed: bool = True,
    cache: Optional[McpRepoCache] = None,
) -> dict[str, Any]:
    """Wave 1p9aj. Reclaim on-disk index bloat by running the tiered ladder — optimize (compact) →
    copy-and-replace rewrite (on the Lance list-offset corruption) → full rebuild (only when a table is
    unreadable) — over the ``docs``/``code`` Lance tables, with **no** re-embedding in the common case.
    Returns per-table ``{tier, rows, size_before, size_after, reclaimed}`` plus a total. When
    ``rebuild_if_needed`` and a table was unreadable (Tier 3), a full rebuild is spawned in the
    background after the build lock is released.

    Wave 1rsh9 (1rq4h): this is now the unified maintenance verb for EVERY index. After the Lance
    pass it also runs SQLite maintenance — WAL checkpoint/truncate, ``VACUUM``, ``PRAGMA optimize``,
    and the two-layer integrity check — across every reachable SQLite store: the index-state store
    and the graph state store (closing the old "graph index is not reclaimed this way" gap).
    SQLite maintenance runs under the same index-build lock, is on-demand only (never alters the
    graph build path), and reports per-store ``size_before/size_after/reclaimed`` under ``stores``."""
    content_s = (content or "all").strip().lower()
    layer_map = {"docs": ("docs",), "code": ("code",), "all": ("docs", "code"), "": ("docs", "code")}
    tables = layer_map.get(content_s)
    if tables is None:
        return _response(
            "error",
            {"content": content, "operation": "optimize"},
            diagnostics=[_diagnostic(
                "invalid_arguments",
                f"index_optimize's content selects the Lance tables — it must be 'docs', 'code', or "
                f"'all' (got {content!r}). The SQLite stores (index-state + graph state) are always "
                f"maintained alongside whichever Lance selection runs.",
            )],
            next_tools=["index_health"],
            usage="index_optimize(content='all')",
        )
    index_dir = root / ".wavefoundry" / "index"
    idx = _load_script("indexer")
    already_running = getattr(idx, "IndexBuildAlreadyRunning", None)
    try:
        results = idx.optimize_index_tables(index_dir, tuple(tables))
    except Exception as exc:  # noqa: BLE001
        if already_running is not None and isinstance(exc, already_running):
            return _response(
                "error",
                {"content": content_s, "operation": "optimize"},
                diagnostics=[_diagnostic(
                    "build_skipped_lock_busy",
                    f"A build is already running ({exc}). Call index_build_status and read the "
                    f"`lock` object; retry index_optimize once `held` is false.",
                    recovery_tools=["index_build_status"],
                    recovery_usage="index_build_status()",
                )],
                next_tools=["index_build_status"],
                usage="index_build_status()",
            )
        return _response(
            "error",
            {"content": content_s, "operation": "optimize"},
            diagnostics=[_diagnostic("index_optimize_failed", f"Optimize failed: {exc}")],
            next_tools=["index_health"],
            usage="index_health()",
        )
    # Wave 1rsh9 (1rq4h): unified maintenance — SQLite stores (index-state +
    # graph state) get WAL checkpoint/truncate, full VACUUM, PRAGMA optimize,
    # and the deep integrity check, under the same index-build lock discipline
    # as the Lance pass. Best-effort: a lock conflict or error is reported as
    # a diagnostic, never a failure of the Lance results.
    stores_out: dict[str, Any] = {}
    store_diagnostics: list[dict[str, Any]] = []
    stores_reclaimed = 0
    try:
        iss = _load_script("index_state_store")
        with idx._index_build_lock(index_dir):
            raw_stores = iss.optimize_state_stores(index_dir, full_vacuum=True, deep_integrity=True)
        for name, res in raw_stores.items():
            s_before = int(res.get("size_before_bytes") or 0)
            s_after = int(res.get("size_after_bytes") or 0)
            s_reclaimed = int(res.get("reclaimed_bytes") or 0)
            stores_reclaimed += s_reclaimed
            stores_out[name] = {
                "present": bool(res.get("present")),
                "integrity": res.get("integrity"),
                "size_before_bytes": s_before,
                "size_before": _human_bytes(s_before),
                "size_after_bytes": s_after,
                "size_after": _human_bytes(s_after),
                "reclaimed_bytes": s_reclaimed,
                "reclaimed": _human_bytes(s_reclaimed),
                "error": res.get("error"),
            }
            if res.get("present") and res.get("integrity") == "structural-fail":
                store_diagnostics.append(_diagnostic(
                    "state_store_structural_fail",
                    f"SQLite store '{name}' failed its integrity check. Stores are derived-only: "
                    f"the next build (or graph rebuild) drops and repopulates it automatically.",
                    recovery_tools=["index_build"],
                    recovery_usage="index_build(content='all', mode='update')",
                ))
    except Exception as exc:  # noqa: BLE001
        if already_running is not None and isinstance(exc, already_running):
            store_diagnostics.append(_diagnostic(
                "build_skipped_lock_busy",
                f"SQLite store maintenance skipped — a build is running ({exc}). Retry once "
                f"index_build_status reports lock.held false.",
                recovery_tools=["index_build_status"],
                recovery_usage="index_build_status()",
            ))
        else:
            store_diagnostics.append(_diagnostic(
                "state_store_maintenance_failed", f"SQLite store maintenance failed: {exc}",
            ))
    if not results:
        return _response(
            "ok",
            {"content": content_s, "operation": "optimize", "tables": {},
             "stores": stores_out,
             "total_reclaimed_bytes": stores_reclaimed,
             "total_reclaimed": _human_bytes(stores_reclaimed),
             "note": "No matching Lance tables present to optimize."},
            diagnostics=store_diagnostics,
            next_tools=["index_health"],
            usage="index_health()",
        )
    # Independent-review N2: the restore-only refusal is a top-level
    # {"error": str}; iterating it as per-table dicts raised AttributeError.
    if isinstance(results.get("error"), str):
        return _response(
            "error",
            {"error": results["error"]},
            diagnostics=[_diagnostic(
                "index_not_ready",
                results["error"],
                recovery_tools=["index_build"],
                recovery_usage="index_build(content='all')",
            )],
            next_tools=["index_build"],
            usage="index_build(content='all')",
        )
    # 1sed6: a dirty optimize deliberately leaves the epoch un-finalized —
    # surface that as a diagnostic instead of listing "finalize" as a table.
    _finalize_note = results.pop("finalize", None) if isinstance(results, dict) else None
    tables_out: dict[str, Any] = {}
    needs_rebuild: list[str] = []
    total_before = 0
    total_after = 0
    for t, res in results.items():
        if not isinstance(res, dict):
            continue
        before = int(res.get("bytes_before") or 0)
        after = int(res.get("bytes_after") or 0)
        total_before += before
        total_after += after
        reclaimed = max(0, before - after)
        tables_out[t] = {
            "tier": res.get("tier"),
            "rows": res.get("rows"),
            "needs_rebuild": bool(res.get("needs_rebuild")),
            "size_before_bytes": before,
            "size_before": _human_bytes(before),
            "size_after_bytes": after,
            "size_after": _human_bytes(after),
            "reclaimed_bytes": reclaimed,
            "reclaimed": _human_bytes(reclaimed),
            "error": res.get("error"),
        }
        if res.get("needs_rebuild"):
            needs_rebuild.append(t)
    if cache:
        cache.invalidate()
    diagnostics = list(store_diagnostics)
    if isinstance(_finalize_note, dict) and _finalize_note.get("error"):
        diagnostics.append(_diagnostic(
            "index_epoch_not_finalized",
            f"{_finalize_note['error']} Readers fail closed until a build restores readiness.",
            recovery_tools=["index_build"],
            recovery_usage="index_build(content='all')",
        ))
    rebuilt: list[str] = []
    if needs_rebuild and rebuild_if_needed:
        # Tier 3: a table was unreadable for a rewrite. The build lock is released now (optimize_index_tables
        # exited its `with`), so spawn a full re-embed rebuild for each — run_index_rebuild is
        # background + single-flight.
        for layer in needs_rebuild:
            try:
                run_index_rebuild(root, content=layer, full=True, rechunk=False, layer="project")
                rebuilt.append(layer)
            except Exception as exc:  # noqa: BLE001
                diagnostics.append(_diagnostic(
                    "index_rebuild_spawn_failed",
                    f"Table '{layer}' needs a rebuild but the rebuild spawn failed ({exc}). "
                    f"Run index_build(content='{layer}', mode='rebuild').",
                ))
        if rebuilt:
            diagnostics.append(_diagnostic(
                "index_optimize_rebuild_spawned",
                f"Tables {rebuilt} were unreadable (Tier 3) and a full rebuild was spawned in the "
                f"background. Poll index_build_status.",
                recovery_tools=["index_build_status"],
                recovery_usage="index_build_status()",
            ))
    elif needs_rebuild:
        diagnostics.append(_diagnostic(
            "index_optimize_needs_rebuild",
            f"Tables {needs_rebuild} were unreadable (Tier 3) and need a full rebuild. "
            f"Run index_build(content='{needs_rebuild[0]}', mode='rebuild').",
            recovery_tools=["index_build"],
            recovery_usage=f"index_build(content='{needs_rebuild[0]}', mode='rebuild')",
        ))
    total_reclaimed = max(0, total_before - total_after) + stores_reclaimed
    return _response(
        "ok",
        {
            "content": content_s,
            "operation": "optimize",
            "tables": tables_out,
            "stores": stores_out,
            "total_reclaimed_bytes": total_reclaimed,
            "total_reclaimed": _human_bytes(total_reclaimed),
            "needs_rebuild": needs_rebuild,
            "rebuild_spawned": rebuilt,
        },
        diagnostics=diagnostics,
        next_tools=["index_health"],
        usage="index_health()",
    )


def index_build_response(
    root: Path,
    *,
    content: str = "docs",
    mode: str = "update",
    layer: str = "project",
    cache: Optional[McpRepoCache] = None,
) -> dict[str, Any]:
    content_s = (content or "").strip().lower()
    layer_s = (layer or "").strip().lower()
    mode_s = (mode or "").strip().lower()
    if mode_s not in {"update", "rebuild", "rechunk"}:
        return _response(
            "error",
            {"content": content, "mode": mode, "layer": layer},
            diagnostics=[
                _diagnostic(
                    "invalid_arguments",
                    f"Unsupported mode {mode!r}. Use 'update' (incremental, changed files only), "
                    "'rechunk' (re-chunk every file but reuse embeddings by hash — only new/changed "
                    "chunks re-embed), or 'rebuild' (full re-embed from scratch). To reclaim on-disk "
                    "bloat without re-embedding, use index_optimize().",
                    recovery_tools=["index_optimize", "wf_help"],
                    recovery_usage="wf_help(goal='refresh_semantic_index')",
                )
            ],
            next_tools=["index_optimize", "wf_help"],
            usage="wf_help(goal='refresh_semantic_index')",
        )
    full = mode_s == "rebuild"
    rechunk = mode_s == "rechunk"
    try:
        result = run_index_rebuild(root, content=content_s, full=full, rechunk=rechunk, layer=layer_s)
    except ValueError as exc:
        return _response(
            "error",
            {"content": content, "mode": mode_s, "layer": layer},
            diagnostics=[
                _diagnostic(
                    "invalid_arguments",
                    str(exc),
                    recovery_tools=["wf_help"],
                    recovery_usage="wf_help(goal='maintain_framework')",
                )
            ],
            next_tools=["wf_help"],
            usage="wf_help(goal='maintain_framework')",
        )
    # Only invalidate the cache when a rebuild was actually spawned and the
    # subprocess survived the verification window — not for up-to-date,
    # already-running, or early-exit short-circuits.
    if (
        cache
        and not result.get("up_to_date")
        and not result.get("already_running")
        and not result.get("build_failed_early")
    ):
        cache.invalidate()
    diagnostics = []
    if result.get("already_running"):
        diagnostics.append(_diagnostic(
            "index_build_already_running",
            result["notice"],
            recovery_tools=["index_health"],
            recovery_usage="index_health()",
        ))
    # Wave 1p2q3 (1p2w5): synchronous Popen-verification surfaced a subprocess
    # early-exit. Emit a `build_skipped_lock_busy` (or
    # `index_build_subprocess_failed`) diagnostic carrying the lock-holder pid
    # so the caller sees a clear actionable recovery path instead of a
    # misleading success response.
    if result.get("build_failed_early"):
        _failure_code = str(result.get("diagnostic_code") or "index_build_subprocess_failed")
        _failure_message = str(result.get("notice") or "Index rebuild subprocess exited early.")
        if result.get("lock_owner_pid"):
            _failure_message = (
                f"{_failure_message} Recovery: call index_build_status and read the `lock` object — "
                f"if `held` is true a build is running, so wait; if it is not held (stale), the lock is "
                f"reclaimed automatically on the next build, so just retry index_build. Do not "
                f"delete the lock file — it persists by design and its presence does not mean a build is running."
            )
        diagnostics.append(_diagnostic(
            _failure_code,
            _failure_message,
            recovery_tools=["index_build_status", "index_build"],
            recovery_usage="index_build_status()",
        ))
    # Wave 13129 (1316n): surface graph state regardless of content. Operators
    # running content='code'|'docs'|'all' need to see the graph wasn't touched
    # (a consumer's misread on 1.2.1+315o). When content is not 'graph', append a
    # clarifying note pointing at content='graph' for graph refresh.
    graph_health = _graph_health_summary(root)
    target_layer = "project"
    layer_graph = graph_health.get(target_layer, {})
    if layer_graph.get("present"):
        result["graph_node_count"] = layer_graph.get("node_count")
        result["graph_edge_count"] = layer_graph.get("edge_count")
        result["graph_last_built_at"] = layer_graph.get("last_built_at")
    if content_s != "graph":
        result["graph_rebuilt"] = False
        existing_notice = str(result.get("notice") or "")
        graph_callout = (
            " | NOTE: The graph layer was NOT rebuilt by this call. "
            "Run index_build(content='graph') if graph-layer refresh is required."
        )
        if graph_callout not in existing_notice:
            result["notice"] = (existing_notice + graph_callout).strip(" |")
    else:
        # Wave 1p2q3 (1p2w5): graph_rebuilt reflects whether a rebuild actually
        # ran. A subprocess early-exit (lock-busy) means the rebuild never
        # happened despite the spawn; do not claim graph_rebuilt: true.
        result["graph_rebuilt"] = not (
            result.get("already_running")
            or result.get("up_to_date")
            or result.get("build_failed_early")
        )
        # Wave 1p2q3 (131hh): explicit graph rebuild — notify MCP clients that
        # cached wavefoundry://graph/* resources may be stale. Skip when the
        # request was already-running, up-to-date, or failed early (no rebuild
        # fired in any of those cases).
        if result["graph_rebuilt"]:
            _dispatch_graph_resources_updated(root=root, layer=target_layer)
    return _response(
        "ok" if not result.get("build_failed_early") else "error",
        result,
        diagnostics=diagnostics,
        next_tools=["index_health"],
        usage="index_health()",
    )


def _index_build_lock_info(root: Path) -> dict[str, Any]:
    """Authoritative index-build lock status (wave 1p99o).

    ``held`` is determined by **non-destructively testing the real OS lock**
    (``indexer._index_build_lock_held`` — POSIX ``fcntl`` ``F_GETLK`` / native Windows momentary
    ``msvcrt``), never from file presence. The lock FILE persists **by design** as a last-owner record,
    so ``present: true`` does not imply a build is running — read ``held``. ``ended_at`` (best-effort,
    written on a clean build exit) distinguishes a clean finish from an **interrupted** build (a hard
    kill can't write it). Plain terminology only — no "zombie"."""
    index_dir = root / ".wavefoundry" / "index"
    lock_path = index_dir / "index-build.lock"
    info: dict[str, Any] = {
        "held": False,
        "present": False,
        "owner_pid": None,
        "owner_cmdline": None,
        "started_at": None,
        "ended_at": None,
        "note": "No index-build lock file is present; no build is running.",
    }
    try:
        idx = _indexer_module()
        present = lock_path.exists()
        info["present"] = present
        if not present:
            return info
        meta = idx.read_index_build_lock_metadata(lock_path)
        held, holder_pid = idx._index_build_lock_held(index_dir)
    except Exception:  # noqa: BLE001 — best-effort; status must never break
        return info
    meta = meta if isinstance(meta, dict) else {}
    started_at = meta.get("started_at") if isinstance(meta.get("started_at"), (int, float)) else None
    ended_at = meta.get("ended_at") if isinstance(meta.get("ended_at"), (int, float)) else None
    cmdline = meta.get("cmdline") if isinstance(meta.get("cmdline"), str) else None
    meta_pid = meta.get("pid") if isinstance(meta.get("pid"), int) else None
    info["started_at"] = started_at
    info["ended_at"] = ended_at
    info["owner_cmdline"] = cmdline
    # Prefer the kernel-reported holder PID when held (ground truth); else the last recorded owner.
    info["owner_pid"] = holder_pid if (held and holder_pid) else meta_pid
    info["held"] = bool(held)
    if held:
        info["note"] = f"A build is running (owner pid {info['owner_pid']})."
    elif held is None:
        info["note"] = (
            "The lock state could not be determined; treat it as not held — the acquire-time lock is "
            "the authority. The lock file's presence does not mean a build is running."
        )
    elif ended_at is not None:
        info["note"] = (
            "The last build finished cleanly; the lock is not held. The lock file persists as a "
            "last-owner record — its presence does not mean a build is running."
        )
    elif started_at is not None:
        info["note"] = (
            "The last build did NOT finish cleanly (interrupted or killed) — the index may be partial; "
            "consider a rebuild. The lock file persists by design; its presence does not mean a build "
            "is running."
        )
    else:
        info["note"] = (
            "A lock file is present but has no recorded owner; the lock is not held. Its presence does "
            "not mean a build is running."
        )
    return info


def index_build_status_response(root: Path, layer: str = "project") -> dict[str, Any]:
    """Wrapper (wave 1p99o): attach the authoritative ``lock`` object to every return path so callers
    ask the classifier, not the by-design-persistent lock file, whether a build is running.

    1sed6 review fix: also attach the store's build ``epoch`` on every return
    path, and never report ``idle`` over a non-complete epoch — a builder that
    died between fence and finalize is ``interrupted`` (readers are failed
    closed), which callers must see to know a rebuild is required.
    """
    resp = _index_build_status_response_inner(root, layer=layer)
    data = resp.get("data")
    if isinstance(data, dict):
        # Read order matters (review F5): epoch state FIRST, lock second, and
        # a positive interrupted classification re-reads the state — so a
        # build finalizing (or starting) between the two reads cannot yield a
        # one-poll false "interrupted".
        def _read_epoch() -> dict[str, Any]:
            out: dict[str, Any] = {"status": "absent", "generation": None, "scope": ""}
            try:
                iss = _load_script("index_state_store")
                state = iss.read_build_state(root / ".wavefoundry" / "index")
                if state is not None:
                    out = {
                        "status": state.get("status"),
                        "generation": state.get("generation"),
                        "scope": state.get("scope", ""),
                    }
            except Exception:
                pass
            return out
        epoch = _read_epoch()
        lock_info = _index_build_lock_info(root)
        data["lock"] = lock_info
        held = bool(lock_info.get("held")) if isinstance(lock_info, dict) else False
        if epoch.get("status") == "building" and not held:
            epoch = _read_epoch()  # double-check: rule out a finalize between reads
        epoch["interrupted"] = epoch.get("status") == "building" and not held
        data["epoch"] = epoch
        if data.get("state") == "idle" and epoch["interrupted"]:
            data["state"] = "interrupted"
            resp.setdefault("diagnostics", []).append(_diagnostic(
                "index_build_interrupted",
                "The store records a `building` epoch but no build holds the lock — a prior "
                "builder died between fence and finalize. Readers are failed closed; run "
                "index_build to recover (an unchanged retry heals the epoch).",
                recovery_tools=["index_build"],
                recovery_usage="index_build(content='all')",
            ))
    return resp


def _index_build_status_response_inner(root: Path, layer: str = "project") -> dict[str, Any]:
    import time as _time
    layer_s = (layer or "").strip().lower()
    # Wave 1p4ww: single project index — the framework layer is folded in.
    if layer_s != "project":
        return _response("error", {"layer": layer}, diagnostics=[_diagnostic("invalid_arguments", f"Unsupported layer '{layer}'. Use 'project'.")])
    state_path = _index_build_state_path(root, layer_s)
    log_path = _index_build_log_path(root, layer_s)
    index_dir = state_path.parent
    stale_locks_cleaned = _cleanup_stale_table_locks(index_dir)
    background_status = _background_build_status(root) if layer_s == "project" else "none"

    if not state_path.exists():
        if background_status == "running":
            pid_path = root / ".wavefoundry" / "index" / "background-build.pid"
            background_pid: Optional[int] = None
            background_started_at: Optional[float] = None
            try:
                background_pid = int(pid_path.read_text(encoding="utf-8").strip())
            except (OSError, ValueError):
                background_pid = None
            try:
                background_started_at = pid_path.stat().st_mtime
            except OSError:
                background_started_at = None
            now = _time.time()
            background_elapsed = (
                int(now - float(background_started_at))
                if isinstance(background_started_at, (int, float))
                else None
            )
            running_data: dict[str, Any] = {
                "layer": layer_s,
                "state": "running",
                "source": "background",
                "pid": background_pid,
                "started_at": background_started_at,
                "elapsed_seconds": background_elapsed,
                "progress": _background_build_progress(root),
            }
            _running_prev = _read_index_build_stats_file(root, layer_s)
            if _running_prev is not None:
                running_data["previous_stats"] = _running_prev
            if stale_locks_cleaned:
                running_data["stale_locks_cleaned"] = stale_locks_cleaned
            return _response(
                "ok",
                running_data,
                next_tools=["index_build_status"],
                usage="index_build_status()",
            )
        idle_data: dict[str, Any] = {"layer": layer_s, "state": "idle"}
        if stale_locks_cleaned:
            idle_data["stale_locks_cleaned"] = stale_locks_cleaned
        return _response("ok", idle_data, next_tools=["index_build"], usage="index_build()")

    try:
        state = json.loads(state_path.read_text(encoding="utf-8"))
    except (OSError, json.JSONDecodeError):
        _clear_index_build_state(root, layer_s)
        idle_data = {"layer": layer_s, "state": "idle"}
        if stale_locks_cleaned:
            idle_data["stale_locks_cleaned"] = stale_locks_cleaned
        return _response("ok", idle_data, next_tools=["index_build"], usage="index_build()")

    pid = state.get("pid")
    started_at = state.get("started_at")
    now = _time.time()
    elapsed = int(now - float(started_at)) if isinstance(started_at, (int, float)) else None

    # Read log once — used for last_line (progress) and done-marker detection.
    # Check log for completion marker before trusting _pid_is_running — the OS can
    # recycle a PID to an unrelated process after the indexer exits, causing a false positive.
    log_text = ""
    last_line = ""
    if log_path.exists():
        try:
            log_text = log_path.read_text(encoding="utf-8", errors="replace")
            last_line = next((l.strip() for l in reversed(log_text.splitlines()) if l.strip()), "")
        except OSError:
            pass
    # Either the "done — N files indexed" completion line or the "index is up to date"
    # early-exit message counts as a terminal state. Without the second pattern, a zombie
    # process (defunct on macOS) keeps reporting state="running" indefinitely because
    # os.kill(pid, 0) succeeds on zombies until the parent reaps them.
    log_done = bool(re.search(r"done\s*[—-]+\s*\d+\s+files? indexed", log_text)) or bool(
        re.search(r"index is up to date", log_text)
    )

    if layer_s == "project" and background_status == "running":
        pid_path = root / ".wavefoundry" / "index" / "background-build.pid"
        background_pid: Optional[int] = None
        background_started_at: Optional[float] = None
        try:
            background_pid = int(pid_path.read_text(encoding="utf-8").strip())
        except (OSError, ValueError):
            background_pid = None
        try:
            background_started_at = pid_path.stat().st_mtime
        except OSError:
            background_started_at = None
        background_elapsed = (
            int(now - float(background_started_at))
            if isinstance(background_started_at, (int, float))
            else None
        )
        running_data: dict[str, Any] = {
            "layer": layer_s,
            "state": "running",
            "source": "background",
            "pid": background_pid,
            "started_at": background_started_at,
            "elapsed_seconds": background_elapsed,
            "progress": _background_build_progress(root),
        }
        _running_prev = _read_index_build_stats_file(root, layer_s)
        if _running_prev is not None:
            running_data["previous_stats"] = _running_prev
        if stale_locks_cleaned:
            running_data["stale_locks_cleaned"] = stale_locks_cleaned
        return _response(
            "ok",
            running_data,
            next_tools=["index_build_status"],
            usage="index_build_status()",
        )

    if not log_done and isinstance(pid, int) and _pid_is_running(pid):
        running_data: dict[str, Any] = {
            "layer": layer_s,
            "state": "running",
            "source": "foreground",
            "mode": "rebuild" if state.get("full") else state.get("mode", "update"),
            "pid": pid,
            "started_at": started_at,
            "elapsed_seconds": elapsed,
            "progress": last_line,
        }
        _running_prev = _read_index_build_stats_file(root, layer_s)
        if _running_prev is not None:
            running_data["previous_stats"] = _running_prev
        if stale_locks_cleaned:
            running_data["stale_locks_cleaned"] = stale_locks_cleaned
        return _response(
            "ok",
            running_data,
            next_tools=["index_build_status"],
            usage="index_build_status()",
        )

    # Process not running (or log confirms done) — build finished (or crashed). Parse summary from log.
    _refresh_index_build_stats_from_finished_log(root, layer_s)
    _clear_index_build_state(root, layer_s)
    finished_at = None
    if log_path.exists():
        try:
            finished_at = int(log_path.stat().st_mtime)
        except OSError:
            pass
    finished_elapsed = int(float(finished_at) - float(started_at)) if finished_at and isinstance(started_at, (int, float)) else elapsed

    files_indexed: Optional[int] = None
    doc_chunks: Optional[int] = None
    code_chunks: Optional[int] = None
    if log_text:
        m = re.search(r"done\s*[—-]+\s*(\d+)\s+files? indexed,\s*(\d+)\s+doc chunks?,\s*(\d+)\s+code chunks?", log_text)
        if m:
            files_indexed, doc_chunks, code_chunks = int(m.group(1)), int(m.group(2)), int(m.group(3))

    previous_stats = _read_index_build_stats_file(root, layer_s)
    summary: dict[str, Any] = {"layer": layer_s, "state": "finished", "started_at": started_at, "finished_at": finished_at, "elapsed_seconds": finished_elapsed}
    if files_indexed is not None:
        summary.update({"files_indexed": files_indexed, "doc_chunks": doc_chunks, "code_chunks": code_chunks})
    else:
        summary["last_log_line"] = last_line
    if previous_stats is not None:
        summary["previous_stats"] = previous_stats
    if stale_locks_cleaned:
        summary["stale_locks_cleaned"] = stale_locks_cleaned
    return _response("ok", summary, next_tools=["index_health"], usage="index_health()")


def wf_start_dashboard_response(root: Path, port: int | None = None) -> dict[str, Any]:
    """Start the local dashboard server (with browser open) or return its URL if already running."""
    import subprocess
    import time as _time
    import dashboard_lib

    # Wave 1rswx: reap finished dashboard children on entry so a prior crashed instance's zombie can't
    # linger and can't be misread by the reconcile/liveness checks below.
    _reap_dashboard_child_pids()

    meta_path = dashboard_lib.dashboard_metadata_path(root)  # 1p64x: the server lock file

    def running_meta() -> dict[str, Any] | None:
        if not meta_path.exists():
            return None
        try:
            meta = json.loads(meta_path.read_text(encoding="utf-8"))
            pid = meta.get("pid")
            url = meta.get("url", "")
            # Wave 1p654: require the PID be a live dashboard for THIS root, not
            # merely os.kill-alive — a recycled/zombie PID must not read as running.
            if isinstance(pid, int) and _dashboard_pid_is_live(pid, root) and url:
                return {"pid": pid, "url": url}
        except (OSError, json.JSONDecodeError):
            pass
        return None

    def already_running(meta: dict[str, Any], *, starting: bool = False) -> dict[str, Any]:
        data: dict[str, Any] = {
            "already_running": True,
            "pid": meta.get("pid"),
            "url": meta.get("url"),
        }
        if starting:
            data["starting"] = True
        return _response(
            "ok",
            data,
            next_tools=["wf_open_dashboard"],
            usage=str(meta.get("url") or "wf_open_dashboard()"),
        )

    def wait_for_running(timeout: float = DASHBOARD_START_WAIT_SECONDS) -> dict[str, Any] | None:
        deadline = _time.monotonic() + timeout
        while _time.monotonic() < deadline:
            meta = running_meta()
            if meta is not None:
                return meta
            _time.sleep(0.25)
        return None

    meta = running_meta()
    if meta is not None:
        return already_running(meta)
    # Wave 1p8pf: also early-out when a dashboard is serving under a drifted/non-matching PID (reachable
    # URL + a live dashboard process) so we never even acquire the start lock to spawn a duplicate.
    serving = _dashboard_already_serving(root, meta_path)
    if serving is not None:
        return already_running(serving)

    try:
        start_lock = dashboard_lib.dashboard_start_lock(root)
        start_lock.__enter__()
    except dashboard_lib.DashboardLockBusy:
        meta = wait_for_running()
        if meta is not None:
            return already_running(meta, starting=True)
        return _response(
            "ok",
            {"already_running": True, "starting": True, "pid": None, "url": None},
            diagnostics=[_diagnostic(
                "dashboard_start_in_progress",
                "Another dashboard start is already in progress for this repository.",
            )],
            next_tools=["wf_open_dashboard"],
            usage="wf_open_dashboard()",
        )

    def server_lock_held() -> bool:
        """Best-effort flock-try on the lifetime lock: busy => the child holds it."""
        try:
            probe = dashboard_lib.dashboard_server_lock(root)
            probe.__enter__()
        except dashboard_lib.DashboardLockBusy:
            return True
        except Exception:
            return False
        # We acquired it ourselves => the child does NOT hold it; release immediately.
        try:
            probe.__exit__(None, None, None)
        except Exception:
            pass
        return False

    try:
        meta = running_meta()
        if meta is not None:
            return already_running(meta)

        # Wave 1p8pf: reconcile-before-spawn — a dashboard may be serving under a DIFFERENT PID than
        # any we recorded (the field race: prior spawn wrote metadata under PID X, this start polls for
        # PID Y). Recognize it by URL-reachability + a live dashboard process and return that URL
        # instead of spawning a duplicate (which climbed ports). running_meta() above already adopted
        # the live-recorded-PID case; this catches the PID-drift case before we kill orphans/spawn.
        serving = _dashboard_already_serving(root, meta_path)
        if serving is not None:
            return already_running(serving)

        # Wave 1p654: no valid recorded instance — but orphaned dashboards for this
        # root may still be alive (drifted/removed metadata). Terminate them so we
        # converge to exactly one instance instead of spawning alongside (the cause
        # of orphan accumulation + port climb). A genuinely-live instance was
        # already adopted by running_meta()/_dashboard_already_serving above; this only
        # fires on real drift (a dead/unreachable recorded instance).
        orphan_diags: list[dict[str, Any]] = []
        _orphans = _dashboard_cmdline_pids(root) or []
        if _orphans:
            for _op in _orphans:
                _terminate_dashboard_pid(_op)
            orphan_diags.append(_diagnostic(
                "dashboard_orphan_detected",
                f"Terminated {len(_orphans)} orphaned dashboard process(es) for this repository before starting.",
            ))

        scripts_dir = Path(__file__).resolve().parent
        cmd = [_preferred_python(), str(scripts_dir / "dashboard_server.py"), "--root", str(root)]
        if port is not None:
            cmd.extend(["--port", str(port)])
        if dashboard_lib.dashboard_browser_open_enabled():
            cmd.append("--open")
        spawn_kwargs: dict[str, Any] = {
            "stdout": subprocess.DEVNULL,
            "stderr": subprocess.DEVNULL,
            "stdin": subprocess.DEVNULL,
            "cwd": str(root),
        }
        if os.name == "nt":
            spawn_kwargs["creationflags"] = (
                subprocess.DETACHED_PROCESS | subprocess.CREATE_NEW_PROCESS_GROUP | _windows_no_window_flag()
            )
        else:
            spawn_kwargs["start_new_session"] = True

        try:
            proc = subprocess.Popen(cmd, **spawn_kwargs)
        except OSError as exc:
            return _response(
                "error",
                {},
                diagnostics=[_diagnostic("spawn_failed", str(exc))],
            )

        # Wave 1rswx: track this server-launched dashboard so a later sweep (index-refresh or any
        # dashboard entry point) reaps it once it exits (POSIX), instead of leaving a defunct PID that
        # a bare os.kill liveness check would misread as a live kill target.
        _register_dashboard_child_pid(proc.pid)

        # Poll up to 5s for a SERVING dashboard (host, port, URL). Wave 1p8pf: accept a serving
        # dashboard by URL-reachability and/or a live dashboard PID for this root — NOT by matching the
        # just-spawned proc.pid. The old PID-exact check (`meta.pid == proc.pid`) false-reported
        # url_not_ready whenever a prior spawn had already written metadata under a different PID, then
        # spawned a duplicate that climbed ports. The bounded deadline still makes a genuinely-failed
        # start (no URL, no reachable server) report failure.
        url = ""
        deadline = _time.monotonic() + DASHBOARD_START_WAIT_SECONDS
        while _time.monotonic() < deadline:
            _time.sleep(0.25)
            if not meta_path.exists():
                continue
            try:
                meta = json.loads(meta_path.read_text(encoding="utf-8"))
            except (OSError, json.JSONDecodeError):
                continue
            meta_url = meta.get("url") or ""
            if not meta_url:
                continue
            meta_pid = meta.get("pid")
            # The just-spawned process owns the metadata → the spawn wrote its own URL: success
            # (unchanged from the original PID-exact accept, so the spawn path is fully backward
            # compatible). This is the common case.
            if meta_pid == proc.pid:
                url = meta_url
                break
            # The metadata PID does NOT match proc.pid (the field race: a prior spawn wrote it). Accept
            # the serving dashboard by liveness + reachability, NOT by our own PID — this is the bug fix.
            # A live dashboard PID for this root, OR an HTTP-reachable URL, proves it is serving.
            if isinstance(meta_pid, int) and _dashboard_pid_is_live(meta_pid, root):
                url = meta_url
                break
            if _dashboard_url_reachable(meta_url):
                url = meta_url
                break

        if not url:
            return _response(
                "ok",
                {"started": True, "pid": proc.pid, "url": None},
                diagnostics=[*orphan_diags, _diagnostic(
                    "url_not_ready",
                    "Dashboard spawned but URL not yet available — it may still be binding.",
                )],
            )

        # Confirm the child holds the lifetime lock before declaring success.
        # Releasing the persistent launch-mutex OS lock is then safe because
        # dashboard-server.lock already gates concurrent starts; the carrier
        # itself deliberately remains under .wavefoundry/locks/.
        server_lock_held()
        return _response(
            "ok",
            {"started": True, "pid": proc.pid, "url": url},
            diagnostics=orphan_diags or None,
            usage=url,
        )
    finally:
        start_lock.__exit__(None, None, None)


def wf_open_dashboard_response(root: Path) -> dict[str, Any]:
    """Open the browser to the running dashboard, or start the dashboard (with browser open) if not running."""
    import webbrowser
    import dashboard_lib

    # Wave 1rswx: reap finished dashboard children so a zombie recorded PID isn't reported as serving.
    _reap_dashboard_child_pids()

    meta_path = dashboard_lib.dashboard_metadata_path(root)
    if meta_path.exists():
        try:
            meta = json.loads(meta_path.read_text(encoding="utf-8"))
            pid = meta.get("pid")
            url = meta.get("url", "")
            # Wave 1rswx: zombie-safe liveness (cmdline-verified) so a <defunct> recorded PID is not
            # reported as a live/serving dashboard (Req 7 / AC-5) — align with the start-path treatment.
            if isinstance(pid, int) and _dashboard_pid_is_live(pid, root) and url:
                opened = False
                if dashboard_lib.dashboard_browser_open_enabled():
                    webbrowser.open(url)
                    opened = True
                return _response(
                    "ok",
                    {"opened": opened, "url": url, "browser_suppressed": not opened},
                    usage=url,
                )
        except (OSError, json.JSONDecodeError):
            pass

    # Dashboard not running — delegate to start (which spawns with --open).
    return wf_start_dashboard_response(root)


def _dashboard_cmdline_pids(root: Path) -> list[int] | None:
    """Live dashboard PIDs for ``root`` by cmdline scan — delegates to the shared
    ``dashboard_lib.dashboard_cmdline_pids`` (1p654; relocated to the shared module
    in the 1p654 review follow-up so upgrade dashboard detection reuses it)."""
    import dashboard_lib

    return dashboard_lib.dashboard_cmdline_pids(root)


def _dashboard_pid_is_live(pid: int, root: Path) -> bool:
    """True only if ``pid`` is running AND is a dashboard for ``root`` (1p654).

    Hardens the bare ``_pid_is_running`` (a zombie or recycled PID passes
    ``os.kill(pid, 0)``) by requiring a cmdline match. When the scan is
    unavailable (``_dashboard_cmdline_pids`` returns None), falls back to the bare
    liveness check so unsupported platforms keep their current behavior.
    """
    if not _pid_is_running(pid):
        return False
    live = _dashboard_cmdline_pids(root)
    if live is None:
        return True
    return pid in live


def _dashboard_url_reachable(url: str, timeout: float = 1.0) -> bool:
    """True iff ``url`` answers an HTTP request (any status — a serving dashboard).

    Wave 1p8pf: the dashboard start path must recognize an already-serving dashboard by
    URL-reachability, not by matching the just-spawned PID. A reachable URL is proof the server
    is up regardless of which PID owns it; any HTTP response (incl. 4xx/5xx) counts as serving —
    only a connection failure / timeout means "not reachable". Never raises.
    """
    if not url:
        return False
    import urllib.request
    import urllib.error

    try:
        req = urllib.request.Request(url, method="GET")
        with urllib.request.urlopen(req, timeout=timeout):  # noqa: S310 — loopback dashboard URL
            return True
    except urllib.error.HTTPError:
        # The server answered with an HTTP error status — it IS serving.
        return True
    except Exception:
        # Connection refused / DNS / timeout / SSE-hang — treat as not (yet) reachable.
        return False


def _dashboard_already_serving(root: Path, meta_path: Path) -> dict[str, Any] | None:
    """Reconcile-before-spawn: return a serving dashboard's metadata, or None.

    Wave 1p8pf: a dashboard counts as already-serving when EITHER
      (a) the recorded metadata names a live dashboard PID for ``root`` with a URL
          (the wave-1p654 ``running_meta`` contract — the common reconcile case, incl. the field
          race once the just-spawned child's PID is the live recorded one), OR
      (b) the recorded URL is actually HTTP-reachable AND a live dashboard process exists for
          ``root`` (cmdline scan) — the dashboard is genuinely serving under a PID that differs from
          the recorded one (the field race: a prior spawn wrote metadata under a different PID). A
          reachable URL means killing+respawning would only churn a working server.
    A present-but-DEAD recorded PID whose URL is NOT reachable is a genuine drift — return None so the
    orphan reconciliation terminates the stale process and respawns (converge to one instance).
    Returns ``{"pid", "url"}`` when serving, else None. Never raises.
    """
    if not meta_path.exists():
        return None
    try:
        meta = json.loads(meta_path.read_text(encoding="utf-8"))
    except (OSError, json.JSONDecodeError):
        return None
    pid = meta.get("pid")
    url = meta.get("url", "") or ""
    if not url:
        return None
    # (a) live recorded PID + URL.
    if isinstance(pid, int) and _dashboard_pid_is_live(pid, root):
        return {"pid": pid, "url": url}
    # (b) a genuinely-reachable URL backed by a live dashboard process for this root (any PID) — adopt
    # rather than churn. A NON-reachable URL falls through to the orphan reconciliation (drift).
    if _dashboard_url_reachable(url):
        live = _dashboard_cmdline_pids(root)
        if live:
            return {"pid": live[0], "url": url}
    return None


def _dashboard_process_metadata(root: Path) -> tuple[Path, dict[str, Any]]:
    import dashboard_lib

    meta_path = dashboard_lib.dashboard_metadata_path(root)
    return meta_path, dashboard_lib.read_dashboard_metadata(root)


def _remove_dashboard_metadata(meta_path: Path) -> bool:
    try:
        meta_path.unlink()
        return True
    except FileNotFoundError:
        return False
    except OSError:
        return False


def _terminate_dashboard_pid(pid: int) -> bool:
    import subprocess
    import time as _time

    if pid <= 0:
        return True

    if os.name == "nt":
        try:
            completed = _mcp_subprocess_run(
                ["taskkill", "/PID", str(pid), "/T", "/F"],
                capture_output=False,
                cwd=str(Path.cwd()),
                check=False,
            )
        except OSError:
            return False
        return completed.returncode == 0 or not _pid_is_running(pid)

    import signal

    try:
        os.kill(pid, signal.SIGTERM)
    except ProcessLookupError:
        return True
    except OSError:
        return False

    deadline = _time.monotonic() + 5.0
    while _time.monotonic() < deadline:
        if not _pid_is_running(pid):
            return True
        try:
            ended_pid, _ = os.waitpid(pid, os.WNOHANG)
        except ChildProcessError:
            ended_pid = 0
        except OSError:
            ended_pid = 0
        if ended_pid == pid:
            return True
        _time.sleep(0.1)

    try:
        os.kill(pid, signal.SIGKILL)
    except ProcessLookupError:
        return True
    except OSError:
        return False

    deadline = _time.monotonic() + 2.0
    while _time.monotonic() < deadline:
        if not _pid_is_running(pid):
            return True
        try:
            ended_pid, _ = os.waitpid(pid, os.WNOHANG)
        except ChildProcessError:
            ended_pid = 0
        except OSError:
            ended_pid = 0
        if ended_pid == pid:
            return True
        _time.sleep(0.1)

    return not _pid_is_running(pid)


def wf_stop_dashboard_response(root: Path) -> dict[str, Any]:
    # Wave 1rswx: reap any of our finished dashboard children first, so a recorded PID that is now a
    # <defunct> zombie is cleared from the process table (and no longer passes os.kill(pid,0)) before we
    # classify targets — otherwise the zombie was added as a kill target and stop returned stop_failed.
    _reap_dashboard_child_pids()

    meta_path, meta = _dashboard_process_metadata(root)
    pid = meta.get("pid")
    url = meta.get("url", "")

    summary: dict[str, Any] = {
        "pid": pid if isinstance(pid, int) else None,
        "url": url if isinstance(url, str) else "",
    }

    # Wave 1p654: reconcile against ALL live dashboards for this root — not just the
    # recorded PID — so a drifted/removed metadata file can't leave an orphan alive.
    scanned = _dashboard_cmdline_pids(root)
    targets: set[int] = set(scanned or [])
    # Wave 1rswx: classify the recorded PID with the cmdline-verified, zombie-safe check (not a bare
    # os.kill liveness). A <defunct> recorded PID fails this test — so it is treated as already stopped
    # (metadata cleared below) instead of a live kill target that SIGTERM/SIGKILL can never reap. A
    # genuinely-live dashboard for this root is already in ``targets`` via the cmdline scan above.
    #
    # SECURITY CONTROL (1rswx AC-3): we never fall back to killing an os.kill-alive-but-unverified
    # recorded PID, because a zombie/recycled PID is indistinguishable from a scan-missed live dashboard
    # WITHOUT the cmdline check — SIGKILLing it could hit a PID recycled to an unrelated process. So when
    # the scan RUNS but misses a genuinely-live dashboard (e.g. a symlink path component repointed
    # mid-session so its --root no longer resolves-equal), that instance is NOT added to targets and is
    # never signalled. The scan-UNAVAILABLE (None) case still falls back to bare liveness inside
    # _dashboard_pid_is_live. (Wave 1rvfw handles the reporting for that unverified-alive case below.)
    if isinstance(pid, int) and pid > 0 and _dashboard_pid_is_live(pid, root):
        targets.add(pid)

    if not targets:
        # Wave 1rvfw: distinguish "genuinely stopped" from "alive but unverifiable". If the recorded PID
        # is still os.kill-alive but was NOT cmdline-verified (not in targets), do NOT claim
        # already_stopped and do NOT delete the metadata — that would be a false success plus state loss
        # while the process keeps serving. Report honestly (already_stopped=False, stopped=False, keep
        # metadata) with a distinct diagnostic and leave the kill decision untouched (the PID is never
        # signalled — the AC-3 control stands). A genuinely dead/reaped/absent PID — including a
        # 1rswx-reaped <defunct> zombie, which is no longer os.kill-alive — takes the clean
        # already_stopped + metadata-cleared path below.
        if isinstance(pid, int) and pid > 0 and _pid_is_running(pid):
            summary.update({"already_stopped": False, "stopped": False})
            return _response(
                "ok",
                summary,
                diagnostics=[_diagnostic(
                    "dashboard_pid_unverified",
                    f"Recorded dashboard PID {pid} is alive but could not be verified as a dashboard for "
                    "this repository (it may be a recycled PID now owned by an unrelated process, or a "
                    "live dashboard the process scan could not match for this root). It was NOT "
                    "terminated and the metadata was kept; investigate and stop it manually if it is a "
                    "stray dashboard.",
                )],
                usage="wf_stop_dashboard()",
            )
        summary.update({"already_stopped": True, "metadata_removed": _remove_dashboard_metadata(meta_path)})
        return _response("ok", summary, usage="wf_stop_dashboard()")

    failed = [p for p in sorted(targets) if not _terminate_dashboard_pid(p)]
    stopped = [p for p in sorted(targets) if p not in failed]
    if failed:
        return _response(
            "error",
            {**summary, "stopped_pids": stopped},
            diagnostics=[_diagnostic("stop_failed", f"Dashboard process(es) {failed} for this repository did not exit cleanly.")],
            usage="wf_stop_dashboard()",
        )

    orphan_count = len([p for p in stopped if p != pid])
    summary.update({"stopped": True, "stopped_pids": stopped, "metadata_removed": _remove_dashboard_metadata(meta_path)})
    if orphan_count:
        summary["orphans_terminated"] = orphan_count
    return _response("ok", summary, usage="wf_stop_dashboard()")


def wf_restart_dashboard_response(root: Path) -> dict[str, Any]:
    # R7 (revised): Allow restart during upgrade. The restarted dashboard
    # detects the upgrade lock at startup and enters upgrade_paused
    # automatically, then resumes when the lock is removed. Blocking the
    # restart was redundant and prevented legitimate recovery via restart.

    # Capture the current port before stopping so the restarted server reuses
    # the same port — the browser tab stays valid without a refresh.
    restart_port: int | None = None
    try:
        _, pre_meta = _dashboard_process_metadata(root)
        recorded_port = pre_meta.get("port")
        if isinstance(recorded_port, int) and recorded_port > 0:
            restart_port = recorded_port
    except Exception:  # noqa: BLE001
        pass

    stop_env = wf_stop_dashboard_response(root)
    if stop_env.get("status") != "ok":
        return stop_env
    start_env = wf_start_dashboard_response(root, port=restart_port)
    if start_env.get("status") != "ok":
        return start_env
    data = dict(stop_env.get("data", {}))
    data.update(start_env.get("data", {}))
    data["restarted"] = True
    return _response(
        "ok",
        data,
        diagnostics=list(stop_env.get("diagnostics", [])) + list(start_env.get("diagnostics", [])),
        next_tools=list(start_env.get("next_tools", [])),
        usage=start_env.get("usage", ""),
    )


def _load_upgrade_lib() -> Any:
    """Import upgrade_lib from the scripts directory, ensuring it is on sys.path."""
    _scripts_dir = str(Path(__file__).resolve().parent)
    if _scripts_dir not in sys.path:
        sys.path.insert(0, _scripts_dir)
    try:
        import upgrade_lib as _ulib  # noqa: PLC0415
        return _ulib
    except ImportError:
        return None


# Wave 1p8eu / TA-1 — the sentinel prefix is the SINGLE constant defined in upgrade_wavefoundry; import
# it (never redefine) so the emit side and the parse side cannot silently desync. A literal fallback is
# kept ONLY for the (practically impossible) case where upgrade_wavefoundry is unimportable in the
# server process — it must equal the canonical value, which a round-trip test enforces.
def _upgrade_summary_sentinel() -> str:
    """Return the canonical ``WAVE_UPGRADE_SUMMARY_JSON:`` sentinel from upgrade_wavefoundry."""
    _scripts_dir = str(Path(__file__).resolve().parent)
    if _scripts_dir not in sys.path:
        sys.path.insert(0, _scripts_dir)
    try:
        import upgrade_wavefoundry as _uw  # noqa: PLC0415
        return _uw.WAVE_UPGRADE_SUMMARY_SENTINEL
    except Exception:  # noqa: BLE001 — fail-safe; the round-trip test pins the fallback to canonical
        return "WAVE_UPGRADE_SUMMARY_JSON:"


def _parse_upgrade_summary(output: str) -> dict[str, Any] | None:
    """Parse the structured operator summary from the upgrade subprocess output (wave 1p8eu).

    Scans ``output`` for the last ``WAVE_UPGRADE_SUMMARY_JSON:`` sentinel line and returns the parsed
    JSON dict. FAIL-SAFE: returns ``None`` when the sentinel is absent or the JSON is malformed (any
    parse error, including RecursionError on a pathological payload) — the caller then falls back to
    the raw ``output`` with no exception. The last occurrence wins so a re-run that appends to the log
    surfaces the most recent summary.
    """
    if not output:
        return None
    sentinel = _upgrade_summary_sentinel()
    found: dict[str, Any] | None = None
    for line in output.splitlines():
        if line.startswith(sentinel):
            payload = line[len(sentinel):].strip()
            # F1 — broaden to Exception so a RecursionError (deeply-nested JSON) cannot escape and
            # violate the AC-3 "malformed → no exception" guarantee.
            try:
                parsed = json.loads(payload)
            except Exception:  # noqa: BLE001 — any parse failure → skip this line, fall back to output
                continue
            if isinstance(parsed, dict):
                found = parsed
    return found


def _upgrade_next_step(phase: str) -> tuple[str, list[str]]:
    """Return a phase-aware ``(next_step, next_tools)`` for the wf_upgrade response (wave 1p8eu)."""
    if phase == "preflight_to_docs_gate":
        return (
            "Run the agent editing pass (drift/journal/spec reconciliation per seed-160), then "
            "call wf_upgrade(phase='update_index') and wf_upgrade(phase='cleanup').",
            ["wf_upgrade_status", "wf_reload_mcp"],
        )
    if phase in ("update_index", "rebuild_index"):
        return (
            "Call wf_upgrade(phase='cleanup') to remove the upgrade lock and print the summary.",
            ["wf_upgrade_status", "wf_reload_mcp"],
        )
    if phase == "cleanup":
        return (
            "Upgrade complete. Call wf_reload_mcp() if the in-process server code is not yet "
            "reloaded; review the summary's reconciliation findings and resolve stale references.",
            ["wf_reload_mcp", "wf_upgrade_status"],
        )
    if phase == "resume_after_gate":
        return (
            "Docs gate re-run finished; check wf_upgrade_status, then continue with "
            "wf_upgrade(phase='update_index') and wf_upgrade(phase='cleanup').",
            ["wf_upgrade_status"],
        )
    if phase == "resume_after_memory":
        return (
            "When the response reports indexed, call wf_upgrade(phase='cleanup'). "
            "If it remains awaiting validation, continue bounded backfill and "
            "memory_validate calls first.",
            ["memory_backfill", "memory_validate", "wf_upgrade_status"],
        )
    return ("Check wf_upgrade_status for the current lock state.", ["wf_upgrade_status"])


def wf_upgrade_response(
    root: Path,
    phase: str = "preflight_to_docs_gate",
    mode: str = "apply",
) -> dict[str, Any]:
    """Invoke upgrade_wavefoundry.py for the requested phase (12r0b).

    mode values:
      "dry_run" — print the full upgrade plan + hook inventory (seed diffs,
          extension module source, convention hook scripts) without modifying
          anything on disk. Use this before the real upgrade to review what
          will change and inspect any hook code. The phase parameter is
          ignored in dry_run mode.
      "apply" (default) — execute the requested phase for real.

    phase values (apply mode only):
      "preflight_to_docs_gate" — phases 0–3 (default): pre-flight, surface
          rendering, pruning, docs gate. Non-interactive (--yes).
      "update_index" — phase 4 (default): incremental docs index update
          (blocking) + code index (background). Re-embeds only files that
          changed; auto-escalates to full rebuild when chunker or embedding
          model version changed. Use for normal post-editing-pass runs.
      "rebuild_index" — phase 4 (full): re-embeds every file from scratch.
          Use when update_index is insufficient (e.g. index corruption, or
          a chunker bump that the auto-escalation did not catch).
      "cleanup" — phase 5: remove upgrade lock + print operator summary.
      "resume_after_gate" — rebuild and persist current review-status projection,
          then re-run docs-gardener + docs-lint against the already-extracted
          tree (no extract/render/prune). Recovers a retained lock whose
          failed_phase is "review_status_projection" or "docs_gate"; preserves
          the actual failing phase on retry and clears it only after both pass.
      "resume_after_memory" — recompute the authoritative historical-memory
          pending set and publish Phase 4 only after it reaches zero. This and
          every index/cleanup phase refuse while review projection or docs lint
          has a retained failed phase; recover through "resume_after_gate".
    """
    valid_modes = ("apply", "dry_run")
    if mode not in valid_modes:
        return _response(
            "error",
            {"mode": mode, "valid_modes": list(valid_modes)},
            diagnostics=[_diagnostic("invalid_mode", f"Unknown mode {mode!r}. Valid: {valid_modes}")],
        )

    valid_phases = (
        "preflight_to_docs_gate",
        "update_index",
        "rebuild_index",
        "cleanup",
        "resume_after_gate",
        "resume_after_memory",
    )
    if mode == "apply" and phase not in valid_phases:
        return _response(
            "error",
            {"phase": phase, "valid_phases": list(valid_phases)},
            diagnostics=[_diagnostic("invalid_phase", f"Unknown phase {phase!r}. Valid: {valid_phases}")],
        )

    upgrade_script = Path(__file__).resolve().parent / "upgrade_wavefoundry.py"
    if not upgrade_script.exists():
        return _response(
            "error",
            {},
            diagnostics=[_diagnostic("script_not_found", f"upgrade_wavefoundry.py not found at {upgrade_script}")],
        )

    if mode == "dry_run":
        cmd = [_preferred_python(), str(upgrade_script), "--root", str(root), "--dry-run"]
    else:
        # Pre-create the log file so log_path in the response is always valid,
        # even if the upgrade fails before the script opens it.  The upgrade
        # script manages truncation (mode="w") and appending (mode="a") itself.
        _log_path = root / ".wavefoundry" / "logs" / "upgrade.log"
        try:
            _log_path.parent.mkdir(parents=True, exist_ok=True)
            _log_path.touch(exist_ok=True)
        except OSError:
            pass

        # All apply-mode phases run non-interactively (no TTY in MCP).
        cmd = [_preferred_python(), str(upgrade_script), "--root", str(root), "--yes"]
        if phase == "update_index":
            cmd.append("--update-index")
        elif phase == "rebuild_index":
            cmd.append("--rebuild-index")
        elif phase == "cleanup":
            cmd.append("--cleanup")
        elif phase == "resume_after_gate":
            cmd.append("--resume-after-gate")  # rebuild review projection, then re-run docs gate
        elif phase == "resume_after_memory":
            cmd.append("--resume-after-memory")
        # phase == "preflight_to_docs_gate": --yes only (default run)

    try:
        result = _mcp_subprocess_run(
            cmd,
            cwd=str(root),
            check=False,
        )
    except OSError as exc:
        return _response(
            "error",
            {"phase": phase},
            diagnostics=[_diagnostic("spawn_failed", str(exc))],
        )

    output = (result.stdout or "") + (result.stderr or "")
    # log_path is deterministic and always present for apply-mode phases;
    # dry_run is read-only so it writes no log file.
    log_path = (
        str(root / ".wavefoundry" / "logs" / "upgrade.log")
        if mode == "apply"
        else None
    )
    data = {
        "phase": phase,
        "exit_code": result.returncode,
        "output": output.strip(),
        "log_path": log_path,
    }

    # Wave 1p8eu — parse the structured operator summary emitted by upgrade_wavefoundry.py on its
    # WAVE_UPGRADE_SUMMARY_JSON: sentinel line into data['summary'] so agents read computed fields
    # (from/to version, pruned_count, docs_gate, index_update, failed_phase, is_major_or_minor, the
    # 1p8et reconciliation findings) instead of regex-scraping prose. FAIL-SAFE: an absent or
    # malformed sentinel leaves 'output' as the only payload — never raises; 'output' and 'exit_code'
    # stay unchanged (back-compatible).
    summary = _parse_upgrade_summary(output)
    if summary is not None:
        data["summary"] = summary

    # Wave 1p8eu / F2 — compute the phase-aware next step + next_tools BEFORE the returncode check so
    # both the success AND the failure response carry them.
    _next_step, _next_tools = _upgrade_next_step(phase)
    if result.returncode != 0 and (
        phase == "resume_after_gate" or "--resume-after-gate" in output
    ):
        _next_step = (
            "Resolve the typed review-state or docs findings, then retry "
            "wf_upgrade(phase='resume_after_gate'). Index publication and "
            "cleanup remain blocked until that recovery succeeds."
        )
        _next_tools = ["wf_upgrade_status", "wf_upgrade"]

    if result.returncode == 4:
        memory_gate: dict[str, Any] = {}
        try:
            _ulib = _load_upgrade_lib()
            lock = _ulib.read_upgrade_lock(root) if _ulib is not None else None
            run_id = (
                str(lock.get("memory_backfill_run_id") or "").strip()
                if isinstance(lock, dict)
                else ""
            )
            if run_id:
                backfill = _load_script("memory_backfill")
                memory_gate = {
                    **backfill.run_summary(root, run_id),
                    **backfill.validation_worklist(root, run_id),
                }
        except (OSError, RuntimeError, ValueError) as exc:
            memory_gate = {"status_error": str(exc)}
        action = _response(
            "ok",
            {
                **data,
                "state": "awaiting_memory_validation",
                "memory_backfill": memory_gate,
            },
            diagnostics=[],
            next_tools=["wf_reload_mcp", "memory_backfill", "memory_validate"],
        )
        action["next_step"] = (
            "Reload the newly installed MCP implementation, run bounded historical "
            "memory backfill and focused validation, then call "
            "wf_upgrade(phase='resume_after_memory')."
        )
        return action
    if result.returncode != 0:
        exit_meanings = {1: "docs gate failed", 2: "surface rendering failed", 3: "pre-flight check failed"}
        reason = exit_meanings.get(result.returncode, f"exited {result.returncode}")
        if result.returncode == 1 and (
            phase == "resume_after_gate" or "--resume-after-gate" in output
        ):
            reason = "review-state projection or docs gate failed"
        err = _response(
            "error",
            data,
            diagnostics=[_diagnostic("upgrade_failed", f"Upgrade phase '{phase}' failed: {reason}")],
            next_tools=_next_tools,
        )
        err["next_step"] = _next_step
        return err

    resp = _response("ok", data, usage=f"wf_upgrade(phase='{phase}')", next_tools=_next_tools)
    resp["next_step"] = _next_step
    # Wave 1p3dk / 1p3ho: reload the MCP server's in-process code after the
    # main upgrade phase or cleanup so subsequent MCP calls (index_health,
    # code_ask, etc.) use the freshly-extracted server_impl. Without this, the
    # parent MCP process keeps the old code in memory even though the new
    # framework files are on disk. Phase `preflight_to_docs_gate` now runs
    # Phase 4 (index update) inside the subprocess too, so reload here is the
    # final step that brings the running server in sync with everything else.
    if mode == "apply" and phase in ("preflight_to_docs_gate", "cleanup"):
        try:
            import server as _srv
            reload_resp = _srv.perform_mcp_reload()
            if reload_resp.get("status") == "ok":
                resp.setdefault("data", {})["mcp_reload"] = reload_resp.get("data", {})
            else:
                resp.setdefault("diagnostics", []).extend(reload_resp.get("diagnostics", []))
        except Exception as exc:
            resp.setdefault("diagnostics", []).append(
                _diagnostic("mcp_reload_skipped", f"In-process MCP reload skipped: {exc}")
            )
    return resp


def wf_upgrade_status_response(root: Path) -> dict[str, Any]:
    """Return the current upgrade lock state (R5 — 12r08)."""
    _ulib = _load_upgrade_lib()
    if _ulib is not None:
        lock = _ulib.read_upgrade_lock(root)
    else:
        lock = None

    if lock is None:
        data: dict[str, Any] = {
            "in_progress": False,
            "started_at": None,
            "from_version": None,
            "to_version": None,
            "pid": None,
        }
    else:
        data = {
            "in_progress": True,
            "started_at": lock.get("started_at"),
            "from_version": lock.get("from_version"),
            "to_version": lock.get("to_version"),
            "pid": lock.get("pid"),
        }
        run_id = str(lock.get("memory_backfill_run_id") or "").strip()
        if run_id:
            try:
                backfill = _load_script("memory_backfill")
                data["memory_backfill"] = {
                    **backfill.run_summary(root, run_id),
                    **backfill.validation_worklist(root, run_id),
                }
            except (OSError, RuntimeError, ValueError) as exc:
                data["memory_backfill"] = {
                    "run_id": run_id,
                    "status_error": str(exc),
                }
    return _response("ok", data, usage="wf_upgrade_status()")


def wf_run_sensors_response(root: Path) -> dict[str, Any]:
    """Run registered project sensors and return structured pass/fail results.

    Sensors are defined in ``docs/workflow-config.json`` under the ``sensors`` key.
    Each sensor entry must have ``name`` and ``command`` fields; ``dimension`` and
    ``description`` are optional.  Commands are run in a subprocess with ``cwd=root``.
    Results include per-sensor pass/fail, exit code, and stdout/stderr summary.
    """
    import subprocess
    sensors = _read_project_sensors(root)
    if not sensors:
        return _response(
            "ok",
            {"sensors_run": 0, "results": [], "all_passed": True, "notice": "No sensors registered in workflow-config.json."},
            next_tools=["wf_audit"],
            usage="wf_audit()",
        )
    results = []
    all_passed = True
    for sensor in sensors:
        cmd = sensor["command"]
        try:
            proc = _mcp_subprocess_run(
                cmd if isinstance(cmd, list) else cmd,
                shell=not isinstance(cmd, list),
                cwd=str(root),
                timeout=120,
            )
            passed = proc.returncode == 0
            output = (proc.stdout + proc.stderr).strip()
            summary_lines = output.splitlines()
            results.append({
                "name": sensor["name"],
                "dimension": sensor["dimension"],
                "passed": passed,
                "exit_code": proc.returncode,
                "output_summary": "\n".join(summary_lines[:20]) if summary_lines else "",
            })
            if not passed:
                all_passed = False
        except subprocess.TimeoutExpired:
            results.append({"name": sensor["name"], "dimension": sensor["dimension"], "passed": False, "exit_code": None, "output_summary": "Sensor timed out after 120s."})
            all_passed = False
        except Exception as exc:
            results.append({"name": sensor["name"], "dimension": sensor["dimension"], "passed": False, "exit_code": None, "output_summary": f"Sensor failed to run: {exc}"})
            all_passed = False

    diagnostics = []
    if not all_passed:
        failed = [r["name"] for r in results if not r["passed"]]
        diagnostics.append(_diagnostic(
            "sensor_failed",
            f"Sensor(s) failed: {', '.join(failed)}. Address failures before declaring done.",
            recovery_tools=["wf_run_sensors"],
            recovery_usage="wf_run_sensors()",
        ))
    return _response(
        "ok" if all_passed else "error",
        {"sensors_run": len(results), "results": results, "all_passed": all_passed},
        diagnostics=diagnostics,
        next_tools=["wf_audit"] if all_passed else ["wf_run_sensors"],
        usage="wf_audit()" if all_passed else "wf_run_sensors()",
    )


def wf_scan_secrets_response(root: Path, mode: str = "incremental") -> dict[str, Any]:
    """Run the secrets scanner and return a structured findings summary.

    mode: "incremental" uses git-changed files; "full" scans all tracked files.
    New findings are appended to docs/scan-findings.json as status 'pending'.

    Runs in a subprocess (matching the graph indexer architecture) so that
    ProcessPoolExecutor workers and the multiprocessing resource_tracker belong
    to the child process and exit when it does — the MCP server never acquires
    a resource_tracker of its own.
    """
    import sys as _sys
    scripts_dir = Path(__file__).resolve().parent
    if str(scripts_dir) not in _sys.path:
        _sys.path.insert(0, str(scripts_dir))

    try:
        from wave_lint_lib.constants import SCAN_FINDINGS_PATH
    except ImportError as exc:
        return _response(
            "error",
            {"error": f"secrets scanner not available: {exc}"},
            diagnostics=[_diagnostic("import_error", str(exc))],
        )

    import time as _time, json as _json

    scan_script = scripts_dir / "run_secrets_scan.py"
    _t0 = _time.monotonic()
    failures: list[str] = []

    try:
        proc = _mcp_subprocess_run(
            [_preferred_python(), str(scan_script), "--root", str(root), "--mode", mode],
            timeout=300, cwd=str(root),
        )
        if proc.returncode != 0:
            raise RuntimeError(proc.stderr.strip() or f"exit {proc.returncode}")
        _out = _json.loads(proc.stdout)
        failures = _out.get("failures", [])
        rules_hash_changed = _out.get("rules_hash_changed", False)
        escalated_to_full = _out.get("escalated_to_full", False)
    except Exception as _exc:
        # Subprocess unavailable or failed — fall back to in-process serial scan.
        rules_hash_changed = False
        escalated_to_full = False
        try:
            from wave_lint_lib.secrets_validators import check_hardcoded_secrets
            failures = check_hardcoded_secrets(root, scan_all=(mode == "full"), max_workers=1)
        except Exception:
            return _response(
                "error",
                {"error": f"secrets scan failed: {_exc}"},
                diagnostics=[_diagnostic("scan_error", str(_exc))],
            )

    elapsed_s = round(_time.monotonic() - _t0, 3)

    import json as _json
    findings_path = root / SCAN_FINDINGS_PATH
    findings: list[dict] = []
    if findings_path.exists():
        try:
            data = _json.loads(findings_path.read_text(encoding="utf-8"))
            if isinstance(data, list):
                findings = data
        except Exception:
            pass

    by_status: dict[str, int] = {}
    for entry in findings:
        s = entry.get("status", "unknown")
        by_status[s] = by_status.get(s, 0) + 1

    all_ok = len(failures) == 0
    return _response(
        "ok" if all_ok else "error",
        {
            "mode": mode,
            "effective_mode": "full" if (mode == "full" or escalated_to_full) else mode,
            "rules_hash_changed": rules_hash_changed,
            "escalated_to_full": escalated_to_full,
            "clean": all_ok,
            "elapsed_s": elapsed_s,
            "total_findings": len(findings),
            "by_status": by_status,
            "failures_total": len(failures),
            "failures": failures[:20] if failures else [],
            "findings_file": SCAN_FINDINGS_PATH,
        },
        diagnostics=[
            _diagnostic(
                "secrets_scan_failures",
                f"{len(failures)} secrets check failure(s) — review {SCAN_FINDINGS_PATH}",
                recovery_tools=["wf_scan_secrets"],
                recovery_usage="wf_scan_secrets(mode='full')",
            )
        ] if failures else [],
        next_tools=["wf_audit"] if all_ok else ["wf_scan_secrets"],
        usage="wf_audit()" if all_ok else "wf_scan_secrets(mode='full')",
    )


# ---------------------------------------------------------------------------
# Audit helpers: commit governance, harnessability, harness coverage, coherence
# ---------------------------------------------------------------------------

def _audit_commit_governance(root: Path) -> dict[str, Any]:
    """Scan recent git commits and classify as governed or unassociated."""
    cfg = _read_workflow_config(root)
    governance_cfg = cfg.get("commit_governance", {})
    window_days = int(governance_cfg.get("window_days", 30)) if isinstance(governance_cfg, dict) else 30
    exclusion_patterns = governance_cfg.get("exclusion_patterns", []) if isinstance(governance_cfg, dict) else []
    if not isinstance(exclusion_patterns, list):
        exclusion_patterns = []

    try:
        # Route through the shared helper so this MCP-reachable git probe never inherits the
        # JSON-RPC stdin and shows no console window on Windows (wave 1p88t subprocess isolation).
        result = _mcp_subprocess_run(
            ["git", "log", f"--since={window_days} days ago", "--pretty=format:%h %s"],
            cwd=str(root), timeout=15,
        )
        if result.returncode != 0:
            return {"available": False, "reason": "git log failed"}
        lines = [l.strip() for l in result.stdout.splitlines() if l.strip()]
    except Exception:
        return {"available": False, "reason": "git unavailable"}

    # Collect known wave/change ID prefixes from docs/waves/
    known_ids: set[str] = set()
    waves_dir = root / "docs" / "waves"
    if waves_dir.is_dir():
        for entry in waves_dir.iterdir():
            if entry.is_dir():
                # wave-id prefix like "12ecs"
                parts = entry.name.split(" ", 1)
                if parts:
                    known_ids.add(parts[0].lower())
                for f in entry.iterdir():
                    if f.suffix == ".md" and "-" in f.stem:
                        # change-id like "12ecs-feat"
                        cid = f.stem.split(" ")[0].lower()
                        known_ids.add(cid)

    governed, unassociated, excluded = [], [], []
    for line in lines:
        parts = line.split(" ", 1)
        sha = parts[0]
        msg = parts[1] if len(parts) > 1 else ""
        msg_lower = msg.lower()
        # Check exclusion patterns first
        if any(msg_lower.startswith(pat.lower()) or pat.lower() in msg_lower for pat in exclusion_patterns):
            excluded.append({"sha": sha, "message": msg})
            continue
        # Check association with known wave/change IDs
        associated = any(kid in msg_lower for kid in known_ids)
        if associated:
            governed.append({"sha": sha, "message": msg})
        else:
            unassociated.append({"sha": sha, "message": msg})

    return {
        "available": True,
        "window_days": window_days,
        "governed": governed,
        "unassociated": unassociated,
        "excluded": excluded,
        "governed_count": len(governed),
        "unassociated_count": len(unassociated),
    }


# Wave 1p35d (1p35p enterprise-deployment review): directories the JVM source-
# pattern fallback skips when walking canonical roots. Enterprise monorepos
# routinely vendor 3rd-party code, archive legacy implementations, or commit
# build-tool caches that contain matching source-file extensions; without this
# allowlist the heuristic would false-positive on any of them.
_JVM_SOURCE_WALK_IGNORE_DIRS: frozenset[str] = frozenset({
    "node_modules", "vendor", "third_party", "third-party", "thirdparty",
    "target", "build", "dist", "out", "bin", "obj",
    ".git", ".gradle", ".mvn", ".idea", ".vscode", ".settings",
    "__pycache__", ".pytest_cache", ".mypy_cache", ".ruff_cache", ".tox",
})

# Canonical JVM project root layouts in priority order. Maven/Gradle conventional
# layouts are checked first (highest specificity); src/ / app/ / lib/ are common
# unconventional fallbacks; root iterdir handles tiny single-file projects.
_JVM_CANONICAL_SOURCE_ROOTS = (
    ("src/main/java", True),
    ("src/main/kotlin", True),
    ("src/main/scala", True),
    ("src/main/groovy", True),
    ("src", True),
    ("app", True),
    ("lib", True),
    ("", False),  # top-level iterdir only — no recursive walk
)
_JVM_SOURCE_PATTERNS: frozenset[str] = frozenset({".java", ".kt", ".scala", ".groovy"})
_JVM_SOURCE_WALK_FILE_BUDGET = 5000  # bail after N files examined; guards against pathological monorepo walks


def _detect_jvm_source_evidence(root: Path) -> list[str]:
    """Return the first JVM source-pattern signal found in canonical project roots.

    Returns a single-element list (e.g. ``["*.java"]``) when a JVM source file
    is found in a canonical location, empty list otherwise. Walks bounded by
    ``_JVM_SOURCE_WALK_IGNORE_DIRS`` (skips vendored/build/archive dirs) and
    by ``_JVM_SOURCE_WALK_FILE_BUDGET`` (caps work on pathological monorepos).
    """
    files_examined = 0
    for rel, recurse in _JVM_CANONICAL_SOURCE_ROOTS:
        src_root = root / rel if rel else root
        if not src_root.is_dir():
            continue
        if recurse:
            try:
                stack = [src_root]
                while stack:
                    if files_examined >= _JVM_SOURCE_WALK_FILE_BUDGET:
                        return []
                    current = stack.pop()
                    try:
                        entries = list(current.iterdir())
                    except OSError:
                        continue
                    for entry in entries:
                        if files_examined >= _JVM_SOURCE_WALK_FILE_BUDGET:
                            return []
                        if entry.is_dir():
                            if entry.name in _JVM_SOURCE_WALK_IGNORE_DIRS:
                                continue
                            stack.append(entry)
                            continue
                        if entry.is_file():
                            files_examined += 1
                            if entry.suffix in _JVM_SOURCE_PATTERNS:
                                return [f"*{entry.suffix}"]
            except OSError:
                continue
        else:
            # Top-level iterdir only — files directly at repo root.
            try:
                for entry in src_root.iterdir():
                    if entry.is_file() and entry.suffix in _JVM_SOURCE_PATTERNS:
                        return [f"*{entry.suffix}"]
            except OSError:
                continue
    return []


# Wave 1p35d (1p35p enterprise-deployment hardening, monorepo detection):
# workspace-marker files signal the operator-CWD is a monorepo parent rather
# than a single project. When present, harnessability checks aggregate signals
# across sub-projects instead of returning a misleading "no config" answer
# based only on the parent dir.
_MONOREPO_MARKER_FILES: tuple[str, ...] = (
    "nx.json",
    "lerna.json",
    "rush.json",
    "pnpm-workspace.yaml",
    "WORKSPACE",          # Bazel
    "WORKSPACE.bazel",
    "MODULE.bazel",
    "pants.toml",         # Pants
    ".buckconfig",        # Buck/Buck2
    "BUCK",
)

# Canonical sub-project parent dirs in monorepo layouts. The walk goes one
# level deep into each — `services/auth-service/` is a sub-project; deeper
# nesting (`services/auth-service/src/main/java/.../`) is left to the per-
# sub-project type-coverage check.
_MONOREPO_SUBPROJECT_PARENTS: tuple[str, ...] = (
    "services",
    "apps",
    "libs",
    "packages",
    "crates",
    "modules",
    "subprojects",
    "components",
    "projects",
)

# Per-sub-project type-config file markers. Each entry: (filename, label-on-evidence).
_SUBPROJECT_TYPE_CONFIG_FILES: tuple[tuple[str, str], ...] = (
    ("tsconfig.json", "tsconfig.json"),
    ("mypy.ini", "mypy.ini"),
    ("pyrightconfig.json", "pyrightconfig.json"),
    (".pyrightconfig.json", ".pyrightconfig.json"),
    ("pom.xml", "pom.xml"),
    ("build.gradle", "build.gradle"),
    ("build.gradle.kts", "build.gradle.kts"),
    ("settings.gradle", "settings.gradle"),
    ("settings.gradle.kts", "settings.gradle.kts"),
    ("Cargo.toml", "Cargo.toml"),
    ("go.mod", "go.mod"),
)

_MONOREPO_SUBPROJECT_BUDGET = 100  # cap sub-projects examined per call


def _detect_monorepo_subprojects(root: Path) -> list[Path]:
    """Return paths of likely sub-project roots when `root` looks like a monorepo.

    Returns empty list when no monorepo workspace marker is found at root —
    callers fall through to single-project behavior. When a marker IS found,
    walks `_MONOREPO_SUBPROJECT_PARENTS` one level deep collecting sub-project
    candidate dirs, skipping `_JVM_SOURCE_WALK_IGNORE_DIRS` and bounded by
    `_MONOREPO_SUBPROJECT_BUDGET`.

    Recognized markers:
    - Direct: nx.json, lerna.json, pnpm-workspace.yaml, rush.json, Bazel
      WORKSPACE files, Pants pants.toml, Buck .buckconfig
    - package.json with a top-level "workspaces" field (npm/yarn workspaces)
    - Cargo.toml with a top-level [workspace] section (Cargo workspaces)
    - pom.xml with packaging=pom (Maven multi-module parent)
    """
    has_monorepo_marker = False

    for marker in _MONOREPO_MARKER_FILES:
        if (root / marker).exists():
            has_monorepo_marker = True
            break

    if not has_monorepo_marker:
        # Inspect package.json for `"workspaces"` field
        pkg_json = root / "package.json"
        if pkg_json.is_file():
            try:
                data = __import__("json").loads(pkg_json.read_text(encoding="utf-8"))
                if isinstance(data, dict) and "workspaces" in data:
                    has_monorepo_marker = True
            except (OSError, ValueError):
                pass

    if not has_monorepo_marker:
        # Inspect Cargo.toml for `[workspace]` section
        cargo_toml = root / "Cargo.toml"
        if cargo_toml.is_file():
            try:
                if "[workspace]" in cargo_toml.read_text(encoding="utf-8"):
                    has_monorepo_marker = True
            except OSError:
                pass

    if not has_monorepo_marker:
        # Inspect pom.xml for multi-module marker — `<packaging>pom</packaging>`
        # plus a `<modules>` section is the canonical Maven multi-module shape.
        pom_xml = root / "pom.xml"
        if pom_xml.is_file():
            try:
                txt = pom_xml.read_text(encoding="utf-8")
                if "<packaging>pom</packaging>" in txt and "<modules>" in txt:
                    has_monorepo_marker = True
            except OSError:
                pass

    if not has_monorepo_marker:
        return []

    found: list[Path] = []
    for parent_name in _MONOREPO_SUBPROJECT_PARENTS:
        parent = root / parent_name
        if not parent.is_dir():
            continue
        try:
            for entry in sorted(parent.iterdir()):
                if not entry.is_dir():
                    continue
                if entry.name in _JVM_SOURCE_WALK_IGNORE_DIRS:
                    continue
                if entry.name.startswith("."):
                    continue
                found.append(entry)
                if len(found) >= _MONOREPO_SUBPROJECT_BUDGET:
                    return found
        except OSError:
            continue
    return found


def _collect_subproject_type_evidence(subprojects: list[Path]) -> list[str]:
    """For each sub-project, return the first type-config file found, prefixed
    with the sub-project's parent/name. Used by the harnessability type-coverage
    check to aggregate signals across a monorepo."""
    evidence: list[str] = []
    for sub in subprojects:
        # Check each type-config file in priority order — first match wins.
        for filename, label in _SUBPROJECT_TYPE_CONFIG_FILES:
            if (sub / filename).exists():
                # `services/auth-service/pom.xml` rather than just `pom.xml`
                rel_label = f"{sub.parent.name}/{sub.name}/{label}"
                evidence.append(rel_label)
                break
        else:
            # No standard build/type file at sub-project root — check for
            # JVM source-pattern fallback within this sub-project.
            jvm_sub = _detect_jvm_source_evidence(sub)
            if jvm_sub:
                rel_label = f"{sub.parent.name}/{sub.name}/{jvm_sub[0]}"
                evidence.append(rel_label)
    return evidence


def _audit_harnessability(root: Path) -> dict[str, Any]:
    """Assess codebase harnessability across three proxy dimensions."""
    # --- Type coverage ---
    type_score = "unknown"
    type_evidence = ""
    typed_configs = []
    for cfg_file in ["tsconfig.json", "mypy.ini", "pyrightconfig.json", ".pyrightconfig.json"]:
        if (root / cfg_file).exists():
            typed_configs.append(cfg_file)
    pyproject = root / "pyproject.toml"
    if pyproject.exists():
        try:
            text = pyproject.read_text(encoding="utf-8")
            if "strict" in text or "disallow_untyped" in text or "mypy" in text:
                typed_configs.append("pyproject.toml (typed)")
        except OSError:
            pass
    # Wave 1p35d (1p35p): JVM build/source detection. Spring Boot and other
    # JVM-ecosystem projects previously read as "no type config detected"
    # because the checker only looked for TS/Python config. Lightweight
    # file-presence check — no compiler invocation, no JVM runtime dependency.
    #
    # Late hardening (1p35p enterprise-deployment review): the previous
    # `root.rglob(*.java)` walked the entire repo, slow on enterprise
    # monorepos and false-positive on any vendored 3rd-party Java sources
    # anywhere in the tree. Scoped to canonical project roots and source
    # patterns are *.{java,kt,scala,groovy}.
    jvm_signals = []
    for build_file in ("pom.xml", "build.gradle", "build.gradle.kts",
                       "settings.gradle", "settings.gradle.kts"):
        if (root / build_file).exists():
            jvm_signals.append(build_file)
    if not jvm_signals:
        jvm_signals.extend(_detect_jvm_source_evidence(root))
    if jvm_signals:
        typed_configs.append(f"JVM ({', '.join(jvm_signals)})")
    # Wave 1p35d (1p35p enterprise-deployment hardening, monorepo support):
    # when the agent's CWD is a monorepo workspace parent (Nx/Lerna/pnpm/
    # Bazel/Pants/Cargo-workspaces/Maven-multi-module etc.), the root-only
    # checks above miss type-config that lives inside sub-project dirs.
    # Aggregate sub-project signals so the harnessability score reflects the
    # actual typed surface, not just what happens to live at the workspace
    # root.
    subprojects = _detect_monorepo_subprojects(root)
    if subprojects:
        subproject_evidence = _collect_subproject_type_evidence(subprojects)
        if subproject_evidence:
            # Report at most 5 sub-projects inline; trailing "+N more" when
            # the monorepo has many typed sub-projects.
            shown = subproject_evidence[:5]
            extra = len(subproject_evidence) - len(shown)
            label = f"monorepo ({len(subprojects)} sub-projects scanned, "
            label += f"{len(subproject_evidence)} typed): {', '.join(shown)}"
            if extra > 0:
                label += f", +{extra} more"
            typed_configs.append(label)
    if typed_configs:
        type_score = "high" if len(typed_configs) >= 2 else "medium"
        type_evidence = f"Type config found: {', '.join(typed_configs)}"
    else:
        type_score = "low"
        type_evidence = "No type configuration files detected"

    # --- Module boundary clarity ---
    boundary_score = "unknown"
    boundary_evidence = ""
    arch_dir = root / "docs" / "architecture"
    boundary_docs = []
    for name in ["domain-map.md", "layering-rules.md", "current-state.md"]:
        if (arch_dir / name).exists():
            boundary_docs.append(name)
    if len(boundary_docs) >= 2:
        boundary_score = "high"
    elif boundary_docs:
        boundary_score = "medium"
    else:
        boundary_score = "low"
    boundary_evidence = f"Architecture docs found: {', '.join(boundary_docs)}" if boundary_docs else "No architecture boundary docs found"

    # --- Debt density proxy ---
    debt_score = "unknown"
    debt_evidence = ""
    try:
        # Route through the shared helper (MCP-reachable git probe): no inherited JSON-RPC stdin,
        # no Windows console window (wave 1p88t subprocess isolation).
        result = _mcp_subprocess_run(
            ["git", "grep", "-c", "-E", "TODO|FIXME|HACK|XXX"],
            cwd=str(root), timeout=10,
        )
        todo_count = sum(int(l.split(":")[-1]) for l in result.stdout.splitlines() if ":" in l and l.split(":")[-1].isdigit())
        if todo_count == 0:
            debt_score = "high"
        elif todo_count < 20:
            debt_score = "medium"
        else:
            debt_score = "low"
        debt_evidence = f"{todo_count} TODO/FIXME/HACK markers found"
    except Exception:
        debt_score = "unknown"
        debt_evidence = "Could not scan for debt markers"

    scores = {"high": 3, "medium": 2, "low": 1, "unknown": 0}
    dims = [type_score, boundary_score, debt_score]
    known = [s for s in dims if s != "unknown"]
    if known:
        avg = sum(scores[s] for s in known) / len(known)
        overall = "high" if avg >= 2.5 else "medium" if avg >= 1.5 else "low"
    else:
        overall = "unknown"

    return {
        "overall": overall,
        "dimensions": {
            "type_coverage": {"score": type_score, "evidence": type_evidence},
            "boundary_clarity": {"score": boundary_score, "evidence": boundary_evidence},
            "debt_density": {"score": debt_score, "evidence": debt_evidence},
        },
    }


def _audit_harness_coverage(root: Path) -> dict[str, Any]:
    """Report which harness dimensions have at least one sensor configured."""
    cfg = _read_workflow_config(root)
    sensors = _read_project_sensors(root)
    required_lanes = _read_project_required_review_lanes(root)
    lanes_lower = [l.lower() for l in required_lanes]

    maintainability_covered = len(sensors) > 0
    architecture_covered = any("architecture" in l for l in lanes_lower)
    behaviour_covered = (
        any(l in ("security", "security-review", "performance", "performance-review") for l in lanes_lower)
        or bool(cfg.get("test_runner"))
    )

    dimensions = {
        "maintainability": {"covered": maintainability_covered, "signal": "computational sensors" if maintainability_covered else None},
        "architecture": {"covered": architecture_covered, "signal": "architecture-review lane" if architecture_covered else None},
        "behaviour": {"covered": behaviour_covered, "signal": "security/performance lanes or test_runner" if behaviour_covered else None},
    }
    covered_count = sum(1 for d in dimensions.values() if d["covered"])
    return {
        "coverage_ratio": f"{covered_count}/3",
        "covered_count": covered_count,
        "dimensions": dimensions,
    }


def _audit_harness_coherence(root: Path) -> dict[str, Any]:
    """Scan seed surface for stale tool references and known contradiction patterns.

    Wave 1p2q3 (1p314 post-ship): tightened detection logic after a 52-finding
    audit on the wavefoundry self-host turned out to be 28+ false positives.
    Fixes:

    1. Scan ``server.py`` in addition to ``server_impl.py`` — ``wf_reload_mcp``
       is defined in the thin runner because it must survive hot-reload.
    2. Treat top-level keys of ``docs/workflow-config.json`` as legitimate
       identifiers — ``code_navigation_hints`` etc. are config blocks, not tools.
    3. Skip parameter-position matches: ``wf_pause_wave(wave_id=...)``, URI
       template variables like ``{wave_id}``, briefing-packet field lists.
    4. Skip wildcard family references: ``wf_new_*`` is the canonical
       reference form for the kind-specific ``wf_new_X`` tool family.
    5. Bypass-pattern detection removed entirely — keyword co-occurrence
       (skip/bypass/omit + gate/lane) is too broad. Every match in the
       wavefoundry self-host was legitimate prose (red-team role descriptions,
       explicit safeguards against bypass, anti-pattern callouts). The signal-
       to-noise ratio doesn't justify keeping it; a future NLP-aware version
       could re-enable.
    """
    seed_dirs = [
        root / ".wavefoundry" / "framework" / "seeds",
        root / "docs" / "prompts",
    ]
    # Collect live MCP tool names from BOTH server modules. server.py defines
    # tools that must survive hot-reload (notably wf_reload_mcp itself);
    # server_impl.py defines the rest of the surface.
    live_tools: set[str] = set()
    try:
        import re as _re
        for src_file in ("server.py", "server_impl.py"):
            src_path = Path(__file__).parent / src_file
            if not src_path.is_file():
                continue
            src = src_path.read_text(encoding="utf-8")
            live_tools.update(
                _re.findall(r'def (wf_\w+|memory_\w+|index_\w+|docs_search|code_\w+|seed_get)\(', src)
            )
    except Exception:
        pass

    # Treat top-level workflow-config keys as legitimate identifiers — they're
    # project-tunable schema blocks (e.g. code_navigation_hints,
    # design_review_triggers), not tool names. Without this allowlist the
    # audit flags them as "stale tool reference" when they're actually live
    # config.
    workflow_config_keys: set[str] = set()
    try:
        import json as _json_wf
        wf_path = root / "docs" / "workflow-config.json"
        if wf_path.is_file():
            wf_data = _json_wf.loads(wf_path.read_text(encoding="utf-8"))
            if isinstance(wf_data, dict):
                workflow_config_keys = {k for k in wf_data if isinstance(k, str)}
    except Exception:
        pass

    # Known non-tool identifiers that match the tool-name regex shape but
    # legitimately appear as parameter/field/URI/module names. Without this
    # allowlist they get over-matched.
    NON_TOOL_IDENTIFIERS = {
        "wave_id",        # parameter name in wf_pause_wave/wf_reopen_wave, URI {wave_id}, briefing field
        "wave_lint_lib",  # Python module under framework/scripts/wave_lint_lib/
    }

    findings = []
    scanned_files = 0

    for seed_dir in seed_dirs:
        if not seed_dir.is_dir():
            continue
        for f in sorted(seed_dir.glob("*.md")):
            try:
                text = f.read_text(encoding="utf-8")
            except OSError:
                continue
            scanned_files += 1
            rel = str(f.relative_to(root)).replace("\\", "/")  # wave 1p9hm: forward-slash in wf_audit output

            # Check for stale tool references (tool names mentioned but not in live set)
            import re as _re2
            # Tool name must end in an alphanumeric character (not underscore)
            # so we don't greedy-consume the trailing underscore in
            # `wf_new_*` constructs. The optional `(_\*)?` group then has a
            # chance to match the wildcard family-reference suffix. `wave_`
            # stays in the scan so leftover pre-rename tool mentions are
            # flagged as stale; `memory_`/`index_` scan by exact tool name
            # because those prefixes collide with common identifiers
            # (memory_id, index_freshness).
            for match in _re2.finditer(
                r'\b(wf_[a-zA-Z_]*[a-zA-Z0-9]|wave_[a-zA-Z_]*[a-zA-Z0-9]'
                r'|memory_add|memory_propose|memory_backfill|memory_validate'
                r'|memory_search|memory_brief|memory_reconcile'
                r'|index_health|index_build_status|index_build|index_optimize'
                r'|docs_search|code_[a-zA-Z_]*[a-zA-Z0-9]|seed_get)(_\*)?',
                text,
            ):
                tool = match.group(1)
                wildcard_suffix = match.group(2)
                if wildcard_suffix:
                    # `wf_new_*` family reference — skip, even if `wave_new` itself isn't live.
                    continue
                clean = tool.rstrip("_")
                if clean in live_tools or clean + "_response" in live_tools:
                    continue
                if clean in workflow_config_keys:
                    continue
                if clean in NON_TOOL_IDENTIFIERS:
                    continue
                # Skip kind-specific dispatcher prefixes that always have a kind suffix
                # (e.g. `wf_new_X`, `wf_list_X`, `wf_get_X`, `wf_set_X`).
                if any(clean.startswith(p) for p in ("wf_new_", "wf_list_", "wf_get_", "wf_set_")):
                    continue
                findings.append({
                    "file": rel,
                    "type": "stale_tool_reference",
                    "detail": f"Tool '{clean}' mentioned but not found in live MCP surface",
                })

            # Bypass-pattern detection deliberately omitted — see docstring.

    return {
        "scanned_files": scanned_files,
        "findings": findings[:50],  # cap at 50 to avoid overwhelming response
        "findings_count": len(findings),
    }


def _select_prepare_council_rotating_seat(wave_text: str) -> tuple[str | None, str]:
    """Select the rotating Wave Council seat for the prepare-phase review.

    Heuristic (first match wins; documented explicitly per 12sp5 AC-2):
    1. docs-contract-reviewer  — wave objective/watchpoints reference seeds, prompts, docs, or templates
    2. security-reviewer       — wave objective/watchpoints reference auth, security, trust, vulnerability,
                                  permission, credential, or secret
    3. architecture-reviewer   — wave objective/watchpoints reference architecture, boundary, structural,
                                  refactor, or layering
    4. code-reviewer           — wave objective/watchpoints reference server_impl, MCP, api, endpoint,
                                  or tool surface
    5. (no rotating seat)      — no clear domain signal; red-team only
    """
    probe = wave_text.casefold()
    if any(kw in probe for kw in ("seed", "prompt", "template", "doc authoring", "seed prompt")):
        return "docs-contract-reviewer", "Wave references seed/prompt authoring or documentation changes"
    if any(kw in probe for kw in ("auth", "security", "trust boundary", "vulnerability", "credential", "permission", "secret")):
        return "security-reviewer", "Wave references authentication, security, or trust boundary changes"
    if any(kw in probe for kw in ("architecture", "boundary", "structural", "refactor", "layering")):
        return "architecture-reviewer", "Wave references architectural or structural changes"
    if any(kw in probe for kw in ("server_impl", "mcp tool", "mcp surface", "api endpoint", "tool registration")):
        return "code-reviewer", "Wave references MCP tool or API surface changes"
    return None, "No clear domain signal; red-team fixed seat only"


_PREPARE_COUNCIL_VERDICT_RE = re.compile(
    r"^\s*-\s*\*\*Prepare-phase Wave Council \[prepare-council\] — (?P<date>[^:]+): (?P<verdict>PASS(?: WITH NOTES)?|BLOCKED)\*\*(?:\s*\((?P<meta>.*)\))?\s*$",
    re.IGNORECASE,
)
_PREPARE_COUNCIL_REQUIRED_META_FIELDS = (
    "moderator",
    "primer-depth",
    "seats",
    "rotating-seat",
    "strongest-challenge",
    "strongest-alternative",
)


def _prepare_council_verdict_info(wave_text: str) -> dict[str, Any]:
    """Parse the prepare-phase Wave Council verdict from ## Review Checkpoints."""
    _heading_pat = re.compile(r"^(#{1,6} .+)$", re.MULTILINE)
    headings = list(_heading_pat.finditer(wave_text))
    for i, m in enumerate(headings):
        if m.group(1).strip() == "## Review Checkpoints":
            end = headings[i + 1].start() if i + 1 < len(headings) else len(wave_text)
            checkpoints = wave_text[m.end():end]
            for raw in checkpoints.splitlines():
                line = raw.strip()
                if "prepare-council" not in line.casefold():
                    continue
                match = _PREPARE_COUNCIL_VERDICT_RE.match(line)
                if not match:
                    return {
                        "present": True,
                        "valid": False,
                        "line": line,
                        "verdict": "",
                        "date": "",
                        "meta": {},
                        "missing_fields": list(_PREPARE_COUNCIL_REQUIRED_META_FIELDS),
                    }
                meta_text = match.group("meta") or ""
                meta: dict[str, str] = {}
                for raw_part in re.split(r";\s*", meta_text):
                    if not raw_part.strip():
                        continue
                    key, sep, value = raw_part.partition(":")
                    if not sep:
                        continue
                    meta[key.strip().casefold()] = value.strip()
                missing_fields = [field for field in _PREPARE_COUNCIL_REQUIRED_META_FIELDS if not meta.get(field)]
                verdict = match.group("verdict").strip().upper()
                valid = not missing_fields and verdict in {"PASS", "PASS WITH NOTES"}
                return {
                    "present": True,
                    "valid": valid,
                    "line": line,
                    "verdict": verdict,
                    "date": match.group("date").strip(),
                    "meta": meta,
                    "missing_fields": missing_fields,
                }
    return {
        "present": False,
        "valid": False,
        "line": "",
        "verdict": "",
        "date": "",
        "meta": {},
        "missing_fields": list(_PREPARE_COUNCIL_REQUIRED_META_FIELDS),
    }


def _prepare_council_verdict_present(wave_text: str) -> bool:
    """True if a valid prepare-council verdict line is recorded."""
    return bool(_prepare_council_verdict_info(wave_text).get("valid"))


def _prepare_council_verdict_template(rotating_seat: str | None) -> str:
    rotating_part = rotating_seat or "none"
    seat_list = ["red-team", "architecture-reviewer", "security-reviewer", "qa-reviewer", "reality-checker"]
    # De-dup: the rotating pick can itself be a fixed seat (security-reviewer and
    # architecture-reviewer are both in the fixed list). The roster lists distinct seats;
    # a seat serving as both fixed and rotating is identified by the separate
    # `rotating-seat:` field, so dropping the duplicate token loses no information.
    if rotating_seat and rotating_seat not in seat_list:
        seat_list.append(rotating_seat)
    seats = ", ".join(seat_list)
    return (
        "- **Prepare-phase Wave Council [prepare-council] — <date>: PASS** "
        "(moderator: wave-council; primer-depth: standard; "
        f"seats: <replace with the seats actually run, each at most once, e.g. {seats}>; "
        f"rotating-seat: {rotating_part}; "
        "strongest-challenge: <summary>; strongest-alternative: <summary>)"
    )


def _build_prepare_council_brief(wave_id: str, wave_text: str, change_ids: list[str]) -> dict[str, Any]:
    """Build the council review brief returned by wf_prepare_wave when no verdict is recorded."""
    rotating_seat, rotating_seat_reason = _select_prepare_council_rotating_seat(wave_text)
    seats = ["red-team (fixed)"]
    if rotating_seat:
        seats.append(f"{rotating_seat} (rotating)")
    return {
        "wave_id": wave_id,
        "change_count": len(change_ids),
        "fixed_seat": "red-team",
        "rotating_seat": rotating_seat,
        "rotating_seat_reason": rotating_seat_reason,
        "council_seats": seats,
        "instructions": (
            "Run each council seat in isolation against the admitted change docs and wave record. "
            "Verification must be code-grounded: verify each plan's load-bearing claims against the "
            "actual tree, not against the plan's own prose — cited file:line sites and symbols must "
            "resolve, 'X already does Y' claims must hold in the code, and 'no other caller/site' "
            "censuses must be complete. Do not approve a plan whose claims were checked only against "
            "its own text. Have wave-council synthesize findings. "
            "Record the verdict in ## Review Checkpoints with a structured 'prepare-council' line "
            "whose seats: field lists the seats actually run, each at most once, with per-seat "
            "evidence (or an explicit no-findings note) recorded in the wave record "
            f"(e.g. `{_prepare_council_verdict_template(rotating_seat)}`) "
            "before calling wf_prepare_wave(mode='create')."
        ),
        "verdict_format": _prepare_council_verdict_template(rotating_seat),
    }


def _wave_uses_external_review_evidence(root: Path, wave_md: Path) -> bool:
    """True for the new contract; unmarked pre-protocol waves remain prose-only legacy."""

    try:
        text = wave_md.read_text(encoding="utf-8")
    except OSError:
        return False
    source, source_errors = parse_review_evidence_source(text)
    state, adoption_error = adopted_protocol_state(root, wave_md.parent.name)
    legacy_inline_marker = re.search(r"(?mi)^review-evidence-protocol\s*:", text) is not None
    return (
        source is not None
        or bool(source_errors)
        or state is not None
        or adoption_error is not None
        or legacy_inline_marker
    )


def _review_evidence_diagnostics(
    text: str,
    *,
    root: Path | None = None,
    wave_key: str | None = None,
    persist_adoption: bool = False,
    closure: bool = False,
    required_run_kind: str | None = None,
) -> list[dict[str, Any]]:
    """Translate the external-ledger validator's errors into lifecycle diagnostics."""

    if root is None or wave_key is None:
        errors = ["external review evidence validation requires repository root and wave key"]
        result = None
    else:
        wave_md = _find_wave_md(root, wave_key)
        if wave_md is None:
            errors = [f"no wave record found for `{wave_key}`"]
            result = None
        elif not _wave_uses_external_review_evidence(root, wave_md):
            errors = []
            result = None
        else:
            result = validate_external_review_evidence(wave_md, closure=closure)
            errors = list(result.errors)
            errors.extend(validate_adopted_protocol_state(root, wave_md.parent.name, wave_md))
            if not result.errors:
                try:
                    raw_projection = wave_md.read_text(encoding="utf-8")
                    if render_review_evidence_projection(raw_projection, result.records) != raw_projection:
                        errors.append(
                            "Finding Synthesis projection is stale relative to canonical events.jsonl; "
                            "replay the last typed review event to reconcile it"
                        )
                    marker_present = (
                        REVIEW_STATUS_MARKER_BEGIN in raw_projection
                        or REVIEW_STATUS_MARKER_END in raw_projection
                    )
                    if marker_present and render_review_status_projection(
                        raw_projection,
                        result.records,
                        _review_status_signoff_keys(
                            root, raw_projection, result.records
                        ),
                    ) != raw_projection:
                        errors.append(
                            "Review Status projection is stale relative to canonical "
                            "events.jsonl; replay the last typed review event to reconcile it"
                        )
                except (OSError, ValueError) as exc:
                    errors.append(f"Finding Synthesis projection could not be checked: {exc}")
    if result is not None and required_run_kind is not None:
        has_required_run = any(
            record.get("record_type") == "review_run"
            and record.get("run_kind") == required_run_kind
            for record in result.records
        )
        if not has_required_run:
            errors.append(
                f"marked wave requires a `{required_run_kind}` Review Run Record at this lifecycle phase"
            )
    if (
        not errors
        and persist_adoption
        and result is not None
        and root is not None
        and wave_key is not None
    ):
        adoption_error = record_protocol_state(root, wave_key, wave_md)
        if adoption_error:
            errors.append(adoption_error)
    return [
        _diagnostic(
            "review_evidence_invalid",
            error,
            recovery_tools=["wf_current_wave", "wf_validate_docs"],
            recovery_usage="wf_current_wave()",
        )
        for error in errors
    ]


def _approval_evidence_diagnostics(
    text: str,
    required_signoff_keys: Iterable[str],
    *,
    root: Path | None = None,
    wave_key: str | None = None,
    records: Iterable[dict[str, Any]] | None = None,
) -> list[dict[str, Any]]:
    """Bind prose lane/council signoffs to executed evidence on marked waves."""

    if records is None:
        if root is None or wave_key is None:
            return []
        wave_md = _find_wave_md(root, wave_key)
        if wave_md is None or not _wave_uses_external_review_evidence(root, wave_md):
            return []
        result = validate_external_review_evidence(wave_md)
        if result.errors:
            return []
        rows = result.records
    else:
        rows = tuple(records)
    status = review_status_rows(rows, required_signoff_keys)
    blocked = [row for row in status if row["state"] != "approved"]
    if not blocked:
        return []
    details = "; ".join(
        f"{row['signoff_key']}={row['state']} ({row['why']})" for row in blocked
    )
    return [
        _diagnostic(
            "missing_executable_approval_evidence",
            "Marked wave approval signoffs require executed delivery Evidence Records with "
            "claim_kind `approval`, claim_id `approval:<signoff-key>`, and a matching actor "
            "(`operator` for operator-signoff, `wave-council` for council signoffs, or the exact "
            "specialist lane); specialist/council evidence must be fresh and independent, and its "
            f"chronology must follow every affected repair; {details}.",
            recovery_tools=["wf_review_wave", "wf_current_wave"],
            recovery_usage="wf_review_wave()",
        )
    ]


def _review_status_signoff_keys(
    root: Path,
    wave_text: str,
    records: Iterable[Mapping[str, Any]] = (),
) -> tuple[str, ...]:
    """Return the canonical keys represented by the bounded status projection."""

    return required_review_status_keys(root, wave_text, records)


def _project_current_review_status(root: Path, wave_md: Path, text: str) -> str:
    """Rebuild both human projections from the canonical ledger."""

    if not _wave_uses_external_review_evidence(root, wave_md):
        return text
    validation = validate_external_review_evidence(wave_md)
    if validation.errors:
        raise ValueError("; ".join(validation.errors))
    projected = render_review_evidence_projection(text, validation.records)
    return render_review_status_projection(
        projected,
        validation.records,
        _review_status_signoff_keys(root, projected, validation.records),
    )


def _append_review_evidence_state_line(text: str, key: str, state: str, note: str) -> str:
    """Append one exact-key state line so the existing latest-state parser remains authoritative."""

    marker = "## Review Evidence"
    start = text.find(marker)
    if start < 0:
        suffix = "" if text.endswith("\n") else "\n"
        return text + suffix + f"\n{marker}\n\n- {key}: {state} — {note}\n"
    section_start = text.find("\n", start + len(marker))
    if section_start < 0:
        section_start = len(text)
    else:
        section_start += 1
    next_heading = re.search(r"(?m)^## ", text[section_start:])
    insert_at = section_start + next_heading.start() if next_heading else len(text)
    prefix = text[:insert_at].rstrip() + "\n"
    suffix = text[insert_at:]
    return prefix + f"- {key}: {state} — {note}\n\n" + suffix.lstrip("\n")


def _identified_review_event_bundle(
    records: Iterable[dict[str, Any]], identity: dict[str, Any]
) -> tuple[dict[str, Any], ...] | None:
    """Return the committed bundle whose leading row owns ``identity``."""

    rows = tuple(records)
    for start, row in enumerate(rows):
        if row.get(EVENT_IDENTITY_FIELD) != identity:
            continue
        end = start + 1
        while end < len(rows) and EVENT_IDENTITY_FIELD not in rows[end]:
            end += 1
        return tuple(rows[start:end])
    return None


def wf_review_evidence_response(
    root: Path,
    wave_id: str,
    event: str,
    actor: str,
    context_id: str,
    *,
    mode: str = "dry_run",
    signoff_key: str | None = None,
    finding_id: str | None = None,
    run_kind: str | None = None,
    cycle: int = 0,
    judgment: dict[str, Any] | None = None,
    evidence: dict[str, Any] | None = None,
    source_lanes: list[str] | None = None,
    blocking_required_lanes: list[str] | None = None,
    approval_recheck_lanes: list[str] | None = None,
    review_boundaries_changed: list[str] | None = None,
    fresh_context: bool = False,
    independent: bool = False,
    integrity_confirmed: bool = False,
) -> dict[str, Any]:
    """Preview or append a compact semantic review event to a marked wave."""

    mode_s = (mode or "dry_run").strip().lower()
    if mode_s not in {"dry_run", "create"}:
        return _response(
            "error",
            {"wave_id": wave_id, "mode": mode_s},
            diagnostics=[_diagnostic("invalid_arguments", "mode must be dry_run or create")],
            next_tools=["wf_help"],
            usage="wf_help()",
        )
    try:
        wave_md = _find_wave_md(root, wave_id)
    except ValueError as exc:
        return _response(
            "error",
            {"wave_id": wave_id, "mode": mode_s, "event": event},
            diagnostics=[_diagnostic("review_evidence_path_escape", str(exc))],
        )
    if wave_md is None:
        return _response(
            "error",
            {"wave_id": wave_id},
            diagnostics=[_diagnostic("wave_not_found", f"No wave found matching '{wave_id}'.")],
            next_tools=["wf_list_waves"],
            usage="wf_list_waves()",
        )
    try:
        wave_md, _events_path = _contained_wave_review_paths(root, wave_md)
    except ValueError as exc:
        return _response(
            "error",
            {"wave_id": wave_id, "mode": mode_s, "event": event},
            diagnostics=[_diagnostic("review_evidence_path_escape", str(exc))],
        )
    semantic_event: dict[str, Any] = {
        "event": event,
        "actor": actor,
        "context_id": context_id,
        "signoff_key": signoff_key,
        "finding_id": finding_id,
        "run_kind": run_kind,
        "cycle": cycle,
        "judgment": judgment,
        "source_lanes": source_lanes or [],
        "blocking_required_lanes": blocking_required_lanes or [],
        "approval_recheck_lanes": approval_recheck_lanes or [],
        "review_boundaries_changed": review_boundaries_changed or [],
        "fresh_context": fresh_context,
        "independent": independent,
        "integrity_confirmed": integrity_confirmed,
    }
    evidence_payload = dict(evidence or {})
    protected_collisions = sorted(
        (set(semantic_event) | {EVENT_IDENTITY_FIELD, REQUEST_DIGEST_FIELD})
        .intersection(evidence_payload)
    )
    if protected_collisions:
        return _response(
            "error",
            {"wave_id": wave_id, "mode": mode_s, "event": event},
            diagnostics=[
                _diagnostic(
                    "invalid_review_event",
                    "evidence may not override protected semantic field(s): "
                    + ", ".join(protected_collisions),
                )
            ],
            next_tools=["wf_help"],
            usage="wf_help(goal='record_review_evidence')",
        )
    semantic_event.update(evidence_payload)
    try:
        identity = derive_review_event_identity(wave_md.parent.name, semantic_event)
        request_digest = review_event_request_digest(semantic_event)
    except (TypeError, ValueError) as exc:
        return _response(
            "error",
            {"wave_id": wave_id, "mode": mode_s, "event": event},
            diagnostics=[_diagnostic("invalid_review_event", str(exc))],
        )

    def transact() -> dict[str, Any]:
        original = wave_md.read_text(encoding="utf-8")
        current = validate_external_review_evidence(wave_md)
        if current.errors:
            return _response(
                "error",
                {"wave_id": wave_id, "mode": mode_s},
                diagnostics=[_diagnostic("review_evidence_invalid", error) for error in current.errors],
                next_tools=["wf_review_wave", "wf_current_wave"],
            )
        existing_bundle = _identified_review_event_bundle(current.records, identity)
        durable_errors = validate_adopted_protocol_state(root, wave_md.parent.name, wave_md)
        recoverable_suffix = durable_errors == ("canonical review event ledger has an unadopted suffix",)
        if durable_errors and not (recoverable_suffix and existing_bundle is not None):
            return _response(
                "error",
                {"wave_id": wave_id, "mode": mode_s},
                diagnostics=[_diagnostic("review_evidence_adoption_invalid", error) for error in durable_errors],
                next_tools=["wf_review_wave"],
            )
        replayed = existing_bundle is not None
        if existing_bundle is not None:
            if existing_bundle[0].get(REQUEST_DIGEST_FIELD) != request_digest:
                return _response(
                    "error",
                    {"wave_id": wave_id, "mode": mode_s, "event": event},
                    diagnostics=[_diagnostic(
                        "review_event_identity_conflict",
                        "the derived event identity already exists with different semantic content",
                    )],
                )
            appended = existing_bundle
            proposed_records = tuple(current.records)
        else:
            appended, build_errors = build_identified_review_event(
                current.records, wave_md.parent.name, semantic_event
            )
            if build_errors:
                return _response(
                    "error",
                    {"wave_id": wave_id, "mode": mode_s, "event": event},
                    diagnostics=[_diagnostic("invalid_review_event", error) for error in build_errors],
                    next_tools=["wf_help"],
                )
            proposed_records = (*current.records, *appended)
            record_errors = validate_review_evidence_records(proposed_records)
            if record_errors:
                return _response(
                    "error",
                    {"wave_id": wave_id, "mode": mode_s, "event": event},
                    diagnostics=[_diagnostic("review_evidence_invalid", error) for error in record_errors],
                )
        projected = render_review_evidence_projection(original, proposed_records)
        projected = render_review_status_projection(
            projected,
            proposed_records,
            _review_status_signoff_keys(root, projected, proposed_records),
        )
        payload = {
            "wave_id": wave_md.parent.name,
            "path": str(wave_md.relative_to(root.resolve())).replace("\\", "/"),
            "events_path": str(review_event_path(wave_md).relative_to(root.resolve())).replace("\\", "/"),
            "mode": mode_s,
            "event": event,
            "appended_records": list(appended),
            "summary": review_evidence_summary(proposed_records),
            "replayed": replayed,
        }
        if mode_s == "dry_run":
            return _response("dry_run", payload, next_tools=["wf_review_evidence"])
        event_committed = replayed
        if not replayed:
            try:
                _atomic_replace_bytes(
                    review_event_path(wave_md),
                    canonical_review_events_bytes(proposed_records),
                    "review-events",
                )
                event_committed = True
            except OSError as exc:
                return _response(
                    "error", payload,
                    diagnostics=[_diagnostic("review_event_commit_failed", str(exc))],
                )
        adoption_error = record_protocol_state_locked(root, wave_md.parent.name, wave_md)
        if adoption_error:
            payload.update(event_committed=event_committed, adoption_pending=True)
            return _response(
                "partial", payload,
                diagnostics=[_diagnostic("review_evidence_adoption_pending", adoption_error)],
                next_tools=["wf_review_evidence"],
            )
        try:
            _atomic_replace_text(wave_md, projected, "review-projection")
        except OSError as exc:
            payload.update(event_committed=True, projection_stale=True)
            return _response(
                "partial", payload,
                diagnostics=[_diagnostic("review_evidence_projection_stale", str(exc))],
                next_tools=["wf_review_evidence", "wf_review_wave"],
            )
        payload.update(event_committed=True, adoption_pending=False, projection_stale=False)
        return _response("ok", payload, next_tools=["wf_review_wave", "wf_current_wave"])

    try:
        if mode_s == "create":
            with review_event_write_lock(root):
                response = transact()
        else:
            response = transact()
    except OSError as exc:
        return _response(
            "error",
            {"wave_id": wave_id, "mode": mode_s, "event": event},
            diagnostics=[_diagnostic("review_evidence_persist_failed", str(exc))],
        )
    if mode_s == "create" and response.get("status") == "ok":
        _trigger_background_index_refresh_for_paths(root, [wave_md])
    return response


def wf_prepare_wave_response(root: Path, wave_id: str, mode: str = "dry_run", cache: Optional[McpRepoCache] = None) -> dict[str, Any]:
    mode_s = "create" if (mode or "").strip().lower() == "apply" else (mode or "").strip().lower()
    if mode_s not in {"dry_run", "ready", "create"}:
        return _response("error", {"wave_id": wave_id, "mode": mode}, diagnostics=[_diagnostic("invalid_arguments", f"Unsupported mode '{mode}'. Valid modes: dry_run, ready, create.")], next_tools=["wf_help"], usage="wf_help()")
    # Wave 1p45l: decouple readiness from activation.
    #   dry_run  — read-only validation, no guard, no writes.
    #   ready    — full readiness (relocate + garden + lint + council verdict) recorded WITHOUT
    #              activating: no single-OPEN guard, status stays `planned` ("readied"). Lets any
    #              number of waves be readied while one is OPEN.
    #   create   — readiness PLUS the single-OPEN guard PLUS the `planned`->`active` flip (prepare-and-open).
    _activating = mode_s == "create"
    _mutating = mode_s in ("create", "ready")
    wave_md = _find_wave_md(root, wave_id)
    if wave_md is None:
        return _response("error", {"wave_id": wave_id, "mode": mode_s}, diagnostics=[_diagnostic("wave_not_found", f"No wave found matching '{wave_id}'.", recovery_tools=["wf_list_waves"], recovery_usage="wf_list_waves()")], next_tools=["wf_list_waves"], usage="wf_list_waves()")
    text = wave_md.read_text(encoding="utf-8")
    change_ids = _extract_change_ids_from_wave_text(text)
    diagnostics: list[dict[str, Any]] = []
    diagnostics.extend(
        _review_evidence_diagnostics(
            text,
            root=root,
            wave_key=wave_md.parent.name,
            persist_adoption=_mutating,
        )
    )
    _ac_advisories: list[dict[str, Any]] = []
    repairs_needed = 0
    repaired = 0
    updated = False
    if not change_ids:
        diagnostics.append(_diagnostic("no_admitted_changes", "Wave has no admitted changes."))
    for admitted_change in change_ids:
        location = _change_location_state(root, wave_md, admitted_change)
        change_path: Optional[Path] = None
        if location["staged_exists"] and location["wave_exists"]:
            diagnostics.append(
                _diagnostic(
                    "duplicate_change_doc_locations",
                    f"Admitted change '{admitted_change}' exists in both {_repo_rel(root, location['staged_path'])} and {_repo_rel(root, location['wave_path'])}.",
                    recovery_tools=["wf_get_change"],
                    recovery_usage=f"wf_get_change(change_id={admitted_change!r})",
                )
            )
            continue
        if location["wave_exists"]:
            change_path = location["wave_path"]
        elif location["staged_exists"]:
            repairs_needed += 1
            if _mutating:
                try:
                    _move_change_doc(location["staged_path"], location["wave_path"])
                except OSError as exc:
                    diagnostics.append(
                        _diagnostic(
                            "change_relocation_failed",
                            f"Failed to relocate admitted change '{admitted_change}' during prepare: {exc}",
                            recovery_tools=["wf_get_change"],
                            recovery_usage=f"wf_get_change(change_id={admitted_change!r})",
                        )
                    )
                    continue
                repaired += 1
                updated = True
                change_path = location["wave_path"]
            else:
                diagnostics.append(
                    _diagnostic(
                        "change_doc_not_relocated",
                        f"Admitted change '{admitted_change}' is still staged at {_repo_rel(root, location['staged_path'])}; prepare must relocate it to {_repo_rel(root, location['wave_path'])}.",
                        recovery_tools=["wf_prepare_wave"],
                        recovery_usage=f"wf_prepare_wave(wave_id={wave_md.parent.name!r}, mode='create')",
                    )
                )
                continue
        else:
            diagnostics.append(
                _diagnostic(
                    "change_not_found",
                    f"Admitted change '{admitted_change}' was not found in {_repo_rel(root, location['staged_path'])} or {_repo_rel(root, location['wave_path'])}.",
                    recovery_tools=["wf_get_change", "wf_list_plans"],
                    recovery_usage=f"wf_get_change(change_id={admitted_change!r})",
                )
            )
            continue
        try:
            change_text = change_path.read_text(encoding="utf-8")
        except OSError as exc:
            diagnostics.append(
                _diagnostic(
                    "change_doc_unreadable",
                    f"Could not read admitted change '{admitted_change}' at {_repo_rel(root, change_path)}: {exc}",
                    recovery_tools=["wf_get_change"],
                    recovery_usage=f"wf_get_change(change_id={admitted_change!r})",
                )
            )
            continue
        missing_headers = _missing_required_change_sections(change_text)
        if missing_headers:
            diagnostics.append(
                _diagnostic(
                    "change_doc_missing_sections",
                    f"Admitted change '{admitted_change}' is missing sections: {', '.join(missing_headers)}.",
                    recovery_tools=["wf_get_change"],
                    recovery_usage=f"wf_get_change(change_id={admitted_change!r})",
                )
            )
        # AC priority advisory (non-blocking): warn if every AC row still has unpopulated placeholder text
        _AC_PLACEHOLDER = "required / important / nice-to-have / not-this-scope"
        if "## AC Priority" in change_text:
            ac_section_start = change_text.find("## AC Priority")
            ac_section = change_text[ac_section_start:]
            ac_rows = [line for line in ac_section.splitlines() if line.strip().startswith("| AC-")]
            if ac_rows and all(_AC_PLACEHOLDER in row for row in ac_rows):
                _ac_advisories.append(
                    _diagnostic(
                        "ac_priority_unpopulated",
                        f"Change '{admitted_change}' AC priority table still contains only placeholder text. Fill in priority values (required / important / nice-to-have / not-this-scope) for each AC row before closing the wave.",
                        recovery_tools=["wf_get_change"],
                        recovery_usage=f"wf_get_change(change_id={admitted_change!r})",
                    )
                )
    # Garden + lint run on create/ready (readiness mutations); dry-run stays read-only.
    required_council_signoffs = _required_wave_council_signoffs(root, "prepare")
    if required_council_signoffs:
        missing_council = [
            signoff_key
            for signoff_key in required_council_signoffs
            if not _lane_has_signoff_in_evidence(_combined_review_evidence(text), signoff_key)
        ]
        if missing_council:
            diagnostics.append(
                _diagnostic(
                    "missing_wave_council_signoff",
                    (
                        "Required Wave Council signoff missing for prepare: "
                        f"{', '.join(missing_council)}. Record the signoff line(s) in `## Review Evidence` before the wave can become active."
                    ),
                    recovery_tools=["wf_current_wave"],
                    recovery_usage="wf_current_wave()",
                )
            )
    garden_passed = True
    lint_passed = True
    if _mutating:
        garden_result = run_garden(root)
        garden_passed = garden_result["passed"]
        if not garden_passed:
            diagnostics.append(_diagnostic("docs_gardener_failed", "docs_gardener failed during prepare.", recovery_tools=["wf_garden_docs", "wf_validate_docs"], recovery_usage="wf_garden_docs(mode='run')"))
    lint_result = run_validate(root)
    lint_passed = lint_result["passed"]
    if not lint_passed:
        diagnostics.extend(_diagnostic("docs_lint_error", err, recovery_tools=["wf_validate_docs"]) for err in lint_result["errors"])
    # Wave 1p45l: the single-OPEN guard runs ONLY on the activating path (`create`). `ready`
    # and `dry_run` never take the slot, so any number of waves can be readied while one is
    # OPEN. The same guard also lives at the other activation transitions (wf_implement_wave,
    # wf_reopen_wave). Keyed on "is any OTHER wave OPEN (active/implementing)?" — self-transitions
    # on the target wave are not blocked.
    other_active = _find_other_active_wave(root, wave_md, cache=cache) if _activating else None
    guard_data: dict[str, Any] = {}
    if other_active is not None:
        guard_data = {
            "active_wave_id": other_active["wave_id"],
            "active_wave_path": _repo_rel(root, Path(other_active["path"])),
        }
        diagnostics.append(
            _diagnostic(
                "another_wave_active",
                f"Wave {other_active['wave_id']!r} is already OPEN (active/implementing). Pause it first, "
                f"or run wf_prepare_wave(wave_id={wave_id!r}, mode='ready') to ready {wave_id!r} without opening it.",
                recovery_tools=["wf_prepare_wave", "wf_pause_wave", "wf_current_wave"],
                recovery_usage=f"wf_prepare_wave(wave_id={wave_id!r}, mode='ready')",
            )
        )
    if diagnostics:
        error_data = {"wave_id": wave_id, "mode": mode_s, "change_count": len(change_ids), "lint_passed": lint_passed, "garden_passed": garden_passed, "repairs_needed": repairs_needed, "repaired": repaired}
        error_data["required_council_signoffs"] = required_council_signoffs
        error_data.update(guard_data)
        next_tools_list = ["wf_prepare_wave", "wf_pause_wave", "wf_current_wave"] if other_active is not None else ["wf_validate_docs", "wf_current_wave"]
        usage_hint = f"wf_prepare_wave(wave_id={wave_id!r}, mode='ready')" if other_active is not None else "wf_validate_docs()"
        return _response("error", error_data, diagnostics=diagnostics, next_tools=next_tools_list, usage=usage_hint)
    # Prepare-phase Wave Council review — final step of wf_prepare_wave (12sp5).
    # Always generate the council brief; block create-mode completion until verdict is recorded.
    council_brief = _build_prepare_council_brief(wave_id, text, change_ids)
    verdict_info = _prepare_council_verdict_info(text)
    verdict_present = bool(verdict_info.get("present"))
    verdict_valid = bool(verdict_info.get("valid"))
    if not verdict_present:
        council_usage = (
            "Run the prepare-phase Wave Council review now (seats and scope in council_brief), "
            "record the verdict in ## Review Checkpoints with a structured 'prepare-council' line, "
            "then call wf_prepare_wave(mode='create') to complete prepare."
        )
        if _mutating:
            return _response(
                "ready_for_council_review",
                {"wave_id": wave_id, "mode": mode_s, "council_brief": council_brief},
                diagnostics=[_diagnostic(
                    "prepare_council_verdict_missing",
                    "Technical checks passed. Ready to run prepare-phase Wave Council review. "
                    "Run each council seat in isolation against the admitted change docs, "
                    "record the verdict in ## Review Checkpoints with a structured 'prepare-council' line, "
                    f"then call wf_prepare_wave(mode={mode_s!r}) again to complete this step.",
                    recovery_tools=["wf_prepare_wave"],
                    recovery_usage=f"wf_prepare_wave(mode={mode_s!r})",
                )],
                next_tools=["wf_prepare_wave"],
                usage=council_usage,
            )
        # dry_run: include brief as advisory, don't block
        _ac_advisories.append(_diagnostic(
            "prepare_council_verdict_missing",
            "Technical checks passed. Ready to run prepare-phase Wave Council review. "
            "Run the council review and record the verdict before calling wf_prepare_wave(mode='create').",
            recovery_tools=["wf_prepare_wave"],
            recovery_usage="wf_prepare_wave(mode='create')",
        ))
    elif not verdict_valid:
        diagnostics.append(
            _diagnostic(
                "prepare_council_verdict_invalid",
                "A prepare-phase Wave Council verdict exists, but it is not structurally valid. "
                "Record a structured verdict in ## Review Checkpoints with moderator, primer-depth, seats, rotating-seat, strongest-challenge, and strongest-alternative fields before calling wf_prepare_wave(mode='create').",
                recovery_tools=["wf_prepare_wave"],
                recovery_usage="wf_prepare_wave(mode='create')",
            )
        )
        if mode_s == "create":
            return _response(
                "error",
                {
                    "wave_id": wave_id,
                    "mode": mode_s,
                    "change_count": len(change_ids),
                    "lint_passed": lint_passed,
                    "garden_passed": garden_passed,
                    "repairs_needed": repairs_needed,
                    "repaired": repaired,
                    "required_council_signoffs": required_council_signoffs,
                    "council_brief": council_brief,
                    "council_verdict_present": verdict_present,
                    "council_verdict_valid": verdict_valid,
                },
                diagnostics=diagnostics,
                next_tools=["wf_prepare_wave"],
                usage="wf_prepare_wave(mode='create')",
            )
    else:
        # The readiness run is evidence *for* the completed prepare review. Do
        # not require it before the council has run: the no-verdict path above
        # must remain able to return the brief that makes that review possible.
        diagnostics.extend(
            _review_evidence_diagnostics(
                text,
                root=root,
                wave_key=wave_md.parent.name,
                required_run_kind="readiness",
            )
        )
    if diagnostics:
        error_data = {"wave_id": wave_id, "mode": mode_s, "change_count": len(change_ids), "lint_passed": lint_passed, "garden_passed": garden_passed, "repairs_needed": repairs_needed, "repaired": repaired}
        error_data["required_council_signoffs"] = required_council_signoffs
        error_data["council_brief"] = council_brief
        error_data["council_verdict_present"] = verdict_present
        error_data["council_verdict_valid"] = verdict_valid
        return _response("error", error_data, diagnostics=diagnostics, next_tools=["wf_prepare_wave"], usage="wf_prepare_wave(mode='create')")
    transitioned_to_active = False
    if mode_s == "create":
        status_match = _STATUS_PATTERN.search(text)
        if status_match and status_match.group(1) != "active":
            text = text[:status_match.start(1)] + "active" + text[status_match.end(1):]
            updated = True
            transitioned_to_active = True
    if _mutating:
        try:
            projected_text = _project_current_review_status(root, wave_md, text)
        except ValueError as exc:
            return _response(
                "error",
                {"wave_id": wave_id, "mode": mode_s},
                diagnostics=[
                    _diagnostic("review_projection_failed", str(exc))
                ],
                next_tools=["wf_review_evidence", "wf_validate_docs"],
            )
        if projected_text != wave_md.read_text(encoding="utf-8"):
            wave_md.write_text(projected_text, encoding="utf-8", newline="")
            text = projected_text
            updated = True
    if mode_s == "create":
        if cache and updated:
            cache.invalidate()
        _trigger_background_index_refresh_for_paths(
            root,
            [wave_md, *(_wave_change_doc_path(root, wave_md, change_id) for change_id in change_ids)],
        )
    # Wave 1p601: refresh the codebase map at the prepare-wave lifecycle
    # checkpoint (fail-safe — never affects the prepare result).
    if mode_s == "create":
        _regenerate_codebase_map_safe(root)
    resp_data = {"wave_id": wave_id, "mode": mode_s, "readied": mode_s == "ready", "transitioned_to_active": transitioned_to_active, "change_count": len(change_ids), "lint_passed": lint_passed, "garden_passed": garden_passed, "updated": updated, "repairs_needed": repairs_needed, "repaired": repaired, "required_council_signoffs": required_council_signoffs, "council_brief": council_brief, "council_verdict_present": verdict_present, "council_verdict_valid": verdict_valid}
    # 1p8gy AC-6: prior-learning advisories before implementation begins —
    # fragile files, repeated failed attempts, operator preferences.
    _mem_advisories = _memory_advisories_for_wave(
        root, {"wave_id": wave_id, "changes": [{"id": cid} for cid in change_ids]}
    )
    if _mem_advisories:
        resp_data["memory_advisories"] = _mem_advisories
    envelope = _response("dry_run" if mode_s == "dry_run" else "ok", resp_data, diagnostics=_ac_advisories if _ac_advisories else None, next_tools=["wf_current_wave"], usage="wf_current_wave()")
    return _attach_lint_to_response(envelope, root, mode_s)


def wf_pause_wave_response(root: Path, wave_id: str, mode: str = "dry_run", cache: Optional[McpRepoCache] = None) -> dict[str, Any]:
    mode_s = "create" if (mode or "").strip().lower() == "apply" else (mode or "").strip().lower()
    if mode_s not in {"dry_run", "create"}:
        return _response("error", {"wave_id": wave_id, "mode": mode}, diagnostics=[_diagnostic("invalid_arguments", f"Unsupported mode '{mode}'.")], next_tools=["wf_help"], usage="wf_help()")
    wave_md = _find_wave_md(root, wave_id)
    if wave_md is None:
        return _response("error", {"wave_id": wave_id, "mode": mode_s}, diagnostics=[_diagnostic("wave_not_found", f"No wave found matching '{wave_id}'.", recovery_tools=["wf_list_waves"], recovery_usage="wf_list_waves()")], next_tools=["wf_list_waves"], usage="wf_list_waves()")
    handoff = root / "docs" / "agents" / "session-handoff.md"
    rel = str(handoff.relative_to(root)).replace("\\", "/")
    # Compute the wave-status transition. Only active → paused writes; other states are no-ops.
    wave_text = wave_md.read_text(encoding="utf-8")
    status_match = _STATUS_PATTERN.search(wave_text)
    current_status = status_match.group(1) if status_match else ""
    if current_status in ("active", "implementing"):
        status_transition = {"from": current_status, "to": "paused"}
    elif current_status == "paused":
        status_transition = {"from": "paused", "to": "paused"}
    else:
        status_transition = {"from": current_status, "to": current_status}
    diagnostics: list[dict[str, Any]] = []
    if current_status not in ("active", "implementing", "paused"):
        diagnostics.append(
            _diagnostic(
                "pause_on_non_active_wave",
                f"Wave '{wave_id}' is not active (status: {current_status!r}). Handoff entry was written but wave status was not changed.",
                recovery_tools=["wf_current_wave"],
                recovery_usage="wf_current_wave()",
            )
        )
    diagnostics.extend(_force_gates_closed(root, mode_s))
    if mode_s == "create":
        # Transition wave status first, then write the handoff entry.
        if status_transition["from"] in ("active", "implementing") and status_transition["to"] == "paused":
            new_text = wave_text[:status_match.start(1)] + "paused" + wave_text[status_match.end(1):]
            wave_md.write_text(new_text, encoding="utf-8")
        handoff.parent.mkdir(parents=True, exist_ok=True)
        prior = handoff.read_text(encoding="utf-8") if handoff.exists() else ""
        handoff.write_text(_update_handoff_wave_ref(prior, wave_id), encoding="utf-8")
        if cache:
            cache.invalidate()
        _trigger_background_index_refresh_for_paths(root, [handoff, wave_md])
    envelope = _response(
        "dry_run" if mode_s == "dry_run" else "ok",
        {
            "wave_id": wave_id,
            "mode": mode_s,
            "path": rel,
            "written": mode_s == "create",
            "status_transition": status_transition,
        },
        diagnostics=diagnostics if diagnostics else None,
        next_tools=["wf_current_wave"],
        usage="wf_current_wave()",
    )
    return _attach_lint_to_response(envelope, root, mode_s)


def _operator_signoff_present(wave_text: str) -> bool:
    """True if Review Evidence contains an operator-signoff line."""
    return _lane_has_signoff_in_evidence(_combined_review_evidence(wave_text), "operator-signoff")


_SEVERITY_ORDER = ["none", "low", "medium", "high", "critical"]
# Wave 1p45s: match severity levels as whole words, not substrings. A bare ``sev in line``
# test fires on ordinary prose ("highest-salience" -> high, "below"/"allow"/"flow" -> low,
# "criticality" -> critical), producing phantom close-time findings. ``\b`` word boundaries
# match genuine standalone severity words while ignoring severity strings embedded inside
# larger words. ("none" is the rank-0 default and is intentionally not matched.)
_SEVERITY_WORD_RE = re.compile(r"\b(" + "|".join(s for s in _SEVERITY_ORDER if s != "none") + r")\b")


def _max_severity_from_evidence(wave_text: str) -> str:
    """Scan Review Evidence signoff lines for severity annotations; return the highest found.

    Severity words are matched as whole tokens (wave 1p45s) so substrings inside larger
    words (e.g. "high" in "highest") do not register. Position-independent: a standalone
    severity word ranks the same wherever it appears in the line.
    """
    evidence = _combined_review_evidence(wave_text)
    max_rank = 0
    for raw in evidence.splitlines():
        line = raw.strip().lower()
        if not line or line.startswith("#") or "<" in line:
            continue
        for word in _SEVERITY_WORD_RE.findall(line):
            rank = _SEVERITY_ORDER.index(word)
            if rank > max_rank:
                max_rank = rank
    return _SEVERITY_ORDER[max_rank]


def wf_review_wave_response(root: Path, wave_id: str, phase: str = "implementation") -> dict[str, Any]:
    phase_s = (phase or "implementation").strip().lower()
    if phase_s not in ("prepare", "implementation"):
        return _response("error", {"wave_id": wave_id, "phase": phase_s}, diagnostics=[_diagnostic("invalid_arguments", f"Invalid phase '{phase_s}'. Valid values: 'prepare', 'implementation'.")], next_tools=["wf_help"], usage="wf_help()")
    wave_md = _find_wave_md(root, wave_id)
    if wave_md is None:
        return _response("error", {"wave_id": wave_id}, diagnostics=[_diagnostic("wave_not_found", f"No wave found matching '{wave_id}'.", recovery_tools=["wf_list_waves"], recovery_usage="wf_list_waves()")], next_tools=["wf_list_waves"], usage="wf_list_waves()")
    lint_result = run_validate(root)
    wave_text = wave_md.read_text(encoding="utf-8")
    review_evidence_diagnostics = _review_evidence_diagnostics(
        wave_text,
        root=root,
        wave_key=wave_md.parent.name,
        persist_adoption=False,
        required_run_kind="readiness" if phase_s == "prepare" else "initial_delivery",
    )
    # Merge lanes from wave.md Participants table and project-declared required_review_lanes
    wave_lanes = _extract_required_review_lanes(wave_text)
    project_lanes = _read_project_required_review_lanes(root)
    extra_lanes = [l for l in project_lanes if l not in wave_lanes]
    required_lanes = (["operator"] + wave_lanes + extra_lanes) if phase_s == "implementation" else wave_lanes + extra_lanes

    if phase_s == "prepare":
        # Prepare-phase: check signoffs in ## Prepare Review Evidence (no operator signoff required)
        evidence = _prepare_review_evidence(wave_text)
        lane_results = [{"lane": lane, "recorded_signoff": _lane_has_signoff_in_evidence(evidence, lane)} for lane in required_lanes]
        diagnostics = list(review_evidence_diagnostics)
        if not lint_result["passed"]:
            diagnostics.extend(_diagnostic("docs_lint_error", err, recovery_tools=["wf_validate_docs"]) for err in lint_result["errors"])
        missing = [entry["lane"] for entry in lane_results if not entry["recorded_signoff"]]
        if missing:
            diagnostics.append(_diagnostic(
                "missing_required_lane",
                f"Prepare-phase review lanes without recorded signoff in `## Prepare Review Evidence`: {', '.join(missing)}. "
                "Record each lane signoff in the `## Prepare Review Evidence` section of wave.md before running wf_implement_wave.",
                recovery_tools=["wf_current_wave"],
                recovery_usage="wf_current_wave()",
            ))
        status = "ok" if lint_result["passed"] and not missing and not review_evidence_diagnostics else "error"
        return _response(
            status,
            {"wave_id": wave_id, "phase": phase_s, "required_lanes": required_lanes, "lane_results": lane_results, "lint_passed": lint_result["passed"]},
            diagnostics=diagnostics,
            next_tools=["wf_implement_wave", "wf_current_wave"],
            usage=f"wf_implement_wave(wave_id={wave_id!r}, mode='dry_run')",
        )

    # Implementation phase (default): current behavior — check ## Review Evidence
    operator_signed = _operator_signoff_present(wave_text)
    lane_results = [{"lane": "operator", "recorded_signoff": operator_signed}] + [{"lane": lane, "recorded_signoff": _lane_has_signoff(wave_text, lane)} for lane in required_lanes[1:]]
    required_council_signoffs = _required_wave_council_signoffs(root, "review", wave_text=wave_text)
    council_results = [
        {"signoff_key": signoff_key, "recorded_signoff": _lane_has_signoff(wave_text, signoff_key)}
        for signoff_key in required_council_signoffs
    ]
    diagnostics = list(review_evidence_diagnostics)
    approval_evidence_diagnostics = _approval_evidence_diagnostics(
        wave_text,
        ["operator-signoff", *required_lanes[1:], *required_council_signoffs],
        root=root,
        wave_key=wave_md.parent.name,
    )
    diagnostics.extend(approval_evidence_diagnostics)
    if not lint_result["passed"]:
        diagnostics.extend(_diagnostic("docs_lint_error", err, recovery_tools=["wf_validate_docs"]) for err in lint_result["errors"])
    missing = [entry["lane"] for entry in lane_results if not entry["recorded_signoff"]]
    if "operator" in missing:
        diagnostics.append(_diagnostic(
            "missing_operator_signoff",
            "Operator review approval is required before closing this wave. "
            "Add `operator-signoff: approved` to `## Review Evidence` in wave.md. "
            "Approval is given by the operator asking to close the wave, or by the agent explicitly asking for approval.",
            recovery_tools=["wf_current_wave"],
            recovery_usage="wf_current_wave()",
        ))
    other_missing = [m for m in missing if m != "operator"]
    if other_missing:
        diagnostics.append(_diagnostic(
            "missing_required_lane",
            f"Required review lanes without recorded signoff: {', '.join(other_missing)}.",
            recovery_tools=["wf_current_wave"],
            recovery_usage="wf_current_wave()",
        ))
    missing_council = [entry["signoff_key"] for entry in council_results if not entry["recorded_signoff"]]
    if missing_council:
        diagnostics.append(_diagnostic(
            "missing_wave_council_signoff",
            (
                "Required Wave Council signoff missing for review: "
                f"{', '.join(missing_council)}. Record the signoff line(s) in `## Review Evidence` before closing the wave."
            ),
            recovery_tools=["wf_current_wave"],
            recovery_usage="wf_current_wave()",
        ))
    max_severity = _max_severity_from_evidence(wave_text)
    if max_severity in ("critical", "high"):
        diagnostics.append(_diagnostic(
            "high_severity_finding",
            f"Sensor findings include {max_severity}-severity issues — prioritise operator review of these before closing.",
            recovery_tools=["wf_current_wave"],
            recovery_usage="wf_current_wave()",
        ))
    # Wave 1t3ek (1t230): retrieval-posture sensor — advisory diagnostic only;
    # like high_severity_finding it never participates in the status computation.
    _posture_gap: Optional[dict[str, Any]] = None
    if phase_s == "implementation":
        try:
            _posture_gap = _retrieval_posture_gap(root, wave_md)
        except Exception:
            _posture_gap = None
        if _posture_gap is not None:
            diagnostics.append(_diagnostic(
                "retrieval_posture_gap",
                _posture_gap["message"],
                recovery_tools=["wf_current_wave"],
                recovery_usage="wf_current_wave()",
            ))
    status = "ok" if (
        lint_result["passed"]
        and not missing
        and not missing_council
        and not review_evidence_diagnostics
        and not approval_evidence_diagnostics
    ) else "error"
    # 1p8gy AC-6: prior review findings and lessons relevant to this wave.
    _review_data = {"wave_id": wave_id, "phase": phase_s, "required_lanes": required_lanes, "lane_results": lane_results, "required_council_signoffs": required_council_signoffs, "council_results": council_results, "lint_passed": lint_result["passed"], "max_severity": max_severity}
    # Wave 1t3ek (1t230): the delivery council reads the implement-stage numbers
    # in-context rather than discovering them at close.
    if phase_s == "implementation":
        try:
            _stage = context_efficiency.read_wave_snapshot(
                root, wave_md.parent.name
            ).get("stages", {}).get("implement")
        except Exception:
            _stage = None
        _review_data["implement_stage_telemetry"] = {
            "stage_totals": _stage or {},
            "retrieval_calls": context_efficiency.implement_stage_retrieval_calls(
                root, wave_md.parent.name
            ),
        }
        if _posture_gap is not None:
            _review_data["retrieval_posture_gap"] = _posture_gap
    _mem_advisories = _memory_advisories_for_wave(
        root, {"wave_id": wave_id, "changes": [{"id": cid} for cid in _extract_change_ids_from_wave_text(wave_text)]}
    )
    if _mem_advisories:
        _review_data["memory_advisories"] = _mem_advisories
    return _response(
        status,
        _review_data,
        diagnostics=diagnostics,
        next_tools=["wf_validate_docs", "wf_current_wave"],
        usage="wf_validate_docs()",
    )


# Wave 1t3ek (1t230): the retrieval-posture loop. The directive travels in-band
# on the activation envelope (self-contained: rule + escape hatch + consequence),
# and the gap sensor fires at implementation review / close dry-run when
# implement-stage retrieval telemetry is near zero against a non-trivial code
# diff. A recorded "Gapfill:" entry clears the advisory; it never blocks.
_RETRIEVAL_POSTURE_DIRECTIVE = (
    "MCP-first implementation retrieval: search, read, and navigate code through "
    "the code_* and docs_search tools first; harness shell and file search are "
    "fallback. When fallback is genuinely the right instrument (bulk-mechanical "
    "edits, docs-only work), record a 'Gapfill:' entry in a Progress Log "
    "explaining why. That same recorded entry clears the retrieval_posture_gap "
    "advisory raised at implementation review and close when implement-stage "
    "retrieval telemetry is near zero against a non-trivial code diff."
)

# Test seam: replace to drive the footprint without a real git history.
_FOOTPRINT_PROVIDER: Optional[Callable[[Path], Optional[int]]] = None

_FOOTPRINT_EXCLUDE_PREFIXES = ("docs/", ".wavefoundry/index/", ".wavefoundry/logs/")


def _wave_code_footprint(root: Path) -> Optional[int]:
    """Count changed tracked non-docs files in the working tree; None when
    git is unavailable (the sensor then stays silent)."""
    if _FOOTPRINT_PROVIDER is not None:
        return _FOOTPRINT_PROVIDER(root)
    try:
        proc = subprocess_util.isolated_run(
            ["git", "-C", str(root), "status", "--porcelain"],
            capture_output=True, text=True, timeout=10, check=False,
        )
    except Exception:
        return None
    if proc.returncode != 0:
        return None
    count = 0
    for line in proc.stdout.splitlines():
        if len(line) < 4:
            continue
        rel = line[3:].strip().strip('"')
        if not rel or rel.endswith("/"):
            continue
        if any(rel.startswith(prefix) for prefix in _FOOTPRINT_EXCLUDE_PREFIXES):
            continue
        count += 1
    return count


def _retrieval_posture_thresholds(root: Path) -> tuple[int, int]:
    """(max_retrieval_calls, min_changed_files) — conservative defaults, tunable
    via workflow-config ``sensors.retrieval_posture``."""
    max_calls, min_files = 0, 5
    cfg = _read_workflow_config(root)
    sensors = cfg.get("sensors") if isinstance(cfg, dict) else None
    posture = sensors.get("retrieval_posture") if isinstance(sensors, dict) else None
    if isinstance(posture, dict):
        try:
            max_calls = int(posture.get("max_retrieval_calls", max_calls))
        except (TypeError, ValueError):
            pass
        try:
            min_files = int(posture.get("min_changed_files", min_files))
        except (TypeError, ValueError):
            pass
    return max_calls, min_files


def _wave_has_gapfill_note(wave_md: Path) -> bool:
    try:
        for doc in sorted(wave_md.parent.glob("*.md")):
            if "Gapfill:" in doc.read_text(encoding="utf-8"):
                return True
    except OSError:
        pass
    return False


def _retrieval_posture_gap(root: Path, wave_md: Path) -> Optional[dict[str, Any]]:
    """Return the gap payload, or None when the sensor has nothing to say.

    Fires only when ALL hold: the store is readable, implement-stage retrieval
    calls are at or below the threshold, the changed-file footprint is at or
    above its threshold, and no Gapfill entry is recorded in the wave.
    """
    calls = context_efficiency.implement_stage_retrieval_calls(
        root, wave_md.parent.name
    )
    if calls is None:
        return None
    max_calls, min_files = _retrieval_posture_thresholds(root)
    if calls > max_calls:
        return None
    footprint = _wave_code_footprint(root)
    if footprint is None or footprint < min_files:
        return None
    if _wave_has_gapfill_note(wave_md):
        return None
    return {
        "implement_stage_retrieval_calls": calls,
        "changed_non_docs_files": footprint,
        "message": (
            f"Implement-stage instrumented retrieval calls: {calls}; changed "
            f"non-docs files in the working tree: {footprint}. Implementation "
            "appears to have bypassed the MCP retrieval tools (code_*, "
            "docs_search). Route exploration through them, or record a "
            "'Gapfill:' entry in a Progress Log explaining why harness "
            "fallback was the right instrument; the recorded entry clears "
            "this advisory."
        ),
    }


def wf_implement_wave_response(root: Path, wave_id: str, mode: str = "dry_run", cache: Optional[McpRepoCache] = None) -> dict[str, Any]:
    """Gate and context builder for starting wave implementation (12sqb).

    Checks:
    1. Wave is OPEN-able — `active` (legacy prepare-and-open) or a readied `planned`
       wave (wave 1p45l); not already implementing, not paused/closed/blocked.
    2. Automated prepare-phase Wave Council verdict is recorded (12sp5).
    3. All required prepare-phase lane reviews are recorded in ## Prepare Review Evidence.
    4. Single-OPEN guard (wave 1p45l): no OTHER wave is already active/implementing.

    On create: runs the single-OPEN guard, then transitions wave status to 'implementing'.
    Returns ordered change list, Journal Watchpoints, and serialization points.
    """
    mode_s = "create" if (mode or "").strip().lower() == "apply" else (mode or "").strip().lower()
    _VALID_MODES = ["dry_run", "create"]
    if mode_s not in _VALID_MODES:
        return _response("error", {"wave_id": wave_id, "mode": mode, "valid_modes": _VALID_MODES}, diagnostics=[_diagnostic("invalid_arguments", f"Unsupported mode '{mode}'. Valid modes: {_VALID_MODES}.")], next_tools=["wf_help"], usage="wf_help()")
    wave_md = _find_wave_md(root, wave_id)
    if wave_md is None:
        return _response("error", {"wave_id": wave_id}, diagnostics=[_diagnostic("wave_not_found", f"No wave found matching '{wave_id}'.", recovery_tools=["wf_list_waves"], recovery_usage="wf_list_waves()")], next_tools=["wf_list_waves"], usage="wf_list_waves()")

    wave_text = wave_md.read_text(encoding="utf-8")
    status_match = _STATUS_PATTERN.search(wave_text)
    current_status = (status_match.group(1) if status_match else "").lower()

    if current_status == "implementing":
        return _response("ok", {"wave_id": wave_id, "mode": mode_s, "status": "implementing", "already_implementing": True, "transitioned_to_implementing": False}, next_tools=["wf_current_wave", "wf_review_wave"], usage="wf_current_wave()")
    # Wave 1p45l: implement opens an `active` wave (legacy prepare-and-open) OR a readied
    # `planned` wave. A non-readied `planned` wave still fails the council/lane gates below.
    if current_status not in ("active", "planned"):
        return _response(
            "error",
            {"wave_id": wave_id, "mode": mode_s, "status": current_status},
            diagnostics=[_diagnostic("wave_not_active", f"wf_implement_wave requires an `active` or readied `planned` wave; '{wave_id}' has status '{current_status}'. Prepare it (`wf_prepare_wave(mode='ready')`), or resume it if paused.", recovery_tools=["wf_prepare_wave", "wf_current_wave"], recovery_usage=f"wf_prepare_wave(wave_id={wave_id!r}, mode='ready')")],
            next_tools=["wf_prepare_wave", "wf_current_wave"],
            usage=f"wf_prepare_wave(wave_id={wave_id!r}, mode='ready')",
        )

    diagnostics: list[dict[str, Any]] = []

    # Gate 1: council verdict
    verdict_info = _prepare_council_verdict_info(wave_text)
    if not verdict_info.get("present"):
        diagnostics.append(_diagnostic(
            "prepare_council_verdict_missing",
            "No prepare-phase Wave Council verdict found in `## Review Checkpoints`. "
            "Run the council review (red-team fixed seat + rotating seat) and record the verdict "
            "with a structured 'prepare-council' line before calling wf_implement_wave.",
            recovery_tools=["wf_prepare_wave", "wf_current_wave"],
            recovery_usage=f"wf_prepare_wave(wave_id={wave_id!r}, mode='dry_run')",
        ))
    elif not verdict_info.get("valid"):
        diagnostics.append(_diagnostic(
            "prepare_council_verdict_invalid",
            "A prepare-phase Wave Council verdict was found, but it is not structurally valid. "
            "Record a structured verdict with moderator, primer-depth, seats, rotating-seat, strongest-challenge, and strongest-alternative before calling wf_implement_wave.",
            recovery_tools=["wf_prepare_wave", "wf_current_wave"],
            recovery_usage=f"wf_prepare_wave(wave_id={wave_id!r}, mode='dry_run')",
        ))

    # Gate 2: prepare-phase lane review
    wave_lanes = _extract_required_review_lanes(wave_text)
    project_lanes = _read_project_required_review_lanes(root)
    required_lanes = wave_lanes + [l for l in project_lanes if l not in wave_lanes]
    if required_lanes:
        evidence = _prepare_review_evidence(wave_text)
        missing_lanes = [lane for lane in required_lanes if not _lane_has_signoff_in_evidence(evidence, lane)]
        if missing_lanes:
            diagnostics.append(_diagnostic(
                "prepare_review_incomplete",
                f"Prepare-phase lane review incomplete — missing signoffs in `## Prepare Review Evidence`: {', '.join(missing_lanes)}. "
                "Run wf_review_wave(phase='prepare') and record each lane signoff before calling wf_implement_wave.",
                recovery_tools=["wf_review_wave", "wf_current_wave"],
                recovery_usage=f"wf_review_wave(wave_id={wave_id!r}, phase='prepare')",
            ))
    else:
        missing_lanes = []

    # Gate 3 (wave 1p45l): single-OPEN guard — at most one wave may be OPEN (active/implementing).
    # This is the relocated single-OPEN enforcement point; readiness paths (prepare ready/dry_run)
    # no longer guard. `_find_other_active_wave` excludes the target wave, so opening a wave that
    # is already `active` (legacy flow) is not blocked by itself.
    other_open = _find_other_active_wave(root, wave_md, cache=cache)
    if other_open is not None:
        diagnostics.append(_diagnostic(
            "another_wave_active",
            f"Wave {other_open['wave_id']!r} is already OPEN (active/implementing); only one wave may be OPEN at a time. "
            f"Pause it before opening {wave_id!r}.",
            recovery_tools=["wf_pause_wave", "wf_current_wave"],
            recovery_usage=f"wf_pause_wave(wave_id={other_open['wave_id']!r}, mode='create')",
        ))

    if diagnostics:
        return _response("error", {"wave_id": wave_id, "mode": mode_s}, diagnostics=diagnostics, next_tools=["wf_review_wave", "wf_current_wave"], usage=f"wf_review_wave(wave_id={wave_id!r}, phase='prepare')")

    # All gates passed — build implementation context
    change_ids = _extract_change_ids_from_wave_text(wave_text)

    # Ordered changes: extract status + dependencies from each change doc
    ordered_changes: list[dict[str, Any]] = []
    for cid in change_ids:
        change_path = wave_md.parent / f"{cid}.md"
        if not change_path.exists():
            ordered_changes.append({"change_id": cid, "status": "unknown", "depends_on": []})
            continue
        ct = change_path.read_text(encoding="utf-8")
        status_m = _CHANGE_STATUS_PATTERN.search(ct)
        cs = status_m.group(1) if status_m else "unknown"
        deps_m = re.findall(r"Depends On:\s*`([^`]+)`", ct)
        ordered_changes.append({"change_id": cid, "status": cs, "depends_on": deps_m})

    # Journal Watchpoints section
    watchpoints_text = ""
    wp_idx = wave_text.find("## Journal Watchpoints")
    if wp_idx != -1:
        tail = wave_text[wp_idx + len("## Journal Watchpoints"):]
        nl = tail.find("\n")
        if nl != -1:
            tail = tail[nl + 1:]
        m_end = re.search(r"\n(?=## )", tail)
        watchpoints_text = (tail[: m_end.start()] if m_end else tail).strip()

    # Serialization points: changes that other changes depend on
    all_deps: set[str] = set()
    for c in ordered_changes:
        all_deps.update(c["depends_on"])
    serialization_points = [cid for cid in change_ids if cid in all_deps]

    if mode_s == "create":
        new_text = wave_text[:status_match.start(1)] + "implementing" + wave_text[status_match.end(1):]
        wave_md.write_text(new_text, encoding="utf-8")
        if cache:
            cache.invalidate()

    resp_data = {
        "wave_id": wave_id,
        "mode": mode_s,
        "transitioned_to_implementing": mode_s == "create",
        "status_transition": {"from": current_status, "to": "implementing"} if mode_s == "create" else {"from": current_status, "to": f"{current_status} (dry_run)"},
        "ordered_changes": ordered_changes,
        "journal_watchpoints": watchpoints_text,
        "serialization_points": serialization_points,
        # Wave 1t3ek (1t230): the retrieval directive arrives in-band at the
        # exact moment implementation starts, not only in a prompt doc.
        "retrieval_posture": _RETRIEVAL_POSTURE_DIRECTIVE,
    }
    envelope = _response(
        "dry_run" if mode_s == "dry_run" else "ok",
        resp_data,
        next_tools=["wf_current_wave", "wf_review_wave"],
        usage="wf_current_wave()",
    )
    return _attach_lint_to_response(envelope, root, mode_s)


def _load_scan_findings(root: Path) -> list[dict]:
    path = root / "docs" / "scan-findings.json"
    if not path.exists():
        return []
    try:
        data = json.loads(path.read_text(encoding="utf-8"))
        return data if isinstance(data, list) else []
    except Exception:
        return []


def _check_secrets_gate(root: Path, canonical_wave_id: str) -> list[dict]:
    """Return blocking diagnostic dicts for the wf_close_wave secrets gate.

    Hard-block (must be classified before close): any entry with status
    'pending' or 'suspected-secret' — these are unresolved and must be
    classified to 'confirmed-secret' (real) or 'false-positive' (not real).

    Wave 1p5pz: 'confirmed-secret' findings no longer block close — they are a
    real, classified, tracked secret surfaced as a non-blocking standing
    reminder (see _confirmed_secret_notice). The per-wave acknowledged_for_wave
    / override_reason soft-block was dropped; classification IS the
    acknowledgment. 'false-positive' clears silently. Legacy findings that still
    carry acknowledged_for_wave / override_reason are tolerated (ignored).
    """
    diagnostics: list[dict] = []
    exceptions = _load_scan_findings(root)
    if not exceptions:
        return diagnostics

    # Fail-closed: only 'false-positive' (not a real secret) and 'confirmed-secret'
    # (real, classified — non-blocking + reminded) clear close. 'pending',
    # 'suspected-secret', and any unknown/missing status are unresolved and
    # hard-block — an unrecognized status must never slip through unblocked.
    unresolved = [
        e for e in exceptions
        if e.get("status") not in ("false-positive", "confirmed-secret")
    ]
    if unresolved:
        lines = "\n".join(
            f"  [{e.get('id', '?')}] {e.get('file', '?')}:{e.get('line', '?')}  rule: {e.get('rule_id', '?')}  status: {e.get('status', '?')}"
            for e in unresolved
        )
        diagnostics.append(_diagnostic(
            "secrets_gate_unresolved",
            (
                f"SECRETS GATE — {len(unresolved)} unresolved finding(s) must be classified before close:\n\n"
                f"{lines}\n\n"
                "To proceed: run the security reviewer (seed-213), which will classify each as "
                "'confirmed-secret' (a real secret — tracked, non-blocking) or 'false-positive' "
                "(not a real secret). Then re-run wf_close_wave. Never label a real secret "
                "'false-positive'."
            ),
            recovery_tools=["wf_review_wave"],
            recovery_usage=f"wf_review_wave(wave_id={canonical_wave_id!r})",
        ))

    return diagnostics


def _confirmed_secret_notice(root: Path) -> dict[str, Any] | None:
    """Build a non-blocking standing reminder of 'confirmed-secret' findings.

    Wave 1p5pz: confirmed secrets do not block wf_close_wave; instead EVERY close
    surfaces this reminder in the response ``data`` so the agent presents it to
    the operator. Returns None when there are no confirmed-secret findings.
    """
    confirmed = [
        e for e in _load_scan_findings(root)
        if e.get("status") == "confirmed-secret"
    ]
    if not confirmed:
        return None
    items = [
        {
            "id": e.get("id", "?"),
            "file": e.get("file", "?"),
            "line": e.get("line", "?"),
            "rule_id": e.get("rule_id", "?"),
        }
        for e in confirmed
    ]
    lines = "\n".join(f"  [{i['id']}] {i['file']}:{i['line']}  rule: {i['rule_id']}" for i in items)
    reminder = (
        f"NOTE — {len(confirmed)} confirmed secret(s) are tracked in this project "
        "(docs/scan-findings.json). These do NOT block wave close; this is a standing "
        "reminder to rotate/remove them before distribution. Present this to the operator:\n\n"
        f"{lines}"
    )
    return {"confirmed_secrets": items, "secrets_reminder": reminder}


def _generate_wf_close_wave_summary(wave_id: str, wave_text: str, wave_md: Path) -> str:
    """Synthesize a wave close summary from structured fields in the wave record and change docs.

    Format: one or more prose paragraphs followed by optional per-change bullet points.
    Reads completed ACs ([x] lines), progress log entries, and decision log entries from
    each admitted change doc. Does not require operator input.
    """
    # Extract wave title
    title_m = re.search(r"^Title:\s*(.+)$", wave_text, re.MULTILINE)
    wave_title = title_m.group(1).strip() if title_m else wave_id

    change_ids = _extract_change_ids_from_wave_text(wave_text)

    def _section_body(text: str, heading: str) -> str:
        idx = text.find(heading)
        if idx == -1:
            return ""
        tail = text[idx + len(heading):]
        nl = tail.find("\n")
        if nl != -1:
            tail = tail[nl + 1:]
        m = re.search(r"\n(?=## )", tail)
        return (tail[: m.start()] if m else tail).strip()

    change_summaries: list[dict] = []
    for cid in change_ids:
        change_path = wave_md.parent / f"{cid}.md"
        if not change_path.exists():
            change_summaries.append({"id": cid, "title": cid, "completed_acs": [], "decisions": [], "progress": []})
            continue
        ct = change_path.read_text(encoding="utf-8")
        # Title from H1
        h1_m = re.search(r"^#\s+(.+)$", ct, re.MULTILINE)
        title = h1_m.group(1).strip() if h1_m else cid
        # Completed ACs: [x] lines in Acceptance Criteria
        ac_body = _section_body(ct, "## Acceptance Criteria")
        completed_acs = [line.strip()[5:].strip() for line in ac_body.splitlines() if re.match(r"\s*-\s*\[x\]", line, re.IGNORECASE)]
        # Progress log: data rows (skip header)
        progress_body = _section_body(ct, "## Progress Log")
        progress_entries = []
        for row in progress_body.splitlines():
            cells = [c.strip() for c in row.strip("|").split("|")]
            if len(cells) >= 2 and cells[0] and cells[0].lower() != "date" and not re.fullmatch(r":?-+:?", cells[0]):
                progress_entries.append(cells[1] if len(cells) > 1 else "")
        # Decision log: data rows
        decision_body = _section_body(ct, "## Decision Log")
        decision_entries = []
        for row in decision_body.splitlines():
            cells = [c.strip() for c in row.strip("|").split("|")]
            if len(cells) >= 2 and cells[0] and cells[0].lower() != "date" and not re.fullmatch(r":?-+:?", cells[0]):
                decision_entries.append(cells[1] if len(cells) > 1 else "")
        change_summaries.append({"id": cid, "title": title, "completed_acs": completed_acs, "decisions": decision_entries, "progress": progress_entries})

    # Compose prose paragraph
    if change_summaries:
        titles = [cs["title"] for cs in change_summaries]
        if len(titles) == 1:
            delivered = f"one change: {titles[0]}"
        elif len(titles) == 2:
            delivered = f"two changes: {titles[0]} and {titles[1]}"
        else:
            delivered = f"{len(titles)} changes: {', '.join(titles[:-1])}, and {titles[-1]}"
        para = f"Wave `{wave_id}` ({wave_title}) delivered {delivered}."
    else:
        para = f"Wave `{wave_id}` ({wave_title}) closed with no admitted changes."

    # Notable pivots from progress logs
    pivots: list[str] = []
    for cs in change_summaries:
        for entry in cs["progress"]:
            lower = entry.lower()
            if any(kw in lower for kw in ("renamed", "removed", "consolidated", "added", "scope", "pivot", "revert", "expanded")):
                pivots.append(f"{cs['title']}: {entry}")
    if pivots:
        para += " Notable adjustments during implementation: " + "; ".join(pivots[:3]) + ("." if not pivots[0].endswith(".") else "")

    lines = [para, ""]

    # Per-change bullet points if there are decisions or completed ACs worth surfacing
    any_detail = any(cs["decisions"] or cs["completed_acs"] for cs in change_summaries)
    if any_detail and change_summaries:
        lines.append("**Changes delivered:**")
        lines.append("")
        for cs in change_summaries:
            ac_count = len(cs["completed_acs"])
            decisions = cs["decisions"]
            bullet = f"- **{cs['title']}** (`{cs['id']}`)"
            if ac_count:
                bullet += f" — {ac_count} AC{'s' if ac_count != 1 else ''} completed"
            if decisions:
                bullet += (". Key decisions: " if ac_count else " — ") + "; ".join(decisions[:2])
            lines.append(bullet)

    return "\n".join(lines)


def _replace_wave_summary_section(text: str, summary: str) -> str:
    """Replace the content of ## Wave Summary with the generated summary."""
    marker = "## Wave Summary"
    idx = text.find(marker)
    if idx == -1:
        return text
    # Find end of section (next ## heading or end of file)
    tail_start = idx + len(marker)
    nl = text.find("\n", tail_start)
    if nl != -1:
        body_start = nl + 1
    else:
        body_start = tail_start
    tail = text[body_start:]
    m_end = re.search(r"\n(?=## )", tail)
    body_end = body_start + (m_end.start() + 1 if m_end else len(tail))
    return text[:body_start] + "\n" + summary + "\n" + text[body_end:]


def _auto_populate_memory_for_wave(root: Path, wave_id: str) -> dict[str, Any]:
    """Fail-isolated close fallback: create candidates, never semantic verdicts."""
    try:
        result = memory_propose_response(
            root, wave_id=wave_id, mode="create", limit=MEMORY_PROPOSE_CAP
        )
        data = result.get("data") or {}
        written = list(data.get("written") or [])
        if not written:
            return {}
        return {
            "drafted": len(written), "promoted": 0,
            "candidate": len(written), "validation_required": len(written),
            "records": written,
        }
    except Exception:
        return {}


def _memory_validation_diagnostics(root: Path, wave_id: str) -> list[dict[str, Any]]:
    """Block close until every structurally eligible source has an agent verdict."""
    try:
        supply = _load_script("memory_supply")
        mem = _memory_mod()
        # Closure is an exhaustive gate, not a display page.
        drafts = supply.draft_candidates(root, wave_id, limit=None)
        if not drafts:
            return []
        by_source: dict[str, list[dict[str, Any]]] = {}
        for record in mem.load_memory_records(root):
            source = str(record.get("source_event") or "")
            if source:
                by_source.setdefault(source, []).append(record)
        missing = [
            draft["source_event"] for draft in drafts
            if draft["source_event"] not in by_source
        ]
        pending = [
            record["memory_id"]
            for draft in drafts
            for record in by_source.get(draft["source_event"], [])
            if record.get("validation") in (None, "pending")
        ]
        diagnostics: list[dict[str, Any]] = []
        if missing:
            diagnostics.append(_diagnostic(
                "memory_validation_candidates_missing",
                f"{len(missing)} evidence-derived memory source(s) need candidate "
                "records before close. Zero-memory waves remain valid when drafting "
                "finds no material source.",
                recovery_tools=["memory_propose"],
                recovery_usage=f"memory_propose(wave_id={wave_id!r}, mode='create')",
            ))
        if pending:
            diagnostics.append(_diagnostic(
                "memory_validation_required",
                f"{len(pending)} evidence-derived memory candidate(s) need focused "
                "agent validation before close: " + ", ".join(pending[:10]),
                recovery_tools=["memory_validate", "memory_search"],
                recovery_usage=(
                    "memory_validate(memory_id=<id>, verdict='promote|retain|"
                    "reject|rewrite', action_delta=..., rationale=..., "
                    "evidence_verified=True, current_target_verified=True, "
                    "canonical_overlap='none|supplements|duplicates')"
                ),
            ))
        return diagnostics
    except Exception as exc:
        return [_diagnostic(
            "memory_validation_check_failed",
            f"Memory validation readiness could not be established: {exc}",
            recovery_tools=["memory_propose", "wf_validate_docs"],
            recovery_usage=f"memory_propose(wave_id={wave_id!r}, mode='dry_run')",
        )]


def wf_close_wave_response(root: Path, wave_id: str, mode: str = "dry_run", cache: Optional[McpRepoCache] = None) -> dict[str, Any]:
    mode_s = "create" if (mode or "").strip().lower() == "apply" else (mode or "").strip().lower()
    _WAVE_CLOSE_VALID_MODES = ["dry_run", "create"]
    if mode_s not in {"dry_run", "create"}:
        return _response("error", {"wave_id": wave_id, "mode": mode, "valid_modes": _WAVE_CLOSE_VALID_MODES}, diagnostics=[_diagnostic("invalid_arguments", f"Unsupported mode '{mode}'. Valid modes: {_WAVE_CLOSE_VALID_MODES}.")], next_tools=["wf_help"], usage="wf_help()")
    wave_md = _find_wave_md(root, wave_id)
    if wave_md is None:
        return _response("error", {"wave_id": wave_id}, diagnostics=[_diagnostic("wave_not_found", f"No wave found matching '{wave_id}'.", recovery_tools=["wf_list_waves"], recovery_usage="wf_list_waves()")], next_tools=["wf_list_waves"], usage="wf_list_waves()")
    # Garden only runs on create — dry-run must stay read-only.
    garden_passed = True
    if mode_s == "create":
        garden_result = run_garden(root)
        garden_passed = garden_result["passed"]
    lint_result = run_validate(root)
    text = wave_md.read_text(encoding="utf-8")
    statuses = [status.lower() for status in _CHANGE_STATUS_PATTERN.findall(text)]
    open_statuses = {"stub", "planned", "ready", "active"}
    unresolved = [s for s in statuses if s in open_statuses]
    diagnostics: list[dict[str, Any]] = []
    diagnostics.extend(
        _review_evidence_diagnostics(
            text,
            root=root,
            wave_key=wave_md.parent.name,
            persist_adoption=mode_s == "create",
            closure=True,
            required_run_kind="initial_delivery",
        )
    )
    if not garden_passed:
        diagnostics.append(_diagnostic("docs_gardener_failed", "docs_gardener failed during close.", recovery_tools=["wf_garden_docs", "wf_validate_docs"], recovery_usage="wf_garden_docs(mode='run')"))
    if unresolved:
        diagnostics.append(_diagnostic("open_changes_remaining", f"Wave has unresolved change statuses: {', '.join(sorted(set(unresolved)))}.", recovery_tools=["wf_current_wave"], recovery_usage="wf_current_wave()"))
    if not _operator_signoff_present(text):
        diagnostics.append(
            _diagnostic(
                "missing_operator_signoff",
                (
                    "Operator review approval is required before closing this wave. "
                    "Add `operator-signoff: approved` to `## Review Evidence` in wave.md. "
                    "Approval is given by the operator asking to close the wave, or by the agent explicitly asking for approval."
                ),
                recovery_tools=["wf_review_wave"],
                recovery_usage=f"wf_review_wave(wave_id={wave_id!r})",
            )
        )
    # Merge lanes from wave.md Participants table and project-declared required_review_lanes
    wave_lanes = _extract_required_review_lanes(text)
    project_lanes = _read_project_required_review_lanes(root)
    required_lanes = list({*wave_lanes, *project_lanes})  # deduped, order doesn't matter here
    required_council_signoffs = _required_wave_council_signoffs(root, "close", wave_text=text)
    diagnostics.extend(
        _approval_evidence_diagnostics(
            text,
            ["operator-signoff", *required_lanes, *required_council_signoffs],
            root=root,
            wave_key=wave_md.parent.name,
        )
    )
    evidence_present = bool(_combined_review_evidence(text).strip())
    if required_lanes:
        if not evidence_present:
            diagnostics.append(
                _diagnostic(
                    "missing_signoff_evidence",
                    "Wave record needs a ## Review Evidence (or ## Review Signoff Evidence) section with per-lane signoffs.",
                    recovery_tools=["wf_review_wave"],
                    recovery_usage=f"wf_review_wave(wave_id={wave_id!r})",
                )
            )
        else:
            missing_lane = [l for l in required_lanes if not _lane_has_signoff_in_evidence(_combined_review_evidence(text), l)]
            if missing_lane:
                diagnostics.append(
                    _diagnostic(
                        "missing_required_lane",
                        f"Required review lanes without a signoff line in Review Evidence: {', '.join(missing_lane)}.",
                        recovery_tools=["wf_review_wave"],
                        recovery_usage=f"wf_review_wave(wave_id={wave_id!r})",
                    )
                )
    else:
        if not _review_evidence_has_any_signoff_line(text):
            diagnostics.append(
                _diagnostic(
                    "missing_signoff_evidence",
                    "Wave record needs ## Review Evidence (or ## Review Signoff Evidence) with at least one signoff line.",
                    recovery_tools=["wf_review_wave"],
                    recovery_usage=f"wf_review_wave(wave_id={wave_id!r})",
                )
            )
    if required_council_signoffs:
        missing_council = [
            signoff_key
            for signoff_key in required_council_signoffs
            if not _lane_has_signoff_in_evidence(_combined_review_evidence(text), signoff_key)
        ]
        if missing_council:
            diagnostics.append(
                _diagnostic(
                    "missing_wave_council_signoff",
                    (
                        "Required Wave Council signoff missing for close: "
                        f"{', '.join(missing_council)}. Record the signoff line(s) in `## Review Evidence` before attempting closure."
                    ),
                    recovery_tools=["wf_review_wave"],
                    recovery_usage=f"wf_review_wave(wave_id={wave_id!r})",
                )
            )
    if not lint_result["passed"]:
        diagnostics.extend([_diagnostic("docs_lint_error", err, recovery_tools=["wf_validate_docs"]) for err in lint_result["errors"]])
    # Wave 1p3rm (1p3rp) + 1p5pz: secrets gate — 'pending'/'suspected-secret' entries
    # hard-block until classified; 'confirmed-secret' entries do NOT block but are surfaced
    # as a non-blocking standing reminder (secrets_notice) on every close (success + error).
    canonical_wave_id_m = _WAVE_ID_PATTERN.search(text)
    canonical_wave_id = canonical_wave_id_m.group(1) if canonical_wave_id_m else wave_id
    diagnostics.extend(_memory_validation_diagnostics(root, canonical_wave_id))
    diagnostics.extend(_check_secrets_gate(root, canonical_wave_id))
    secrets_notice = _confirmed_secret_notice(root) or {}
    # Wave 1t3ek (1t230): retrieval-posture sensor at close — surfaced in DATA
    # (the secrets_notice pattern), never a diagnostic, because close hard-blocks
    # on any diagnostic and this advisory must never block by itself.
    try:
        _close_posture_gap = _retrieval_posture_gap(root, wave_md)
    except Exception:
        _close_posture_gap = None
    if _close_posture_gap is not None:
        secrets_notice = {**secrets_notice, "retrieval_posture_gap": _close_posture_gap}
    # Wave 1p31b (1p32k): close-time hard gate — every AC and task across admitted changes
    # must be `[x]` (done) or `[~]` (intentionally deferred). Silent `[ ]` items block close.
    silent_unchecked = _collect_silent_unchecked_items_for_close(wave_md, text)
    if silent_unchecked:
        # Build a structured, operator-readable message naming up to 10 items inline; counts
        # beyond that summarized. The diagnostic carries the full list in its data for tools.
        sample_lines: list[str] = []
        for item in silent_unchecked[:10]:
            tag = f"[{item['item_id']}]" if item["item_id"] else "[task]"
            sample_lines.append(f"  - {item['change_id']} {tag} {item['item_type']}: {item['item_text']}")
        more = f"\n  ...and {len(silent_unchecked) - 10} more" if len(silent_unchecked) > 10 else ""
        diagnostics.append(
            _diagnostic(
                "silent_unchecked_items_at_close",
                (
                    f"Wave close blocked: {len(silent_unchecked)} unchecked AC or task item(s) "
                    "across admitted changes must be marked `[x]` (completed) or `[~]` (intentionally deferred) before close. "
                    "Silent `[ ]` items are blocking findings per the close-time hard gate. "
                    f"See seed `170-plan-feature.prompt.md` for the `[~]` convention.\n{chr(10).join(sample_lines)}{more}"
                ),
                recovery_tools=["wf_current_wave", "wf_validate_docs"],
                recovery_usage="wf_current_wave()",
            )
        )
    # Gate close runs unconditionally so open gates are always reported (and closed in
    # create mode) even when other diagnostics cause an early return.
    gate_diagnostics = _force_gates_closed(root, mode_s)
    if diagnostics:
        return _response("error", {"wave_id": wave_id, "mode": mode_s, "lint_passed": lint_result["passed"], "garden_passed": garden_passed, "required_council_signoffs": required_council_signoffs, **secrets_notice}, diagnostics=diagnostics + gate_diagnostics, next_tools=["wf_validate_docs", "wf_current_wave"], usage="wf_validate_docs()")
    # Generate the wave summary from structured change doc fields (12sq4).
    wave_summary = _generate_wf_close_wave_summary(wave_id, text, wave_md)
    updated = False
    transitioned_to_closed = False
    handoff_rel = ""
    close_optimize: Optional[dict[str, Any]] = None
    memory_summary: dict[str, Any] = {}
    if mode_s == "create":
        status_match = _STATUS_PATTERN.search(text)
        if status_match and status_match.group(1) != "closed":
            import time
            # Summary write precedes status checkpoint (per 12sq4 AC risk note).
            text = _replace_wave_summary_section(text, wave_summary)
            text = text[:status_match.start(1)] + "closed" + text[status_match.end(1):]
            if "Completed At:" not in text:
                text = text.replace("## Wave Summary", f"Completed At: {time.strftime('%Y-%m-%d')}\n\n## Wave Summary", 1)
            try:
                text = _project_current_review_status(root, wave_md, text)
            except ValueError as exc:
                return _response(
                    "error",
                    {"wave_id": wave_id, "mode": mode_s},
                    diagnostics=[
                        _diagnostic("review_projection_failed", str(exc)),
                        *gate_diagnostics,
                    ],
                    next_tools=["wf_review_evidence", "wf_validate_docs"],
                )
            wave_md.write_text(text, encoding="utf-8")
            updated = True
            transitioned_to_closed = True
            handoff = root / "docs" / "agents" / "session-handoff.md"
            handoff.parent.mkdir(parents=True, exist_ok=True)
            prior = handoff.read_text(encoding="utf-8") if handoff.exists() else ""
            handoff.write_text(_update_handoff_wave_ref(prior, None), encoding="utf-8")
            handoff_rel = str(handoff.relative_to(root)).replace("\\", "/")
            if cache:
                cache.invalidate()
            # Wave 1rycf: interim bloat reclaim. Run BEFORE the close's own background refresh so the
            # index build lock is still free; the optimize is gated (only bloated tables), lock-aware
            # (skips if a build holds the lock), tier-1-only (never spawns a synchronous rebuild), and
            # fail-safe (never affects the close). Superseded later by the SQLite FTS5 migration.
            close_optimize = _maybe_optimize_index_on_close(root)
            refresh_paths: list[str | Path] = [wave_md]
            if handoff_rel:
                refresh_paths.append(handoff)
            _trigger_background_index_refresh_for_paths(root, refresh_paths)
            # Defensive fallback: the pre-close validation gate normally means
            # every source already has a disposition. If evidence changed after
            # the gate, create candidates only; never invent a semantic verdict.
            memory_summary = _auto_populate_memory_for_wave(root, wave_id)
    # Wave 1p601: refresh the codebase map at the close-wave lifecycle
    # checkpoint (fail-safe — never affects the close result).
    if mode_s == "create":
        _regenerate_codebase_map_safe(root)
    envelope = _response(
        "dry_run" if mode_s == "dry_run" else "ok",
        {"wave_id": wave_id, "mode": mode_s, "updated": updated, "transitioned_to_closed": transitioned_to_closed, "handoff_path": handoff_rel, "wave_summary": wave_summary,
         **({"index_optimize": close_optimize} if close_optimize else {}),
         **({"memory": memory_summary} if memory_summary else {}), **secrets_notice},
        diagnostics=gate_diagnostics if gate_diagnostics else None,
        next_tools=["wf_current_wave"],
        usage="wf_current_wave()",
    )
    return _attach_lint_to_response(envelope, root, mode_s)


def wf_reopen_wave_response(root: Path, wave_id: str) -> dict[str, Any]:
    wave_md = _find_wave_md(root, wave_id)
    if wave_md is None:
        return _response("error", {"wave_id": wave_id}, diagnostics=[_diagnostic("wave_not_found", f"No wave found matching '{wave_id}'.", recovery_tools=["wf_list_waves"], recovery_usage="wf_list_waves()")], next_tools=["wf_list_waves"], usage="wf_list_waves()")
    text = wave_md.read_text(encoding="utf-8")
    status_match = _STATUS_PATTERN.search(text)
    current_status = status_match.group(1).lower() if status_match else ""
    if current_status not in ("closed", "paused"):
        return _response("error", {"wave_id": wave_id, "current_status": current_status}, diagnostics=[_diagnostic("wave_not_closed", f"Wave '{wave_id}' has status '{current_status}' — only closed or paused waves can be reopened.", recovery_tools=["wf_current_wave"], recovery_usage="wf_current_wave()")], next_tools=["wf_current_wave"], usage="wf_current_wave()")
    # Wave 1p45l: reopening transitions the wave to `active` (OPEN), so it runs the single-OPEN
    # guard — at most one wave may be OPEN (active/implementing) at a time. (Previously unguarded:
    # a latent two-active-wave hole.)
    other_open = _find_other_active_wave(root, wave_md)
    if other_open is not None:
        return _response(
            "error",
            {"wave_id": wave_id, "current_status": current_status, "active_wave_id": other_open["wave_id"]},
            diagnostics=[_diagnostic(
                "another_wave_active",
                f"Wave {other_open['wave_id']!r} is already OPEN (active/implementing); only one wave may be OPEN at a time. "
                f"Pause it before reopening {wave_id!r}.",
                recovery_tools=["wf_pause_wave", "wf_current_wave"],
                recovery_usage=f"wf_pause_wave(wave_id={other_open['wave_id']!r}, mode='create')",
            )],
            next_tools=["wf_pause_wave", "wf_current_wave"],
            usage=f"wf_pause_wave(wave_id={other_open['wave_id']!r}, mode='create')",
        )
    # Set status back to active
    text = text[:status_match.start(1)] + "active" + text[status_match.end(1):]
    # Remove any "Completed At: ..." line stamped by wf_close_wave
    text = re.sub(r"^Completed At:.*\n?", "", text, flags=re.MULTILINE)
    wave_md.write_text(text, encoding="utf-8")
    _trigger_background_index_refresh_for_paths(root, [wave_md])
    envelope = _response("ok", {"wave_id": wave_id, "status": "active", "updated": True}, next_tools=["wf_current_wave", "wf_review_wave"], usage="wf_current_wave()")
    # wf_reopen_wave has no `mode` param — it always writes. Pass "create" so the
    # lint integration fires.
    return _attach_lint_to_response(envelope, root, "create")


