_EXT_TO_LANG: dict[str, str] = {
    ".py": "python", ".js": "javascript", ".ts": "typescript",
    ".jsx": "javascript", ".tsx": "typescript", ".mjs": "javascript", ".cjs": "javascript",
    ".go": "go", ".rs": "rust", ".java": "java", ".rb": "ruby",
    ".cs": "csharp", ".cpp": "cpp", ".hpp": "cpp", ".c": "c", ".h": "c",
    ".sh": "shell", ".bash": "shell", ".zsh": "shell", ".fish": "fish",
    ".kt": "kotlin", ".kts": "kotlin", ".groovy": "groovy", ".scala": "scala",
    ".css": "css", ".scss": "scss",
    ".sql": "sql", ".psql": "sql", ".pgsql": "sql", ".ddl": "sql", ".dml": "sql", ".tsql": "sql", ".hql": "sql", ".xml": "xml",
    ".html": "html", ".htm": "html",
    ".swift": "swift",
    ".json": "json", ".jsonc": "json",
    ".toml": "toml", ".yaml": "yaml", ".yml": "yaml",
}

# Reverse map: language name → sorted list of extensions (without leading dot).
_LANG_TO_EXTS: dict[str, list[str]] = {}
for _ext, _lang in _EXT_TO_LANG.items():
    _LANG_TO_EXTS.setdefault(_lang, []).append(_ext.lstrip("."))
_LANG_TO_EXTS = {k: sorted(v) for k, v in _LANG_TO_EXTS.items()}

# Category map: category name → frozenset of canonical language names.
# Categories are intent-based groupings; a language may appear in multiple categories.
# "java" covers the JVM family; "sparksql" is an alias for sql (SparkSQL is SQL syntax).
_LANG_CATEGORIES: dict[str, frozenset] = {
    "java":     frozenset({"java", "kotlin", "scala", "groovy"}),
    "web":      frozenset({"typescript", "javascript", "html", "css", "scss"}),
    "systems":  frozenset({"c", "cpp", "rust", "go"}),
    "data":     frozenset({"sql"}),
    "sparksql": frozenset({"sql"}),
    "dotnet":   frozenset({"csharp"}),
    "script":   frozenset({"python", "ruby", "shell", "fish"}),
}

_TREE_SITTER_DEFINITION_LANGS = {"javascript", "typescript", "java", "csharp", "kotlin", "sql"}
_TREE_SITTER_REFERENCE_LANGS = {"javascript", "typescript", "java", "csharp", "kotlin", "sql"}
_CHUNKER_MOD = None

_SUPPORTED_DEFINITION_LANGS = {
    "python", "javascript", "typescript", "go", "rust", "java", "csharp", "kotlin", "swift", "sql",
    "css", "scss",
}
_SUPPORTED_REFERENCE_LANGS = set(_LANG_TO_EXTS)

_DOC_REFERENCE_EXTS = {".md", ".markdown", ".mdx", ".rst", ".txt", ".adoc", ".asciidoc"}
_TEST_REFERENCE_PATH_RE = re.compile(r"(^|/)(tests?|__tests__)(/|$)|(^|/)(test|spec)[^/]*\.(py|js|jsx|ts|tsx|java|cs|go|rs|kt|swift)$|(\.test|\.spec)\.[^.]+$", re.IGNORECASE)

_TS_CALL_PARENT_TYPES: dict[str, set[str]] = {
    "javascript": {"call_expression", "new_expression"},
    "typescript": {"call_expression", "new_expression"},
    # Java method references (`Foo::bar`, `this::bar`) classify as call sites
    # so the call-site scanner in code_callhierarchy attaches line+snippet to
    # incoming entries that only reference the target via method references
    # (wave 130rj / 130r7 — field feedback §1.2 reproduced 2026-05-31).
    "java": {"method_invocation", "object_creation_expression", "method_reference"},
    "csharp": {"invocation_expression", "object_creation_expression"},
    # Kotlin callable references (`String::length`, `::myFn`, `this::handle`)
    # are the Kotlin analogue of Java method references — classify as call
    # sites for the same reason (wave 130rj — 130tc Kotlin enablement).
    "kotlin": {"call_expression", "callable_reference"},
    "sql": {"function_call", "call", "call_expression", "routine_invocation"},
}

_TS_IMPORT_PARENT_TYPES: dict[str, set[str]] = {
    "javascript": {"import_statement", "import_clause", "import_specifier", "named_imports", "namespace_import"},
    "typescript": {"import_statement", "import_clause", "import_specifier", "named_imports", "namespace_import"},
    "java": {"import_declaration"},
    "csharp": {"using_directive"},
    # Kotlin import grammar: `import_header` wraps `identifier` (with optional alias) (wave 130tc).
    "kotlin": {"import_header"},
    "sql": {"with_clause"},
}

_IDENTIFIER_SYMBOL_RE = re.compile(r"^[A-Za-z_]\w*$")


def _sql_symbol_variants(symbol: str) -> set[str]:
    symbol_s = symbol.strip()
    variants = {symbol_s}
    if "." in symbol_s:
        variants.add(symbol_s.rsplit(".", 1)[-1])
    return variants


def _sql_symbol_matches(candidate: str, symbol: str) -> bool:
    candidate_s = candidate.strip()
    symbol_s = symbol.strip()
    if candidate_s == symbol_s:
        return True
    candidate_base = candidate_s.rsplit(".", 1)[-1]
    symbol_base = symbol_s.rsplit(".", 1)[-1]
    if candidate_base != symbol_base:
        return False
    candidate_qualified = "." in candidate_s
    symbol_qualified = "." in symbol_s
    return candidate_qualified != symbol_qualified


def _sql_schema_retry_symbol(symbol: str) -> Optional[str]:
    symbol_s = symbol.strip()
    if "." not in symbol_s:
        return None
    retry = symbol_s.rsplit(".", 1)[-1].strip()
    return retry if retry and retry != symbol_s else None


def _sql_schema_doc_mention_refs(root: Path, symbol: str) -> list[dict[str, Any]]:
    """Return doc/mention hits for a schema-qualified SQL symbol using the bare name."""
    retry_symbol = _sql_schema_retry_symbol(symbol)
    if retry_symbol is None:
        return []
    refs: list[dict[str, Any]] = []
    for ref in _non_python_references(root, retry_symbol):
        if ref.get("reference_kind") in {"docs", "mention"}:
            ref["sql_query_symbol"] = retry_symbol
            refs.append(ref)
    return refs

# Regex-based structural definition patterns for languages where we have a
# reliable top-level symbol shape but no AST/LSP navigation in the MCP layer.
_DEFINITION_PATTERNS: dict[str, list[tuple[str, re.Pattern]]] = {
    "javascript": [
        ("function", re.compile(r"^(?:export\s+)?(?:default\s+)?function\s+(\w+)")),
        ("class", re.compile(r"^(?:export\s+)?(?:default\s+)?class\s+(\w+)")),
        ("variable", re.compile(r"^(?:export\s+)?(?:const|let|var)\s+(\w+)\s*=")),
    ],
    "typescript": [
        ("function", re.compile(r"^(?:export\s+)?(?:default\s+)?function\s+(\w+)")),
        ("class", re.compile(r"^(?:export\s+)?(?:default\s+)?class\s+(\w+)")),
        ("interface", re.compile(r"^(?:export\s+)?interface\s+(\w+)")),
        ("type", re.compile(r"^(?:export\s+)?type\s+(\w+)")),
        ("enum", re.compile(r"^(?:export\s+)?enum\s+(\w+)")),
        ("variable", re.compile(r"^(?:export\s+)?(?:const|let|var)\s+(\w+)\s*=")),
    ],
    "go": [
        ("function", re.compile(r"^func\s+(?:\([^)]*\)\s*)?(\w+)\s*\(")),
        ("type", re.compile(r"^type\s+(\w+)")),
        ("variable", re.compile(r"^var\s+(\w+)")),
        ("const", re.compile(r"^const\s+(\w+)")),
    ],
    "rust": [
        ("function", re.compile(r"^(?:pub\s+)?fn\s+(\w+)")),
        ("struct", re.compile(r"^(?:pub\s+)?struct\s+(\w+)")),
        ("enum", re.compile(r"^(?:pub\s+)?enum\s+(\w+)")),
        ("trait", re.compile(r"^(?:pub\s+)?trait\s+(\w+)")),
        ("type", re.compile(r"^(?:pub\s+)?type\s+(\w+)")),
        ("const", re.compile(r"^(?:pub\s+)?const\s+(\w+)")),
    ],
    "java": [
        ("class", re.compile(r"^(?:public|protected|private)?\s*(?:abstract\s+|final\s+)?class\s+(\w+)")),
        ("interface", re.compile(r"^(?:public|protected|private)?\s*interface\s+(\w+)")),
        ("enum", re.compile(r"^(?:public|protected|private)?\s*enum\s+(\w+)")),
        ("method", re.compile(r"^(?:public|protected|private)\s+(?:static\s+)?[\w<>\[\], ?]+\s+(\w+)\s*\(")),
    ],
    "csharp": [
        ("class", re.compile(r"^(?:public|internal|protected|private)?\s*(?:abstract\s+|sealed\s+)?(?:partial\s+)?class\s+(\w+)")),
        ("interface", re.compile(r"^(?:public|internal|protected|private)?\s*interface\s+(\w+)")),
        ("enum", re.compile(r"^(?:public|internal|protected|private)?\s*enum\s+(\w+)")),
        ("struct", re.compile(r"^(?:public|internal|protected|private)?\s*struct\s+(\w+)")),
        ("record", re.compile(r"^(?:public|internal|protected|private)?\s*record\s+(\w+)")),
        ("method", re.compile(r"^(?:public|protected|private|internal)\s+(?:static\s+)?[\w<>\[\], ?.]+\s+(\w+)\s*\(")),
    ],
    "kotlin": [
        ("function", re.compile(r"^(?:public|private|internal|protected)?\s*fun\s+(\w+)")),
        ("class", re.compile(r"^(?:data\s+)?class\s+(\w+)")),
        ("object", re.compile(r"^object\s+(\w+)")),
        ("interface", re.compile(r"^interface\s+(\w+)")),
        ("enum", re.compile(r"^enum\s+class\s+(\w+)")),
    ],
    "swift": [
        ("function", re.compile(r"^(?:public|internal|private|open)?\s*func\s+(\w+)")),
        ("class", re.compile(r"^(?:public|internal|private|open)?\s*class\s+(\w+)")),
        ("struct", re.compile(r"^(?:public|internal|private|open)?\s*struct\s+(\w+)")),
        ("enum", re.compile(r"^(?:public|internal|private|open)?\s*enum\s+(\w+)")),
        ("protocol", re.compile(r"^(?:public|internal|private|open)?\s*protocol\s+(\w+)")),
    ],
}


# CSS/SCSS definition patterns.  Class and ID selectors can appear anywhere in
# a selector string (e.g. `html[data-theme="dark"] .classname { ... }`), so
# these use finditer on rule-opening lines rather than match() at line start.
_CSS_CLASS_RE    = re.compile(r"(?<![.\w#])\.(-?[a-zA-Z_][a-zA-Z0-9_-]*)")
_CSS_ID_RE       = re.compile(r"(?<![.\w])#([a-zA-Z_][a-zA-Z0-9_-]*)")
_CSS_PROP_RE     = re.compile(r"^--([\w-]+)\s*:")
_CSS_KEYFRAME_RE = re.compile(r"^@keyframes\s+([\w-]+)")
_CSS_MIXIN_RE    = re.compile(r"^@(?:mixin|function)\s+([\w-]+)")  # SCSS


def _detect_language(path: str) -> str:
    ext = Path(path).suffix.lower()
    return _EXT_TO_LANG.get(ext, "unknown")


def _get_chunker_module():
    """Load chunker.py lazily for tree-sitter-backed navigation."""
    global _CHUNKER_MOD
    if _CHUNKER_MOD is not None:
        return _CHUNKER_MOD
    chunker_path = Path(__file__).resolve().parent / "chunker.py"
    script_dir = str(chunker_path.parent)
    added = False
    if script_dir not in sys.path:
        sys.path.insert(0, script_dir)
        added = True
    try:
        spec = importlib.util.spec_from_file_location("wf_server_chunker", chunker_path)
        if spec is None or spec.loader is None:
            raise ImportError(f"Unable to load chunker module from {chunker_path}")
        mod = importlib.util.module_from_spec(spec)
        sys.modules["wf_server_chunker"] = mod
        spec.loader.exec_module(mod)
        _CHUNKER_MOD = mod
        return mod
    finally:
        if added:
            with contextlib.suppress(ValueError):
                sys.path.remove(script_dir)


def _symbol_search_pattern(symbol: str) -> re.Pattern:
    if _IDENTIFIER_SYMBOL_RE.match(symbol):
        return re.compile(r"\b" + re.escape(symbol) + r"\b")
    return re.compile(re.escape(symbol))


def _definition_match_kind(name: str, symbol: str) -> str:
    return "exact" if name == symbol else "partial"


def _definition_sort_key(defn: dict[str, Any], symbol: str) -> tuple[int, int, int, int, str, int]:
    match_rank = 0 if str(defn.get("name", "")) == symbol else 1
    method_rank = {"ast": 0, "treesitter": 1, "regex": 2, "keyword_fallback": 3}.get(str(defn.get("method", "")), 4)
    language_rank = 0 if str(defn.get("language", "")) == "python" else 1
    kind_rank = {"class": 0, "interface": 1, "enum": 2, "struct": 3, "record": 4, "method": 5, "function": 6, "variable": 7, "symbol": 8}.get(str(defn.get("kind", "symbol")), 9)
    return (
        match_rank,
        method_rank,
        language_rank,
        kind_rank,
        str(defn.get("path", "")),
        int(defn.get("line", 0) or 0),
    )


def _python_definitions(
    root: Path,
    symbol: str,
    *,
    restrict_files: frozenset[str] | None = None,
) -> list[dict[str, Any]]:
    """Find function/class definitions matching *symbol* in Python files via AST.

    When ``restrict_files`` is non-None, the repo walk is skipped entirely — file
    paths are constructed directly from the restriction set (wave 12xr3, 1301h).
    This turns 10s+ cold walks into <50ms direct reads on the common path.
    """
    import ast as _ast
    results: list[dict[str, Any]] = []
    root_r = root.resolve()
    if restrict_files is not None:
        files: Iterable[Path] = (root_r / rel for rel in restrict_files)
    else:
        files = _walk_repo_for_navigation(root)
    for p in files:
        if p.suffix.lower() != ".py":
            continue
        try:
            source = p.read_text(encoding="utf-8", errors="replace")
            tree = _ast.parse(source, filename=str(p))
        except (SyntaxError, OSError):
            continue
        rel = str(p.resolve().relative_to(root_r)).replace("\\", "/")
        for node in _ast.walk(tree):
            name = None
            if isinstance(node, (_ast.FunctionDef, _ast.AsyncFunctionDef, _ast.ClassDef)):
                name = node.name
            if name and (name == symbol or symbol in name):
                results.append({
                    "path": rel,
                    "line": node.lineno,
                    "kind": type(node).__name__.lower().replace("asyncfunctiondef", "async_function").replace("functiondef", "function").replace("classdef", "class"),
                    "name": name,
                    "language": "python",
                    "method": "ast",
                    "match_kind": _definition_match_kind(name, symbol),
                })
    return results


def _python_reference_call_sites(root: Path, symbol: str, *, restrict_files: frozenset[str] | None = None, _files: list | None = None) -> list[dict[str, Any]]:
    """Find structural Python call sites for *symbol* via AST."""
    import ast as _ast
    results: list[dict[str, Any]] = []
    root_r = root.resolve()
    for p in (_files if _files is not None else _walk_repo_for_navigation(root)):
        if p.suffix.lower() != ".py":
            continue
        rel = str(p.resolve().relative_to(root_r)).replace("\\", "/")
        if restrict_files is not None and rel not in restrict_files:
            continue
        try:
            source = p.read_text(encoding="utf-8", errors="replace")
            tree = _ast.parse(source, filename=str(p))
        except (SyntaxError, OSError):
            continue
        lines = source.splitlines()
        for node in _ast.walk(tree):
            if not isinstance(node, _ast.Call):
                continue
            func = node.func
            matched = False
            if isinstance(func, _ast.Name):
                matched = func.id == symbol
            elif isinstance(func, _ast.Attribute):
                matched = func.attr == symbol
            if not matched:
                continue
            line = getattr(node, "lineno", 0)
            if line <= 0 or line > len(lines):
                continue
            results.append({
                "path": rel,
                "line": line,
                "snippet": lines[line - 1].rstrip(),
                "language": "python",
                "method": "ast",
                "reference_kind": "call_sites",
            })
    return results


def _python_references(root: Path, symbol: str, *, restrict_files: frozenset[str] | None = None, _files: list | None = None) -> list[dict[str, Any]]:
    """Find references to *symbol* in Python files via AST call-site detection plus text fallback."""
    results: list[dict[str, Any]] = []
    root_r = root.resolve()
    pattern = _symbol_search_pattern(symbol)
    call_sites_by_path: dict[str, set[int]] = {}
    for ref in _python_reference_call_sites(root, symbol, restrict_files=restrict_files, _files=_files):
        ref["reference_kind"] = "call_sites"
        ref["method"] = "ast"
        results.append(ref)
        call_sites_by_path.setdefault(ref["path"], set()).add(ref["line"])
    for p in (_files if _files is not None else _walk_repo_for_navigation(root)):
        if p.suffix.lower() != ".py":
            continue
        rel = str(p.resolve().relative_to(root_r)).replace("\\", "/")
        if restrict_files is not None and rel not in restrict_files:
            continue
        try:
            source = p.read_text(encoding="utf-8", errors="replace")
        except OSError:
            continue
        call_site_lines = call_sites_by_path.get(rel, set())
        for lineno, line in enumerate(source.splitlines(), 1):
            if pattern.search(line):
                if lineno in call_site_lines:
                    continue
                results.append({
                    "path": rel,
                    "line": lineno,
                    "snippet": line.rstrip(),
                    "language": "python",
                    "method": "text",
                    "reference_kind": _text_reference_kind(rel, line, symbol),
                })
    return results


def _treesitter_definition_results(
    root: Path,
    symbol: str,
    *,
    restrict_files: frozenset[str] | None = None,
) -> list[dict[str, Any]]:
    """Find definitions in tree-sitter-backed languages using chunker parse helpers.

    When ``restrict_files`` is non-None, the repo walk is skipped — file paths are
    constructed directly from the restriction set.
    """
    chunker = _get_chunker_module()
    by_language = {
        "javascript": chunker.chunk_js_ts_treesitter,
        "typescript": chunker.chunk_js_ts_treesitter,
        "java": chunker.chunk_java_treesitter,
        "csharp": chunker.chunk_csharp_treesitter,
        "sql": chunker.chunk_sql,
    }
    results: list[dict[str, Any]] = []
    root_r = root.resolve()
    if restrict_files is not None:
        files: Iterable[Path] = (root_r / rel for rel in restrict_files)
    else:
        files = _walk_repo_for_navigation(root)
    for p in files:
        rel = str(p.resolve().relative_to(root_r)).replace("\\", "/")
        lang = _detect_language(rel)
        if lang not in _TREE_SITTER_DEFINITION_LANGS:
            continue
        chunk_fn = by_language.get(lang)
        if chunk_fn is None:
            continue
        try:
            source = p.read_text(encoding="utf-8", errors="replace")
            chunks = chunk_fn(source, rel)
        except Exception:
            continue
        if not chunks:
            continue
        for chunk in chunks:
            if getattr(chunk, "kind", None) != "code":
                continue
            chunk_id = getattr(chunk, "id", "")
            if not chunk_id.startswith(f"{rel}::"):
                continue
            local_id = chunk_id.split("::", 1)[1]
            section = getattr(chunk, "section", "")
            line = getattr(chunk, "lines", (1, 1))[0]
            match_name = local_id
            kind = "symbol"
            if local_id.endswith(".__decl__"):
                match_name = local_id[: -len(".__decl__")]
                if lang in {"java", "csharp"}:
                    kind = "class"
                elif lang == "sql":
                    kind = "object"
                else:
                    kind = "class"
            elif "." in local_id:
                match_name = local_id.split(".")[-1]
                kind = "method"
            else:
                kind = "object" if lang == "sql" else "function"
            if (lang == "sql" and _sql_symbol_matches(match_name, symbol)) or match_name == symbol or symbol in match_name:
                results.append({
                    "path": rel,
                    "line": line,
                    "kind": kind,
                    "name": match_name,
                    "language": lang,
                    "method": "treesitter",
                    "section": section,
                    "match_kind": _definition_match_kind(match_name, symbol),
                })
    return results


_TS_IDENTIFIER_NODE_TYPES: dict[str, set[str]] = {
    "javascript": {"identifier", "property_identifier"},
    "typescript": {"identifier", "property_identifier", "type_identifier"},
    "java": {"identifier"},
    "csharp": {"identifier"},
    # Kotlin uses bare `identifier` for symbol references; the grammar does not
    # split into property_identifier / type_identifier the way TS does (wave 130tc).
    "kotlin": {"identifier"},
    "sql": {"identifier", "bare_identifier", "quoted_identifier", "object_reference", "column_reference"},
}

_TS_DEFINITION_PARENT_TYPES: dict[str, set[str]] = {
    "javascript": {
        "function_declaration", "generator_function_declaration", "class_declaration",
        "method_definition", "variable_declarator",
    },
    "typescript": {
        "function_declaration", "generator_function_declaration", "class_declaration",
        "method_definition", "variable_declarator", "interface_declaration",
        "type_alias_declaration", "enum_declaration",
    },
    "java": {
        "class_declaration", "interface_declaration", "enum_declaration",
        "annotation_type_declaration", "method_declaration", "constructor_declaration",
    },
    "csharp": {
        "class_declaration", "interface_declaration", "struct_declaration",
        "enum_declaration", "record_declaration", "method_declaration",
        "constructor_declaration", "operator_declaration",
    },
    # Kotlin definition parents (wave 130tc). `property_declaration` is left
    # OUT — local `val`/`var` shouldn't be classified as a definition for
    # caller/callee navigation (matches the variable-binding pattern handled
    # in wave 130qf for the graph extractor side).
    "kotlin": {
        "class_declaration", "object_declaration", "interface_declaration",
        "enum_class_body", "function_declaration", "secondary_constructor",
        "primary_constructor",
    },
}


def _treesitter_references(root: Path, symbol: str, *, restrict_files: frozenset[str] | None = None, _files: list | None = None) -> list[dict[str, Any]]:
    """Find identifier references in tree-sitter-backed languages."""
    chunker = _get_chunker_module()
    results: list[dict[str, Any]] = []
    root_r = root.resolve()
    for p in (_files if _files is not None else _walk_repo_for_navigation(root)):
        rel = str(p.resolve().relative_to(root_r)).replace("\\", "/")
        lang = _detect_language(rel)
        if lang not in _TREE_SITTER_REFERENCE_LANGS:
            continue
        if restrict_files is not None and rel not in restrict_files:
            continue
        try:
            source = p.read_text(encoding="utf-8", errors="replace")
            # Wave 1p3hd: shared cache — references queries reuse the parsed
            # tree if `code_outline` / `code_hover` / `code_read` structural
            # touched the same file earlier in this session.
            tree = _cached_ts_parse(p.resolve(), lang, source)
        except Exception:
            continue
        if tree is None:
            continue
        source_lines = source.splitlines()
        id_types = _TS_IDENTIFIER_NODE_TYPES.get(lang, {"identifier"})
        def_parents = _TS_DEFINITION_PARENT_TYPES.get(lang, set())
        stack = [tree.root_node]
        while stack:
            node = stack.pop()
            if getattr(node, "type", "") in id_types:
                text = source_lines[node.start_point[0]][node.start_point[1]:node.end_point[1]]
                if (lang == "sql" and _sql_symbol_matches(text, symbol)) or text == symbol:
                    line = node.start_point[0] + 1
                    snippet = source_lines[node.start_point[0]].rstrip()
                    parent = getattr(node, "parent", None)
                    method = "treesitter_reference"
                    if parent is not None and getattr(parent, "type", "") in def_parents:
                        method = "treesitter_definition_reference"
                    results.append({
                        "path": rel,
                        "line": line,
                        "snippet": snippet,
                        "language": lang,
                        "method": method,
                        "reference_kind": _tree_sitter_reference_kind(lang, node, symbol, source_lines),
                    })
            children = list(getattr(node, "children", []) or [])
            stack.extend(reversed(children))
    return results


def _regex_definitions(
    root: Path,
    symbol: str,
    *,
    restrict_files: frozenset[str] | None = None,
) -> list[dict[str, Any]]:
    """Find structural definitions in supported languages via regex (non-AST path).

    When ``restrict_files`` is non-None, the repo walk is skipped — file paths are
    constructed directly from the restriction set.
    """
    results: list[dict[str, Any]] = []
    root_r = root.resolve()
    if restrict_files is not None:
        files: Iterable[Path] = (root_r / rel for rel in restrict_files)
    else:
        files = _walk_repo_for_navigation(root)
    for p in files:
        rel = str(p.resolve().relative_to(root_r)).replace("\\", "/")
        lang = _detect_language(str(p))
        patterns = _DEFINITION_PATTERNS.get(lang)
        if not patterns:
            continue
        try:
            source = p.read_text(encoding="utf-8", errors="replace")
        except OSError:
            continue
        for lineno, line in enumerate(source.splitlines(), 1):
            stripped = line.strip()
            for kind, pattern in patterns:
                match = pattern.match(stripped)
                if not match:
                    continue
                name = match.group(1)
                if name == symbol or symbol in name:
                    results.append({
                        "path": rel,
                        "line": lineno,
                        "kind": kind,
                        "name": name,
                        "language": lang,
                        "method": "regex",
                        "match_kind": _definition_match_kind(name, symbol),
                    })
                break
    return results


def _css_definitions(
    root: Path,
    symbol: str,
    *,
    restrict_files: frozenset[str] | None = None,
) -> list[dict[str, Any]]:
    """Find CSS/SCSS class, ID, custom-property, keyframe, and mixin definitions.

    When ``restrict_files`` is non-None, the repo walk is skipped — file paths are
    constructed directly from the restriction set.
    """
    results: list[dict[str, Any]] = []
    root_r = root.resolve()
    structural_patterns = (
        ("custom-property", _CSS_PROP_RE),
        ("keyframes",       _CSS_KEYFRAME_RE),
        ("mixin",           _CSS_MIXIN_RE),
    )
    if restrict_files is not None:
        files: Iterable[Path] = (root_r / rel for rel in restrict_files)
    else:
        files = _walk_repo_for_navigation(root)
    for p in files:
        rel = str(p.resolve().relative_to(root_r)).replace("\\", "/")
        lang = _detect_language(str(p))
        if lang not in {"css", "scss"}:
            continue
        try:
            source = p.read_text(encoding="utf-8", errors="replace")
        except OSError:
            continue
        for lineno, line in enumerate(source.splitlines(), 1):
            stripped = line.strip()
            if not stripped or stripped.startswith("//") or stripped.startswith("/*"):
                continue
            # Custom property / @keyframes / @mixin — anchored at line start
            matched_structural = False
            for kind, pat in structural_patterns:
                m = pat.match(stripped)
                if m:
                    matched_structural = True
                    name = m.group(1)
                    if name == symbol or symbol in name:
                        results.append({
                            "path": rel, "line": lineno, "kind": kind, "name": name,
                            "language": lang, "method": "regex",
                            "match_kind": _definition_match_kind(name, symbol),
                        })
                    break
            if matched_structural:
                continue
            # Class and ID selectors — only on lines that open a rule block
            if "{" not in stripped:
                continue
            for kind, pat in (("class", _CSS_CLASS_RE), ("id", _CSS_ID_RE)):
                for m in pat.finditer(stripped):
                    name = m.group(1)
                    if name == symbol or symbol in name:
                        results.append({
                            "path": rel, "line": lineno, "kind": kind, "name": name,
                            "language": lang, "method": "regex",
                            "match_kind": _definition_match_kind(name, symbol),
                        })
                        break
    return results


def _non_python_references(root: Path, symbol: str, *, restrict_files: frozenset[str] | None = None, _files: list | None = None) -> list[dict[str, Any]]:
    """Find references to *symbol* across non-AST-parsed files via text search."""
    results: list[dict[str, Any]] = []
    root_r = root.resolve()
    pattern = _symbol_search_pattern(symbol)
    sql_variants = _sql_symbol_variants(symbol) if "." in symbol else {symbol}
    for p in (_files if _files is not None else _walk_repo_for_navigation(root)):
        rel = str(p.resolve().relative_to(root_r)).replace("\\", "/")
        lang = _detect_language(rel)
        if lang == "python":
            continue
        if restrict_files is not None and rel not in restrict_files:
            continue
        try:
            source = p.read_text(encoding="utf-8", errors="replace")
        except OSError:
            continue
        for lineno, line in enumerate(source.splitlines(), 1):
            if lang == "sql" and sql_variants:
                matched = any(
                    re.search(rf"(?<!\w){re.escape(variant)}(?!\w)", line)
                    for variant in sql_variants
                )
            else:
                matched = bool(pattern.search(line))
            if matched:
                results.append({
                    "path": rel,
                    "line": lineno,
                    "snippet": line.rstrip(),
                    "language": lang,
                    "method": "text",
                    "reference_kind": _text_reference_kind(rel, line, symbol),
                })
    return results


_KEYWORD_FALLBACK_RESULT_CAP = 50


def _keyword_fallback_definitions(root: Path, symbol: str) -> list[dict[str, Any]]:
    """Broad keyword fallback for unsupported or unmatched languages."""
    results = []
    root_r = root.resolve()
    pattern = _symbol_search_pattern(symbol)
    for p in _walk_repo_for_navigation(root):
        if len(results) >= _KEYWORD_FALLBACK_RESULT_CAP:
            break
        try:
            source = p.read_text(encoding="utf-8", errors="replace")
        except OSError:
            continue
        rel = str(p.resolve().relative_to(root_r)).replace("\\", "/")
        for lineno, line in enumerate(source.splitlines(), 1):
            if pattern.search(line):
                results.append({
                    "path": rel,
                    "line": lineno,
                    "snippet": line.rstrip(),
                    "language": _detect_language(rel),
                    "method": "keyword_fallback",
                    "match_kind": "exact" if pattern.search(line) and re.search(rf"\b{re.escape(symbol)}\b", line) else "partial",
                })
                if len(results) >= _KEYWORD_FALLBACK_RESULT_CAP:
                    break
    return results


def _dedupe_navigation_results(results: list[dict[str, Any]], key_fields: tuple[str, ...]) -> list[dict[str, Any]]:
    """Deduplicate navigation hits while preserving the earliest/strongest entry order."""
    deduped: list[dict[str, Any]] = []
    seen: set[tuple[Any, ...]] = set()
    for item in results:
        key = tuple(item.get(field) for field in key_fields)
        if key in seen:
            continue
        seen.add(key)
        deduped.append(item)
    return deduped


def _reference_counts(refs: list[dict[str, Any]]) -> dict[str, int]:
    counts = {"call_sites": 0, "other": 0, "docs": 0, "tests": 0}
    for ref in refs:
        counts[_reference_bucket(str(ref.get("reference_bucket", ref.get("reference_kind", "other"))))] += 1
    return counts


def _is_test_reference_path(rel_path: str) -> bool:
    rel = rel_path.replace("\\", "/").lower()
    return bool(_TEST_REFERENCE_PATH_RE.search(rel))


def _is_doc_reference_path(rel_path: str) -> bool:
    rel = rel_path.replace("\\", "/").lower()
    return rel.startswith("docs/") or "/docs/" in rel or Path(rel).suffix.lower() in _DOC_REFERENCE_EXTS


def _text_reference_kind(path: str, line: str, symbol: str) -> str:
    if _is_test_reference_path(path):
        return "tests"
    if _is_doc_reference_path(path):
        return "docs"
    stripped = line.strip()
    if not stripped:
        return "mention"
    if stripped.startswith(("import ", "from ", "export ", "using ", "package ")):
        return "import"
    if re.match(rf"^(?:def|class|func|function|const|let|var|type|interface|enum|record|struct)\s+{re.escape(symbol)}\b", stripped):
        return "definition"
    if re.match(rf"^(?:public|private|protected|internal|static|final|abstract|sealed|export)\b", stripped) and symbol in stripped:
        return "definition"
    if re.search(rf"\b{re.escape(symbol)}\s*\(", line):
        return "call_sites"
    if re.search(rf"\b{re.escape(symbol)}\b", line):
        return "mention"
    return "mention"


def _tree_sitter_reference_kind(lang: str, node: Any, symbol: str, source_lines: list[str]) -> str:
    if lang == "sql":
        return _sql_tree_sitter_reference_kind(node, symbol, source_lines)
    path = getattr(node, "parent", None)
    ancestor = path
    depth = 0
    while ancestor is not None and depth < 4:
        if getattr(ancestor, "type", "") in _TS_CALL_PARENT_TYPES.get(lang, set()):
            return "call_sites"
        ancestor = getattr(ancestor, "parent", None)
        depth += 1
    ancestor = path
    depth = 0
    while ancestor is not None and depth < 4:
        if getattr(ancestor, "type", "") in _TS_IMPORT_PARENT_TYPES.get(lang, set()):
            return "import"
        ancestor = getattr(ancestor, "parent", None)
        depth += 1
    if path is not None and getattr(path, "type", "") in _TS_DEFINITION_PARENT_TYPES.get(lang, set()):
        return "definition"
    line_idx = getattr(node, "start_point", (0, 0))[0]
    if 0 <= line_idx < len(source_lines):
        return _text_reference_kind("", source_lines[line_idx], symbol)
    return "mention"


def _sql_tree_sitter_reference_kind(node: Any, symbol: str, source_lines: list[str]) -> str:
    ancestor = getattr(node, "parent", None)
    depth = 0
    while ancestor is not None and depth < 4:
        ancestor_type = getattr(ancestor, "type", "").lower()
        if any(token in ancestor_type for token in ("call", "function", "routine")):
            return "call_sites"
        if any(token in ancestor_type for token in ("create", "alter", "drop", "declare", "definition", "table", "view", "procedure", "index", "schema", "trigger", "type")):
            return "definition"
        ancestor = getattr(ancestor, "parent", None)
        depth += 1
    line_idx = getattr(node, "start_point", (0, 0))[0]
    if 0 <= line_idx < len(source_lines):
        line = source_lines[line_idx]
        stripped = line.strip()
        if re.match(rf"^(?:CREATE|ALTER|DROP)\b.*\b{re.escape(symbol)}\b", stripped, re.IGNORECASE):
            return "definition"
        if re.search(rf"\b{re.escape(symbol)}\s*\(", line):
            return "call_sites"
        if re.search(rf"\b{re.escape(symbol)}\b", line):
            return "mention"
    return "mention"


def _reference_bucket(kind: str) -> str:
    if kind == "call_sites":
        return "call_sites"
    if kind == "tests":
        return "tests"
    if kind == "docs":
        return "docs"
    return "other"

def _reference_sort_key(ref: dict[str, Any]) -> tuple[int, int, int, str, int, str]:
    kind_rank = {
        "call_sites": 0,
        "definition": 1,
        "import": 2,
        "mention": 3,
        "other": 4,
        "docs": 5,
        "tests": 6,
    }.get(str(ref.get("reference_kind", "other")), 4)
    language_rank = 0 if ref.get("language") == "python" else 1
    method_rank = 0 if str(ref.get("method", "")).startswith("treesitter") else 1
    return (
        kind_rank,
        language_rank,
        method_rank,
        str(ref.get("path", "")),
        int(ref.get("line", 0) or 0),
        str(ref.get("snippet", "")),
    )


def _reference_detail_counts(refs: list[dict[str, Any]]) -> dict[str, int]:
    counts = {"call_sites": 0, "definition": 0, "import": 0, "mention": 0, "docs": 0, "tests": 0, "other": 0}
    for ref in refs:
        kind = str(ref.get("reference_kind", "other"))
        counts[kind] = counts.get(kind, 0) + 1
    return counts


def _apply_reference_filters(
    refs: list[dict[str, Any]],
    *,
    exclude_tests: bool = False,
    exclude_docs: bool = False,
    call_sites_only: bool = False,
) -> tuple[list[dict[str, Any]], dict[str, int], dict[str, int], dict[str, int], dict[str, int]]:
    """Normalize reference kinds, sort by signal, and apply optional filters."""
    all_counts = {"call_sites": 0, "other": 0, "docs": 0, "tests": 0}
    filtered_counts = {"call_sites": 0, "other": 0, "docs": 0, "tests": 0}
    detail_all_counts = {"call_sites": 0, "definition": 0, "import": 0, "mention": 0, "docs": 0, "tests": 0, "other": 0}
    detail_filtered_counts = {"call_sites": 0, "definition": 0, "import": 0, "mention": 0, "docs": 0, "tests": 0, "other": 0}
    filtered: list[dict[str, Any]] = []
    for ref in refs:
        detail_kind = str(ref.get("reference_kind", "other"))
        broad_kind = _reference_bucket(detail_kind)
        ref["reference_kind"] = detail_kind
        ref["reference_bucket"] = broad_kind
        all_counts[broad_kind] += 1
        detail_all_counts[detail_kind] = detail_all_counts.get(detail_kind, 0) + 1
        if call_sites_only and broad_kind != "call_sites":
            continue
        if exclude_tests and broad_kind == "tests":
            continue
        if exclude_docs and broad_kind == "docs":
            continue
        filtered_counts[broad_kind] += 1
        detail_filtered_counts[detail_kind] = detail_filtered_counts.get(detail_kind, 0) + 1
        filtered.append(ref)
    filtered.sort(key=_reference_sort_key)
    return filtered, filtered_counts, all_counts, detail_filtered_counts, detail_all_counts


def _graph_definition_candidate_files(root: Path, symbol: str) -> frozenset[str] | None:
    """Return candidate file set from graph nodes whose label/id matches symbol.

    Returns:
        - ``None`` when the graph index is absent or fails to load — signals caller to
          fall back to full repo walk.
        - ``frozenset()`` (empty) when graph is present but no nodes match — caller
          should also fall back, since the symbol may be in code added since the last
          graph build.
        - A non-empty frozenset of repo-relative ``source_file`` paths when graph
          candidates match. Mirrors the scanner predicate ``name == symbol or
          symbol in name`` so substring queries still resolve.

    Implementation of wave 12xr3 / 1301h: short-circuits the four-pass full repo walk
    for the common case where the symbol is in the graph.
    """
    try:
        gq = _load_graph_query()
        index = gq.get_query_index(root, layer="project")
    except Exception:
        return None
    if not index.present:
        return None
    suffix_key = f"::{symbol}"
    files: set[str] = set()
    for nid, node in index._node_by_id.items():
        label = str(node.get("label") or "")
        # Mirror scanner predicate: exact match, suffix on id, or substring on label
        if label == symbol or nid.endswith(suffix_key) or symbol in label:
            sf = node.get("source_file")
            if isinstance(sf, str) and sf:
                files.add(sf)
    return frozenset(files)


def code_definition_response(root: Path, symbol_or_path_position: str) -> dict[str, Any]:
    """Find definition(s) for a symbol across all supported languages using best available parser."""
    symbol = symbol_or_path_position.strip()
    retry_symbol = _sql_schema_retry_symbol(symbol)
    if not symbol:
        return _response("error", {"symbol": symbol}, diagnostics=[_diagnostic("invalid_arguments", "Symbol must be a non-empty string.")], next_tools=["code_keyword"], usage="code_keyword(query='MyClass')")
    # Wave 12xr3 / 1301h: consult the graph to narrow the file set before scanning.
    candidate_files = _graph_definition_candidate_files(root, symbol)
    graph_present = candidate_files is not None
    if not graph_present:
        # Graph never built — emit an advisory diagnostic but degrade gracefully.
        # The pre-1301h full structural walk was 40+s (4 × walk_repo); we skip it
        # and go straight to the keyword fallback (single walk, ~10s) so the
        # response is bounded. Operators see the diagnostic and can run
        # index_build(content='graph') to enable the fast path on next call.
        graph_missing_diagnostic = _diagnostic(
            "graph_index_missing_degraded",
            "Graph index is not built. `code_definition` is running in degraded mode (keyword fallback, ~10s). For sub-300ms lookups, run `index_build(content='graph')` once.",
            recovery_tools=["index_build"],
            recovery_usage="index_build(content='graph', mode='create')",
        )
        lookup_method = "graph_index_missing_degraded"
    else:
        graph_missing_diagnostic = None
        lookup_method = "graph_narrowed" if candidate_files else "graph_refresh_pending"
    # When the graph is present but had no match, try a cheap incremental
    # graph update — recently-added code is a common case and refresh is ~4ms
    # when nothing has changed. Skip when graph was absent entirely.
    refresh_attempted = False
    if graph_present and not candidate_files:
        try:
            index_build_response(root, content="graph", mode="update")
            refresh_attempted = True
            # Known rewrite: drop the cached index so the re-read reloads even
            # on a same-(mtime_ns, size) rewrite (coarse-mtime filesystems).
            try:
                _load_graph_query().invalidate_query_index_cache(root)
            except Exception:
                pass
            refreshed = _graph_definition_candidate_files(root, symbol)
            if refreshed:
                candidate_files = refreshed
                lookup_method = "graph_narrowed_after_refresh"
        except Exception:
            # Refresh attempt is best-effort; if it fails, fall through to definitive-not-found
            pass
    # When the graph is present and the incremental refresh confirmed no match,
    # the graph is the source of truth — skip the structural full walk and the
    # keyword fallback. Return a fast not-found response with a clear recovery hint.
    if refresh_attempted and not candidate_files:
        # Wave 1p2q3 (1p2qb): mirror code_callhierarchy's suggestions field on miss.
        # Operators chaining the two tools expect parallel recovery affordances —
        # a near-match suggestion helps recover from typos or stale names without
        # falling back to keyword search blindly.
        suggestions: list[dict[str, Any]] = []
        attribution_counts: dict[str, dict[str, int]] = {}
        try:
            gq = _load_graph_query()
            sugg_index = gq.get_query_index(root, layer="project")
            if sugg_index.present:
                suggestions = _suggest_near_symbols(sugg_index, symbol)
                # Wave 1p2q3 (1p2q9 B): when the graph spoke (definitive-not-found),
                # surface per-language attribution from the full graph so operators
                # can tell whether the empty result reflects a real absence or a
                # per-language coverage gap (e.g. typescript receiver-resolved=0).
                attribution_counts = _compute_attribution_counts_by_language(list(sugg_index.edges), sugg_index)
        except Exception:
            suggestions = []
            attribution_counts = {}
        return _response(
            "ok",
            {
                "symbol": symbol,
                "definitions": [],
                "method": "graph_definitive_not_found",
                "lookup_method": "graph_definitive_not_found",
                "suggestions": suggestions,
                "attribution_counts_by_language": attribution_counts,
            },
            diagnostics=[_diagnostic(
                "not_found",
                f"No definition for '{symbol}' in the project graph (refreshed). If the symbol is in a file type the graph does not index, fall back to code_keyword.",
                recovery_tools=["code_keyword"],
                recovery_usage=f"code_keyword(query={symbol!r})",
            )],
            next_tools=["code_keyword"],
            usage=f"code_keyword(query={symbol!r})",
        )
    # When graph is absent, fall back to the pre-1301h structural full walk so the
    # tests and callers that rely on `name`-bearing structural definitions still
    # work. The advisory diagnostic above ("graph_index_missing_degraded") tells
    # the operator to run index_build(content='graph') to switch to the fast
    # graph-narrowed path.
    restrict = candidate_files if candidate_files else None
    try:
        python_definitions = _python_definitions(root, symbol, restrict_files=restrict)
        treesitter_definitions = _treesitter_definition_results(root, symbol, restrict_files=restrict)
        regex_definitions = _regex_definitions(root, symbol, restrict_files=restrict)
        css_definitions = _css_definitions(root, symbol, restrict_files=restrict)
    except Exception as exc:
        return _response("error", {"symbol": symbol, "lookup_method": lookup_method}, diagnostics=[_diagnostic("navigation_error", f"Definition search failed: {exc}")], next_tools=["code_keyword"], usage=f"code_keyword(query={symbol!r})")
    definitions = _dedupe_navigation_results(
        python_definitions + treesitter_definitions + regex_definitions + css_definitions,
        ("path", "line", "language", "name"),
    )
    note = None
    if not definitions and retry_symbol is not None:
        retry_candidates = _graph_definition_candidate_files(root, retry_symbol)
        retry_restrict = retry_candidates if retry_candidates else None
        if retry_candidates is not None and not retry_candidates:
            lookup_method = "full_walk"  # retry path falls through full-walk too
        try:
            python_definitions = _python_definitions(root, retry_symbol, restrict_files=retry_restrict)
            treesitter_definitions = _treesitter_definition_results(root, retry_symbol, restrict_files=retry_restrict)
            regex_definitions = _regex_definitions(root, retry_symbol, restrict_files=retry_restrict)
            css_definitions = _css_definitions(root, retry_symbol, restrict_files=retry_restrict)
        except Exception as exc:
            return _response("error", {"symbol": symbol, "lookup_method": lookup_method}, diagnostics=[_diagnostic("navigation_error", f"Definition search failed: {exc}")], next_tools=["code_keyword"], usage=f"code_keyword(query={symbol!r})")
        definitions = _dedupe_navigation_results(
            python_definitions + treesitter_definitions + regex_definitions + css_definitions,
            ("path", "line", "language", "name"),
        )
        if definitions:
            note = f"Retried lookup with schema-stripped SQL symbol '{retry_symbol}'."
    definitions.sort(key=lambda d: _definition_sort_key(d, symbol))
    if definitions:
        languages = sorted({d.get("language") for d in definitions if d.get("language")})
        definition_methods = {d.get("method") for d in definitions}
        method = "multi_language"
        structural_diagnostics = [graph_missing_diagnostic] if graph_missing_diagnostic is not None else []
        # Wave 1p2q3 (1p2q9 B): empty per-language counts on the found-definition
        # path — `code_definition` doesn't surface graph edges in this response,
        # so the diagnostic is consistently `{}` here. Operators wanting per-
        # language attribution should call `wf_graph_report`.
        _attr_empty: dict[str, dict[str, int]] = {}
        if definition_methods == {"ast"}:
            return _response(
                "ok",
                {"symbol": symbol, "language": "python", "definitions": definitions, "supported_languages": sorted(_SUPPORTED_DEFINITION_LANGS), "method": "ast", "lookup_method": lookup_method, "attribution_counts_by_language": _attr_empty, **({"note": note} if note else {})},
                diagnostics=structural_diagnostics,
                next_tools=["code_read"],
                usage=f"code_read(path={definitions[0]['path']!r}, start_line={definitions[0]['line']}, end_line={definitions[0]['line'] + 20})",
            )
        if definition_methods == {"treesitter"}:
            method = "treesitter"
        elif definition_methods == {"regex"}:
            method = "regex"
        return _response(
            "ok",
                {
                    "symbol": symbol,
                    "definitions": definitions,
                    "supported_languages": sorted(_SUPPORTED_DEFINITION_LANGS),
                    "method": method,
                    "languages": languages,
                    "lookup_method": lookup_method,
                    "attribution_counts_by_language": _attr_empty,
                    **({"note": note} if note else {}),
                },
                diagnostics=structural_diagnostics,
                next_tools=["code_read"],
                usage=f"code_read(path={definitions[0]['path']!r}, start_line={definitions[0]['line']}, end_line={definitions[0]['line'] + 20})",
            )
    fallback_symbol = retry_symbol or symbol
    # No structural definitions found — run keyword fallback across all files.
    try:
        fallback = _keyword_fallback_definitions(root, fallback_symbol)
    except Exception as exc:
        return _response("error", {"symbol": symbol, "lookup_method": lookup_method}, diagnostics=[_diagnostic("navigation_error", f"Fallback search failed: {exc}")], next_tools=["code_keyword"], usage=f"code_keyword(query={symbol!r})")
    fallback_diagnostics: list[dict[str, Any]] = []
    if graph_missing_diagnostic is not None:
        fallback_diagnostics.append(graph_missing_diagnostic)
    fallback_lookup_method = lookup_method if not graph_present else "keyword_fallback"
    if not fallback:
        fallback_diagnostics.append(_diagnostic("not_found", f"No definition found for '{symbol}' in any language.", recovery_tools=["code_keyword"], recovery_usage=f"code_keyword(query={symbol!r})"))
        return _response(
            "ok",
            {"symbol": symbol, "definitions": [], "method": "keyword_fallback", "lookup_method": fallback_lookup_method, "attribution_counts_by_language": {}},
            diagnostics=fallback_diagnostics,
            next_tools=["code_keyword"],
            usage=f"code_keyword(query={symbol!r})",
        )
    return _response(
        "ok",
        {"symbol": symbol, "definitions": fallback, "method": "keyword_fallback", "lookup_method": fallback_lookup_method, "attribution_counts_by_language": {}, "note": note or (f"Retried lookup with schema-stripped SQL symbol '{retry_symbol}'." if retry_symbol else "No structural definition matcher found a result. Returning broad keyword matches across the repo.")},
        diagnostics=fallback_diagnostics,
        next_tools=["code_read"],
        usage=f"code_read(path={fallback[0]['path']!r}, start_line={fallback[0]['line']}, end_line={fallback[0]['line'] + 20})",
    )


def _graph_constant_reader_refs(root: Path, symbol: str) -> list[dict[str, Any]]:
    """Wave 1p4ls: graph-confirmed readers of a CONSTANT, as reference entries tagged
    ``reference_kind="reads"`` — DISTINCT from ``call_sites`` (callers). These are functions that
    read the constant's value, bound by the faithfulness-gated ``reads`` edge (never a coincidental
    same-name twin). Empty unless the symbol resolves to a ``kind="constant"`` node."""
    try:
        gq = _load_graph_query()
        index = gq.get_query_index(root, layer="project")
        if not index.present:
            return []
        node_id = index.resolve_symbol(symbol)
        if node_id is None:
            return []
        if (index.get_node(node_id) or {}).get("kind") != "constant":
            return []
        out: list[dict[str, Any]] = []
        seen: set[tuple[str, int]] = set()
        for edge in index._in.get(node_id, []):
            if edge.get("relation") != "reads":
                continue
            src = edge.get("source")
            if not isinstance(src, str) or src.startswith("external::"):
                continue
            reader = index.get_node(src) or {}
            sf = reader.get("source_file")
            if not isinstance(sf, str) or not sf:
                continue
            loc = str(reader.get("source_location") or "")
            head = loc.split(":", 1)[0]
            line = int(head) if head.isdigit() else 0
            if (sf, line) in seen:
                continue
            seen.add((sf, line))
            snippet = ""
            try:
                fp = root / sf
                if line > 0 and fp.is_file():
                    snippet = fp.read_text(encoding="utf-8", errors="replace").splitlines()[line - 1].strip()[:200]
            except Exception:
                snippet = ""
            out.append({
                "path": sf,
                "line": line,
                "snippet": snippet,
                "language": _detect_language(sf),
                "method": "graph_reads",
                "reference_kind": "reads",
                "name": reader.get("label") or src.split("::")[-1],
            })
        return out
    except Exception:
        return []


def code_references_response(
    root: Path,
    symbol_or_path_position: str,
    *,
    exclude_tests: bool = False,
    exclude_docs: bool = False,
    call_sites_only: bool = False,
    limit: Optional[int] = None,
) -> dict[str, Any]:
    """Find references to a symbol across known code languages with structural call-site detection where available."""
    symbol = symbol_or_path_position.strip()
    retry_symbol = _sql_schema_retry_symbol(symbol)
    if not symbol:
        return _response("error", {"symbol": symbol}, diagnostics=[_diagnostic("invalid_arguments", "Symbol must be a non-empty string.")], next_tools=["code_keyword"], usage="code_keyword(query='my_func')")
    if limit is not None and limit < 0:
        return _response("error", {"symbol": symbol, "limit": limit}, diagnostics=[_diagnostic("invalid_arguments", "limit must be a non-negative integer or omitted.")], next_tools=["code_help"], usage="code_help()")
    restrict_files = _graph_references_candidate_files(root, symbol)
    # Wave 1304x / 1304r: refresh-then-recheck on graph miss before falling through to walk.
    if restrict_files is None:
        refreshed = _graph_refresh_then_recheck(root, lambda: _graph_references_candidate_files(root, symbol))
        if refreshed is not None:
            restrict_files = refreshed
    # When graph gives candidate files, build the Path list once — avoids 4× repo walks
    _ref_files: list | None = (
        [root / rel for rel in sorted(restrict_files) if (root / rel).is_file()]
        if restrict_files is not None else None
    )
    try:
        python_refs = _python_references(root, symbol, restrict_files=restrict_files, _files=_ref_files)
        treesitter_refs = _treesitter_references(root, symbol, restrict_files=restrict_files, _files=_ref_files)
        other_refs = _non_python_references(root, symbol, restrict_files=restrict_files, _files=_ref_files)
    except Exception as exc:
        return _response("error", {"symbol": symbol}, diagnostics=[_diagnostic("navigation_error", f"Reference search failed: {exc}")], next_tools=["code_keyword"], usage=f"code_keyword(query={symbol!r})")
    refs = _dedupe_navigation_results(
        python_refs + treesitter_refs + other_refs,
        ("path", "line", "language", "snippet"),
    )
    note = None
    sql_doc_refs = _sql_schema_doc_mention_refs(root, symbol)
    if sql_doc_refs:
        refs = _dedupe_navigation_results(
            refs + sql_doc_refs,
            ("path", "line", "language", "snippet"),
        )
        note = f"Included docs and mention matches from schema-stripped SQL symbol '{_sql_schema_retry_symbol(symbol)}'."
    # Wave 1p4ls: graph-confirmed CONSTANT readers as a distinct `reads` bucket (functions that
    # read the constant's value) — faithfulness-gated, never merged into `call_sites` (callers).
    reads_refs = _graph_constant_reader_refs(root, symbol)
    if reads_refs:
        refs = _dedupe_navigation_results(refs + reads_refs, ("path", "line", "language", "snippet"))
    if refs:
        refs, filtered_counts, all_counts, detail_filtered_counts, detail_all_counts = _apply_reference_filters(
            refs,
            exclude_tests=exclude_tests,
            exclude_docs=exclude_docs,
            call_sites_only=call_sites_only,
        )
        matched_count = len(refs)
        matched_counts = dict(filtered_counts)
        if limit is not None and limit > 0:
            refs = refs[:limit]
        returned_counts = _reference_counts(refs)
        detail_returned_counts = _reference_detail_counts(refs)
        languages = sorted({r.get("language") for r in refs if r.get("language")})
        ref_methods = {r.get("method") for r in refs}
        method = "multi_language"
        broad_buckets = {
            "call_sites": [r for r in refs if _reference_bucket(str(r["reference_kind"])) == "call_sites"],
            "other": [r for r in refs if _reference_bucket(str(r["reference_kind"])) == "other"],
            "docs": [r for r in refs if _reference_bucket(str(r["reference_kind"])) == "docs"],
            "tests": [r for r in refs if _reference_bucket(str(r["reference_kind"])) == "tests"],
        }
        detail_buckets = {
            "call_sites": [r for r in refs if r["reference_kind"] == "call_sites"],
            "definition": [r for r in refs if r["reference_kind"] == "definition"],
            "import": [r for r in refs if r["reference_kind"] == "import"],
            "mention": [r for r in refs if r["reference_kind"] == "mention"],
            "reads": [r for r in refs if r["reference_kind"] == "reads"],
            "docs": [r for r in refs if r["reference_kind"] == "docs"],
            "tests": [r for r in refs if r["reference_kind"] == "tests"],
            "other": [r for r in refs if r["reference_kind"] == "other"],
        }
        if languages == ["python"] and ref_methods.issubset({"ast", "text"}):
            return _response(
                "ok",
                {
                    "symbol": symbol,
                    "language": "python",
                    "count": len(refs),
                    "matched_count": matched_count,
                    "total_count": sum(all_counts.values()),
                    "counts": returned_counts,
                    "matched_counts": matched_counts,
                    "all_counts": all_counts,
                    "detail_counts": detail_returned_counts,
                    "detail_matched_counts": detail_filtered_counts,
                    "detail_all_counts": detail_all_counts,
                    "references": refs,
                    "buckets": broad_buckets,
                    "detail_buckets": detail_buckets,
                    "method": "ast",
                    "supported_languages": sorted(_SUPPORTED_REFERENCE_LANGS),
                    "exclude_tests": exclude_tests,
                    "exclude_docs": exclude_docs,
                    "call_sites_only": call_sites_only,
                    "limit": limit,
                    "graph_assisted": restrict_files is not None,
                },
                next_tools=["code_read"],
                usage=f"code_read(path='...', start_line=N, end_line=N+20)",
            )
        if all(str(m).startswith("treesitter") for m in ref_methods):
            method = "treesitter"
        elif ref_methods == {"text"}:
            method = "text"
        return _response(
            "ok",
            {
                "symbol": symbol,
                "count": len(refs),
                "matched_count": matched_count,
                "total_count": sum(all_counts.values()),
                "counts": returned_counts,
                "matched_counts": matched_counts,
                "all_counts": all_counts,
                "detail_counts": detail_returned_counts,
                "detail_matched_counts": detail_filtered_counts,
                "detail_all_counts": detail_all_counts,
                "references": refs,
                "buckets": broad_buckets,
                "detail_buckets": detail_buckets,
                "method": method,
                "supported_languages": sorted(_SUPPORTED_REFERENCE_LANGS),
                "languages": languages,
                **({"note": note} if note else {}),
                "exclude_tests": exclude_tests,
                "exclude_docs": exclude_docs,
                "call_sites_only": call_sites_only,
                "limit": limit,
                "graph_assisted": restrict_files is not None,
            },
            next_tools=["code_read"],
            usage=f"code_read(path='...', start_line=N, end_line=N+20)",
        )
    if retry_symbol is not None:
        retry_restrict = _graph_references_candidate_files(root, retry_symbol)
        _retry_files: list | None = (
            [root / rel for rel in sorted(retry_restrict) if (root / rel).is_file()]
            if retry_restrict is not None else None
        )
        try:
            python_refs = _python_references(root, retry_symbol, restrict_files=retry_restrict, _files=_retry_files)
            treesitter_refs = _treesitter_references(root, retry_symbol, restrict_files=retry_restrict, _files=_retry_files)
            other_refs = _non_python_references(root, retry_symbol, restrict_files=retry_restrict, _files=_retry_files)
        except Exception as exc:
            return _response("error", {"symbol": symbol}, diagnostics=[_diagnostic("navigation_error", f"Reference search failed: {exc}")], next_tools=["code_keyword"], usage=f"code_keyword(query={symbol!r})")
        refs = _dedupe_navigation_results(
            python_refs + treesitter_refs + other_refs,
            ("path", "line", "language", "snippet"),
        )
        sql_doc_refs = _sql_schema_doc_mention_refs(root, symbol)
        if sql_doc_refs:
            refs = _dedupe_navigation_results(
                refs + sql_doc_refs,
                ("path", "line", "language", "snippet"),
            )
            note = f"Included docs and mention matches from schema-stripped SQL symbol '{retry_symbol}'."
        if refs:
            if note is None:
                note = f"Retried lookup with schema-stripped SQL symbol '{retry_symbol}'."
            refs, filtered_counts, all_counts, detail_filtered_counts, detail_all_counts = _apply_reference_filters(
                refs,
                exclude_tests=exclude_tests,
                exclude_docs=exclude_docs,
                call_sites_only=call_sites_only,
            )
            matched_count = len(refs)
            matched_counts = dict(filtered_counts)
            if limit is not None and limit > 0:
                refs = refs[:limit]
            returned_counts = _reference_counts(refs)
            detail_returned_counts = _reference_detail_counts(refs)
            languages = sorted({r.get("language") for r in refs if r.get("language")})
            ref_methods = {r.get("method") for r in refs}
            method = "multi_language"
            broad_buckets = {
                "call_sites": [r for r in refs if _reference_bucket(str(r["reference_kind"])) == "call_sites"],
                "other": [r for r in refs if _reference_bucket(str(r["reference_kind"])) == "other"],
                "docs": [r for r in refs if _reference_bucket(str(r["reference_kind"])) == "docs"],
                "tests": [r for r in refs if _reference_bucket(str(r["reference_kind"])) == "tests"],
            }
            detail_buckets = {
                "call_sites": [r for r in refs if r["reference_kind"] == "call_sites"],
                "definition": [r for r in refs if r["reference_kind"] == "definition"],
                "import": [r for r in refs if r["reference_kind"] == "import"],
                "mention": [r for r in refs if r["reference_kind"] == "mention"],
                "docs": [r for r in refs if r["reference_kind"] == "docs"],
                "tests": [r for r in refs if r["reference_kind"] == "tests"],
                "other": [r for r in refs if r["reference_kind"] == "other"],
            }
            if languages == ["python"] and ref_methods.issubset({"ast", "text"}):
                return _response(
                    "ok",
                    {
                        "symbol": symbol,
                        "language": "python",
                        "count": len(refs),
                        "matched_count": matched_count,
                        "total_count": sum(all_counts.values()),
                        "counts": returned_counts,
                        "matched_counts": matched_counts,
                        "all_counts": all_counts,
                        "detail_counts": detail_returned_counts,
                        "detail_matched_counts": detail_filtered_counts,
                        "detail_all_counts": detail_all_counts,
                        "references": refs,
                        "buckets": broad_buckets,
                        "detail_buckets": detail_buckets,
                        "method": "ast",
                        "supported_languages": sorted(_SUPPORTED_REFERENCE_LANGS),
                        "exclude_tests": exclude_tests,
                        "exclude_docs": exclude_docs,
                        "call_sites_only": call_sites_only,
                        "limit": limit,
                        **({"note": note} if note else {}),
                    },
                    next_tools=["code_read"],
                    usage=f"code_read(path='...', start_line=N, end_line=N+20)",
                )
            if all(str(m).startswith("treesitter") for m in ref_methods):
                method = "treesitter"
            elif ref_methods == {"text"}:
                method = "text"
            return _response(
                "ok",
                {
                    "symbol": symbol,
                    "count": len(refs),
                    "matched_count": matched_count,
                    "total_count": sum(all_counts.values()),
                    "counts": returned_counts,
                    "matched_counts": matched_counts,
                    "all_counts": all_counts,
                    "detail_counts": detail_returned_counts,
                    "detail_matched_counts": detail_filtered_counts,
                    "detail_all_counts": detail_all_counts,
                    "references": refs,
                    "buckets": broad_buckets,
                    "detail_buckets": detail_buckets,
                    "method": method,
                    "supported_languages": sorted(_SUPPORTED_REFERENCE_LANGS),
                    "languages": languages,
                    **({"note": note} if note else {}),
                    "exclude_tests": exclude_tests,
                    "exclude_docs": exclude_docs,
                    "call_sites_only": call_sites_only,
                    "limit": limit,
                },
                next_tools=["code_read"],
                usage=f"code_read(path='...', start_line=N, end_line=N+20)",
            )
    fallback_symbol = retry_symbol or symbol
    # No known-language references — run broad keyword fallback across all files.
    try:
        fallback = _keyword_fallback_definitions(root, fallback_symbol)
    except Exception as exc:
        return _response("error", {"symbol": symbol}, diagnostics=[_diagnostic("navigation_error", f"Fallback search failed: {exc}")], next_tools=["code_keyword"], usage=f"code_keyword(query={symbol!r})")
    if not fallback:
        return _response(
            "ok",
            {"symbol": symbol, "references": [], "count": 0, "method": "keyword_fallback"},
            diagnostics=[_diagnostic("not_found", f"No references found for '{symbol}'.", recovery_tools=["code_keyword"], recovery_usage=f"code_keyword(query={symbol!r})")],
            next_tools=["code_keyword"],
            usage=f"code_keyword(query={symbol!r})",
        )
    fallback_total = len(fallback)
    fallback, fallback_counts, fallback_all_counts, fallback_detail_counts, fallback_detail_all_counts = _apply_reference_filters(
        fallback,
        exclude_tests=exclude_tests,
        exclude_docs=exclude_docs,
        call_sites_only=call_sites_only,
    )
    fallback_matched_count = len(fallback)
    fallback_matched_counts = dict(fallback_counts)
    if limit is not None and limit > 0:
        fallback = fallback[:limit]
    fallback_returned_counts = _reference_counts(fallback)
    fallback_detail_returned_counts = _reference_detail_counts(fallback)
    fallback_buckets = {
        "call_sites": [r for r in fallback if _reference_bucket(str(r["reference_kind"])) == "call_sites"],
        "other": [r for r in fallback if _reference_bucket(str(r["reference_kind"])) == "other"],
        "docs": [r for r in fallback if _reference_bucket(str(r["reference_kind"])) == "docs"],
        "tests": [r for r in fallback if _reference_bucket(str(r["reference_kind"])) == "tests"],
    }
    fallback_detail_buckets = {
        "call_sites": [r for r in fallback if r["reference_kind"] == "call_sites"],
        "definition": [r for r in fallback if r["reference_kind"] == "definition"],
        "import": [r for r in fallback if r["reference_kind"] == "import"],
        "mention": [r for r in fallback if r["reference_kind"] == "mention"],
        "docs": [r for r in fallback if r["reference_kind"] == "docs"],
        "tests": [r for r in fallback if r["reference_kind"] == "tests"],
        "other": [r for r in fallback if r["reference_kind"] == "other"],
    }
    return _response(
        "ok",
        {
            "symbol": symbol,
            "references": fallback,
            "count": len(fallback),
            "matched_count": fallback_matched_count,
            "total_count": fallback_total,
            "counts": fallback_returned_counts,
            "matched_counts": fallback_matched_counts,
            "all_counts": fallback_all_counts,
            "detail_counts": fallback_detail_returned_counts,
            "detail_matched_counts": fallback_detail_counts,
            "detail_all_counts": fallback_detail_all_counts,
            "buckets": fallback_buckets,
            "detail_buckets": fallback_detail_buckets,
            "method": "keyword_fallback",
            "exclude_tests": exclude_tests,
            "exclude_docs": exclude_docs,
            "call_sites_only": call_sites_only,
            "limit": limit,
            "note": "No known-language reference search found a result. Returning broad keyword matches across the repo.",
        },
        next_tools=["code_read"],
        usage=f"code_read(path='...', start_line=N, end_line=N+20)",
    )


# ---------------------------------------------------------------------------
# code_callhierarchy — call graph for a symbol (depth 1)
# ---------------------------------------------------------------------------

def code_callhierarchy_response(
    root: Path,
    symbol: str,
    file: Optional[str] = None,
    direction: str = "both",
    context_depth: int = 0,
    include_external: bool = False,
) -> dict[str, Any]:
    """Return the call hierarchy for a symbol using the persisted graph.

    By default (``include_external=False``, wave 130ol), entries whose target
    is an external (non-project) symbol — surfaced as ``file: "external"`` with
    no line/snippet — are excluded from the ``outgoing``/``incoming`` lists.
    The response gains an ``external_outgoing_count`` / ``external_incoming_count``
    field showing how many were suppressed. Pass ``include_external=True`` to
    surface them inline for callers that want the full set.

    The default suppression reflects two realities: (1) external entries lack
    file/line/snippet so they can't be navigated, and (2) the pre-1.1.0 graph
    extractor over-produced external entries because its call-resolution heuristic
    bottomed out at ``external::<name>`` for every cross-file call (fixed in this
    wave by the cross-file resolution pass in graph_indexer). Operators
    inspecting call graphs benefit from a clean signal-only default.
    """
    if direction not in {"both", "outgoing", "incoming"}:
        return _response(
            "error", {"symbol": symbol, "direction": direction},
            diagnostics=[_diagnostic("invalid_arguments", f"direction must be 'both', 'outgoing', or 'incoming'; got '{direction}'.")],
            next_tools=[], usage="",
        )
    if not symbol or not symbol.strip():
        return _response(
            "error", {"symbol": symbol},
            diagnostics=[_diagnostic("invalid_arguments", "symbol must be a non-empty string.")],
            next_tools=[], usage="",
        )
    symbol = symbol.strip()

    gq = _load_graph_query()
    try:
        index = gq.get_query_index(root, layer="project")
    except Exception as exc:
        return _response(
            "error", {"symbol": symbol},
            diagnostics=[_diagnostic("graph_error", f"Failed to load graph: {exc}")],
            next_tools=["index_build"],
            usage="index_build(content='graph', mode='create')",
        )

    if not index.present:
        return _response(
            "error", {"symbol": symbol},
            diagnostics=[gq.graph_not_ready_diagnostic("project")],
            next_tools=["index_build"],
            usage="index_build(content='graph', mode='create')",
        )

    # Resolve symbol — prefer file-qualified node when file is given
    node_id: Optional[str] = None
    if file:
        candidate = f"{file}::{symbol}"
        if index.get_node(candidate) is not None:
            node_id = candidate
    if node_id is None:
        node_id = index.resolve_symbol(symbol)

    if node_id is None:
        # Wave 1304x / 1304r: refresh-then-resolve before emitting suggestions
        new_index, refreshed_id = _graph_refresh_and_resolve(root, symbol)
        if refreshed_id is not None:
            index = new_index
            node_id = refreshed_id

    if node_id is None:
        suggestions = _suggest_near_symbols(index, symbol)
        data: dict[str, Any] = {"symbol": symbol, "node_id": None, "definition_file": None, "parser_used": "graph", "suggestions": suggestions}
        if direction in {"both", "outgoing"}:
            data["outgoing"] = []
        if direction in {"both", "incoming"}:
            data["incoming"] = []
        return _response(
            "ok", data,
            diagnostics=[_diagnostic(
                "graph_symbol_not_found",
                f"Symbol '{symbol}' does not resolve to a graph node (refresh attempted).",
                recovery_tools=["code_keyword", "index_build"],
                recovery_usage=f"code_keyword(query={symbol!r})",
            )],
            next_tools=["index_build"], usage="index_build(content='graph', mode='create')",
        )

    node = index.get_node(node_id) or {}
    definition_file = node.get("source_file") or (node_id.split("::")[0] if "::" in node_id else node_id)
    _cloc = node.get("source_location") or "0:0"
    try:
        _current_start = int(str(_cloc).split(":")[0])
    except (ValueError, IndexError):
        _current_start = 0

    data: dict[str, Any] = {
        "symbol": symbol,
        "node_id": node_id,
        "definition_file": definition_file,
        "parser_used": "graph",
    }

    # Wave 1sbfi (1sbfh): declared supertypes, calls-parity external handling —
    # project supertypes always listed; external supertype entries gated on
    # ``include_external`` with ALWAYS-ON suppressed counts (a class whose only
    # supertypes are external must never read as "no relationships" with no
    # signal). Absent entirely when the node declares no supertypes.
    try:
        _supers = index.supertype_summary(node_id)
    except AttributeError:
        _supers = None
    if _supers:
        _supers_out = dict(_supers)
        if not include_external:
            _supers_out.pop("external", None)
        data["supertypes"] = _supers_out

    community_lookup = _load_cluster_lookup_with_ids(root)

    def _node_entry(nid: str) -> dict[str, Any]:
        n = index.get_node(nid) or {}
        label = n.get("label") or (nid.split("::")[-1] if "::" in nid else nid)
        src = n.get("source_file") or (nid.split("::")[0] if "::" in nid else nid)
        loc = n.get("source_location") or "0:0"
        try:
            start_line = int(str(loc).split(":")[0])
        except (ValueError, IndexError):
            start_line = 0
        c_label, c_id = community_lookup.get(nid, (None, None))
        return {"name": label, "file": src, "line": None, "snippet": None, "community": c_label, "community_id": c_id, "_start_line": start_line}

    # Accumulator for advice-pattern diagnostics emitted on the incoming branch.
    # Initialized before direction conditionals so the variable is always defined
    # at the final _response call regardless of the requested direction.
    advice_diagnostics: list[dict[str, Any]] = []
    # Wave 1p2q3 (1p2q9 B): collect the edges actually surfaced so we can
    # populate `attribution_counts_by_language` from them at the end.
    _attr_edges: list[dict[str, Any]] = []
    if direction in {"both", "outgoing"}:
        _, out_edges, _ = index.traverse(node_id, relations=["calls"], max_hops=1, direction="callees")
        _attr_edges.extend(out_edges or [])
        out_entries: list[tuple[str, dict[str, Any]]] = []
        for e in out_edges:
            tgt = e.get("target")
            if not isinstance(tgt, str):
                continue
            entry = _node_entry(tgt)
            # Wave 1p2q3 (1p2td post-ship feedback): propagate edge.self_edge_kind
            # from the underlying edge to the outgoing entry so consumers reading
            # code_callhierarchy's outgoing list see the overload classification
            # without re-querying the raw edge layer.
            sek = e.get("self_edge_kind")
            if sek:
                entry["self_edge_kind"] = sek
            out_entries.append((tgt, entry))
        # Batch: scan definition_file once for all non-external callees
        if definition_file:
            callee_names = [
                entry["name"] for tgt_id, entry in out_entries
                if not tgt_id.startswith("external::")
            ]
            all_out_sites = _scan_all_call_sites_in_file(root, callee_names, definition_file)
        else:
            all_out_sites = {}
        outgoing: list[dict[str, Any]] = []
        external_outgoing_count = 0
        for tgt_id, entry in out_entries:
            if not tgt_id.startswith("external::") and definition_file:
                sites = all_out_sites.get(entry["name"], [])
                ref = _first_call_site_at_or_after(sites, _current_start)
                if ref:
                    entry["line"] = ref["line"]
                    entry["snippet"] = ref.get("snippet")
            entry.pop("_start_line", None)
            is_external = tgt_id.startswith("external::") or entry.get("file") == "external"
            if is_external:
                external_outgoing_count += 1
                if not include_external:
                    continue
            outgoing.append(entry)
        data["outgoing"] = outgoing
        data["external_outgoing_count"] = external_outgoing_count

    if direction in {"both", "incoming"}:
        _, in_edges, _ = index.traverse(node_id, relations=["calls"], max_hops=1, direction="callers")
        _attr_edges.extend(in_edges or [])
        incoming_raw: list[tuple[str, dict[str, Any]]] = []
        for e in in_edges:
            src = e.get("source")
            if not isinstance(src, str):
                continue
            entry = _node_entry(src)
            # Wave 1p2q3 (1p2td post-ship feedback): propagate edge.self_edge_kind
            # from the underlying edge to the incoming entry so consumers reading
            # code_callhierarchy's incoming list see the overload classification.
            sek = e.get("self_edge_kind")
            if sek:
                entry["self_edge_kind"] = sek
            incoming_raw.append((src, entry))

        # Group by source file — scan each file once
        by_file: dict[str, list[tuple[str, dict[str, Any]]]] = {}
        for src_id, entry in incoming_raw:
            f = entry.get("file", "")
            if f and not src_id.startswith("external::"):
                by_file.setdefault(f, []).append((src_id, entry))

        # Wave 130rj (130tw): for Java queries with class-qualified node_ids,
        # filter caller-side call sites whose receiver type doesn't match the
        # queried class. Suppresses phantom cross-class callers from
        # simple-name attribution (e.g. ``oos.writeObject(...)`` falsely
        # matching ``JSON.writeObject``).
        #
        # Wave 13129 (1312l delivery review): the filter is provably redundant
        # on graphs built by the v13+ indexer (1312l moved receiver-type
        # resolution to graph-build time, eliminating phantoms at the source).
        # Short-circuit on v13+ to avoid per-query AST walks; the defense-in-
        # depth path stays active for cached pre-bump graphs (builder_version
        # < 13 or absent) that operators haven't rebuilt yet.
        _expected_owner_class = _extract_java_owner_class_from_node_id(node_id)
        try:
            _graph_builder_version_int = int(index.builder_version) if index.builder_version else 0
        except (TypeError, ValueError):
            _graph_builder_version_int = 0
        _receiver_filter_redundant = _graph_builder_version_int >= 13
        # Use the resolved node's bare label for call-site scanning; the user's
        # `symbol` may be qualified ("JSON.writeObject") which would never match
        # bare identifier text. Falls back to symbol when label is absent.
        _scan_label = node.get("label") or symbol
        _excluded_caller_ids: set[str] = set()
        for source_file, file_entries in by_file.items():
            sites = _scan_call_sites_in_file(root, _scan_label, source_file)
            if not sites:
                continue
            _apply_receiver_filter = bool(
                _expected_owner_class
                and source_file.endswith(".java")
                and not _receiver_filter_redundant
            )
            # Sort callers by their definition start line to attribute call sites correctly
            sorted_entries = sorted(file_entries, key=lambda x: x[1].get("_start_line", 0))
            used_lines: set[int] = set()
            for i, (_src_id, entry) in enumerate(sorted_entries):
                start_line = entry.get("_start_line", 0)
                next_start = (
                    sorted_entries[i + 1][1].get("_start_line", 0)
                    if i + 1 < len(sorted_entries) else (10 ** 12)
                )
                # Call sites within this entry's method scope.
                in_scope = [
                    r for r in sites
                    if (r.get("line") or 0) >= start_line
                    and (r.get("line") or 0) < next_start
                    and (r.get("line") or 0) not in used_lines
                ]
                if _apply_receiver_filter and in_scope:
                    # Phantom-caller test: if EVERY in-scope call site has a
                    # definitive receiver-type mismatch, this caller is a
                    # simple-name attribution phantom — exclude it.
                    has_match_or_uncertain = any(
                        r.get("_receiver_type") is None
                        or r.get("_receiver_type") == _expected_owner_class
                        for r in in_scope
                    )
                    if not has_match_or_uncertain:
                        _excluded_caller_ids.add(_src_id)
                        continue
                    # Keep only matching-or-uncertain refs for line attribution.
                    in_scope = [
                        r for r in in_scope
                        if r.get("_receiver_type") is None
                        or r.get("_receiver_type") == _expected_owner_class
                    ]
                if not in_scope:
                    continue
                ref = in_scope[0]
                line = ref.get("line") or 0
                entry["line"] = line
                entry["snippet"] = ref.get("snippet")
                used_lines.add(line)
        if _excluded_caller_ids:
            incoming_raw = [
                (sid, entry) for sid, entry in incoming_raw
                if sid not in _excluded_caller_ids
            ]

        incoming = []
        external_incoming_count = 0
        for _src_id, entry in incoming_raw:
            entry.pop("_start_line", None)
            is_external = _src_id.startswith("external::") or entry.get("file") == "external"
            if is_external:
                external_incoming_count += 1
                if not include_external:
                    continue
            incoming.append(entry)
        data["incoming"] = incoming
        data["external_incoming_count"] = external_incoming_count

        # Wave 130rj — field feedback §2.3: AOP/advice empty-incoming detection.
        # When the response would report zero project-internal callers AND the
        # queried method carries an AOP advice annotation/attribute, surface
        # `caller_pattern: "advice"` plus an `advice_pattern_detected`
        # diagnostic so agents route to instrumentation/aspect declarations
        # rather than falling back to code_references (which also returns
        # nothing useful — callers are wired at weave time).
        if not incoming:
            queried_node = index.get_node(node_id) or {}
            annotations = queried_node.get("annotations") or []
            advice_tail_set = {
                # Java / ByteBuddy / AspectJ
                "Advice.OnMethodEnter", "Advice.OnMethodExit",
                "Around", "Before", "After", "AfterReturning", "AfterThrowing",
                # C# / PostSharp / Castle / MethodBoundary aspects (130tc)
                "OnEntry", "OnExit", "OnSuccess", "OnException",
                "OnMethodBoundaryAspect", "MethodBoundaryAspect",
                "MethodInterceptionAspect", "OnMethodInvokeAspect",
                "AroundAdvice", "BeforeAdvice", "AfterAdvice",
            }
            def _annotation_tail(name: str) -> str:
                # `org.aspectj.lang.annotation.Around` → `Around`;
                # `Advice.OnMethodEnter` stays as-is.
                segs = name.split(".")
                if len(segs) >= 2 and segs[-2] == "Advice":
                    return f"Advice.{segs[-1]}"
                return segs[-1]
            matched_advice = [
                _annotation_tail(str(a))
                for a in annotations
                if _annotation_tail(str(a)) in advice_tail_set
            ]
            if matched_advice:
                # The "advice class name" is the enclosing class — strip the
                # method-name leaf from the qualified node_id portion after `::`.
                qualified = node_id.split("::", 1)[1] if "::" in node_id else ""
                advice_class = qualified.rsplit(".", 1)[0] if "." in qualified else qualified
                data["caller_pattern"] = "advice"
                data["advice_annotations"] = matched_advice
                # Language-aware recovery hint: choose glob + framework
                # references based on whether annotations look Java-style or
                # C#-style. Heuristic: any matched advice tail in the C# set
                # suggests C#; otherwise default to Java.
                csharp_tails = {
                    "OnEntry", "OnExit", "OnSuccess", "OnException",
                    "OnMethodBoundaryAspect", "MethodBoundaryAspect",
                    "MethodInterceptionAspect", "OnMethodInvokeAspect",
                    "AroundAdvice", "BeforeAdvice", "AfterAdvice",
                }
                is_csharp = any(tail in csharp_tails for tail in matched_advice)
                if is_csharp:
                    recovery_hint = (
                        f"Method '{symbol}' is decorated with a C# AOP attribute "
                        f"({', '.join(matched_advice)}). Callers are wired at runtime by "
                        f"PostSharp / Castle DynamicProxy / a method-boundary aspect framework "
                        f"and have no C# call sites. Search for the aspect registration via "
                        f"code_keyword(queries=['{advice_class or symbol}'], glob='**/*.cs') "
                        f"or look for the framework's interception configuration."
                    )
                else:
                    recovery_hint = (
                        f"Method '{symbol}' is annotated as AOP advice "
                        f"({', '.join(matched_advice)}). Callers are wired at weave time by "
                        f"ByteBuddy/AspectJ and have no Java call sites. "
                        f"Search for the advice registration via "
                        f"code_keyword(queries=['{advice_class or symbol}'], glob='**/*Instrumentation*.java') "
                        f"or via @Aspect pointcut declarations."
                    )
                # Surface as a diagnostic (the AC-3 contract); thread through
                # the final _response call below via a local advice_diagnostics
                # list. Data-field surfacing is retained for back-compat with
                # the test fixtures and downstream consumers.
                advice_diagnostics.append(_diagnostic(
                    "advice_pattern_detected",
                    recovery_hint,
                    recovery_tools=["code_keyword"],
                    recovery_usage=(
                        f"code_keyword(queries=['{advice_class or symbol}'], "
                        f"glob='**/*Instrumentation*.java')"
                        if not is_csharp else
                        f"code_keyword(queries=['{advice_class or symbol}'], glob='**/*.cs')"
                    ),
                ))

    if context_depth > 0:
        # Gather all immediate caller/callee ids in one pass
        immediate_ids: set[str] = set()
        if direction in {"both", "outgoing"}:
            for edges in (index._out.get(node_id, []),):
                for e in edges:
                    if e.get("relation") != "calls":
                        continue
                    tgt = e.get("target")
                    if isinstance(tgt, str):
                        immediate_ids.add(tgt)
        if direction in {"both", "incoming"}:
            for edges in (index._in.get(node_id, []),):
                for e in edges:
                    if e.get("relation") != "calls":
                        continue
                    src = e.get("source")
                    if isinstance(src, str):
                        immediate_ids.add(src)
        immediate_ids.discard(node_id)
        # Single combined one-hop expansion across all immediate neighbors
        already_known = immediate_ids | {node_id}
        neighborhood = index.one_hop_neighbors(immediate_ids, relations=["calls"])
        context_entries: list[dict[str, Any]] = []
        seen_context: set[str] = set()
        for e in neighborhood.get("edges") or []:
            for other in (e.get("source"), e.get("target")):
                if not isinstance(other, str) or other in already_known or other in seen_context:
                    continue
                n = index.get_node(other) or {}
                c_label, c_id = community_lookup.get(other, (None, None))
                context_entries.append({
                    "id": other,
                    "label": n.get("label", other),
                    "kind": n.get("kind"),
                    "source_file": n.get("source_file"),
                    "community": c_label,
                    "community_id": c_id,
                    "relation": e.get("relation"),
                })
                seen_context.add(other)
        data["context"] = context_entries

    # Wave 1p2q3 (1p2q9 B): per-language attribution-confidence counts.
    data["attribution_counts_by_language"] = _compute_attribution_counts_by_language(_attr_edges, index)

    # 1p8gy AC-5: active memory attached to the symbol or its defining file.
    _mem_advisories = _memory_advisories_for_path(
        root, str((index.get_node(node_id) or {}).get("source_file") or file or ""), symbol=symbol,
    )
    if _mem_advisories:
        data["memory_advisories"] = _mem_advisories

    return _attach_auto_rebuild_diag(
        _response("ok", data, diagnostics=advice_diagnostics, next_tools=["code_read", "code_callgraph"], usage=f"code_callgraph(symbol={symbol!r}, direction='both')"),
        index,
    )


# ---------------------------------------------------------------------------
# code_dependencies — on-demand import graph extraction
# ---------------------------------------------------------------------------

def _parse_python_imports(source: str) -> list[dict[str, Any]]:
    import ast as _ast
    try:
        tree = _ast.parse(source)
    except SyntaxError:
        return []
    imports = []
    for node in _ast.walk(tree):
        if isinstance(node, _ast.Import):
            for alias in node.names:
                imports.append({"module": alias.name, "resolved": False})
        elif isinstance(node, _ast.ImportFrom):
            module = node.module or ""
            level = node.level or 0
            name = ("." * level) + module if level else module
            imports.append({"module": name, "resolved": False})
    return imports


_JS_TS_IMPORT_RE = re.compile(r"""(?:import|export)\s+(?:[^'"]*?\s+from\s+)?['"]([^'"]+)['"]""")
_JS_TS_REQUIRE_RE = re.compile(r"""require\s*\(\s*['"]([^'"]+)['"]\s*\)""")
_GO_IMPORT_BLOCK_RE = re.compile(r"import\s*\(([^)]+)\)", re.DOTALL)
_GO_IMPORT_INLINE_RE = re.compile(r'import\s+"([^"]+)"')
_GO_IMPORT_STR_RE = re.compile(r'"([^"]+)"')
_RUST_USE_RE = re.compile(r"^(?:pub\s+)?use\s+([\w:]+)", re.MULTILINE)


def _parse_js_ts_imports(source: str) -> list[dict[str, Any]]:
    imports = []
    for m in _JS_TS_IMPORT_RE.finditer(source):
        imports.append({"module": m.group(1), "resolved": False})
    for m in _JS_TS_REQUIRE_RE.finditer(source):
        imports.append({"module": m.group(1), "resolved": False})
    return imports


def _parse_go_imports(source: str) -> list[dict[str, Any]]:
    imports = []
    for block in _GO_IMPORT_BLOCK_RE.finditer(source):
        for m in _GO_IMPORT_STR_RE.finditer(block.group(1)):
            imports.append({"module": m.group(1), "resolved": False})
    for m in _GO_IMPORT_INLINE_RE.finditer(source):
        imports.append({"module": m.group(1), "resolved": False})
    return imports


def _parse_rust_imports(source: str) -> list[dict[str, Any]]:
    imports = []
    for m in _RUST_USE_RE.finditer(source):
        imports.append({"module": m.group(1), "resolved": False})
    return imports


_IMPORT_PARSERS: dict[str, Any] = {
    "python": (_parse_python_imports, "ast"),
    "javascript": (_parse_js_ts_imports, "regex"),
    "typescript": (_parse_js_ts_imports, "regex"),
    "go": (_parse_go_imports, "regex"),
    "rust": (_parse_rust_imports, "regex"),
}

_JS_TS_SUFFIXES = {".js", ".jsx", ".ts", ".tsx", ".mjs", ".cjs"}


def code_dependencies_response(root: Path, path: str) -> dict[str, Any]:
    """Return imported modules/files for a given repo-relative path, parsed on demand."""
    rel = path.strip().replace("\\", "/")
    if not rel:
        return _response("error", {"path": rel}, diagnostics=[_diagnostic("invalid_arguments", "path must be a non-empty repo-relative file path.")], next_tools=["code_list_files"], usage="code_list_files()")
    abs_path = _resolve_repo_path(root, rel)
    if abs_path is None:
        return _response("error", {"path": rel}, diagnostics=[_diagnostic("invalid_arguments", "path escapes the repository root or is absolute.")], next_tools=["code_list_files"], usage="code_list_files()")
    try:
        source = abs_path.read_text(encoding="utf-8", errors="replace")
    except FileNotFoundError:
        return _response("error", {"path": rel}, diagnostics=[_diagnostic("file_not_found", f"File not found: {rel}")], next_tools=["code_list_files"], usage="code_list_files()")
    except OSError as exc:
        return _response("error", {"path": rel}, diagnostics=[_diagnostic("read_error", str(exc))], next_tools=[], usage="")

    suffix = Path(rel).suffix.lower()
    if suffix == ".py":
        lang = "python"
    elif suffix in _JS_TS_SUFFIXES:
        lang = _EXT_TO_LANG.get(suffix, "javascript")
    else:
        lang = _EXT_TO_LANG.get(suffix, "")

    parser_entry = _IMPORT_PARSERS.get(lang)
    if not parser_entry:
        return _response("ok", {"path": rel, "imports": [], "method": "unsupported"}, next_tools=[], usage="")

    parser_fn, method = parser_entry
    imports = parser_fn(source)
    # Deduplicate while preserving order
    seen: set[str] = set()
    deduped = []
    for entry in imports:
        mod = entry["module"]
        if mod not in seen:
            seen.add(mod)
            deduped.append(entry)

    return _response(
        "ok",
        {"path": rel, "imports": deduped, "method": method},
        next_tools=["code_read"],
        usage=f"code_read(path={rel!r})",
    )


# ---------------------------------------------------------------------------
# code_impact — reverse dependency / impact analysis
# ---------------------------------------------------------------------------


def _match_import_to_target(import_entry: dict[str, Any], target_rel: str, importing_file_rel: str) -> bool:
    """Return True if *import_entry* appears to import *target_rel*."""
    module = import_entry.get("module", "")
    if not module:
        return False

    target_path = Path(target_rel)
    target_stem = target_rel
    for ext in (".py", ".ts", ".js", ".tsx", ".jsx"):
        if target_stem.endswith(ext):
            target_stem = target_stem[: -len(ext)]
            break

    # Heuristic 1: module path normalization
    # Strip leading dots (relative Python imports) then normalize
    stripped = module.lstrip(".")
    normalized = stripped.replace(".", "/")
    if (
        normalized == target_stem
        or target_rel.endswith("/" + normalized + ".py")
        or target_rel.endswith("/" + normalized + ".ts")
        or target_rel.endswith("/" + normalized + ".js")
        or target_rel.endswith("/" + normalized + ".tsx")
        or target_rel.endswith("/" + normalized + ".jsx")
        or target_stem.endswith("/" + normalized)
        or normalized == target_stem.split("/")[-1]
    ):
        return True

    # Heuristic 2: filename stem match (≥ 4 chars)
    module_parts = normalized.replace("/", ".").split(".")
    module_last = module_parts[-1] if module_parts else ""
    target_file_stem = target_path.stem
    if len(module_last) >= 4 and module_last == target_file_stem:
        return True

    # Heuristic 3: relative path resolution for JS/TS ./.. imports
    if module.startswith(("./", "../")):
        importing_dir = Path(importing_file_rel).parent
        try:
            resolved_base = (importing_dir / module).as_posix()
            # Normalize to remove .. components
            resolved_parts = []
            for part in resolved_base.split("/"):
                if part == "..":
                    if resolved_parts:
                        resolved_parts.pop()
                else:
                    resolved_parts.append(part)
            resolved_str = "/".join(resolved_parts)
            # Ensure no escaping
            if resolved_str.startswith(".."):
                pass  # escaped repo, skip
            else:
                candidates = [
                    resolved_str,
                    resolved_str + ".ts",
                    resolved_str + ".tsx",
                    resolved_str + ".js",
                    resolved_str + ".jsx",
                    resolved_str + "/index.ts",
                    resolved_str + "/index.js",
                ]
                if target_rel in candidates:
                    return True
        except Exception:
            pass

    return False


def _code_impact_heuristic_response(root: Path, path: str, max_results: int = 50) -> dict[str, Any]:
    """Find all files that import a given file (reverse dependency analysis).

    Heuristic import detection covers Python, JavaScript, TypeScript, Go, and
    Rust (see ``_IMPORT_PARSERS``). Targets in other languages (Swift, Java,
    Kotlin, C/C++/C#, etc.) return ``unsupported_language: true`` rather than
    silently scanning every file and returning zero importers (wave 130ol).
    For graph-backed impact analysis on supported tree-sitter languages, use
    ``symbol=`` mode instead.
    """
    resolved = _resolve_repo_path(root, path)
    if resolved is None:
        return _response(
            "error", {"path": path},
            diagnostics=[_diagnostic("path_rejected", f"Path '{path}' is outside the project root or invalid.")],
            next_tools=["code_list_files"], usage="code_list_files()",
        )
    if not resolved.exists():
        return _response(
            "error", {"path": path},
            diagnostics=[_diagnostic("file_not_found", f"File '{path}' does not exist.")],
            next_tools=["code_list_files"], usage="code_list_files()",
        )

    root_r = root.resolve()
    target_rel = str(resolved.relative_to(root_r)).replace("\\", "/")

    # AC-12: explicit unsupported-language diagnostic. The heuristic only
    # detects imports in Python/JS/TS/Go/Rust; for any other suffix, scanning
    # every file in the repo to return zero importers is wasteful and
    # misleading. Surface the limitation so operators know to use a different
    # tool (or accept that heuristic impact analysis doesn't apply).
    target_suffix = resolved.suffix.lower()
    if target_suffix in _JS_TS_SUFFIXES:
        target_lang = _EXT_TO_LANG.get(target_suffix, "javascript")
    else:
        target_lang = _EXT_TO_LANG.get(target_suffix, "")
    if target_lang not in _IMPORT_PARSERS:
        supported = sorted(_IMPORT_PARSERS.keys())
        return _response(
            "ok",
            {
                "path": target_rel,
                "importers": [],
                "truncated": False,
                "total_found": 0,
                "method": "heuristic",
                "unsupported_language": True,
                "target_language": target_lang or "unknown",
                "supported_languages": supported,
            },
            diagnostics=[_diagnostic(
                "unsupported_language",
                f"Heuristic code_impact does not parse imports for language '{target_lang or 'unknown'}' "
                f"(supported: {', '.join(supported)}). For graph-backed analysis, query a symbol defined in this file with code_impact(symbol=...).",
                recovery_tools=["code_impact", "code_references"],
                recovery_usage=f"code_impact(symbol='SomeSymbolFromThisFile')",
            )],
            next_tools=["code_impact", "code_references"],
            usage=f"code_impact(symbol='SomeSymbolFromThisFile')  # graph mode",
        )

    importers: list[dict[str, Any]] = []
    total = 0
    limit_hit = max_results + 1

    for p in _walk_repo_for_navigation(root):
        file_rel = str(p.resolve().relative_to(root_r)).replace("\\", "/")
        if file_rel == target_rel:
            continue
        try:
            source = p.read_text(encoding="utf-8", errors="replace")
        except (OSError, UnicodeDecodeError):
            continue

        suffix = p.suffix.lower()
        if suffix == ".py":
            lang = "python"
        elif suffix in _JS_TS_SUFFIXES:
            lang = _EXT_TO_LANG.get(suffix, "javascript")
        else:
            lang = _EXT_TO_LANG.get(suffix, "")

        parser_entry = _IMPORT_PARSERS.get(lang)
        if not parser_entry:
            continue

        parser_fn, _ = parser_entry
        try:
            imports = parser_fn(source)
        except Exception:
            continue

        for imp in imports:
            if _match_import_to_target(imp, target_rel, file_rel):
                total += 1
                if len(importers) < max_results:
                    importers.append({
                        "file": file_rel,
                        "import_statement": imp.get("module", ""),
                        "kind": imp.get("kind", "import"),
                    })
                if total >= limit_hit:
                    break
        if total >= limit_hit:
            break

    # Wave 1p2q3 (1p2q9 Workstream D): heuristic-no-matches diagnostic.
    # When the heuristic import-walk found zero importers for a TS file, the
    # silent empty result is the highest-confusion outcome — operators see
    # `affected: []` and assume the file has no callers, but the more common
    # cause is the heuristic can't resolve aliased imports (e.g. Nx monorepo
    # `@scope/lib` aliases that don't match the file's literal repo path).
    # Surface a diagnostic recommending `symbol=` graph mode or `code_references`.
    diagnostics: list[dict[str, Any]] = []
    if total == 0 and target_lang in ("typescript", "javascript", "tsx", "jsx"):
        diagnostics.append(_diagnostic(
            "heuristic_import_no_matches",
            f"No importers found for '{target_rel}' via heuristic import-statement walk. "
            f"Common cause on TS/JS monorepos: imports use path aliases (e.g. `@scope/lib`) "
            f"that the heuristic doesn't resolve. For coverage on aliased imports, query a "
            f"specific symbol defined in this file: code_impact(symbol='SomeSymbolFromThisFile'). "
            f"To cross-check via the tree-sitter parser, use code_references(symbol='SomeSymbolFromThisFile').",
            recovery_tools=["code_impact", "code_references"],
            recovery_usage=f"code_impact(symbol='SomeSymbolFromThisFile')",
        ))
    # 1p8gy AC-5: active memory attached to the file whose impact is queried.
    _mem_advisories = _memory_advisories_for_path(root, target_rel)
    return _response(
        "ok",
        {
            "path": target_rel,
            "importers": importers,
            "truncated": total > max_results,
            "total_found": total,
            **({"memory_advisories": _mem_advisories} if _mem_advisories else {}),
            "method": "heuristic",
        },
        diagnostics=diagnostics,
        next_tools=["code_read"],
        usage=f"code_read(path='{target_rel}')",
    )


# ---------------------------------------------------------------------------
# graph_query — structural graph traversal (12xs4-feat)
# ---------------------------------------------------------------------------

def _load_graph_query():
    return _load_script("graph_query")


# Wave 1p2q3 (1p2q9 B): per-language attribution-confidence diagnostic.
# `attribution_counts_by_language` surfaces how many edges in a response carry
# each confidence tier, grouped by the source language. Operators can flag a
# coverage gap at a glance (e.g. `{typescript: {receiver_resolved: 0,
# extracted: 3892}}` means the TS receiver-type resolver isn't engaging).
#
# IMPORTANT: these tiers are EXTRACTION-TIME confidence, NOT cross-file
# resolution outcomes. `receiver_resolved` counts edges whose receiver TYPE was
# determined at graph-build — even when the call's target stays `external::`
# (type known, but not bound to a project node). A target rebind
# (`external::Foo.bar` → a project node) does NOT move an edge between tiers, so
# a cross-file resolution improvement that rebinds targets leaves these AGGREGATE
# counts flat while per-symbol incoming-edge counts (`code_impact` on the now-
# bound node) rise — the two views are orthogonal, not inconsistent. To gauge
# cross-file resolution SUCCESS, count `receiver_resolved` edges whose target is
# a project node (not `external::`), not this tier total.

_ATTR_LANG_BY_EXTENSION: dict[str, str] = {
    ".py": "python",
    ".ts": "typescript", ".tsx": "typescript", ".mts": "typescript", ".cts": "typescript",
    ".js": "javascript", ".jsx": "javascript", ".mjs": "javascript", ".cjs": "javascript",
    ".java": "java", ".kt": "kotlin", ".kts": "kotlin",
    ".cs": "csharp", ".swift": "swift", ".go": "go", ".rs": "rust",
    ".rb": "ruby", ".php": "php",
    ".c": "c", ".h": "c", ".cpp": "cpp", ".cc": "cpp", ".cxx": "cpp", ".hpp": "cpp", ".hxx": "cpp",
    ".scala": "scala", ".m": "objc", ".mm": "objc",
}

_ATTR_CONFIDENCE_BUCKETS = ("receiver_resolved", "construction_resolved", "extracted")


def _attribution_language_for_node(node_id: str | None, index: Any) -> str:
    if not node_id or not isinstance(node_id, str):
        return ""
    if node_id.startswith("external::"):
        return ""
    source_file = ""
    try:
        node = index.get_node(node_id) if hasattr(index, "get_node") else None
    except Exception:
        node = None
    if node:
        source_file = str(node.get("source_file") or "")
    if not source_file and "::" in node_id:
        source_file = node_id.split("::", 1)[0]
    elif not source_file:
        source_file = node_id
    if not source_file:
        return ""
    suffix = Path(source_file).suffix.lower()
    return _ATTR_LANG_BY_EXTENSION.get(suffix, "")


def _compute_attribution_counts_by_language(edges: Any, index: Any) -> dict[str, dict[str, int]]:
    """Return `{language: {receiver_resolved, construction_resolved, extracted}}`
    over the supplied edges. Edges without a known confidence tier or a
    resolvable source-language are skipped silently — the diagnostic only
    surfaces confident attribution data.

    NOTE: buckets are extraction-time confidence tiers, not resolution outcomes —
    a `receiver_resolved` edge may still target `external::` (receiver type known,
    target not bound to a project node). See the module comment above the
    `_ATTR_*` tables for why a cross-file resolution gain leaves these aggregate
    counts flat (it rebinds targets within the same tier)."""
    counts: dict[str, dict[str, int]] = {}
    if not edges:
        return counts
    for e in edges:
        if not isinstance(e, dict):
            continue
        bucket_key = str(e.get("confidence") or "").strip().lower()
        if bucket_key not in _ATTR_CONFIDENCE_BUCKETS:
            continue
        lang = ""
        for nid in (e.get("source"), e.get("target")):
            lang = _attribution_language_for_node(nid, index)
            if lang:
                break
        if not lang:
            continue
        bucket = counts.setdefault(lang, {k: 0 for k in _ATTR_CONFIDENCE_BUCKETS})
        bucket[bucket_key] += 1
    return counts


# Wave 1p2q3 (131hh): URIs whose contents may change when the graph rebuilds.
# Notifications dispatched fire-and-forget — see _dispatch_graph_resources_updated.
_GRAPH_RESOURCE_URIS = (
    "wavefoundry://graph/status",
    "wavefoundry://graph/communities",
)

# Module-global FastMCP instance, set by register_mcp_surface so the post-rebuild
# callback registered on graph_query can resolve the active session without
# circular imports. None when register_mcp_surface has not run (e.g., test
# harness importing server_impl directly).
_MCP_INSTANCE: Any = None


def _dispatch_graph_resources_updated(*, root: Path | None = None, layer: str | None = None) -> None:
    """Send `notifications/resources/updated` for each wavefoundry://graph/* URI.

    Mirrors the `send_tool_list_changed` pattern from server.py: schedule the
    coroutine on the running event loop when one exists, otherwise fall through
    silently. Best-effort — exceptions are swallowed so query results are not
    affected by notification delivery problems.
    """
    if _MCP_INSTANCE is None:
        return
    try:
        ctx = _MCP_INSTANCE.get_context()
        session = ctx.request_context.session
    except Exception:
        return
    try:
        import asyncio
        from pydantic import AnyUrl
        try:
            loop = asyncio.get_running_loop()
        except RuntimeError:
            loop = None
        for uri_str in _GRAPH_RESOURCE_URIS:
            try:
                uri = AnyUrl(uri_str)
            except Exception:
                continue
            try:
                if loop is not None:
                    loop.create_task(session.send_resource_updated(uri))
                else:
                    asyncio.run(session.send_resource_updated(uri))
            except Exception:
                continue
    except Exception:
        return


def _suggest_near_symbols(index: Any, query: str, n: int = 3) -> list[dict[str, Any]]:
    """Return up to n near-match candidates when resolve_symbol() returned None.

    Candidates are ranked by match quality: exact suffix/id > label exact > id substring >
    label substring > all-tokens in id > all-tokens in label. Tokens are derived by splitting
    on whitespace and underscores so 'load cluster' matches `_load_cluster_lookup` and
    'shortest path' matches `shortest_path`. Within each tier, shorter ids rank first.
    Called only on error paths; O(N) scan is acceptable for infrequent miss recovery.
    """
    query_lower = query.strip().lower()
    if not query_lower:
        return []
    suffix_key = f"::{query_lower}"
    tokens = [t for t in re.split(r"[\s_]+", query_lower) if t]
    multi_token = len(tokens) > 1
    # Six quality buckets, highest confidence first.
    buckets: list[list[tuple[int, str, dict[str, Any]]]] = [[], [], [], [], [], []]
    for nid, node in index._node_by_id.items():
        nid_lower = nid.lower()
        label_lower = str(node.get("label") or "").lower()
        if nid_lower.endswith(suffix_key) or nid_lower == query_lower:
            buckets[0].append((len(nid), nid, node))
        elif label_lower == query_lower:
            buckets[1].append((len(nid), nid, node))
        elif query_lower in nid_lower:
            buckets[2].append((len(nid), nid, node))
        elif query_lower in label_lower:
            buckets[3].append((len(nid), nid, node))
        elif multi_token and all(tok in nid_lower for tok in tokens):
            buckets[4].append((len(nid), nid, node))
        elif multi_token and all(tok in label_lower for tok in tokens):
            buckets[5].append((len(nid), nid, node))
    results: list[dict[str, Any]] = []
    seen: set[str] = set()
    for bucket in buckets:
        for _, nid, node in sorted(bucket, key=lambda x: x[0]):
            if nid not in seen:
                results.append({"id": nid, "label": node.get("label", nid), "kind": node.get("kind")})
                seen.add(nid)
            if len(results) >= n:
                return results
    return results


def _suggest_near_communities(
    communities: list[dict[str, Any]], query: str, n: int = 5
) -> list[dict[str, Any]]:
    """Return up to n near-match communities ranked by id/label substring then node count."""
    query_lower = (query or "").strip().lower()
    # Buckets: 0=substring in community_id, 1=substring in label, 2=fallback by size
    buckets: list[list[tuple[int, dict[str, Any]]]] = [[], [], []]
    for c in communities:
        cid = str(c.get("community_id") or "")
        if not cid:
            continue
        label = str(c.get("label") or "")
        node_count = int(c.get("node_count") or 0)
        entry = {"community_id": cid, "label": label, "node_count": node_count}
        if query_lower and query_lower in cid.lower():
            buckets[0].append((-node_count, entry))
        elif query_lower and query_lower in label.lower():
            buckets[1].append((-node_count, entry))
        else:
            buckets[2].append((-node_count, entry))
    results: list[dict[str, Any]] = []
    seen: set[str] = set()
    for bucket in buckets:
        for _, entry in sorted(bucket, key=lambda x: x[0]):
            cid = entry["community_id"]
            if cid in seen:
                continue
            results.append(entry)
            seen.add(cid)
            if len(results) >= n:
                return results
    return results


def _load_cluster_lookup(root: Path, layer: str = "project") -> dict[str, str]:
    """Return node_id → community_label mapping from the cluster artifact.

    Returns an empty dict when the artifact is absent or cannot be loaded.

    Preserved for backward compatibility with call sites that only need the
    label. Use ``_load_cluster_lookup_with_ids`` (wave 130rj) when the
    response shape includes both ``community`` and ``community_id``.
    """
    try:
        gc = _load_script("graph_cluster")
        payload = gc.read_cluster_payload(root, layer)
        if not payload.get("present"):
            return {}
        lookup: dict[str, str] = {}
        for community in (payload.get("communities") or []):
            label = str(community.get("label") or "")
            for nid in (community.get("node_ids") or []):
                lookup[str(nid)] = label
        return lookup
    except Exception:
        return {}


def _load_cluster_lookup_with_ids(root: Path, layer: str = "project") -> dict[str, tuple[str, str]]:
    """Return node_id → (community_label, community_id) mapping (wave 130rj).

    Field feedback §1.1: every tool that surfaces a community label
    should also expose the community_id needed to drill in via
    ``code_graph_community``. Returning both eliminates the failed-call
    recovery dance documented in the feedback report.

    Returns an empty dict when the cluster artifact is absent.
    """
    try:
        gc = _load_script("graph_cluster")
        payload = gc.read_cluster_payload(root, layer)
        if not payload.get("present"):
            return {}
        lookup: dict[str, tuple[str, str]] = {}
        for community in (payload.get("communities") or []):
            label = str(community.get("label") or "")
            community_id = str(community.get("community_id") or "")
            for nid in (community.get("node_ids") or []):
                lookup[str(nid)] = (label, community_id)
        return lookup
    except Exception:
        return {}


def _graph_references_candidate_files(root: Path, symbol: str) -> frozenset[str] | None:
    """Return files the graph says reference symbol, or None if graph unavailable/empty."""
    try:
        gq = _load_graph_query()
        index = gq.get_query_index(root, layer="project")
        if not index.present:
            return None
        node_id = index.resolve_symbol(symbol)
        if node_id is None:
            return None
        files: set[str] = set()
        for edge in index._in.get(node_id, []):
            src = edge.get("source")
            if not isinstance(src, str) or src.startswith("external::"):
                continue
            src_node = index.get_node(src)
            if src_node:
                sf = src_node.get("source_file")
                if isinstance(sf, str) and sf:
                    files.add(sf)
            elif "::" in src:
                files.add(src.split("::")[0])
            else:
                files.add(src)
        return frozenset(files) if files else None
    except Exception:
        return None


def _extract_java_owner_class_from_node_id(node_id: str) -> str | None:
    """Parse owner class name from a Java graph node_id.

    Node IDs have format ``<file>::<symbol>``. For Java the symbol part is
    ``<Class>.<method>`` or ``<Outer>.<Inner>.<method>`` etc. Return the
    simple class name (last `.`-segment before the method), or None when
    the symbol is bare (no class context).
    """
    if not node_id or "::" not in node_id:
        return None
    symbol_part = node_id.rsplit("::", 1)[-1]
    if "." not in symbol_part:
        return None
    # Drop the trailing method name; take the last segment of what remains.
    class_path = symbol_part.rsplit(".", 1)[0]
    return class_path.rsplit(".", 1)[-1] or None


