def _annotate_java_call_sites_with_receiver_type(
    path: Path,
    callee_label: str,
    refs: list[dict[str, Any]],
) -> list[dict[str, Any]]:
    """Annotate Java call-site refs with ``_receiver_type`` field.

    Each ref's ``_receiver_type`` is the resolved simple class name of the
    method_invocation's receiver, or None when uncertain (preserve per
    false-positive bias). Refs whose line has no matching method_invocation
    candidate get ``_receiver_type: None``.
    """
    try:
        source = path.read_text(encoding="utf-8", errors="replace")
        # Wave 1p3hd: shared cache.
        tree = _cached_ts_parse(path.resolve(), "java", source)
    except Exception:
        return refs
    if tree is None:
        return refs
    source_bytes = source.encode("utf-8", errors="replace")
    line_to_invocations: dict[int, list] = {}
    stack = [tree.root_node]
    while stack:
        n = stack.pop()
        if getattr(n, "type", "") == "method_invocation":
            name_node = n.child_by_field_name("name")
            if name_node is not None:
                name_text = source_bytes[name_node.start_byte:name_node.end_byte].decode("utf-8", errors="replace")
                if name_text == callee_label:
                    line = n.start_point[0] + 1
                    line_to_invocations.setdefault(line, []).append(n)
        stack.extend(reversed(getattr(n, "children", []) or []))
    for ref in refs:
        line = ref.get("line") or 0
        invocations = line_to_invocations.get(line, [])
        if not invocations:
            ref["_receiver_type"] = None
            continue
        # If multiple invocations on one line, take the first resolvable one.
        resolved: str | None = None
        for inv in invocations:
            r = _resolve_java_receiver_type(inv, source_bytes)
            if r is not None:
                resolved = r
                break
        ref["_receiver_type"] = resolved
    return refs


def _scan_call_sites_in_file(root: Path, callee_label: str, source_file: str) -> list[dict[str, Any]]:
    """Scan source_file for call sites of callee_label. Returns list sorted by line.

    For Java files, each ref carries a ``_receiver_type`` annotation
    (simple class name of the method_invocation's receiver, or None when
    uncertain). Callers use the annotation to filter phantom cross-class
    callers when the queried symbol's owning class is known (wave 130rj —
    130tw).
    """
    p = root / source_file
    if not p.is_file():
        return []
    files = [p]
    restrict = frozenset({source_file})
    if source_file.endswith(".py"):
        refs = _python_reference_call_sites(root, callee_label, restrict_files=restrict, _files=files)
    else:
        ts_refs = _treesitter_references(root, callee_label, restrict_files=restrict, _files=files)
        refs = [r for r in ts_refs if r.get("reference_kind") == "call_sites"]
        if not refs:
            text_refs = _non_python_references(root, callee_label, restrict_files=restrict, _files=files)
            refs = [r for r in text_refs if r.get("reference_kind") == "call_sites"]
        if source_file.endswith(".java") and refs:
            refs = _annotate_java_call_sites_with_receiver_type(p, callee_label, refs)
    return sorted(refs, key=lambda r: r.get("line") or 0)


def _scan_all_call_sites_in_file(
    root: Path, callee_labels: list[str], source_file: str
) -> dict[str, list[dict[str, Any]]]:
    """Scan source_file once for all callee_labels. Returns dict: label → sorted call sites."""
    if not callee_labels:
        return {}
    p = root / source_file
    result: dict[str, list[dict[str, Any]]] = {label: [] for label in callee_labels}
    if not p.is_file():
        return result
    label_set = set(callee_labels)
    if source_file.endswith(".py"):
        import ast as _ast
        try:
            source = p.read_text(encoding="utf-8", errors="replace")
            tree = _ast.parse(source, filename=str(p))
        except (SyntaxError, OSError):
            return result
        lines = source.splitlines()
        for node in _ast.walk(tree):
            if not isinstance(node, _ast.Call):
                continue
            func = node.func
            matched_label: str | None = None
            if isinstance(func, _ast.Name) and func.id in label_set:
                matched_label = func.id
            elif isinstance(func, _ast.Attribute) and func.attr in label_set:
                matched_label = func.attr
            if matched_label is None:
                continue
            line = getattr(node, "lineno", 0)
            if line <= 0 or line > len(lines):
                continue
            result[matched_label].append({
                "path": source_file,
                "line": line,
                "snippet": lines[line - 1].rstrip(),
                "language": "python",
                "method": "ast",
                "reference_kind": "call_sites",
            })
        for label in result:
            result[label].sort(key=lambda r: r.get("line") or 0)
    else:
        files = [p]
        restrict = frozenset({source_file})
        for label in callee_labels:
            ts_refs = _treesitter_references(root, label, restrict_files=restrict, _files=files)
            refs = [r for r in ts_refs if r.get("reference_kind") == "call_sites"]
            if not refs:
                text_refs = _non_python_references(root, label, restrict_files=restrict, _files=files)
                refs = [r for r in text_refs if r.get("reference_kind") == "call_sites"]
            result[label] = sorted(refs, key=lambda r: r.get("line") or 0)
    return result


def _first_call_site_at_or_after(call_sites: list[dict[str, Any]], start_line: int) -> dict[str, Any] | None:
    """Return first call site at or after start_line, or None if none found."""
    for ref in call_sites:
        if (ref.get("line") or 0) >= start_line:
            return ref
    return None


def _graph_layer_value(layer: str) -> str:
    # Wave 1p4ww: single project graph. The framework/union layers were removed
    # (the separate framework graph is gone), so every request resolves to the
    # one project graph. The ``layer`` arg is retained as a harmless no-op for
    # back-compat with callers that still pass it.
    return "project"


def _maybe_append_graph_neighbors(
    response: dict[str, Any],
    root: Path,
    *,
    graph: bool,
    node_ids: list[str],
    layer: str = "project",
    max_nodes: int = 50,
) -> dict[str, Any]:
    if not graph or response.get("status") != "ok":
        return response
    unique_ids = [nid for nid in dict.fromkeys(node_ids) if nid]
    if not unique_ids:
        return response
    try:
        gq = _load_graph_query()
        index = gq.get_query_index(root, layer=_graph_layer_value(layer))
        if not index.present:
            return response
        neighbors = index.one_hop_neighbors(unique_ids)
        # Wave 1p4ls: `reads` is opt-in for default traversal (so a hot constant never balloons a
        # 1p4hu expansion), but when a SEED is itself a constant the caller is asking about that
        # constant — include its reader edges. Bounded by the max_nodes cap below.
        const_seeds = [nid for nid in unique_ids if (index.get_node(nid) or {}).get("kind") == "constant"]
        if const_seeds:
            reads_nb = index.one_hop_neighbors(const_seeds, relations=["reads"])
            _seen_n = {n["id"] for n in neighbors.get("nodes", []) if isinstance(n.get("id"), str)}
            for n in reads_nb.get("nodes", []):
                if isinstance(n.get("id"), str) and n["id"] not in _seen_n:
                    neighbors["nodes"].append(n)
                    _seen_n.add(n["id"])
            _seen_e = {(e.get("source"), e.get("target"), e.get("relation")) for e in neighbors.get("edges", [])}
            for e in reads_nb.get("edges", []):
                k = (e.get("source"), e.get("target"), e.get("relation"))
                if k not in _seen_e:
                    neighbors["edges"].append(e)
                    _seen_e.add(k)
        if not neighbors.get("nodes"):
            return response
        if max_nodes > 0 and len(neighbors["nodes"]) > max_nodes:
            kept_nodes = neighbors["nodes"][:max_nodes]
            kept_ids = {n["id"] for n in kept_nodes if isinstance(n.get("id"), str)}
            kept_edges = [
                e for e in neighbors.get("edges") or []
                if e.get("source") in kept_ids and e.get("target") in kept_ids
            ]
            neighbors = {**neighbors, "nodes": kept_nodes, "edges": kept_edges, "truncated": True}
        data = dict(response.get("data") or {})
        data["graph_neighbors"] = neighbors
        return {**response, "data": data}
    except Exception:
        return response


def _inject_timing(result: dict[str, Any], t_start: float, tool: str = "") -> dict[str, Any]:
    total_ms = round((time.monotonic() - t_start) * 1000)
    if tool:
        _wf_log(f"[wavefoundry] {tool} timing: total={total_ms}ms")
    data = dict(result.get("data") or {})
    data["total_ms"] = total_ms
    return {**result, "data": data}


def _graph_seed_node_ids(data: dict[str, Any], tool: str) -> list[str]:
    """Collect graph node id seeds from a tool response data payload."""
    ids: list[str] = []
    if tool in ("code_keyword", "code_search"):
        for row in data.get("results") or []:
            if isinstance(row, dict):
                path = row.get("path")
                if isinstance(path, str) and path:
                    ids.append(path)
    elif tool == "code_definition":
        for row in data.get("definitions") or []:
            if not isinstance(row, dict):
                continue
            path = row.get("path")
            name = row.get("name")
            if isinstance(path, str) and path:
                if isinstance(name, str) and name:
                    ids.append(f"{path}::{name}")
                else:
                    ids.append(path)
    elif tool == "code_references":
        for row in data.get("references") or []:
            if isinstance(row, dict):
                path = row.get("path")
                if isinstance(path, str) and path:
                    ids.append(path)
    return ids


def _graph_refresh_then_recheck(
    root: Path,
    recheck_fn: Callable[[], Any],
) -> Any:
    """Run an incremental graph update, then re-call ``recheck_fn`` and return its result.

    Wave 1304x / 1304r: shared helper used by every graph-using MCP tool when its
    initial graph query returns no result. Incremental refresh is ~4ms when nothing
    has changed (measured during wave 12xr3 close-review), so it's cheap to attempt
    inline. Returns ``None`` on any exception so callers fall through to their
    existing not-found / suggestions path without surfacing the refresh error;
    exceptions are logged to stderr via ``_wf_log`` so operators see real failures
    rather than silent degradation.

    Usage pattern:
        candidate = primary_query(...)
        if candidate is None or empty:
            candidate = _graph_refresh_then_recheck(root, lambda: primary_query(...))
            if candidate:
                # found after refresh — proceed
            else:
                # genuinely missing — emit suggestions / not-found
    """
    try:
        index_build_response(root, content="graph", mode="update")
    except Exception as exc:
        _wf_log(f"[wavefoundry] graph refresh failed during recheck: {exc!r}")
        return None
    # Wave 1p9q3 (1p9pz): the refresh may have rewritten the graph payload —
    # explicitly drop the cached constructed index so the recheck reloads even
    # if the rewrite landed with identical (mtime_ns, size).
    try:
        _load_graph_query().invalidate_query_index_cache(root)
    except Exception:
        pass
    try:
        return recheck_fn()
    except Exception as exc:
        _wf_log(f"[wavefoundry] recheck closure failed after graph refresh: {exc!r}")
        return None


def _graph_refresh_and_resolve(
    root: Path,
    symbol: str,
    layer: str = "project",
) -> tuple[Any, Optional[str]]:
    """Refresh graph, reload index, resolve symbol — convenience for resolve-symbol callers.

    Returns ``(fresh_index, node_id)`` on success or ``(None, None)`` on refresh
    failure or symbol-still-missing. The caller should swap its existing ``index``
    for ``fresh_index`` so subsequent traversal sees the new graph state (the
    original ``index`` is a stale snapshot).

    Note: returns ``(None, None)`` even when the refresh succeeded but the specific
    symbol still doesn't resolve — callers that need the fresh index for *other*
    symbols (e.g. ``code_graph_path`` with two symbols) should use
    ``_graph_refresh_then_recheck`` directly with a recheck closure that returns
    everything they need to reuse.
    """
    try:
        index_build_response(root, content="graph", mode="update")
    except Exception as exc:
        _wf_log(f"[wavefoundry] graph refresh failed during resolve: {exc!r}")
        return None, None
    try:
        gq = _load_graph_query()
        # Known rewrite: drop the cached index so the re-read reloads even on
        # a same-(mtime_ns, size) rewrite (coarse-mtime filesystems).
        try:
            gq.invalidate_query_index_cache(root)
        except Exception:
            pass
        new_index = gq.get_query_index(root, layer=layer)
    except Exception as exc:
        _wf_log(f"[wavefoundry] graph index reload failed after refresh: {exc!r}")
        return None, None
    node_id = new_index.resolve_symbol(symbol)
    if node_id is None:
        return None, None
    return new_index, node_id


def _augment_with_graph_neighbors_if_enabled(
    result: dict[str, Any],
    root: Path,
    *,
    tool_key: str,
    graph: bool,
    graph_limit: int = 5,
    layer: str = "project",
) -> dict[str, Any]:
    """Apply opt-out-able graph augmentation to a tool response.

    Used by `code_keyword`, `code_search`, `code_definition`, `code_references`
    MCP wrappers. Returns ``result`` unchanged when ``graph=False``. Otherwise
    collects seed node ids via ``_graph_seed_node_ids(data, tool_key)``, caps
    at ``graph_limit`` (default 5, ``0`` means no cap), and appends
    ``graph_neighbors`` via ``_maybe_append_graph_neighbors``.

    Extracted so the wrapper logic is unit-testable without invoking the
    FastMCP tool registry (wave 12xr3 / 12xs5 wrapper-test gap closure).
    """
    if not graph:
        return result
    data = result.get("data") or {}
    seeds = _graph_seed_node_ids(data, tool_key)
    return _maybe_append_graph_neighbors(
        result,
        root,
        graph=True,
        node_ids=seeds[:graph_limit] if graph_limit > 0 else seeds,
        layer=layer,
    )


def _code_impact_graph_response(
    root: Path,
    symbol: str,
    *,
    max_hops: int = 3,
    layer: str = "project",
    relations: Optional[list[str]] = None,
    max_results: int = 50,
    include_tests: bool = False,
) -> dict[str, Any]:
    # Wave 1p4eq (1p4es hardening): clamp negative max_results to 0. A negative
    # value would otherwise hit Python's drop-last-N slice semantics
    # (`edges[:-1]` returns all-but-one) rather than an empty/capped result.
    max_results = max(0, max_results)
    gq = _load_graph_query()
    try:
        layer_value = _graph_layer_value(layer)
    except ValueError as exc:
        return _response(
            "error",
            {"symbol": symbol, "method": "graph"},
            diagnostics=[_diagnostic("invalid_arguments", str(exc))],
            next_tools=["wf_help"],
            usage="code_impact(symbol='path::symbol', layer='project')",
        )
    index = gq.get_query_index(root, layer=layer_value)
    if not index.present:
        return _response(
            "error",
            {"symbol": symbol, "method": "graph", "layer": layer_value},
            diagnostics=[gq.graph_not_ready_diagnostic(layer_value)],
            next_tools=["index_build"],
            usage="index_build(content='graph', mode='create')",
        )
    impact = index.graph_impact(symbol, max_hops=max(1, max_hops), relations=relations)
    if not impact.get("resolved"):
        # Wave 1304x / 1304r: refresh-then-resolve before emitting suggestions
        new_index, refreshed_id = _graph_refresh_and_resolve(root, symbol, layer=layer_value)
        if refreshed_id is not None:
            index = new_index
            impact = index.graph_impact(symbol, max_hops=max(1, max_hops), relations=relations)
    if not impact.get("resolved"):
        # Wave 1sbfi (1sbfh): a simple name matching MULTIPLE distinct external
        # supertype ids stays unresolved by design (never silently merged) —
        # surface the grouped breakdown so the caller can re-query with the
        # exact ``external::`` id (council amendment: distinct-id grouping).
        ext_groups = []
        try:
            ext_groups = index.external_supertype_group(symbol)
        except AttributeError:
            pass  # older loaded index module without the helper
        if len(ext_groups) > 1:
            return _response(
                "ok",
                {
                    "symbol": symbol,
                    "resolved": False,
                    "method": "graph",
                    "layer": layer_value,
                    "external_candidates": ext_groups,
                },
                diagnostics=[_diagnostic(
                    "external_supertype_ambiguous",
                    f"'{symbol}' matches {len(ext_groups)} distinct external supertypes "
                    f"(declared with different qualifications). Re-query with the exact id, "
                    f"e.g. code_impact(symbol={ext_groups[0]['id']!r}).",
                )],
                next_tools=["code_impact"],
                usage=f"code_impact(symbol={ext_groups[0]['id']!r}, max_hops=2)",
            )
        suggestions = _suggest_near_symbols(index, symbol)
        return _response(
            "error",
            {"symbol": symbol, "method": "graph", "layer": layer_value, "suggestions": suggestions},
            diagnostics=[_diagnostic(
                "graph_symbol_not_found",
                f"Symbol '{symbol}' does not resolve to a graph node (refresh attempted).",
                recovery_tools=["code_definition", "code_keyword"],
                recovery_usage=f"code_definition(symbol_or_path_position={symbol!r})",
            )],
            next_tools=["code_definition"],
            usage=f"code_definition(symbol_or_path_position={symbol!r})",
        )
    community_lookup = _load_cluster_lookup_with_ids(root, layer_value)
    affected_raw = impact.get("affected") or []
    if not include_tests:
        affected_raw = [a for a in affected_raw if not _is_test_path(str(a.get("source_file") or ""))]
    # Attach community label + id to each affected node (wave 130rj — community label
    # and id dual return per field feedback §1.1).
    def _with_community(a: dict) -> dict:
        c_label, c_id = community_lookup.get(a.get("node_id", ""), (None, None))
        return {**a, "community": c_label, "community_id": c_id}
    affected_enriched = [_with_community(a) for a in affected_raw]
    truncated = len(affected_enriched) > max_results
    # Recompute affected_files after test filter
    affected_files = sorted({str(a.get("source_file") or "") for a in affected_enriched if a.get("source_file")})
    impact_edges = impact.get("edges") or []
    # Wave 1p4es: bound the edges array by max_results. On a high-fan-in symbol
    # (field report: rethrowError, 754 edges) the UNBOUNDED array blew the
    # MCP token cap (~227K chars) even though max_results capped `affected` — the
    # edges list was the size driver. The full list still feeds the attribution
    # counts (accurate); the response carries at most max_results edges plus
    # edges_total so the caller knows the real count (re-query with a higher
    # max_results, or use code_callgraph for the full edge set).
    edges_total = len(impact_edges)
    edges_truncated = edges_total > max_results
    response_edges = impact_edges[:max_results]
    # Wave 1sbfi (1sbfh): external-supertype visibility. When the resolved
    # seed IS an external supertype (blast radius = its project implementors/
    # subtypes + their dependents), label it so consumers never mistake it
    # for a project node. On any seed, surface the node's declared supertypes
    # (project + external, with always-on external counts) — a class whose
    # only supertypes are external no longer reads as "no edges".
    _resolved_id = str(impact.get("node_id") or "")
    _extra: dict[str, Any] = {}
    if _resolved_id.startswith("external::"):
        _extra["external_target"] = True
        _extra["external_name"] = _resolved_id[len("external::"):]
    try:
        _supers = index.supertype_summary(_resolved_id)
    except AttributeError:
        _supers = None
    if _supers:
        _extra["supertypes"] = _supers
    # 1p8gy AC-5: active memory attached to the impacted symbol/file.
    _mem_advisories = _memory_advisories_for_path(
        root, _resolved_id.split("::", 1)[0] if "::" in _resolved_id else "", symbol=symbol,
    )
    if _mem_advisories:
        _extra["memory_advisories"] = _mem_advisories
    return _attach_auto_rebuild_diag(
        _response(
            "ok",
            {
                "symbol": symbol,
                # Wave 1p4es: documented response field that was never emitted →
                # came back null (field report). At the OK path the symbol is resolved.
                "resolved": True,
                "node_id": impact.get("node_id"),
                **_extra,
                "layer": layer_value,
                "method": "graph",
                "max_hops": max_hops,
                "relations": impact.get("relations") or [],
                "include_tests": include_tests,
                "affected": affected_enriched[:max_results],
                "affected_files": affected_files,
                "edges": response_edges,
                "edges_total": edges_total,
                "truncated": truncated or edges_truncated,
                "total_found": len(affected_enriched),
                # Wave 1p2q3 (1p2q9 B): per-language attribution-confidence counts.
                "attribution_counts_by_language": _compute_attribution_counts_by_language(impact_edges, index),
            },
            next_tools=["code_callgraph", "code_read"],
            usage=f"code_callgraph(symbol={symbol!r}, direction='both')",
        ),
        index,
    )


def code_impact_response(
    root: Path,
    path: str = "",
    max_results: int = 50,
    *,
    symbol: str = "",
    max_hops: int = 3,
    layer: str = "project",
    relations: Optional[list[str]] = None,
    include_tests: bool = False,
) -> dict[str, Any]:
    """Reverse dependency / impact analysis — heuristic (path) or graph-backed (symbol)."""
    if symbol.strip():
        return _code_impact_graph_response(
            root,
            symbol.strip(),
            max_hops=max_hops,
            layer=layer,
            relations=relations,
            max_results=max_results,
            include_tests=include_tests,
        )
    if not path.strip():
        return _response(
            "error",
            {"path": path, "symbol": symbol},
            diagnostics=[_diagnostic("invalid_arguments", "Provide path= for heuristic mode or symbol= for graph mode.")],
            next_tools=["code_impact"],
            usage="code_impact(path='src/module.py')",
        )
    return _code_impact_heuristic_response(root, path, max_results)


def code_risk_score_response(
    root: Path,
    scope: str = "",
    *,
    top: int = 20,
    max_hops: int = 3,
    candidate_cap: int = 200,
    layer: str = "project",
    include_tests: bool = False,
) -> dict[str, Any]:
    """Rank in-scope symbols by composite change-risk (blast-radius × degree) — wave 1p41o."""
    if not scope.strip():
        return _response(
            "error",
            {"scope": scope},
            diagnostics=[_diagnostic("invalid_arguments", "Provide scope= (a file path, directory prefix, or glob) to rank.")],
            next_tools=["code_risk_score"],
            usage="code_risk_score(scope='src/module.py')",
        )
    gq = _load_graph_query()
    try:
        layer_value = _graph_layer_value(layer)
    except ValueError as exc:
        return _response(
            "error",
            {"scope": scope},
            diagnostics=[_diagnostic("invalid_arguments", str(exc))],
            next_tools=["wf_help"],
            usage="code_risk_score(scope='src/', layer='project')",
        )
    index = gq.get_query_index(root, layer=layer_value)
    if not index.present:
        return _response(
            "error",
            {"scope": scope, "layer": layer_value},
            diagnostics=[gq.graph_not_ready_diagnostic(layer_value)],
            next_tools=["index_build"],
            usage="index_build(content='graph', mode='create')",
        )
    result = index.risk_score(
        scope.strip(),
        max_hops=max(1, max_hops),
        top=top,
        candidate_cap=candidate_cap,
        is_test_path=None if include_tests else _is_test_path,
    )
    if result.get("over_candidate_cap"):
        return _response(
            "error",
            {**result, "include_tests": include_tests},
            diagnostics=[_diagnostic(
                "scope_too_large",
                f"{result.get('candidate_count')} candidate symbols in scope exceeds the cap "
                f"({result.get('candidate_cap')}); narrow scope= to a file or subdirectory so the "
                f"per-symbol blast-radius BFS stays bounded.",
            )],
            next_tools=["code_risk_score", "code_list_files"],
            usage="code_risk_score(scope='src/submodule/')",
        )
    next_tools = ["code_impact", "code_read"] if result.get("results") else ["code_list_files", "code_outline"]
    return _attach_auto_rebuild_diag(
        _response(
            "ok",
            {**result, "layer": layer_value, "include_tests": include_tests},
            next_tools=next_tools,
            usage="code_impact(symbol='path::symbol') to size a single symbol's blast radius",
        ),
        index,
    )


def code_callgraph_response(
    root: Path,
    symbol: str,
    *,
    depth: int = 1,
    direction: str = "both",
    layer: str = "project",
    include_tests: bool = False,
) -> dict[str, Any]:
    gq = _load_graph_query()
    try:
        layer_value = _graph_layer_value(layer)
    except ValueError as exc:
        return _response(
            "error",
            {"symbol": symbol},
            diagnostics=[_diagnostic("invalid_arguments", str(exc))],
            next_tools=["wf_help"],
            usage="code_callgraph(symbol='path::symbol')",
        )
    direction_value = (direction or "both").strip().lower()
    if direction_value not in ("callers", "callees", "both"):
        return _response(
            "error",
            {"symbol": symbol, "direction": direction},
            diagnostics=[_diagnostic("invalid_arguments", "direction must be callers, callees, or both.")],
            next_tools=["code_callgraph"],
            usage="code_callgraph(symbol='path::symbol', direction='both')",
        )
    index = gq.get_query_index(root, layer=layer_value)
    if not index.present:
        return _response(
            "error",
            {"symbol": symbol, "layer": layer_value},
            diagnostics=[gq.graph_not_ready_diagnostic(layer_value)],
            next_tools=["index_build"],
            usage="index_build(content='graph', mode='create')",
        )
    result = index.callgraph(symbol, depth=max(1, depth), direction=direction_value)  # type: ignore[arg-type]
    if not result.get("resolved"):
        # Wave 1304x / 1304r: refresh-then-resolve before emitting suggestions
        new_index, refreshed_id = _graph_refresh_and_resolve(root, symbol, layer=layer_value)
        if refreshed_id is not None:
            index = new_index
            result = index.callgraph(symbol, depth=max(1, depth), direction=direction_value)  # type: ignore[arg-type]
    if not result.get("resolved"):
        suggestions = _suggest_near_symbols(index, symbol)
        return _response(
            "error",
            {"symbol": symbol, "layer": layer_value, "suggestions": suggestions},
            diagnostics=[_diagnostic(
                "graph_symbol_not_found",
                f"Symbol '{symbol}' does not resolve to a graph node (refresh attempted).",
                recovery_tools=["code_definition", "code_keyword"],
                recovery_usage=f"code_definition(symbol_or_path_position={symbol!r})",
            )],
            next_tools=["code_definition"],
            usage=f"code_definition(symbol_or_path_position={symbol!r})",
        )

    if not include_tests:
        nodes_kept = [
            n for n in (result.get("nodes") or [])
            if not _is_test_path(str(n.get("source_file") or ""))
        ]
        kept_ids = {n.get("id") for n in nodes_kept if n.get("id")}
        edges_kept = [
            e for e in (result.get("edges") or [])
            if e.get("source") in kept_ids and e.get("target") in kept_ids
        ]
        result["nodes"] = nodes_kept
        result["edges"] = edges_kept

    # Enrich call edges with call-site line numbers via targeted file scan
    _node_map: dict[str, dict[str, Any]] = {
        n["id"]: n for n in (result.get("nodes") or []) if isinstance(n.get("id"), str)
    }
    # Pre-collect all (src_file → callee_labels) and batch-scan each file once
    _file_callees: dict[str, set[str]] = {}
    for edge in (result.get("edges") or []):
        if edge.get("relation") != "calls":
            continue
        src_id = str(edge.get("source") or "")
        tgt_id = str(edge.get("target") or "")
        if src_id.startswith("external::"):
            continue
        src_node = _node_map.get(src_id) or {}
        tgt_node = _node_map.get(tgt_id) or {}
        src_file = src_node.get("source_file") or (src_id.split("::")[0] if "::" in src_id else "")
        callee_label = tgt_node.get("label") or (tgt_id.rsplit("::", 1)[-1] if "::" in tgt_id else tgt_id)
        if src_file and callee_label:
            _file_callees.setdefault(src_file, set()).add(callee_label)
    _batch_sites: dict[str, dict[str, list[dict[str, Any]]]] = {
        src_file: _scan_all_call_sites_in_file(root, list(labels), src_file)
        for src_file, labels in _file_callees.items()
    }
    enriched_edges: list[dict[str, Any]] = []
    for edge in (result.get("edges") or []):
        new_edge = dict(edge)
        if edge.get("relation") == "calls":
            src_id = str(edge.get("source") or "")
            tgt_id = str(edge.get("target") or "")
            if not src_id.startswith("external::"):
                src_node = _node_map.get(src_id) or {}
                tgt_node = _node_map.get(tgt_id) or {}
                src_file = src_node.get("source_file") or (src_id.split("::")[0] if "::" in src_id else "")
                callee_label = tgt_node.get("label") or (tgt_id.rsplit("::", 1)[-1] if "::" in tgt_id else tgt_id)
                if src_file and callee_label:
                    sites = _batch_sites.get(src_file, {}).get(callee_label, [])
                    src_loc = src_node.get("source_location") or "0:0"
                    try:
                        src_start = int(str(src_loc).split(":")[0])
                    except (ValueError, IndexError):
                        src_start = 0
                    ref = _first_call_site_at_or_after(sites, src_start)
                    if ref:
                        new_edge["line"] = ref["line"]
        enriched_edges.append(new_edge)

    return _attach_auto_rebuild_diag(
        _response(
            "ok",
            {
                "symbol": symbol,
                "node_id": result.get("node_id"),
                "layer": layer_value,
                "depth": depth,
                "direction": direction_value,
                "include_tests": include_tests,
                "nodes": result.get("nodes") or [],
                "edges": enriched_edges,
            },
            next_tools=["code_impact", "code_read"],
            usage=f"code_impact(symbol={symbol!r}, max_hops=2)",
        ),
        index,
    )


def wf_graph_report_response(
    root: Path,
    *,
    layer: str = "project",
    limit: int = 20,
    sections: Optional[list[str]] = None,
    exclude_generated: bool = False,
    exclude_external: bool = False,
    collapse_generated_files: bool = False,
    collapse_class_module_pairs: bool = False,
    collapse_package_to_directory: bool = False,
) -> dict[str, Any]:
    gq = _load_graph_query()
    try:
        layer_value = _graph_layer_value(layer)
    except ValueError as exc:
        return _response(
            "error",
            {"layer": layer},
            diagnostics=[_diagnostic("invalid_arguments", str(exc))],
            next_tools=["wf_help"],
            usage="wf_graph_report(layer='project')",
        )
    index = gq.get_query_index(root, layer=layer_value)
    if not index.present:
        # Wave 1304x / 1304r: refresh-then-recheck on absent graph
        def _recheck_present():
            new_index = gq.get_query_index(root, layer=layer_value)
            return new_index if new_index.present else None
        refreshed_index = _graph_refresh_then_recheck(root, _recheck_present)
        if refreshed_index is not None:
            index = refreshed_index
    if not index.present:
        return _response(
            "error",
            {"layer": layer_value},
            diagnostics=[gq.graph_not_ready_diagnostic(layer_value)],
            next_tools=["index_build"],
            usage="index_build(content='graph', mode='create')",
        )
    # Wave 130rj (130su): collapse_generated_files aggregates each generated
    # file into a single file-node before running the report. Drops internal
    # generated edges and rewrites boundary edges. The collapse runs on a
    # snapshot payload; the original index is not mutated. Per-symbol tools
    # (code_callhierarchy/code_impact/code_graph_path/code_callgraph) deliberately
    # do NOT support this flag — they need the full per-symbol view.
    if collapse_generated_files:
        original_payload = {
            "layer": index.layer,
            "present": index.present,
            "nodes": list(index.nodes),
            "edges": list(index.edges),
        }
        collapsed_payload = gq.collapse_generated_view(original_payload)
        index = gq.GraphQueryIndex(collapsed_payload)
    # Wave 13129 (1312h): collapse_class_module_pairs merges Swift file+class
    # pairs into one node for report consumption. Independent of generated-file
    # collapse — both can be applied together. Swift-first; other languages
    # extend via _CLASS_MODULE_COLLAPSE_LANGUAGES table in graph_query.py.
    if collapse_class_module_pairs:
        original_payload = {
            "layer": index.layer,
            "present": index.present,
            "nodes": list(index.nodes),
            "edges": list(index.edges),
        }
        merged_payload = gq.collapse_class_module_view(original_payload)
        index = gq.GraphQueryIndex(merged_payload)
    # Wave 131bt (1319m): collapse_package_to_directory aggregates files in a
    # directory into a single package/namespace node per language detection
    # (Go: matching package declarations; Python: __init__.py presence;
    # Java/Kotlin/Scala/C#/PHP: matching package/namespace declarations;
    # Swift: directory-presence convention). Independent of class/module
    # pair collapse — both can apply together. Per-symbol tools don't consume.
    if collapse_package_to_directory:
        original_payload = {
            "layer": index.layer,
            "present": index.present,
            "nodes": list(index.nodes),
            "edges": list(index.edges),
        }
        directory_payload = gq.collapse_package_to_directory_view(original_payload, root=root)
        index = gq.GraphQueryIndex(directory_payload)
    report = index.report(limit=max(1, min(limit, 100)), sections=sections)
    # AC-from-wave-130rj (field feedback §2.2): community overview section.
    # Adds a single-call architectural-orientation surface listing top
    # communities by node_count with the IDs needed to follow up via
    # code_graph_community. Lazy-loaded so the section only fires when
    # requested OR when the default section set is used.
    wanted = set(sections) if sections is not None else {"fan_in", "fan_out", "orphan_docs", "chokepoints", "file_hubs", "communities"}
    if "communities" in wanted:
        try:
            gc = _load_script("graph_cluster")
            cluster_layer = layer_value
            payload = gc.read_cluster_payload(root, cluster_layer)
            communities_section: list[dict[str, Any]] = []
            if payload.get("present"):
                # Build degree lookup for hub selection.
                degree: dict[str, int] = {}
                for nid, edges in index._in.items():
                    degree[nid] = degree.get(nid, 0) + len(edges)
                for nid, edges in index._out.items():
                    degree[nid] = degree.get(nid, 0) + len(edges)
                ranked = sorted(
                    (payload.get("communities") or []),
                    key=lambda c: -int(c.get("node_count") or 0),
                )[:max(1, min(limit, 100))]
                for c in ranked:
                    cid = str(c.get("community_id") or "")
                    label = str(c.get("label") or cid)
                    members = c.get("node_ids") or []
                    hub_id = max(members, key=lambda n: degree.get(n, 0), default="") if members else ""
                    hub_label = (index.get_node(hub_id) or {}).get("label", hub_id) if hub_id else ""
                    # Wave 130rj — field feedback §6.5: per-community generated_node_fraction
                    # comes from the cluster artifact; flag generated-dominated
                    # communities (>40%) so agents can decide whether to trust the
                    # community's structural metrics.
                    gen_fraction = float(c.get("generated_node_fraction") or 0.0)
                    entry = {
                        "community_id": cid,
                        "label": label,
                        "node_count": int(c.get("node_count") or 0),
                        "hub_node_id": hub_id,
                        "hub_label": hub_label,
                        "generated_node_fraction": gen_fraction,
                    }
                    if gen_fraction > 0.4:
                        entry["community_type"] = "generated-dominated"
                    communities_section.append(entry)
            # Wave 130rj — exclude_generated suppresses generated-dominated communities.
            if exclude_generated:
                communities_section = [
                    c for c in communities_section
                    if c.get("community_type") != "generated-dominated"
                ]
            report["communities"] = communities_section
        except Exception:
            report.setdefault("communities", [])

    # Wave 1p9q3 (1p9q1): the betweenness section is SERVED from the persisted
    # build-time ranking in the clusters artifact (graph_cluster.compute_betweenness_ranking:
    # size-tiered exact / igraph-cutoff / degree_fallback, top-200 with method
    # metadata) — never computed at query time. The old inline igraph computation
    # and its 10k-node cap diagnostic are retired; `betweenness_method` +
    # `betweenness_metadata` surface how the persisted ranking was produced.
    if "betweenness" in wanted:
        bw_rows_served: list[dict[str, Any]] = []
        bw_computed = False
        try:
            gc_bw = _load_script("graph_cluster")
            bw_payload = gc_bw.read_cluster_payload(root, layer_value)
            bw_section = bw_payload.get("betweenness") if bw_payload.get("present") else None
            if isinstance(bw_section, dict) and isinstance(bw_section.get("ranking"), list):
                bw_rows_served = [
                    dict(row)
                    for row in bw_section["ranking"][: max(1, min(limit, 100))]
                    if isinstance(row, dict)
                ]
                bw_metadata: dict[str, Any] = {
                    "node_count": int(bw_section.get("node_count") or 0),
                    "edge_count": int(bw_section.get("edge_count") or 0),
                    "top_n": int(bw_section.get("top_n") or 0),
                    "elapsed_ms": int(bw_section.get("elapsed_ms") or 0),
                }
                if bw_section.get("cutoff") is not None:
                    bw_metadata["cutoff"] = int(bw_section["cutoff"])
                # Assign report fields only after every cast above succeeded,
                # so a corrupted section can never leave a half-populated
                # response (method set alongside a skipped_reason).
                report["betweenness_method"] = str(bw_section.get("method") or "")
                report["betweenness_metadata"] = bw_metadata
                bw_computed = True
        except Exception:
            bw_rows_served = []
            bw_computed = False
            report.pop("betweenness_method", None)
            report.pop("betweenness_metadata", None)
        report["betweenness"] = bw_rows_served
        report["betweenness_computed"] = bw_computed
        if not bw_computed:
            # Legacy clusters artifact (pre-build-time-betweenness, no section)
            # or no clusters artifact yet — graceful absent-section response,
            # not a crash; the next graph rebuild persists the section.
            report["betweenness_skipped_reason"] = "betweenness_not_in_artifact"
            report["betweenness_note"] = (
                "Betweenness is computed at build time and persisted in the graph "
                "clusters artifact; this artifact predates the build-time pass. "
                "Rebuild the graph index (index_build(content='graph', "
                "mode='rebuild')) to populate it."
            )

    # Wave 130rj — field feedback §6.4 + §6.2: filter generated nodes out of
    # fan_in/fan_out/chokepoints when exclude_generated=True; emit a
    # `betweenness_dominated_by_generated` warning when >50% of top-N
    # betweenness results are tagged generated.
    def _node_is_generated(nid: str) -> bool:
        n = index.get_node(nid) or {}
        return bool(n.get("generated"))

    if exclude_generated:
        for section_name in ("fan_in", "fan_out", "chokepoints"):
            rows = report.get(section_name)
            if isinstance(rows, list):
                report[section_name] = [
                    row for row in rows
                    if isinstance(row, dict) and not _node_is_generated(str(row.get("node_id") or ""))
                ]
        # Betweenness section uses the same node_id field.
        bw = report.get("betweenness")
        if isinstance(bw, list):
            report["betweenness"] = [
                row for row in bw
                if isinstance(row, dict) and not _node_is_generated(str(row.get("node_id") or ""))
            ]
    # Wave 130rj (130tw) normalization note: `betweenness_computed` /
    # `betweenness_skipped_reason` are now set directly by the artifact-serving
    # block above (wave 1p9q3 / 1p9q1) — the dict-shaped inline diagnostics that
    # this block used to normalize no longer exist.

    # Compute the dominated warning over the (possibly post-filter) betweenness rows.
    bw_rows = report.get("betweenness") if isinstance(report.get("betweenness"), list) else None
    if bw_rows:
        gen_count = sum(1 for row in bw_rows if isinstance(row, dict) and _node_is_generated(str(row.get("node_id") or "")))
        if gen_count * 2 > len(bw_rows):  # >50%
            report["betweenness_dominated_by_generated"] = True
        else:
            report["betweenness_dominated_by_generated"] = False
    # Wave 13129 (1316p): curated allowlist of common Java stdlib + framework
    # method simple names. The pre-1316p graph-state-based count no longer
    # fires for the common Java case because 1312l's receiver-type resolution
    # at index time eliminates the spurious `external::*` nodes the count
    # depended on. The allowlist answers the operator's actual question.
    # Wave 13129 (13192): extended to multi-language dispatch by source-file
    # extension. Each language has different stdlib patterns; one global
    # allowlist would either over-flag or be ambiguous.
    _STDLIB_COMMON_NAMES_BY_LANG: dict[str, frozenset[str]] = {
        ".java": frozenset({
            # java.lang.Object
            "equals", "hashCode", "toString", "getClass", "notify", "notifyAll", "wait",
            # java.lang.Runnable / Thread
            "run",
            # java.lang.AutoCloseable / Closeable
            "close",
            # java.util.function (Functional interfaces)
            "accept", "apply", "test", "get",
            # java.util.Comparator / Comparable
            "compare", "compareTo",
            # java.util.Iterator / Iterable
            "iterator", "next", "hasNext",
            # java.lang.reflect (commonly mistaken)
            "getMethod", "getDeclaredMethod", "getField", "getDeclaredField",
            # java.io
            "read", "write", "flush", "writeObject", "readObject",
            # java.util.Map.Entry / collections
            "getKey", "getValue",
            # Spring patterns
            "execute", "process", "handle",
        }),
        ".cs": frozenset({
            # System.Object
            "Equals", "GetHashCode", "ToString", "GetType",
            # System.IDisposable
            "Dispose",
            # System.Collections.IEnumerator / IEnumerable
            "MoveNext", "Current", "GetEnumerator",
            # System.IComparable / IComparer
            "Compare", "CompareTo",
            # System.ICloneable
            "Clone",
            # System.IO (stream patterns)
            "Read", "Write", "Close", "Flush",
            # Common method names on services
            "Start", "Stop", "Reset", "Cancel", "Invoke",
            # System.Collections.Generic.List / IDictionary
            "Add", "Remove", "Contains", "Clear", "ToArray", "ToList",
            # Parsing / formatting
            "Format", "Parse", "TryParse",
            # Visitor patterns / .NET internals
            "Visit", "Execute", "Process", "Handle",
        }),
        ".kt": frozenset({
            # Kotlin runs on JVM — inherits Java common method names
            "equals", "hashCode", "toString", "compareTo",
            "iterator", "next", "hasNext", "close", "run",
            "accept", "apply", "test", "get",
            # Kotlin stdlib extension functions commonly used as method names
            "let", "also", "with", "invoke", "getValue", "setValue",
            # Operator overloads
            "plus", "minus", "times", "div", "rangeTo",
        }),
        ".swift": frozenset({
            # Initializers / deinitializers
            "init", "deinit",
            # CustomStringConvertible
            "description", "debugDescription",
            # Hashable / Equatable
            "hash",
            # Codable
            "encode", "decode",
            # Comparable
            "compare",
            # Collection
            "count", "append", "remove", "insert", "contains", "forEach",
            # Sequence
            "map", "filter", "reduce", "compactMap", "flatMap",
            "sorted", "prefix", "suffix", "first", "last", "min", "max",
            "allSatisfy",
            # Indexing
            "index",
        }),
        ".py": frozenset({
            # Dunder methods
            "__init__", "__str__", "__repr__", "__eq__", "__hash__",
            "__len__", "__iter__", "__next__",
            "__enter__", "__exit__", "__call__",
            "__getitem__", "__setitem__", "__delitem__",
            "__contains__", "__bool__",
            "__add__", "__sub__", "__mul__", "__lt__",
            # threading / file IO
            "close", "read", "write", "flush", "run", "start", "join",
        }),
    }
    # Wave 13129 (13198): extended allowlist coverage to JS/TS/Go/Rust/Scala/PHP/Ruby.
    _JS_COMMON = frozenset({
        # Object.prototype
        "toString", "valueOf", "hasOwnProperty", "isPrototypeOf", "propertyIsEnumerable",
        # Promise
        "then", "catch", "finally",
        # Array.prototype
        "forEach", "map", "filter", "reduce", "find", "findIndex",
        "some", "every", "includes", "push", "pop", "shift", "unshift",
        "slice", "splice", "indexOf", "lastIndexOf", "join", "split", "concat",
        # String.prototype
        "charAt", "charCodeAt", "substring", "substr", "toLowerCase", "toUpperCase", "trim",
        # generic
        "length",
    })
    _STDLIB_COMMON_NAMES_BY_LANG[".js"]  = _JS_COMMON
    _STDLIB_COMMON_NAMES_BY_LANG[".jsx"] = _JS_COMMON
    _STDLIB_COMMON_NAMES_BY_LANG[".mjs"] = _JS_COMMON
    _STDLIB_COMMON_NAMES_BY_LANG[".cjs"] = _JS_COMMON

    _TS_COMMON = _JS_COMMON | frozenset({
        # TS framework lifecycle / serialization
        "toJSON", "render",
        # React class component lifecycle
        "componentDidMount", "componentWillUnmount", "componentDidUpdate",
        "shouldComponentUpdate", "getSnapshotBeforeUpdate",
        # Hooks (used as method names occasionally)
        "useState", "useEffect", "useMemo", "useCallback",
    })
    _STDLIB_COMMON_NAMES_BY_LANG[".ts"]  = _TS_COMMON
    _STDLIB_COMMON_NAMES_BY_LANG[".tsx"] = _TS_COMMON

    _STDLIB_COMMON_NAMES_BY_LANG[".go"] = frozenset({
        # io.Reader / io.Writer / io.Closer
        "Read", "Write", "Close",
        # fmt.Stringer / error
        "String", "Error",
        # encoding/json, encoding/xml, encoding/gob, encoding/binary
        "Marshal", "Unmarshal", "Encode", "Decode",
        # sync
        "Wait", "Done", "Lock", "Unlock", "RLock", "RUnlock",
        # http.Handler
        "ServeHTTP",
        # standard runnable patterns
        "Run", "Start", "Stop",
        # Stringer / formatter
        "Format", "Scan", "Reset",
    })

    _STDLIB_COMMON_NAMES_BY_LANG[".rs"] = frozenset({
        # Default / construction
        "new", "default",
        # Clone / Drop / fmt::Debug / Display
        "clone", "drop", "fmt",
        # PartialEq / Ord / PartialOrd
        "eq", "ne", "cmp", "partial_cmp",
        # Hash
        "hash",
        # serde
        "serialize", "deserialize",
        # From / Into / AsRef / AsMut
        "from", "into", "as_ref", "as_mut",
        # Option / Result idioms
        "unwrap", "expect", "ok", "err",
        # Iterator
        "iter", "iter_mut", "into_iter", "next", "collect",
        "map", "filter", "fold", "len",
    })

    _STDLIB_COMMON_NAMES_BY_LANG[".scala"] = frozenset({
        # Scala on JVM — inherits Java common names
        "equals", "hashCode", "toString", "compareTo",
        # Scala-specific apply/unapply/copy
        "apply", "unapply", "copy",
        # Case-class product methods
        "productElement", "productArity", "canEqual",
        # Collection
        "foreach", "map", "flatMap", "filter", "fold", "reduce",
        "collect", "groupBy", "head", "tail", "isEmpty", "nonEmpty",
        # Common
        "run", "execute", "close",
    })

    _STDLIB_COMMON_NAMES_BY_LANG[".php"] = frozenset({
        # PHP magic methods
        "__construct", "__destruct", "__toString",
        "__get", "__set", "__isset", "__unset",
        "__call", "__callStatic", "__invoke",
        "__clone", "__sleep", "__wakeup", "__serialize", "__unserialize",
        # Iterator / Countable / ArrayAccess
        "count", "getIterator",
        "current", "next", "key", "valid", "rewind",
        "offsetGet", "offsetSet", "offsetExists", "offsetUnset",
        # JsonSerializable
        "jsonSerialize",
    })

    _STDLIB_COMMON_NAMES_BY_LANG[".rb"] = frozenset({
        # Object
        "initialize", "to_s", "inspect",
        # Conversions
        "to_a", "to_h", "to_proc", "to_i", "to_f", "to_str",
        # Enumerable
        "each", "each_with_index", "each_with_object",
        "map", "select", "reject", "reduce", "inject",
        "find", "any?", "all?", "none?", "count",
        # Comparable
        "==", "<=>", "eql?",
        # Object identity / cloning
        "hash", "dup", "clone", "object_id",
        # Reflection
        "send", "public_send", "method_missing", "respond_to?",
        "is_a?", "kind_of?", "instance_of?",
        # Standard hooks
        "call",
    })

    def _stdlib_collision_for_node(_node: dict[str, Any], _simple: str) -> int:
        """Return 1 when the project node's simple name appears in the language-specific
        stdlib allowlist (extension-derived from source_file); 0 otherwise. Wave 13192.
        """
        source_file = str(_node.get("source_file") or "")
        # Extract extension; lowercase for case-insensitive match (.JAVA, .Cs etc).
        ext_idx = source_file.rfind(".")
        slash_idx = source_file.rfind("/")
        if ext_idx <= slash_idx:
            return 0
        ext = source_file[ext_idx:].lower()
        allowlist = _STDLIB_COMMON_NAMES_BY_LANG.get(ext)
        if allowlist is None:
            return 0
        return 1 if _simple in allowlist else 0

    # Wave 13129 (1316j): single-source-of-truth simple-name extraction.
    # For symbol nodes (`<file>::<qname>`), take the last `.`-segment of the
    # qname (e.g. `JSON.writeObject` → `writeObject`).
    # For module/file nodes (no `::`), take the basename without extension
    # (e.g. `path/StatusBarManager.swift` → `StatusBarManager`).
    # The pre-1316j behavior took the file extension for module nodes,
    # producing the same constant for every module entry (a consumer reported
    # `same_name_node_count: 72` on every Swift module — the total Swift
    # module count, not a per-symbol value).
    def _node_simple_name(nid: str) -> str:
        if not nid:
            return ""
        if "::" in nid:
            symbol = nid.rsplit("::", 1)[-1]
            return symbol.rsplit(".", 1)[-1]
        # Module/file node: take last path segment, drop extension.
        basename = nid.rsplit("/", 1)[-1]
        if "." in basename:
            return basename.rsplit(".", 1)[0]
        return basename

    # Wave 130rj (130tw): name_collision_count on each ranking entry.
    # Wave 13129 (1312b): decomposed into same_name_node_count + cross_file_collision
    # + external_name_collision_count. The original field is preserved as a
    # deprecated alias for same_name_node_count for one release.
    #
    # Simple-name attribution can over-count fan_in two ways:
    # - same-file aggregation (Swift StatusBarManager nested types) → reflected
    #   in same_name_node_count without cross_file_collision (operator can
    #   verify the file-tree shape is not the actual signal)
    # - external collision (Java JSON.writeObject vs ObjectOutputStream.writeObject)
    #   → reflected in external_name_collision_count > 0
    #
    # The simple-name match uses the last `.`-segment of the symbol part after
    # `::`, identical for project and external nodes (1312b AC-3) — so a project
    # `JSON.writeObject` matches both `external::writeObject` and
    # `external::ObjectOutputStream.writeObject`.
    # Wave 13129 (1316p): only the project-side precompute remains. The
    # external-side precompute (`external_counts_by_simple_name`) is replaced
    # by the curated `_JAVA_STDLIB_COMMON_NAMES` allowlist lookup.
    project_files_by_simple_name: dict[str, set[str]] = {}
    for _node in index.nodes:
        nid = str(_node.get("id") or "")
        if not nid:
            continue
        if nid.startswith("external::"):
            continue
        simple = _node_simple_name(nid)
        if not simple:
            continue
        source_file = str(_node.get("source_file") or "")
        if not source_file:
            # Fall back to file portion of node_id when source_file missing.
            source_file = nid.split("::")[0] if "::" in nid else nid
        project_files_by_simple_name.setdefault(simple, set()).add(source_file)

    project_node_count_by_simple_name: dict[str, int] = {}
    for _node in index.nodes:
        _nid = str(_node.get("id") or "")
        if not _nid or _nid.startswith("external::"):
            continue
        _simple = _node_simple_name(_nid)
        if _simple:
            project_node_count_by_simple_name[_simple] = (
                project_node_count_by_simple_name.get(_simple, 0) + 1
            )

    def _collision_fields(nid: str) -> dict[str, Any]:
        if not nid or nid.startswith("external::"):
            return {
                "same_name_node_count": 1,
                "cross_file_collision": False,
                "external_name_collision_count": 0,
                "name_collision_count": 1,
            }
        simple = _node_simple_name(nid)
        same_name = project_node_count_by_simple_name.get(simple, 1)
        files = project_files_by_simple_name.get(simple, set())
        cross_file = len(files) >= 2
        # Wave 13192: per-language allowlist lookup (extension-derived from
        # source_file). Java was 1316p; this dispatches across .java/.cs/.kt/
        # .swift/.py with curated lists per language.
        node = index.get_node(nid) or {}
        external_count = _stdlib_collision_for_node(node, simple)
        return {
            "same_name_node_count": same_name,
            "cross_file_collision": cross_file,
            "external_name_collision_count": external_count,
            # Deprecated alias preserved for one release (wave 13129 1312b AC-4).
            "name_collision_count": same_name,
        }

    for _section_name in ("fan_in", "fan_out", "chokepoints", "file_hubs", "betweenness"):
        _rows = report.get(_section_name)
        if isinstance(_rows, list):
            for _row in _rows:
                if isinstance(_row, dict):
                    _row.update(_collision_fields(str(_row.get("node_id") or "")))

    # Wave 130rj (130tw): exclude_external filters external::* nodes from
    # the architectural-ranking sections. Independent of exclude_generated —
    # operators typically combine both for "show me MY code" orientation.
    if exclude_external:
        for _section_name in ("fan_in", "fan_out", "chokepoints", "file_hubs", "betweenness"):
            _rows = report.get(_section_name)
            if isinstance(_rows, list):
                report[_section_name] = [
                    _row for _row in _rows
                    if isinstance(_row, dict)
                    and not str(_row.get("node_id") or "").startswith("external::")
                ]

    report["exclude_generated"] = exclude_generated
    report["exclude_external"] = exclude_external
    report["collapse_generated_files"] = collapse_generated_files
    report["collapse_class_module_pairs"] = collapse_class_module_pairs
    report["collapse_package_to_directory"] = collapse_package_to_directory
    # Wave 1p2q3 (1p2q9 B): per-language attribution-confidence counts. wf_graph_report
    # surfaces structural sections (fan_in/out, chokepoints, file_hubs, etc.) but doesn't
    # carry edges directly — compute from the underlying graph edges so the diagnostic
    # reflects the layer's attribution distribution at large.
    report["attribution_counts_by_language"] = _compute_attribution_counts_by_language(list(index.edges), index)
    return _attach_auto_rebuild_diag(
        _response(
            "ok",
            report,
            next_tools=["code_callgraph", "code_impact"],
            usage="code_callgraph(symbol='path::symbol')",
        ),
        index,
    )


# ---------------------------------------------------------------------------
# code_graph_path — BFS shortest path between two graph symbols
# ---------------------------------------------------------------------------

def code_graph_path_response(
    root: Path,
    from_symbol: str,
    to_symbol: str,
    *,
    relations: Optional[list[str]] = None,
    max_hops: int = 10,
    layer: str = "project",
    direction: str = "forward",
    min_confidence: str = "EXTRACTED",
) -> dict[str, Any]:
    """Find the shortest connecting path between two symbols in the graph.

    Prefer when: tracing dependency chains, understanding how module A reaches module B,
    or identifying indirect coupling between two symbols. Always returns the consistent
    shape {found, path_nodes, path_edges, hop_count, suggestions} regardless of outcome.

    Response fields:
    - found: true when a path exists within max_hops
    - path_nodes: ordered list of {node_id, label, kind, source_file} from from_symbol to to_symbol
    - path_edges: ordered list of traversed edges; when direction="either" each edge carries
      an extra ``traversal_direction`` field ("forward" or "backward")
    - hop_count: number of edges in the path (0 when symbols are identical, 0 when not found)
    - suggestions: list of {id, label, kind} near-matches when either symbol is unresolvable
    - direction: echoes the requested direction

    Args:
        from_symbol: Starting graph node id or resolvable symbol.
        to_symbol: Target graph node id or resolvable symbol.
        relations: Optional edge relation filter (default: all relations).
        max_hops: Maximum hops before giving up (default 10).
        layer: Graph layer (default ``project``).
        direction: ``forward`` (default), ``backward``, or ``either``. Forward walks outgoing
            edges only; backward walks incoming; either walks both with per-edge
            ``traversal_direction`` annotations.
    """
    direction_value = (direction or "forward").strip().lower()
    if direction_value not in ("forward", "backward", "either"):
        return _response(
            "error",
            {"from_symbol": from_symbol, "to_symbol": to_symbol, "direction": direction, "found": False, "path_nodes": [], "path_edges": [], "hop_count": 0, "suggestions": []},
            diagnostics=[_diagnostic("invalid_arguments", f"direction must be 'forward', 'backward', or 'either'; got {direction!r}.")],
            next_tools=["wf_help"],
            usage="code_graph_path(from_symbol='...', to_symbol='...', direction='forward')",
        )
    gq = _load_graph_query()
    try:
        layer_value = _graph_layer_value(layer)
    except ValueError as exc:
        return _response(
            "error",
            {"from_symbol": from_symbol, "to_symbol": to_symbol, "direction": direction_value, "found": False, "path_nodes": [], "path_edges": [], "hop_count": 0, "suggestions": []},
            diagnostics=[_diagnostic("invalid_arguments", str(exc))],
            next_tools=["wf_help"],
            usage="code_graph_path(from_symbol='...', to_symbol='...')",
        )
    index = gq.get_query_index(root, layer=layer_value)
    if not index.present:
        return _response(
            "error",
            {"from_symbol": from_symbol, "to_symbol": to_symbol, "direction": direction_value, "found": False, "path_nodes": [], "path_edges": [], "hop_count": 0, "suggestions": []},
            diagnostics=[gq.graph_not_ready_diagnostic(layer_value)],
            next_tools=["index_build"],
            usage="index_build(content='graph', mode='create')",
        )
    suggestions: list[dict[str, Any]] = []
    from_id = index.resolve_symbol(from_symbol)
    to_id = index.resolve_symbol(to_symbol)
    # Wave 1304x / 1304r: refresh + reload + re-resolve BOTH symbols if either missed.
    # We can't use _graph_refresh_and_resolve here because it returns (None, None)
    # when its single target symbol still misses post-refresh — that would discard
    # the freshly loaded index even though the OTHER symbol might now resolve.
    if from_id is None or to_id is None:
        def _recheck_both_paths():
            new_index = gq.get_query_index(root, layer=layer_value)
            return (new_index, new_index.resolve_symbol(from_symbol), new_index.resolve_symbol(to_symbol))
        refreshed = _graph_refresh_then_recheck(root, _recheck_both_paths)
        if refreshed is not None:
            new_index, new_from_id, new_to_id = refreshed
            index = new_index
            if from_id is None:
                from_id = new_from_id
            if to_id is None:
                to_id = new_to_id
    if from_id is None:
        suggestions.extend(_suggest_near_symbols(index, from_symbol))
    if to_id is None:
        for s in _suggest_near_symbols(index, to_symbol):
            if s not in suggestions:
                suggestions.append(s)
    if from_id is None or to_id is None:
        missing_label = (
            f"both symbols '{from_symbol}' and '{to_symbol}'" if from_id is None and to_id is None
            else f"'{from_symbol}'" if from_id is None
            else f"'{to_symbol}'"
        )
        return _response(
            "ok",
            {"from_symbol": from_symbol, "to_symbol": to_symbol, "direction": direction_value, "found": False, "path_nodes": [], "path_edges": [], "hop_count": 0, "suggestions": suggestions},
            diagnostics=[_diagnostic(
                "graph_symbol_not_found",
                f"Could not resolve {missing_label} to a graph node (refresh attempted).",
                recovery_tools=["code_definition", "code_keyword"],
                recovery_usage=f"code_definition(symbol_or_path_position={from_symbol if from_id is None else to_symbol!r})",
            )],
            next_tools=["code_callhierarchy"],
            usage="code_callhierarchy(symbol='...')",
        )
    try:
        result = index.shortest_path(
            from_id, to_id,
            relations=relations,
            max_hops=max_hops,
            direction=direction_value,
            min_confidence=min_confidence,
        )
    except ValueError as exc:
        return _response(
            "error",
            {"from_symbol": from_symbol, "to_symbol": to_symbol, "direction": direction_value, "found": False, "path_nodes": [], "path_edges": [], "hop_count": 0, "suggestions": []},
            diagnostics=[_diagnostic("invalid_arguments", str(exc))],
            next_tools=["wf_help"],
            usage="code_graph_path(from_symbol='...', to_symbol='...', min_confidence='EXTRACTED')",
        )
    # Wave 1p2q3 (1p2q4): structural-path diagnostic. When the resolved path
    # contains zero `calls` edges, the endpoints share structural reachability
    # but no direct call chain — the headline `found: true` is honest, but
    # operators reading the result should know the path is structural-only.
    diagnostics: list[dict[str, Any]] = []
    if result["found"] and result["path_edges"]:
        calls_edges = [e for e in result["path_edges"] if e.get("relation") == "calls"]
        if not calls_edges:
            structural_count = len(result["path_edges"])
            diagnostics.append(_diagnostic(
                "path_is_structural",
                f"Path connects via {structural_count} imports/defines edge(s), not via calls. "
                "Endpoints share structural reachability but no direct call chain. "
                "Pass `relations=[\"calls\"]` to restrict to call edges only.",
            ))
    return _attach_auto_rebuild_diag(
        _response(
            "ok",
            {
                "from_symbol": from_symbol,
                "to_symbol": to_symbol,
                "direction": direction_value,
                "layer": layer_value,
                "found": result["found"],
                "path_nodes": result["path_nodes"],
                "path_edges": result["path_edges"],
                "hop_count": result["hop_count"],
                "suggestions": suggestions,
            },
            diagnostics=diagnostics,
            next_tools=["code_callhierarchy", "code_impact"],
            usage=f"code_callhierarchy(symbol={from_symbol!r})",
        ),
        index,
    )


# ---------------------------------------------------------------------------
# code_graph_community — drill down into a single community's member nodes
# ---------------------------------------------------------------------------

def code_graph_community_response(
    root: Path,
    community_id: str = "",
    *,
    hub_node_id: str = "",
    layer: str = "project",
    limit: int = 50,
    offset: int = 0,
    exclude_generated: bool = False,
) -> dict[str, Any]:
    """Return member nodes of a community from the cluster artifact.

    Prefer when: drilling into a specific community identified from wf_graph_report
    or the cluster dashboard. Returns members sorted by degree descending so the
    most-connected nodes appear first.

    Pagination (wave 130rj — field feedback §1.3): default ``limit=50``
    so communities of 50+ members are usable inline. ``total_node_count`` and
    ``has_more`` let the caller page through larger communities. Communities
    under 50 nodes return all members in one call.

    Response fields:
    - community_id: the requested community identifier
    - label: human-readable community label
    - total_node_count: total members of the community (independent of pagination)
    - returned_count: number of members in this response page
    - offset: the requested page offset
    - has_more: true when more members exist past this page
    - nodes: page of {id, label, kind, source_file, degree} sorted by degree descending

    Args:
        community_id: Community ID as returned in the cluster artifact.
        layer: Graph layer (default ``project``).
        limit: Max members in this page (default 50, max 500).
        offset: Member index to start from (default 0). Members are sorted by degree desc.
    """
    # Wave 13129 (1316r): community_id and hub_node_id are alternative inputs.
    # community_id wins when both are provided; hub_node_id is the stable
    # cross-rebuild anchor that resolves to whatever community contains the
    # node (Leiden ids change between rebuilds; node ids don't).
    community_id = (community_id or "").strip()
    hub_node_id = (hub_node_id or "").strip()
    hub_node_id_used = False
    if not community_id and not hub_node_id:
        return _response(
            "error",
            {"community_id": community_id},
            diagnostics=[_diagnostic("invalid_arguments",
                                     "Provide either community_id or hub_node_id.")],
            next_tools=["wf_graph_report"],
            usage="wf_graph_report(layer='project')",
        )
    try:
        layer_value = _graph_layer_value(layer)
    except ValueError as exc:
        return _response(
            "error",
            {"community_id": community_id},
            diagnostics=[_diagnostic("invalid_arguments", str(exc))],
            next_tools=["wf_help"],
            usage="code_graph_community(community_id='...')",
        )
    gq = _load_graph_query()
    try:
        gc = _load_script("graph_cluster")
    except Exception as exc:
        return _response(
            "error",
            {"community_id": community_id},
            diagnostics=[_diagnostic("load_error", f"Failed to load graph_cluster: {exc}")],
            next_tools=["index_build"],
            usage="index_build(content='graph', mode='create')",
        )
    payload = gc.read_cluster_payload(root, layer_value)
    if not payload.get("present"):
        return _response(
            "error",
            {"community_id": community_id},
            diagnostics=[_diagnostic("cluster_not_ready", "Cluster artifact is absent. Run graph indexing with clustering enabled.")],
            next_tools=["index_build"],
            usage="index_build(content='graph', mode='create')",
        )
    def _find_community(_payload):
        for c in (_payload.get("communities") or []):
            if community_id and str(c.get("community_id") or "") == community_id:
                return c
        return None

    def _find_community_by_hub_node(_payload):
        # Wave 13129 (1316r): resolve hub_node_id to its current community.
        # The hub is identified by membership — any community containing the
        # node id resolves. Leiden produces hard-clustering so node_id matches
        # exactly one community; if multiple match (defensive), first wins.
        for c in (_payload.get("communities") or []):
            members = c.get("node_ids") or []
            if hub_node_id in members:
                return c
        return None

    target: Optional[dict[str, Any]] = None
    if community_id:
        target = _find_community(payload)
    if target is None and hub_node_id:
        target = _find_community_by_hub_node(payload)
        if target is not None:
            hub_node_id_used = True
            # Use the resolved community_id for the response.
            community_id = str(target.get("community_id") or "")
    if target is None:
        # Wave 1304x / 1304r: refresh-then-recheck before emitting suggestions
        def _recheck_community():
            refreshed_payload = gc.read_cluster_payload(root, layer_value)
            return _find_community(refreshed_payload) or {}  # truthy on hit, {} so it's falsy on miss but not None
        refreshed = _graph_refresh_then_recheck(root, _recheck_community)
        if refreshed:
            target = refreshed
            payload = gc.read_cluster_payload(root, layer_value)
    if target is None:
        suggestions = _suggest_near_communities(payload.get("communities") or [], community_id, n=5)
        return _response(
            "error",
            {"community_id": community_id, "suggestions": suggestions},
            diagnostics=[_diagnostic("not_found", f"No community found with id '{community_id}'.")],
            next_tools=["wf_graph_report"],
            usage="wf_graph_report(layer='project')",
        )
    # Load graph to get degree information
    index = gq.get_query_index(root, layer=layer_value)
    node_ids = target.get("node_ids") or []
    nodes: list[dict[str, Any]] = []
    for nid in node_ids:
        n = index.get_node(nid) or {}
        in_deg = len(index._in.get(nid, []))
        out_deg = len(index._out.get(nid, []))
        nodes.append({
            "id": nid,
            "label": n.get("label", nid),
            "kind": n.get("kind"),
            "source_file": n.get("source_file"),
            "generated": bool(n.get("generated")),
            "degree": in_deg + out_deg,
        })
    nodes.sort(key=lambda x: -x["degree"])
    # total_node_count is the community's actual size (pre-filter). Wave 130rj —
    # Field feedback §6.3: exclude_generated filter removes generated members from the
    # response, but the total reflects the unfiltered community so operators can
    # see how much was suppressed.
    total_node_count = len(nodes)
    if exclude_generated:
        nodes = [n for n in nodes if not n.get("generated")]
    # Apply pagination (wave 130rj). Clamp limit/offset to safe ranges.
    safe_limit = max(1, min(int(limit) if limit is not None else 50, 500))
    safe_offset = max(0, int(offset) if offset is not None else 0)
    page = nodes[safe_offset:safe_offset + safe_limit]
    has_more = (safe_offset + len(page)) < total_node_count
    # Wave 13129 (1312j): community_size_class lets callers branch on size without
    # threshold knowledge. Thresholds: <50 small, 50-200 medium, 200+ large.
    if total_node_count < 50:
        community_size_class = "small"
    elif total_node_count <= 200:
        community_size_class = "medium"
    else:
        community_size_class = "large"
    # Wave 130rj (130tw): pagination_hint surfaces the next-page call shape so
    # operators see the truncation and the recovery path in one response.
    # Wave 13129 (1316r): community_hub_node_id is the stable cross-rebuild
    # anchor — the highest-degree member of the community. The pre-pagination
    # `nodes` list is already sorted by degree desc, so nodes[0] is the hub.
    # When the resolved community has zero members (defensive), use the
    # hub_node_id parameter (if provided) or empty string.
    community_hub_node_id = (
        nodes[0]["id"] if nodes
        else (hub_node_id if hub_node_id else "")
    )
    response_payload: dict[str, Any] = {
        "community_id": community_id,
        "label": target.get("label", community_id),
        "total_node_count": total_node_count,
        "returned_count": len(page),
        "offset": safe_offset,
        "has_more": has_more,
        # node_count kept for backward-compat callers; equals returned_count.
        "node_count": len(page),
        # Generated-node fraction surfaced from the cluster artifact (wave 130rj).
        "generated_node_fraction": float(target.get("generated_node_fraction") or 0.0),
        "exclude_generated": exclude_generated,
        # Wave 13129 (1312j): observability field for caller branching.
        "community_size_class": community_size_class,
        # Wave 13129 (1316r): stable cross-rebuild anchor.
        "community_hub_node_id": community_hub_node_id,
        "hub_node_id_used": hub_node_id_used,
        "nodes": page,
    }
    if has_more:
        next_offset = safe_offset + len(page)
        shown_lo = safe_offset + 1
        shown_hi = safe_offset + len(page)
        response_payload["pagination_hint"] = (
            f"Use limit={safe_limit} offset={next_offset} to retrieve the next page "
            f"({shown_lo}-{shown_hi} of {total_node_count} members shown)"
        )
    # Wave 13129 (1312j): large_community_advisory diagnostic — when the community
    # exceeds 200 members, full traversal will burn token budgets at default
    # pagination (60+ round-trips on a 3119-node community). The recovery hint
    # points operators at code_callhierarchy on the hub (the community's most-
    # connected member, looked up here from the in/out degree across page+remaining
    # members) so they can identify the public API without enumerating the whole
    # community. The advisory surfaces ALONGSIDE pagination_hint; both stay
    # available.
    advisory_diagnostics: list[dict[str, Any]] = []
    if community_size_class == "large":
        # Compute hub from the pre-pagination, pre-exclude_generated node list:
        # use the highest-degree node as the hub. (Same algorithm wave 130rj's
        # communities-section hub selection uses.)
        full_nodes_with_degree = nodes  # already sorted by degree desc above (line 11122)
        # When exclude_generated dropped members, `nodes` may be shorter; recover
        # the unfiltered list by re-fetching for hub lookup.
        if exclude_generated:
            # Recompute the unfiltered, degree-sorted list for hub selection.
            unfiltered: list[dict[str, Any]] = []
            for nid in node_ids:
                n = index.get_node(nid) or {}
                in_deg = len(index._in.get(nid, []))
                out_deg = len(index._out.get(nid, []))
                unfiltered.append({
                    "id": nid, "label": n.get("label", nid),
                    "degree": in_deg + out_deg,
                })
            unfiltered.sort(key=lambda x: -x["degree"])
            full_nodes_with_degree = unfiltered
        hub_node = full_nodes_with_degree[0] if full_nodes_with_degree else None
        hub_node_id = hub_node["id"] if hub_node else ""
        recovery_usage = (
            f"code_callhierarchy(symbol='{hub_node_id}', direction='both')"
            if hub_node_id else ""
        )
        advisory_diagnostics.append(_diagnostic(
            "large_community_advisory",
            (
                f"Community has {total_node_count} members; full traversal will exceed token "
                "budgets at default pagination. Consider `code_callhierarchy` on the hub "
                f"`{hub_node_id}` to identify the community's public API, then narrow with "
                "`code_graph_path` between specific endpoints. Pagination remains available "
                "via the `pagination_hint` if full enumeration is required."
            ),
            recovery_tools=["code_callhierarchy", "code_graph_path"],
            recovery_usage=recovery_usage,
        ))
    usage_target = page[0]['id'] if page else '...'
    return _attach_auto_rebuild_diag(
        _response(
            "ok",
            response_payload,
            diagnostics=advisory_diagnostics if advisory_diagnostics else None,
            next_tools=["code_callhierarchy", "code_impact"],
            usage=f"code_callhierarchy(symbol='{usage_target}', direction='both')",
        ),
        index,
    )


# ---------------------------------------------------------------------------
# code_ask — mechanical retrieval routing for codebase Q&A
# ---------------------------------------------------------------------------

def _partition_infra(results: list[dict]) -> list[dict]:
    """Stable index-based partition: move scaffolding-layer results to the end.

    Uses enumerate to avoid false drops from dict equality comparison when two
    results share identical content (same path, text, score).
    """
    infra_idx = {
        i for i, r in enumerate(results)
        if any(seg in Path(r.get("path", "")).parts for seg in INFRASTRUCTURE_PATH_SEGMENTS)
    }
    non_infra = [r for i, r in enumerate(results) if i not in infra_idx]
    infra = [r for i, r in enumerate(results) if i in infra_idx]
    return non_infra + infra


# Test-file detection: directory segments and filename patterns across ecosystems.
# Directory check uses exact segment matching (not substring) to avoid false positives
# such as src/contest/ matching "test". Filename regex covers Python, Go, Java, C#,
# JS/TS, Swift, Kotlin, Ruby, and PHP conventions.
_TEST_DIR_SEGMENTS = frozenset(["tests", "test", "__tests__", "spec", "specs"])
_TEST_FILENAME_RE = re.compile(
    r"^test_"                                               # Python: test_foo.py
    r"|_test\.[a-z]+$"                                      # Go/Python: foo_test.go
    r"|(?:Tests?|TestCase|TestSuite|Specs?)\.[a-zA-Z]+$"    # Java/C#/Swift/Kotlin: FooTest.java
    r"|\.(?:test|spec)\.[a-z]+$"                            # JS/TS: foo.test.js, foo.spec.ts
)


def _is_test_path(path: str) -> bool:
    """Return True when path belongs to a test file across common ecosystems."""
    normalized = path.replace("\\", "/")
    parts = normalized.split("/")
    name = parts[-1] if parts else ""
    return (
        any(p.lower() in _TEST_DIR_SEGMENTS for p in parts[:-1])
        or bool(_TEST_FILENAME_RE.search(name))
    )


def _partition_tests(results: list[dict]) -> list[dict]:
    """Stable index-based partition: move test-file citations to the end.

    Applied after reranking in the artifact-anchored exact-first path so
    implementation owner files rank ahead of test fixtures.
    Uses enumerate to avoid false drops from dict equality comparison when two
    results share identical content.
    """
    test_idx = {i for i, r in enumerate(results) if _is_test_path(r.get("path", ""))}
    non_test = [r for i, r in enumerate(results) if i not in test_idx]
    test = [r for i, r in enumerate(results) if i in test_idx]
    return non_test + test


def _doc_demotion_weight(path: str, kind: str) -> float:
    """Return the demotion multiplier for a result based on its path and kind."""
    normalized = (path or "").replace("\\", "/")
    if normalized.startswith("docs/waves/"):
        return _DEMOTION_WAVES
    if normalized.startswith("docs/plans/"):
        return _DEMOTION_PLANS
    if kind == "seed" or normalized.startswith(".wavefoundry/framework/seeds/"):
        return _DEMOTION_SEEDS
    parts = Path(normalized).parts
    name = Path(normalized).name.lower()
    if any(seg in parts for seg in ("journals", "reports")) or "feedback" in name or "journal" in name:
        return _DEMOTION_JRNLS
    # Wave 1p66s: reference prose — architecture docs, specs, and ADRs. ADRs live under
    # docs/architecture/decisions/ (covered by the architecture prefix); docs/specs/ added
    # explicitly. Gentler than the narrative tiers — still valid context, just not ahead of code.
    if normalized.startswith("docs/architecture/") or normalized.startswith("docs/specs/"):
        return _DEMOTION_REFDOCS
    return 1.0


# Wave 1p66s: code-implementation intents whose answer should lead with implementing
# source, so reference prose (specs/ADRs/architecture/narrative) is demoted below code.
_DOC_DEMOTION_INTENTS = ("explanatory", "navigational")


def _demote_doc_results(results: list[dict], question_type: str) -> tuple[list[dict], int]:
    """Down-weight narrative/reference doc sources for code-implementation intents so the
    implementing source is not outranked by prose (1p66s extends this from explanatory-only
    to navigational "where is X" and to architecture/spec/ADR paths). Demotion is a
    down-weight, never an exclusion — a genuinely doc-answerable result still surfaces."""
    if question_type not in _DOC_DEMOTION_INTENTS:
        return results, 0

    demotion_count = 0
    for r in results:
        weight = _doc_demotion_weight(r.get("path", ""), str(r.get("kind") or "").strip().lower())
        if weight < 1.0:
            r["score"] = (r.get("score") or 0.0) * weight
            demotion_count += 1

    if demotion_count:
        results.sort(key=lambda x: x.get("score") or 0.0, reverse=True)

    return results, demotion_count


# Wave 1p66r (downstream finding): English interrogatives / leading question words that
# the bare-word symbol fallbacks below would otherwise pick as a "symbol" (e.g. a capitalized
# "Which"/"Where") — symbol-first injection then keyword-boosts off-topic citations above the
# relevance floor and DEFEATS abstention (the lowercase form, not matched by the capitalized
# fallback, abstains correctly). Skip these so a capitalized question abstains like its lowercase
# form; an actual symbol later in the question is still found (re.findall, not re.search).
_QUESTION_NONSYMBOLS = frozenset({
    # interrogatives + auxiliaries
    "which", "where", "what", "when", "why", "how", "who", "whose", "whom",
    "does", "do", "did", "is", "are", "was", "were", "can", "could", "should",
    "would", "will", "the", "this", "that", "these", "those",
    # conversational lead-ins ("Tell me about how X works", "Show/Explain/Describe/Walk …",
    # "I want to understand …") — capitalized at sentence start, they'd otherwise be picked as
    # symbols by the capitalized fallback, same class as the interrogative bug.
    "tell", "show", "explain", "describe", "walk", "give", "list", "find", "please",
    "about", "me", "through", "understand", "want", "need", "into", "regarding", "also",
})


def _extract_question_symbol(question: str) -> Optional[str]:
    """Extract the primary code symbol from a question for symbol-first injection."""
    m = re.search(r'`([^`]+)`', question)
    if m:
        sym = m.group(1).strip()
        if sym:
            return sym
    m = re.search(r'\b(\w+(?:(?:\.|::|->)\w+)+)\b', question)
    if m:
        qualified = m.group(1)
        sym = re.split(r'\.|::|->', qualified)[-1]
        if sym:
            return sym
    m = re.search(r'@(\w+)', question)
    if m:
        return '@' + m.group(1)
    m = re.search(r'\b(_\w+)\b', question)
    if m:
        return m.group(1)
    m = re.search(r'\b([A-Z][A-Z0-9]*(?:_[A-Z0-9]+)+)\b', question)
    if m:
        return m.group(1)
    # Bare-word fallbacks (snake_case, camelCase, Capitalized) can match plain English words —
    # iterate and skip interrogatives/leading stopwords so "Which …"/"How does Foo work" yields
    # the real symbol (or nothing) rather than the question word.
    for pat in (
        r'\b([a-z][a-z0-9]+(?:_[a-z0-9]+)+)\b',
        r'\b([a-z][a-z0-9]*(?:[A-Z][a-zA-Z0-9]*)+)\b',
        r'\b([A-Z][a-zA-Z0-9]{3,})\b',
    ):
        for cand in re.findall(pat, question):
            if cand.lower() not in _QUESTION_NONSYMBOLS:
                return cand
    return None


# Artifact-anchored question detection: implementation verbs + concrete artifact cue.
# A question qualifies as artifact_anchored when it contains both a verb from
# _ARTIFACT_VERBS and a token matched by _ARTIFACT_CUE_RE. Detection uses named
# constants so the scope is auditable and extensible without reimplementing the classifier.
_ARTIFACT_VERBS = frozenset([
    "generated", "generate", "generates",
    "derived", "derive", "derives",
    "stamped", "stamp", "stamps",
    "computed", "compute", "computes",
    "encoded", "encode", "encodes",
    "written", "writes", "write",
])
_ARTIFACT_CUE_RE = re.compile(
    r"\+[a-z0-9]{4,5}"                             # version suffix like +2vr8
    r"|\w+\.(?:py|toml|json|md|yaml|yml|js|ts)\b"  # dotted filename like lifecycle_id.py
    r"|[A-Z][a-z]+[A-Z]\w+"                        # CamelCase identifier like BuildPrefix
    r"|[a-z]{3,}_[a-z]{2,}\w*"                     # snake_case identifier like build_prefix
)


def _extract_artifact_cue(question: str) -> str:
    """Return the first concrete artifact cue token in question, or empty string."""
    m = _ARTIFACT_CUE_RE.search(question)
    return m.group(0) if m else ""


_ENUMERATION_RE = re.compile(
    # A collection word (which/what/all/every/each) followed (within a short span) by a
    # set-membership verb. Requires BOTH so "what IS the value of X" (a single-value lookup)
    # does not match — only genuine "which/what/all … are/registered/defined/…" enumerations.
    r"\b(?:which|what|all|every|each)\b.{0,40}"
    r"\b(?:are|registered|defined|declared|supported|available|exist|configured|"
    r"implemented|handled|subscribed|listed|enabled)\b",
    re.IGNORECASE | re.DOTALL,
)
_ENUMERATION_LEAD_RE = re.compile(r"^\s*(?:list|enumerate|how many)\b", re.IGNORECASE)


def _is_enumeration_query(question: str) -> bool:
    """Wave 1p66t: heuristic for "enumerate all X" intent ("which handlers are registered",
    "list all providers", "what events are subscribed", "how many ..."). Enumerations need the
    full set, not a reranked top-k — so we widen retrieval and flag incompleteness rather than
    silently truncate. Conservative: a plain "where is X" / "how does X work" is NOT enumeration."""
    q = (question or "").strip()
    if not q:
        return False
    if _ENUMERATION_LEAD_RE.search(q):
        return True
    return bool(_ENUMERATION_RE.search(q))


def _classify_question(question: str) -> str:
    """Heuristic question classifier: navigational | explanatory | instructional | artifact_anchored."""
    q = question.lower()
    navigational_signals = ["where is", "where are", "where can i find", "which file", "what file", "find the", "find where", "locate the", "path to"]
    instructional_signals = ["how do i", "how to", "steps to", "how can i", "how should i", "how would i"]
    for sig in instructional_signals:
        if sig in q:
            return "instructional"
    for sig in navigational_signals:
        if sig in q:
            return "navigational"
    if any(verb in q for verb in _ARTIFACT_VERBS) and _extract_artifact_cue(question):
        return "artifact_anchored"
    return "explanatory"


def _heuristic_confidence(citations: list[dict], reranked: bool = False) -> str:
    """Coarse confidence for the response.

    Count alone is misleading: an off-topic query still returns many candidates. Wave 1p52p: when the
    cross-encoder ran (``reranked=True`` on GPU FP16 or CPU INT8), every citation carries the UNIFIED
    cross-encoder relevance ``sigmoid(logit)`` ∈ [0,1] — comparable across docs+code — so we gate
    "high" on a genuinely relevant top score and flag a clearly-weak band "low" around the model's
    native ~0.5 relevance boundary. Without a reranker (explicitly disabled or unbuildable), the
    per-citation scores are mixed-model cosine (arctic-doc vs bge-code, 1p4wx split) and are NOT a
    trustworthy band → confidence is CAPPED at "medium" ("low" with zero citations); "high" is never
    claimed without the cross-encoder. In lexical_fallback mode the caller further caps to "low"
    (BM25 exact-token ordering). Still coarse — the per-citation scores carry the fine signal.
    """
    if not citations:
        return "low"
    n = len(citations)
    if reranked:
        top = max((c.get("score") or 0.0) for c in citations)
        if n >= 2 and top >= CONF_AGENT_RERANK_HIGH:
            return "high"
        if top < CONF_AGENT_RERANK_LOW:
            return "low"
        return "medium"
    # Wave 1p66r: no-reranker path — the per-citation scores are mixed-model cosine
    # (arctic-doc vs bge-code) on incomparable scales, so an absolute floor here is
    # miscalibrated and the prior count-based "high" was relevance-blind (the
    # per-index floor guarantees n >= 2 on any non-empty index → always "high").
    # Cap at "medium": without the cross-encoder we cannot certify a "high"
    # relevance band, but a non-empty retrieval is still a usable lead. The
    # fine-grained relevance signal lives in the abstention floor on the
    # post-rerank scores; here we simply never over-claim.
    return "medium"


def _tokenize_identifier(name: str) -> list[str]:
    """Split an identifier on snake_case + camelCase + acronym + digit boundaries, lowercased.
    `RERANKER_MODEL` → [reranker, model]; `MaxRetries` → [max, retries]; `apiURL` → [api, url]."""
    s = re.sub(r"([a-z0-9])([A-Z])", r"\1 \2", name)      # camelCase → camel Case
    s = re.sub(r"([A-Z]+)([A-Z][a-z])", r"\1 \2", s)      # HTTPServer → HTTP Server
    s = s.replace("_", " ")
    return [t.lower() for t in re.findall(r"[A-Za-z0-9]+", s)]


def _query_content_terms(query: str) -> set[str]:
    """Query tokens (len > 1) minus function-word stopwords. Each word is ALSO camel/snake-split
    (wave 1p4lr) so a query that NAMES a camelCase/PascalCase symbol — ``ParseConfig``, ``WaveIndex``
    — yields its sub-tokens (parse, config / wave, index) to match a definition's name tokens; snake
    and UPPER_SNAKE names already split on ``_``. The joined form is kept too (harmless superset)."""
    terms: set[str] = set()
    for word in re.findall(r"[A-Za-z0-9_]+", query):
        for sub in (word, *_tokenize_identifier(word)):
            s = sub.lower()
            if len(s) > 1 and s not in _QUERY_STOPWORDS:
                terms.add(s)
    return terms


def _definition_qname(candidate: dict) -> Optional[str]:
    """Wave 1p4lr: the declared symbol name (qualified, e.g. ``Config.connect``) of a DEFINITION
    chunk, or ``None`` when the candidate is not a code definition. A definition is a CONSTANT
    (1p4mf ``" [const]"`` marker) OR a ``kind="code"`` chunk whose id/breadcrumb leaf is a declared
    symbol — function, method, class, interface, type, enum, const — across EVERY language the
    chunker chunks (Python/JS/TS/Java/Kotlin/C#/Go/Rust/Swift/Ruby/PHP; the chunker emits one code
    chunk per declaration with a ``stem > Qname`` breadcrumb + ``path::Qname`` id). Imports,
    code-summaries, doc/seed chunks, and dunder pseudo-symbols (``__imports__``/``__decl__``/
    ``__namespace__``) are NOT definitions."""
    section = str(candidate.get("section") or "")
    is_const = section.endswith(_CONST_SECTION_SUFFIX)
    if not is_const and str(candidate.get("kind") or "") != "code":
        return None
    cid = str(candidate.get("id") or "")
    if "::" in cid:
        qname = cid.rsplit("::", 1)[-1]
    elif " > " in section:
        qname = section.rsplit(" > ", 1)[-1]
    else:
        return None
    qname = qname.replace(_CONST_SECTION_SUFFIX, "").strip()
    # Wave 1p4lr (delivery review C1): an oversized declaration is split into chunks whose id
    # carries a ``:L<start>-L<end>`` suffix and whose breadcrumb leaf carries a `` (part N/M)`` tail.
    # Both inject tokens (``l1274``, ``part``…) that can NEVER appear in a natural-language query, so
    # the all-tokens match in ``_definition_match_boost`` would always fail — silently disabling the
    # boost for every large symbol (e.g. ``WaveIndex.search_combined``). Strip them so the boost sees
    # the real declared name.
    qname = re.sub(r":L\d+-L\d+$", "", qname)
    qname = re.sub(r"\s*\(part \d+/\d+\)$", "", qname).strip()
    leaf = qname.rsplit(".", 1)[-1]
    if not qname or leaf in ("imports", "__imports__") or leaf.startswith("__"):
        return None
    return qname


def _definition_match_boost(query_terms: set[str], candidate: dict) -> float:
    """Wave 1p4lr: DEFINITION_MATCH_BOOST when the candidate is a DEFINITION chunk (constant,
    function/method, or class/interface/type/enum — see ``_definition_qname``) whose declared name
    the query NAMES; else 1.0. Language-agnostic: detection is the chunk's declaration shape and the
    casing-agnostic camel/snake tokenizer, so it covers every chunked language. The query NAMES the
    symbol when EITHER the full QUALIFIED name's tokens are all present (``how does Config connect
    work`` → {config, connect}) OR — for a multi-token LEAF — the leaf name alone is present (``how
    does search_combined work`` → {search, combined}; a natural-language method/function query rarely
    repeats the enclosing class — delivery-review C3). The ≥2-token guard on whichever set fires
    keeps a single common word from over-boosting; a single-token leaf (e.g. ``connect``) still needs
    its qualified context. The bounded multiplier lifts a name-matching definition — a short constant
    (``what value/model/flag is X``) or the very function/class the query names — into the returned
    set WITHOUT re-imposing any casing rule, firing only on a real name match, not coincidental term
    overlap."""
    qname = _definition_qname(candidate)
    if qname is None:
        return 1.0
    segs = qname.split(".")
    qualified_tokens = [t for seg in segs for t in _tokenize_identifier(seg) if len(t) > 1]
    leaf_tokens = [t for t in _tokenize_identifier(segs[-1]) if len(t) > 1]
    if len(qualified_tokens) >= 2 and all(t in query_terms for t in qualified_tokens):
        return DEFINITION_MATCH_BOOST
    if len(leaf_tokens) >= 2 and all(t in query_terms for t in leaf_tokens):
        return DEFINITION_MATCH_BOOST
    return 1.0


def code_ask_response(index: "WaveIndex", root: Path, question: str, rerank: str = "agent", epoch_state: Any = "__compute__") -> dict[str, Any]:
    """Mechanical routing: broad retrieval pass → targeted pass → assemble structured response.

    Wave 1p52p: ONE ranking path — agent candidate selection with a
    rerank-FIRST cross-encoder. ``rerank="local"`` is a deprecated alias for
    the identical path (the old local/RRF pipelines are removed); citations
    are labeled, deduped, full-chunk in both spellings.
    """
    t_start = time.monotonic()

    question = question.strip()
    if not question:
        return _response("error", {"question": question, "search_mode": None, "fallback_reason": None}, diagnostics=[_diagnostic("invalid_arguments", "question must be a non-empty string.")], next_tools=[], usage="")

    # Wave 1p52p: code_ask has a single ranking path (agent selection + rerank-FIRST cross-encoder).
    # The ``rerank`` param is retained for API back-compat: "agent" (default) and the deprecated alias
    # "local" both route through the one path (search_combined ignores the value). Other values error.
    rerank = (rerank or "agent").strip().lower()
    if rerank not in ("agent", "local"):
        return _response("error", {"question": question, "rerank": rerank, "search_mode": None, "fallback_reason": None}, diagnostics=[_diagnostic("invalid_arguments", "rerank must be 'agent' (default); 'local' is a deprecated alias for the same single path.")], next_tools=["code_ask"], usage="code_ask(question='...')")

    question_type = _classify_question(question)
    gaps: list[str] = []
    citations: list[dict] = []

    # Index freshness (wave 1seav / 1sbxq): the cheap cached three-state
    # verdict — per-layer last-embedded hashes + stat-fast-path walk +
    # chunker check, NEVER the O(corpus) `_layer_health` hash walk its own
    # docstring forbids on the hot path. "unknown" on any indeterminacy.
    index_freshness = _index_freshness_verdict(root)["state"]

    # Broad pass: combined semantic search with reranking
    combined_reranked = False
    vector_ms = 0
    rerank_ms = 0
    infrastructure_demoted = False
    definition_boosted: list[str] = []
    second_hop_symbols: list[str] = []
    symbol_extraction_method: str = "none"
    graph_related: Optional[dict] = None
    # 1seaq typed degradation contract: search_mode/fallback_reason are part
    # of code_ask's envelope in EVERY mode; the serve decision uses the
    # CAPTURED 1sed7 token (passed by the registration; computed once for
    # direct callers).
    search_mode = "hybrid"
    fallback_reason: "str | None" = None
    if epoch_state == "__compute__":
        epoch_state = _epoch_state(root)
    _epoch_complete = epoch_state is not None and epoch_state[1] == "complete"

    degraded_coverage: dict[str, Any] = {}

    def _degraded_citation_pass(reason: str, exc_msg: str) -> list:
        """FTS-built citations for the degraded mode (complete epoch only)."""
        nonlocal search_mode, fallback_reason, gaps, degraded_coverage
        if not _epoch_complete:
            fallback_reason = "index_not_ready" if epoch_state is not None else "store_absent"
            gaps.append(f"search index unavailable ({fallback_reason}): {exc_msg}")
            return []
        serve = _fts_degraded_serve(root, ("docs", "code"), question, 7)
        degraded_coverage = serve.get("coverage") or {}
        if not serve["available"]:
            fallback_reason = serve["failure_reason"]
            search_mode = "lexical_fallback"  # attempted-and-failed (cross-tool consistency)
            gaps.append(f"search infrastructure failure ({serve['failure_reason']}): {exc_msg}")
            return []
        search_mode = "lexical_fallback"
        fallback_reason = reason
        gaps.append(
            f"semantic retrieval unavailable ({reason}) — citations are BM25 exact-token "
            "matches from the published FTS layer, not semantic recall; confidence is capped"
        )
        if not serve["results"]:
            # Working-lexical zero-hit honesty (review fix): the same
            # token-semantics guidance the search tools carry.
            gaps.append(
                "zero lexical hits — tokens are matched as exact literals (compound "
                "identifiers are indivisible; substrings do not match); try the full "
                "identifier, code_keyword (live substring), or code_pattern (regex)"
            )
        return serve["results"]

    try:
        combined_results, combined_reranked, vector_ms, rerank_ms, definition_boosted, second_hop_symbols, symbol_extraction_method, graph_related = index.search_combined(
            question, top_n=7, question_type=question_type, rerank=rerank
        )
        # 1seaq: classify the exact-first artifact short-circuit honestly —
        # it returns keyword matches BEFORE semantic retrieval (a healthy
        # mode, not a fallback). The marker is the sentinel the short-circuit
        # return places in the definition_boosted slot; no DEFINITION_BOOST
        # rule may ever be labeled "artifact_anchored" (it would misclassify
        # semantic results as exact).
        if definition_boosted == ["artifact_anchored"]:
            search_mode = "exact"
        # Detect whether the scaffolding-layer partition fired (explanatory questions only)
        if question_type == "explanatory" and combined_reranked and combined_results:
            infra_paths = {
                r.get("path", "") for r in combined_results
                if any(seg in Path(r.get("path", "")).parts for seg in INFRASTRUCTURE_PATH_SEGMENTS)
            }
            infrastructure_demoted = bool(infra_paths)
    except SemanticModelUnavailableOfflineError as exc:
        combined_results = _degraded_citation_pass("model_unavailable", str(exc))
    except IndexNotReadyError as exc:
        combined_results = _degraded_citation_pass("index_missing", str(exc))
    except Exception as exc:  # noqa: BLE001 - typed, never a bare generic gap
        combined_results = []
        fallback_reason = "query_failed"
        gaps.append(f"search infrastructure failure (query_failed): {exc}")
    _log_degradation_transition(root, "code_ask", fallback_reason)

    def _to_citation(r: dict) -> dict:
        path = r.get("path", "")
        lines = r.get("lines") or []
        line_range = f":{lines[0]}-{lines[1]}" if len(lines) == 2 else ""
        # Wave 1p4hj: return the FULL chunk text (reranker parity — the unit
        # the cross-encoder ranks on, not a 300-char sliver). Release-review
        # fix: "local" is a documented alias of the same single path, so it
        # gets the identical excerpt (the old 300-char truncation is gone).
        full = r.get("text") or ""
        cit = {
            "ref": f"{path}{line_range}",
            "path": path,
            "lines": lines,
            "excerpt": full,
            "score": r.get("score"),
            "kind": r.get("kind"),
        }
        # Release-review fix: "local" is a documented alias of "agent" — the
        # source metadata is part of the citation contract in both.
        if r.get("source") is not None:
            cit["source"] = r.get("source")
        if r.get("sources"):
            cit["sources"] = r.get("sources")
        return cit

    broad_hits = combined_results
    # Wave 1p52p: code_ask is always the agent path, which applied the doc-type demotion PRE-selection
    # (so the relevance drop-off could trim the demoted narrative tail) — don't double-apply here; just
    # report how many of the returned candidates carry the demotion weight.
    demotion_count = (
        sum(1 for r in broad_hits
            if _doc_demotion_weight(r.get("path", ""), str(r.get("kind") or "").strip().lower()) < 1.0)
        if question_type in _DOC_DEMOTION_INTENTS else 0
    )
    partition_applied = bool(demotion_count)
    citations = []
    for final_rank, r in enumerate(broad_hits, start=1):
        # Wave 1p4hj: agent-mode's text budget (AGENT_TEXT_BUDGET_CHARS) is enforced
        # inside the candidate selection (_agent_candidate_select), which packs by
        # relevance within the budget AND honors the per-index floor — so there's no
        # post-hoc tail-trim to do here (a response-side trim would re-cut the floor
        # when the floor itself is near budget). Just build the citations.
        citation = _to_citation(r)
        citation["final_rank"] = final_rank
        citations.append(citation)

    # Targeted pass: keyword and structural lookup when broad pass is thin.
    # Review fix: SUPPRESSED in lexical fallback — mixing live code_keyword
    # citations into an envelope labeled lexical_fallback would violate the
    # mode contract (the citations would not all be FTS-published data).
    if len(citations) < 2 and search_mode != "lexical_fallback" and not (
        fallback_reason in ("query_failed", "store_absent", "index_not_ready")
    ):
        # (release-review fix: the live keyword pass must not mask an
        # infrastructure failure with "Based on indexed sources" — during a
        # store/model outage the honest envelope is the failure itself.)
        try:
            kw_resp = code_keyword_response(root, question.split()[0] if question.split() else question)
            if kw_resp.get("status") != "ok":
                gaps.append("keyword search failed")
            else:
                kw_results = kw_resp.get("data", {}).get("results", [])[:3]
                for r in kw_results:
                    _kw_path = r.get("path", "")
                    citations.append({
                        "ref": f"{_kw_path}:{r.get('line', '')}",
                        "path": _kw_path,
                        "lines": [r.get("line"), r.get("line")],
                        "excerpt": r.get("snippet", ""),
                        "score": None,
                        "kind": "keyword",
                        # Release-review fix: citation source parity — the
                        # same path-based labeling the exact-first pass uses.
                        "source": "docs" if (_kw_path.startswith("docs/") or "/docs/" in _kw_path or _kw_path.endswith(".md")) else "code",
                    })
        except Exception:
            gaps.append("keyword search unavailable")

    if not citations:
        gaps.append(f"no indexed evidence found for: {question!r}")

    for final_rank, citation in enumerate(citations, start=1):
        citation["final_rank"] = final_rank

    # 1ro43: per-citation freshness annotation (batched; silent absence; the
    # helper skips live_fallback — code_ask never serves that mode, but the
    # guard is uniform). Drift partition only on the healthy reranked path;
    # `final_rank` is re-stamped when it fires so rank matches output order.
    _annotate_freshness(citations, index.root, search_mode=search_mode)
    drift_demoted_count = 0
    if combined_reranked and search_mode in ("semantic", "hybrid"):
        drift_demoted_count = _partition_drift(citations)
        if drift_demoted_count:
            for final_rank, citation in enumerate(citations, start=1):
                citation["final_rank"] = final_rank

    # Wave 1p66r: relevance-gated abstention. The per-index anti-starvation floor
    # always returns ~6 citations even when every cross-encoder score is ~0.001
    # (zero-signal retrieval), which previously read as confident evidence. When
    # the reranker ran, mark each sub-floor citation `weak` (a navigation lead, not
    # answer-bearing) and — if even the BEST candidate is below the relevance floor
    # — surface an explicit "no confident match" gap so a consumer does not treat
    # the result as load-bearing. Citations are still returned (anti-starvation
    # preserved) and fidelity is untouched — this only labels weak results honestly.
    # No absolute floor in the no-reranker path: mixed-model cosine (arctic-doc vs
    # bge-code) is not a calibrated band (see `_heuristic_confidence`), so the
    # no-reranker confidence cap is the signal there.
    if citations and combined_reranked:
        top_score = max((c.get("score") or 0.0) for c in citations)
        for c in citations:
            if (c.get("score") or 0.0) < CONF_AGENT_RERANK_LOW:
                c["weak"] = True
        if top_score < CONF_AGENT_RERANK_LOW:
            gaps.append(
                "no confident match — all retrieval scores are below the relevance "
                "floor; treat the citations as weak navigation leads and verify with "
                "code_keyword / code_search / grep before relying on them"
            )
    elif citations and not combined_reranked and search_mode != "lexical_fallback" and fallback_reason is None:
        # (1seav review fix: in lexical fallback the ranking is BM25 by
        # design, confidence is already capped low, and the cause is stated
        # in the degraded-mode gap — the reranker-unavailable text would
        # misdiagnose "vector-only" and misdirect to reranker setup.)
        # Wave 1p66r: the cross-encoder is the single intended ranking path; a
        # False here means it did not run (disabled via WAVEFOUNDRY_DISABLE_RERANKER
        # or the reranker model could not be built/loaded), so ranking is vector-only
        # and degraded. Make that degradation LOUD rather than silently returning
        # count-capped confidence — a healthy install always reranks.
        gaps.append(
            "reranker unavailable — ranking is vector-only and degraded; the "
            "cross-encoder did not run (disabled via WAVEFOUNDRY_DISABLE_RERANKER, "
            "or the reranker model could not be built/loaded). Confidence is capped "
            "at 'medium'; verify the reranker setup if you expect reranking."
        )

    # Wave 1p66t: enumeration intent ("which/all X are …") — semantic retrieval returns a reranked
    # top-k, which under-counts a full set. Retrieval was widened (text budget), but flag that the
    # list may be incomplete and route to an exact pass rather than implying completeness.
    if citations and _is_enumeration_query(question):
        gaps.append(
            "enumeration query — citations are a ranked sample and may be INCOMPLETE; for the full "
            "set use an exact pass (code_keyword / code_references / code_pattern) or grep."
        )

    confidence = _heuristic_confidence(citations, combined_reranked)
    # 1seaq: degraded (lexical-fallback) citations are exact-token matches,
    # not cross-encoder-ranked semantic recall — cap the confidence.
    if search_mode == "lexical_fallback" and confidence in ("high", "medium"):
        confidence = "low"

    # Assemble answer text from top citations
    _infra_failure = fallback_reason in ("query_failed", "store_absent", "index_not_ready")
    if citations:
        top = citations[0]
        answer = f"Based on indexed sources: see {top['ref']}."
        if len(citations) > 1:
            answer += f" Additional evidence in {', '.join(c['ref'] for c in citations[1:3])}."
    elif _infra_failure:
        # Review fix: an infrastructure failure must never read as corpus
        # absence — an agent synthesizing from `answer` would conclude
        # "not covered" when the truth is "retrieval was unavailable".
        answer = (
            f"Search infrastructure failure ({fallback_reason}) — retrieval was "
            "unavailable, so the absence of citations says NOTHING about corpus "
            "coverage. Check index_health and retry."
        )
    elif search_mode == "lexical_fallback":
        # Release-review fix: a WORKING lexical zero-hit is an exact-token
        # miss, not evidence of absence — semantic recall was unavailable.
        answer = (
            "No exact-token matches in the lexical fallback (semantic recall was "
            "unavailable). This is NOT evidence the topic is uncovered — compound "
            "identifiers are indivisible tokens; try the full identifier, "
            "code_keyword, or code_pattern, or retry when the semantic path recovers."
        )
    else:
        answer = f"No indexed evidence found for this question. The topic may not be covered in the current index or may use different terminology."

    total_ms = round((time.monotonic() - t_start) * 1000)
    _wf_log(f"[wavefoundry] code_ask timing: total={total_ms}ms vector={vector_ms}ms rerank={rerank_ms}ms")

    data: dict[str, Any] = {
        "question": question,
        "question_type": question_type,
        "answer": answer,
        "citations": citations,
        "confidence": confidence,
        "gaps": gaps,
        "index_freshness": index_freshness,
        "search_mode": search_mode,
        "fallback_reason": fallback_reason,
        **({"coverage": degraded_coverage} if (degraded_coverage or search_mode == "lexical_fallback" or fallback_reason is not None) else {}),
        "reranked": combined_reranked,
        # Wave 1p52p: code_ask has a single ranking path — agent selection with a rerank-FIRST
        # cross-encoder. ``rerank_mode`` is always "agent"; the ``reranked`` bool tells whether the
        # cross-encoder actually ran (True; GPU FP16 or CPU INT8) or reranking was explicitly disabled /
        # unbuildable (False). The former "local"/"rrf_fallback" modes were removed.
        "rerank_mode": "agent",
        "partition_applied": partition_applied,
        "demotion_count": demotion_count,
        "total_ms": total_ms,
        "vector_ms": vector_ms,
        "rerank_ms": rerank_ms,
    }
    if infrastructure_demoted:
        data["infrastructure_demoted"] = True
    if drift_demoted_count:
        # 1ro43: distinct from `partition_applied` (doc-type SCORE demotion,
        # 1p52p) — the drift partition is order-only and reason-tagged
        # per-citation; never overload the existing flag's meaning.
        data["drift_partition_applied"] = True
        data["drift_demoted_count"] = drift_demoted_count
    if definition_boosted:
        data["definition_boosted"] = definition_boosted
    if second_hop_symbols:
        data["second_hop_symbols"] = second_hop_symbols
    if symbol_extraction_method != "none":
        data["symbol_extraction_method"] = symbol_extraction_method
    # Wave 1p4hu: structural matches grouped by relationship to the query symbol (callers / readers /
    # importers / related), separate from the textual citations. Present only in agent mode when the
    # graph signal resolved a symbol and found neighbors.
    if graph_related and any(graph_related.get(k) for k in _GRAPH_RELATED_SIGNAL_KEYS):
        data["graph_related"] = graph_related

    if question_type == "explanatory" and citations and citations[0].get("kind") in ("doc", "doc-summary"):
        data["validation_required"] = True

    next_tools = ["code_read", "docs_search"]
    if citations:
        top_path = citations[0].get("path", "")
        if top_path:
            try:
                with (root / top_path).open(encoding="utf-8", errors="replace") as _f:
                    line_count = sum(1 for _ in _f)
                if line_count > 300:
                    next_tools = ["code_outline", "code_read"]
            except Exception:
                pass

    _ask_diagnostics: list[dict[str, Any]] = []
    if _infra_failure:  # release-review fix: attached regardless of citations
        _ask_diagnostics.append(_diagnostic(
            "search_infrastructure_failure",
            f"Retrieval was unavailable ({fallback_reason}); zero citations here does "
            "not mean the topic is uncovered. Check the index state and retry.",
            recovery_tools=["index_health"],
            recovery_usage="index_health()",
        ))
    return _response(
        "ok",
        data,
        diagnostics=_ask_diagnostics,
        next_tools=next_tools,
        usage=f"code_read(path={citations[0]['path']!r}, start_line={citations[0]['lines'][0] if citations[0]['lines'] else 1})" if citations else "code_search(query=...)",
    )


