def _context_data(response: dict[str, Any]) -> dict[str, Any]:
    data = response.get("data")
    if isinstance(data, dict):
        return data
    data = {}
    response["data"] = data
    return data


def _context_source_paths(
    tool_name: str, response: dict[str, Any]
) -> list[str]:
    """Extract only paths whose content-bearing fields are in the envelope.

    This is deliberately an explicit public-shape census. Recursive
    ``path``/``file`` guessing is unsafe because indexed envelopes also carry
    graph neighbors, communities, dependency scope, and other reference-only
    metadata that must never become a whole-file savings baseline.
    """

    data = response.get("data")
    if not isinstance(data, dict):
        return []
    paths: set[str] = set()

    def add_rows(
        rows_key: str,
        path_key: str,
        content_keys: tuple[str, ...],
        *,
        present_is_content: bool = False,
    ) -> None:
        rows = data.get(rows_key)
        if not isinstance(rows, list):
            return
        for row in rows:
            if not isinstance(row, dict):
                continue
            path = row.get(path_key)
            if not isinstance(path, str) or not path or path == "external":
                continue
            if present_is_content:
                content_bearing = any(key in row for key in content_keys)
            else:
                content_bearing = any(
                    row.get(key) not in (None, "") for key in content_keys
                )
            if content_bearing:
                paths.add(path)

    if tool_name == "code_ask":
        add_rows("citations", "path", ("excerpt",))
    elif tool_name in {"code_search", "docs_search"}:
        add_rows("results", "path", ("excerpt", "text"))
    elif tool_name == "code_lexical":
        add_rows("results", "path", ("text",))
    elif tool_name == "code_keyword":
        add_rows("results", "path", ("snippet", "text"))
    elif tool_name == "code_pattern":
        add_rows("matches", "file", ("text",), present_is_content=True)
    elif tool_name == "code_constants":
        add_rows("results", "file", ("value",), present_is_content=True)
    elif tool_name == "code_read":
        path = data.get("path")
        if isinstance(path, str) and path and "content" in data:
            paths.add(path)
    elif tool_name == "code_hover":
        # The hover envelope names its file under "file" (not "path") —
        # live-verified against code_hover_response; the symbol dict is the
        # content-bearing signal.
        path = data.get("file")
        if isinstance(path, str) and path and data.get("symbol"):
            paths.add(path)
    elif tool_name == "code_outline":
        path = data.get("file")
        symbols = data.get("symbols")
        if isinstance(path, str) and path and isinstance(symbols, list) and symbols:
            paths.add(path)
    elif tool_name == "code_definition":
        add_rows("definitions", "path", ("snippet",))
    elif tool_name == "code_references":
        add_rows("references", "path", ("snippet",))
    elif tool_name == "code_callhierarchy":
        add_rows("outgoing", "file", ("snippet",))
        add_rows("incoming", "file", ("snippet",))
    elif tool_name == "code_commit_provenance":
        # The resolved wave record / change docs whose recorded reasoning
        # (Decision Log excerpt) the response surfaces in lieu of re-reading them.
        add_rows("provenance", "path", ("excerpt", "rationale"))
    return sorted(paths)


def _context_structural_paths(
    tool_name: str, response: dict[str, Any]
) -> list[str]:
    """Extract only file fields explicitly represented by graph results."""

    data = response.get("data")
    if not isinstance(data, dict):
        return []
    paths: set[str] = set()

    def add(value: Any) -> None:
        if isinstance(value, str) and value and value != "external":
            paths.add(value)

    def add_rows(value: Any, key: str) -> None:
        if not isinstance(value, list):
            return
        for row in value:
            if isinstance(row, dict):
                add(row.get(key))

    if tool_name == "code_dependencies":
        add(data.get("path"))
    elif tool_name == "code_impact":
        # Heuristic mode exposes the seed and importers; graph mode exposes
        # the bounded affected rows. Hidden neighbors never enter this census.
        add(data.get("path"))
        add_rows(data.get("importers"), "file")
        add_rows(data.get("affected"), "source_file")
    elif tool_name == "code_callgraph":
        add_rows(data.get("nodes"), "source_file")
    elif tool_name == "code_graph_path":
        add_rows(data.get("path_nodes"), "source_file")
    elif tool_name == "code_graph_community":
        add_rows(data.get("nodes"), "source_file")
    elif tool_name == "code_risk_score":
        add_rows(data.get("results"), "source_file")
    return sorted(paths)


def _context_indexed_proofs(
    root: Path,
    tool_name: str,
    response: dict[str, Any],
    *,
    epoch_stable: bool,
) -> list[context_efficiency.SourceProof]:
    paths = _context_source_paths(tool_name, response)
    if not paths:
        return []
    normalized: list[tuple[str, str]] = []
    for path in paths:
        rel = path
        try:
            candidate = Path(path)
            if candidate.is_absolute():
                rel = candidate.resolve().relative_to(root.resolve()).as_posix()
            else:
                rel = candidate.as_posix()
        except (OSError, RuntimeError, ValueError):
            rel = path
        normalized.append((path, rel))
    try:
        metadata = _load_script("index_state_store").read_build_file_meta(
            root / ".wavefoundry" / "index",
            [rel for _, rel in normalized],
        )
    except Exception:
        metadata = None
    rows = metadata if isinstance(metadata, dict) else {}
    proofs: list[context_efficiency.SourceProof] = []
    for _path, rel in normalized:
        row = rows.get(rel)
        version = (
            context_efficiency.FileVersion.from_index_meta(row)
            if isinstance(row, dict)
            else None
        )
        proofs.append(
            context_efficiency.indexed_source_proof(
                rel, version, epoch_stable=epoch_stable
            )
        )
    return proofs


def _context_current_size_proofs(
    tool_name: str, response: dict[str, Any],
) -> list[context_efficiency.SourceProof]:
    return [
        context_efficiency.SourceProof(path, "live", None)
        for path in _context_source_paths(tool_name, response)
    ]


def _context_structural_proofs(
    tool_name: str, response: dict[str, Any],
) -> list[context_efficiency.SourceProof]:
    return [
        context_efficiency.SourceProof(
            path,
            "live",
            None,
            credit_kind="structural",
        )
        for path in _context_structural_paths(tool_name, response)
    ]


def _retrieval_failure_metric(core_response: dict[str, Any]) -> dict[str, Any]:
    try:
        returned = context_efficiency.estimate_tokens_utf8(
            context_efficiency.canonical_core_json(core_response)
        )
    except Exception:
        returned = 0
    return {
        "estimated_request_tokens": 0,
        "estimated_returned_tokens": returned,
        "estimated_source_tokens": 0,
        "estimated_avoided_tokens": 0,
        "source_files_counted": 0,
        "source_files_verified": 0,
        "source_files_estimated": 0,
        "source_files_credited": 0,
        "source_credits_dropped": 0,
        "captured": False,
        "persistence": "failed",
        "method": context_efficiency.RETRIEVAL_METHOD,
    }


def _attach_retrieval_failure_context(
    tool_name: str, response: dict[str, Any]
) -> dict[str, Any]:
    """Keep every retrieval envelope shaped without buffering rejected work."""

    retrieval_tools = globals().get("_CONTEXT_RETRIEVAL_TOOLS", ())
    if tool_name in retrieval_tools:
        _context_data(response)["context_avoided"] = (
            _retrieval_failure_metric(response)
        )
    return response


def code_commit_provenance_response(
    root: Path,
    commit: str = "",
    path: str = "",
    line_start: int = 0,
    line_end: int = 0,
) -> dict[str, Any]:
    """Reverse provenance: a commit SHA (or file + line range) -> the wave(s)
    that produced it and their recorded reasoning. Local, read-only, honest on
    absence and on message/evidence conflict (both reported, never reconciled)."""
    cp = _load_script("commit_provenance")
    commit = (commit or "").strip()
    path = (path or "").strip()
    if bool(commit) == bool(path):
        return _response(
            "error", {"resolved": False, "waves": [], "provenance": []},
            diagnostics=[_diagnostic(
                "invalid_arguments",
                "Provide exactly one input mode: commit SHA, or file path with a line range.",
                recovery_tools=["code_commit_provenance"],
                recovery_usage="code_commit_provenance(commit='<sha>') or code_commit_provenance(path='<file>', line_start=N, line_end=M)")],
            next_tools=["code_commit_provenance"], usage="")
    if commit:
        if not cp.is_valid_sha(commit):
            return _response(
                "error", {"resolved": False, "waves": [], "provenance": []},
                diagnostics=[_diagnostic(
                    "invalid_arguments", "commit must be a 7-40 character hexadecimal SHA",
                    recovery_tools=["code_commit_provenance"],
                    recovery_usage="code_commit_provenance(commit='<sha>')")],
                next_tools=["code_commit_provenance"], usage="")
        data = cp.provenance_for_sha(root, commit)
    else:
        try:
            start = int(line_start)
            end = int(line_end or start)
        except (TypeError, ValueError):
            start = 0
            end = -1
        if start < 1 or end < start:
            return _response(
                "error", {"resolved": False, "waves": [], "provenance": []},
                diagnostics=[_diagnostic(
                    "invalid_arguments", "line range must satisfy 1 <= line_start <= line_end",
                    recovery_tools=["code_commit_provenance"],
                    recovery_usage="code_commit_provenance(path='<file>', line_start=N, line_end=M)")],
                next_tools=["code_commit_provenance"], usage="")
        data = cp.provenance_for_line(root, path, start, end)
    diagnostics = []
    # Per-call activity signal (not a token target): the atom that a
    # resolution_hit_rate / honest_absence_rate aggregates over. Honest, derived
    # only from what this call actually resolved.
    if data.get("conflict"):
        data["resolution"] = "conflict"
    elif data.get("partial"):
        data["resolution"] = "partial"
    elif not data.get("resolved"):
        data["resolution"] = "honest_absence"
    else:
        data["resolution"] = "resolved"
    if data.get("partial"):
        diagnostics.append(_diagnostic(
            "partial_provenance",
            "The requested range includes uncommitted lines; committed provenance is "
            "reported with explicit coverage and is not presented as complete.",
            recovery_tools=["code_commit_provenance"], recovery_usage=""))
    if not data.get("resolved") and not data.get("partial"):
        diagnostics.append(_diagnostic(
            "no_wave_provenance",
            "No wave provenance found for this commit/line — it may predate the "
            "framework, be a non-conventional commit, or have been rebased/squashed. "
            "Reported honestly, not guessed.",
            recovery_tools=["code_commit_provenance"], recovery_usage=""))
    if data.get("conflict"):
        diagnostics.append(_diagnostic(
            "provenance_conflict",
            "The commit-message and evidence-search paths named different waves; "
            "both are reported, not reconciled.",
            recovery_tools=["code_commit_provenance"], recovery_usage=""))
    return _response(
        "ok", data, diagnostics=diagnostics,
        next_tools=["wf_get_change", "code_read"],
        usage="wf_get_change(change_id=...)")


def _record_retrieval_context(
    handler: "ImplHandler",
    tool_name: str,
    response: dict[str, Any],
    *,
    indexed_epoch_stable: bool = False,
    request_arguments: Any = None,
) -> dict[str, Any]:
    """Attach one fail-isolated metric at the public tool envelope."""

    if tool_name not in _CONTEXT_RETRIEVAL_TOOLS:
        return response
    try:
        if tool_name in _REFERENCE_ONLY_GRAPH_TOOLS:
            proofs = _context_structural_proofs(tool_name, response)
        elif tool_name in _INDEXED_CONTEXT_TOOLS:
            proofs = _context_indexed_proofs(
                handler.root,
                tool_name,
                response,
                epoch_stable=indexed_epoch_stable,
            )
        else:
            # Exact-navigation helpers do not expose a read-bracketing
            # signature. Their contained current-file size is still a useful
            # estimate, but the metric classifies it separately from a
            # same-version verified baseline.
            proofs = _context_current_size_proofs(tool_name, response)
        metric = context_efficiency.retrieval_context_avoided(
            response,
            handler.root,
            proofs,
            request_arguments=request_arguments,
        )
        if metric.get("captured") is not True:
            public = _poisoned_or_fatal_telemetry_failure(
                handler.root, metric
            )
        else:
            public = handler.telemetry.record_retrieval(
                metric, tool_name=tool_name
            )
    except Exception:
        public = _poisoned_or_fatal_telemetry_failure(
            handler.root, _retrieval_failure_metric(response)
        )
    if public.get("fatal_persistence_failure") is True:
        return {
            "status": "error",
            "data": {
                "failed": True,
                "stage": "context_efficiency",
                "error_code": "telemetry_persistence_failed",
            },
            "diagnostics": [
                {
                    "code": "telemetry_persistence_failed",
                    "message": (
                        "The tool result was withheld because neither its "
                        "telemetry event nor the durable accounting-gap "
                        "barrier could be persisted."
                    ),
                }
            ],
            "next_tools": [],
        }
    _context_data(response)["context_avoided"] = public
    return response


def _workflow_failure_metric(core_response: dict[str, Any]) -> dict[str, Any]:
    try:
        returned = context_efficiency.estimate_tokens_utf8(
            context_efficiency.canonical_core_json(core_response)
        )
    except Exception:
        returned = 0
    return {
        "estimated_request_tokens": 0,
        "estimated_returned_tokens": returned,
        "prompt_surface_tokens": 0,
        "estimated_compaction_tokens": 0,
        "credited": False,
        "captured": False,
        "persistence": "failed",
        "method": context_efficiency.WORKFLOW_PROXY_METHOD,
        "limitation": context_efficiency.WORKFLOW_PROXY_LIMITATION,
    }


def _poisoned_or_fatal_telemetry_failure(
    root: Path, metric: dict[str, Any]
) -> dict[str, Any]:
    """Fail closed when instrumentation raises before its normal commit path."""

    payload = dict(metric)
    if context_efficiency.poison_accounting_gap(root):
        payload["persistence"] = "poisoned"
    else:
        payload["persistence"] = "failed"
        payload["fatal_persistence_failure"] = True
    payload["captured"] = False
    return payload


def _record_workflow_context(
    handler: "ImplHandler",
    tool_name: str,
    wave_id: str,
    response: dict[str, Any],
    *,
    request_arguments: Any = None,
    milestone_completed: bool,
) -> dict[str, Any]:
    """Persist debits for every reached handler; credit only a milestone."""

    try:
        metric = context_efficiency.workflow_instruction_proxy(
            response,
            handler.root,
            tool_name,
            request_arguments=request_arguments,
            milestone_completed=milestone_completed,
        )
        if metric.get("captured") is not True:
            public = _poisoned_or_fatal_telemetry_failure(
                handler.root, metric
            )
        else:
            public = handler.telemetry.record_workflow(
                wave_id,
                _LIFECYCLE_CONTEXT_STAGES[tool_name],
                tool_name,
                metric,
            )
    except Exception:
        public = _poisoned_or_fatal_telemetry_failure(
            handler.root, _workflow_failure_metric(response)
        )
    if public.get("fatal_persistence_failure") is True:
        return {
            "status": "error",
            "data": {
                "failed": True,
                "stage": "context_efficiency",
                "error_code": "telemetry_persistence_failed",
            },
            "diagnostics": [
                {
                    "code": "telemetry_persistence_failed",
                    "message": (
                        "The lifecycle result was withheld because neither "
                        "its telemetry event nor the durable accounting-gap "
                        "barrier could be persisted."
                    ),
                }
            ],
            "next_tools": [],
        }
    _context_data(response)["workflow_instruction_proxy"] = public
    return response


def _wave_checkpoint_floor(root: Path, wave_id: str) -> dict[str, Any]:
    wave_md = _find_wave_md(root, wave_id)
    if wave_md is None:
        return context_efficiency.empty_checkpoint(wave_id)
    try:
        parsed = context_efficiency.parse_checkpoint_block(
            wave_md.read_text(encoding="utf-8")
        )
    except OSError:
        parsed = None
    return parsed or context_efficiency.empty_checkpoint(wave_md.parent.name)


def _flush_context_efficiency(
    handler: "ImplHandler",
    wave_id: str,
    *,
    transfer_general: bool = False,
) -> tuple[dict[str, Any], context_efficiency.FlushResult | None]:
    """Persist one process buffer and project its durable wave checkpoint."""

    root = handler.root
    canonical_wave = wave_id
    try:
        wave_md = _find_wave_md(root, wave_id)
        if wave_md is None:
            return (
                {"persistence": "failed", "projection": "wave_not_found"},
                None,
            )
        canonical_wave = wave_md.parent.name
        floor = _wave_checkpoint_floor(root, canonical_wave)
        initial_markdown = wave_md.read_text(encoding="utf-8")
        status_match = _STATUS_PATTERN.search(initial_markdown)
        sealed = bool(status_match and status_match.group(1) == "closed")
        context_efficiency.reconcile_checkpoint_authority(
            root, canonical_wave, floor, sealed=sealed
        )
        # Wave 1t3ek (1t3el): boundary adoption stamps the stage the wave is
        # actually in — plan while planned/paused (create/prepare boundaries),
        # implement while OPEN, review once the ledger holds a delivery run.
        wave_status = status_match.group(1) if status_match else ""
        if wave_status in ("active", "implementing"):
            transfer_stage = context_efficiency._derive_open_wave_stage(wave_md.parent)
        else:
            transfer_stage = "plan"
        flushed = handler.telemetry.flush(
            root,
            transfer_general_to=canonical_wave if transfer_general else None,
            transfer_stage=transfer_stage,
            checkpoint_floors=None,
        )
        if not flushed.success:
            return (
                {
                    "persistence": "failed",
                    "projection": "pending",
                    "error": flushed.error,
                },
                flushed,
            )
        with review_event_write_lock(root):
            # Re-read both authorities under the shared writer lock. A second
            # process may have flushed a newer generation after this process's
            # transaction committed but before it reached projection.
            snapshot = context_efficiency.read_wave_snapshot(
                root, canonical_wave
            )
            published = dict(snapshot)
            published["pending"] = False
            current = wave_md.read_text(encoding="utf-8")
            updated = context_efficiency.replace_checkpoint_block(
                current, published
            )
            exploration = _load_script("exploration_avoided")
            updated = exploration.replace_checkpoint_block(
                updated, root, canonical_wave
            )
            if updated != current:
                _atomic_replace_text(
                    wave_md, updated, "context-efficiency-projection"
                )
            marked = context_efficiency.mark_checkpoint_published(
                root,
                canonical_wave,
                published,
                expected_generation=int(snapshot.get("generation", 0)),
                seal=sealed,
            )
            compacted = (
                context_efficiency.compact_published_wave(
                    root,
                    canonical_wave,
                    expected_generation=int(snapshot.get("generation", 0)),
                )
                if marked and sealed
                else not sealed
            )
            if marked and sealed and compacted:
                handler.telemetry.clear_focus()
        return (
            {
                "persistence": "durable",
                "projection": "published" if marked and compacted else "pending",
                "sealed": sealed,
                "compacted": bool(marked and sealed and compacted),
                "credited_invocations": sorted(
                    f"{wave}:{invocation_id}"
                    for wave, invocation_id in flushed.credited_keys
                ),
                "duplicate_invocations": sorted(
                    f"{wave}:{invocation_id}"
                    for wave, invocation_id in flushed.duplicate_keys
                ),
            },
            flushed,
        )
    except Exception as exc:
        return (
            {
                "persistence": "failed",
                "projection": "pending",
                "error": f"{type(exc).__name__}: {exc}",
                "wave_id": canonical_wave,
            },
            None,
        )


def project_pending_context_efficiency(
    handler: "ImplHandler",
) -> dict[str, Any]:
    """Project every pending durable wave generation before reload/upgrade."""

    pending_state = context_efficiency.pending_wave_ids(handler.root)
    if not pending_state.get("ok"):
        return {
            "ok": False,
            "projected": [],
            "failed_wave": None,
            "detail": {
                "persistence": "failed",
                "projection": "unavailable",
                "error": pending_state.get("error"),
                "authority_status": pending_state.get("status"),
            },
        }
    pending = list(pending_state.get("pending", []))
    projected: list[str] = []
    for wave_id in pending:
        result, _flushed = _flush_context_efficiency(handler, wave_id)
        if result.get("projection") != "published":
            return {
                "ok": False,
                "projected": projected,
                "failed_wave": wave_id,
                "detail": result,
            }
        projected.append(wave_id)
    return {"ok": True, "projected": projected}


def _context_efficiency_state(
    handler: "ImplHandler", wave_ids: Iterable[str]
) -> dict[str, Any]:
    """Read-only durable + current-process overlay; never creates the store."""

    canonical_waves = sorted({wave for wave in wave_ids if wave})
    health = context_efficiency.read_store_health(handler.root)
    if health["status"] == "failed":
        durable = {
            wave_id: _wave_checkpoint_floor(handler.root, wave_id)
            for wave_id in canonical_waves
        }
        durable_general = {
            "calls": 0,
            "request_debit": 0,
            "response_debit": 0,
            "source_credit": 0,
            "estimated_tokens_saved": 0,
        }
        durable_source = "published_checkpoint_floor"
        durable_general_available = False
    else:
        durable = {
            wave_id: context_efficiency.read_wave_snapshot(
                handler.root, wave_id
            )
            for wave_id in canonical_waves
        }
        durable_general = context_efficiency.read_general_totals(handler.root)
        durable_source = (
            "sidecar"
            if health["status"] in {"healthy", "accounting_gap"}
            else "empty_store"
        )
        durable_general_available = True
    producer_id: str | None = None
    try:
        buffered = handler.telemetry.buffered_snapshot()
        producer_id = buffered.pop("producer_id", None)
    except Exception:
        buffered = {
            "focus": None,
            "retrieval": {},
            "workflow_credit_intents": [],
            "general_note": context_efficiency.GENERAL_ASSOCIATION_NOTE,
            "available": False,
            "persistence": "failed",
        }
    if health["status"] in {"healthy", "accounting_gap"}:
        durable_general = context_efficiency.read_general_totals(
            handler.root, producer_id
        )
    return {
        "durable_waves": durable,
        "current_process": buffered,
        "durable_general": durable_general,
        "durable_source": durable_source,
        "durable_general_available": durable_general_available,
        "persistence_health": health,
        "visibility": (
            "SQLite is the live write-through authority. Process focus and "
            "producer-scoped general attribution remain isolated; wave.md is "
            "the last published checkpoint. Accounting gaps suppress a "
            "positive headline."
        ),
    }


def _implementation_review_complete(response: dict[str, Any]) -> bool:
    """Return whether an implementation review reached its public milestone."""

    if response.get("status") != "ok":
        return False
    data = response.get("data")
    if not isinstance(data, dict) or data.get("phase") != "implementation":
        return False
    if data.get("lint_passed") is not True:
        return False
    lane_results = data.get("lane_results")
    council_results = data.get("council_results")
    return (
        isinstance(lane_results, list)
        and isinstance(council_results, list)
        and all(
            isinstance(row, dict) and row.get("recorded_signoff") is True
            for row in lane_results
        )
        and all(
            isinstance(row, dict) and row.get("recorded_signoff") is True
            for row in council_results
        )
    )


def wf_context_efficiency_eval_response(
    root: Path,
    wave_id: str,
    phase_id: str,
    *,
    mode: str,
    report_path: str = "",
    applicability: Mapping[str, Any] | None = None,
) -> dict[str, Any]:
    """Register or attach one phase-scoped paired evaluation."""

    mode_s = str(mode or "").strip().lower()
    try:
        if mode_s == "register":
            result = context_efficiency.attach_evaluation(
                root,
                wave_id,
                phase_id,
                mode=mode_s,
                applicability=applicability,
            )
        elif mode_s in {"attach", "replace"}:
            candidate = Path(report_path)
            if not candidate.is_absolute():
                candidate = root / candidate
            resolved_root = root.resolve(strict=True)
            report_file = candidate.resolve(strict=True)
            if (
                not report_file.is_relative_to(resolved_root)
                or not report_file.is_file()
            ):
                raise ValueError("report_path must be a contained file")
            payload = json.loads(report_file.read_text(encoding="utf-8"))
            scorer = _load_script("score_context_efficiency_pairs")
            report = scorer.score_pairs(payload)
            result = context_efficiency.attach_evaluation(
                root,
                wave_id,
                phase_id,
                mode=mode_s,
                report=report,
            )
            result["scorer"] = {
                "qualifying_pairs": int(report["qualifying_pairs"]),
                "quality_gate_passed": bool(report["quality_gate_passed"]),
                "matched_pair_residual": int(report["matched_pair_residual"]),
            }
        elif mode_s == "revoke":
            result = context_efficiency.attach_evaluation(
                root, wave_id, phase_id, mode=mode_s
            )
        else:
            raise ValueError("mode must be register, attach, replace, or revoke")
        return _response(
            "ok",
            result,
            next_tools=["wf_current_wave"],
            usage=(
                "wf_context_efficiency_eval("
                f"wave_id={wave_id!r}, phase_id={phase_id!r}, mode={mode_s!r})"
            ),
        )
    except (OSError, ValueError, json.JSONDecodeError) as exc:
        return _response(
            "error",
            {
                "failed": True,
                "stage": "context_efficiency_evaluation",
                "error": f"{type(exc).__name__}: {exc}",
            },
            diagnostics=[
                {
                    "code": "context_efficiency_evaluation_invalid",
                    "message": str(exc),
                }
            ],
            usage=(
                "Register applicability before running pairs, then attach a "
                "contained context-efficiency pair artifact."
            ),
        )


def _lifecycle_milestone_completed(
    tool_name: str,
    response: dict[str, Any],
    *,
    mutating: bool,
) -> bool:
    """Return whether a mutating lifecycle call completed new milestone work."""

    if not mutating or response.get("status") != "ok":
        return False
    data = response.get("data")
    if not isinstance(data, dict):
        return False
    if tool_name == "wf_create_wave":
        return data.get("created") is True
    if tool_name == "wf_prepare_wave":
        mode = str(data.get("mode", "")).strip().lower()
        if mode == "ready":
            return data.get("readied") is True
        return data.get("transitioned_to_active") is True
    if tool_name == "wf_implement_wave":
        return data.get("transitioned_to_implementing") is True
    if tool_name == "wf_close_wave":
        return data.get("transitioned_to_closed") is True
    return False


def _lifecycle_context_result(
    handler: "ImplHandler",
    tool_name: str,
    wave_id: str,
    response: dict[str, Any],
    *,
    focus_stage: str | None = None,
    credit: bool | None = None,
    flush: bool = False,
    transfer_general: bool = False,
    request_arguments: Any = None,
) -> dict[str, Any]:
    """Apply focus, proxy, flush, and projection after a successful core call."""

    core_succeeded = response.get("status") in {"ok", "dry_run"}
    try:
        wave_md = _find_wave_md(handler.root, wave_id)
    except ValueError:
        wave_md = None
    if wave_md is not None:
        wave_id = wave_md.parent.name
    if credit is None:
        credit = flush
    response_data = response.get("data")
    reached_review = (
        tool_name == "wf_review_wave"
        and isinstance(response_data, dict)
        and isinstance(response_data.get("wave_id"), str)
        and isinstance(response_data.get("lane_results"), list)
        and (response_data.get("phase") in {"prepare", "implementation"})
    )
    if (core_succeeded or reached_review) and focus_stage is not None:
        try:
            handler.telemetry.set_focus(
                wave_id, focus_stage, new_phase=bool(credit)
            )
        except Exception:
            # Telemetry is observational. A wedged in-process buffer must
            # never change the already-successful lifecycle result.
            pass
    response = _record_workflow_context(
        handler,
        tool_name,
        wave_id,
        response,
        request_arguments=request_arguments,
        milestone_completed=bool(credit),
    )
    if response.get("status") == "error" and not (flush and reached_review):
        # Wave 1t3ek (1t22z): a review that RAN but reports pending signoffs
        # (the normal pre-close state) still publishes the checkpoint so the
        # delivery council reads current implement-stage numbers; a review
        # that could not run at all (wave not found, validation crash) does not.
        return response
    if not flush:
        return response
    projection, flushed = _flush_context_efficiency(
        handler,
        wave_id,
        # Wave 1t3ek (1t3el): create/prepare adopt on milestone completion
        # (unchanged); a review that RAN and a mutating close also adopt, so
        # exited helper agents' buckets land on THIS wave instead of the next
        # wave's prepare.
        transfer_general=transfer_general and (bool(credit) or reached_review),
    )
    data = _context_data(response)
    data["context_efficiency_persistence"] = projection
    if flushed is not None and isinstance(
        data.get("workflow_instruction_proxy"), dict
    ):
        data["workflow_instruction_proxy"] = (
            context_efficiency.workflow_proxy_after_flush(
                data["workflow_instruction_proxy"],
                wave_id,
                flushed,
            )
        )
    elif isinstance(data.get("workflow_instruction_proxy"), dict):
        data["workflow_instruction_proxy"]["persistence"] = "failed"
        data["workflow_instruction_proxy"]["credited"] = False
    return response


def set_server_runner_version(v: str) -> None:
    global _runner_version
    _runner_version = v


def version_payload(root: Path, *, server_runner_version: str) -> dict[str, Any]:
    framework_version = _read_framework_version_at_root(root)
    impl_version = SERVER_IMPL_VERSION
    impl_matches_disk: bool | None = None
    if framework_version and impl_version:
        impl_matches_disk = framework_version == impl_version
    return {
        "framework_version": framework_version,
        "server_runner_version": server_runner_version,
        "server_impl_version": impl_version,
        "impl_matches_disk": impl_matches_disk,
    }


class ImplHandler:
    """Owns per-process MCP business state (index, cache, root)."""

    def __init__(self, root: Path) -> None:
        self.root = root.resolve()
        self.index = WaveIndex(self.root)
        self.cache = McpRepoCache(self.root, index=self.index)
        self.telemetry = context_efficiency.ProcessTelemetry(self.root)
        # Wave 1p5xu: in-session index-staleness monitor. Fail-safe + daemon;
        # never blocks __init__/close, swallows all errors, config-gated.
        self._monitor_stop: Any | None = None
        self._monitor_thread: Any | None = None
        try:
            self._start_staleness_monitor()
        except Exception:  # noqa: BLE001
            pass

    def _start_staleness_monitor(self) -> None:
        import threading

        cfg = _read_monitor_config(self.root)
        if not cfg.get("enabled", True):
            return
        interval = float(cfg.get("interval_seconds", _MONITOR_DEFAULT_INTERVAL_SECONDS))
        stop_event = threading.Event()
        root = self.root

        def _loop() -> None:
            while not stop_event.wait(interval):
                try:
                    _maybe_refresh_if_stale(root)
                except Exception:  # noqa: BLE001
                    pass

        thread = threading.Thread(
            target=_loop, name="wavefoundry-index-monitor", daemon=True
        )
        self._monitor_stop = stop_event
        self._monitor_thread = thread
        thread.start()

    def _stop_staleness_monitor(self) -> None:
        stop_event = self._monitor_stop
        thread = self._monitor_thread
        self._monitor_stop = None
        self._monitor_thread = None
        if stop_event is not None:
            try:
                stop_event.set()
            except Exception:  # noqa: BLE001
                pass
        if thread is not None:
            try:
                thread.join(timeout=1.0)
            except Exception:  # noqa: BLE001
                pass

    def close(self) -> None:
        try:
            self._stop_staleness_monitor()
        except Exception:  # noqa: BLE001
            pass
        try:
            self.telemetry.close()
        except Exception:  # noqa: BLE001
            pass
        self.cache.invalidate()
        self.index._loaded = False
        self.index._docs_lance_table = None
        self.index._code_lance_table = None
        self.index._reranker = None
        self.index._model_downloads_started = False
        self.index._loaded_meta_signature = {}
        self.index._lance_available = set()


def build_handler(root: Path) -> ImplHandler:
    return ImplHandler(root)


def wf_server_info_response(root: Path, *, server_runner_version: str | None = None) -> dict[str, Any]:
    return _response(
        "ok",
        server_identity(root, server_runner_version=server_runner_version),
        next_tools=["wf_current_wave", "wf_help"],
        usage="wf_server_info()",
    )


def wf_gpu_doctor_response(root: Path) -> dict[str, Any]:
    """Wave 1p6et: embedding-provider / GPU capability diagnostic (read-only). Runs setup's bounded
    provider probe so the selected provider matches runtime (CoreML on Apple Silicon, etc.). The probe
    loads a model, so stdout is redirected to stderr to keep the MCP stdio stream clean."""
    import contextlib
    import sys as _sys
    import provider_policy
    import setup_index
    import cli_stdio
    # The cold ORT/DirectML probe writes native diagnostics straight to OS fd 1 — the MCP JSON-RPC
    # stdout channel — which `redirect_stdout` (Python-level) cannot intercept; on the first call
    # after a host restart that corrupts the protocol and hangs (wave 1p8vc). `redirect_stdout`
    # routes Python-level output to stderr; `cli_stdio.isolated_stdout_fd()` drops native fd-1 writes.
    # Both wrap ONLY the synchronous probe; fd 1 is restored before the framework writes the response.
    with contextlib.redirect_stdout(_sys.stderr), cli_stdio.isolated_stdout_fd():
        report = provider_policy.diagnostic_report(provider_probe=setup_index._probe_embedding_provider)
    return _response(
        "ok",
        report,
        next_tools=["index_health", "wf_server_info"],
        usage="wf_gpu_doctor()",
    )

# --- First-party tool cost accounting (wave 1t3ek / 1t3s7) -------------------
# Debit-only for the previously unmeasured surface, plus derived-artifact
# credit (avoided writing) where a tool persists textual artifacts the caller
# did not supply. Lifecycle tools (workflow proxies) and the retrieval tools
# (retrieval events) stay on their existing instrumentation.

_COST_EXEMPT_TOOLS = frozenset({
    "wf_create_wave", "wf_prepare_wave", "wf_implement_wave",
    "wf_review_wave", "wf_close_wave", "wf_reload_mcp",
    "code_ask", "code_search", "code_lexical", "docs_search",
    "code_keyword", "code_pattern", "code_constants",
    "code_read", "code_outline", "code_definition", "code_references",
    "code_callhierarchy", "code_impact", "code_dependencies",
    "code_callgraph", "code_graph_path", "code_graph_community",
    "code_commit_provenance",
    # Wave 1t3ek (1t15a): now natively retrieval-instrumented.
    "code_hover", "code_risk_score",
})


def _artifact_file_token_list(root: Path, rel_paths: Iterable[str]) -> list[int]:
    """Per-artifact token sizes for contained files — the credit contract
    floors each artifact independently, so callers get a list, not a sum."""
    tokens: list[int] = []
    for rel in rel_paths:
        if not rel:
            continue
        try:
            candidate = (root / str(rel)).resolve()
            if candidate.is_relative_to(root.resolve()) and candidate.is_file():
                tokens.append(candidate.stat().st_size // 4)
        except (OSError, ValueError):
            continue
    return tokens


def _artifact_from_review_evidence(root: Path, result: Mapping[str, Any]) -> tuple[int, Optional[str]]:
    data = result.get("data") if isinstance(result.get("data"), dict) else {}
    if result.get("status") != "ok" or data.get("mode") != "create" or data.get("replayed"):
        return 0, None
    records = data.get("appended_records") or []
    if not records:
        return 0, None
    digest = None
    for record in records:
        digest = record.get("request_digest") or digest
    tokens = [
        context_efficiency.estimate_tokens_utf8(
            json.dumps(record, sort_keys=True, default=str)
        )
        for record in records
    ]
    return tokens, (f"artifact:{digest}" if digest else None)


def _artifact_from_written_paths(field: str):
    def extract(root: Path, result: Mapping[str, Any]) -> tuple[int, Optional[str]]:
        data = result.get("data") if isinstance(result.get("data"), dict) else {}
        if result.get("status") != "ok":
            return 0, None
        value = data.get(field)
        paths: list[str] = []
        if isinstance(value, list):
            for item in value:
                if isinstance(item, Mapping) and item.get("path"):
                    paths.append(str(item["path"]))
                elif isinstance(item, str):
                    paths.append(item)
        elif isinstance(value, Mapping) and value.get("path"):
            paths.append(str(value["path"]))
        elif isinstance(value, str):
            paths.append(value)
        return _artifact_file_token_list(root, paths), None
    return extract


def _state_sources_review_evidence(root: Path, result: Mapping[str, Any]) -> list[str]:
    data = result.get("data") if isinstance(result.get("data"), dict) else {}
    if result.get("status") != "ok" or data.get("mode") != "create" or data.get("replayed"):
        return []
    paths = []
    for field in ("events_path", "path"):
        value = data.get(field)
        if isinstance(value, str) and value:
            paths.append(value)
    return paths


def _state_sources_memory_validate(root: Path, result: Mapping[str, Any]) -> list[str]:
    data = result.get("data") if isinstance(result.get("data"), dict) else {}
    if result.get("status") != "ok":
        return []
    record = data.get("record")
    path = record.get("path") if isinstance(record, Mapping) else None
    return [str(path)] if path else []


def _state_sources_memory_propose(root: Path, result: Mapping[str, Any]) -> list[str]:
    """Best-effort: resolve the change docs the drafted records derive from."""
    data = result.get("data") if isinstance(result.get("data"), dict) else {}
    if result.get("status") != "ok" or not data.get("written"):
        return []
    change_ids: set[str] = set()
    for item in data.get("written") or []:
        source = item.get("source_event") if isinstance(item, Mapping) else None
        if isinstance(source, str) and source.startswith("decision-log:"):
            parts = source.split(":", 2)
            if len(parts) >= 2 and parts[1]:
                change_ids.add(parts[1])
    paths: list[str] = []
    waves_dir = root / "docs" / "waves"
    try:
        for change_id in sorted(change_ids):
            for match in waves_dir.glob(f"*/{change_id}*.md"):
                paths.append(str(match.relative_to(root)))
                break
    except OSError:
        pass
    return paths


def _state_sources_get_change(root: Path, result: Mapping[str, Any]) -> list[str]:
    """Credit only change docs whose content the response conveys.

    Bulk rows cap content at 300 lines and carry a structural ``truncated``
    field; a truncated row conveys an excerpt, not the document, so it earns
    no whole-file credit. Listing digests (wf_current_wave, wf_list_waves,
    wf_list_plans, wf_map, memory_search, memory_brief) are deliberately
    absent from the extractor table for the same reason: their responses
    reference documents without conveying them, so deterministic whole-file
    credit would scale with corpus size rather than information delivered.
    Counterfactual read-avoidance for digests belongs to paired evaluations
    (wf_context_efficiency_eval), never the measured ledger.
    """
    data = result.get("data") if isinstance(result.get("data"), dict) else {}
    if result.get("status") != "ok":
        return []
    paths: list[str] = []
    change = data.get("change")
    if isinstance(change, Mapping) and change.get("path") and change.get("content"):
        paths.append(str(change["path"]))
    for row in data.get("changes") or []:
        if (
            isinstance(row, Mapping)
            and row.get("path")
            and row.get("content")
            and not row.get("truncated")
        ):
            paths.append(str(row["path"]))
    return paths


def _state_sources_live_waves(root: Path, result: Mapping[str, Any]) -> list[str]:
    """Credit the LIVE working set a wave listing enumerates — never history.

    Whole-corpus credit was rejected (operator direction, 2026-07-20): a
    listing sweeps every wave record to answer a one-line question, so credit
    would scale with repository age. The bounded middle ground credits only
    rows the response marks non-closed — the waves an operator acting on this
    listing would actually open — so credit tracks work in flight, not the
    archive tail.
    """
    data = result.get("data") if isinstance(result.get("data"), dict) else {}
    if result.get("status") != "ok":
        return []
    paths: list[str] = []
    for row in data.get("waves") or []:
        if (
            isinstance(row, Mapping)
            and row.get("path")
            and str(row.get("status") or "") not in ("closed", "")
        ):
            paths.append(str(row["path"]))
    return paths


def _state_sources_list_plans(root: Path, result: Mapping[str, Any]) -> list[str]:
    """Plan docs under docs/plans/ are pending work by construction — the
    listing enumerates the live backlog, bounded by work in flight."""
    data = result.get("data") if isinstance(result.get("data"), dict) else {}
    if result.get("status") != "ok":
        return []
    return [
        str(row["path"])
        for row in data.get("plans") or []
        if isinstance(row, Mapping) and row.get("path")
    ]


def _state_sources_memory_views(*rows_keys: str):
    """Memory views credit the record files they surface (operator direction,
    2026-07-20): each surfaced row names a real record file an agent without
    the tool would have opened, and the response cap bounds the set."""
    def extract(root: Path, result: Mapping[str, Any]) -> list[str]:
        data = result.get("data") if isinstance(result.get("data"), dict) else {}
        if result.get("status") != "ok":
            return []
        paths: list[str] = []
        for key in rows_keys:
            for row in data.get(key) or []:
                if isinstance(row, Mapping) and row.get("path"):
                    paths.append(str(row["path"]))
        return paths
    return extract


def _state_sources_map(root: Path, result: Mapping[str, Any]) -> list[str]:
    """wf_map resolves exactly one address; credit the one resolved document."""
    data = result.get("data") if isinstance(result.get("data"), dict) else {}
    if result.get("status") != "ok":
        return []
    path = data.get("path")
    if isinstance(path, str) and path and data.get("file_exists"):
        return [path]
    return []


# Wave 1t3ek (1t2zq/1t15a): state files a tool demonstrably reads on the
# caller's behalf — credited through the canonical source-proof machinery
# (once-only per (wave, phase, source, version)). Tools that read nothing for
# the caller (memory_add, the wf_new_* scaffolds) are deliberately absent, as
# are full-content returners whose credit would equal their response debit
# (seed_get, wf_get_prompt). Listings credit only the live working set they
# enumerate, never closed history (see _state_sources_live_waves); memory
# views credit the capped set of record files they surface.
_STATE_SOURCE_EXTRACTORS: dict[str, Any] = {
    "wf_review_evidence": _state_sources_review_evidence,
    "memory_validate": _state_sources_memory_validate,
    "memory_propose": _state_sources_memory_propose,
    "wf_get_change": _state_sources_get_change,
    "wf_current_wave": _state_sources_live_waves,
    "wf_list_waves": _state_sources_live_waves,
    "wf_list_plans": _state_sources_list_plans,
    "wf_map": _state_sources_map,
    "memory_search": _state_sources_memory_views("records"),
    "memory_brief": _state_sources_memory_views("advisories", "community_scoped"),
}


_ARTIFACT_EXTRACTORS: dict[str, Any] = {
    "wf_review_evidence": _artifact_from_review_evidence,
    "memory_propose": _artifact_from_written_paths("written"),
    "memory_add": _artifact_from_written_paths("record"),
    "memory_validate": _artifact_from_written_paths("rewrite_record"),
    "memory_backfill": _artifact_from_written_paths("written"),
    **{
        name: _artifact_from_written_paths("path")
        for name in (
            "wf_new_feature", "wf_new_bug", "wf_new_enhancement",
            "wf_new_refactor", "wf_new_change", "wf_new_documentation",
            "wf_new_tech_debt", "wf_new_task", "wf_new_maintenance",
            "wf_new_operations",
        )
    },
}


def _wrap_first_party_tool_costs(mcp: Any, get_handler: Any) -> None:
    """Post-registration pass: wrap uninstrumented first-party tools with a
    debit recorder (plus artifact credit where an extractor exists). Purely
    observational — any failure leaves the tool untouched."""
    try:
        tm = getattr(mcp, "_tool_manager", None)
        tools = getattr(tm, "_tools", None) if tm is not None else None
        if not tools:
            return
        for name, tool in tools.items():
            if name in _COST_EXEMPT_TOOLS:
                continue
            if not any(name.startswith(prefix) for prefix in MCP_TOOL_PREFIXES):
                continue
            original = getattr(tool, "fn", None)
            if original is None or getattr(original, "_wf_cost_wrapped", False):
                continue

            def _make(tool_name: str, fn: Any) -> Any:
                @functools.wraps(fn)
                def wrapped(*args: Any, **kwargs: Any) -> Any:
                    result = fn(*args, **kwargs)
                    try:
                        handler = get_handler()
                        request_payload = {
                            k: v for k, v in kwargs.items() if k != "kwargs"
                        }
                        request_json = json.dumps(
                            request_payload, sort_keys=True, default=str
                        )
                        request_tokens = context_efficiency.estimate_tokens_utf8(
                            request_json
                        )
                        response_json = (
                            json.dumps(result, sort_keys=True, default=str)
                            if isinstance(result, (dict, list))
                            else ""
                        )
                        response_tokens = (
                            context_efficiency.estimate_tokens_utf8(response_json)
                            if response_json
                            else 0
                        )
                        artifact_tokens = 0
                        event_id: Optional[str] = None
                        extractor = _ARTIFACT_EXTRACTORS.get(tool_name)
                        if extractor is not None and isinstance(result, Mapping):
                            raw_artifacts, event_id = extractor(handler.root, result)
                            # Credit only what the caller did not supply,
                            # floored at zero PER ARTIFACT (the 1t3s7 contract):
                            # a request larger than every individual artifact
                            # credits nothing even when outputs sum higher.
                            artifact_tokens = sum(
                                max(0, int(raw) - request_tokens)
                                for raw in raw_artifacts
                            )
                            if event_id is None:
                                # Stable replay identity for artifact tools that
                                # carry no operation digest: an identical
                                # request producing an identical response is a
                                # replay and must not credit twice, while a
                                # different outcome (e.g. idempotent second run
                                # writing nothing) still records its debits.
                                event_id = "artifact:" + hashlib.sha256(
                                    (tool_name + "\x00" + request_json
                                     + "\x00" + response_json).encode("utf-8")
                                ).hexdigest()
                        source_proofs = None
                        state_extractor = _STATE_SOURCE_EXTRACTORS.get(tool_name)
                        if state_extractor is not None and isinstance(result, Mapping):
                            # Wave 1t3ek (1t2zq): avoided reading — live proofs
                            # for the state files this call consumed; any
                            # resolution failure credits nothing.
                            proofs = []
                            for rel in state_extractor(handler.root, result):
                                signature = context_efficiency.contained_stat_signature(
                                    handler.root, rel
                                )
                                if signature is not None:
                                    proofs.append(
                                        context_efficiency.SourceProof(
                                            path=rel,
                                            kind="live",
                                            expected=signature,
                                            boundary_stable=True,
                                        )
                                    )
                            source_proofs = proofs or None
                        handler.telemetry.record_tool_cost(
                            tool_name,
                            request_tokens=request_tokens,
                            response_tokens=response_tokens,
                            derived_artifact_tokens=artifact_tokens,
                            source_proofs=source_proofs,
                            event_id=event_id or uuid.uuid4().hex,
                        )
                    except Exception:
                        pass
                    return result

                wrapped._wf_cost_wrapped = True  # type: ignore[attr-defined]
                return wrapped

            tool.fn = _make(name, original)
    except Exception:
        pass


def register_mcp_surface(mcp: Any, get_handler: Any) -> None:
    """Register tools and resources; resolve state via get_handler() for hot reload."""
    # Wave 1p2q3 (131hh): stash the FastMCP instance and register the post-rebuild
    # notification callback against graph_query so auto-rebuilds dispatch
    # `notifications/resources/updated` for the wavefoundry://graph/* URIs.
    global _MCP_INSTANCE
    _MCP_INSTANCE = mcp
    try:
        _load_graph_query().set_post_rebuild_callback(_dispatch_graph_resources_updated)
    except Exception:
        pass
    # Tool annotation constants — passed to @mcp.tool(annotations={...}).
    # All handlers also accept **kwargs so FastMCP's auto-generated "kwargs"
    # schema parameter is captured and rejected via _ensure_no_extra_args rather
    # than causing an unexpected-argument error at the Python call boundary.
    _READONLY_TOOL = {"readOnlyHint": True, "destructiveHint": False, "idempotentHint": True, "openWorldHint": False}
    _OBSERVATIONAL_TOOL = {
        "readOnlyHint": False,
        "destructiveHint": False,
        "idempotentHint": False,
        "openWorldHint": False,
    }
    _MUTATING_TOOL = {"readOnlyHint": False, "destructiveHint": False, "idempotentHint": False, "openWorldHint": False}
    _DESTRUCTIVE_TOOL = {"readOnlyHint": False, "destructiveHint": True, "idempotentHint": False, "openWorldHint": False}

    # --- Search and retrieval ---

    @mcp.tool(annotations=_READONLY_TOOL)
    def wf_help(goal: str = "", **kwargs: Any) -> dict[str, Any]:
        """Return a structured MCP workflow catalogue or a goal-specific recommended chain.

        Args:
            goal: Optional workflow goal, e.g. "plan_feature" or "inspect_wave".
        """
        bad = _ensure_no_extra_args("wf_help", kwargs)
        if bad is not None:
            return bad
        return wf_help_response(goal)

    @mcp.tool(annotations=_READONLY_TOOL)
    def wf_server_info(**kwargs: Any) -> dict[str, Any]:
        """Return the repository root and implementation version info for this MCP server.

        Use immediately after connect when you need to confirm which checkout this server is attached to.
        """
        bad = _ensure_no_extra_args("wf_server_info", kwargs)
        if bad is not None:
            return bad
        return wf_server_info_response(get_handler().root)

    @mcp.tool(annotations=_READONLY_TOOL)
    def wf_gpu_doctor(**kwargs: Any) -> dict[str, Any]:
        """Embedding-provider / GPU capability diagnostic — platform, onnxruntime, GPU detection
        (nvidia/apple), available ONNX execution providers, the provider Wavefoundry would select
        (+ reason/remediation + decision provenance: setup-cache / fresh-probe / operator-request),
        and the CUDA 12/13 ABI-gap check. Read-only, no index build; note it RUNS the bounded
        model-loading provider probe (seconds; needs the model cached), the same probe setup uses.
        Same report as the `setup-wavefoundry --check-gpu` CLI.
        """
        bad = _ensure_no_extra_args("wf_gpu_doctor", kwargs)
        if bad is not None:
            return bad
        return wf_gpu_doctor_response(get_handler().root)

    @mcp.tool(annotations=_OBSERVATIONAL_TOOL)
    def docs_search(
        query: str,
        kind: Literal["", "doc", "seed", "architecture", "prompt", "doc-summary"] = "",
        tags: list = [],
        limit: int = 7,
        **kwargs: Any,
    ) -> dict[str, Any]:
        """Semantic search over docs, architecture, prompts, seed chunks, and framework seeds at .wavefoundry/framework/seeds/.

        Prefer when: searching by concept, intent, or natural language across project and framework documentation.
        Use code_keyword instead when the exact text is known.
        Degrades per the 1seaq state table: with a PUBLISHED index (complete build epoch)
        but an unavailable semantic model, serves BM25 results from the FTS layer
        (search_mode: lexical_fallback); with no published index at all, serves the
        live-filesystem walk (search_mode: live_fallback). Every response carries
        search_mode (semantic | lexical_fallback | live_fallback; null on refusal/validation errors) and fallback_reason
        (null when healthy; else model_unavailable | index_missing | store_absent |
        index_not_ready | query_failed — query_failed means infrastructure failure,
        NOT an empty corpus).

        Tags pre-filter the search space before cosine ranking. Use to scope results to a specific doc category.
        Tag vocabulary: wave, agent, lifecycle, reference, journal, prompt, seed, framework, test, config.
        Multiple tags use OR semantics (a chunk matching any requested tag is included).
        kind and tags compose with AND semantics (a chunk must satisfy both when both are provided).
        Examples: tags=["wave"] for wave records, tags=["agent"] for agent prompts and journals,
                  tags=["lifecycle"] for install/onboarding docs, tags=["journal"] for agent journals only.

        Args:
            query: Natural language search query.
            kind: Optional filter — one of: doc, seed, architecture, prompt, doc-summary.
            tags: Optional list of classification tags to pre-filter results. See tag vocabulary above.
            limit: Maximum results to return (1–20, default 7).
        """
        bad = _ensure_no_extra_args("docs_search", kwargs)
        if bad is not None:
            if isinstance(bad.get("data"), dict):  # search contract: fields always present
                bad["data"].setdefault("search_mode", None)
                bad["data"].setdefault("fallback_reason", None)
            return bad
        # 1sed6 seqlock read: capture the complete epoch token before the
        # whole operation; discard results if it changed underneath. A None
        # pre-token is allowed here — docs_search's live-filesystem fallback
        # is the explicitly degraded path for a not-ready index.
        _tok = _epoch_state(get_handler().root)
        # The CAPTURED token drives the fallback serve decisions inside the
        # response fn (1seaq single-capture discipline — no second read).
        result = docs_search_response(get_handler().index, query, kind, limit=limit, tags=tags or None, epoch_state=_tok)
        # Review fix (ABA-hardened): the post-compare is UNCONDITIONAL and
        # uses the FULL state row. A stable pair (same attempt/status/
        # generation — including a stable not-ready store) is the sanctioned
        # degraded live-walk; ANY transition — publish mid-operation, or
        # building A → complete → building B (invisible to the complete-only
        # token, both endpoints None) — discards the results.
        if _epoch_state(get_handler().root) != _tok:
            return _index_rebuilding_response("docs_search", {"query": query})
        return _record_retrieval_context(
            get_handler(),
            "docs_search",
            result,
            indexed_epoch_stable=bool(_tok and _tok[1] == "complete"),
            request_arguments={
                "query": query,
                "kind": kind,
                "tags": tags,
                "limit": limit,
            },
        )

    @mcp.tool(annotations=_OBSERVATIONAL_TOOL)
    def code_search(query: str, language: str = "", kind: str = "", max_per_file: int = 0, tags: list = [], limit: int = 7, graph: bool = True, graph_limit: int = 5, layer: str = "project", **kwargs: Any) -> dict[str, Any]:
        """Semantic search over indexed source code chunks. Requires a built code index (index_build content='code').

        Prefer when: searching for code by concept, behavior, or intent (e.g. "React component with loading state").
        Use code_keyword instead when the exact token, symbol, or string is known — always available, deterministic.
        Use docs_search instead when the answer is in a spec, architecture doc, or prompt rather than source code.
        When the code index is absent: returns status='error' with a diagnostic — does not crash.
        Degrades per the 1seaq state table: with a PUBLISHED index (complete build epoch) but an
        unavailable semantic model, serves BM25 results from the FTS layer with the requested
        filters preserved (search_mode: lexical_fallback, exact-token recall). With no published
        index there is NO degraded path — the tool refuses (index_not_ready). Every response
        carries search_mode (hybrid | lexical_fallback; null on refusal/validation errors) and fallback_reason (null when healthy;
        else model_unavailable | index_missing | store_absent | index_not_ready | query_failed).

        Orientation pass (Guru): use kind="code-summary" with max_per_file=1 for a fast file-level survey before targeted retrieval.

        Tags pre-filter the search space before cosine ranking. Use to scope results to a specific file category.
        Tag vocabulary: test, config, framework, seed. Multiple tags use OR semantics.
        language, kind, and tags all compose with AND semantics when provided together.
        Example: tags=["test"] to scope to test files only, tags=["config"] for config/infra files.

        Choosing a language filter:
        - No filter: query spans the whole codebase. Best when you don't know which language has the answer.
        - Category: use when the answer could be in any language of a family, or the codebase mixes them.
          Categories: java (java/kotlin/scala/groovy), web (typescript/javascript/html/css/scss),
          systems (c/cpp/rust/go), script (python/ruby/shell/fish), data (sql), sparksql (sql alias), dotnet (csharp).
          Category responses include language_resolved (expanded language list) and language_extensions.
        - Canonical name or extension: use when you know the exact language. e.g. "python", "typescript", "tsx", ".tsx".
          Note: .tsx and .ts files are both indexed as language="typescript" — tsx/.tsx normalizes to typescript.
          Use "web" (category) if you want TypeScript + JavaScript + HTML + CSS + SCSS together.

        Args:
            query: Natural language description of the code behavior or concept to find.
            language: Optional — category name, canonical language name, or raw extension (with or without dot).
            kind: Optional — filter to a specific chunk kind. Use "code-summary" for file-level orientation chunks only.
            max_per_file: Optional — cap results per file path (0 = no cap). Use 1 for orientation pass diversity.
            tags: Optional list of classification tags to pre-filter results. See tag vocabulary above.
            limit: Maximum results to return (1–20, default 7).
            graph: When True (default), append 1-hop ``graph_neighbors`` for top hits. Pass ``graph=False`` to suppress augmentation when you need the lean response.
            graph_limit: Number of top hits to expand when ``graph=True`` (default 5). Use 0 for no cap.
            layer: Graph layer for ``graph=True`` (default ``project``).

        Response fields:
        - graph_neighbors: (present unless ``graph=False``) 1-hop structural neighbors of the top-ranked hits, sourced from the graph index — file-level imports and symbol-level call relations.
        """
        bad = _ensure_no_extra_args("code_search", kwargs)
        if bad is not None:
            if isinstance(bad.get("data"), dict):  # search contract: fields always present
                bad["data"].setdefault("search_mode", None)
                bad["data"].setdefault("fallback_reason", None)
            return bad
        t_start = time.monotonic()
        # 1sed6 seqlock read (review-hardened): strict pre-gate — indexed code
        # search has NO sanctioned degraded path, so a missing complete epoch
        # refuses up front (deterministic, and immune to a mid-operation
        # publication racing the index load) — plus an unconditional
        # post-compare.
        # ONE state-token capture (review fix: a separate complete-probe +
        # state-capture pair left a between-reads window where a writer could
        # fence and the unchanged building==building post-check passed). The
        # completeness gate checks the CAPTURED token's own status.
        _tok = _epoch_state(get_handler().root)
        if _tok is None or _tok[1] != "complete":
            return _index_rebuilding_response("code_search", {"query": query})
        result = code_search_response(get_handler().index, query, language, limit=limit, kind=kind or None, max_per_file=max_per_file or None, tags=tags or None, epoch_state=_tok)
        result = _augment_with_graph_neighbors_if_enabled(
            result, get_handler().root,
            tool_key="code_search", graph=graph, graph_limit=graph_limit, layer=layer,
        )
        # Review fix (P0): the post-compare closes the fence AFTER graph
        # augmentation — the graph read is part of the indexed operation, so
        # a build fencing during augmentation must discard the WHOLE result,
        # not just the pre-augmentation half.
        if _epoch_state(get_handler().root) != _tok:
            return _index_rebuilding_response("code_search", {"query": query})
        return _record_retrieval_context(
            get_handler(),
            "code_search",
            _inject_timing(result, t_start, "code_search"),
            indexed_epoch_stable=True,
            request_arguments={
                "query": query,
                "language": language,
                "kind": kind,
                "max_per_file": max_per_file,
                "tags": tags,
                "limit": limit,
                "graph": graph,
                "graph_limit": graph_limit,
                "layer": layer,
            },
        )

    @mcp.tool(annotations=_READONLY_TOOL)
    def seed_get(name: str, **kwargs: Any) -> dict[str, Any]:
        """Retrieve a framework seed prompt by name or partial slug.

        Prefer when: you know the seed name or number. Use docs_search instead when searching for seed content by concept.

        Args:
            name: Seed name or partial slug, e.g. "plan-feature" or "020-run-contract".
        """
        bad = _ensure_no_extra_args("seed_get", kwargs)
        if bad is not None:
            if isinstance(bad.get("data"), dict):  # search contract: fields always present
                bad["data"].setdefault("search_mode", None)
                bad["data"].setdefault("fallback_reason", None)
            return bad
        # 1sed6 seqlock read (review fix): seed_get reads indexed chunks (with
        # a sanctioned disk fallback), so it takes the same whole-operation
        # fence as docs_search — unconditional post-compare, None pre allowed.
        _tok = _epoch_state(get_handler().root)
        result = seed_get_response(get_handler().index, name)
        if _epoch_state(get_handler().root) != _tok:
            return _index_rebuilding_response("seed_get", {"name": name})
        return result

