    @mcp.tool(annotations=_OBSERVATIONAL_TOOL)
    def code_impact(
        path: str = "",
        max_results: int = 50,
        symbol: str = "",
        max_hops: int = 3,
        layer: str = "project",
        relations: list[str] | None = None,
        include_tests: bool = False,
        **kwargs: Any,
    ) -> dict[str, Any]:
        """Find files/symbols affected by a change — import heuristics (path) or graph traversal (symbol).

        Prefer when: assessing blast radius before editing or deleting a module. Use ``path=`` for
        classic reverse-import analysis (``method: heuristic``). Use ``symbol=`` for graph-backed
        upstream impact via ``imports``/``calls``/``implements``/``extends`` edges
        (``method: graph``). Dispatch-aware (wave 1p9qh/1p9qa): inheritance hops are
        down-weighted (potential dispatch, not proven flow), and a supertype/interface
        METHOD seed also pulls subtype implementations of the same-named method into the
        blast radius via synthetic ``derived: "dispatch"`` edges. Pass
        ``relations=["calls","imports"]`` to opt out of dispatch traversal.

        Response fields (graph mode — symbol=):
        - symbol: the queried symbol name
        - resolved: true when the symbol was found in the graph
        - node_id: resolved graph node id
        - affected: list of {node_id, label, kind, source_file, hop, community_id, community} —
          upstream callers/importers. ``hop`` (int) is the traversal distance from the queried
          symbol (1 = direct caller). ``community_id`` is the stable community identifier of
          the affected node (wave 1316r) — useful for grouping cross-cutting changes by
          community. Test callers excluded by default.
        - affected_files: sorted list of unique files containing affected nodes
        - edges: traversed edges, CAPPED at max_results (see edges_total for the
          full count; attribution counts are computed over the full set). Each
          edge carries a ``confidence`` field:
          ``RECEIVER_RESOLVED`` (type-resolved at graph-builder; high confidence),
          ``CONSTRUCTION_RESOLVED`` (construction-call routed to the class node;
          peer to RECEIVER_RESOLVED in deterministic-attribution rank), or
          ``EXTRACTED`` (heuristic / text-based fallback). For refactor-safety
          analysis, filter to ``RECEIVER_RESOLVED`` + ``CONSTRUCTION_RESOLVED``
          edges only; for ``EXTRACTED`` edges that look load-bearing, corroborate
          with ``code_references``.
        - edges_total: full count of traversed edges before the max_results cap
          (re-query with a higher max_results, or use code_callgraph, for all)
        - truncated: true when affected nodes or edges were capped at max_results
        - include_tests: whether test-path nodes were included
        - suggestions: near-match candidates when the symbol is not found in the graph
        - external_target / external_name: present when the resolved seed is an EXTERNAL
          supertype (e.g. a third-party interface project classes implement). The blast
          radius is then its project implementors/subtypes plus their dependents — so
          "what implements this external interface?" is a first-class query. External
          names never shadow project symbols (a project node with the same name wins).
        - external_candidates: returned instead of a resolution when a simple name
          matches MULTIPLE distinct external supertypes (declared with different
          qualifications) — grouped ``{id, name, implementor_count, subtype_count}``
          entries, never a silently merged list; re-query with the exact ``external::``
          id from the group.
        - supertypes: present when the resolved node declares supertypes —
          ``{project: [...], external: [{id, name, relation, confidence}],
          external_implements_count, external_extends_count}``. A class whose only
          supertypes are external no longer reads as "no relationships": the counts
          are always present.

        Response fields (heuristic mode — path=):
        - path: the queried file path
        - importers: list of {file, line, snippet} — files that import the queried path
        - truncated: true when results were capped at max_results
        - method: "heuristic"

        Args:
            path: Repo-relative file path for heuristic import analysis.
            max_results: Maximum results to return (default 50).
            symbol: Qualified graph node id or resolvable symbol for graph mode.
            max_hops: Reverse traversal depth for graph mode (default 3).
            layer: Graph layer — only ``project`` exists (the framework/union layers
                were removed in 1p4ww); retained as a no-op for back-compat.
            relations: Optional edge relation filter for graph mode.
            include_tests: When False (default), affected nodes in test paths are excluded from
                the production blast-radius view. Set True to include test callers.
        """
        bad = _ensure_no_extra_args("code_impact", kwargs)
        if bad is not None:
            return bad
        t_start = time.monotonic()
        result = _inject_timing(code_impact_response(
            get_handler().root,
            path,
            max_results,
            symbol=symbol,
            max_hops=max_hops,
            layer=layer,
            relations=relations,
            include_tests=include_tests,
        ), t_start, "code_impact")
        return _record_retrieval_context(
            get_handler(),
            "code_impact",
            result,
            request_arguments={
                "path": path,
                "max_results": max_results,
                "symbol": symbol,
                "max_hops": max_hops,
                "layer": layer,
                "relations": relations,
                "include_tests": include_tests,
            },
        )

    @mcp.tool(annotations=_OBSERVATIONAL_TOOL)
    def code_risk_score(
        scope: str = "",
        top: int = 20,
        max_hops: int = 3,
        layer: str = "project",
        include_tests: bool = False,
        **kwargs: Any,
    ) -> dict[str, Any]:
        """Rank the symbols in a scope by how risky they are to *change* — a composite of blast-radius × call-degree.

        Prefer when: before a cross-cutting change or refactor, to prioritize WHICH symbols in a
        module/directory to touch most carefully. This RANKS MANY symbols across a scope in one call;
        contrast ``code_impact``, which sizes ONE symbol's blast radius. The score is structural
        (graph-derived) — it is **not** git-commit-history churn.

        Score (v2): ``risk = weighted_affected_file_count * log1p(weighted_fan_in)`` — blast radius
        (how many files break if this symbol changes) times log-dampened incoming call-degree (so
        hubs don't dominate), both **weighted by edge attribution confidence**. ``EXTRACTED``
        (heuristic name-based) edges count fractionally (``extracted_edge_weight``) while
        ``RECEIVER_RESOLVED``/``CONSTRUCTION_RESOLVED`` count in full, so a ubiquitous accessor name
        (``getKey``/``getValue``/``toString``) can't top the rank purely on a name collision with an
        unrelated symbol (e.g. ``Map.Entry.getKey()``). ``fan_out`` (what the symbol itself calls) is
        surfaced separately, NOT multiplied in. Raw + weighted components are returned per symbol so
        the score is transparent and re-weightable.

        Read it as a **relative rank within the queried scope**, not an absolute or
        cross-module-comparable magnitude. Signal is strongest on broad scopes (a directory) where
        blast radius varies; on a single small module with uniform blast radius it can track ``fan_in``.

        Response fields:
        - scope, layer, top, max_hops, candidate_count, candidate_cap, include_tests
        - score_formula: the composite formula string
        - score_components: names of the inputs (``weighted_affected_file_count``, ``weighted_fan_in``,
          ``fan_out``, ``affected_file_count``, ``fan_in``, ``extracted_edge_fraction``,
          ``transitive_extracted_fraction``)
        - extracted_edge_weight: the fractional weight applied to ``EXTRACTED`` edges
        - results: list ranked DESC by ``risk``, each with ``node_id``, ``label``, ``source_file``,
          ``kind``, ``risk``, ``weighted_affected_file_count``, ``weighted_fan_in``,
          ``affected_file_count`` (raw), ``fan_in`` (raw), ``fan_out``, ``extracted_edge_fraction``
          (share of blast-radius edges that are heuristic — discount a high score when near 1.0),
          ``transitive_extracted_fraction`` (Wave 1p7df: share of affected nodes reachable only via a
          path that traverses an ``EXTRACTED`` edge — the transitive confidence of the blast radius),
          ``hop`` (worst-case blast-radius hop distance)
        - over_candidate_cap: true (with empty ``results``) when the scope has more than
          ``candidate_cap`` definitions — narrow ``scope=`` and retry

        Args:
            scope: Repo-relative file path, directory prefix, or glob (``*``/``?``/``[]``) to rank over.
            top: Max ranked symbols returned (default 20).
            max_hops: Blast-radius traversal depth passed to impact (default 3).
            layer: Graph layer — only ``project`` exists (framework/union removed in 1p4ww); a back-compat no-op.
            include_tests: When False (default), test-path nodes are excluded from the blast radius
                (symmetric with code_impact's filter).
        """
        bad = _ensure_no_extra_args("code_risk_score", kwargs)
        if bad is not None:
            return bad
        t_start = time.monotonic()
        handler = get_handler()
        return _record_retrieval_context(
            handler,
            "code_risk_score",
            _inject_timing(code_risk_score_response(
                handler.root,
                scope,
                top=top,
                max_hops=max_hops,
                layer=layer,
                include_tests=include_tests,
            ), t_start, "code_risk_score"),
            request_arguments={
                "scope": scope,
                "top": top,
                "max_hops": max_hops,
                "layer": layer,
                "include_tests": include_tests,
            },
        )

    @mcp.tool(annotations=_OBSERVATIONAL_TOOL)
    def code_callgraph(
        symbol: str,
        depth: int = 1,
        direction: str = "both",
        layer: str = "project",
        include_tests: bool = False,
        **kwargs: Any,
    ) -> dict[str, Any]:
        """Return direct (and optionally deeper) ``calls`` edges for a graph symbol.

        Prefer when: tracing execution paths beyond one hop (depth > 1), building a full call
        tree, or when raw graph edges with line numbers are more useful than the
        incoming/outgoing framing of code_callhierarchy. Use code_callhierarchy for targeted
        depth-1 caller/callee lookups; use code_callgraph when the broader call structure is needed.

        Response fields:
        - symbol: the queried symbol name
        - node_id: resolved graph node id
        - depth: the requested expansion depth
        - direction: the traversal direction used
        - include_tests: whether test-path nodes were included
        - nodes: list of graph nodes in the subgraph, each with id, label, kind, source_file
        - edges: list of call edges; ``calls`` edges include ``line`` when the call site was located
        - has_cycles: true when a back-edge to an already-visited node was encountered

        Args:
            symbol: Required graph node id or resolvable symbol.
            depth: Expansion depth (default 1).
            direction: ``callers``, ``callees``, or ``both``.
            layer: Graph layer — only ``project`` exists (framework/union removed in 1p4ww); a back-compat no-op.
            include_tests: When False (default), test-path nodes (and edges referencing them)
                are excluded from the response. Symmetric with code_impact's filter.
        """
        bad = _ensure_no_extra_args("code_callgraph", kwargs)
        if bad is not None:
            return bad
        t_start = time.monotonic()
        result = _inject_timing(code_callgraph_response(
            get_handler().root,
            symbol,
            depth=depth,
            direction=direction,
            layer=layer,
            include_tests=include_tests,
        ), t_start, "code_callgraph")
        return _record_retrieval_context(
            get_handler(),
            "code_callgraph",
            result,
            request_arguments={
                "symbol": symbol,
                "depth": depth,
                "direction": direction,
                "layer": layer,
                "include_tests": include_tests,
            },
        )

    @mcp.tool(annotations=_READONLY_TOOL)
    def wf_graph_report(
        layer: str = "project",
        limit: int = 20,
        sections: list[str] | None = None,
        exclude_generated: bool = False,
        exclude_external: bool = False,
        collapse_generated_files: bool = False,
        collapse_class_module_pairs: bool = False,
        collapse_package_to_directory: bool = False,
        **kwargs: Any,
    ) -> dict[str, Any]:
        """Structural summary over the persisted code/doc graph.

        Prefer when: orienting to a codebase for the first time, identifying over-connected
        modules before a cross-cutting refactor, or finding documentation gaps. Run once per
        investigation rather than per-symbol; use code_callhierarchy or code_impact for
        per-symbol follow-up.

        Response fields (one key per requested section):
        - fan_in: ranked list of {node_id, label, kind, count} — most-called symbols by incoming ``calls`` edge
          count. ``count`` is the number of distinct ``calls``-relation edges targeting the node. For
          ``kind: "function"`` / ``"method"`` / ``"class"`` entries this is the direct caller count. For
          ``kind: "module"`` entries (files), ``count`` is the number of ``calls`` edges whose target is the file
          node itself — typically attributed when the indexer couldn't bind the call to a specific symbol inside
          the file (1312f locks this contract via `TestModuleFanOutCountSemantics`). Use the entry's ``kind``
          field to interpret the number; ``imports`` and ``defines`` edges are NOT included.
        - fan_out: ranked list of {node_id, label, kind, count} — symbols that issue the most outgoing ``calls``
          edges. Same kind-aware shape as fan_in. Note: file-level (``kind: "module"``) entries with high fan_out
          appear in the dedicated ``file_hubs`` section (wave 13129); operators seeking architectural orientation
          should read both ``chokepoints`` and ``file_hubs`` together.
        - chokepoints: nodes with ``kind: "function"`` / ``"method"`` / ``"class"`` fan_out >= threshold (default 20)
          — potential bottlenecks in the call graph. Module/file entries are NOT in this section (wave 13129);
          see ``file_hubs`` for the parallel file-level view.
        - orphan_docs: doc/seed nodes with no ``doc_references_code`` edges — disconnected documentation
        - betweenness: ranked list of {node_id, label, kind, score} — nodes with high betweenness centrality
          (bridge nodes on shortest paths). Served from the ranking persisted at BUILD time in the clusters
          artifact (wave 1p9q3: size-tiered — exact igraph betweenness on small/medium graphs, bounded
          `cutoff` approximation on large ones, deterministic degree/fan-out fallback on very large graphs
          or when igraph is absent); no per-query computation and NO graph-size cap. `betweenness_method`
          ("exact" | "cutoff" | "degree_fallback") and `betweenness_metadata` (node_count, edge_count,
          top_n, elapsed_ms, cutoff when applicable) report how the ranking was produced.
        - communities: top communities by node_count with `community_id`, `label`, `hub_node_id`, `hub_label`,
          `generated_node_fraction`; entries with `generated_node_fraction > 0.4` carry `community_type: "generated-dominated"`
        - betweenness_dominated_by_generated: true when >50% of top-N betweenness results are tagged generated
        - exclude_generated: echoes the requested filter flag

        Each ranking entry (fan_in, fan_out, chokepoints, file_hubs, betweenness) also carries collision
        diagnostic fields (wave 13129):
        - ``same_name_node_count`` (int): count of project nodes sharing the entry's simple name.
        - ``cross_file_collision`` (bool): True when 2+ project files own a same-simple-name node.
        - ``external_name_collision_count`` (int, wave 1316p): 1 when the simple name appears in the
          curated Java stdlib/framework allowlist (``run``, ``close``, ``equals``, ``hashCode``,
          ``toString``, ``compareTo``, ``iterator``, ``accept``, ``apply``, ``getMethod``,
          ``execute``, ``process``, etc.), 0 otherwise. Replaces the pre-1316p graph-state-based
          count, which stopped firing for the common Java case after 1312l's receiver-type
          resolution at index time eliminated the residue external nodes the count depended on.
          Allowlist is Java-focused in this release; non-Java symbols receive 0.
        - ``name_collision_count`` (deprecated alias for ``same_name_node_count``, removed after one release).

        Empty-section diagnostic fields (wave 1316t) distinguish "no data" from "no hits"
        on sections that can legitimately return ``[]``:

        - ``chokepoints_candidates_total`` / ``chokepoints_threshold`` — how many function/method/
          class candidates were considered before the threshold filter, and the cutoff that
          filtered them.
        - ``file_hubs_candidates_total`` / ``file_hubs_threshold`` — same shape for file-level
          (``kind: "module"``) entries.
        - ``orphan_docs_candidates_total`` — docs node pool considered before the
          ``doc_references_code`` filter.
        - ``betweenness_computed`` (bool, from wave 130rj) + ``betweenness_skipped_reason``
          (when False) — since wave 1p9q3 the only skip reason is ``betweenness_not_in_artifact``
          (legacy clusters artifact predating the build-time pass, or no clusters artifact yet;
          rebuild the graph index to populate it — ``betweenness_note`` carries the recovery hint).

        When a section is ``[]`` AND ``<section>_candidates_total: 0``, the graph genuinely
        has nothing matching. When ``[]`` AND ``_candidates_total > 0``, the threshold filter
        removed everything — adjust the request or investigate threshold fit. The
        ``communities`` section also carries ``betweenness_dominated_by_generated: bool``
        when >50% of top-N betweenness results are tagged generated.

        Args:
            layer: Graph layer — only ``project`` exists (the framework/union layers
                were removed in 1p4ww); retained as a no-op for back-compat.
            limit: Max rows per ranking section (default 20).
            sections: Optional subset: fan_in, fan_out, orphan_docs, chokepoints, file_hubs, betweenness, communities.
            exclude_generated: When True (wave 130rj), filters nodes tagged ``generated: true`` out of
                fan_in/fan_out/chokepoints/betweenness/communities. The classifier covers Java and C#
                generated-code conventions (multi-language follow-up tracked separately).
            exclude_external: When True (wave 130rj — 130tw), filters ``external::*`` nodes (stdlib /
                third-party library symbols) out of fan_in/fan_out/chokepoints/betweenness. Use for
                "show me MY code" architectural orientation. Independent of ``exclude_generated`` —
                both can be set together to remove stdlib + machine-generated noise simultaneously.
                Default False for backward compat (existing callers using fan_in as a dependency-density
                signal still see external entries). The ``communities`` section is unaffected (external
                nodes are not community members).
            collapse_generated_files: When True (wave 130rj — 130su), aggregates each generated
                source file into a single file-node before computing report sections. Internal edges
                within a generated file are dropped; cross-boundary edges have generated endpoints
                rewritten to the file-node id. Preserves "handwritten code calls into ELParser"
                topology while shrinking the apparent complexity of generated parsers (e.g. ELParser's
                330 internal nodes collapse to 1). Per-symbol tools (code_callhierarchy, code_impact,
                code_graph_path, code_callgraph) deliberately do NOT support this flag — they need
                the full per-symbol view.
            collapse_package_to_directory: When True (wave 131bt — 1319m), aggregates files in a
                directory into a single package/namespace node per-language. Detection: Go matches
                files sharing the same ``package <name>`` declaration; Python uses ``__init__.py``
                presence; Java/Kotlin/Scala/C#/PHP match files sharing the same ``package``/``namespace``
                declaration; Swift collapses ``.swift`` files in a directory via build-target convention.
                Rust (``mod`` tree), Ruby (namespace declaration), JS/TS (ES modules) are excluded.
                Single-file directories and mixed-package directories skip with no collapse. Collapsed
                nodes carry ``collapse_origin_files``, ``collapse_unit``, and ``kind`` of ``"package"`` or
                ``"namespace"`` preserving language idiom. Stacks with ``collapse_class_module_pairs``.
                Per-symbol navigation tools deliberately do NOT support this flag.
            collapse_class_module_pairs: When True (wave 13129 — 1312h), merges Swift file-and-class
                pairs into one node for report consumption. For ``Foo.swift`` containing top-level
                ``class Foo`` (or ``struct``/``actor``/``enum``/``protocol`` Foo), the file node and
                the class node aggregate into a single node with the class label and a
                ``collapsed_pair: true`` marker. Files without a basename-matching top-level type are
                unaffected. Swift-first; Java/Kotlin/C# enablement is operator-validation-driven via
                the ``_CLASS_MODULE_COLLAPSE_LANGUAGES`` dispatch in graph_query.py. Per-symbol tools
                deliberately do NOT support this flag.
        """
        bad = _ensure_no_extra_args("wf_graph_report", kwargs)
        if bad is not None:
            return bad
        t_start = time.monotonic()
        return _inject_timing(wf_graph_report_response(
            get_handler().root,
            layer=layer,
            limit=limit,
            sections=sections,
            exclude_generated=exclude_generated,
            exclude_external=exclude_external,
            collapse_generated_files=collapse_generated_files,
            collapse_class_module_pairs=collapse_class_module_pairs,
            collapse_package_to_directory=collapse_package_to_directory,
        ), t_start, "wf_graph_report")

    @mcp.tool(annotations=_OBSERVATIONAL_TOOL)
    def code_ask(question: str, rerank: str = "agent", **kwargs: Any) -> dict[str, Any]:
        """Ask a natural-language question about the codebase and receive a grounded, cited answer.

        Prefer when: the question spans multiple files or layers ("how does X work end-to-end?",
        "what calls Y?", "where is Z implemented?"). Use code_search or docs_search directly when
        you want raw result lists to browse rather than a pre-assembled answer.

        Performs mechanical retrieval routing: broad semantic pass (code_search + docs_search) followed by
        targeted keyword pass. Returns a structured response with citations, confidence, and gaps.
        No LLM synthesis occurs in this tool — the calling agent synthesizes from the returned citations.

        Response fields:
        - answer: Navigation pointer ("Based on indexed sources: see X") — ignore this field; synthesize
          directly from citations.
        - citations: List of {ref, path, lines, excerpt, score, kind}. kind="keyword" means the semantic
          pass was thin and keyword fallback fired — results are still relevant but ranked by term overlap,
          not vector similarity. In the default `rerank="agent"` mode each citation also carries `source`
          (the index it came from: "docs"/"code") and, when it surfaced from more than one index, `sources`
          (the set — cross-source agreement); `excerpt` is the FULL chunk text (not a 300-char truncation).
          Wave 1p52p: when the reranker is available, the candidate set is RANKED by a cross-encoder relevance score
          (`score` = sigmoid of the cross-encoder logit ∈ [0,1], unified across docs+code) applied BEFORE
          the coverage floor + budget selection — citations come best-first; still read the winners. On a
          GPU machine this uses FP16; on a CPU-only machine it uses the INT8 export. If reranking is
          explicitly disabled or unbuildable, ordering falls back to coverage-floor over mixed-model cosine
          (`reranked=false`) — fuse from full context yourself.
        - rerank_mode: always "agent" — code_ask has one ranking path (agent selection + a rerank-FIRST
          cross-encoder). Use the `reranked` bool to tell whether the cross-encoder ran.
        - reranked: true = the cross-encoder ran and scored/ordered the candidates on one unified
          relevance scale; false = the cross-encoder did not run. Two `reranked=false` cases:
          on the HEALTHY path (reranker disabled/unbuildable) ordering is vector/coverage over
          mixed-model cosine; in `lexical_fallback` mode ordering is BM25 exact-token.
        - confidence: "high" / "medium" / "low". When `reranked=true` it is calibrated on the unified
          cross-encoder relevance (high = a genuinely relevant top match with ≥2 citations; low = nothing
          relevant retrieved). When `reranked=false`: capped at "medium" on the healthy path ("low"
          with zero citations — cosine bands are untrustworthy, so "high" is never claimed), and
          "low" in `lexical_fallback`. Retrieval signal only — not an
          answer-quality signal. Evaluate citations by path and content; high confidence with wrong-layer
          citations (e.g. infrastructure scaffolding for an explanatory question) still requires follow-up.
        - gaps: Retrieval gaps or index unavailability notices
        - question_type: "navigational" | "explanatory" | "instructional". Influences retrieval pool
          weighting and candidate window size. "explanatory" triggers two enhancements when the
          cross-encoder reranker is available: (1) a wider candidate window (VECTOR_TOP_K_EXPLANATORY=60
          per index vs 30 for other types), and (2) two-hop symbol expansion — symbol names are extracted
          from the top reranked citations and a second keyword retrieval pass fetches their definitions,
          reaching call-chain layers the original query vocabulary cannot reach. Navigational questions
          bias toward code results via RRF weight adjustment.
        - second_hop_symbols: list of symbol names that triggered second-hop retrieval for explanatory
          questions. Only present when non-empty. When present: the citations already include candidates
          surfaced by following these symbols one layer deeper; use this list to understand which call
          chain references were automatically expanded rather than re-chasing them manually. Absent when
          question_type != "explanatory", reranked=false, or no extractable symbols were found in the
          top citations.
        - symbol_extraction_method: extraction method used for the two-hop symbol pass. Present when
          the second-hop gate fired and at least one citation survived the infra filter. Values: "ast"
          — Python stdlib AST or tree-sitter produced at least one symbol; "regex" — AST was
          unavailable or produced no symbols (regex was the effective extractor). Use this field to
          detect silent grammar degradation: "regex" on a TypeScript-heavy codebase indicates the
          tree-sitter grammar failed to load or produced no symbols.
        - validation_required: present and true when question_type=="explanatory" and the top
          citation is a doc or doc-summary (spec, architecture, or reference doc). When present,
          code_read in next_tools is a REQUIRED continuation — not optional. A spec citation is
          the starting point, not the answer; read the implementation file named in the spec's
          source metadata before synthesizing.
        - index_freshness: "current" | "stale" | "unknown" (unknown = the check could not
          determine freshness — treat results as potentially stale, verify with index_health)
        - search_mode: "hybrid" (normal), "exact" (the artifact-anchored exact-first pass answered
          before semantic retrieval — a healthy mode), or "lexical_fallback" (semantic retrieval
          unavailable; citations are BM25 exact-token matches, confidence capped)
        - fallback_reason: null when healthy; else model_unavailable | index_missing |
          store_absent | index_not_ready | query_failed (infrastructure failure, not zero hits)
        - coverage: per-table lexical coverage (present on every degraded/failed envelope; {} = collection unavailable)
        - Refusal/invalid-argument error envelopes carry search_mode: null (status "error"
          disambiguates from a healthy null fallback_reason)
        - vector_ms: milliseconds spent on vector retrieval across all indexes.
        - rerank_ms: milliseconds spent on cross-encoder reranking (0 when reranked=false).
        - total_ms: wall-clock milliseconds for the full code_ask call.

        Args:
            question: Natural-language question about the codebase, e.g. "where does billing handle failed payments?"
            rerank: deprecated/optional. code_ask has a single ranking path — agent selection with a
                rerank-FIRST cross-encoder (Wave 1p52p; FP16 on GPU, INT8 on CPU, so it is now embedded in
                the default flow). "agent" (default) and the legacy alias "local" behave identically. If the
                reranker is explicitly disabled or unbuildable, ordering falls back to vector/coverage order
                (`reranked=false`).
        """
        bad = _ensure_no_extra_args("code_ask", kwargs)
        if bad is not None:
            if isinstance(bad.get("data"), dict):  # search contract: fields always present
                bad["data"].setdefault("search_mode", None)
                bad["data"].setdefault("fallback_reason", None)
            return bad
        # 1sed6 seqlock read (review-hardened): strict pre-gate + unconditional
        # post-compare around the complete combined operation (vector + FTS +
        # graph + rerank). Without the pre-gate, a not-ready index let the
        # keyword/graph stages return citations labeled current.
        # ONE state-token capture; completeness gate on the captured token
        # (review fix — no separate probe pair, no between-reads window).
        _tok = _epoch_state(get_handler().root)
        if _tok is None or _tok[1] != "complete":
            return _index_rebuilding_response("code_ask", {"question": question})
        result = code_ask_response(get_handler().index, get_handler().root, question, rerank=rerank, epoch_state=_tok)
        if _epoch_state(get_handler().root) != _tok:
            return _index_rebuilding_response("code_ask", {"question": question})
        return _record_retrieval_context(
            get_handler(),
            "code_ask",
            result,
            indexed_epoch_stable=True,
            request_arguments={"question": question, "rerank": rerank},
        )

