    @mcp.tool(annotations=_MUTATING_TOOL)
    def wf_upgrade(phase: str = "preflight_to_docs_gate", **kwargs: Any) -> dict[str, Any]:
        """Run the automated Wavefoundry framework upgrade script.

        Invokes ``upgrade_wavefoundry.py`` for the requested phase. Always runs
        non-interactively (equivalent to ``upgrade-wavefoundry --yes``).

        Args:
            phase: Which upgrade phase to run.

              - ``"preflight_to_docs_gate"`` *(default)* — phases 0–3: pre-flight
                checks, zip adoption, surface rendering, pruning, docs gate.
                Run this first. The agent's editing pass (drift detection, journal
                reconciliation, spec gap remediation) follows after this completes.
              - ``"update_index"`` — phase 4 *(default post-editing choice)*:
                incremental docs index update (blocking) then code (background).
                Re-embeds only files that changed since the last run.
                Auto-escalates to a full rebuild when chunker or embedding model
                version changed. Use this for normal post-editing-pass runs.
              - ``"rebuild_index"`` — phase 4 (full): re-embeds every file from
                scratch. Use when ``update_index`` is insufficient — e.g. index
                corruption or a manual forced refresh.
              - ``"cleanup"`` — phase 5: remove the upgrade lock file and print the
                operator summary. Call after ``update_index`` or ``rebuild_index``.
              - ``"resume_after_gate"`` — rebuild and persist current
                review-status projection, then re-run docs-gardener + docs-lint
                against the already-extracted tree (no extract/render/prune).
                Accepts retained ``failed_phase`` values
                ``"review_status_projection"`` and ``"docs_gate"``; preserves
                the actual failing phase on retry and clears it only after both
                pass.
              - ``"resume_after_memory"`` — after bounded historical candidate
                extraction and focused validation, recompute the SQLite pending
                set and publish Phase 4 only when it is zero. This and every
                index/cleanup phase refuse while review projection or docs lint
                has a retained failed phase; recover through
                ``"resume_after_gate"`` first.

        Response fields:
          - ``exit_code``: 0 = success, 1 = docs gate failed, 2 = surface rendering
            failed, 3 = pre-flight check failed (downgrade detected, lock conflict),
            4 = action required for historical-memory validation.
          - ``output``: combined stdout + stderr from the upgrade script.
          - ``phase``: echoes the phase that was run.

        Upgrade sequence::

            wf_upgrade()                          # phases 0–3
            # … agent editing pass …
            wf_upgrade(phase="update_index")      # phase 4 — incremental (default)
            wf_upgrade(phase="cleanup")           # phase 5

        Use ``wf_upgrade_status`` to check lock state at any time.
        """
        bad = _ensure_no_extra_args("wf_upgrade", kwargs)
        if bad is not None:
            return bad
        handler = get_handler()
        projection = project_pending_context_efficiency(handler)
        if not projection.get("ok"):
            return _response(
                "error",
                {
                    "failed": True,
                    "stage": "context_efficiency_projection",
                    "projection": projection,
                },
                diagnostics=[
                    _diagnostic(
                        "context_efficiency_projection_failed",
                        "Upgrade was refused because pending durable context-"
                        "efficiency telemetry could not be projected.",
                    )
                ],
                usage="Resolve the projection failure, then retry wf_upgrade.",
            )
        return wf_upgrade_response(handler.root, phase=phase)

