    @mcp.tool(annotations=_OBSERVATIONAL_TOOL)
    def code_keyword(
        query: str = "",
        glob: str = "",
        queries: list[str] | None = None,
        limit: int = 50,
        graph: bool = True,
        graph_limit: int = 5,
        layer: str = "project",
        **kwargs: Any,
    ) -> dict[str, Any]:
        """Search repository files for an exact keyword or substring.

        Prefer code_definition first when the goal is to find where a specific symbol, CSS class, or
        custom property is *declared* — it returns a precise definition location without scanning all occurrences.
        Use code_keyword when you need all occurrences of a token, or when code_definition returns no results.
        Use docs_search or code_search instead when searching by concept or intent rather than exact text.
        Use code_pattern when you need regex (non-literal) matching.
        Returns deterministic path/line/snippet results for each match.
        Respects the same ignore/exclusion rules as the semantic index.

        Pass either ``query`` (single string) or ``queries`` (list of strings) — not both. When
        ``queries`` is supplied, results from all entries are merged and deduplicated by (path, line);
        each result includes ``matched_query`` identifying which query string produced it. The ``glob``
        parameter applies uniformly across all queries in a batch.

        Args:
            query: Exact text to search for (substring match). Omit when using ``queries``.
            glob: Optional glob to restrict the search, e.g. "**/*.py" or "*.md".
            queries: List of exact strings to search for in a single call. Omit when using ``query``.
            limit: Cap on returned results (default 50; matches ``code_pattern`` / ``code_references``).
                When the cap fires the response includes ``truncated: true`` and ``total_matches_found``
                so the caller sees there's more. Pass ``limit=0`` for exhaustive results.
                Wave 1p3dk addition — prevents response-token-cap overflow on prevalent tokens.
            graph: When True (default), append 1-hop ``graph_neighbors`` for top hits. Pass ``graph=False`` to suppress augmentation when you need the lean response.
            graph_limit: Number of top hits to expand when ``graph=True`` (default 5). Use 0 for no cap.
            layer: Graph layer for ``graph=True`` (default ``project``).

        Response fields:
        - truncated: True when ``limit`` capped the results below the actual match count
        - total_matches_found: actual total before truncation
        - graph_neighbors: (present unless ``graph=False``) 1-hop structural neighbors of the top hits, sourced from the graph index — file-level imports and symbol-level call relations.
        """
        bad = _ensure_no_extra_args("code_keyword", kwargs)
        if bad is not None:
            return bad
        t_start = time.monotonic()
        result = code_keyword_response(get_handler().root, query, glob=glob, queries=queries, limit=limit)
        result = _augment_with_graph_neighbors_if_enabled(
            result, get_handler().root,
            tool_key="code_keyword", graph=graph, graph_limit=graph_limit, layer=layer,
        )
        return _record_retrieval_context(
            get_handler(),
            "code_keyword",
            _inject_timing(result, t_start, "code_keyword"),
            request_arguments={
                "query": query,
                "glob": glob,
                "queries": queries,
                "limit": limit,
                "graph": graph,
                "graph_limit": graph_limit,
                "layer": layer,
            },
        )

    @mcp.tool(annotations=_OBSERVATIONAL_TOOL)
    def code_lexical(
        query: str = "",
        table: str = "both",
        kind: str = "",
        limit: int = 20,
        **kwargs: Any,
    ) -> dict[str, Any]:
        """BM25-ranked exact-token search over the indexed lexical layer (FTS5).

        Searches the SAME corpus the hybrid retrieval fuses (`fts_code`/`fts_docs` in the
        index-state store) and returns chunks ranked by BM25 — use it for exact-identifier
        lookups (compound identifiers, error strings, rare tokens) and to verify what the
        lexical layer actually holds (e.g. when a `code_ask` citation lacks the "lexical"
        source tag and you want to know whether the chunk is indexed).

        Routing: this is NOT regex (`code_pattern` does regex over live files), NOT live-file
        substring match (`code_keyword`), and NOT concept search (`code_search`/`docs_search`).
        Tokens are matched as literals; FTS operators in the query are treated as plain text.
        The tokenizer keeps `_` inside tokens, so compound identifiers are single indivisible
        tokens — `webhook_activity` does NOT match `webhook_activity_inserted`; query the full
        identifier.

        Args:
            query: Whitespace-separated tokens, each matched as an exact literal token
                (OR-joined for BM25 recall). Required.
            table: "code", "docs", or "both" (default) — which FTS table(s) to search;
                "both" merges best-first by BM25.
            kind: Optional exact chunk-kind filter (e.g. "code", "doc", "seed").
            limit: Max results (default 20, hard cap 50).

        Response fields:
        - results: [{id, path, kind, language, lines, text, text_truncated, bm25, table}]
          ordered best-first (BM25 is smaller-is-better; already sorted).
        - coverage: per-table lexical coverage vs Lance (present when the store reports it).
        - A `chunk_index_undercovered` diagnostic when a searched table is materially behind —
          zero results on an under-covered store mean "store not healed yet", not "absent".
        """
        bad = _ensure_no_extra_args("code_lexical", kwargs)
        if bad is not None:
            if isinstance(bad.get("data"), dict):  # search contract: fields always present
                bad["data"].setdefault("search_mode", None)
                bad["data"].setdefault("fallback_reason", None)
            return bad
        t_start = time.monotonic()
        # 1sed6: FTS is derived from Lance — mid-build/uninitialized state is
        # mixed and never served as current. Fail closed on a missing epoch,
        # and discard on a mid-operation change.
        # ONE state-token capture; completeness gate on the captured token
        # (review fix — no separate probe pair, no between-reads window).
        _tok = _epoch_state(get_handler().root)
        if _tok is None or _tok[1] != "complete":
            return _index_rebuilding_response("code_lexical", {"query": query})
        result = code_lexical_response(get_handler().root, query, table=table, kind=kind, limit=limit)
        if _epoch_state(get_handler().root) != _tok:
            return _index_rebuilding_response("code_lexical", {"query": query})
        return _record_retrieval_context(
            get_handler(),
            "code_lexical",
            _inject_timing(result, t_start, "code_lexical"),
            indexed_epoch_stable=True,
            request_arguments={
                "query": query,
                "table": table,
                "kind": kind,
                "limit": limit,
            },
        )

    @mcp.tool(annotations=_OBSERVATIONAL_TOOL)
    def code_constants(symbols: list[str], glob: str = "", **kwargs: Any) -> dict[str, Any]:
        """Look up current values of named module-/type-level constants in one call.

        Prefer when: you need the current value of one or more named constants
        (e.g. VECTOR_TOP_K, AGENT_CANDIDATE_MAX) without manually parsing
        grep output. Returns structured name/value/file/line/kind per match.
        Use code_keyword when searching for arbitrary substrings rather than
        constant assignments specifically.

        Multi-language (wave 1p4pz): finds module-/type-level constants across all
        languages — Python module + class constants, Java ``static final``, Go/C#
        ``const``, Kotlin ``const val``, Rust ``const``, Swift ``static let``,
        Ruby/PHP constants, JS/TS ``const`` (plus TS ``enum``/``const enum`` members
        as ``Enum.Member`` and ``namespace``-scoped consts) — by reusing the indexer's
        per-language constant detector (NOT a Python-only column-0 scan). Both a
        qualified name (``Status.OK``) and the bare member (``OK``) resolve; a Go
        grouped ``const (...)`` / ``iota`` block resolves every member. The value is
        the right-hand-side after ``=`` (trailing ``;`` trimmed; PHP ``define('NAME',
        value)`` second arg), extracted string-aware so a ``,``/``;``/``}`` inside a
        quoted value is kept; multiline literals (frozenset/list/dict/array) are
        preserved, and a value that does not close is returned with
        kind="multiline-truncated". Function/block locals are NOT returned.

        Symbols not found in the codebase are included in the result with
        value=null so callers can verify every lookup was attempted. When a
        symbol appears in multiple files, all matches are returned — use the
        glob parameter to scope to a specific file.

        Response fields per result entry:
        - name: the requested symbol name
        - value: right-hand-side of the assignment as a raw string, or null if not found
        - file: repo-relative path, or null if not found
        - line: 1-based line number, or null if not found
        - kind: "scalar" | "multiline" | "multiline-truncated" | null

        Args:
            symbols: List of constant names to look up, e.g. ["VECTOR_TOP_K", "RRF_K"].
            glob: Optional glob to restrict search, e.g. "**/server.py" or "**/*.py".
        """
        bad = _ensure_no_extra_args("code_constants", kwargs)
        if bad is not None:
            return bad
        t_start = time.monotonic()
        result = _inject_timing(
            code_constants_response(get_handler().root, symbols, glob=glob),
            t_start,
            "code_constants",
        )
        return _record_retrieval_context(
            get_handler(),
            "code_constants",
            result,
            request_arguments={"symbols": symbols, "glob": glob},
        )

