    @mcp.tool(annotations=_OBSERVATIONAL_TOOL)
    def code_callhierarchy(
        symbol: str,
        file: str = "",
        direction: str = "both",
        context_depth: int = 0,
        include_external: bool = False,
        **kwargs: Any,
    ) -> dict[str, Any]:
        """Return the call hierarchy for a symbol: what it calls (outgoing) and what calls it (incoming).

        Prefer when: tracing execution paths, understanding a function's callers and callees,
        or planning a refactor that affects a specific symbol. Depth is always 1 — direct callers
        and callees only. Chain calls for transitive analysis.

        Response fields:
        - symbol: the queried symbol name
        - definition_file: path of the file where the symbol is defined (null if not found)
        - outgoing: list of {name, file, line, snippet, community_id, community} — symbols called by
          this symbol (when direction includes "outgoing"). ``community_id`` (wave 1316r) is the
          stable identifier of the caller's community, useful for grouping cross-cutting changes.
        - incoming: list of {name, file, line, snippet, community_id, community} — symbols that call
          this symbol (when direction includes "incoming"). ``community_id`` is the stable
          community id of each caller (stable across graph rebuilds, unlike Leiden numbering).
        - external_outgoing_count, external_incoming_count: number of external (non-project) entries
          suppressed from the lists (wave 130ol). Set ``include_external=True`` to surface them inline.
        - supertypes: present when the symbol's class declares supertypes —
          ``{project: [...], external_implements_count, external_extends_count}`` always, plus the
          ``external`` entry list (``{id, name, relation, confidence}``) when ``include_external=True``.
          Counts are ALWAYS present, so a class implementing only external interfaces (e.g. a
          third-party SDK interface) is never silently invisible. To get the reverse view — every
          project class implementing an external interface — call ``code_impact(symbol=<name>)``.
        - context: (when context_depth > 0) one-hop expansion from all immediate callers/callees;
          each entry is {id, label, kind, source_file, community_id, community, relation}
        - suggestions: near-match candidates when the symbol is not found in the graph
        - parser_used: method used for definition lookup

        **AOP/advice exception:** empty ``incoming`` on a Java method with
        ``@Advice.OnMethodEnter`` / ``@Advice.OnMethodExit`` / ``@Around`` / ``@Before`` /
        ``@After`` / ``@AfterReturning`` / ``@AfterThrowing`` annotations is expected —
        the callers are wired by the AOP framework (ByteBuddy, AspectJ) at weave time and
        have no Java call sites. Do NOT fall back to ``code_references``; instead look for
        the advice registration via ``code_keyword`` on ``**/*Instrumentation*.java``.

        Edge confidence: incoming/outgoing entries are derived from graph edges that carry
        a ``confidence`` field (``RECEIVER_RESOLVED`` for type-resolved attribution at the
        graph-builder, ``EXTRACTED`` for heuristic fallback). See the seed-211 confidence
        guidance for client-side filtering recommendations on refactor-safety or
        security-review investigations.

        Args:
            symbol: Symbol name to query (e.g. "process_payment", "UserService").
            file: Optional repo-relative file path to disambiguate when the symbol appears in multiple files.
            direction: "both" (default), "outgoing" (callee direction only), or "incoming" (caller direction only).
            context_depth: When > 0, appends a ``context`` list with one additional BFS hop from all immediate callers/callees (single combined traversal). Default 0 (no expansion).
            include_external: When True, includes entries whose target is an external (non-project) symbol — surfaced as ``file: "external"`` with no line/snippet. Default False (wave 130ol): external entries are suppressed and counted in ``external_outgoing_count`` / ``external_incoming_count``.
        """
        bad = _ensure_no_extra_args("code_callhierarchy", kwargs)
        if bad is not None:
            return bad
        t_start = time.monotonic()
        result = _inject_timing(
            code_callhierarchy_response(
                get_handler().root,
                symbol,
                file or None,
                direction,
                context_depth=context_depth,
                include_external=include_external,
            ),
            t_start,
            "code_callhierarchy",
        )
        return _record_retrieval_context(
            get_handler(),
            "code_callhierarchy",
            result,
            request_arguments={
                "symbol": symbol,
                "file": file,
                "direction": direction,
                "context_depth": context_depth,
                "include_external": include_external,
            },
        )

    @mcp.tool(annotations=_OBSERVATIONAL_TOOL)
    def code_graph_path(
        from_symbol: str,
        to_symbol: str,
        relations: list[str] | None = None,
        max_hops: int = 10,
        layer: str = "project",
        direction: str = "forward",
        min_confidence: str = "EXTRACTED",
        **kwargs: Any,
    ) -> dict[str, Any]:
        """Find the lowest-cost connecting path between two graph symbols.

        Wave 1p2q3 (1p2q4): path search is weighted-cost Dijkstra-equivalent
        rather than shortest-hop BFS. Per-edge cost reflects semantic weight:
        deterministic-attribution call edges cost 1 (RECEIVER_RESOLVED /
        CONSTRUCTION_RESOLVED), heuristic call edges cost 2 (EXTRACTED),
        structural edges cost 100 (imports / defines). Real call chains beat
        shorter structural shortcuts even when the structural path has fewer
        hops — a 3-hop RECEIVER_RESOLVED chain (cost 3) wins against a 1-hop
        import bridge (cost 100). External::* nodes are non-transitive (valid
        as endpoints but never as intermediate bridges) to eliminate the
        "two functions share an `external::e` exception variable" failure mode.

        Prefer when:
        - ``direction="forward"`` (default): tracing dependency chains — "does A reach B
          through outgoing calls/imports?". Use when directionality is part of the question.
        - ``direction="backward"``: reverse dependency — "is A reached by B?" / "what
          upstream chain leads to A from B?". Use when you know the destination but want
          to find the caller chain.
        - ``direction="either"``: general coupling — "are A and B connected at all,
          regardless of direction?". Use when you don't know which way the call flows.
          Each ``path_edges`` entry carries a ``traversal_direction`` field so the chain
          is unambiguous.

        Response fields:
        - found: true when a path exists within max_hops
        - path_nodes: ordered list of {node_id, label, kind, source_file} from from_symbol to to_symbol
        - path_edges: ordered list of traversed edges; in ``direction="either"`` each edge
          includes ``traversal_direction`` ("forward" or "backward")
        - hop_count: number of edges in the path (0 when symbols are identical or path not found)
        - direction: echoes the resolved direction value
        - suggestions: list of {id, label, kind} near-match candidates when either symbol is unresolvable

        Structured diagnostic (wave 1p2q3): when the resolved path contains
        zero ``calls`` edges, the response includes ``path_is_structural`` —
        endpoints share structural reachability but no direct call chain.
        Common case: caller passed ``relations=["imports"]`` explicitly OR the
        graph has no calls chain between the endpoints.

        Args:
            from_symbol: Starting graph node id or resolvable symbol.
            to_symbol: Target graph node id or resolvable symbol.
            relations: Optional edge relation filter (default: all relations — cost function
                surfaces calls paths preferentially; pass ``["calls"]`` to restrict explicitly).
            max_hops: Maximum hops before giving up (default 10).
            layer: Graph layer (default ``project``).
            direction: ``forward`` (default — outgoing edges only), ``backward`` (incoming
                edges only), or ``either`` (both, with per-edge ``traversal_direction``).
            min_confidence: Edge confidence floor — ``EXTRACTED`` (default, all edges),
                ``RECEIVER_RESOLVED``, or ``CONSTRUCTION_RESOLVED``. Higher floors restrict
                the search to deterministic-attribution edges for refactor-safety / security-
                review workflows. Orthogonal to the weighted-cost selection.
        """
        bad = _ensure_no_extra_args("code_graph_path", kwargs)
        if bad is not None:
            return bad
        t_start = time.monotonic()
        result = _inject_timing(code_graph_path_response(
            get_handler().root,
            from_symbol,
            to_symbol,
            relations=relations,
            max_hops=max_hops,
            layer=layer,
            direction=direction,
            min_confidence=min_confidence,
        ), t_start, "code_graph_path")
        return _record_retrieval_context(
            get_handler(),
            "code_graph_path",
            result,
            request_arguments={
                "from_symbol": from_symbol,
                "to_symbol": to_symbol,
                "relations": relations,
                "max_hops": max_hops,
                "layer": layer,
                "direction": direction,
                "min_confidence": min_confidence,
            },
        )

    @mcp.tool(annotations=_OBSERVATIONAL_TOOL)
    def code_graph_community(
        community_id: str = "",
        hub_node_id: str = "",
        layer: str = "project",
        limit: int = 50,
        offset: int = 0,
        exclude_generated: bool = False,
        **kwargs: Any,
    ) -> dict[str, Any]:
        """Return member nodes of a graph community from the cluster artifact.

        Prefer when: drilling into a specific community identified from wf_graph_report or
        the cluster dashboard to understand what code belongs to it. Returns members sorted
        by degree descending so the most-connected nodes (likely the community's key APIs) appear first.

        Read ``wavefoundry://graph/communities`` first to discover available community ids
        without a tool call.

        Pagination (wave 130rj — field feedback §1.3): default ``limit=50`` so
        communities of 50+ members stay within agent context limits. Use ``offset`` to
        page; ``has_more`` in the response indicates whether further pages exist.

        Response fields (success):
        - community_id: the requested community identifier
        - label: human-readable community label
        - total_node_count: total members of the community (independent of pagination)
        - returned_count: number of members in this response page
        - offset: the requested page offset
        - has_more: true when more members exist past this page
        - nodes: page of {id, label, kind, source_file, degree} sorted by degree descending
        - community_hub_node_id / hub_label (wave 1316r): the highest-degree member of
          the community, identified by node id. Stable across graph rebuilds — pass this
          back via the ``hub_node_id`` parameter for cached/persisted references rather
          than the ``community_id`` (which Leiden re-clustering renumbers between builds).
        - community_size_class (wave 1312j): ``"small"`` (< 50) / ``"medium"`` (50–200) /
          ``"large"`` (200+) — always present. Use this to decide whether to page through
          members or follow the advisory.
        - large_community_advisory (wave 1312j): structured diagnostic present when
          ``total_node_count > 200``. Carries
          ``recovery_tools: ["code_callhierarchy", "code_graph_path"]`` and ``recovery_usage``
          pointing at the hub's ``code_callhierarchy`` call. Follow it instead of paging
          through 200+ members one offset at a time. Complements ``pagination_hint`` (both
          surface on large communities) rather than replacing it.

        Response fields (not-found error):
        - community_id: the requested community identifier
        - suggestions: list of up to 5 {community_id, label, node_count} near-match
          communities — substring-matched on id/label first, then ranked by node count.
          Use these to recover from a typo or stale id without a second tool call.

        Args:
            community_id: Community ID as returned in the cluster artifact or wf_graph_report.
                Stable within a single graph build; Leiden re-clustering across rebuilds
                renumbers these. Use ``hub_node_id`` for cross-rebuild stability.
            hub_node_id: Stable community anchor (wave 1316r). The id of the community's
                highest-degree member, which is persistent across graph rebuilds (node ids
                don't churn even when Leiden ids do). When provided, the tool resolves to
                the current community containing this node. ``community_id`` wins when
                both are provided.
            layer: Graph layer (default ``project``).
            limit: Max members in this page (default 50, max 500).
            offset: Member index to start from (default 0). Members sorted by degree desc.
        """
        bad = _ensure_no_extra_args("code_graph_community", kwargs)
        if bad is not None:
            return bad
        t_start = time.monotonic()
        result = _inject_timing(code_graph_community_response(
            get_handler().root,
            community_id,
            hub_node_id=hub_node_id,
            layer=layer,
            limit=limit,
            offset=offset,
            exclude_generated=exclude_generated,
        ), t_start, "code_graph_community")
        return _record_retrieval_context(
            get_handler(),
            "code_graph_community",
            result,
            request_arguments={
                "community_id": community_id,
                "hub_node_id": hub_node_id,
                "layer": layer,
                "limit": limit,
                "offset": offset,
                "exclude_generated": exclude_generated,
            },
        )

    # --- Read-only MCP Resources ---
    # These expose stable context as MCP resources rather than tool calls.
    # Agents should prefer resources for read-only context discovery and
    # fall back to the equivalent tools when they need structured envelopes.

    def _read_doc_or_not_found(path: Path, label: str) -> str:
        """Read a markdown doc and return its text, or a clear not-found message."""
        if path.exists():
            return path.read_text(encoding="utf-8")
        return f"# Not Found\n\n`{label}` does not exist at `{_repo_rel(get_handler().root, path)}`.\n"

    def _validated_wave_markdown(path: Path) -> str:
        """Serve canonical-event-derived projection or fail closed on authority damage."""

        if not _wave_uses_external_review_evidence(get_handler().root, path):
            return path.read_text(encoding="utf-8")
        validation = validate_external_review_evidence(path)
        adoption_errors = validate_adopted_protocol_state(
            get_handler().root, path.parent.name, path
        )
        if validation.authority_errors or adoption_errors:
            details = [*validation.authority_errors, *adoption_errors]
            return (
                "# Wave Review Evidence Unavailable\n\n"
                "The canonical `events.jsonl` authority failed validation; the Markdown "
                "projection is not being served as review state.\n\n"
                + "\n".join(f"- {detail}" for detail in details)
                + "\n"
            )
        raw = path.read_text(encoding="utf-8")
        projection_status = "current"
        try:
            rendered = _project_current_review_status(
                get_handler().root, path, raw
            )
            if rendered != raw or validation.projection_errors:
                projection_status = "stale"
        except ValueError:
            projection_status = "missing"
            recovery_source = (
                raw.rstrip()
                + "\n\n"
                + empty_external_finding_synthesis_section().strip()
                + "\n"
            )
            try:
                rendered = render_review_evidence_projection(
                    recovery_source, validation.records
                )
                rendered = render_review_status_projection(
                    rendered,
                    validation.records,
                    _review_status_signoff_keys(
                        get_handler().root, rendered, validation.records
                    ),
                )
            except ValueError as exc:
                return (
                    "# Wave Review Evidence Unavailable\n\n"
                    "The canonical ledger is valid, but the Markdown projection "
                    f"cannot be derived safely: {exc}.\n"
                )
        if projection_status != "current":
            return (
                rendered.rstrip()
                + "\n\n> Wavefoundry diagnostic: the on-disk review projection "
                f"is {projection_status}; this response was derived from validated `events.jsonl`. "
                "Replay the last typed review event to repair it.\n"
            )
        return raw

